-- OpenPlantDB — PostgreSQL table.
-- Load the full dataset with:  psql "$DSN" -f schema/plants.sql
-- (schema/plants.sql = this file + one UPSERT per plant, regenerated by build.py)
CREATE TABLE IF NOT EXISTS plants (
    slug                 TEXT PRIMARY KEY,
    common_name          TEXT NOT NULL,
    scientific_name      TEXT,
    category             TEXT,
    subcategory          TEXT,
    germ_days_min        INT,
    germ_days_max        INT,
    germ_soil_temp_f_min INT,
    germ_soil_temp_f_max INT,
    maturity_days_min    INT,
    maturity_days_max    INT,
    maturity_from        TEXT,
    sow_method           TEXT,
    season               TEXT,
    frost_tolerance      TEXT,
    plant_anchor         TEXT,
    plant_weeks_min      INT,
    plant_weeks_max      INT,
    plant_note           TEXT,
    usda_zone_min        INT,
    usda_zone_max        INT,
    spacing_in_min       REAL,
    spacing_in_max       REAL,
    height_in_min        REAL,
    height_in_max        REAL,
    spread_in_min        REAL,
    spread_in_max        REAL,
    sun                  TEXT,
    water                TEXT,
    directions           TEXT,
    sources              JSONB NOT NULL DEFAULT '[]',
    data                 JSONB NOT NULL DEFAULT '{}'
);
CREATE INDEX IF NOT EXISTS idx_plants_category ON plants(category);
CREATE INDEX IF NOT EXISTS idx_plants_common   ON plants(lower(common_name));


INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('alpine-strawberry','Alpine Strawberry','Fragaria vesca','berry','ground fruit',14,28,60,75,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 8–10 weeks before last frost; seeds are very small and should be pressed onto the soil surface without covering.',3,10,9,12,6,10,9,12,'partial','moderate','Alpine strawberries are compact, clumping, runner-free plants that produce small but intensely fragrant and flavored berries continuously from early summer through fall frost. Seeds are tiny and require light for germination — surface sow in trays and do not cover; keep moist at 65–75°F. Unlike garden strawberries, alpines form clumps rather than runners and are best propagated by division every 3–4 years or from seed. They are more shade-tolerant than hybrid strawberries, making them excellent for edging partially shaded paths. Harvest individual berries when fully red and aromatic.','["general horticultural reference", "university extension guides"]','{"slug": "alpine-strawberry", "common_name": "Alpine Strawberry", "scientific_name": "Fragaria vesca", "category": "berry", "subcategory": "ground fruit", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 60, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 8–10 weeks before last frost; seeds are very small and should be pressed onto the soil surface without covering."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 6, "max": 10}, "spread_in": {"min": 9, "max": 12}, "sun": "partial", "water": "moderate", "directions": "Alpine strawberries are compact, clumping, runner-free plants that produce small but intensely fragrant and flavored berries continuously from early summer through fall frost. Seeds are tiny and require light for germination — surface sow in trays and do not cover; keep moist at 65–75°F. Unlike garden strawberries, alpines form clumps rather than runners and are best propagated by division every 3–4 years or from seed. They are more shade-tolerant than hybrid strawberries, making them excellent for edging partially shaded paths. Harvest individual berries when fully red and aromatic.", "sources": ["general horticultural reference", "university extension guides"]}')
