  VALUES ('kolomikta-kiwi','Arctic Kiwi / Kolomikta Kiwi','Actinidia kolomikta','berry','vine fruit',NULL,NULL,NULL,NULL,1460,2555,'transplant','cutting','perennial','hardy','last_frost',0,4,'Plant one male per 4–6 female vines after last frost; protect new shoots from cats, which are strongly attracted to kolomikta vines.',3,8,96,120,96,180,96,144,'partial','moderate','Actinidia kolomikta is the hardiest kiwi species, tolerating temperatures to -40°F in zone 3, and is grown for its small (1 in), sweet, smooth-skinned fruits that ripen in late summer. The vine is ornamentally striking due to pink-and-white variegated foliage on male plants. It is dioecious and requires both male and female plants — one male per 4–6 females. Cats are intensely attracted to the plants and will damage young vines, so protect new plantings with wire cages. Prune each dormant season to maintain a framework of lateral arms on a sturdy arbor or fence.','["general horticultural reference", "university extension guides"]','{"slug": "kolomikta-kiwi", "common_name": "Arctic Kiwi / Kolomikta Kiwi", "scientific_name": "Actinidia kolomikta", "category": "berry", "subcategory": "vine fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2555}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant one male per 4–6 female vines after last frost; protect new shoots from cats, which are strongly attracted to kolomikta vines."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 96, "max": 120}, "height_in": {"min": 96, "max": 180}, "spread_in": {"min": 96, "max": 144}, "sun": "partial", "water": "moderate", "directions": "Actinidia kolomikta is the hardiest kiwi species, tolerating temperatures to -40°F in zone 3, and is grown for its small (1 in), sweet, smooth-skinned fruits that ripen in late summer. The vine is ornamentally striking due to pink-and-white variegated foliage on male plants. It is dioecious and requires both male and female plants — one male per 4–6 females. Cats are intensely attracted to the plants and will damage young vines, so protect new plantings with wire cages. Prune each dormant season to maintain a framework of lateral arms on a sturdy arbor or fence.", "sources": ["general horticultural reference", "university extension guides"]}')
