  VALUES ('aronia-chokeberry','Aronia / Chokeberry','Aronia melanocarpa','berry','shrub fruit',NULL,NULL,NULL,NULL,548,730,'transplant','transplant','perennial','hardy','spring',0,4,'Plant bare-root or container stock in early spring; extremely adaptable to wet or dry soils.',3,8,48,72,36,72,48,72,'full','low','Aronia is exceptionally hardy and tolerates wet, poorly drained soils, making it suitable for rain gardens. It is self-fruitful and rarely needs a pollinator, though yields improve with a second plant nearby. Prune by removing the oldest, thickest canes at the base every 3–4 years to encourage vigorous new growth and better light penetration. Harvest clusters in late summer when berries are very dark purple-black; the astringent flavor mellows after a light frost or processing.','["general horticultural reference", "university extension guides"]','{"slug": "aronia-chokeberry", "common_name": "Aronia / Chokeberry", "scientific_name": "Aronia melanocarpa", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 548, "max": 730}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant bare-root or container stock in early spring; extremely adaptable to wet or dry soils."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 48, "max": 72}, "sun": "full", "water": "low", "directions": "Aronia is exceptionally hardy and tolerates wet, poorly drained soils, making it suitable for rain gardens. It is self-fruitful and rarely needs a pollinator, though yields improve with a second plant nearby. Prune by removing the oldest, thickest canes at the base every 3–4 years to encourage vigorous new growth and better light penetration. Harvest clusters in late summer when berries are very dark purple-black; the astringent flavor mellows after a light frost or processing.", "sources": ["general horticultural reference", "university extension guides"]}')
