INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('autumn-olive','Autumn Olive','Elaeagnus umbellata','berry','shrub fruit',30,90,50,68,1095,1460,'transplant','cutting','perennial','hardy','spring',0,4,'Plant in spring in any well-drained soil; autumn olive is highly invasive in the eastern U.S. — confirm it is legal in your state before planting.',3,8,72,120,72,180,72,144,'full','low','Autumn olive is a nitrogen-fixing Asian shrub with extremely high yields of small red-speckled berries that are rich in lycopene and have a sweet-tart flavor; it is among the most productive fruiting shrubs per acre in temperate climates. However, it is considered an invasive species across much of the eastern U.S. and is prohibited or discouraged in many states — verify legal status in your jurisdiction before planting. Named fruit-producing selections such as ''Garnet'' or ''Red Wing'' are more compact and productive than seedlings. Harvest by hand-stripping clusters in fall when berries are fully red; fruit quality improves after light frost.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "autumn-olive", "common_name": "Autumn Olive", "scientific_name": "Elaeagnus umbellata", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": 30, "max": 90}, "germination_soil_temp_f": {"min": 50, "max": 68}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring in any well-drained soil; autumn olive is highly invasive in the eastern U.S. — confirm it is legal in your state before planting."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 72, "max": 120}, "height_in": {"min": 72, "max": 180}, "spread_in": {"min": 72, "max": 144}, "sun": "full", "water": "low", "directions": "Autumn olive is a nitrogen-fixing Asian shrub with extremely high yields of small red-speckled berries that are rich in lycopene and have a sweet-tart flavor; it is among the most productive fruiting shrubs per acre in temperate climates. However, it is considered an invasive species across much of the eastern U.S. and is prohibited or discouraged in many states — verify legal status in your jurisdiction before planting. Named fruit-producing selections such as ''Garnet'' or ''Red Wing'' are more compact and productive than seedlings. Harvest by hand-stripping clusters in fall when berries are fully red; fruit quality improves after light frost.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
