  VALUES ('beach-plum','Beach Plum','Prunus maritima','berry','shrub fruit',90,150,40,55,1095,1460,'transplant','transplant','perennial','hardy','spring',0,4,'Plant two or more named cultivars for cross-pollination in spring in sandy, well-drained, slightly acidic to neutral soil.',3,7,60,96,48,96,60,96,'full','low','Beach plum is a native Atlantic coastal shrub that thrives in sandy, salt-spray-exposed sites where few other fruits survive, making it invaluable for coastal and xeric gardens. The small (0.5–1 in), round fruits range from red to purple to blue at maturity in late summer and are traditionally used for preserves and jams on Cape Cod and Long Island. Plant at least two named cultivars such as ''Autumn'' and ''Premier'' for adequate cross-pollination, as seedlings are variable and often infertile. Prune lightly after flowering to maintain shape; heavy pruning reduces fruiting the following year.','["general horticultural reference", "Cornell University Cooperative Extension"]','{"slug": "beach-plum", "common_name": "Beach Plum", "scientific_name": "Prunus maritima", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": 90, "max": 150}, "germination_soil_temp_f": {"min": 40, "max": 55}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant two or more named cultivars for cross-pollination in spring in sandy, well-drained, slightly acidic to neutral soil."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 60, "max": 96}, "height_in": {"min": 48, "max": 96}, "spread_in": {"min": 60, "max": 96}, "sun": "full", "water": "low", "directions": "Beach plum is a native Atlantic coastal shrub that thrives in sandy, salt-spray-exposed sites where few other fruits survive, making it invaluable for coastal and xeric gardens. The small (0.5–1 in), round fruits range from red to purple to blue at maturity in late summer and are traditionally used for preserves and jams on Cape Cod and Long Island. Plant at least two named cultivars such as ''Autumn'' and ''Premier'' for adequate cross-pollination, as seedlings are variable and often infertile. Prune lightly after flowering to maintain shape; heavy pruning reduces fruiting the following year.", "sources": ["general horticultural reference", "Cornell University Cooperative Extension"]}')
