INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('bearberry-kinnikinnick','Bearberry / Kinnikinnick','Arctostaphylos uva-ursi','berry','ground fruit',NULL,NULL,NULL,NULL,1095,1460,'transplant','cutting','perennial','hardy','spring',0,4,'Plant rooted cuttings or container stock in spring in very well-drained, sandy or rocky, acidic soil; bearberry strongly resents wet, fertile conditions.',2,6,18,24,4,8,24,60,'full','low','Bearberry is a prostrate, evergreen groundcover native to circumpolar regions, widely used in northern and mountain landscapes for erosion control on dry, acidic, sandy slopes. The small red berries ripen in fall and persist through winter, providing important wildlife food for bears, grouse, and other species; they are mealy and bland fresh but edible when cooked or dried. Bearberry is best propagated from rooted stem cuttings as seed germination is notoriously slow and difficult. Once established, the plant is extremely drought-tolerant and essentially maintenance-free; avoid fertilizing or overwatering, which quickly kills it.','["general horticultural reference", "university extension guides"]','{"slug": "bearberry-kinnikinnick", "common_name": "Bearberry / Kinnikinnick", "scientific_name": "Arctostaphylos uva-ursi", "category": "berry", "subcategory": "ground fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted cuttings or container stock in spring in very well-drained, sandy or rocky, acidic soil; bearberry strongly resents wet, fertile conditions."}, "usda_zones": {"min": 2, "max": 6}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 4, "max": 8}, "spread_in": {"min": 24, "max": 60}, "sun": "full", "water": "low", "directions": "Bearberry is a prostrate, evergreen groundcover native to circumpolar regions, widely used in northern and mountain landscapes for erosion control on dry, acidic, sandy slopes. The small red berries ripen in fall and persist through winter, providing important wildlife food for bears, grouse, and other species; they are mealy and bland fresh but edible when cooked or dried. Bearberry is best propagated from rooted stem cuttings as seed germination is notoriously slow and difficult. Once established, the plant is extremely drought-tolerant and essentially maintenance-free; avoid fertilizing or overwatering, which quickly kills it.", "sources": ["general horticultural reference", "university extension guides"]}')
