INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('bilberry','Bilberry','Vaccinium myrtillus','berry','shrub fruit',30,90,55,70,1095,1460,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions or plugs in early spring in strongly acidic, humus-rich, moist soil, ideally under light tree canopy.',3,7,18,24,12,24,18,36,'partial','moderate','Bilberry is a low-growing European relative of blueberry that differs in producing berries singly rather than in clusters; the deep purple-red flesh (unlike blueberry''s white flesh) stains heavily and has an intense, slightly tart flavor. It demands strongly acidic soil (pH 4.0–5.0) with high organic matter and cool, moist conditions, making it challenging to grow in most American gardens but worth attempting in zones 3–7 under high shade or at elevation. Minimal pruning is needed; shear plants lightly every 3–4 years to rejuvenate. Harvest in mid- to late summer when berries are fully dark blue-black and tender.','["general horticultural reference", "Royal Horticultural Society"]','{"slug": "bilberry", "common_name": "Bilberry", "scientific_name": "Vaccinium myrtillus", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": 30, "max": 90}, "germination_soil_temp_f": {"min": 55, "max": 70}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions or plugs in early spring in strongly acidic, humus-rich, moist soil, ideally under light tree canopy."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 18, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Bilberry is a low-growing European relative of blueberry that differs in producing berries singly rather than in clusters; the deep purple-red flesh (unlike blueberry''s white flesh) stains heavily and has an intense, slightly tart flavor. It demands strongly acidic soil (pH 4.0–5.0) with high organic matter and cool, moist conditions, making it challenging to grow in most American gardens but worth attempting in zones 3–7 under high shade or at elevation. Minimal pruning is needed; shear plants lightly every 3–4 years to rejuvenate. Harvest in mid- to late summer when berries are fully dark blue-black and tender.", "sources": ["general horticultural reference", "Royal Horticultural Society"]}')
