  VALUES ('buffaloberry','Buffaloberry','Shepherdia argentea','berry','shrub fruit',30,90,40,55,1095,1460,'transplant','transplant','perennial','hardy','spring',0,4,'Plant one male plant for every 5–7 female plants in early spring; buffaloberry is wind-pollinated and both sexes must be within 50 ft.',2,6,72,120,72,180,60,120,'full','low','Silver buffaloberry is an extremely cold-hardy nitrogen-fixing shrub native to the Great Plains, valued for its bright red, tart berries that have historically been used by Indigenous peoples of North America for pemmican and sauces. It is dioecious and wind-pollinated, requiring male and female plants; purchase sexed plants, as seedlings cannot be sexed until flowering at 3–5 years. The thorny, silver-leaved plants thrive in alkaline, dry, or infertile soils where other fruits fail. Harvest by spreading a tarp and gently shaking or beating branches after a light frost, which softens the bitterness; berries are very tart raw but excellent cooked.','["general horticultural reference", "USDA Forest Service"]','{"slug": "buffaloberry", "common_name": "Buffaloberry", "scientific_name": "Shepherdia argentea", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": 30, "max": 90}, "germination_soil_temp_f": {"min": 40, "max": 55}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant one male plant for every 5–7 female plants in early spring; buffaloberry is wind-pollinated and both sexes must be within 50 ft."}, "usda_zones": {"min": 2, "max": 6}, "spacing_in": {"min": 72, "max": 120}, "height_in": {"min": 72, "max": 180}, "spread_in": {"min": 60, "max": 120}, "sun": "full", "water": "low", "directions": "Silver buffaloberry is an extremely cold-hardy nitrogen-fixing shrub native to the Great Plains, valued for its bright red, tart berries that have historically been used by Indigenous peoples of North America for pemmican and sauces. It is dioecious and wind-pollinated, requiring male and female plants; purchase sexed plants, as seedlings cannot be sexed until flowering at 3–5 years. The thorny, silver-leaved plants thrive in alkaline, dry, or infertile soils where other fruits fail. Harvest by spreading a tarp and gently shaking or beating branches after a light frost, which softens the bitterness; berries are very tart raw but excellent cooked.", "sources": ["general horticultural reference", "USDA Forest Service"]}')
