  VALUES ('chilean-guava','Chilean Guava (Ugni)','Ugni molinae','berry','shrub fruit',14,28,65,75,730,1095,'transplant','cutting','perennial','half-hardy','spring',0,4,'Plant container-grown stock in spring after frost in a sheltered site; appreciates afternoon shade in hot climates.',8,10,36,60,36,72,36,60,'partial','moderate','Chilean guava (Ugni molinae) is a compact, evergreen myrtle-family shrub native to Chile, grown for its small, crimson, aromatic berries with a flavor often described as strawberry-vanilla-bubblegum. The Queen of England''s personal favorite berry, it is widely grown in the UK and mild coastal climates. It tolerates some frost but is best suited to USDA zones 8–10 in the ground, or grown in containers and overwintered frost-free. Prune lightly after harvest to maintain shape; no heavy pruning is needed. Harvest in late fall and winter when berries are deep red-purple and fully aromatic.','["general horticultural reference", "Royal Horticultural Society"]','{"slug": "chilean-guava", "common_name": "Chilean Guava (Ugni)", "scientific_name": "Ugni molinae", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant container-grown stock in spring after frost in a sheltered site; appreciates afternoon shade in hot climates."}, "usda_zones": {"min": 8, "max": 10}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 36, "max": 60}, "sun": "partial", "water": "moderate", "directions": "Chilean guava (Ugni molinae) is a compact, evergreen myrtle-family shrub native to Chile, grown for its small, crimson, aromatic berries with a flavor often described as strawberry-vanilla-bubblegum. The Queen of England''s personal favorite berry, it is widely grown in the UK and mild coastal climates. It tolerates some frost but is best suited to USDA zones 8–10 in the ground, or grown in containers and overwintered frost-free. Prune lightly after harvest to maintain shape; no heavy pruning is needed. Harvest in late fall and winter when berries are deep red-purple and fully aromatic.", "sources": ["general horticultural reference", "Royal Horticultural Society"]}')
