  VALUES ('cloudberry','Cloudberry','Rubus chamaemorus','berry','ground fruit',90,180,35,50,1460,2190,'transplant','division','perennial','hardy','spring',0,4,'Plant rhizome divisions in spring in acidic, peaty, boggy or moist woodland soil; requires both male and female plants for fruit set.',2,5,12,18,4,10,12,24,'full','high','Cloudberry is a low-growing, rhizomatous Arctic-boreal species that requires cold winters, strongly acidic peat or sphagnum-rich soil (pH 3.5–5.0), and consistent moisture — it is exceptionally difficult to cultivate outside its native subarctic habitat. It is dioecious, so both male and female plants must be planted in proximity for fruit to set. The amber-golden berries are among the most highly prized wild fruits in Scandinavia and are used in traditional preserves; ripe berries are extremely soft and must be processed immediately. Not suited to continental climates south of USDA zone 5.','["general horticultural reference", "Nordic Genetic Resource Center"]','{"slug": "cloudberry", "common_name": "Cloudberry", "scientific_name": "Rubus chamaemorus", "category": "berry", "subcategory": "ground fruit", "days_to_germination": {"min": 90, "max": 180}, "germination_soil_temp_f": {"min": 35, "max": 50}, "days_to_maturity": {"min": 1460, "max": 2190}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rhizome divisions in spring in acidic, peaty, boggy or moist woodland soil; requires both male and female plants for fruit set."}, "usda_zones": {"min": 2, "max": 5}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 4, "max": 10}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "high", "directions": "Cloudberry is a low-growing, rhizomatous Arctic-boreal species that requires cold winters, strongly acidic peat or sphagnum-rich soil (pH 3.5–5.0), and consistent moisture — it is exceptionally difficult to cultivate outside its native subarctic habitat. It is dioecious, so both male and female plants must be planted in proximity for fruit to set. The amber-golden berries are among the most highly prized wild fruits in Scandinavia and are used in traditional preserves; ripe berries are extremely soft and must be processed immediately. Not suited to continental climates south of USDA zone 5.", "sources": ["general horticultural reference", "Nordic Genetic Resource Center"]}')
