  VALUES ('clove-currant','Clove Currant','Ribes odoratum','berry','shrub fruit',30,90,40,60,548,730,'transplant','cutting','perennial','hardy','spring',0,4,'Plant hardwood cuttings or bare-root stock in early spring; highly adaptable to dry, alkaline soils unlike most Ribes.',4,8,48,72,48,72,48,72,'full','low','Clove currant (Ribes odoratum, syn. R. aureum) is a tough, drought-tolerant native prairie shrub with intensely clove-spice-scented yellow spring flowers and glossy black berries in mid-summer. It tolerates alkaline, clay, or droughty soils far better than European currants, making it the best Ribes choice for the Great Plains and intermountain West. The berries range from mild to somewhat astringent depending on selection; look for named fruit-producing cultivars such as ''Crandall''. Prune by removing the oldest canes at the base every few years; the plant suckers moderately and can form a thicket if not managed. Verify state restrictions before planting.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "clove-currant", "common_name": "Clove Currant", "scientific_name": "Ribes odoratum", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": 30, "max": 90}, "germination_soil_temp_f": {"min": 40, "max": 60}, "days_to_maturity": {"min": 548, "max": 730}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant hardwood cuttings or bare-root stock in early spring; highly adaptable to dry, alkaline soils unlike most Ribes."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 48, "max": 72}, "sun": "full", "water": "low", "directions": "Clove currant (Ribes odoratum, syn. R. aureum) is a tough, drought-tolerant native prairie shrub with intensely clove-spice-scented yellow spring flowers and glossy black berries in mid-summer. It tolerates alkaline, clay, or droughty soils far better than European currants, making it the best Ribes choice for the Great Plains and intermountain West. The berries range from mild to somewhat astringent depending on selection; look for named fruit-producing cultivars such as ''Crandall''. Prune by removing the oldest canes at the base every few years; the plant suckers moderately and can form a thicket if not managed. Verify state restrictions before planting.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
