  VALUES ('creeping-oregon-grape','Creeping Oregon Grape','Mahonia repens','berry','ground fruit',NULL,NULL,NULL,NULL,730,1095,'transplant','transplant','perennial','hardy','spring',0,4,'Plant container stock in spring in well-drained, sandy to loamy, slightly acidic soil; excellent groundcover for dry, shaded slopes in western gardens.',4,8,18,36,8,18,24,48,'shade','low','Creeping Oregon grape is a low-growing, mat-forming relative of upright Oregon grape, native to dry mountain forests and plains of western North America and exceptionally hardy once established. It spreads slowly by underground stems to form weed-suppressing colonies bearing clusters of blue-purple berries in summer that are sour but edible and rich in vitamin C. Like its taller relative, the berries are best used in jellies and syrups with added sweetener rather than eaten fresh. The plant requires no fertilizer and very little irrigation once established in appropriate rocky or sandy soil; excess moisture and fertility promote root rot.','["general horticultural reference", "university extension guides"]','{"slug": "creeping-oregon-grape", "common_name": "Creeping Oregon Grape", "scientific_name": "Mahonia repens", "category": "berry", "subcategory": "ground fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant container stock in spring in well-drained, sandy to loamy, slightly acidic soil; excellent groundcover for dry, shaded slopes in western gardens."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 18, "max": 36}, "height_in": {"min": 8, "max": 18}, "spread_in": {"min": 24, "max": 48}, "sun": "shade", "water": "low", "directions": "Creeping Oregon grape is a low-growing, mat-forming relative of upright Oregon grape, native to dry mountain forests and plains of western North America and exceptionally hardy once established. It spreads slowly by underground stems to form weed-suppressing colonies bearing clusters of blue-purple berries in summer that are sour but edible and rich in vitamin C. Like its taller relative, the berries are best used in jellies and syrups with added sweetener rather than eaten fresh. The plant requires no fertilizer and very little irrigation once established in appropriate rocky or sandy soil; excess moisture and fertility promote root rot.", "sources": ["general horticultural reference", "university extension guides"]}')
