  VALUES ('everbearing-fall-raspberry','Everbearing / Fall Raspberry','Rubus idaeus','berry','cane fruit',NULL,NULL,NULL,NULL,120,180,'transplant','transplant','perennial','hardy','spring',0,4,'Plant bare-root canes in early spring; primocane-fruiting types can yield a fall crop in their first year.',3,9,18,24,36,60,18,36,'full','moderate','Primocane-fruiting (everbearing) raspberries bear on the top portion of first-year canes in fall, then on lower portions the following summer if left. For the simplest management, mow all canes to the ground each late winter and enjoy a single fall crop on new primocanes — this eliminates disease buildup and minimizes pruning. Harvest from late summer through first frost when berries release easily from the plug. Consistent moisture during fruit development prevents crumbling.','["general horticultural reference", "university extension guides"]','{"slug": "everbearing-fall-raspberry", "common_name": "Everbearing / Fall Raspberry", "scientific_name": "Rubus idaeus", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant bare-root canes in early spring; primocane-fruiting types can yield a fall crop in their first year."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 36}, "sun": "full", "water": "moderate", "directions": "Primocane-fruiting (everbearing) raspberries bear on the top portion of first-year canes in fall, then on lower portions the following summer if left. For the simplest management, mow all canes to the ground each late winter and enjoy a single fall crop on new primocanes — this eliminates disease buildup and minimizes pruning. Harvest from late summer through first frost when berries release easily from the plug. Consistent moisture during fruit development prevents crumbling.", "sources": ["general horticultural reference", "university extension guides"]}')
