  VALUES ('five-flavor-berry','Five Flavor Berry (Schisandra)','Schisandra chinensis','berry','vine',NULL,NULL,NULL,NULL,1095,1460,'transplant','cutting','perennial','hardy','spring',0,4,'Plant softwood cuttings or container stock in spring in moist, well-drained, humus-rich acidic soil; provide a sturdy trellis or arbor — the twining vine reaches 20–30 ft.',4,8,60,96,120,360,60,96,'partial','moderate','Schisandra chinensis is a vigorous deciduous twining vine native to northeastern China and Russia, bearing pendant clusters of small, brilliant red berries in late summer whose juice is famously described as simultaneously sweet, sour, salty, bitter, and pungent — hence the common name wu wei zi (''five flavor fruit''). The plant is predominantly dioecious, so plant at least one male and one female vine for fruit production, though some cultivars bear perfect flowers. Train on a trellis, pergola, or fence with afternoon shade; the vine prefers cool, moist, slightly acidic woodland conditions. Prune to control size after fruiting; berries are used medicinally and in herbal preparations worldwide.','["general horticultural reference", "university extension guides"]','{"slug": "five-flavor-berry", "common_name": "Five Flavor Berry (Schisandra)", "scientific_name": "Schisandra chinensis", "category": "berry", "subcategory": "vine", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant softwood cuttings or container stock in spring in moist, well-drained, humus-rich acidic soil; provide a sturdy trellis or arbor — the twining vine reaches 20–30 ft."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 60, "max": 96}, "height_in": {"min": 120, "max": 360}, "spread_in": {"min": 60, "max": 96}, "sun": "partial", "water": "moderate", "directions": "Schisandra chinensis is a vigorous deciduous twining vine native to northeastern China and Russia, bearing pendant clusters of small, brilliant red berries in late summer whose juice is famously described as simultaneously sweet, sour, salty, bitter, and pungent — hence the common name wu wei zi (''five flavor fruit''). The plant is predominantly dioecious, so plant at least one male and one female vine for fruit production, though some cultivars bear perfect flowers. Train on a trellis, pergola, or fence with afternoon shade; the vine prefers cool, moist, slightly acidic woodland conditions. Prune to control size after fruiting; berries are used medicinally and in herbal preparations worldwide.", "sources": ["general horticultural reference", "university extension guides"]}')
