  VALUES ('huckleberry-garden','Garden Huckleberry','Solanum scabrum','berry','shrub fruit',10,21,70,85,75,90,'transplant','indoor-start','warm','tender','last_frost',0,2,'Start seeds indoors 6–8 weeks before last frost; transplant after all frost danger has passed, spacing plants 24–30 in apart.',3,11,24,30,24,48,24,36,'full','moderate','Garden huckleberry (Solanum scabrum) is an African-origin annual grown for its jet-black, blueberry-sized fruit, which must be cooked before eating as raw berries contain solanine. Start seeds indoors 6–8 weeks before last frost at 75–80°F and transplant outdoors after frost danger has passed. The bushy plants are prolific producers and generally need no staking. Harvest when all berries in a cluster have turned uniformly shiny black; cook with sugar and lemon juice to reduce bitterness and break down solanine before use in jams or pies.','["general horticultural reference", "University of Wisconsin Extension"]','{"slug": "huckleberry-garden", "common_name": "Garden Huckleberry", "scientific_name": "Solanum scabrum", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 75, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Start seeds indoors 6–8 weeks before last frost; transplant after all frost danger has passed, spacing plants 24–30 in apart."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 24, "max": 30}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Garden huckleberry (Solanum scabrum) is an African-origin annual grown for its jet-black, blueberry-sized fruit, which must be cooked before eating as raw berries contain solanine. Start seeds indoors 6–8 weeks before last frost at 75–80°F and transplant outdoors after frost danger has passed. The bushy plants are prolific producers and generally need no staking. Harvest when all berries in a cluster have turned uniformly shiny black; cook with sugar and lemon juice to reduce bitterness and break down solanine before use in jams or pies.", "sources": ["general horticultural reference", "University of Wisconsin Extension"]}')
