  VALUES ('goji-berry','Goji Berry','Lycium barbarum','berry','shrub fruit',NULL,NULL,NULL,NULL,548,730,'transplant','transplant','perennial','hardy','spring',0,4,'Plant container or bare-root stock in spring after frost danger; goji tolerates alkaline soils and drought once established.',3,10,36,60,36,96,36,60,'full','low','Goji berries are highly adaptable, tolerating poor, alkaline soils where other fruits fail, but perform best in well-drained loam with a pH of 6.5–8.0. The arching, slightly thorny canes can be left as a shrub or trained to a central leader with a stake. Prune lightly after fruiting to maintain shape and encourage new fruiting laterals. Harvest ripe berries by gently rolling the stem between your fingers — ripe fruits are bright red-orange, soft, and drop easily (avoid touching them, as the sap stains).','["general horticultural reference", "university extension guides"]','{"slug": "goji-berry", "common_name": "Goji Berry", "scientific_name": "Lycium barbarum", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 548, "max": 730}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant container or bare-root stock in spring after frost danger; goji tolerates alkaline soils and drought once established."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 36, "max": 96}, "spread_in": {"min": 36, "max": 60}, "sun": "full", "water": "low", "directions": "Goji berries are highly adaptable, tolerating poor, alkaline soils where other fruits fail, but perform best in well-drained loam with a pH of 6.5–8.0. The arching, slightly thorny canes can be left as a shrub or trained to a central leader with a stake. Prune lightly after fruiting to maintain shape and encourage new fruiting laterals. Harvest ripe berries by gently rolling the stem between your fingers — ripe fruits are bright red-orange, soft, and drop easily (avoid touching them, as the sap stains).", "sources": ["general horticultural reference", "university extension guides"]}')
