INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('golden-raspberry','Golden Raspberry','Rubus idaeus','berry','cane fruit',NULL,NULL,NULL,NULL,120,180,'transplant','transplant','perennial','hardy','spring',0,4,'Plant bare-root canes in early spring; most golden raspberries are primocane-fruiting and will yield a fall crop in their first year.',3,9,18,24,48,72,18,36,'full','moderate','Golden raspberries are yellow-fruited mutations of red raspberry cultivars, most commonly primocane-fruiting (everbearing) types such as ''Anne'' or ''Fall Gold'', with exceptionally sweet, mild flavor and low acidity. Manage as you would a primocane-fruiting red raspberry: for the simplest system, mow all canes to the ground each late winter and allow new primocanes to grow and fruit in fall. For a two-crop system, retain canes over winter to produce a summer crop on floricanes. Harvest when berries turn fully golden-yellow and release easily; they are more fragile than red types and should be processed quickly.','["general horticultural reference", "university extension guides"]','{"slug": "golden-raspberry", "common_name": "Golden Raspberry", "scientific_name": "Rubus idaeus", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant bare-root canes in early spring; most golden raspberries are primocane-fruiting and will yield a fall crop in their first year."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 18, "max": 36}, "sun": "full", "water": "moderate", "directions": "Golden raspberries are yellow-fruited mutations of red raspberry cultivars, most commonly primocane-fruiting (everbearing) types such as ''Anne'' or ''Fall Gold'', with exceptionally sweet, mild flavor and low acidity. Manage as you would a primocane-fruiting red raspberry: for the simplest system, mow all canes to the ground each late winter and allow new primocanes to grow and fruit in fall. For a two-crop system, retain canes over winter to produce a summer crop on floricanes. Harvest when berries turn fully golden-yellow and release easily; they are more fragile than red types and should be processed quickly.", "sources": ["general horticultural reference", "university extension guides"]}')
