  VALUES ('gooseberry','Gooseberry','Ribes uva-crispa','berry','shrub fruit',NULL,NULL,NULL,NULL,548,730,'transplant','cutting','perennial','hardy','spring',0,3,'Plant dormant cuttings or bare-root stock in early spring; fall planting works well in milder zones.',3,8,48,60,36,60,36,60,'partial','moderate','Gooseberries tolerate partial shade better than most fruits and prefer cool, well-drained soil with a pH of 6.0–6.5. Prune to an open-vase structure each late winter, removing canes older than 3 years and any crossing branches to reduce disease pressure. Pick berries early for cooking (when green and firm) or allow them to ripen to red, yellow, or white for fresh eating. Note: check local regulations, as Ribes species are restricted in some U.S. states due to white pine blister rust.','["general horticultural reference", "university extension guides"]','{"slug": "gooseberry", "common_name": "Gooseberry", "scientific_name": "Ribes uva-crispa", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 548, "max": 730}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 3}, "note": "Plant dormant cuttings or bare-root stock in early spring; fall planting works well in milder zones."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 48, "max": 60}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 36, "max": 60}, "sun": "partial", "water": "moderate", "directions": "Gooseberries tolerate partial shade better than most fruits and prefer cool, well-drained soil with a pH of 6.0–6.5. Prune to an open-vase structure each late winter, removing canes older than 3 years and any crossing branches to reduce disease pressure. Pick berries early for cooking (when green and firm) or allow them to ripen to red, yellow, or white for fresh eating. Note: check local regulations, as Ribes species are restricted in some U.S. states due to white pine blister rust.", "sources": ["general horticultural reference", "university extension guides"]}')
