INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('goumi','Goumi','Elaeagnus multiflora','berry','shrub fruit',30,90,55,70,730,1095,'transplant','cutting','perennial','hardy','spring',0,4,'Plant in early spring; goumi is partially self-fertile but yields improve with cross-pollination from a second plant.',5,9,72,120,60,96,60,96,'full','low','Goumi is a nitrogen-fixing shrub from East Asia that produces abundant small, cherry-red, speckled fruits with a sweet-tart flavor reminiscent of cherry. It is remarkably drought-tolerant once established and fixes atmospheric nitrogen through root nodules, making it a valued plant in permaculture systems. Prune lightly after fruiting to shape the plant and encourage denser branching; heavy pruning stimulates excessive vegetative growth at the expense of fruit. Harvest when berries are fully red and slightly soft — ripe fruits have little to no astringency and taste excellent fresh or dried.','["general horticultural reference", "USDA National Agroforestry Center"]','{"slug": "goumi", "common_name": "Goumi", "scientific_name": "Elaeagnus multiflora", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": 30, "max": 90}, "germination_soil_temp_f": {"min": 55, "max": 70}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in early spring; goumi is partially self-fertile but yields improve with cross-pollination from a second plant."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 72, "max": 120}, "height_in": {"min": 60, "max": 96}, "spread_in": {"min": 60, "max": 96}, "sun": "full", "water": "low", "directions": "Goumi is a nitrogen-fixing shrub from East Asia that produces abundant small, cherry-red, speckled fruits with a sweet-tart flavor reminiscent of cherry. It is remarkably drought-tolerant once established and fixes atmospheric nitrogen through root nodules, making it a valued plant in permaculture systems. Prune lightly after fruiting to shape the plant and encourage denser branching; heavy pruning stimulates excessive vegetative growth at the expense of fruit. Harvest when berries are fully red and slightly soft — ripe fruits have little to no astringency and taste excellent fresh or dried.", "sources": ["general horticultural reference", "USDA National Agroforestry Center"]}')
