  VALUES ('ground-cherry-cape-gooseberry','Ground Cherry / Cape Gooseberry','Physalis peruviana / Physalis pruinosa','berry','ground fruit',NULL,NULL,NULL,NULL,75,100,'transplant','transplant','warm','tender','last_frost',0,2,'Transplant starts after all frost danger has passed; start seeds indoors 6–8 weeks before last frost.',3,11,18,24,18,36,18,36,'full','moderate','Ground cherries are grown as warm-season annuals in most climates; start seeds indoors 6–8 weeks before last frost and transplant after danger of frost has passed. The bushy plants produce prolific small fruits enclosed in papery husks and often sprawl without support — a tomato cage or light staking helps. Harvest when the papery husk has dried to tan-brown and the golden berry inside detaches easily. Fallen fruits left in their husks on the ground remain fresh for several weeks.','["general horticultural reference", "university extension guides"]','{"slug": "ground-cherry-cape-gooseberry", "common_name": "Ground Cherry / Cape Gooseberry", "scientific_name": "Physalis peruviana / Physalis pruinosa", "category": "berry", "subcategory": "ground fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 75, "max": 100}, "maturity_from": "transplant", "sow_method": "transplant", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Transplant starts after all frost danger has passed; start seeds indoors 6–8 weeks before last frost."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 36}, "sun": "full", "water": "moderate", "directions": "Ground cherries are grown as warm-season annuals in most climates; start seeds indoors 6–8 weeks before last frost and transplant after danger of frost has passed. The bushy plants produce prolific small fruits enclosed in papery husks and often sprawl without support — a tomato cage or light staking helps. Harvest when the papery husk has dried to tan-brown and the golden berry inside detaches easily. Fallen fruits left in their husks on the ground remain fresh for several weeks.", "sources": ["general horticultural reference", "university extension guides"]}')
