INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('half-high-blueberry','Half-High Blueberry','Vaccinium corymbosum x angustifolium','berry','shrub fruit',NULL,NULL,NULL,NULL,730,1095,'transplant','transplant','perennial','hardy','spring',0,4,'Plant two or more compatible cultivars in early spring in very acidic soil; half-high types excel in zones 3–5 where standard highbush varieties suffer winter dieback.',3,6,36,60,24,48,36,60,'full','moderate','Half-high blueberries are crosses between highbush and lowbush species, combining the large-berry quality of highbush with the extreme cold hardiness of lowbush — cultivars such as ''Northblue'', ''Northcountry'', and ''Polaris'' survive to -35°F when snow-covered. Maintain soil pH between 4.5 and 5.0 and mulch heavily with pine bark or sawdust. Cross-pollination between two compatible cultivars improves berry size and total yield. Pruning is minimal for the first five years; thereafter remove the thickest, oldest canes each late winter to encourage fresh productive wood.','["general horticultural reference", "university extension guides"]','{"slug": "half-high-blueberry", "common_name": "Half-High Blueberry", "scientific_name": "Vaccinium corymbosum x angustifolium", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant two or more compatible cultivars in early spring in very acidic soil; half-high types excel in zones 3–5 where standard highbush varieties suffer winter dieback."}, "usda_zones": {"min": 3, "max": 6}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 36, "max": 60}, "sun": "full", "water": "moderate", "directions": "Half-high blueberries are crosses between highbush and lowbush species, combining the large-berry quality of highbush with the extreme cold hardiness of lowbush — cultivars such as ''Northblue'', ''Northcountry'', and ''Polaris'' survive to -35°F when snow-covered. Maintain soil pH between 4.5 and 5.0 and mulch heavily with pine bark or sawdust. Cross-pollination between two compatible cultivars improves berry size and total yield. Pruning is minimal for the first five years; thereafter remove the thickest, oldest canes each late winter to encourage fresh productive wood.", "sources": ["general horticultural reference", "university extension guides"]}')
