  VALUES ('wineberry-japanese','Japanese Wineberry','Rubus phoenicolasius','berry','cane fruit',NULL,NULL,NULL,NULL,365,548,'transplant','transplant','perennial','hardy','spring',0,4,'Plant bare-root or container canes in spring on a trellis in well-drained soil; note that Japanese wineberry is invasive in parts of the eastern U.S. — check local regulations before planting.',5,8,36,60,48,96,36,60,'full','moderate','Japanese wineberry is an Asian Rubus species with distinctive red glandular-hairy canes that are ornamentally attractive year-round. It fruits on floricanes in mid-to-late summer, bearing translucent orange-red to deep ruby berries enclosed in a sticky calyx that opens at ripeness — a feature that helps distinguish ripe from unripe fruit and reduces bird predation. Cut all fruited floricanes to the ground after harvest and thin primocanes to 4–6 per hill for next year''s crop. The species naturalizes aggressively in disturbed areas in the eastern U.S. and is considered invasive in several states; confirm legality before planting.','["general horticultural reference", "university extension guides"]','{"slug": "wineberry-japanese", "common_name": "Japanese Wineberry", "scientific_name": "Rubus phoenicolasius", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant bare-root or container canes in spring on a trellis in well-drained soil; note that Japanese wineberry is invasive in parts of the eastern U.S. — check local regulations before planting."}, "usda_zones": {"min": 5, "max": 8}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 48, "max": 96}, "spread_in": {"min": 36, "max": 60}, "sun": "full", "water": "moderate", "directions": "Japanese wineberry is an Asian Rubus species with distinctive red glandular-hairy canes that are ornamentally attractive year-round. It fruits on floricanes in mid-to-late summer, bearing translucent orange-red to deep ruby berries enclosed in a sticky calyx that opens at ripeness — a feature that helps distinguish ripe from unripe fruit and reduces bird predation. Cut all fruited floricanes to the ground after harvest and thin primocanes to 4–6 per hill for next year''s crop. The species naturalizes aggressively in disturbed areas in the eastern U.S. and is considered invasive in several states; confirm legality before planting.", "sources": ["general horticultural reference", "university extension guides"]}')
