  VALUES ('jostaberry','Jostaberry','Ribes x nidigrolaria','berry','shrub fruit',NULL,NULL,NULL,NULL,548,730,'transplant','cutting','perennial','hardy','spring',0,4,'Plant hardwood cuttings or bare-root stock in early spring; jostaberry is self-fertile and a single plant will produce fruit.',3,8,60,72,48,72,60,72,'partial','moderate','Jostaberry is a thornless hybrid of black currant and gooseberry, combining the vigor and disease resistance of both parents with a flavor profile between the two. It is significantly larger and more vigorous than either parent, and is notably resistant to gooseberry mildew and currant big bud mite. Prune as you would a black currant — remove one-third of the oldest canes each late winter to stimulate new productive growth. Harvest in mid-summer when berries have turned from red to very dark purple-black and developed a sweet, slightly musky flavor; verify local Ribes restrictions before planting.','["general horticultural reference", "RHS Fruit Garden Displayed"]','{"slug": "jostaberry", "common_name": "Jostaberry", "scientific_name": "Ribes x nidigrolaria", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 548, "max": 730}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant hardwood cuttings or bare-root stock in early spring; jostaberry is self-fertile and a single plant will produce fruit."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 60, "max": 72}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 60, "max": 72}, "sun": "partial", "water": "moderate", "directions": "Jostaberry is a thornless hybrid of black currant and gooseberry, combining the vigor and disease resistance of both parents with a flavor profile between the two. It is significantly larger and more vigorous than either parent, and is notably resistant to gooseberry mildew and currant big bud mite. Prune as you would a black currant — remove one-third of the oldest canes each late winter to stimulate new productive growth. Harvest in mid-summer when berries have turned from red to very dark purple-black and developed a sweet, slightly musky flavor; verify local Ribes restrictions before planting.", "sources": ["general horticultural reference", "RHS Fruit Garden Displayed"]}')
