  VALUES ('kiwiberry','Kiwiberry','Actinidia arguta','berry','vine fruit',NULL,NULL,NULL,NULL,1460,2190,'transplant','cutting','perennial','hardy','last_frost',0,2,'Plant after last frost with a very sturdy pergola or trellis; self-fertile cultivars such as ''Issai'' are suitable for single-plant planting.',4,9,96,180,120,240,120,240,'full','moderate','Kiwiberry is a compact-fruited selection of hardy kiwi (Actinidia arguta) grown specifically for smooth-skinned, grape-sized fruits that are eaten whole without peeling — they have the same flavor as standard kiwifruit but ripen 3–4 weeks earlier. Self-fertile cultivars such as ''Issai'' and ''Ken''s Red'' allow single-plant production, but yields are higher when a male pollenizer is present. The extremely vigorous vines require a heavy-gauge trellis or pergola capable of bearing hundreds of pounds of vine and fruit; prune hard each dormant season to renewal spurs. Harvest when fruits yield to gentle pressure and taste sweet with no starchiness.','["general horticultural reference", "Oregon State University Extension"]','{"slug": "kiwiberry", "common_name": "Kiwiberry", "scientific_name": "Actinidia arguta", "category": "berry", "subcategory": "vine fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2190}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Plant after last frost with a very sturdy pergola or trellis; self-fertile cultivars such as ''Issai'' are suitable for single-plant planting."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 96, "max": 180}, "height_in": {"min": 120, "max": 240}, "spread_in": {"min": 120, "max": 240}, "sun": "full", "water": "moderate", "directions": "Kiwiberry is a compact-fruited selection of hardy kiwi (Actinidia arguta) grown specifically for smooth-skinned, grape-sized fruits that are eaten whole without peeling — they have the same flavor as standard kiwifruit but ripen 3–4 weeks earlier. Self-fertile cultivars such as ''Issai'' and ''Ken''s Red'' allow single-plant production, but yields are higher when a male pollenizer is present. The extremely vigorous vines require a heavy-gauge trellis or pergola capable of bearing hundreds of pounds of vine and fruit; prune hard each dormant season to renewal spurs. Harvest when fruits yield to gentle pressure and taste sweet with no starchiness.", "sources": ["general horticultural reference", "Oregon State University Extension"]}')
