INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('loganberry','Loganberry','Rubus x loganobaccus','berry','cane fruit',NULL,NULL,NULL,NULL,365,548,'transplant','cutting','perennial','half-hardy','spring',0,4,'Plant rooted tip cuttings in early spring after last frost; provide a sturdy T-trellis at planting since canes reach 8–10 ft.',6,9,72,96,48,72,84,120,'full','moderate','Loganberry, a natural hybrid of blackberry and raspberry discovered in California in the 1880s, produces long, dark red, tart berries that are excellent for jams and wine. Train the vigorous trailing canes on a two- or three-wire trellis, weaving new primocanes along the wires during the growing season. After the summer harvest, cut all floricanes that bore fruit to the ground and secure the new primocanes in their place. The thornless ''LY59'' strain is preferred for home gardens; in borderline zones, lay canes down and mulch after leaf drop.','["general horticultural reference", "University of California Cooperative Extension"]','{"slug": "loganberry", "common_name": "Loganberry", "scientific_name": "Rubus x loganobaccus", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted tip cuttings in early spring after last frost; provide a sturdy T-trellis at planting since canes reach 8–10 ft."}, "usda_zones": {"min": 6, "max": 9}, "spacing_in": {"min": 72, "max": 96}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 84, "max": 120}, "sun": "full", "water": "moderate", "directions": "Loganberry, a natural hybrid of blackberry and raspberry discovered in California in the 1880s, produces long, dark red, tart berries that are excellent for jams and wine. Train the vigorous trailing canes on a two- or three-wire trellis, weaving new primocanes along the wires during the growing season. After the summer harvest, cut all floricanes that bore fruit to the ground and secure the new primocanes in their place. The thornless ''LY59'' strain is preferred for home gardens; in borderline zones, lay canes down and mulch after leaf drop.", "sources": ["general horticultural reference", "University of California Cooperative Extension"]}')
