INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('marionberry','Marionberry','Rubus hybrid','berry','cane fruit',NULL,NULL,NULL,NULL,365,548,'transplant','cutting','perennial','half-hardy','spring',0,4,'Plant bare-root or tip-rooted canes in early spring as soon as soil is workable, with a T-trellis capable of handling 8-ft canes installed at the same time.',6,9,60,84,36,60,84,120,'full','moderate','Marionberry is a trailing blackberry hybrid (Chehalem x Olallie) developed by Oregon State University and is the most widely grown blackberry in the Pacific Northwest, prized for its deep, complex, slightly tart flavor. The thorny, vigorous canes must be trained along a two-wire trellis; weave new primocanes along the lower wire during the summer and tie them to the upper wire the following spring. After the mid-summer harvest, remove all fruited floricanes at the base and train the new primocanes into their place. Marionberries are sensitive to freezes below about 10°F; in colder areas, protect canes over winter.','["general horticultural reference", "Oregon State University Extension Service"]','{"slug": "marionberry", "common_name": "Marionberry", "scientific_name": "Rubus hybrid", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant bare-root or tip-rooted canes in early spring as soon as soil is workable, with a T-trellis capable of handling 8-ft canes installed at the same time."}, "usda_zones": {"min": 6, "max": 9}, "spacing_in": {"min": 60, "max": 84}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 84, "max": 120}, "sun": "full", "water": "moderate", "directions": "Marionberry is a trailing blackberry hybrid (Chehalem x Olallie) developed by Oregon State University and is the most widely grown blackberry in the Pacific Northwest, prized for its deep, complex, slightly tart flavor. The thorny, vigorous canes must be trained along a two-wire trellis; weave new primocanes along the lower wire during the summer and tie them to the upper wire the following spring. After the mid-summer harvest, remove all fruited floricanes at the base and train the new primocanes into their place. Marionberries are sensitive to freezes below about 10°F; in colder areas, protect canes over winter.", "sources": ["general horticultural reference", "Oregon State University Extension Service"]}')
