  VALUES ('mayhaw','Mayhaw','Crataegus aestivalis','berry','shrub fruit',90,180,40,55,1825,2555,'transplant','transplant','perennial','hardy','spring',0,4,'Plant grafted named cultivars in early spring in moist to wet, acidic, bottomland soil for best fruit production.',6,9,120,180,120,240,120,180,'full','high','Mayhaw is a small flowering hawthorn tree native to swampy bottomlands of the Gulf South, prized for its tart red fruits — ripening in May — that make exceptional jelly of deep pink color. It is well adapted to poorly drained, acidic, wet soil and is often planted along pond edges or low spots. Grafted cultivars such as ''Big Red'', ''Super Berry'', and ''Texas Star'' bear much more reliably and earlier than seedlings. Fruit is harvested by spreading tarps under the tree and shaking, or by netting floating fruit from ponds in traditional southern production.','["general horticultural reference", "LSU AgCenter"]','{"slug": "mayhaw", "common_name": "Mayhaw", "scientific_name": "Crataegus aestivalis", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": 90, "max": 180}, "germination_soil_temp_f": {"min": 40, "max": 55}, "days_to_maturity": {"min": 1825, "max": 2555}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant grafted named cultivars in early spring in moist to wet, acidic, bottomland soil for best fruit production."}, "usda_zones": {"min": 6, "max": 9}, "spacing_in": {"min": 120, "max": 180}, "height_in": {"min": 120, "max": 240}, "spread_in": {"min": 120, "max": 180}, "sun": "full", "water": "high", "directions": "Mayhaw is a small flowering hawthorn tree native to swampy bottomlands of the Gulf South, prized for its tart red fruits — ripening in May — that make exceptional jelly of deep pink color. It is well adapted to poorly drained, acidic, wet soil and is often planted along pond edges or low spots. Grafted cultivars such as ''Big Red'', ''Super Berry'', and ''Texas Star'' bear much more reliably and earlier than seedlings. Fruit is harvested by spreading tarps under the tree and shaking, or by netting floating fruit from ponds in traditional southern production.", "sources": ["general horticultural reference", "LSU AgCenter"]}')
