INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('maypop','Maypop (Native Passionflower)','Passiflora incarnata','berry','vine fruit',14,30,70,85,365,548,'transplant','transplant','perennial','hardy','last_frost',0,2,'Plant after last frost in full sun with a trellis or fence; roots are cold-hardy to zone 6 and re-sprout from the roots each spring.',6,10,36,60,72,120,60,120,'full','low','Maypop (Passiflora incarnata) is a North American native passionflower that is cold-hardy to zone 6, distinguishing it clearly from the tropical Passiflora edulis (passionfruit). The ornamental lavender flowers are stunning and the egg-sized yellow-green fruits have sweet, aromatic pulp similar to tropical passionfruit. Plants die back to the roots in zone 6–7 winters and re-sprout vigorously in late spring — do not remove the crown before new growth appears. Plant cross-pollinators nearby (more than one plant) for reliable fruit set. Harvest when fruits turn yellowish-green and fall or detach easily.','["general horticultural reference", "Lady Bird Johnson Wildflower Center"]','{"slug": "maypop", "common_name": "Maypop (Native Passionflower)", "scientific_name": "Passiflora incarnata", "category": "berry", "subcategory": "vine fruit", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Plant after last frost in full sun with a trellis or fence; roots are cold-hardy to zone 6 and re-sprout from the roots each spring."}, "usda_zones": {"min": 6, "max": 10}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 72, "max": 120}, "spread_in": {"min": 60, "max": 120}, "sun": "full", "water": "low", "directions": "Maypop (Passiflora incarnata) is a North American native passionflower that is cold-hardy to zone 6, distinguishing it clearly from the tropical Passiflora edulis (passionfruit). The ornamental lavender flowers are stunning and the egg-sized yellow-green fruits have sweet, aromatic pulp similar to tropical passionfruit. Plants die back to the roots in zone 6–7 winters and re-sprout vigorously in late spring — do not remove the crown before new growth appears. Plant cross-pollinators nearby (more than one plant) for reliable fruit set. Harvest when fruits turn yellowish-green and fall or detach easily.", "sources": ["general horticultural reference", "Lady Bird Johnson Wildflower Center"]}')
