  VALUES ('muscadine-grape','Muscadine Grape','Vitis rotundifolia','berry','vine fruit',NULL,NULL,NULL,NULL,1095,1460,'transplant','cutting','perennial','half-hardy','spring',0,4,'Plant rooted cuttings or container vines in early spring; use self-fertile cultivars or plant one male (''bronze'') vine per 4–6 female vines.',7,10,120,240,72,120,120,240,'full','low','Muscadine grapes are native to the southeastern U.S. and far more heat- and disease-resistant than European or labrusca types. Train to a single trunk with two permanent lateral cordons on a high-wire trellis at 5–6 ft; spur-prune cordons each dormant season to 2–3 bud spurs spaced 4–6 in apart. Many cultivars are not self-fertile, so check pollination requirements before purchasing. Harvest by shaking or hand-picking individual berries when they reach full color and slip easily from the skin.','["general horticultural reference", "university extension guides"]','{"slug": "muscadine-grape", "common_name": "Muscadine Grape", "scientific_name": "Vitis rotundifolia", "category": "berry", "subcategory": "vine fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted cuttings or container vines in early spring; use self-fertile cultivars or plant one male (''bronze'') vine per 4–6 female vines."}, "usda_zones": {"min": 7, "max": 10}, "spacing_in": {"min": 120, "max": 240}, "height_in": {"min": 72, "max": 120}, "spread_in": {"min": 120, "max": 240}, "sun": "full", "water": "low", "directions": "Muscadine grapes are native to the southeastern U.S. and far more heat- and disease-resistant than European or labrusca types. Train to a single trunk with two permanent lateral cordons on a high-wire trellis at 5–6 ft; spur-prune cordons each dormant season to 2–3 bud spurs spaced 4–6 in apart. Many cultivars are not self-fertile, so check pollination requirements before purchasing. Harvest by shaking or hand-picking individual berries when they reach full color and slip easily from the skin.", "sources": ["general horticultural reference", "university extension guides"]}')
