INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('nagoonberry','Nagoonberry','Rubus arcticus','berry','ground fruit',NULL,NULL,NULL,NULL,730,1095,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions or rooted runners in spring in moist, acidic, peaty soil; requires cool summer temperatures and will not thrive where summers are hot.',2,5,12,18,4,10,18,36,'partial','high','The nagoonberry (arctic raspberry) is a low-growing, rhizomatous Rubus native to Alaska, Scandinavia, and northern Russia, bearing small, deep rose-red berries in early summer that are considered among the finest-flavored wild berries in the boreal world — exceptionally fragrant, rich, and complex. Plants require cool, moist, acidic bog or tundra-edge conditions (pH 4.5–5.5) and cool summer temperatures; they will not survive heat and are rarely successful south of zone 5 except at high elevations. Propagate by dividing rhizomes in early spring. The Finnish-bred cultivar ''Mespi'' (a nagoonberry x Arctic raspberry hybrid) shows improved yield and adaptability while retaining the outstanding flavor of the wild species.','["general horticultural reference", "university extension guides"]','{"slug": "nagoonberry", "common_name": "Nagoonberry", "scientific_name": "Rubus arcticus", "category": "berry", "subcategory": "ground fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions or rooted runners in spring in moist, acidic, peaty soil; requires cool summer temperatures and will not thrive where summers are hot."}, "usda_zones": {"min": 2, "max": 5}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 4, "max": 10}, "spread_in": {"min": 18, "max": 36}, "sun": "partial", "water": "high", "directions": "The nagoonberry (arctic raspberry) is a low-growing, rhizomatous Rubus native to Alaska, Scandinavia, and northern Russia, bearing small, deep rose-red berries in early summer that are considered among the finest-flavored wild berries in the boreal world — exceptionally fragrant, rich, and complex. Plants require cool, moist, acidic bog or tundra-edge conditions (pH 4.5–5.5) and cool summer temperatures; they will not survive heat and are rarely successful south of zone 5 except at high elevations. Propagate by dividing rhizomes in early spring. The Finnish-bred cultivar ''Mespi'' (a nagoonberry x Arctic raspberry hybrid) shows improved yield and adaptability while retaining the outstanding flavor of the wild species.", "sources": ["general horticultural reference", "university extension guides"]}')
