  VALUES ('nanking-cherry','Nanking Cherry','Prunus tomentosa','berry','shrub fruit',60,120,40,55,730,1095,'transplant','transplant','perennial','hardy','spring',0,4,'Plant two or more plants for cross-pollination in early spring; extremely adaptable to cold, dry, or alkaline sites.',2,7,60,96,60,96,60,96,'full','low','Nanking cherry is one of the hardiest fruiting shrubs available, reliably surviving temperatures below -40°F and tolerating poor, dry, or alkaline soils. The abundant small red cherries ripen in early summer and have a sweet, slightly tart flavor excellent for jams, juices, and fresh eating. Two or more plants are needed for cross-pollination; plants flower very early in spring and may need frost protection of blossoms in zones 3–4 during cold snaps. Prune after harvest to remove dead wood and open the canopy; the shrub is generally very healthy with minimal pest and disease problems.','["general horticultural reference", "South Dakota State University Extension"]','{"slug": "nanking-cherry", "common_name": "Nanking Cherry", "scientific_name": "Prunus tomentosa", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": 60, "max": 120}, "germination_soil_temp_f": {"min": 40, "max": 55}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant two or more plants for cross-pollination in early spring; extremely adaptable to cold, dry, or alkaline sites."}, "usda_zones": {"min": 2, "max": 7}, "spacing_in": {"min": 60, "max": 96}, "height_in": {"min": 60, "max": 96}, "spread_in": {"min": 60, "max": 96}, "sun": "full", "water": "low", "directions": "Nanking cherry is one of the hardiest fruiting shrubs available, reliably surviving temperatures below -40°F and tolerating poor, dry, or alkaline soils. The abundant small red cherries ripen in early summer and have a sweet, slightly tart flavor excellent for jams, juices, and fresh eating. Two or more plants are needed for cross-pollination; plants flower very early in spring and may need frost protection of blossoms in zones 3–4 during cold snaps. Prune after harvest to remove dead wood and open the canopy; the shrub is generally very healthy with minimal pest and disease problems.", "sources": ["general horticultural reference", "South Dakota State University Extension"]}')
