  VALUES ('oregon-grape','Oregon Grape','Mahonia aquifolium','berry','shrub fruit',NULL,NULL,NULL,NULL,730,1095,'transplant','transplant','perennial','hardy','spring',0,4,'Plant container stock in spring or fall in well-drained, slightly acidic soil; thrives in dry shade where few other fruiting shrubs succeed.',5,9,36,60,36,72,36,60,'shade','low','Oregon grape is a native Pacific Northwest evergreen shrub with holly-like spiny leaves that produces clusters of tart, powder-blue berries in midsummer — one of the most shade- and drought-tolerant edible-fruiting shrubs available. The berries are too tart to eat fresh in quantity but are excellent for jellies, syrups, and wine when sweetened; they are high in berberine, a compound with traditional medicinal use. Plant in groups of three or more for best cross-pollination and fruit set. Prune by removing the oldest, leggiest canes at the base every few years to encourage compact, multi-stemmed growth.','["general horticultural reference", "university extension guides"]','{"slug": "oregon-grape", "common_name": "Oregon Grape", "scientific_name": "Mahonia aquifolium", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant container stock in spring or fall in well-drained, slightly acidic soil; thrives in dry shade where few other fruiting shrubs succeed."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 36, "max": 60}, "sun": "shade", "water": "low", "directions": "Oregon grape is a native Pacific Northwest evergreen shrub with holly-like spiny leaves that produces clusters of tart, powder-blue berries in midsummer — one of the most shade- and drought-tolerant edible-fruiting shrubs available. The berries are too tart to eat fresh in quantity but are excellent for jellies, syrups, and wine when sweetened; they are high in berberine, a compound with traditional medicinal use. Plant in groups of three or more for best cross-pollination and fruit set. Prune by removing the oldest, leggiest canes at the base every few years to encourage compact, multi-stemmed growth.", "sources": ["general horticultural reference", "university extension guides"]}')
