  VALUES ('partridgeberry','Partridgeberry','Mitchella repens','berry','ground fruit',30,90,55,65,1095,1825,'transplant','division','perennial','hardy','spring',0,4,'Plant rooted cuttings or transplants in spring in humus-rich, strongly acidic, moist woodland soil in full shade.',3,9,6,12,1,3,12,24,'shade','moderate','Partridgeberry is a native North American groundcover for shaded, acidic woodland gardens, forming a dense mat of evergreen, trailing stems barely 2 in tall. The bright red, twin-fused berries persist through winter and are edible but bland and seedy, making them more valuable as wildlife food and ornamental ground cover than for human harvest. Each berry is the fused product of two twin flowers — visible as two distinct calyxes on mature fruit. Grow in strongly acidic soil (pH 4.5–5.5) under deciduous trees; it is slow to establish but extremely long-lived with virtually no maintenance needed.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "partridgeberry", "common_name": "Partridgeberry", "scientific_name": "Mitchella repens", "category": "berry", "subcategory": "ground fruit", "days_to_germination": {"min": 30, "max": 90}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted cuttings or transplants in spring in humus-rich, strongly acidic, moist woodland soil in full shade."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 1, "max": 3}, "spread_in": {"min": 12, "max": 24}, "sun": "shade", "water": "moderate", "directions": "Partridgeberry is a native North American groundcover for shaded, acidic woodland gardens, forming a dense mat of evergreen, trailing stems barely 2 in tall. The bright red, twin-fused berries persist through winter and are edible but bland and seedy, making them more valuable as wildlife food and ornamental ground cover than for human harvest. Each berry is the fused product of two twin flowers — visible as two distinct calyxes on mature fruit. Grow in strongly acidic soil (pH 4.5–5.5) under deciduous trees; it is slow to establish but extremely long-lived with virtually no maintenance needed.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
