  VALUES ('passionfruit','Passionfruit','Passiflora edulis','berry','vine fruit',NULL,NULL,NULL,NULL,365,548,'transplant','transplant','perennial','tender','spring',0,4,'Plant after all frost danger has passed in zones 9–11; in cooler zones grow in large containers and overwinter indoors.',9,11,72,120,96,180,72,120,'full','moderate','Passionfruit is a vigorous, tendril-climbing vine requiring a sturdy wire trellis or fence. Train the main stem vertically and allow lateral shoots to drape horizontally from the top — these laterals bear the flowers and fruit. Prune heavily after fruiting to rejuvenate the vine and maintain productive growth. Harvest when the fruit skin begins to wrinkle and the fruit falls or detaches easily; purple cultivars are generally more cold-tolerant than yellow types.','["general horticultural reference", "university extension guides"]','{"slug": "passionfruit", "common_name": "Passionfruit", "scientific_name": "Passiflora edulis", "category": "berry", "subcategory": "vine fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant after all frost danger has passed in zones 9–11; in cooler zones grow in large containers and overwinter indoors."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 72, "max": 120}, "height_in": {"min": 96, "max": 180}, "spread_in": {"min": 72, "max": 120}, "sun": "full", "water": "moderate", "directions": "Passionfruit is a vigorous, tendril-climbing vine requiring a sturdy wire trellis or fence. Train the main stem vertically and allow lateral shoots to drape horizontally from the top — these laterals bear the flowers and fruit. Prune heavily after fruiting to rejuvenate the vine and maintain productive growth. Harvest when the fruit skin begins to wrinkle and the fruit falls or detaches easily; purple cultivars are generally more cold-tolerant than yellow types.", "sources": ["general horticultural reference", "university extension guides"]}')
