  VALUES ('pineberry','Pineberry','Fragaria x ananassa','berry','ground fruit',NULL,NULL,NULL,NULL,365,425,'transplant','transplant','perennial','hardy','last_frost',-2,2,'Plant bare-root crowns in early spring with crowns level at the soil surface; must be grown near standard red strawberries for adequate pollination.',4,9,12,18,6,10,12,18,'full','moderate','Pineberry is a white-fruited strawberry cultivar (largely derived from the South American species Fragaria chiloensis crossed with F. x ananassa) that produces pale cream-white berries with red achenes and a distinctive pineapple-like aroma when fully ripe. Pineberries have low self-fertility and require a red-fruiting strawberry variety planted nearby as a pollinator for adequate fruit set. Grow exactly as you would a june-bearing or everbearing strawberry, removing blossoms the first season to build root strength. Harvest when berries are white to pale pink with red seeds and give off a sweet pineapple fragrance.','["general horticultural reference", "university extension guides"]','{"slug": "pineberry", "common_name": "Pineberry", "scientific_name": "Fragaria x ananassa", "category": "berry", "subcategory": "ground fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 425}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Plant bare-root crowns in early spring with crowns level at the soil surface; must be grown near standard red strawberries for adequate pollination."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 6, "max": 10}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Pineberry is a white-fruited strawberry cultivar (largely derived from the South American species Fragaria chiloensis crossed with F. x ananassa) that produces pale cream-white berries with red achenes and a distinctive pineapple-like aroma when fully ripe. Pineberries have low self-fertility and require a red-fruiting strawberry variety planted nearby as a pollinator for adequate fruit set. Grow exactly as you would a june-bearing or everbearing strawberry, removing blossoms the first season to build root strength. Harvest when berries are white to pale pink with red seeds and give off a sweet pineapple fragrance.", "sources": ["general horticultural reference", "university extension guides"]}')
