  VALUES ('pink-currant','Pink Currant','Ribes rubrum (pink-fruited cultivars)','berry','shrub fruit',NULL,NULL,NULL,NULL,548,730,'transplant','cutting','perennial','hardy','spring',0,3,'Plant hardwood cuttings or bare-root stock in early spring; grows well alongside red and white currants with identical cultural requirements.',3,7,48,60,36,60,36,60,'partial','moderate','Pink currants are naturally occurring or selected mutations of red currant (Ribes rubrum) producing pale rose-pink to blush-colored berries that are milder and sweeter than the typical red forms — popular cultivars include ''Pink Champagne'' and ''Gloire de Sablons''. Culture is identical to red currant: plant in cool, well-drained soil with a pH of 6.0–6.5 and prune each late winter to retain 8–12 mixed-age canes, removing any older than 5 years. The translucent pink strigs are ornamentally striking and ripen slightly earlier than most red currants. Check state Ribes restrictions before ordering.','["general horticultural reference", "university extension guides"]','{"slug": "pink-currant", "common_name": "Pink Currant", "scientific_name": "Ribes rubrum (pink-fruited cultivars)", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 548, "max": 730}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 3}, "note": "Plant hardwood cuttings or bare-root stock in early spring; grows well alongside red and white currants with identical cultural requirements."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 48, "max": 60}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 36, "max": 60}, "sun": "partial", "water": "moderate", "directions": "Pink currants are naturally occurring or selected mutations of red currant (Ribes rubrum) producing pale rose-pink to blush-colored berries that are milder and sweeter than the typical red forms — popular cultivars include ''Pink Champagne'' and ''Gloire de Sablons''. Culture is identical to red currant: plant in cool, well-drained soil with a pH of 6.0–6.5 and prune each late winter to retain 8–12 mixed-age canes, removing any older than 5 years. The translucent pink strigs are ornamentally striking and ripen slightly earlier than most red currants. Check state Ribes restrictions before ordering.", "sources": ["general horticultural reference", "university extension guides"]}')
