  VALUES ('purple-flowering-raspberry','Purple-Flowering Raspberry','Rubus odoratus','berry','cane fruit',NULL,NULL,NULL,NULL,730,1095,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions or bare-root stock in spring in moist, well-drained, humus-rich soil; tolerates more shade than most Rubus species — ideal for woodland edges.',3,9,36,60,48,72,48,96,'partial','moderate','Purple-flowering raspberry is a thornless native North American Rubus producing large, showy rose-purple flowers attractive to pollinators followed by broad, flat, raspberry-like fruits in midsummer. The berries are edible but dry and seedy — more appealing to wildlife than humans — making this species primarily grown as an ornamental fruiting shrub for naturalizing woodland edges and native plantings. It spreads vigorously by root suckering and can colonize large areas; control spread by removing suckers as needed at the perimeter. No trellising is required; prune out older, dying canes to the ground in late winter to encourage fresh, vigorous shoots.','["general horticultural reference", "university extension guides"]','{"slug": "purple-flowering-raspberry", "common_name": "Purple-Flowering Raspberry", "scientific_name": "Rubus odoratus", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions or bare-root stock in spring in moist, well-drained, humus-rich soil; tolerates more shade than most Rubus species — ideal for woodland edges."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 48, "max": 96}, "sun": "partial", "water": "moderate", "directions": "Purple-flowering raspberry is a thornless native North American Rubus producing large, showy rose-purple flowers attractive to pollinators followed by broad, flat, raspberry-like fruits in midsummer. The berries are edible but dry and seedy — more appealing to wildlife than humans — making this species primarily grown as an ornamental fruiting shrub for naturalizing woodland edges and native plantings. It spreads vigorously by root suckering and can colonize large areas; control spread by removing suckers as needed at the perimeter. No trellising is required; prune out older, dying canes to the ground in late winter to encourage fresh, vigorous shoots.", "sources": ["general horticultural reference", "university extension guides"]}')
