  VALUES ('rabbiteye-blueberry','Rabbiteye Blueberry','Vaccinium virgatum','berry','shrub fruit',NULL,NULL,NULL,NULL,730,1095,'transplant','transplant','perennial','half-hardy','spring',0,4,'Plant two or more compatible cultivars in early spring in acidic, well-drained soil; rabbiteye types require cross-pollination for good yields.',7,9,60,84,72,180,60,120,'full','moderate','Rabbiteye blueberries are native to the southeastern U.S. and are far more heat- and drought-tolerant than northern highbush types, thriving in zones 7–9 with minimal chilling hours. Soil pH must be maintained between 4.5 and 5.5; amend with elemental sulfur well in advance of planting and mulch thickly with pine bark or wood chips. Plant at least two different cultivars from the same ripening window (early, mid, or late) for adequate cross-pollination. Fruit typically ripens over a 4–6-week window in summer, turning fully blue-black and softening before peak sweetness — taste-test before harvesting large quantities.','["general horticultural reference", "university extension guides"]','{"slug": "rabbiteye-blueberry", "common_name": "Rabbiteye Blueberry", "scientific_name": "Vaccinium virgatum", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant two or more compatible cultivars in early spring in acidic, well-drained soil; rabbiteye types require cross-pollination for good yields."}, "usda_zones": {"min": 7, "max": 9}, "spacing_in": {"min": 60, "max": 84}, "height_in": {"min": 72, "max": 180}, "spread_in": {"min": 60, "max": 120}, "sun": "full", "water": "moderate", "directions": "Rabbiteye blueberries are native to the southeastern U.S. and are far more heat- and drought-tolerant than northern highbush types, thriving in zones 7–9 with minimal chilling hours. Soil pH must be maintained between 4.5 and 5.5; amend with elemental sulfur well in advance of planting and mulch thickly with pine bark or wood chips. Plant at least two different cultivars from the same ripening window (early, mid, or late) for adequate cross-pollination. Fruit typically ripens over a 4–6-week window in summer, turning fully blue-black and softening before peak sweetness — taste-test before harvesting large quantities.", "sources": ["general horticultural reference", "university extension guides"]}')
