  VALUES ('aronia-red','Red Chokeberry','Aronia arbutifolia','berry','shrub fruit',NULL,NULL,NULL,NULL,548,730,'transplant','transplant','perennial','hardy','spring',0,4,'Plant bare-root or container stock in early spring; adapts to a wide range of soils including wet, poorly drained sites.',4,9,36,60,48,96,36,60,'full','low','Red chokeberry (Aronia arbutifolia) is a taller, more upright native shrub than its black-fruited relative, bearing bright red berries that ripen in fall and persist well into winter, providing exceptional wildlife food and four-season ornamental interest. The berries are intensely astringent fresh but soften after frost and are suitable for jellies, juices, and wines with added sweetener. The cultivar ''Brilliantissima'' is widely grown for its especially vibrant fall foliage and heavy fruit set. Prune oldest canes to the ground every 3–4 years to control suckering and maintain vigor.','["general horticultural reference", "university extension guides"]','{"slug": "aronia-red", "common_name": "Red Chokeberry", "scientific_name": "Aronia arbutifolia", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 548, "max": 730}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant bare-root or container stock in early spring; adapts to a wide range of soils including wet, poorly drained sites."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 48, "max": 96}, "spread_in": {"min": 36, "max": 60}, "sun": "full", "water": "low", "directions": "Red chokeberry (Aronia arbutifolia) is a taller, more upright native shrub than its black-fruited relative, bearing bright red berries that ripen in fall and persist well into winter, providing exceptional wildlife food and four-season ornamental interest. The berries are intensely astringent fresh but soften after frost and are suitable for jellies, juices, and wines with added sweetener. The cultivar ''Brilliantissima'' is widely grown for its especially vibrant fall foliage and heavy fruit set. Prune oldest canes to the ground every 3–4 years to control suckering and maintain vigor.", "sources": ["general horticultural reference", "university extension guides"]}')
