  VALUES ('red-huckleberry','Red Huckleberry','Vaccinium parvifolium','berry','shrub fruit',NULL,NULL,NULL,NULL,1095,1460,'transplant','transplant','perennial','hardy','spring',0,4,'Plant in spring in very acidic, humus-rich soil or on decaying conifer wood; native to the Pacific Northwest understory and tolerates deep shade.',5,8,48,72,36,120,36,72,'partial','moderate','Red huckleberry is a Pacific Northwest native that naturally colonizes rotting conifer stumps and logs, requiring extremely acidic conditions (pH 4.0–5.0) and excellent drainage with abundant organic matter. The bright scarlet berries ripen in summer and are tart — excellent for jams, syrups, and pies — and are an important wildlife food for birds and bears. Established plants spread slowly by rhizomes and require minimal pruning; remove only dead or crossing branches in late winter. Difficult to transplant as a wild specimen; use nursery-grown container stock for best results.','["general horticultural reference", "university extension guides"]','{"slug": "red-huckleberry", "common_name": "Red Huckleberry", "scientific_name": "Vaccinium parvifolium", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring in very acidic, humus-rich soil or on decaying conifer wood; native to the Pacific Northwest understory and tolerates deep shade."}, "usda_zones": {"min": 5, "max": 8}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 36, "max": 120}, "spread_in": {"min": 36, "max": 72}, "sun": "partial", "water": "moderate", "directions": "Red huckleberry is a Pacific Northwest native that naturally colonizes rotting conifer stumps and logs, requiring extremely acidic conditions (pH 4.0–5.0) and excellent drainage with abundant organic matter. The bright scarlet berries ripen in summer and are tart — excellent for jams, syrups, and pies — and are an important wildlife food for birds and bears. Established plants spread slowly by rhizomes and require minimal pruning; remove only dead or crossing branches in late winter. Difficult to transplant as a wild specimen; use nursery-grown container stock for best results.", "sources": ["general horticultural reference", "university extension guides"]}')
