  VALUES ('salal','Salal','Gaultheria shallon','berry','shrub fruit',30,90,55,68,1095,1460,'transplant','division','perennial','hardy','spring',0,4,'Plant container-grown divisions in spring in moist, strongly acidic, well-drained soil under conifer canopy.',6,9,24,48,18,60,24,48,'shade','moderate','Salal is an evergreen native shrub of the Pacific Northwest coast, found beneath conifers from central California to Alaska, where it forms dense thickets on acidic, well-drained forest soils. The dark blue-purple berries are similar in size to a blueberry but have mealy, mildly sweet flesh and were an important food source for coastal Indigenous peoples, eaten fresh or dried into cakes. Salal is propagated by division or from container-grown nursery stock; seed germination is slow and unreliable. The glossy foliage is commercially valuable in the floral trade, and home growers can cut leathery stems for arrangements without harming the plant.','["general horticultural reference", "USDA Forest Service"]','{"slug": "salal", "common_name": "Salal", "scientific_name": "Gaultheria shallon", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": 30, "max": 90}, "germination_soil_temp_f": {"min": 55, "max": 68}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant container-grown divisions in spring in moist, strongly acidic, well-drained soil under conifer canopy."}, "usda_zones": {"min": 6, "max": 9}, "spacing_in": {"min": 24, "max": 48}, "height_in": {"min": 18, "max": 60}, "spread_in": {"min": 24, "max": 48}, "sun": "shade", "water": "moderate", "directions": "Salal is an evergreen native shrub of the Pacific Northwest coast, found beneath conifers from central California to Alaska, where it forms dense thickets on acidic, well-drained forest soils. The dark blue-purple berries are similar in size to a blueberry but have mealy, mildly sweet flesh and were an important food source for coastal Indigenous peoples, eaten fresh or dried into cakes. Salal is propagated by division or from container-grown nursery stock; seed germination is slow and unreliable. The glossy foliage is commercially valuable in the floral trade, and home growers can cut leathery stems for arrangements without harming the plant.", "sources": ["general horticultural reference", "USDA Forest Service"]}')
