INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('salmonberry','Salmonberry','Rubus spectabilis','berry','cane fruit',30,60,40,55,730,1095,'transplant','transplant','perennial','hardy','spring',0,4,'Plant divisions or rooted cuttings in spring in moist, humus-rich soil; salmonberry naturalizes readily in Pacific Northwest conditions.',5,9,48,72,48,96,48,96,'partial','high','Salmonberry is a Pacific Northwest native shrub that thrives in moist to wet, shaded sites along streams and forest edges, making it one of the few fruiting canes suitable for boggy ground. Fruits ripen very early — often in May or June — in shades from yellow-orange to deep red-salmon, with a mild, slightly bland flavor best suited to fresh eating or jams. Thin old canes to the ground each year after fruiting to maintain vigor, as the plant spreads by rhizomes and can form dense thickets. Wildlife value is extremely high; berries attract birds and bears within days of ripening.','["general horticultural reference", "USDA Forest Service"]','{"slug": "salmonberry", "common_name": "Salmonberry", "scientific_name": "Rubus spectabilis", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": 30, "max": 60}, "germination_soil_temp_f": {"min": 40, "max": 55}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions or rooted cuttings in spring in moist, humus-rich soil; salmonberry naturalizes readily in Pacific Northwest conditions."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 48, "max": 96}, "spread_in": {"min": 48, "max": 96}, "sun": "partial", "water": "high", "directions": "Salmonberry is a Pacific Northwest native shrub that thrives in moist to wet, shaded sites along streams and forest edges, making it one of the few fruiting canes suitable for boggy ground. Fruits ripen very early — often in May or June — in shades from yellow-orange to deep red-salmon, with a mild, slightly bland flavor best suited to fresh eating or jams. Thin old canes to the ground each year after fruiting to maintain vigor, as the plant spreads by rhizomes and can form dense thickets. Wildlife value is extremely high; berries attract birds and bears within days of ripening.", "sources": ["general horticultural reference", "USDA Forest Service"]}')
