  VALUES ('sand-cherry','Sand Cherry','Prunus pumila','berry','shrub fruit',NULL,NULL,NULL,NULL,548,730,'transplant','transplant','perennial','hardy','spring',0,4,'Plant bare-root or container stock in early spring in well-drained, sandy, or gravelly soil; sand cherry excels on poor, droughty sites where other stone fruits fail.',3,6,36,60,12,36,36,72,'full','low','Sand cherry is a small, sprawling native North American shrub bearing small dark purple to black cherries in midsummer with a flavor ranging from pleasantly tart to bitter depending on provenance and ripeness stage. The fruits are consumed fresh, dried, or processed into pemmican and preserves and were an important food source for Plains Indigenous peoples. The plant is extraordinarily cold-hardy and drought-tolerant once established, spreading by root suckers to form low thickets excellent for erosion control. Harvest when berries are fully dark and soft; cross-pollination between multiple plants improves fruit set significantly.','["general horticultural reference", "university extension guides"]','{"slug": "sand-cherry", "common_name": "Sand Cherry", "scientific_name": "Prunus pumila", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 548, "max": 730}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant bare-root or container stock in early spring in well-drained, sandy, or gravelly soil; sand cherry excels on poor, droughty sites where other stone fruits fail."}, "usda_zones": {"min": 3, "max": 6}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 12, "max": 36}, "spread_in": {"min": 36, "max": 72}, "sun": "full", "water": "low", "directions": "Sand cherry is a small, sprawling native North American shrub bearing small dark purple to black cherries in midsummer with a flavor ranging from pleasantly tart to bitter depending on provenance and ripeness stage. The fruits are consumed fresh, dried, or processed into pemmican and preserves and were an important food source for Plains Indigenous peoples. The plant is extraordinarily cold-hardy and drought-tolerant once established, spreading by root suckers to form low thickets excellent for erosion control. Harvest when berries are fully dark and soft; cross-pollination between multiple plants improves fruit set significantly.", "sources": ["general horticultural reference", "university extension guides"]}')
