INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sea-buckthorn','Sea Buckthorn','Hippophae rhamnoides','berry','shrub fruit',NULL,NULL,NULL,NULL,1095,1460,'transplant','cutting','perennial','hardy','spring',0,4,'Plant one male plant for every 5–7 female plants in early spring; sea buckthorn is wind-pollinated and needs close proximity between sexes.',3,7,72,120,72,180,72,120,'full','low','Sea buckthorn is a thorny, nitrogen-fixing shrub that thrives in poor, dry, sandy soils where most fruits struggle. It is dioecious and requires male plants for pollination — one male per 5–7 females; sex is not identifiable until first flowering, so purchase sexed plants. The tiny berries are borne directly on the branches in dense clusters and are difficult to harvest without damaging the plant; a common approach is to cut fruiting branches in fall and strip berries indoors or by freezing and shaking. The tart, orange berries are extremely high in vitamin C.','["general horticultural reference", "university extension guides"]','{"slug": "sea-buckthorn", "common_name": "Sea Buckthorn", "scientific_name": "Hippophae rhamnoides", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant one male plant for every 5–7 female plants in early spring; sea buckthorn is wind-pollinated and needs close proximity between sexes."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 72, "max": 120}, "height_in": {"min": 72, "max": 180}, "spread_in": {"min": 72, "max": 120}, "sun": "full", "water": "low", "directions": "Sea buckthorn is a thorny, nitrogen-fixing shrub that thrives in poor, dry, sandy soils where most fruits struggle. It is dioecious and requires male plants for pollination — one male per 5–7 females; sex is not identifiable until first flowering, so purchase sexed plants. The tiny berries are borne directly on the branches in dense clusters and are difficult to harvest without damaging the plant; a common approach is to cut fruiting branches in fall and strip berries indoors or by freezing and shaking. The tart, orange berries are extremely high in vitamin C.", "sources": ["general horticultural reference", "university extension guides"]}')
