  VALUES ('southern-highbush-blueberry','Southern Highbush Blueberry','Vaccinium corymbosum (hybrid)','berry','shrub fruit',NULL,NULL,NULL,NULL,730,1095,'transplant','transplant','perennial','half-hardy','spring',0,4,'Plant in early spring in very acidic, well-drained soil; low-chill cultivars such as ''Sunshine Blue'' or ''O''Neal'' are essential in mild-winter climates.',6,10,48,72,48,96,48,72,'full','moderate','Southern highbush blueberries are interspecific hybrids bred for low chill-hour requirements (150–500 hours below 45°F), making them the only highbush-type blueberry suitable for Gulf Coast, Florida, and mild-winter California climates. Maintain soil pH at 4.5–5.5 with pine bark mulch and acidifying fertilizers; do not use lime. Plant two or more cultivars for cross-pollination and improved fruit size. Prune lightly for the first three years, then begin removing the oldest, least productive canes each late winter to stimulate vigorous new wood.','["general horticultural reference", "university extension guides"]','{"slug": "southern-highbush-blueberry", "common_name": "Southern Highbush Blueberry", "scientific_name": "Vaccinium corymbosum (hybrid)", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in early spring in very acidic, well-drained soil; low-chill cultivars such as ''Sunshine Blue'' or ''O''Neal'' are essential in mild-winter climates."}, "usda_zones": {"min": 6, "max": 10}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 48, "max": 96}, "spread_in": {"min": 48, "max": 72}, "sun": "full", "water": "moderate", "directions": "Southern highbush blueberries are interspecific hybrids bred for low chill-hour requirements (150–500 hours below 45°F), making them the only highbush-type blueberry suitable for Gulf Coast, Florida, and mild-winter California climates. Maintain soil pH at 4.5–5.5 with pine bark mulch and acidifying fertilizers; do not use lime. Plant two or more cultivars for cross-pollination and improved fruit size. Prune lightly for the first three years, then begin removing the oldest, least productive canes each late winter to stimulate vigorous new wood.", "sources": ["general horticultural reference", "university extension guides"]}')
