  VALUES ('strawberry-everbearing','Strawberry (Everbearing)','Fragaria x ananassa','berry','ground fruit',NULL,NULL,NULL,NULL,120,180,'transplant','transplant','perennial','hardy','last_frost',-2,2,'Set crowns in early spring; everbearing types can yield a partial crop the first fall if planted promptly.',3,10,12,18,6,10,12,18,'full','moderate','Plant in spring with crowns at soil level; remove only the spring flush of blossoms and allow the summer and fall crops to set. Everbearing types produce two distinct flushes — early summer and late summer into fall — with fewer runners than june-bearing types, making them well suited to hill culture or raised beds. Harvest when berries are fully red and fragrant. Replace plants every 3–4 years as productivity declines.','["general horticultural reference", "university extension guides"]','{"slug": "strawberry-everbearing", "common_name": "Strawberry (Everbearing)", "scientific_name": "Fragaria x ananassa", "category": "berry", "subcategory": "ground fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Set crowns in early spring; everbearing types can yield a partial crop the first fall if planted promptly."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 6, "max": 10}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Plant in spring with crowns at soil level; remove only the spring flush of blossoms and allow the summer and fall crops to set. Everbearing types produce two distinct flushes — early summer and late summer into fall — with fewer runners than june-bearing types, making them well suited to hill culture or raised beds. Harvest when berries are fully red and fragrant. Replace plants every 3–4 years as productivity declines.", "sources": ["general horticultural reference", "university extension guides"]}')
