INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('strawberry-tree-arbutus','Strawberry Tree','Arbutus unedo','berry','shrub fruit',NULL,NULL,NULL,NULL,1095,1460,'transplant','transplant','perennial','half-hardy','spring',0,4,'Plant container stock in spring in well-drained, slightly acidic to neutral soil; tolerates drought, salt spray, and wind — excellent for coastal gardens in zones 7–10.',7,10,60,120,96,240,72,180,'full','low','The strawberry tree is an attractive Mediterranean evergreen grown as a large shrub or small tree prized for the remarkable phenomenon of simultaneously bearing flowers and ripe fruit in autumn and winter — fruit from the previous year''s flowers ripens just as the new season''s flowers open. The round, warty, red-orange fruits are mildly sweet and grainy when fully ripe, high in sugar and suitable for jams, liqueurs, and fermented beverages (the species name ''unedo'' is said to derive from the Latin ''I eat only one''). It tolerates poor, shallow, well-drained soils and thrives in Mediterranean-climate gardens with minimal summer irrigation once established. Little pruning is required; remove dead wood and shape lightly to maintain structure.','["general horticultural reference", "university extension guides"]','{"slug": "strawberry-tree-arbutus", "common_name": "Strawberry Tree", "scientific_name": "Arbutus unedo", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant container stock in spring in well-drained, slightly acidic to neutral soil; tolerates drought, salt spray, and wind — excellent for coastal gardens in zones 7–10."}, "usda_zones": {"min": 7, "max": 10}, "spacing_in": {"min": 60, "max": 120}, "height_in": {"min": 96, "max": 240}, "spread_in": {"min": 72, "max": 180}, "sun": "full", "water": "low", "directions": "The strawberry tree is an attractive Mediterranean evergreen grown as a large shrub or small tree prized for the remarkable phenomenon of simultaneously bearing flowers and ripe fruit in autumn and winter — fruit from the previous year''s flowers ripens just as the new season''s flowers open. The round, warty, red-orange fruits are mildly sweet and grainy when fully ripe, high in sugar and suitable for jams, liqueurs, and fermented beverages (the species name ''unedo'' is said to derive from the Latin ''I eat only one''). It tolerates poor, shallow, well-drained soils and thrives in Mediterranean-climate gardens with minimal summer irrigation once established. Little pruning is required; remove dead wood and shape lightly to maintain structure.", "sources": ["general horticultural reference", "university extension guides"]}')
