  VALUES ('table-grape','Table Grape','Vitis vinifera / Vitis labrusca','berry','vine fruit',NULL,NULL,NULL,NULL,1095,1460,'transplant','cutting','perennial','hardy','spring',0,4,'Plant dormant bare-root vines in early spring; install a sturdy trellis or arbor before planting.',5,9,72,96,72,120,72,120,'full','low','Table grapes require a robust trellis capable of supporting 15–30 lbs of fruit per vine; the two-wire Kniffin system or a pergola are common choices. Train a permanent trunk and 2–4 fruiting arms during the first 3 years; thereafter, annual dormant pruning should remove 90% of the previous year''s growth, leaving spurs or canes with 2–4 buds each. Thin clusters after fruit set to improve berry size and airflow. Harvest when berries reach full color, the tendrils nearest the cluster have dried, and sugar is confirmed by taste.','["general horticultural reference", "university extension guides"]','{"slug": "table-grape", "common_name": "Table Grape", "scientific_name": "Vitis vinifera / Vitis labrusca", "category": "berry", "subcategory": "vine fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant dormant bare-root vines in early spring; install a sturdy trellis or arbor before planting."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 72, "max": 96}, "height_in": {"min": 72, "max": 120}, "spread_in": {"min": 72, "max": 120}, "sun": "full", "water": "low", "directions": "Table grapes require a robust trellis capable of supporting 15–30 lbs of fruit per vine; the two-wire Kniffin system or a pergola are common choices. Train a permanent trunk and 2–4 fruiting arms during the first 3 years; thereafter, annual dormant pruning should remove 90% of the previous year''s growth, leaving spurs or canes with 2–4 buds each. Thin clusters after fruit set to improve berry size and airflow. Harvest when berries reach full color, the tendrils nearest the cluster have dried, and sugar is confirmed by taste.", "sources": ["general horticultural reference", "university extension guides"]}')
