  VALUES ('tayberry','Tayberry','Rubus fruticosus x idaeus','berry','cane fruit',NULL,NULL,NULL,NULL,365,548,'transplant','cutting','perennial','half-hardy','spring',0,4,'Plant rooted tip cuttings or bare-root canes in early spring and install a two-wire trellis at 3 and 5 ft at the same time.',5,9,60,84,36,60,72,120,'full','moderate','Tayberry is a Scottish-bred hybrid (blackberry x raspberry) with long, conical, deep purple-red berries that ripen in mid-summer; the flavor is richer and sweeter than loganberry. Train the long trailing canes fan-style along wires, keeping current-year primocanes separate from fruiting floricanes to simplify post-harvest cleanup. After harvest, remove all fruited canes to the ground and tie in the new primocanes. In zone 5–6, protect canes over winter by detaching them from wires and covering with straw mulch or a frost-cloth tunnel.','["general horticultural reference", "RHS Fruit Garden Displayed"]','{"slug": "tayberry", "common_name": "Tayberry", "scientific_name": "Rubus fruticosus x idaeus", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted tip cuttings or bare-root canes in early spring and install a two-wire trellis at 3 and 5 ft at the same time."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 60, "max": 84}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 72, "max": 120}, "sun": "full", "water": "moderate", "directions": "Tayberry is a Scottish-bred hybrid (blackberry x raspberry) with long, conical, deep purple-red berries that ripen in mid-summer; the flavor is richer and sweeter than loganberry. Train the long trailing canes fan-style along wires, keeping current-year primocanes separate from fruiting floricanes to simplify post-harvest cleanup. After harvest, remove all fruited canes to the ground and tie in the new primocanes. In zone 5–6, protect canes over winter by detaching them from wires and covering with straw mulch or a frost-cloth tunnel.", "sources": ["general horticultural reference", "RHS Fruit Garden Displayed"]}')
