INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('thimbleberry','Thimbleberry','Rubus parviflorus','berry','cane fruit',30,90,40,60,1095,1460,'transplant','division','perennial','hardy','spring',0,4,'Plant root divisions or container-grown plants in early spring in partial shade with moist, well-drained soil.',3,9,48,60,36,72,36,60,'partial','moderate','Thimbleberry is a large-leafed, thornless native Rubus that thrives along woodland edges and mountain slopes from Alaska to Mexico, tolerating more shade than almost any other fruiting cane. The soft, bright red berries resemble a wide, shallow thimble and have a delicate, sweet flavor but are extremely fragile — they must be eaten or processed within hours of harvest. Propagate by dividing root clumps in spring; seed germination is erratic and requires cold stratification. Allow the plant to naturalize in a semi-wild planting rather than managing it as a formal fruiting cane.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "thimbleberry", "common_name": "Thimbleberry", "scientific_name": "Rubus parviflorus", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": 30, "max": 90}, "germination_soil_temp_f": {"min": 40, "max": 60}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant root divisions or container-grown plants in early spring in partial shade with moist, well-drained soil."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 48, "max": 60}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 36, "max": 60}, "sun": "partial", "water": "moderate", "directions": "Thimbleberry is a large-leafed, thornless native Rubus that thrives along woodland edges and mountain slopes from Alaska to Mexico, tolerating more shade than almost any other fruiting cane. The soft, bright red berries resemble a wide, shallow thimble and have a delicate, sweet flavor but are extremely fragile — they must be eaten or processed within hours of harvest. Propagate by dividing root clumps in spring; seed germination is erratic and requires cold stratification. Allow the plant to naturalize in a semi-wild planting rather than managing it as a formal fruiting cane.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
