  VALUES ('tummelberry','Tummelberry','Rubus hybrid (tayberry x unknown)','berry','cane fruit',NULL,NULL,NULL,NULL,365,548,'transplant','transplant','perennial','hardy','spring',0,4,'Plant bare-root canes in early spring on a trellis; tummelberry is more cold-hardy than tayberry and better suited to short-season northern gardens.',4,8,48,72,24,60,60,96,'full','moderate','The tummelberry is a Scottish-bred Rubus hybrid developed at the Scottish Crop Research Institute from a tayberry cross, selected specifically for greater cold hardiness and easier mechanical harvest than its parent. It produces large, dark red to maroon conical berries slightly smaller than tayberries in midsummer with a rich, aromatic flavor well suited to preserves, juices, and desserts. Train the long, semi-trailing canes on a two-wire trellis at 3 and 5 ft, fruiting on second-year floricanes; cut all fruited canes to the ground after harvest and train new primocanes for the following year. It is substantially hardier than tayberry and performs reliably in zones 4–5 with minimal winter protection.','["general horticultural reference", "university extension guides"]','{"slug": "tummelberry", "common_name": "Tummelberry", "scientific_name": "Rubus hybrid (tayberry x unknown)", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant bare-root canes in early spring on a trellis; tummelberry is more cold-hardy than tayberry and better suited to short-season northern gardens."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 60, "max": 96}, "sun": "full", "water": "moderate", "directions": "The tummelberry is a Scottish-bred Rubus hybrid developed at the Scottish Crop Research Institute from a tayberry cross, selected specifically for greater cold hardiness and easier mechanical harvest than its parent. It produces large, dark red to maroon conical berries slightly smaller than tayberries in midsummer with a rich, aromatic flavor well suited to preserves, juices, and desserts. Train the long, semi-trailing canes on a two-wire trellis at 3 and 5 ft, fruiting on second-year floricanes; cut all fruited canes to the ground after harvest and train new primocanes for the following year. It is substantially hardier than tayberry and performs reliably in zones 4–5 with minimal winter protection.", "sources": ["general horticultural reference", "university extension guides"]}')
