  VALUES ('white-currant','White Currant','Ribes rubrum','berry','shrub fruit',NULL,NULL,NULL,NULL,548,730,'transplant','cutting','perennial','hardy','spring',0,3,'Plant hardwood cuttings or bare-root stock in early spring; white currants perform well trained as a cordon against a north- or east-facing wall.',3,7,48,60,36,60,36,60,'partial','moderate','White currant is a yellow-fruited mutation of red currant sharing identical cultivation requirements: it fruits most heavily on spurs of two-year-old and older wood. The translucent, ivory-white berries are sweeter and milder than red currants and are prized for elegant fresh-eating and jellies. Prune each late winter to maintain 8–12 canes of mixed ages, removing canes older than 5 years. Harvest entire strigs when berries have turned fully translucent white-golden and taste sweet; check local Ribes restrictions before purchasing.','["general horticultural reference", "university extension guides"]','{"slug": "white-currant", "common_name": "White Currant", "scientific_name": "Ribes rubrum", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 548, "max": 730}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 3}, "note": "Plant hardwood cuttings or bare-root stock in early spring; white currants perform well trained as a cordon against a north- or east-facing wall."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 48, "max": 60}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 36, "max": 60}, "sun": "partial", "water": "moderate", "directions": "White currant is a yellow-fruited mutation of red currant sharing identical cultivation requirements: it fruits most heavily on spurs of two-year-old and older wood. The translucent, ivory-white berries are sweeter and milder than red currants and are prized for elegant fresh-eating and jellies. Prune each late winter to maintain 8–12 canes of mixed ages, removing canes older than 5 years. Harvest entire strigs when berries have turned fully translucent white-golden and taste sweet; check local Ribes restrictions before purchasing.", "sources": ["general horticultural reference", "university extension guides"]}')
