  VALUES ('wineberry','Wineberry','Rubus phoenicolasius','berry','cane fruit',14,30,60,75,365,548,'transplant','transplant','perennial','hardy','spring',0,4,'Plant rooted cuttings or transplants in early spring; note that wineberry is invasive in much of the eastern U.S., so check local regulations before planting.',5,8,48,72,36,72,36,72,'partial','moderate','Wineberry, native to Japan and China, produces small, brilliant red, jewel-like drupes with a sweet, delicate flavor; it is grown for fruit production in Asia and has naturalized extensively in the eastern U.S. and should be grown only in contained settings or where legal. The canes are covered in red glandular hairs and tip-root readily, so remove spent canes promptly and clear any rooted tips. Harvest when berries are uniformly bright red and detach easily from the sticky calyx — they do not ripen after picking and must be used within 1–2 days. Pruning follows the same floricane/primocane cycle as standard raspberries.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "wineberry", "common_name": "Wineberry", "scientific_name": "Rubus phoenicolasius", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 60, "max": 75}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted cuttings or transplants in early spring; note that wineberry is invasive in much of the eastern U.S., so check local regulations before planting."}, "usda_zones": {"min": 5, "max": 8}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 36, "max": 72}, "sun": "partial", "water": "moderate", "directions": "Wineberry, native to Japan and China, produces small, brilliant red, jewel-like drupes with a sweet, delicate flavor; it is grown for fruit production in Asia and has naturalized extensively in the eastern U.S. and should be grown only in contained settings or where legal. The canes are covered in red glandular hairs and tip-root readily, so remove spent canes promptly and clear any rooted tips. Harvest when berries are uniformly bright red and detach easily from the sticky calyx — they do not ripen after picking and must be used within 1–2 days. Pruning follows the same floricane/primocane cycle as standard raspberries.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
