  VALUES ('worcesterberry','Worcesterberry','Ribes divaricatum','berry','shrub fruit',NULL,NULL,NULL,NULL,548,730,'transplant','cutting','perennial','hardy','spring',0,3,'Plant hardwood cuttings or bare-root stock in early spring in well-drained, fertile soil; worcesterberry is very thorny — wear heavy gloves when handling.',4,8,48,60,48,72,48,60,'partial','moderate','The worcesterberry is a North American species of gooseberry (Ribes divaricatum) sometimes grown as a productive alternative to European gooseberries because it shows good resistance to powdery mildew and American gooseberry mildew. The small, dark purple-black berries resemble currants more than typical gooseberries and ripen in midsummer with a tart, rich flavor excellent for jams and pies. Prune to an open-vase structure each late winter, keeping 8–10 canes of mixed ages. Verify state restrictions on Ribes planting before ordering, as some states still restrict the genus.','["general horticultural reference", "university extension guides"]','{"slug": "worcesterberry", "common_name": "Worcesterberry", "scientific_name": "Ribes divaricatum", "category": "berry", "subcategory": "shrub fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 548, "max": 730}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 3}, "note": "Plant hardwood cuttings or bare-root stock in early spring in well-drained, fertile soil; worcesterberry is very thorny — wear heavy gloves when handling."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 48, "max": 60}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 48, "max": 60}, "sun": "partial", "water": "moderate", "directions": "The worcesterberry is a North American species of gooseberry (Ribes divaricatum) sometimes grown as a productive alternative to European gooseberries because it shows good resistance to powdery mildew and American gooseberry mildew. The small, dark purple-black berries resemble currants more than typical gooseberries and ripen in midsummer with a tart, rich flavor excellent for jams and pies. Prune to an open-vase structure each late winter, keeping 8–10 canes of mixed ages. Verify state restrictions on Ribes planting before ordering, as some states still restrict the genus.", "sources": ["general horticultural reference", "university extension guides"]}')
