INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('youngberry','Youngberry','Rubus caesius x idaeus x ursinus hybrid','berry','cane fruit',NULL,NULL,NULL,NULL,365,548,'transplant','transplant','perennial','half-hardy','spring',0,4,'Plant bare-root canes in spring on a sturdy two- or three-wire trellis; youngberry is a trailing type requiring support and grows best in warm, humid climates.',6,9,60,96,24,60,72,120,'full','moderate','The youngberry is a dewberry hybrid developed in Louisiana in the early 1900s by B.M. Young, producing very large, dark maroon-purple berries with a high juice content and sweet-tart flavor excellent for wine, juice, and pies. Culture is similar to boysenberry: train long, trailing canes on a T-trellis at 3 and 5 ft, fruiting on second-year floricanes; after harvest, cut all fruited canes to the ground and tie new primocanes in their place. The plants are less cold-hardy than standard blackberries and benefit from cane protection or mulching in zone 6 winters. Harvest when berries turn uniformly dark purple-black and release easily from the plug.','["general horticultural reference", "university extension guides"]','{"slug": "youngberry", "common_name": "Youngberry", "scientific_name": "Rubus caesius x idaeus x ursinus hybrid", "category": "berry", "subcategory": "cane fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant bare-root canes in spring on a sturdy two- or three-wire trellis; youngberry is a trailing type requiring support and grows best in warm, humid climates."}, "usda_zones": {"min": 6, "max": 9}, "spacing_in": {"min": 60, "max": 96}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 72, "max": 120}, "sun": "full", "water": "moderate", "directions": "The youngberry is a dewberry hybrid developed in Louisiana in the early 1900s by B.M. Young, producing very large, dark maroon-purple berries with a high juice content and sweet-tart flavor excellent for wine, juice, and pies. Culture is similar to boysenberry: train long, trailing canes on a T-trellis at 3 and 5 ft, fruiting on second-year floricanes; after harvest, cut all fruited canes to the ground and tie new primocanes in their place. The plants are less cold-hardy than standard blackberries and benefit from cane protection or mulching in zone 6 winters. Harvest when berries turn uniformly dark purple-black and release easily from the plug.", "sources": ["general horticultural reference", "university extension guides"]}')
