INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('alfalfa','Alfalfa','Medicago sativa','cover-crop','legume',5,10,40,85,60,90,'seed','direct','perennial','hardy','last_frost',-2,2,'Sow in early spring around the last frost date, or in late summer 6–8 weeks before first frost to allow fall establishment.',3,9,1,2,18,36,6,12,'full','low','Inoculate seed with Medicago-specific rhizobium and broadcast at 15–20 lb per acre (about 1/4 oz per 100 sq ft), raking seed to 1/4 in depth into a firm, well-prepared seedbed with pH 6.5–7.0. Alfalfa fixes 100–200 lb of nitrogen per acre per year once established and deep taproots (up to 6 ft) break hardpan and mine subsoil minerals. Terminate by mowing at early bloom stage — typically every 30–40 days in summer — before the first killing frost; turning it under releases a large pulse of nitrogen. In perennial plantings, allow one cutting to go to seed to rejuvenate the stand every two or three years.','["general horticultural reference"]','{"slug": "alfalfa", "common_name": "Alfalfa", "scientific_name": "Medicago sativa", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 40, "max": 85}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Sow in early spring around the last frost date, or in late summer 6–8 weeks before first frost to allow fall establishment."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "low", "directions": "Inoculate seed with Medicago-specific rhizobium and broadcast at 15–20 lb per acre (about 1/4 oz per 100 sq ft), raking seed to 1/4 in depth into a firm, well-prepared seedbed with pH 6.5–7.0. Alfalfa fixes 100–200 lb of nitrogen per acre per year once established and deep taproots (up to 6 ft) break hardpan and mine subsoil minerals. Terminate by mowing at early bloom stage — typically every 30–40 days in summer — before the first killing frost; turning it under releases a large pulse of nitrogen. In perennial plantings, allow one cutting to go to seed to rejuvenate the stand every two or three years.", "sources": ["general horticultural reference"]}')
