  VALUES ('alsike-clover','Alsike Clover','Trifolium hybridum','cover-crop','legume',7,14,40,70,60,90,'seed','direct','cool','hardy','soil_workable',0,4,'Sow in early spring or late summer; thrives on wet, acidic, or cold soils where red and white clover struggle.',3,8,1,2,12,30,6,12,'full','high','Broadcast inoculated seed at 6–8 lb/acre into a firm seedbed; alsike clover is a short-lived perennial that tolerates more acid and waterlogged conditions than red clover and requires no liming on pH 5.5–6.5 soils. It will fix nitrogen reliably for 2–3 seasons without reseeding and pairs well with timothy or orchardgrass in mixed stands. Mow to prevent flowering from exhausting the plant, or allow it to bloom and incorporate as green manure in the second year. Avoid using as sole forage for horses, as alsike can cause photosensitization in equines.','["general horticultural reference"]','{"slug": "alsike-clover", "common_name": "Alsike Clover", "scientific_name": "Trifolium hybridum", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 40, "max": 70}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Sow in early spring or late summer; thrives on wet, acidic, or cold soils where red and white clover struggle."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 12, "max": 30}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "high", "directions": "Broadcast inoculated seed at 6–8 lb/acre into a firm seedbed; alsike clover is a short-lived perennial that tolerates more acid and waterlogged conditions than red clover and requires no liming on pH 5.5–6.5 soils. It will fix nitrogen reliably for 2–3 seasons without reseeding and pairs well with timothy or orchardgrass in mixed stands. Mow to prevent flowering from exhausting the plant, or allow it to bloom and incorporate as green manure in the second year. Avoid using as sole forage for horses, as alsike can cause photosensitization in equines.", "sources": ["general horticultural reference"]}')
