INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('annual-ryegrass','Annual Ryegrass (Italian Ryegrass)','Lolium multiflorum','cover-crop','grass',5,10,40,75,60,90,'seed','direct','cool','hardy','first_frost',-6,-2,'Sow 2–6 weeks before first fall frost; germinates and establishes faster than perennial ryegrass and can be interseeded into standing late-season crops.',3,9,1,2,18,36,3,6,'full','moderate','Broadcast seed at 20–25 lb per acre (about 1/2 oz per 100 sq ft) onto a prepared surface and rake to 1/4 in depth; annual ryegrass has one of the fastest establishment rates of all cool-season grasses, providing rapid erosion control and weed suppression. The dense, fibrous root system scavenges residual nitrogen effectively, locking it up over winter to prevent leaching. Terminate in early spring before it joints and sets seed — once headed, it becomes very difficult to kill without herbicide or repeated tillage. Mow to 2–3 in and till, or use a roller-crimper at boot stage for no-till termination; allow residue 2–3 weeks to break down before planting.','["general horticultural reference"]','{"slug": "annual-ryegrass", "common_name": "Annual Ryegrass (Italian Ryegrass)", "scientific_name": "Lolium multiflorum", "category": "cover-crop", "subcategory": "grass", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -6, "max": -2}, "note": "Sow 2–6 weeks before first fall frost; germinates and establishes faster than perennial ryegrass and can be interseeded into standing late-season crops."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 3, "max": 6}, "sun": "full", "water": "moderate", "directions": "Broadcast seed at 20–25 lb per acre (about 1/2 oz per 100 sq ft) onto a prepared surface and rake to 1/4 in depth; annual ryegrass has one of the fastest establishment rates of all cool-season grasses, providing rapid erosion control and weed suppression. The dense, fibrous root system scavenges residual nitrogen effectively, locking it up over winter to prevent leaching. Terminate in early spring before it joints and sets seed — once headed, it becomes very difficult to kill without herbicide or repeated tillage. Mow to 2–3 in and till, or use a roller-crimper at boot stage for no-till termination; allow residue 2–3 weeks to break down before planting.", "sources": ["general horticultural reference"]}')
