  VALUES ('balansa-clover','Balansa Clover','Trifolium michelianum','cover-crop','legume',5,10,40,68,150,200,'seed','direct','cool','half-hardy','first_frost',-8,-4,'Sow 4–8 weeks before frost; balansa clover is exceptionally flood- and waterlogging-tolerant, making it ideal for wet, low-lying spots.',6,9,1,2,6,18,4,10,'full','high','Broadcast tiny seed at 2–4 lb/acre (due to its small seed size) onto a firm, moist seedbed; balansa clover establishes quickly and tolerates prolonged waterlogging that would kill crimson or Persian clover. It hollows out a rapid canopy that suppresses winter weeds while fixing nitrogen throughout the cool season. Terminate at early bloom by mowing or rolling for the best nitrogen contribution and easiest residue breakdown. Excellent choice for poorly drained field margins or orchard middles that receive runoff.','["general horticultural reference"]','{"slug": "balansa-clover", "common_name": "Balansa Clover", "scientific_name": "Trifolium michelianum", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 40, "max": 68}, "days_to_maturity": {"min": 150, "max": 200}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow 4–8 weeks before frost; balansa clover is exceptionally flood- and waterlogging-tolerant, making it ideal for wet, low-lying spots."}, "usda_zones": {"min": 6, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 6, "max": 18}, "spread_in": {"min": 4, "max": 10}, "sun": "full", "water": "high", "directions": "Broadcast tiny seed at 2–4 lb/acre (due to its small seed size) onto a firm, moist seedbed; balansa clover establishes quickly and tolerates prolonged waterlogging that would kill crimson or Persian clover. It hollows out a rapid canopy that suppresses winter weeds while fixing nitrogen throughout the cool season. Terminate at early bloom by mowing or rolling for the best nitrogen contribution and easiest residue breakdown. Excellent choice for poorly drained field margins or orchard middles that receive runoff.", "sources": ["general horticultural reference"]}')
