INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('berseem-clover','Berseem Clover','Trifolium alexandrinum','cover-crop','legume',5,10,38,75,60,90,'seed','direct','cool','half-hardy','first_frost',-8,-4,'Sow in early fall 4–8 weeks before first frost, or in early spring; survives light frost but not hard freezes, so it winter-kills in zones 6 and colder.',5,10,1,2,18,30,4,8,'full','moderate','Broadcast inoculated seed at 15–20 lb per acre, raking seed lightly to 1/4 in depth; berseem germinates in near-freezing soil and establishes faster than crimson clover. Unlike most clovers, berseem regrows vigorously after each mowing, allowing two to three cuts before termination, with each cut releasing a pulse of nitrogen. It tolerates moderate salinity and poorly drained soils better than most cool-season legumes, making it useful in difficult garden sites. Terminate by incorporating the last flush of growth 3–4 weeks before planting the next crop.','["general horticultural reference"]','{"slug": "berseem-clover", "common_name": "Berseem Clover", "scientific_name": "Trifolium alexandrinum", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 38, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow in early fall 4–8 weeks before first frost, or in early spring; survives light frost but not hard freezes, so it winter-kills in zones 6 and colder."}, "usda_zones": {"min": 5, "max": 10}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "moderate", "directions": "Broadcast inoculated seed at 15–20 lb per acre, raking seed lightly to 1/4 in depth; berseem germinates in near-freezing soil and establishes faster than crimson clover. Unlike most clovers, berseem regrows vigorously after each mowing, allowing two to three cuts before termination, with each cut releasing a pulse of nitrogen. It tolerates moderate salinity and poorly drained soils better than most cool-season legumes, making it useful in difficult garden sites. Terminate by incorporating the last flush of growth 3–4 weeks before planting the next crop.", "sources": ["general horticultural reference"]}')
