  VALUES ('birdsfoot-trefoil','Birdsfoot Trefoil','Lotus corniculatus','cover-crop','legume',10,21,41,68,60,120,'seed','direct','cool','hardy','soil_workable',0,4,'Sow in early spring; establishes slowly but becomes a persistent, non-bloating perennial legume ideal for slopes and orchard floors.',3,8,2,4,6,24,8,18,'full','low','Inoculate seed with Mesorhizobium loti and broadcast at 5–8 lb/acre onto a firm, weed-free seedbed; seedling vigor is slow, so suppress weed competition aggressively in the establishment year. Once established, birdsfoot trefoil is drought-tolerant and persists on shallow, acidic, or gravelly soils where alfalfa fails. It fixes moderate nitrogen, flowers bright yellow, and does not cause bloat in livestock — a key advantage over true clovers. Mow or graze periodically to prevent it from going rank and woody but allow it to flower at least once per season to feed pollinators.','["general horticultural reference"]','{"slug": "birdsfoot-trefoil", "common_name": "Birdsfoot Trefoil", "scientific_name": "Lotus corniculatus", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 41, "max": 68}, "days_to_maturity": {"min": 60, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Sow in early spring; establishes slowly but becomes a persistent, non-bloating perennial legume ideal for slopes and orchard floors."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 2, "max": 4}, "height_in": {"min": 6, "max": 24}, "spread_in": {"min": 8, "max": 18}, "sun": "full", "water": "low", "directions": "Inoculate seed with Mesorhizobium loti and broadcast at 5–8 lb/acre onto a firm, weed-free seedbed; seedling vigor is slow, so suppress weed competition aggressively in the establishment year. Once established, birdsfoot trefoil is drought-tolerant and persists on shallow, acidic, or gravelly soils where alfalfa fails. It fixes moderate nitrogen, flowers bright yellow, and does not cause bloat in livestock — a key advantage over true clovers. Mow or graze periodically to prevent it from going rank and woody but allow it to flower at least once per season to feed pollinators.", "sources": ["general horticultural reference"]}')
