  VALUES ('oats-black','Black Oat (Brazilian Oat Cover)','Avena strigosa','cover-crop','grass',5,10,40,72,60,90,'seed','direct','cool','half-hardy','first_frost',-8,-4,'Sow 4–8 weeks before frost; black oat produces more biomass and stronger allelopathy than common oats and is the preferred cover in no-till systems.',5,10,1,2,36,60,4,8,'full','moderate','Broadcast seed at 40–60 lb/acre and cover to 1 in depth in fall; black oat (Avena strigosa) is widely used in Brazilian no-till systems for its exceptional allelopathic residue that suppresses weeds well into the following season. It winter-kills in zones colder than 5, creating a ready-made mulch mat without any tillage needed. In milder climates it overwinters and can be roll-crimped in spring when fully headed out to create a thick residue layer for direct transplanting through. Combine with a legume such as hairy vetch or crimson clover to add a nitrogen component to the mulch.','["general horticultural reference"]','{"slug": "oats-black", "common_name": "Black Oat (Brazilian Oat Cover)", "scientific_name": "Avena strigosa", "category": "cover-crop", "subcategory": "grass", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 40, "max": 72}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow 4–8 weeks before frost; black oat produces more biomass and stronger allelopathy than common oats and is the preferred cover in no-till systems."}, "usda_zones": {"min": 5, "max": 10}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "moderate", "directions": "Broadcast seed at 40–60 lb/acre and cover to 1 in depth in fall; black oat (Avena strigosa) is widely used in Brazilian no-till systems for its exceptional allelopathic residue that suppresses weeds well into the following season. It winter-kills in zones colder than 5, creating a ready-made mulch mat without any tillage needed. In milder climates it overwinters and can be roll-crimped in spring when fully headed out to create a thick residue layer for direct transplanting through. Combine with a legume such as hairy vetch or crimson clover to add a nitrogen component to the mulch.", "sources": ["general horticultural reference"]}')
