INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('chickling-vetch','Chickling Vetch (Grass Pea Cover)','Lathyrus sativus','cover-crop','legume',7,14,40,72,70,110,'seed','direct','cool','half-hardy','first_frost',-8,-4,'Sow 4–8 weeks before frost in fall, or in earliest spring; extremely drought- and cold-tolerant legume for challenging sites.',5,9,1,3,18,48,6,12,'full','low','Sow inoculated seed 1–2 in deep at 40–60 lb/acre; chickling vetch is one of the most drought-tolerant annual legumes, surviving on less than 10 in of annual rainfall and fixing substantial nitrogen even on marginal soils. The vining tendrils latch onto cereal companions like rye or triticale for support. Terminate at full bloom before pods set, as mature seed contains ODAP, a neurotoxin that is harmless in soil but hazardous if consumed in large quantities. Do not grow where children or livestock might graze the ripe seeds.','["general horticultural reference"]','{"slug": "chickling-vetch", "common_name": "Chickling Vetch (Grass Pea Cover)", "scientific_name": "Lathyrus sativus", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 40, "max": 72}, "days_to_maturity": {"min": 70, "max": 110}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow 4–8 weeks before frost in fall, or in earliest spring; extremely drought- and cold-tolerant legume for challenging sites."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 1, "max": 3}, "height_in": {"min": 18, "max": 48}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "low", "directions": "Sow inoculated seed 1–2 in deep at 40–60 lb/acre; chickling vetch is one of the most drought-tolerant annual legumes, surviving on less than 10 in of annual rainfall and fixing substantial nitrogen even on marginal soils. The vining tendrils latch onto cereal companions like rye or triticale for support. Terminate at full bloom before pods set, as mature seed contains ODAP, a neurotoxin that is harmless in soil but hazardous if consumed in large quantities. Do not grow where children or livestock might graze the ripe seeds.", "sources": ["general horticultural reference"]}')
