INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('common-vetch','Common Vetch','Vicia sativa','cover-crop','legume',7,14,40,65,60,90,'seed','direct','cool','hardy','first_frost',-8,-4,'Sow 4–8 weeks before first fall frost; common vetch is slightly more cold-tolerant than crimson clover and grows in poorer soils than hairy vetch.',4,9,1,2,12,36,6,12,'full','moderate','Sow inoculated seed at 40–50 lb per acre (about 1 oz per 20 sq ft) in fall, raking to 1/2 in depth; common vetch tolerates sandy, low-fertility soils where hairy vetch may struggle and establishes a climbing, vining habit that benefits from a grass companion for support. It fixes 80–120 lb of nitrogen per acre over winter and spring and is easier to terminate than hairy vetch because the vines are thinner and dry down faster. Mow at early bloom before pods swell to prevent reseeding; the narrow tendriled stems break down readily and release nitrogen within 2–3 weeks.','["general horticultural reference"]','{"slug": "common-vetch", "common_name": "Common Vetch", "scientific_name": "Vicia sativa", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 40, "max": 65}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow 4–8 weeks before first fall frost; common vetch is slightly more cold-tolerant than crimson clover and grows in poorer soils than hairy vetch."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 12, "max": 36}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow inoculated seed at 40–50 lb per acre (about 1 oz per 20 sq ft) in fall, raking to 1/2 in depth; common vetch tolerates sandy, low-fertility soils where hairy vetch may struggle and establishes a climbing, vining habit that benefits from a grass companion for support. It fixes 80–120 lb of nitrogen per acre over winter and spring and is easier to terminate than hairy vetch because the vines are thinner and dry down faster. Mow at early bloom before pods swell to prevent reseeding; the narrow tendriled stems break down readily and release nitrogen within 2–3 weeks.", "sources": ["general horticultural reference"]}')
