INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('forage-radish','Forage Radish (Tillage Radish Type)','Raphanus sativus var. niger','cover-crop','brassica',3,7,45,85,45,65,'seed','direct','cool','half-hardy','first_frost',-10,-6,'Sow 6–10 weeks before first frost; produces a large, soil-penetrating taproot that winter-kills in cold climates, leaving a decomposed channel.',3,9,2,4,12,24,6,12,'full','moderate','Broadcast seed at 8–10 lb/acre or drill at 6–7 lb/acre and cover to 1/4 in depth; forage radish emerges quickly and develops a taproot up to 18 in deep that fractures compacted subsoil and scavenges nitrates before they leach. In USDA zones 5 and colder the taproot reliably winter-kills, leaving a hollow channel that improves spring drainage and air porosity. Where winters are mild, mow the rosette before it bolts in spring to avoid a weedy seed bank. The decomposing roots have a pungent sulfur smell for 1–2 weeks after freeze-kill — this is normal.','["general horticultural reference"]','{"slug": "forage-radish", "common_name": "Forage Radish (Tillage Radish Type)", "scientific_name": "Raphanus sativus var. niger", "category": "cover-crop", "subcategory": "brassica", "days_to_germination": {"min": 3, "max": 7}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 45, "max": 65}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -10, "max": -6}, "note": "Sow 6–10 weeks before first frost; produces a large, soil-penetrating taproot that winter-kills in cold climates, leaving a decomposed channel."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 2, "max": 4}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Broadcast seed at 8–10 lb/acre or drill at 6–7 lb/acre and cover to 1/4 in depth; forage radish emerges quickly and develops a taproot up to 18 in deep that fractures compacted subsoil and scavenges nitrates before they leach. In USDA zones 5 and colder the taproot reliably winter-kills, leaving a hollow channel that improves spring drainage and air porosity. Where winters are mild, mow the rosette before it bolts in spring to avoid a weedy seed bank. The decomposing roots have a pungent sulfur smell for 1–2 weeks after freeze-kill — this is normal.", "sources": ["general horticultural reference"]}')
