INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('turnip-forage','Forage Turnip','Brassica rapa subsp. rapa','cover-crop','brassica',3,7,45,85,50,80,'seed','direct','cool','hardy','first_frost',-10,-6,'Sow 6–10 weeks before first frost; forage turnip produces heavy leaf canopy that smothers weeds and a fleshy taproot that winterkills to release nutrients.',3,9,2,4,12,24,6,14,'full','moderate','Broadcast or drill seed at 1–2 lb/acre and cover to 1/4 in depth; forage turnip is faster-maturing and less prone to overwintering than oilseed radish, making it a reliable fall cover where a quick canopy is needed. It scavenges residual nitrogen and suppresses winter annual weeds under its broad leaves. The bulbous root winter-kills in hard frost zones and decomposes rapidly, releasing stored nutrients at planting time. In mild climates it may overwinter and bolt in spring — mow before flowering to prevent volunteer seedlings in subsequent crops.','["general horticultural reference"]','{"slug": "turnip-forage", "common_name": "Forage Turnip", "scientific_name": "Brassica rapa subsp. rapa", "category": "cover-crop", "subcategory": "brassica", "days_to_germination": {"min": 3, "max": 7}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 50, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -10, "max": -6}, "note": "Sow 6–10 weeks before first frost; forage turnip produces heavy leaf canopy that smothers weeds and a fleshy taproot that winterkills to release nutrients."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 2, "max": 4}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 6, "max": 14}, "sun": "full", "water": "moderate", "directions": "Broadcast or drill seed at 1–2 lb/acre and cover to 1/4 in depth; forage turnip is faster-maturing and less prone to overwintering than oilseed radish, making it a reliable fall cover where a quick canopy is needed. It scavenges residual nitrogen and suppresses winter annual weeds under its broad leaves. The bulbous root winter-kills in hard frost zones and decomposes rapidly, releasing stored nutrients at planting time. In mild climates it may overwinter and bolt in spring — mow before flowering to prevent volunteer seedlings in subsequent crops.", "sources": ["general horticultural reference"]}')
