INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('guar-cover','Guar (Cluster Bean Cover)','Cyamopsis tetragonoloba','cover-crop','legume',5,10,68,95,70,100,'seed','direct','warm','tender','last_frost',1,6,'Sow after last frost in hot, dry climates; exceptional drought tolerance makes this the best legume cover for arid Southwest summers.',7,11,2,4,24,60,8,16,'full','low','Direct-sow inoculated seed 1 in deep at 20–30 lb/acre into warm, well-drained soil after all frost danger has passed; guar is native to arid Asia and thrives in sandy, alkaline soils with limited irrigation. It fixes atmospheric nitrogen through root nodules and produces significant biomass even in drought conditions, making it invaluable in the semi-arid Southwest and high plains. Terminate by mowing at early pod formation before seed fully hardens; the dense residue builds organic matter in soils chronically short of it. Avoid waterlogged sites — standing water causes rapid root rot.','["general horticultural reference"]','{"slug": "guar-cover", "common_name": "Guar (Cluster Bean Cover)", "scientific_name": "Cyamopsis tetragonoloba", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 68, "max": 95}, "days_to_maturity": {"min": 70, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 6}, "note": "Sow after last frost in hot, dry climates; exceptional drought tolerance makes this the best legume cover for arid Southwest summers."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 2, "max": 4}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 8, "max": 16}, "sun": "full", "water": "low", "directions": "Direct-sow inoculated seed 1 in deep at 20–30 lb/acre into warm, well-drained soil after all frost danger has passed; guar is native to arid Asia and thrives in sandy, alkaline soils with limited irrigation. It fixes atmospheric nitrogen through root nodules and produces significant biomass even in drought conditions, making it invaluable in the semi-arid Southwest and high plains. Terminate by mowing at early pod formation before seed fully hardens; the dense residue builds organic matter in soils chronically short of it. Avoid waterlogged sites — standing water causes rapid root rot.", "sources": ["general horticultural reference"]}')
