  VALUES ('cowpea-cover-iron-clay','Iron and Clay Cowpea (Cover Crop)','Vigna unguiculata','cover-crop','legume',5,10,65,95,60,90,'seed','direct','warm','tender','last_frost',1,6,'Sow after last frost when soil reaches 65°F; one of the most heat- and drought-tolerant warm-season cover-crop legumes.',5,11,1,3,12,24,12,36,'full','low','Broadcast or drill inoculated seed at 40–50 lb per acre (about 1 oz per 25 sq ft), 1/2 in deep in warm, well-drained soil; cowpeas germinate and grow rapidly, fixing 100–150 lb of nitrogen per acre while suppressing summer weeds with their spreading vines. The crop tolerates sandy, infertile, and slightly acidic soils where most legumes struggle. Terminate by mowing at early pod stage before seeds mature to prevent volunteer plants; large amounts of vine biomass decompose quickly in warm weather. Pairs well with sorghum-sudangrass for a combined legume-grass summer cover.','["general horticultural reference"]','{"slug": "cowpea-cover-iron-clay", "common_name": "Iron and Clay Cowpea (Cover Crop)", "scientific_name": "Vigna unguiculata", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 95}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 6}, "note": "Sow after last frost when soil reaches 65°F; one of the most heat- and drought-tolerant warm-season cover-crop legumes."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 1, "max": 3}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 36}, "sun": "full", "water": "low", "directions": "Broadcast or drill inoculated seed at 40–50 lb per acre (about 1 oz per 25 sq ft), 1/2 in deep in warm, well-drained soil; cowpeas germinate and grow rapidly, fixing 100–150 lb of nitrogen per acre while suppressing summer weeds with their spreading vines. The crop tolerates sandy, infertile, and slightly acidic soils where most legumes struggle. Terminate by mowing at early pod stage before seeds mature to prevent volunteer plants; large amounts of vine biomass decompose quickly in warm weather. Pairs well with sorghum-sudangrass for a combined legume-grass summer cover.", "sources": ["general horticultural reference"]}')
