  VALUES ('lablab-cover','Lablab (Hyacinth Bean Cover)','Lablab purpureus','cover-crop','legume',7,14,65,95,60,90,'seed','direct','warm','tender','last_frost',1,6,'Sow after last frost in warm soil; an exceptionally heat- and drought-tolerant warm-season legume cover from Africa.',9,11,2,6,48,120,12,36,'full','low','Plant inoculated seed 1 in deep after soil temperatures exceed 65°F; lablab vines grow vigorously and can climb trellises or sprawl as a smothering ground cover. It fixes up to 200 lb N/acre equivalent under good conditions and tolerates low-fertility and mildly saline soils where cowpea struggles. Terminate by mowing or chopping at early pod set; raw mature pods contain toxic lectins, so the foliage should not be eaten without cooking. In frost-free zones it can be managed as a short-lived perennial ground cover.','["general horticultural reference"]','{"slug": "lablab-cover", "common_name": "Lablab (Hyacinth Bean Cover)", "scientific_name": "Lablab purpureus", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 95}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 6}, "note": "Sow after last frost in warm soil; an exceptionally heat- and drought-tolerant warm-season legume cover from Africa."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 2, "max": 6}, "height_in": {"min": 48, "max": 120}, "spread_in": {"min": 12, "max": 36}, "sun": "full", "water": "low", "directions": "Plant inoculated seed 1 in deep after soil temperatures exceed 65°F; lablab vines grow vigorously and can climb trellises or sprawl as a smothering ground cover. It fixes up to 200 lb N/acre equivalent under good conditions and tolerates low-fertility and mildly saline soils where cowpea struggles. Terminate by mowing or chopping at early pod set; raw mature pods contain toxic lectins, so the foliage should not be eaten without cooking. In frost-free zones it can be managed as a short-lived perennial ground cover.", "sources": ["general horticultural reference"]}')
