INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('oats-cover','Oats (Cover Crop)','Avena sativa','cover-crop','grass',5,10,35,75,60,90,'seed','direct','cool','half-hardy','first_frost',-8,-4,'Sow 4–8 weeks before first fall frost; oats winter-kill below about 10°F, leaving a ready-to-plant mat of residue in spring without tillage.',3,9,1,2,24,48,3,6,'full','moderate','Broadcast seed at 50–80 lb per acre (about 1 oz per 30 sq ft) and rake to 1/2 in depth; oats establish quickly and produce substantial biomass before being killed by hard freezes. Their winter-killed residue lies flat as a weed-suppressing mulch that is easy to plant or transplant through in spring without additional termination work. Often mixed with field peas or hairy vetch to add nitrogen to the primarily carbonaceous grass residue. In mild-winter regions (zones 8–9), oats may overwinter and require mowing to terminate before spring planting.','["general horticultural reference"]','{"slug": "oats-cover", "common_name": "Oats (Cover Crop)", "scientific_name": "Avena sativa", "category": "cover-crop", "subcategory": "grass", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 35, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow 4–8 weeks before first fall frost; oats winter-kill below about 10°F, leaving a ready-to-plant mat of residue in spring without tillage."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 3, "max": 6}, "sun": "full", "water": "moderate", "directions": "Broadcast seed at 50–80 lb per acre (about 1 oz per 30 sq ft) and rake to 1/2 in depth; oats establish quickly and produce substantial biomass before being killed by hard freezes. Their winter-killed residue lies flat as a weed-suppressing mulch that is easy to plant or transplant through in spring without additional termination work. Often mixed with field peas or hairy vetch to add nitrogen to the primarily carbonaceous grass residue. In mild-winter regions (zones 8–9), oats may overwinter and require mowing to terminate before spring planting.", "sources": ["general horticultural reference"]}')
