  VALUES ('pearl-millet','Pearl Millet','Pennisetum glaucum','cover-crop','grass',5,10,68,95,60,90,'seed','direct','warm','tender','last_frost',1,10,'Sow after last frost in warm soil; the most heat- and drought-tolerant warm-season cover grass, thriving in Gulf Coast summers.',7,11,1,3,60,120,4,8,'full','low','Drill or broadcast seed 1/2 in deep into warm soil; pearl millet germinates and establishes faster than sorghum-sudangrass in sandy, low-fertility soils. It produces large amounts of biomass for smothering weeds and building organic matter, and tolerate short dry spells without wilting like corn or sorghum can. Mow or terminate before seed heads mature to prevent unwanted reseeding. Mix with cowpeas for a combined nitrogen-fixing and biomass cover.','["USDA SARE cover crop guide", "Sustainable Agriculture Research and Education (SARE) cover crop charts"]','{"slug": "pearl-millet", "common_name": "Pearl Millet", "scientific_name": "Pennisetum glaucum", "category": "cover-crop", "subcategory": "grass", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 68, "max": 95}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 10}, "note": "Sow after last frost in warm soil; the most heat- and drought-tolerant warm-season cover grass, thriving in Gulf Coast summers."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 1, "max": 3}, "height_in": {"min": 60, "max": 120}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "low", "directions": "Drill or broadcast seed 1/2 in deep into warm soil; pearl millet germinates and establishes faster than sorghum-sudangrass in sandy, low-fertility soils. It produces large amounts of biomass for smothering weeds and building organic matter, and tolerate short dry spells without wilting like corn or sorghum can. Mow or terminate before seed heads mature to prevent unwanted reseeding. Mix with cowpeas for a combined nitrogen-fixing and biomass cover.", "sources": ["USDA SARE cover crop guide", "Sustainable Agriculture Research and Education (SARE) cover crop charts"]}')
