  VALUES ('perennial-peanut','Perennial Peanut','Arachis glabrata','cover-crop','legume',NULL,NULL,NULL,NULL,365,548,'transplant','transplant','perennial','half-hardy','last_frost',1,6,'Plant rhizome sprigs in late spring once soil is warm; establishment is slow the first season but the stand fills in by year 2.',8,11,12,24,4,10,12,36,'full','low','Plant rhizome sections 2–3 in deep in well-drained, sandy or loamy soil; perennial peanut tolerates poor, acidic soils typical of Gulf Coast landscapes. Establishment is slow the first year but the low, dense mat fixes nitrogen and crowds out weeds without mowing once established. It can be used as a lawn alternative, orchard under-planting, or living mulch in vegetable corridors. In zones 8–9 the top may freeze back in hard winters but the rhizomes resprout reliably from below ground.','["University of Florida IFAS Extension", "Texas A&M AgriLife Extension Service"]','{"slug": "perennial-peanut", "common_name": "Perennial Peanut", "scientific_name": "Arachis glabrata", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 6}, "note": "Plant rhizome sprigs in late spring once soil is warm; establishment is slow the first season but the stand fills in by year 2."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 12, "max": 24}, "height_in": {"min": 4, "max": 10}, "spread_in": {"min": 12, "max": 36}, "sun": "full", "water": "low", "directions": "Plant rhizome sections 2–3 in deep in well-drained, sandy or loamy soil; perennial peanut tolerates poor, acidic soils typical of Gulf Coast landscapes. Establishment is slow the first year but the low, dense mat fixes nitrogen and crowds out weeds without mowing once established. It can be used as a lawn alternative, orchard under-planting, or living mulch in vegetable corridors. In zones 8–9 the top may freeze back in hard winters but the rhizomes resprout reliably from below ground.", "sources": ["University of Florida IFAS Extension", "Texas A&M AgriLife Extension Service"]}')
