  VALUES ('ryegrass-perennial-cover','Perennial Ryegrass (Cover)','Lolium perenne','cover-crop','grass',5,10,50,65,60,90,'seed','direct','cool','hardy','first_frost',-8,-4,'Sow in late summer to early fall; perennial ryegrass establishes fastest of all cool-season grasses and forms dense sod for erosion control.',3,8,1,2,12,24,4,8,'full','moderate','Broadcast seed at 20–30 lb/acre and rake lightly to 1/4 in depth; perennial ryegrass germinates in 5–7 days at optimal temperatures and establishes the fastest ground cover of any cool-season grass, making it excellent for emergency erosion control or orchard middles. It can be used as a short-rotation annual cover in cold winters (zones 3–5) or managed as a persistent sod in mild climates. Terminate before planting vegetables by aggressive mowing followed by solarization or herbicide; perennial ryegrass regrows readily from crowns and requires thorough kill. Mix with red or white clover for a nitrogen-fixing living mulch under fruit trees.','["general horticultural reference"]','{"slug": "ryegrass-perennial-cover", "common_name": "Perennial Ryegrass (Cover)", "scientific_name": "Lolium perenne", "category": "cover-crop", "subcategory": "grass", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow in late summer to early fall; perennial ryegrass establishes fastest of all cool-season grasses and forms dense sod for erosion control."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "moderate", "directions": "Broadcast seed at 20–30 lb/acre and rake lightly to 1/4 in depth; perennial ryegrass germinates in 5–7 days at optimal temperatures and establishes the fastest ground cover of any cool-season grass, making it excellent for emergency erosion control or orchard middles. It can be used as a short-rotation annual cover in cold winters (zones 3–5) or managed as a persistent sod in mild climates. Terminate before planting vegetables by aggressive mowing followed by solarization or herbicide; perennial ryegrass regrows readily from crowns and requires thorough kill. Mix with red or white clover for a nitrogen-fixing living mulch under fruit trees.", "sources": ["general horticultural reference"]}')
