  VALUES ('phacelia','Phacelia (Lacy Phacelia)','Phacelia tanacetifolia','cover-crop','broadleaf',7,14,45,65,45,70,'seed','direct','cool','half-hardy','last_frost',-6,-2,'Sow 2–6 weeks before last spring frost, or in early fall in mild climates; flowers arrive in about 6 weeks and are among the best for attracting bees.',3,9,1,2,18,36,4,8,'full','moderate','Broadcast tiny seed at 3–5 lb per acre (a light dusting per 100 sq ft) on the surface of a firm, moist seedbed without covering, as seed needs light to germinate; rake in very lightly if birds are a problem. Phacelia establishes quickly in cool soil, outcompeting many weeds with dense, ferny foliage that also conserves soil moisture. The blue-purple flowers are exceptional for beneficial insects and bees — allow partial bloom before mowing to maximize pollinator benefit. Terminate by mowing just as the last flowers fade; it decomposes rapidly and leaves no allelopathic residue.','["general horticultural reference"]','{"slug": "phacelia", "common_name": "Phacelia (Lacy Phacelia)", "scientific_name": "Phacelia tanacetifolia", "category": "cover-crop", "subcategory": "broadleaf", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 45, "max": 65}, "days_to_maturity": {"min": 45, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -2}, "note": "Sow 2–6 weeks before last spring frost, or in early fall in mild climates; flowers arrive in about 6 weeks and are among the best for attracting bees."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "moderate", "directions": "Broadcast tiny seed at 3–5 lb per acre (a light dusting per 100 sq ft) on the surface of a firm, moist seedbed without covering, as seed needs light to germinate; rake in very lightly if birds are a problem. Phacelia establishes quickly in cool soil, outcompeting many weeds with dense, ferny foliage that also conserves soil moisture. The blue-purple flowers are exceptional for beneficial insects and bees — allow partial bloom before mowing to maximize pollinator benefit. Terminate by mowing just as the last flowers fade; it decomposes rapidly and leaves no allelopathic residue.", "sources": ["general horticultural reference"]}')
