INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('red-clover','Red Clover','Trifolium pratense','cover-crop','legume',5,10,40,75,60,90,'seed','direct','cool','hardy','first_frost',-8,-4,'Sow 4–8 weeks before first fall frost, or frost-seed in late winter; short-lived perennial that fixes nitrogen and blooms its second year.',3,9,1,2,12,24,6,12,'full','moderate','Broadcast inoculated seed onto a prepared bed at 8–10 lb per acre, raking to 1/4 in depth; red clover tolerates slightly acidic soils and moderate shade better than most legume cover crops. It overwinters in zones 4 and warmer and puts on vigorous growth in early spring, often topping 2 ft before bloom. Terminate at early flower stage — before the first florets open to brown — to capture maximum fixed nitrogen of 80–150 lb per acre. A second flush of growth often follows mowing, allowing a second cut of biomass before final incorporation.','["general horticultural reference"]','{"slug": "red-clover", "common_name": "Red Clover", "scientific_name": "Trifolium pratense", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow 4–8 weeks before first fall frost, or frost-seed in late winter; short-lived perennial that fixes nitrogen and blooms its second year."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Broadcast inoculated seed onto a prepared bed at 8–10 lb per acre, raking to 1/4 in depth; red clover tolerates slightly acidic soils and moderate shade better than most legume cover crops. It overwinters in zones 4 and warmer and puts on vigorous growth in early spring, often topping 2 ft before bloom. Terminate at early flower stage — before the first florets open to brown — to capture maximum fixed nitrogen of 80–150 lb per acre. A second flush of growth often follows mowing, allowing a second cut of biomass before final incorporation.", "sources": ["general horticultural reference"]}')
