  VALUES ('sorghum-sudangrass','Sorghum-Sudangrass','Sorghum bicolor × Sorghum bicolor var. sudanense','cover-crop','grass',5,10,65,95,45,75,'seed','direct','warm','tender','last_frost',1,10,'Sow after last frost when soil is above 65°F; produces massive biomass for weed suppression and soil building.',5,11,1,3,60,120,4,8,'full','low','Broadcast or drill seed 3/4 in deep into warm soil; sorghum-sudangrass hybrids germinate and grow aggressively, reaching 6–8 feet before termination. The dense canopy suppresses even aggressive perennial weeds, and allelopathic root exudates further inhibit weed germination. Mow to 4–6 in to encourage regrowth and additional tillering before final termination; allow residue 2–3 weeks to partially break down before transplanting into it. Avoid planting in soybean rotations immediately after, as the sorghum-family residue can briefly stunt legume establishment.','["USDA SARE cover crop guide", "Midwest Cover Crops Council field guide"]','{"slug": "sorghum-sudangrass", "common_name": "Sorghum-Sudangrass", "scientific_name": "Sorghum bicolor × Sorghum bicolor var. sudanense", "category": "cover-crop", "subcategory": "grass", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 95}, "days_to_maturity": {"min": 45, "max": 75}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 10}, "note": "Sow after last frost when soil is above 65°F; produces massive biomass for weed suppression and soil building."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 1, "max": 3}, "height_in": {"min": 60, "max": 120}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "low", "directions": "Broadcast or drill seed 3/4 in deep into warm soil; sorghum-sudangrass hybrids germinate and grow aggressively, reaching 6–8 feet before termination. The dense canopy suppresses even aggressive perennial weeds, and allelopathic root exudates further inhibit weed germination. Mow to 4–6 in to encourage regrowth and additional tillering before final termination; allow residue 2–3 weeks to partially break down before transplanting into it. Avoid planting in soybean rotations immediately after, as the sorghum-family residue can briefly stunt legume establishment.", "sources": ["USDA SARE cover crop guide", "Midwest Cover Crops Council field guide"]}')
