INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('subterranean-clover','Subterranean Clover','Trifolium subterraneum','cover-crop','legume',5,12,45,70,150,210,'seed','direct','cool','half-hardy','first_frost',-10,-6,'Sow 6–10 weeks before first frost in mild-winter climates; uniquely reseeds itself by burying its own seed pods underground.',7,10,1,2,4,12,6,18,'full','moderate','Broadcast inoculated seed at 15–20 lb/acre onto a well-prepared seedbed in late summer to early fall; subterranean clover tolerates poorly drained and acidic soils better than most annual clovers. The prostrate stems root at nodes and the spent flower heads push seed capsules into the soil surface, allowing the stand to self-reseed year after year without replanting. It fixes moderate nitrogen and forms a dense mat that suppresses winter and spring weeds. Mow or graze lightly in late winter to stimulate pod development, then allow to dry before any tillage.','["general horticultural reference"]','{"slug": "subterranean-clover", "common_name": "Subterranean Clover", "scientific_name": "Trifolium subterraneum", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 12}, "germination_soil_temp_f": {"min": 45, "max": 70}, "days_to_maturity": {"min": 150, "max": 210}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -10, "max": -6}, "note": "Sow 6–10 weeks before first frost in mild-winter climates; uniquely reseeds itself by burying its own seed pods underground."}, "usda_zones": {"min": 7, "max": 10}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 4, "max": 12}, "spread_in": {"min": 6, "max": 18}, "sun": "full", "water": "moderate", "directions": "Broadcast inoculated seed at 15–20 lb/acre onto a well-prepared seedbed in late summer to early fall; subterranean clover tolerates poorly drained and acidic soils better than most annual clovers. The prostrate stems root at nodes and the spent flower heads push seed capsules into the soil surface, allowing the stand to self-reseed year after year without replanting. It fixes moderate nitrogen and forms a dense mat that suppresses winter and spring weeds. Mow or graze lightly in late winter to stimulate pod development, then allow to dry before any tillage.", "sources": ["general horticultural reference"]}')
