  VALUES ('sunn-hemp','Sunn Hemp','Crotalaria juncea','cover-crop','legume',5,10,65,95,60,90,'seed','direct','warm','tender','last_frost',1,8,'Sow after last frost once soil is consistently warm; a standout warm-season nitrogen fixer and nematode suppressor for zone 9–11.',9,11,1,3,48,120,4,8,'full','moderate','Broadcast or drill seed 1/2 in deep into warm, well-drained soil after danger of frost has passed. Sunn hemp grows rapidly — up to 6 feet in two months — and fixes 100–200 lb of nitrogen per acre while suppressing root-knot nematodes through root exudates. Terminate by mowing at first bloom (roughly 60–70 days) before seed set, since mature plants become woody and slow to decompose. Do not plant where livestock can graze, as the foliage contains alkaloids toxic to most grazing animals.','["USDA SARE cover crop guide", "University of Florida IFAS Extension"]','{"slug": "sunn-hemp", "common_name": "Sunn Hemp", "scientific_name": "Crotalaria juncea", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 95}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 8}, "note": "Sow after last frost once soil is consistently warm; a standout warm-season nitrogen fixer and nematode suppressor for zone 9–11."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 1, "max": 3}, "height_in": {"min": 48, "max": 120}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "moderate", "directions": "Broadcast or drill seed 1/2 in deep into warm, well-drained soil after danger of frost has passed. Sunn hemp grows rapidly — up to 6 feet in two months — and fixes 100–200 lb of nitrogen per acre while suppressing root-knot nematodes through root exudates. Terminate by mowing at first bloom (roughly 60–70 days) before seed set, since mature plants become woody and slow to decompose. Do not plant where livestock can graze, as the foliage contains alkaloids toxic to most grazing animals.", "sources": ["USDA SARE cover crop guide", "University of Florida IFAS Extension"]}')
