  VALUES ('daikon-tillage-radish','Tillage Radish (Daikon Cover)','Raphanus sativus var. longipinnatus','cover-crop','brassica',3,7,45,85,50,70,'seed','direct','cool','half-hardy','first_frost',-10,-6,'Sow 6–10 weeks before first frost; the deep taproot breaks up compacted soil and winter-kills in cold zones.',3,9,2,4,12,24,4,8,'full','moderate','Broadcast seed about 1/2 in deep in late summer; the thick taproot drills deep and shatters compaction. In cold-winter areas it dies and rots in place, leaving channels and released nutrients. Where it survives, mow before it flowers to prevent seeding.','["general horticultural reference"]','{"slug": "daikon-tillage-radish", "common_name": "Tillage Radish (Daikon Cover)", "scientific_name": "Raphanus sativus var. longipinnatus", "category": "cover-crop", "subcategory": "brassica", "days_to_germination": {"min": 3, "max": 7}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -10, "max": -6}, "note": "Sow 6–10 weeks before first frost; the deep taproot breaks up compacted soil and winter-kills in cold zones."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 2, "max": 4}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "moderate", "directions": "Broadcast seed about 1/2 in deep in late summer; the thick taproot drills deep and shatters compaction. In cold-winter areas it dies and rots in place, leaving channels and released nutrients. Where it survives, mow before it flowers to prevent seeding.", "sources": ["general horticultural reference"]}')
