INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('triticale-cover','Triticale (Winter Cover)','×Triticosecale rimpaui','cover-crop','grass',5,10,34,72,60,100,'seed','direct','cool','hardy','first_frost',-6,0,'Sow 4–6 weeks before first frost in fall; combines the cold-hardiness of rye with the palatability and residue quality of wheat.',4,9,1,2,36,60,4,8,'full','low','Drill or broadcast seed at 60–90 lb/acre and cover to 1 in depth in fall; triticale is a wheat-rye hybrid that is nearly as cold-hardy as cereal rye but produces softer, lower-lignin residue that breaks down faster in spring. It scavenges soil nitrogen over winter and produces abundant biomass for weed suppression and organic matter. Terminate in early spring at the jointing stage (before the seed head emerges from the boot) by rolling, flail-mowing, or tillage; residue breaks down within 3–4 weeks in warm spring conditions. Pairs well with hairy vetch to combine nitrogen fixation with grass biomass.','["general horticultural reference"]','{"slug": "triticale-cover", "common_name": "Triticale (Winter Cover)", "scientific_name": "×Triticosecale rimpaui", "category": "cover-crop", "subcategory": "grass", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 34, "max": 72}, "days_to_maturity": {"min": 60, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -6, "max": 0}, "note": "Sow 4–6 weeks before first frost in fall; combines the cold-hardiness of rye with the palatability and residue quality of wheat."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "low", "directions": "Drill or broadcast seed at 60–90 lb/acre and cover to 1 in depth in fall; triticale is a wheat-rye hybrid that is nearly as cold-hardy as cereal rye but produces softer, lower-lignin residue that breaks down faster in spring. It scavenges soil nitrogen over winter and produces abundant biomass for weed suppression and organic matter. Terminate in early spring at the jointing stage (before the seed head emerges from the boot) by rolling, flail-mowing, or tillage; residue breaks down within 3–4 weeks in warm spring conditions. Pairs well with hairy vetch to combine nitrogen fixation with grass biomass.", "sources": ["general horticultural reference"]}')
