INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('velvet-bean-cover','Velvet Bean (Mucuna Cover)','Mucuna pruriens var. utilis','cover-crop','legume',7,14,65,95,90,150,'seed','direct','warm','tender','last_frost',1,4,'Sow after last frost; velvet bean is the most aggressive warm-season smothering cover legume, capable of blanketing 100+ sq ft per plant.',9,11,12,24,12,36,36,120,'full','moderate','Plant large seeds 1–2 in deep at 40–60 lb/acre (or 12 in apart in garden rows) after the soil is consistently warm; velvet bean vines scramble aggressively over weeds, fixing up to 400 lb N/acre equivalent while out-competing even nutsedge and Bermuda grass. All plant parts carry stinging trichomes — wear long sleeves and gloves when handling. Terminate by mowing or machete-chopping at flowering, then incorporate for a massive nitrogen and organic-matter boost. The hard, shiny seeds require scarification or a 24-hour soak before planting to improve germination.','["general horticultural reference"]','{"slug": "velvet-bean-cover", "common_name": "Velvet Bean (Mucuna Cover)", "scientific_name": "Mucuna pruriens var. utilis", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 95}, "days_to_maturity": {"min": 90, "max": 150}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 4}, "note": "Sow after last frost; velvet bean is the most aggressive warm-season smothering cover legume, capable of blanketing 100+ sq ft per plant."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 12, "max": 24}, "height_in": {"min": 12, "max": 36}, "spread_in": {"min": 36, "max": 120}, "sun": "full", "water": "moderate", "directions": "Plant large seeds 1–2 in deep at 40–60 lb/acre (or 12 in apart in garden rows) after the soil is consistently warm; velvet bean vines scramble aggressively over weeds, fixing up to 400 lb N/acre equivalent while out-competing even nutsedge and Bermuda grass. All plant parts carry stinging trichomes — wear long sleeves and gloves when handling. Terminate by mowing or machete-chopping at flowering, then incorporate for a massive nitrogen and organic-matter boost. The hard, shiny seeds require scarification or a 24-hour soak before planting to improve germination.", "sources": ["general horticultural reference"]}')
