INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('white-clover','White Clover','Trifolium repens','cover-crop','legume',5,10,40,80,45,70,'seed','direct','perennial','hardy','last_frost',-4,0,'Frost-seed onto bare or thin ground in late winter to early spring; the freeze-thaw cycle works seed into the soil surface naturally.',3,9,1,2,4,8,12,24,'full','moderate','Broadcast inoculated seed at 1/4–1/2 lb per 1,000 sq ft onto a lightly raked surface; the tiny seed needs good soil contact but should not be covered more than 1/4 in. White clover spreads by stolons to form a dense living mulch that fixes nitrogen and feeds beneficial insects with nectar-rich flowers. Mow periodically to prevent flowering from shading out adjacent crops, or allow it to bloom freely when used as a pollinator corridor. In annual vegetable beds, turn the stand under in early spring and wait 2–3 weeks before planting so the nitrogen flush is available to the next crop.','["general horticultural reference"]','{"slug": "white-clover", "common_name": "White Clover", "scientific_name": "Trifolium repens", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 40, "max": 80}, "days_to_maturity": {"min": 45, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Frost-seed onto bare or thin ground in late winter to early spring; the freeze-thaw cycle works seed into the soil surface naturally."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 4, "max": 8}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "moderate", "directions": "Broadcast inoculated seed at 1/4–1/2 lb per 1,000 sq ft onto a lightly raked surface; the tiny seed needs good soil contact but should not be covered more than 1/4 in. White clover spreads by stolons to form a dense living mulch that fixes nitrogen and feeds beneficial insects with nectar-rich flowers. Mow periodically to prevent flowering from shading out adjacent crops, or allow it to bloom freely when used as a pollinator corridor. In annual vegetable beds, turn the stand under in early spring and wait 2–3 weeks before planting so the nitrogen flush is available to the next crop.", "sources": ["general horticultural reference"]}')
