INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('mustard-cover','White Mustard (Cover Crop)','Sinapis alba','cover-crop','brassica',3,7,40,75,45,70,'seed','direct','cool','half-hardy','first_frost',-8,-4,'Sow 4–8 weeks before first fall frost, or in early spring as soon as soil can be worked; a fast-growing brassica smother crop with biofumigant properties.',3,9,1,2,24,48,6,12,'full','moderate','Broadcast seed at 8–10 lb per acre (about 1/4 oz per 100 sq ft) onto a firm seedbed, raking to 1/4 in depth; mustard germinates in cold soil within days and establishes an aggressive canopy that smothers weeds. When chopped and incorporated at early flower stage, the glucosinolates in the tissue break down into biofumigant compounds that suppress soil-borne pathogens and weed seeds — a technique called biofumigation. Mow and immediately till to a 4–6 in depth, then water and tarp the bed for 2 weeks to trap fumigant gases. Terminate before it sets seed, as mustard reseeds abundantly and can become a weed.','["general horticultural reference"]','{"slug": "mustard-cover", "common_name": "White Mustard (Cover Crop)", "scientific_name": "Sinapis alba", "category": "cover-crop", "subcategory": "brassica", "days_to_germination": {"min": 3, "max": 7}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 45, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow 4–8 weeks before first fall frost, or in early spring as soon as soil can be worked; a fast-growing brassica smother crop with biofumigant properties."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Broadcast seed at 8–10 lb per acre (about 1/4 oz per 100 sq ft) onto a firm seedbed, raking to 1/4 in depth; mustard germinates in cold soil within days and establishes an aggressive canopy that smothers weeds. When chopped and incorporated at early flower stage, the glucosinolates in the tissue break down into biofumigant compounds that suppress soil-borne pathogens and weed seeds — a technique called biofumigation. Mow and immediately till to a 4–6 in depth, then water and tarp the bed for 2 weeks to trap fumigant gases. Terminate before it sets seed, as mustard reseeds abundantly and can become a weed.", "sources": ["general horticultural reference"]}')
