  VALUES ('sweet-clover-white','White Sweet Clover','Melilotus albus','cover-crop','legume',7,14,40,75,300,365,'seed','direct','cool','hardy','soil_workable',0,4,'Sow in early spring as soon as soil can be worked, or in late summer 6–8 weeks before frost; a biennial that fixes up to 150 lb N/acre in its second year.',3,9,1,3,24,72,6,12,'full','low','Scarify or inoculate seed with Rhizobium meliloti, then broadcast at 10–15 lb/acre and cover lightly; white sweet clover tolerates alkaline, poor soils where other clovers fail. The plant forms a taproot in year one and overwinters to bloom prolifically in year two, fixing enormous nitrogen and feeding pollinators. Terminate in year two at early bud stage before stems become woody; chop and incorporate so the high-coumarin stems have several weeks to break down before planting. Avoid using freshly mowed green residue as mulch around brassicas, as coumarin can temporarily inhibit germination.','["general horticultural reference"]','{"slug": "sweet-clover-white", "common_name": "White Sweet Clover", "scientific_name": "Melilotus albus", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 300, "max": 365}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Sow in early spring as soon as soil can be worked, or in late summer 6–8 weeks before frost; a biennial that fixes up to 150 lb N/acre in its second year."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 1, "max": 3}, "height_in": {"min": 24, "max": 72}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "low", "directions": "Scarify or inoculate seed with Rhizobium meliloti, then broadcast at 10–15 lb/acre and cover lightly; white sweet clover tolerates alkaline, poor soils where other clovers fail. The plant forms a taproot in year one and overwinters to bloom prolifically in year two, fixing enormous nitrogen and feeding pollinators. Terminate in year two at early bud stage before stems become woody; chop and incorporate so the high-coumarin stems have several weeks to break down before planting. Avoid using freshly mowed green residue as mulch around brassicas, as coumarin can temporarily inhibit germination.", "sources": ["general horticultural reference"]}')
