  VALUES ('winter-rye','Winter Rye (Cereal Rye)','Secale cereale','cover-crop','grass',5,10,34,75,60,90,'seed','direct','cool','hardy','first_frost',-6,2,'Sow from 6 weeks before to just after first frost; the most cold-hardy cover crop, germinating in near-freezing soil.',3,11,1,2,36,60,4,8,'full','low','Broadcast seed at about 1/2 in depth in fall; it germinates in cold soil when little else will. It scavenges leftover nitrogen and smothers weeds over winter, then puts on fast spring growth. Mow and turn under 2–3 weeks before planting, as its residue briefly suppresses small seeds.','["general horticultural reference"]','{"slug": "winter-rye", "common_name": "Winter Rye (Cereal Rye)", "scientific_name": "Secale cereale", "category": "cover-crop", "subcategory": "grass", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 34, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -6, "max": 2}, "note": "Sow from 6 weeks before to just after first frost; the most cold-hardy cover crop, germinating in near-freezing soil."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "low", "directions": "Broadcast seed at about 1/2 in depth in fall; it germinates in cold soil when little else will. It scavenges leftover nitrogen and smothers weeds over winter, then puts on fast spring growth. Mow and turn under 2–3 weeks before planting, as its residue briefly suppresses small seeds.", "sources": ["general horticultural reference"]}')
