INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sweet-clover-yellow','Yellow Sweet Clover','Melilotus officinalis','cover-crop','legume',7,14,40,75,300,365,'seed','direct','cool','hardy','soil_workable',0,4,'Direct-sow in early spring or late summer; behaves like white sweet clover but is slightly shorter and prefers drier soils.',3,9,1,3,24,60,6,12,'full','low','Scarify hard-coated seed before sowing to improve germination, and inoculate with Sinorhizobium meliloti for reliable nitrogen fixation in new plantings. Broadcast at 10–12 lb/acre and press lightly into a firm seedbed; yellow sweet clover is more drought-tolerant than most clovers and establishes well on thin, calcareous soils. It overwinters as a rosette and bolts to bloom in spring of the second year; terminate at early bud for maximum N contribution. Allow 3–4 weeks between incorporation and planting to let allelopathic coumarin compounds dissipate.','["general horticultural reference"]','{"slug": "sweet-clover-yellow", "common_name": "Yellow Sweet Clover", "scientific_name": "Melilotus officinalis", "category": "cover-crop", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 300, "max": 365}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Direct-sow in early spring or late summer; behaves like white sweet clover but is slightly shorter and prefers drier soils."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 1, "max": 3}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "low", "directions": "Scarify hard-coated seed before sowing to improve germination, and inoculate with Sinorhizobium meliloti for reliable nitrogen fixation in new plantings. Broadcast at 10–12 lb/acre and press lightly into a firm seedbed; yellow sweet clover is more drought-tolerant than most clovers and establishes well on thin, calcareous soils. It overwinters as a rosette and bolts to bloom in spring of the second year; terminate at early bud for maximum N contribution. Allow 3–4 weeks between incorporation and planting to let allelopathic coumarin compounds dissipate.", "sources": ["general horticultural reference"]}')
