INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('osteospermum','African Daisy','Osteospermum ecklonis','flower','annual',10,14,65,75,60,80,'transplant','indoor-start','cool','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant 2–4 weeks before last frost as plants tolerate light frost.',2,11,12,18,10,20,12,20,'full','moderate','Sow seeds 1/4 in deep in well-drained germination mix; seedlings grow quickly and should be potted on before becoming root-bound. Plant in full sun in well-drained soil as soon as the risk of hard frost has passed; osteospermum thrives in cool weather and slows during peak summer heat. Deadhead spent flowers to encourage continuous bloom and pinch stem tips to promote branching early in the season. In zones 9–11 it may survive as a short-lived perennial; take stem cuttings in late summer to perpetuate favorite selections.','["general horticultural reference"]','{"slug": "osteospermum", "common_name": "African Daisy", "scientific_name": "Osteospermum ecklonis", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant 2–4 weeks before last frost as plants tolerate light frost."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 10, "max": 20}, "spread_in": {"min": 12, "max": 20}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep in well-drained germination mix; seedlings grow quickly and should be potted on before becoming root-bound. Plant in full sun in well-drained soil as soon as the risk of hard frost has passed; osteospermum thrives in cool weather and slows during peak summer heat. Deadhead spent flowers to encourage continuous bloom and pinch stem tips to promote branching early in the season. In zones 9–11 it may survive as a short-lived perennial; take stem cuttings in late summer to perpetuate favorite selections.", "sources": ["general horticultural reference"]}')
