INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('marigold-african','African Marigold','Tagetes erecta','flower','annual',4,7,70,75,60,90,'transplant','indoor-start','warm','tender','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after nights stay reliably above 50°F.',2,11,12,18,18,36,12,18,'full','moderate','Sow seed 1/4 in deep in a warm starting mix and keep evenly moist until germination. Transplant after all frost risk is gone, spacing larger varieties 12–18 in apart. Deadhead large pompom blooms as they fade to redirect energy to new buds. Tall varieties may need staking in exposed, windy sites.','["general horticultural reference"]','{"slug": "marigold-african", "common_name": "African Marigold", "scientific_name": "Tagetes erecta", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after nights stay reliably above 50°F."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep in a warm starting mix and keep evenly moist until germination. Transplant after all frost risk is gone, spacing larger varieties 12–18 in apart. Deadhead large pompom blooms as they fade to redirect energy to new buds. Tall varieties may need staking in exposed, windy sites.", "sources": ["general horticultural reference"]}')
