INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ageratum','Ageratum (Floss Flower)','Ageratum houstonianum','flower','annual',5,10,70,75,60,80,'transplant','indoor-start','warm','tender','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after all frost risk has passed.',3,11,6,10,6,18,6,10,'full','moderate','Sow dust-fine seed on the surface of moist starting mix without covering — light is essential for germination. Ageratum produces fluffy, powder-puff blooms that attract butterflies and beneficial insects. Shear plants back lightly when flowering slows or plants become leggy to promote a fresh flush of bloom. Consistent moisture is important, as dry conditions cause the plants to stop flowering.','["general horticultural reference"]','{"slug": "ageratum", "common_name": "Ageratum (Floss Flower)", "scientific_name": "Ageratum houstonianum", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after all frost risk has passed."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 10}, "height_in": {"min": 6, "max": 18}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Sow dust-fine seed on the surface of moist starting mix without covering — light is essential for germination. Ageratum produces fluffy, powder-puff blooms that attract butterflies and beneficial insects. Shear plants back lightly when flowering slows or plants become leggy to promote a fresh flush of bloom. Consistent moisture is important, as dry conditions cause the plants to stop flowering.", "sources": ["general horticultural reference"]}')
