INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('angelonia','Angelonia','Angelonia angustifolia','flower','annual',14,21,70,75,60,80,'transplant','indoor-start','warm','tender','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; transplant after all frost danger has passed and soil has warmed.',2,11,12,18,12,24,10,14,'full','moderate','Start seeds on the surface of a moist, fine-textured germination mix at 70–75°F; seeds need light to germinate so do not cover. Transplant into full sun after last frost, spacing 12–18 in apart in well-drained soil enriched with compost. Angelonia is heat- and drought-tolerant once established and rarely needs deadheading, as spent florets drop cleanly. Pinch stem tips early to encourage branching and a fuller plant shape.','["general horticultural reference"]','{"slug": "angelonia", "common_name": "Angelonia", "scientific_name": "Angelonia angustifolia", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; transplant after all frost danger has passed and soil has warmed."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 10, "max": 14}, "sun": "full", "water": "moderate", "directions": "Start seeds on the surface of a moist, fine-textured germination mix at 70–75°F; seeds need light to germinate so do not cover. Transplant into full sun after last frost, spacing 12–18 in apart in well-drained soil enriched with compost. Angelonia is heat- and drought-tolerant once established and rarely needs deadheading, as spent florets drop cleanly. Pinch stem tips early to encourage branching and a fuller plant shape.", "sources": ["general horticultural reference"]}')
