  VALUES ('annual-salvia','Annual Salvia','Salvia splendens','flower','annual',12,21,70,75,70,100,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after frost danger has completely passed.',3,11,10,14,12,30,10,14,'full','moderate','Sow seed on the surface of moist starting mix, barely pressing in, as light aids germination. Grow on under bright light to prevent tall, weak seedlings before transplanting. Remove spent spikes at their base to encourage a continuous succession of new flower stems. Annual salvia blooms from early summer until the first hard frost.','["general horticultural reference"]','{"slug": "annual-salvia", "common_name": "Annual Salvia", "scientific_name": "Salvia splendens", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 12, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 70, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after frost danger has completely passed."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 10, "max": 14}, "height_in": {"min": 12, "max": 30}, "spread_in": {"min": 10, "max": 14}, "sun": "full", "water": "moderate", "directions": "Sow seed on the surface of moist starting mix, barely pressing in, as light aids germination. Grow on under bright light to prevent tall, weak seedlings before transplanting. Remove spent spikes at their base to encourage a continuous succession of new flower stems. Annual salvia blooms from early summer until the first hard frost.", "sources": ["general horticultural reference"]}')
