INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('annual-vinca','Annual Vinca (Catharanthus)','Catharanthus roseus','flower','annual',14,21,75,80,70,90,'transplant','indoor-start','warm','tender','last_frost',-12,-10,'Start indoors 10–12 weeks before last frost; transplant only when nights are consistently above 55°F.',3,11,10,14,12,24,12,18,'full','low','Sow seed 1/4 in deep in warm, moist starting mix and maintain soil temperature above 75°F for best germination. Annual vinca is self-cleaning and requires no deadheading, shedding spent blooms on its own. It excels in summer heat and humidity and is highly drought tolerant. Avoid planting in cold or wet soil, as chilling causes the foliage to yellow and growth to stall.','["general horticultural reference"]','{"slug": "annual-vinca", "common_name": "Annual Vinca (Catharanthus)", "scientific_name": "Catharanthus roseus", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 75, "max": 80}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -12, "max": -10}, "note": "Start indoors 10–12 weeks before last frost; transplant only when nights are consistently above 55°F."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 10, "max": 14}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seed 1/4 in deep in warm, moist starting mix and maintain soil temperature above 75°F for best germination. Annual vinca is self-cleaning and requires no deadheading, shedding spent blooms on its own. It excels in summer heat and humidity and is highly drought tolerant. Avoid planting in cold or wet soil, as chilling causes the foliage to yellow and growth to stall.", "sources": ["general horticultural reference"]}')
