  VALUES ('asiatic-lily','Asiatic Lily','Lilium asiatic hybrids','flower','bulb',NULL,NULL,NULL,NULL,80,120,'transplant','bulb','perennial','hardy','spring',-2,2,'Plant bulbs in spring as soon as soil is workable, or in fall for early establishment.',3,8,12,18,24,48,12,18,'full','moderate','Plant bulbs scales-down at a depth of 3 times the bulb''s height, typically 6–8 in deep, in well-drained, humus-rich soil. Lilies prefer cool roots but sunny tops; mulch the soil surface and underplant with low perennials to shade the root zone. Remove only spent flowers, never the stem and leaves, so the plant can photosynthesize and recharge the bulb. Red lily beetle is a serious pest in many regions; inspect plants regularly and remove beetles and larvae by hand.','["general horticultural reference"]','{"slug": "asiatic-lily", "common_name": "Asiatic Lily", "scientific_name": "Lilium asiatic hybrids", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 80, "max": 120}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Plant bulbs in spring as soon as soil is workable, or in fall for early establishment."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Plant bulbs scales-down at a depth of 3 times the bulb''s height, typically 6–8 in deep, in well-drained, humus-rich soil. Lilies prefer cool roots but sunny tops; mulch the soil surface and underplant with low perennials to shade the root zone. Remove only spent flowers, never the stem and leaves, so the plant can photosynthesize and recharge the bulb. Red lily beetle is a serious pest in many regions; inspect plants regularly and remove beetles and larvae by hand.", "sources": ["general horticultural reference"]}')
