  VALUES ('bachelor-button','Bachelor Button (Cornflower)','Centaurea cyanus','flower','annual',7,14,55,65,60,90,'seed','direct','cool','hardy','last_frost',-6,-4,'Direct sow 4–6 weeks before last frost; seeds germinate in cool soil and young plants are frost hardy. For fall bloom, sow again in late summer.',2,11,6,12,12,36,6,10,'full','low','Direct sow seed 1/4 in deep in early spring as soon as the soil can be worked. Bachelor buttons resent transplanting due to a taproot and grow best when started in place. Deadhead spent flowers to prolong blooming, or allow a few to set seed for natural reseeding. Plants decline in summer heat; a second sowing in late summer yields a flush of fall bloom in cool climates.','["general horticultural reference"]','{"slug": "bachelor-button", "common_name": "Bachelor Button (Cornflower)", "scientific_name": "Centaurea cyanus", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Direct sow 4–6 weeks before last frost; seeds germinate in cool soil and young plants are frost hardy. For fall bloom, sow again in late summer."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 12, "max": 36}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "low", "directions": "Direct sow seed 1/4 in deep in early spring as soon as the soil can be worked. Bachelor buttons resent transplanting due to a taproot and grow best when started in place. Deadhead spent flowers to prolong blooming, or allow a few to set seed for natural reseeding. Plants decline in summer heat; a second sowing in late summer yields a flush of fall bloom in cool climates.", "sources": ["general horticultural reference"]}')
