INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('balloon-flower','Balloon Flower','Platycodon grandiflorus','flower','perennial',14,21,60,70,365,730,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost or direct sow outdoors in early spring; blooms appear the second year from seed.',3,8,12,18,18,30,12,18,'full','moderate','Sow seeds shallowly, just barely covering them, since light aids germination; thin or transplant to 12–18 in spacing. Balloon flowers are late to emerge in spring — mark their location to avoid accidentally digging the fleshy taproot. Deadhead spent flowers to extend the blooming period through summer, and avoid dividing since the taproot resents disturbance. Plants are long-lived and improve in beauty over many years with minimal care.','["general horticultural reference"]','{"slug": "balloon-flower", "common_name": "Balloon Flower", "scientific_name": "Platycodon grandiflorus", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost or direct sow outdoors in early spring; blooms appear the second year from seed."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds shallowly, just barely covering them, since light aids germination; thin or transplant to 12–18 in spacing. Balloon flowers are late to emerge in spring — mark their location to avoid accidentally digging the fleshy taproot. Deadhead spent flowers to extend the blooming period through summer, and avoid dividing since the taproot resents disturbance. Plants are long-lived and improve in beauty over many years with minimal care.", "sources": ["general horticultural reference"]}')
