INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('bells-of-ireland','Bells of Ireland','Moluccella laevis','flower','annual',25,35,55,65,90,100,'seed','direct','cool','half-hardy','last_frost',-2,0,'Direct sow around last frost date; seeds need cool temperatures to germinate and benefit from cold stratification.',2,11,9,12,24,36,9,12,'full','moderate','Refrigerate seeds for one week before sowing; then direct sow on the soil surface in early spring since seeds need light and cool temperatures to germinate. Thin to 9–12 in apart — crowded plants are prone to powdery mildew. The tall, architectural stems bear small white flowers nestled inside large, shell-shaped green calyces that remain ornamental for months and dry beautifully. Cut stems for fresh or dried arrangements before calyces begin to brown.','["general horticultural reference"]','{"slug": "bells-of-ireland", "common_name": "Bells of Ireland", "scientific_name": "Moluccella laevis", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 25, "max": 35}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 90, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 0}, "note": "Direct sow around last frost date; seeds need cool temperatures to germinate and benefit from cold stratification."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "moderate", "directions": "Refrigerate seeds for one week before sowing; then direct sow on the soil surface in early spring since seeds need light and cool temperatures to germinate. Thin to 9–12 in apart — crowded plants are prone to powdery mildew. The tall, architectural stems bear small white flowers nestled inside large, shell-shaped green calyces that remain ornamental for months and dry beautifully. Cut stems for fresh or dried arrangements before calyces begin to brown.", "sources": ["general horticultural reference"]}')
