INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('bishops-flower','Bishop''s Flower','Ammi majus','flower','annual',7,14,55,65,90,120,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow in early spring 2–4 weeks before last frost; does not transplant well — sow in situ.',2,11,9,12,30,48,9,12,'full','moderate','Sow seeds directly where they are to grow, pressing them onto moist soil — they need light to germinate; thin to 9–12 in apart. Ammi majus produces flat, lacy white umbels similar to Queen Anne''s Lace but with cleaner, more refined flowers that are highly valued by florists. The feathery foliage and long stems make it an ideal filler in bouquets with a vase life of 7–10 days. Successive sowings 3–4 weeks apart extend the harvest period; plants bolt in summer heat so succession-sow in spring only.','["general horticultural reference"]','{"slug": "bishops-flower", "common_name": "Bishop''s Flower", "scientific_name": "Ammi majus", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring 2–4 weeks before last frost; does not transplant well — sow in situ."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 30, "max": 48}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds directly where they are to grow, pressing them onto moist soil — they need light to germinate; thin to 9–12 in apart. Ammi majus produces flat, lacy white umbels similar to Queen Anne''s Lace but with cleaner, more refined flowers that are highly valued by florists. The feathery foliage and long stems make it an ideal filler in bouquets with a vase life of 7–10 days. Successive sowings 3–4 weeks apart extend the harvest period; plants bolt in summer heat so succession-sow in spring only.", "sources": ["general horticultural reference"]}')
