INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('black-eyed-susan','Black-Eyed Susan','Rudbeckia hirta','flower','perennial',7,21,65,75,60,90,'seed','direct','perennial','hardy','last_frost',-2,2,'Direct sow on or near last frost date; seeds need light to germinate so press onto soil surface.',3,9,18,24,24,36,18,24,'full','low','Press seeds onto the soil surface — they need light to germinate and should not be covered. Plants often bloom their first year from an early start, flowering freely into fall. Deadhead to prolong blooming or allow seeds to self-sow for a naturalized planting. Rudbeckia fulgida varieties are longer-lived perennials; divide every 3 years to refresh the planting.','["general horticultural reference"]','{"slug": "black-eyed-susan", "common_name": "Black-Eyed Susan", "scientific_name": "Rudbeckia hirta", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Direct sow on or near last frost date; seeds need light to germinate so press onto soil surface."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Press seeds onto the soil surface — they need light to germinate and should not be covered. Plants often bloom their first year from an early start, flowering freely into fall. Deadhead to prolong blooming or allow seeds to self-sow for a naturalized planting. Rudbeckia fulgida varieties are longer-lived perennials; divide every 3 years to refresh the planting.", "sources": ["general horticultural reference"]}')
