INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('blanket-flower','Blanket Flower','Gaillardia x grandiflora','flower','perennial',14,21,70,75,90,120,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; do not cover seeds, as light aids germination.',3,10,18,24,18,30,18,24,'full','low','Press seeds onto the surface of moist growing medium and provide warmth (70–75°F) and bright light without covering; transplant after frost into sharply drained, even poor soil since gaillardia thrives on neglect. Deadhead spent blooms continuously to keep the bold red and yellow flowers coming from early summer through frost. Avoid clay soils and overwatering — wet conditions in winter are the primary cause of plant loss. Divide or replace plants every 2–3 years, as they tend to be short-lived perennials.','["general horticultural reference"]','{"slug": "blanket-flower", "common_name": "Blanket Flower", "scientific_name": "Gaillardia x grandiflora", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; do not cover seeds, as light aids germination."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Press seeds onto the surface of moist growing medium and provide warmth (70–75°F) and bright light without covering; transplant after frost into sharply drained, even poor soil since gaillardia thrives on neglect. Deadhead spent blooms continuously to keep the bold red and yellow flowers coming from early summer through frost. Avoid clay soils and overwatering — wet conditions in winter are the primary cause of plant loss. Divide or replace plants every 2–3 years, as they tend to be short-lived perennials.", "sources": ["general horticultural reference"]}')
