INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('bleeding-heart','Bleeding Heart','Lamprocapnos spectabilis','flower','perennial',30,60,60,65,270,365,'transplant','division','perennial','hardy','spring',-2,2,'Plant bare-root crowns in early spring as soon as the soil can be worked; dormant division in fall is also successful.',3,9,24,36,24,36,24,36,'partial','moderate','Plant crowns 1–2 in deep in cool, humus-rich, consistently moist but well-drained soil in partial shade. Bleeding heart goes dormant by midsummer in warm climates — interplant with hostas, ferns, or other shade-lovers to fill the gap left when the foliage yellows and dies back. Divide clumps every 4–5 years in early spring just as new growth emerges; the fleshy roots are brittle, so handle with care. All parts of the plant are mildly toxic if ingested.','["general horticultural reference"]','{"slug": "bleeding-heart", "common_name": "Bleeding Heart", "scientific_name": "Lamprocapnos spectabilis", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 30, "max": 60}, "germination_soil_temp_f": {"min": 60, "max": 65}, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Plant bare-root crowns in early spring as soon as the soil can be worked; dormant division in fall is also successful."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 24, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Plant crowns 1–2 in deep in cool, humus-rich, consistently moist but well-drained soil in partial shade. Bleeding heart goes dormant by midsummer in warm climates — interplant with hostas, ferns, or other shade-lovers to fill the gap left when the foliage yellows and dies back. Divide clumps every 4–5 years in early spring just as new growth emerges; the fleshy roots are brittle, so handle with care. All parts of the plant are mildly toxic if ingested.", "sources": ["general horticultural reference"]}')
