INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('blue-fescue','Blue Fescue','Festuca glauca','flower','ornamental-grass',14,21,60,70,90,120,'seed','division','perennial','hardy','spring',0,4,'Plant divisions or container-grown plants in spring or fall; division every 2–3 years maintains the intense blue color.',4,8,9,12,6,12,9,12,'full','low','Plant in full sun and very well-drained, lean to average soil; blue fescue is a cool-season grass that goes semi-dormant in the heat of summer and performs best in cool, dry climates. The tight, spiky mounds of intensely silvery-blue foliage are striking as edging or mass plantings; tan flower spikes appear in early summer. Divide every 2–3 years in early spring, discarding the dead center and replanting the vigorous outer portions — this maintains the best blue coloration. Avoid heavy, wet clay soils and humid conditions which promote crown rot.','["general horticultural reference"]','{"slug": "blue-fescue", "common_name": "Blue Fescue", "scientific_name": "Festuca glauca", "category": "flower", "subcategory": "ornamental-grass", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions or container-grown plants in spring or fall; division every 2–3 years maintains the intense blue color."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "low", "directions": "Plant in full sun and very well-drained, lean to average soil; blue fescue is a cool-season grass that goes semi-dormant in the heat of summer and performs best in cool, dry climates. The tight, spiky mounds of intensely silvery-blue foliage are striking as edging or mass plantings; tan flower spikes appear in early summer. Divide every 2–3 years in early spring, discarding the dead center and replanting the vigorous outer portions — this maintains the best blue coloration. Avoid heavy, wet clay soils and humid conditions which promote crown rot.", "sources": ["general horticultural reference"]}')
