INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('rudbeckia-triloba','Brown-Eyed Susan','Rudbeckia triloba','flower','perennial',7,14,65,75,90,120,'seed','direct','perennial','hardy','last_frost',-2,2,'Direct sow around last frost date or start indoors 6–8 weeks earlier for bloom the first season.',3,8,18,24,24,60,18,24,'full','moderate','Press seeds onto moist soil surface or cover very lightly; they need light to germinate and germinate readily in 7–14 days. Unlike Rudbeckia hirta, R. triloba is a true biennial-to-short-lived-perennial that produces abundant small golden-yellow flowers with a dark center from midsummer through hard frost. Plant in full sun to partial shade in average garden soil; plants self-sow prolifically and naturalize easily in meadow and prairie plantings. Deadhead some stems to extend the season and let others set seed to perpetuate the colony.','["general horticultural reference"]','{"slug": "rudbeckia-triloba", "common_name": "Brown-Eyed Susan", "scientific_name": "Rudbeckia triloba", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Direct sow around last frost date or start indoors 6–8 weeks earlier for bloom the first season."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Press seeds onto moist soil surface or cover very lightly; they need light to germinate and germinate readily in 7–14 days. Unlike Rudbeckia hirta, R. triloba is a true biennial-to-short-lived-perennial that produces abundant small golden-yellow flowers with a dark center from midsummer through hard frost. Plant in full sun to partial shade in average garden soil; plants self-sow prolifically and naturalize easily in meadow and prairie plantings. Deadhead some stems to extend the season and let others set seed to perpetuate the colony.", "sources": ["general horticultural reference"]}')
