INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('butterfly-weed','Butterfly Weed','Asclepias tuberosa','flower','perennial',21,30,70,85,365,730,'seed','direct','perennial','hardy','last_frost',-10,-8,'Cold-stratify seeds for 4–6 weeks in the refrigerator, then start indoors; or direct sow in fall for natural stratification and spring emergence.',3,9,18,24,18,36,18,24,'full','low','Cold-stratify seeds by mixing with moist sand in a sealed bag and refrigerating for 30 days before sowing at soil surface — seeds need light and should not be covered. Butterfly weed has a deep taproot that makes it drought tolerant once established but very sensitive to transplanting; direct sowing or using deep individual cells causes the least disturbance. First-year plants rarely bloom, investing energy into root development; blooms appear reliably from the second year onward in vivid orange clusters that are among the most attractive nectar sources for monarchs and other butterflies. Leave seedheads through winter to self-sow and feed birds.','["Lady Bird Johnson Wildflower Center", "general horticultural reference"]','{"slug": "butterfly-weed", "common_name": "Butterfly Weed", "scientific_name": "Asclepias tuberosa", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 30}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Cold-stratify seeds for 4–6 weeks in the refrigerator, then start indoors; or direct sow in fall for natural stratification and spring emergence."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Cold-stratify seeds by mixing with moist sand in a sealed bag and refrigerating for 30 days before sowing at soil surface — seeds need light and should not be covered. Butterfly weed has a deep taproot that makes it drought tolerant once established but very sensitive to transplanting; direct sowing or using deep individual cells causes the least disturbance. First-year plants rarely bloom, investing energy into root development; blooms appear reliably from the second year onward in vivid orange clusters that are among the most attractive nectar sources for monarchs and other butterflies. Leave seedheads through winter to self-sow and feed birds.", "sources": ["Lady Bird Johnson Wildflower Center", "general horticultural reference"]}')
