INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('caladium','Caladium','Caladium bicolor','flower','bulb',NULL,NULL,NULL,NULL,60,90,'transplant','tuber','warm','tender','last_frost',0,3,'Plant tubers after all frost danger passes and soil is reliably above 70°F; cold soil causes rot.',9,12,12,18,12,30,12,18,'partial','moderate','Set tubers knobby-side up, 2 in deep in rich, moist, well-drained soil; for a head start, pot tubers indoors 6–8 weeks before the last frost date in a warm (75–80°F) location. Caladiums are prized for spectacular heart-shaped foliage in combinations of red, pink, white, and green rather than for their flowers. They excel in shady spots where little else provides vibrant color and thrive in humid conditions. In fall, before temperatures drop below 50°F, dig tubers, allow to cure for 2 weeks, and store in dry vermiculite at 60–65°F.','["general horticultural reference"]','{"slug": "caladium", "common_name": "Caladium", "scientific_name": "Caladium bicolor", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "tuber", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 3}, "note": "Plant tubers after all frost danger passes and soil is reliably above 70°F; cold soil causes rot."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 30}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Set tubers knobby-side up, 2 in deep in rich, moist, well-drained soil; for a head start, pot tubers indoors 6–8 weeks before the last frost date in a warm (75–80°F) location. Caladiums are prized for spectacular heart-shaped foliage in combinations of red, pink, white, and green rather than for their flowers. They excel in shady spots where little else provides vibrant color and thrive in humid conditions. In fall, before temperatures drop below 50°F, dig tubers, allow to cure for 2 weeks, and store in dry vermiculite at 60–65°F.", "sources": ["general horticultural reference"]}')
