INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('calendula','Calendula (Pot Marigold)','Calendula officinalis','flower','annual',7,14,55,65,45,70,'seed','direct','cool','half-hardy','last_frost',-6,-4,'Direct sow 4–6 weeks before last frost in cool soil; young plants tolerate frost and prefer cool weather.',2,11,8,12,12,24,10,14,'full','moderate','Sow seed 1/4 in deep in cool, well-drained soil in early spring. Calendula prefers cool weather and will slow or stop blooming when summer heat arrives, often rebounding in fall. Deadhead consistently to prevent seed set and extend the blooming period. The ray petals are edible and can be used as a garnish or in salads.','["general horticultural reference"]','{"slug": "calendula", "common_name": "Calendula (Pot Marigold)", "scientific_name": "Calendula officinalis", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 45, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Direct sow 4–6 weeks before last frost in cool soil; young plants tolerate frost and prefer cool weather."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 10, "max": 14}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep in cool, well-drained soil in early spring. Calendula prefers cool weather and will slow or stop blooming when summer heat arrives, often rebounding in fall. Deadhead consistently to prevent seed set and extend the blooming period. The ray petals are edible and can be used as a garnish or in salads.", "sources": ["general horticultural reference"]}')
