INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('camassia','Camassia','Camassia leichtlinii','flower','bulb',NULL,NULL,NULL,NULL,150,180,'transplant','bulb','perennial','hardy','fall',-8,-4,'Plant bulbs in fall, 4–6 in deep in moist, fertile soil; camassia tolerates seasonally wet conditions better than most bulbs.',3,8,4,6,24,36,4,6,'full','moderate','Plant bulbs 4–6 in deep in organically rich, moisture-retentive soil; unlike many spring bulbs, camassia tolerates and even prefers seasonally moist or wet ground. Star-shaped flowers in blue, violet, or creamy white appear on tall spikes in late spring, bridging the gap between early bulbs and summer perennials. Allow foliage to die back naturally after blooming; bulbs naturalize readily in meadow or prairie-style plantings. Deer and rodents avoid camassia bulbs.','["general horticultural reference"]','{"slug": "camassia", "common_name": "Camassia", "scientific_name": "Camassia leichtlinii", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 150, "max": 180}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant bulbs in fall, 4–6 in deep in moist, fertile soil; camassia tolerates seasonally wet conditions better than most bulbs."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Plant bulbs 4–6 in deep in organically rich, moisture-retentive soil; unlike many spring bulbs, camassia tolerates and even prefers seasonally moist or wet ground. Star-shaped flowers in blue, violet, or creamy white appear on tall spikes in late spring, bridging the gap between early bulbs and summer perennials. Allow foliage to die back naturally after blooming; bulbs naturalize readily in meadow or prairie-style plantings. Deer and rodents avoid camassia bulbs.", "sources": ["general horticultural reference"]}')
