INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('canna-lily','Canna Lily','Canna x generalis','flower','bulb',NULL,NULL,NULL,NULL,90,120,'transplant','tuber','perennial','tender','last_frost',0,2,'Plant rhizomes after the last frost when soil is warm; or start indoors in pots 4–6 weeks early.',8,12,18,36,36,96,24,36,'full','high','Plant rhizomes 2–4 in deep with the growing eyes pointing up after all frost danger has passed and soil has warmed; starting in pots indoors 4–6 weeks early extends the season in short-summer regions. Cannas are heavy feeders — apply a balanced slow-release fertilizer at planting and a monthly liquid feed during the growing season. Deadhead by removing the entire spent flower spike back to a side shoot to keep the display going. In zones below 8, dig rhizomes after frost, allow to dry for a day, then pack in barely moist peat or newspaper at 50–55°F for winter storage.','["general horticultural reference"]','{"slug": "canna-lily", "common_name": "Canna Lily", "scientific_name": "Canna x generalis", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "tuber", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Plant rhizomes after the last frost when soil is warm; or start indoors in pots 4–6 weeks early."}, "usda_zones": {"min": 8, "max": 12}, "spacing_in": {"min": 18, "max": 36}, "height_in": {"min": 36, "max": 96}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "high", "directions": "Plant rhizomes 2–4 in deep with the growing eyes pointing up after all frost danger has passed and soil has warmed; starting in pots indoors 4–6 weeks early extends the season in short-summer regions. Cannas are heavy feeders — apply a balanced slow-release fertilizer at planting and a monthly liquid feed during the growing season. Deadhead by removing the entire spent flower spike back to a side shoot to keep the display going. In zones below 8, dig rhizomes after frost, allow to dry for a day, then pack in barely moist peat or newspaper at 50–55°F for winter storage.", "sources": ["general horticultural reference"]}')
