INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cardinal-flower','Cardinal Flower','Lobelia cardinalis','flower','perennial',14,21,65,75,365,730,'seed','indoor-start','perennial','hardy','last_frost',-10,-8,'Start seeds indoors 8–10 weeks before last frost; surface-sow without covering as seeds need light to germinate.',3,9,12,18,24,48,12,18,'partial','high','Surface-sow tiny seeds on moist mix and provide light at 65–70°F; seedlings emerge in 2–3 weeks and grow slowly their first season. Plant in consistently moist to wet soil — rain gardens, pond edges, and low-lying areas suit this plant perfectly. Brilliant red spikes appear in midsummer to early fall and are hummingbird magnets. Individual plants are short-lived (2–3 years), so allow self-sowing or divide offsets each spring to maintain the colony.','["general horticultural reference"]','{"slug": "cardinal-flower", "common_name": "Cardinal Flower", "scientific_name": "Lobelia cardinalis", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start seeds indoors 8–10 weeks before last frost; surface-sow without covering as seeds need light to germinate."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "high", "directions": "Surface-sow tiny seeds on moist mix and provide light at 65–70°F; seedlings emerge in 2–3 weeks and grow slowly their first season. Plant in consistently moist to wet soil — rain gardens, pond edges, and low-lying areas suit this plant perfectly. Brilliant red spikes appear in midsummer to early fall and are hummingbird magnets. Individual plants are short-lived (2–3 years), so allow self-sowing or divide offsets each spring to maintain the colony.", "sources": ["general horticultural reference"]}')
