INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('catmint','Catmint','Nepeta x faassenii','flower','perennial',14,21,60,70,60,90,'transplant','division','perennial','hardy','spring',0,4,'Plant in spring or fall in well-drained soil; plants establish quickly and bloom the first season.',3,8,18,24,12,24,24,36,'full','low','Plant in lean, well-drained soil — catmint thrives in conditions that would challenge many perennials and blooms heavily from spring into early summer. Shear the entire plant back by one-half after the first flowering flush to refresh the mounding habit and trigger a second wave of lavender-blue flowers in late summer. The silvery-green aromatic foliage is deer-resistant and provides a reliable edging throughout the season. Divide in spring every 3–4 years or propagate from cuttings taken in late spring.','["general horticultural reference"]','{"slug": "catmint", "common_name": "Catmint", "scientific_name": "Nepeta x faassenii", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring or fall in well-drained soil; plants establish quickly and bloom the first season."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Plant in lean, well-drained soil — catmint thrives in conditions that would challenge many perennials and blooms heavily from spring into early summer. Shear the entire plant back by one-half after the first flowering flush to refresh the mounding habit and trigger a second wave of lavender-blue flowers in late summer. The silvery-green aromatic foliage is deer-resistant and provides a reliable edging throughout the season. Divide in spring every 3–4 years or propagate from cuttings taken in late spring.", "sources": ["general horticultural reference"]}')
