INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('china-aster','China Aster','Callistephus chinensis','flower','annual',10,14,65,70,70,100,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant after all frost risk has passed.',3,10,9,15,12,30,10,14,'full','moderate','Sow seed 1/8 in deep in moist starting mix at 65–70°F. Rotate planting locations each year, as China asters are prone to Fusarium wilt when grown in the same soil repeatedly. Avoid overhead watering and ensure good air circulation to reduce disease pressure. Harvest cut flowers when petals are just beginning to open fully for maximum vase life.','["general horticultural reference"]','{"slug": "china-aster", "common_name": "China Aster", "scientific_name": "Callistephus chinensis", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 70}, "days_to_maturity": {"min": 70, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant after all frost risk has passed."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 9, "max": 15}, "height_in": {"min": 12, "max": 30}, "spread_in": {"min": 10, "max": 14}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/8 in deep in moist starting mix at 65–70°F. Rotate planting locations each year, as China asters are prone to Fusarium wilt when grown in the same soil repeatedly. Avoid overhead watering and ensure good air circulation to reduce disease pressure. Harvest cut flowers when petals are just beginning to open fully for maximum vase life.", "sources": ["general horticultural reference"]}')
