INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('china-pink','China Pink','Dianthus chinensis','flower','annual',10,14,60,70,50,70,'transplant','indoor-start','cool','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant into the garden 2–4 weeks before last frost, as plants tolerate light frost.',2,11,8,12,6,18,8,12,'full','moderate','Sow seeds 1/8 in deep in well-drained germination mix; seedlings grow quickly and can be transplanted while still small. Plant in full sun in well-drained, neutral-to-slightly-alkaline soil; heavy clay and overwet conditions lead to crown rot. Deadhead spent flowers continuously to prevent early seed set and extend the blooming season well into summer. Plants often decline in intense summer heat but may rebloom in fall if sheared back and kept watered.','["general horticultural reference"]','{"slug": "china-pink", "common_name": "China Pink", "scientific_name": "Dianthus chinensis", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant into the garden 2–4 weeks before last frost, as plants tolerate light frost."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 6, "max": 18}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/8 in deep in well-drained germination mix; seedlings grow quickly and can be transplanted while still small. Plant in full sun in well-drained, neutral-to-slightly-alkaline soil; heavy clay and overwet conditions lead to crown rot. Deadhead spent flowers continuously to prevent early seed set and extend the blooming season well into summer. Plants often decline in intense summer heat but may rebloom in fall if sheared back and kept watered.", "sources": ["general horticultural reference"]}')
