  VALUES ('chinese-forget-me-not','Chinese Forget-Me-Not','Cynoglossum amabile','flower','annual',5,10,60,70,55,80,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow in early spring 2–4 weeks before last frost; can also sow in fall in mild winter climates.',2,11,9,12,18,24,9,12,'full','moderate','Sow seeds 1/4 in deep in early spring directly where they are to grow; cover seeds lightly as they germinate better in darkness. The clusters of tiny, intensely blue flowers resemble true forget-me-nots but bloom for a much longer period — from late spring well into summer. Shear plants back by one-third after the first main flush to encourage a second wave of bloom. Plants self-sow freely; allow some seeds to drop for naturalised succession planting in subsequent years.','["general horticultural reference"]','{"slug": "chinese-forget-me-not", "common_name": "Chinese Forget-Me-Not", "scientific_name": "Cynoglossum amabile", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 55, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring 2–4 weeks before last frost; can also sow in fall in mild winter climates."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep in early spring directly where they are to grow; cover seeds lightly as they germinate better in darkness. The clusters of tiny, intensely blue flowers resemble true forget-me-nots but bloom for a much longer period — from late spring well into summer. Shear plants back by one-third after the first main flush to encourage a second wave of bloom. Plants self-sow freely; allow some seeds to drop for naturalised succession planting in subsequent years.", "sources": ["general horticultural reference"]}')
