INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('clarkia','Clarkia','Clarkia amoena','flower','annual',7,14,55,65,60,90,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow in early spring 2–4 weeks before last frost while soil is still cool; succession sow every 3 weeks for extended bloom.',2,11,9,12,18,36,9,12,'full','low','Direct sow on the soil surface or barely cover; seeds germinate best at cool soil temperatures and seedlings dislike transplanting. Thin ruthlessly to 9–12 in because overcrowded plants bloom poorly and are prone to powdery mildew in humid conditions. Clarkia thrives on neglect in poor, well-drained soil — fertilizing too heavily causes lush foliage at the expense of flowers. Plants naturally set seed and die when summer heat arrives; in mild-winter climates, sow in fall for late-winter to spring bloom.','["general horticultural reference"]','{"slug": "clarkia", "common_name": "Clarkia", "scientific_name": "Clarkia amoena", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring 2–4 weeks before last frost while soil is still cool; succession sow every 3 weeks for extended bloom."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "low", "directions": "Direct sow on the soil surface or barely cover; seeds germinate best at cool soil temperatures and seedlings dislike transplanting. Thin ruthlessly to 9–12 in because overcrowded plants bloom poorly and are prone to powdery mildew in humid conditions. Clarkia thrives on neglect in poor, well-drained soil — fertilizing too heavily causes lush foliage at the expense of flowers. Plants naturally set seed and die when summer heat arrives; in mild-winter climates, sow in fall for late-winter to spring bloom.", "sources": ["general horticultural reference"]}')
