INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cleome','Cleome (Spider Flower)','Cleome hassleriana','flower','annual',7,14,65,75,70,100,'seed','direct','warm','tender','last_frost',-2,0,'Direct sow at or 2 weeks before last frost; cold stratification of seed for 7 days in the refrigerator improves germination.',3,11,18,24,36,60,18,24,'full','low','Press seed lightly onto the soil surface with barely 1/8 in of cover — light aids germination. Cleome self-sows prolifically and can become weedy; deadhead to limit reseeding if preferred. The tall, airy flower heads open from the base upward over several weeks, providing an extended season of bloom. Handle plants with care as stems bear small spines and the foliage has a musky scent.','["general horticultural reference"]','{"slug": "cleome", "common_name": "Cleome (Spider Flower)", "scientific_name": "Cleome hassleriana", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 70, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 0}, "note": "Direct sow at or 2 weeks before last frost; cold stratification of seed for 7 days in the refrigerator improves germination."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Press seed lightly onto the soil surface with barely 1/8 in of cover — light aids germination. Cleome self-sows prolifically and can become weedy; deadhead to limit reseeding if preferred. The tall, airy flower heads open from the base upward over several weeks, providing an extended season of bloom. Handle plants with care as stems bear small spines and the foliage has a musky scent.", "sources": ["general horticultural reference"]}')
