INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('columbine','Columbine','Aquilegia spp.','flower','perennial',21,30,60,70,365,730,'seed','direct','perennial','hardy','fall',-6,-4,'Direct sow in fall for natural cold stratification, or cold-stratify seeds indoors for 3–4 weeks before spring sowing.',3,9,12,18,18,36,12,18,'partial','moderate','Sow seeds shallowly on the soil surface and provide 3–4 weeks of cold stratification (fall sowing outdoors achieves this naturally) to break dormancy. Columbines bloom most freely in their second and third years and are prolific self-seeders that will hybridize freely, creating a constantly shifting mix of colors. Leafminer damage creates white tunnels in the foliage but rarely threatens plant health; remove affected leaves and dispose of them. Plants are short-lived perennials (3–5 years) but the colony self-perpetuates readily through self-seeding.','["general horticultural reference"]','{"slug": "columbine", "common_name": "Columbine", "scientific_name": "Aquilegia spp.", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 30}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Direct sow in fall for natural cold stratification, or cold-stratify seeds indoors for 3–4 weeks before spring sowing."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Sow seeds shallowly on the soil surface and provide 3–4 weeks of cold stratification (fall sowing outdoors achieves this naturally) to break dormancy. Columbines bloom most freely in their second and third years and are prolific self-seeders that will hybridize freely, creating a constantly shifting mix of colors. Leafminer damage creates white tunnels in the foliage but rarely threatens plant health; remove affected leaves and dispose of them. Plants are short-lived perennials (3–5 years) but the colony self-perpetuates readily through self-seeding.", "sources": ["general horticultural reference"]}')
