INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('coral-bells','Coral Bells','Heuchera spp.','flower','perennial',14,21,60,70,270,365,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; surface sow as seeds need light to germinate — do not cover.',4,9,12,18,12,30,12,18,'partial','moderate','Press seeds onto the surface of a moist germination medium — do not cover, as light is required for germination; transplant to a humus-rich, well-drained site after last frost. Grown primarily for their spectacular mound-forming foliage in shades of burgundy, copper, lime, silver, and purple, heucheras also produce airy wands of tiny flowers beloved by hummingbirds. Divide every 3–4 years in early spring to rejuvenate the woody crowns; reset divisions with the crown at soil level. Most modern hybrids tolerate more sun with adequate moisture but prefer afternoon shade in hot climates.','["general horticultural reference"]','{"slug": "coral-bells", "common_name": "Coral Bells", "scientific_name": "Heuchera spp.", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; surface sow as seeds need light to germinate — do not cover."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 30}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Press seeds onto the surface of a moist germination medium — do not cover, as light is required for germination; transplant to a humus-rich, well-drained site after last frost. Grown primarily for their spectacular mound-forming foliage in shades of burgundy, copper, lime, silver, and purple, heucheras also produce airy wands of tiny flowers beloved by hummingbirds. Divide every 3–4 years in early spring to rejuvenate the woody crowns; reset divisions with the crown at soil level. Most modern hybrids tolerate more sun with adequate moisture but prefer afternoon shade in hot climates.", "sources": ["general horticultural reference"]}')
