  VALUES ('coreopsis','Coreopsis','Coreopsis grandiflora','flower','perennial',14,21,60,70,70,120,'seed','direct','perennial','hardy','last_frost',-2,0,'Direct sow around last frost date; seeds tolerate light frost and germinate best in cool soil.',4,9,12,18,18,36,18,24,'full','low','Sow seed on the soil surface and tamp lightly; good drainage is essential since coreopsis rots in wet soil over winter. Deadhead regularly to keep the bright yellow flowers coming all summer. Shear plants back by half after the first flush to encourage compact regrowth and a second bloom. Divide clumps every 2–3 years in spring to prevent the center from dying out.','["general horticultural reference"]','{"slug": "coreopsis", "common_name": "Coreopsis", "scientific_name": "Coreopsis grandiflora", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 70, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 0}, "note": "Direct sow around last frost date; seeds tolerate light frost and germinate best in cool soil."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Sow seed on the soil surface and tamp lightly; good drainage is essential since coreopsis rots in wet soil over winter. Deadhead regularly to keep the bright yellow flowers coming all summer. Shear plants back by half after the first flush to encourage compact regrowth and a second bloom. Divide clumps every 2–3 years in spring to prevent the center from dying out.", "sources": ["general horticultural reference"]}')
