  VALUES ('cosmos','Cosmos','Cosmos bipinnatus','flower','annual',7,10,65,75,60,90,'seed','direct','warm','tender','last_frost',0,2,'Direct sow after last frost; cosmos thrives in poor soil and needs no fertilizing.',2,11,12,18,24,60,12,18,'full','low','Press seed lightly onto the soil surface and cover with 1/4 in of fine soil. Cosmos germinates best in poor, well-drained soil — avoid fertilizing, which promotes foliage over flowers. Pinch young plants at 12 in to encourage branching. Deadhead regularly or allow seed to set for self-sowing the following year.','["general horticultural reference"]','{"slug": "cosmos", "common_name": "Cosmos", "scientific_name": "Cosmos bipinnatus", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow after last frost; cosmos thrives in poor soil and needs no fertilizing."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Press seed lightly onto the soil surface and cover with 1/4 in of fine soil. Cosmos germinates best in poor, well-drained soil — avoid fertilizing, which promotes foliage over flowers. Pinch young plants at 12 in to encourage branching. Deadhead regularly or allow seed to set for self-sowing the following year.", "sources": ["general horticultural reference"]}')
