INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('crocosmia','Crocosmia','Crocosmia x crocosmiiflora','flower','bulb',NULL,NULL,NULL,NULL,60,90,'transplant','bulb','perennial','half-hardy','last_frost',-2,2,'Plant corms in spring around last frost; in zones 6–7 apply a thick mulch in fall to protect overwintering corms.',6,9,6,8,24,36,12,18,'full','moderate','Plant corms 3–4 in deep in groups of 6 or more for the best visual impact; crocosmia forms clumps through underground stolons. Arching sprays of scarlet, orange, or yellow tubular flowers appear from midsummer into fall and are excellent for cutting. Where hardy, divide congested clumps every 3–4 years in early spring to refresh bloom; in zone 5 and colder, lift and store over winter like gladiolus. ''Lucifer'' is among the hardiest cultivars, tolerating zone 5 with reliable mulching.','["general horticultural reference"]','{"slug": "crocosmia", "common_name": "Crocosmia", "scientific_name": "Crocosmia x crocosmiiflora", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Plant corms in spring around last frost; in zones 6–7 apply a thick mulch in fall to protect overwintering corms."}, "usda_zones": {"min": 6, "max": 9}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Plant corms 3–4 in deep in groups of 6 or more for the best visual impact; crocosmia forms clumps through underground stolons. Arching sprays of scarlet, orange, or yellow tubular flowers appear from midsummer into fall and are excellent for cutting. Where hardy, divide congested clumps every 3–4 years in early spring to refresh bloom; in zone 5 and colder, lift and store over winter like gladiolus. ''Lucifer'' is among the hardiest cultivars, tolerating zone 5 with reliable mulching.", "sources": ["general horticultural reference"]}')
