INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('culvers-root','Culver''s Root','Veronicastrum virginicum','flower','perennial',14,28,60,70,365,548,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; cold stratification for 4–6 weeks improves germination rates.',3,8,24,36,48,72,24,36,'full','moderate','Sow seeds indoors after cold stratification or plant divisions in spring in moist to moderately moist, organically rich soil; culver''s root is an imposing native prairie plant with whorled, lance-shaped leaves and tall candelabra-like spikes of white to pale lavender flowers in mid- to late summer. The architectural form makes it a striking back-of-border plant, and the flowers attract a wide variety of native bees and butterflies. Rarely needs staking when grown in adequate light; divide every 4–5 years in spring to maintain vigor. Excellent companion for joe-pye weed, prairie blazing star, and native grasses.','["general horticultural reference"]','{"slug": "culvers-root", "common_name": "Culver''s Root", "scientific_name": "Veronicastrum virginicum", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; cold stratification for 4–6 weeks improves germination rates."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Sow seeds indoors after cold stratification or plant divisions in spring in moist to moderately moist, organically rich soil; culver''s root is an imposing native prairie plant with whorled, lance-shaped leaves and tall candelabra-like spikes of white to pale lavender flowers in mid- to late summer. The architectural form makes it a striking back-of-border plant, and the flowers attract a wide variety of native bees and butterflies. Rarely needs staking when grown in adequate light; divide every 4–5 years in spring to maintain vigor. Excellent companion for joe-pye weed, prairie blazing star, and native grasses.", "sources": ["general horticultural reference"]}')
