  VALUES ('cupid-dart','Cupid''s Dart','Catananche caerulea','flower','perennial',21,28,60,70,120,150,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; transplant after last frost into a dry, sunny site.',4,9,12,18,18,24,12,18,'full','low','Start seeds indoors 6–8 weeks before last frost and transplant to a sunny, very well-drained site — catananche is native to dry Mediterranean hillsides and rots in moist soil. The papery, cornflower-blue blooms on wiry stems are excellent cut or dried flowers that hold their color well. Shear plants by half after the first flush in early summer to encourage repeat flowering into fall. Best treated as a short-lived perennial; replace plants every 2–3 years or allow to self-sow for a continuing colony.','["general horticultural reference"]','{"slug": "cupid-dart", "common_name": "Cupid''s Dart", "scientific_name": "Catananche caerulea", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 28}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 120, "max": 150}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; transplant after last frost into a dry, sunny site."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Start seeds indoors 6–8 weeks before last frost and transplant to a sunny, very well-drained site — catananche is native to dry Mediterranean hillsides and rots in moist soil. The papery, cornflower-blue blooms on wiry stems are excellent cut or dried flowers that hold their color well. Shear plants by half after the first flush in early summer to encourage repeat flowering into fall. Best treated as a short-lived perennial; replace plants every 2–3 years or allow to self-sow for a continuing colony.", "sources": ["general horticultural reference"]}')
