  VALUES ('daffodil','Daffodil','Narcissus spp.','flower','bulb',NULL,NULL,NULL,NULL,150,210,'transplant','bulb','perennial','hardy','fall',-8,-4,'Plant bulbs in fall, 4–8 weeks before the ground freezes, for spring bloom.',3,9,4,6,8,20,4,6,'full','moderate','Plant bulbs in fall at a depth of 3 times the bulb''s height (typically 6–8 in) in well-drained soil with the pointed end up. Daffodils naturalize readily and multiply over time; deer and rodents avoid them because the bulbs are mildly toxic. Allow foliage to yellow and die back naturally — at least 6 weeks — so the bulb can store energy for next year''s bloom. Divide congested clumps every 5–7 years when flowering diminishes.','["general horticultural reference"]','{"slug": "daffodil", "common_name": "Daffodil", "scientific_name": "Narcissus spp.", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 150, "max": 210}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant bulbs in fall, 4–8 weeks before the ground freezes, for spring bloom."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 8, "max": 20}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Plant bulbs in fall at a depth of 3 times the bulb''s height (typically 6–8 in) in well-drained soil with the pointed end up. Daffodils naturalize readily and multiply over time; deer and rodents avoid them because the bulbs are mildly toxic. Allow foliage to yellow and die back naturally — at least 6 weeks — so the bulb can store energy for next year''s bloom. Divide congested clumps every 5–7 years when flowering diminishes.", "sources": ["general horticultural reference"]}')
