INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('anemone-de-caen','De Caen Anemone','Anemone coronaria','flower','bulb',NULL,NULL,NULL,NULL,90,120,'transplant','bulb','cool','half-hardy','fall',-8,-4,'Plant corms in fall in mild climates (zones 7–10) or in early spring after danger of hard frost has passed in colder zones.',7,10,4,6,12,18,4,6,'full','moderate','Soak the small, irregular corms in water for 4–6 hours before planting; set them about 2 in deep with the pointed side down (or on their side if unsure). Anemones prefer cool, well-drained soil and perform best where winters are mild and springs are long and cool. Poppy-like blooms in vivid red, blue, purple, white, and bicolors appear over a 6–8 week period in late winter to spring. In cold climates treat as an annual, planting corms in spring for early summer color.','["general horticultural reference"]','{"slug": "anemone-de-caen", "common_name": "De Caen Anemone", "scientific_name": "Anemone coronaria", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "bulb", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant corms in fall in mild climates (zones 7–10) or in early spring after danger of hard frost has passed in colder zones."}, "usda_zones": {"min": 7, "max": 10}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Soak the small, irregular corms in water for 4–6 hours before planting; set them about 2 in deep with the pointed side down (or on their side if unsure). Anemones prefer cool, well-drained soil and perform best where winters are mild and springs are long and cool. Poppy-like blooms in vivid red, blue, purple, white, and bicolors appear over a 6–8 week period in late winter to spring. In cold climates treat as an annual, planting corms in spring for early summer color.", "sources": ["general horticultural reference"]}')
