INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('dusty-miller','Dusty Miller','Senecio cineraria','flower','annual',10,14,65,75,60,80,'transplant','indoor-start','warm','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after frost risk passes.',2,11,8,12,8,18,10,14,'full','low','Surface-sow tiny seeds on moist germination mix and provide light at 65–75°F; germination is slow and uneven over 10–14 days. Plant in full sun in well-drained soil; excellent salt and drought tolerance makes this ideal for coastal and hot dry sites. The silvery white, felted foliage is the ornamental feature — pinch off yellow flower buds when they appear to keep plants neat and maintain vigorous leaf growth. In zones 8–11 dusty miller overwinters as a short-lived perennial.','["general horticultural reference"]','{"slug": "dusty-miller", "common_name": "Dusty Miller", "scientific_name": "Senecio cineraria", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after frost risk passes."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 8, "max": 18}, "spread_in": {"min": 10, "max": 14}, "sun": "full", "water": "low", "directions": "Surface-sow tiny seeds on moist germination mix and provide light at 65–75°F; germination is slow and uneven over 10–14 days. Plant in full sun in well-drained soil; excellent salt and drought tolerance makes this ideal for coastal and hot dry sites. The silvery white, felted foliage is the ornamental feature — pinch off yellow flower buds when they appear to keep plants neat and maintain vigorous leaf growth. In zones 8–11 dusty miller overwinters as a short-lived perennial.", "sources": ["general horticultural reference"]}')
