INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('dutch-iris','Dutch Iris','Iris x hollandica','flower','bulb',NULL,NULL,NULL,NULL,120,150,'transplant','bulb','perennial','half-hardy','fall',-8,-4,'Plant bulbs in fall, 4–6 in deep; in zones 5–6 apply a winter mulch for protection.',6,9,4,6,18,24,4,6,'full','low','Plant bulbs 4–6 in deep in well-drained, moderately fertile soil; Dutch iris bloom in late spring to early summer and are superb cut flowers with a vase life of 7–10 days. The large falls and standards come in shades of blue, purple, yellow, white, and bicolor. After bloom, allow foliage to die back naturally; in warm, humid climates the bulbs may rot in summer — lift and store dry in a cool place if this occurs. Replant in early fall and incorporate grit into heavy clay soils to improve drainage.','["general horticultural reference"]','{"slug": "dutch-iris", "common_name": "Dutch Iris", "scientific_name": "Iris x hollandica", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 120, "max": 150}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant bulbs in fall, 4–6 in deep; in zones 5–6 apply a winter mulch for protection."}, "usda_zones": {"min": 6, "max": 9}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "low", "directions": "Plant bulbs 4–6 in deep in well-drained, moderately fertile soil; Dutch iris bloom in late spring to early summer and are superb cut flowers with a vase life of 7–10 days. The large falls and standards come in shades of blue, purple, yellow, white, and bicolor. After bloom, allow foliage to die back naturally; in warm, humid climates the bulbs may rot in summer — lift and store dry in a cool place if this occurs. Replant in early fall and incorporate grit into heavy clay soils to improve drainage.", "sources": ["general horticultural reference"]}')
