INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lobelia-annual','Edging Lobelia','Lobelia erinus','flower','annual',14,21,65,75,70,90,'transplant','indoor-start','cool','half-hardy','last_frost',-10,-8,'Start seeds indoors 8–10 weeks before last frost; lobelia has extremely tiny seeds and a slow early growth rate.',2,11,6,9,4,8,6,10,'partial','moderate','Surface-sow the dust-like seeds on moist fine-textured mix; do not cover, as they need light to germinate, and use a spray mist to avoid washing them away. Grow seedlings on at cool temperatures (60–65°F) once germinated; pot up in small clusters of 3–5 seedlings rather than separating individuals. Lobelia blooms best in cool weather and partial shade in hot climates, often slowing or stopping in midsummer heat — shear back by half and water regularly for rebloom as fall approaches. The vivid blue, trailing types are classic basket and container plants.','["general horticultural reference"]','{"slug": "lobelia-annual", "common_name": "Edging Lobelia", "scientific_name": "Lobelia erinus", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start seeds indoors 8–10 weeks before last frost; lobelia has extremely tiny seeds and a slow early growth rate."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 4, "max": 8}, "spread_in": {"min": 6, "max": 10}, "sun": "partial", "water": "moderate", "directions": "Surface-sow the dust-like seeds on moist fine-textured mix; do not cover, as they need light to germinate, and use a spray mist to avoid washing them away. Grow seedlings on at cool temperatures (60–65°F) once germinated; pot up in small clusters of 3–5 seedlings rather than separating individuals. Lobelia blooms best in cool weather and partial shade in hot climates, often slowing or stopping in midsummer heat — shear back by half and water regularly for rebloom as fall approaches. The vivid blue, trailing types are classic basket and container plants.", "sources": ["general horticultural reference"]}')
