INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('heliopsis','False Sunflower','Heliopsis helianthoides','flower','perennial',7,14,65,75,90,120,'seed','direct','perennial','hardy','last_frost',-2,2,'Direct sow around last frost date or start indoors 4–6 weeks earlier for bloom the first season.',3,9,18,24,36,60,18,24,'full','moderate','Sow seeds 1/4 in deep directly in the garden or start indoors; unlike true perennial rudbeckia, heliopsis often blooms robustly in its first season from an early start. Plant in full sun in average, well-drained soil; plants tolerate heat and short dry periods better than helenium. Deadhead regularly throughout summer to keep the golden-yellow, semi-double or double flowers coming continuously from July through September. Divide clumps every 3 years in spring or fall to maintain vigor and prevent the center from dying out.','["general horticultural reference"]','{"slug": "heliopsis", "common_name": "False Sunflower", "scientific_name": "Heliopsis helianthoides", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Direct sow around last frost date or start indoors 4–6 weeks earlier for bloom the first season."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep directly in the garden or start indoors; unlike true perennial rudbeckia, heliopsis often blooms robustly in its first season from an early start. Plant in full sun in average, well-drained soil; plants tolerate heat and short dry periods better than helenium. Deadhead regularly throughout summer to keep the golden-yellow, semi-double or double flowers coming continuously from July through September. Divide clumps every 3 years in spring or fall to maintain vigor and prevent the center from dying out.", "sources": ["general horticultural reference"]}')
