  VALUES ('feather-reed-grass','Feather Reed Grass','Calamagrostis x acutiflora','flower','ornamental-grass',NULL,NULL,NULL,NULL,90,120,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions in spring; ''Karl Foerster'' is sterile and must be propagated by division.',4,9,18,24,36,60,18,24,'full','moderate','Plant in full sun to light shade in average, moisture-retentive soil; ''Karl Foerster'' feather reed grass is one of the most reliable and widely adapted ornamental grasses, tolerating clay soil, humidity, and cold winters that defeat many others. Strongly upright, narrow clumps emerge early in spring with feathery bronze-pink plumes appearing in early summer that fade to wheat-gold and persist through winter. Cut back to 4–6 in in late winter or early spring before new growth begins. Divide every 4–5 years in spring when the center begins to die out.','["general horticultural reference"]','{"slug": "feather-reed-grass", "common_name": "Feather Reed Grass", "scientific_name": "Calamagrostis x acutiflora", "category": "flower", "subcategory": "ornamental-grass", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in spring; ''Karl Foerster'' is sterile and must be propagated by division."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Plant in full sun to light shade in average, moisture-retentive soil; ''Karl Foerster'' feather reed grass is one of the most reliable and widely adapted ornamental grasses, tolerating clay soil, humidity, and cold winters that defeat many others. Strongly upright, narrow clumps emerge early in spring with feathery bronze-pink plumes appearing in early summer that fade to wheat-gold and persist through winter. Cut back to 4–6 in in late winter or early spring before new growth begins. Divide every 4–5 years in spring when the center begins to die out.", "sources": ["general horticultural reference"]}')
