  VALUES ('firebush','Firebush','Hamelia patens','flower','perennial',14,21,70,85,90,180,'transplant','transplant','perennial','tender','last_frost',0,4,'Plant container stock after last frost; firebush is a Florida and Gulf Coast native that quickly reaches shrub size and blooms nonstop in summer heat.',8,11,48,96,60,120,48,96,'full','low','Plant in any well-drained soil in full sun; firebush tolerates heat, drought, and poor soils once established and reblooms continuously from late spring through frost. The tubular orange-red flowers are magnets for hummingbirds and butterflies, while the small black fruits that follow attract songbirds — making it one of the most wildlife-productive native shrubs for Gulf Coast gardens. In zone 8–9 the top freezes back in winter, but the plant regrows vigorously from the base each spring; cut dead stems to the ground once new growth begins. Native firebush (var. patens) is superior to the commonly sold ''Compacta'' cultivar for wildlife value and cold hardiness.','["Florida Native Plant Society", "University of Florida IFAS Extension"]','{"slug": "firebush", "common_name": "Firebush", "scientific_name": "Hamelia patens", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 90, "max": 180}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant container stock after last frost; firebush is a Florida and Gulf Coast native that quickly reaches shrub size and blooms nonstop in summer heat."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 48, "max": 96}, "height_in": {"min": 60, "max": 120}, "spread_in": {"min": 48, "max": 96}, "sun": "full", "water": "low", "directions": "Plant in any well-drained soil in full sun; firebush tolerates heat, drought, and poor soils once established and reblooms continuously from late spring through frost. The tubular orange-red flowers are magnets for hummingbirds and butterflies, while the small black fruits that follow attract songbirds — making it one of the most wildlife-productive native shrubs for Gulf Coast gardens. In zone 8–9 the top freezes back in winter, but the plant regrows vigorously from the base each spring; cut dead stems to the ground once new growth begins. Native firebush (var. patens) is superior to the commonly sold ''Compacta'' cultivar for wildlife value and cold hardiness.", "sources": ["Florida Native Plant Society", "University of Florida IFAS Extension"]}')
