  VALUES ('nicotiana','Flowering Tobacco (Nicotiana)','Nicotiana alata','flower','annual',10,20,65,75,70,90,'transplant','indoor-start','warm','tender','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after all frost danger has passed.',3,11,12,18,12,60,10,18,'partial','moderate','Surface sow tiny seed on moist starting mix under bright light — do not cover, as seed is extremely small and needs light to germinate. Nicotiana tolerates partial shade better than most annuals and performs well in dappled light. Fragrant varieties release scent primarily in the evening, making them ideal planted near a patio or window. Deadhead spent flower clusters to encourage continuous blooming.','["general horticultural reference"]','{"slug": "nicotiana", "common_name": "Flowering Tobacco (Nicotiana)", "scientific_name": "Nicotiana alata", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 20}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after all frost danger has passed."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 60}, "spread_in": {"min": 10, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Surface sow tiny seed on moist starting mix under bright light — do not cover, as seed is extremely small and needs light to germinate. Nicotiana tolerates partial shade better than most annuals and performs well in dappled light. Fragrant varieties release scent primarily in the evening, making them ideal planted near a patio or window. Deadhead spent flower clusters to encourage continuous blooming.", "sources": ["general horticultural reference"]}')
