  VALUES ('foamflower','Foamflower','Tiarella cordifolia','flower','perennial',21,42,55,65,270,365,'seed','indoor-start','perennial','hardy','last_frost',-10,-8,'Start seeds indoors 8–10 weeks before last frost with a cold stratification period; or plant divisions in spring or fall.',3,9,12,18,6,12,18,24,'shade','moderate','Plant in humus-rich, consistently moist, well-drained shade; foamflower spreads by stolons to form a weed-suppressing ground cover with attractive, deeply lobed, often patterned foliage. Frothy spikes of tiny white to pink flowers appear in mid-spring above the foliage and last for 4–6 weeks. Divide clumps every 3–4 years in early spring to prevent overcrowding and maintain vigor. Many named cultivars with exceptional leaf markings are available and are best propagated by division to maintain cultivar characteristics.','["general horticultural reference"]','{"slug": "foamflower", "common_name": "Foamflower", "scientific_name": "Tiarella cordifolia", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start seeds indoors 8–10 weeks before last frost with a cold stratification period; or plant divisions in spring or fall."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 18, "max": 24}, "sun": "shade", "water": "moderate", "directions": "Plant in humus-rich, consistently moist, well-drained shade; foamflower spreads by stolons to form a weed-suppressing ground cover with attractive, deeply lobed, often patterned foliage. Frothy spikes of tiny white to pink flowers appear in mid-spring above the foliage and last for 4–6 weeks. Divide clumps every 3–4 years in early spring to prevent overcrowding and maintain vigor. Many named cultivars with exceptional leaf markings are available and are best propagated by division to maintain cultivar characteristics.", "sources": ["general horticultural reference"]}')
