INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('forget-me-not','Forget-Me-Not','Myosotis sylvatica','flower','annual',7,14,55,65,60,90,'seed','direct','cool','hardy','first_frost',-4,0,'Sow in late summer to early fall so plants overwinter as rosettes and bloom in spring alongside tulips and daffodils.',2,11,6,9,6,12,6,9,'partial','moderate','Scatter seeds on the soil surface or barely cover them; they germinate best in cool conditions and seedlings overwinter as low rosettes in mild climates. Forget-me-nots self-sow prolifically once established — let plants go to seed, then pull them after flowering to control spread. The sky-blue flowers are traditionally combined with spring bulbs in beds and create a charming filler under shrubs in partial shade. Remove spent plants when temperatures rise, as they become straggly and die back in summer heat.','["general horticultural reference"]','{"slug": "forget-me-not", "common_name": "Forget-Me-Not", "scientific_name": "Myosotis sylvatica", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Sow in late summer to early fall so plants overwinter as rosettes and bloom in spring alongside tulips and daffodils."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 6, "max": 9}, "sun": "partial", "water": "moderate", "directions": "Scatter seeds on the soil surface or barely cover them; they germinate best in cool conditions and seedlings overwinter as low rosettes in mild climates. Forget-me-nots self-sow prolifically once established — let plants go to seed, then pull them after flowering to control spread. The sky-blue flowers are traditionally combined with spring bulbs in beds and create a charming filler under shrubs in partial shade. Remove spent plants when temperatures rise, as they become straggly and die back in summer heat.", "sources": ["general horticultural reference"]}')
