INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('foxtail-lily','Foxtail Lily','Eremurus spp.','flower','perennial',NULL,NULL,NULL,NULL,270,365,'transplant','division','perennial','hardy','fall',-8,-4,'Plant the spider-like fleshy roots in fall, spreading them horizontally 4 in deep in a well-drained, sunny site.',5,8,24,36,36,96,24,36,'full','low','Spread the octopus-like fleshy roots horizontally over a mound of gritty soil, crown just below the surface, with perfect drainage — wet winter soil rots the crowns quickly. The strap-like foliage emerges in early spring and can be killed by a late frost; a light cover of straw protects emerging growth in zones 5–6. Spectacular bottle-brush spikes up to 8 ft tall erupt in late spring to early summer in shades of white, yellow, orange, and pink. Leaves die back after bloom, so interplant with later-emerging perennials to fill the gap.','["general horticultural reference"]','{"slug": "foxtail-lily", "common_name": "Foxtail Lily", "scientific_name": "Eremurus spp.", "category": "flower", "subcategory": "perennial", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant the spider-like fleshy roots in fall, spreading them horizontally 4 in deep in a well-drained, sunny site."}, "usda_zones": {"min": 5, "max": 8}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 96}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Spread the octopus-like fleshy roots horizontally over a mound of gritty soil, crown just below the surface, with perfect drainage — wet winter soil rots the crowns quickly. The strap-like foliage emerges in early spring and can be killed by a late frost; a light cover of straw protects emerging growth in zones 5–6. Spectacular bottle-brush spikes up to 8 ft tall erupt in late spring to early summer in shades of white, yellow, orange, and pink. Leaves die back after bloom, so interplant with later-emerging perennials to fill the gap.", "sources": ["general horticultural reference"]}')
