INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('freesia','Freesia','Freesia spp.','flower','bulb',NULL,NULL,NULL,NULL,90,110,'transplant','bulb','cool','tender','fall',-8,-4,'Plant corms in fall in frost-free areas (zones 9–10) or start indoors 10–12 weeks before last frost in cold climates.',9,11,2,3,12,18,3,4,'full','moderate','Plant corms 2 in deep and 2–3 in apart in gritty, well-drained soil; freesias resent wet conditions especially after bloom. The fragrant, funnel-shaped flowers on arching stems need staking or a grow-through support as stems are slender. In frost-free gardens the corms are perennial and naturalize freely; in colder climates lift after foliage dies, dry thoroughly, and store in a cool dry place. Corms multiply quickly — divide every 2–3 years to maintain bloom quality.','["general horticultural reference"]','{"slug": "freesia", "common_name": "Freesia", "scientific_name": "Freesia spp.", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 110}, "maturity_from": "transplant", "sow_method": "bulb", "season": "cool", "frost_tolerance": "tender", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant corms in fall in frost-free areas (zones 9–10) or start indoors 10–12 weeks before last frost in cold climates."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 2, "max": 3}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 3, "max": 4}, "sun": "full", "water": "moderate", "directions": "Plant corms 2 in deep and 2–3 in apart in gritty, well-drained soil; freesias resent wet conditions especially after bloom. The fragrant, funnel-shaped flowers on arching stems need staking or a grow-through support as stems are slender. In frost-free gardens the corms are perennial and naturalize freely; in colder climates lift after foliage dies, dry thoroughly, and store in a cool dry place. Corms multiply quickly — divide every 2–3 years to maintain bloom quality.", "sources": ["general horticultural reference"]}')
