INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('marigold-french','French Marigold','Tagetes patula','flower','annual',4,7,70,75,45,60,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant after all frost danger has passed.',2,11,6,10,6,18,6,12,'full','moderate','Sow seed 1/4 in deep in warm starting mix. Pinch out the first flower bud to encourage bushier branching and heavier bloom set. Deadhead spent flowers regularly to keep plants producing through summer. Blooms appear approximately 6–8 weeks after transplant and continue until frost.','["general horticultural reference"]','{"slug": "marigold-french", "common_name": "French Marigold", "scientific_name": "Tagetes patula", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 45, "max": 60}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant after all frost danger has passed."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 6, "max": 10}, "height_in": {"min": 6, "max": 18}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep in warm starting mix. Pinch out the first flower bud to encourage bushier branching and heavier bloom set. Deadhead spent flowers regularly to keep plants producing through summer. Blooms appear approximately 6–8 weeks after transplant and continue until frost.", "sources": ["general horticultural reference"]}')
