INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('garden-mum','Garden Mum','Chrysanthemum x morifolium','flower','perennial',10,18,60,70,120,180,'transplant','division','perennial','half-hardy','last_frost',2,6,'Plant divisions or rooted cuttings in spring, 2–6 weeks after the last frost, for fall bloom.',5,9,18,24,12,36,18,24,'full','moderate','Plant in spring into fertile, well-drained soil; pinch growing tips every 2–3 weeks from planting until midsummer (around July 4) to develop compact, well-branched plants with dozens of buds. Mums are short-day plants that begin flower bud formation as nights lengthen; stop pinching by midsummer to avoid disrupting this process. Mulch heavily after the first hard frost to improve winter hardiness in colder zones. Divide annually in spring to rejuvenate the planting and maintain plant vigor.','["general horticultural reference"]','{"slug": "garden-mum", "common_name": "Garden Mum", "scientific_name": "Chrysanthemum x morifolium", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 18}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 6}, "note": "Plant divisions or rooted cuttings in spring, 2–6 weeks after the last frost, for fall bloom."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Plant in spring into fertile, well-drained soil; pinch growing tips every 2–3 weeks from planting until midsummer (around July 4) to develop compact, well-branched plants with dozens of buds. Mums are short-day plants that begin flower bud formation as nights lengthen; stop pinching by midsummer to avoid disrupting this process. Mulch heavily after the first hard frost to improve winter hardiness in colder zones. Divide annually in spring to rejuvenate the planting and maintain plant vigor.", "sources": ["general horticultural reference"]}')
