INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('garden-phlox','Garden Phlox','Phlox paniculata','flower','perennial',14,28,65,75,90,120,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions in spring as new growth emerges or in early fall for establishment before frost.',4,8,18,24,24,48,24,36,'full','moderate','Plant in moist, well-drained, humus-rich soil with good air circulation to reduce powdery mildew, which is the plant''s main problem. Thin stems to 5–7 per clump in spring to improve airflow and produce larger flower trusses on the remaining stems. Deadhead the central flower cluster as it fades to encourage lateral buds to open and extend the bloom season. Divide every 3 years in spring, replanting only the outermost, most vigorous sections.','["general horticultural reference"]','{"slug": "garden-phlox", "common_name": "Garden Phlox", "scientific_name": "Phlox paniculata", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in spring as new growth emerges or in early fall for establishment before frost."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Plant in moist, well-drained, humus-rich soil with good air circulation to reduce powdery mildew, which is the plant''s main problem. Thin stems to 5–7 per clump in spring to improve airflow and produce larger flower trusses on the remaining stems. Deadhead the central flower cluster as it fades to encourage lateral buds to open and extend the bloom season. Divide every 3 years in spring, replanting only the outermost, most vigorous sections.", "sources": ["general horticultural reference"]}')
