INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('gaura','Gaura','Oenothera lindheimeri','flower','perennial',14,21,65,75,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost and transplant after all frost danger has passed.',5,9,18,24,24,48,18,24,'full','low','Sow seeds 1/8 in deep in loose, well-drained germination mix; plants develop a deep taproot early so pot on before roots become crowded. Plant in full sun and lean, well-drained soil — gaura thrives on neglect and declines in fertile, wet conditions. The wand-like stems bearing butterfly-shaped white or pink flowers sway gracefully all season without deadheading. Cut plants back to 6 in after the first heavy bloom flush to encourage a tidy second flush through autumn.','["general horticultural reference"]','{"slug": "gaura", "common_name": "Gaura", "scientific_name": "Oenothera lindheimeri", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost and transplant after all frost danger has passed."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Sow seeds 1/8 in deep in loose, well-drained germination mix; plants develop a deep taproot early so pot on before roots become crowded. Plant in full sun and lean, well-drained soil — gaura thrives on neglect and declines in fertile, wet conditions. The wand-like stems bearing butterfly-shaped white or pink flowers sway gracefully all season without deadheading. Cut plants back to 6 in after the first heavy bloom flush to encourage a tidy second flush through autumn.", "sources": ["general horticultural reference"]}')
