INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('gazania','Gazania','Gazania rigens','flower','annual',7,14,65,75,60,80,'transplant','indoor-start','warm','tender','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost and transplant after all frost risk has passed.',2,11,8,12,8,14,8,12,'full','low','Sow seeds 1/8 in deep; they germinate readily at 65–75°F and grow quickly into compact transplants. Plant in sharply drained, even poor soil in the hottest, sunniest location available — gazania excels in sandy or gravelly beds where other plants fail. Flowers close at night and on overcast days, but modern hybrid varieties stay open longer than older types. Drought tolerance is excellent once established; overwatering and heavy clay soils are the most common causes of failure.','["general horticultural reference"]','{"slug": "gazania", "common_name": "Gazania", "scientific_name": "Gazania rigens", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost and transplant after all frost risk has passed."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 8, "max": 14}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "low", "directions": "Sow seeds 1/8 in deep; they germinate readily at 65–75°F and grow quickly into compact transplants. Plant in sharply drained, even poor soil in the hottest, sunniest location available — gazania excels in sandy or gravelly beds where other plants fail. Flowers close at night and on overcast days, but modern hybrid varieties stay open longer than older types. Drought tolerance is excellent once established; overwatering and heavy clay soils are the most common causes of failure.", "sources": ["general horticultural reference"]}')
