INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('gerbera-daisy','Gerbera Daisy','Gerbera jamesonii','flower','perennial',14,21,70,75,90,120,'transplant','indoor-start','warm','tender','last_frost',-12,-10,'Start seeds indoors 10–12 weeks before last frost and transplant after all frost danger has passed.',8,11,12,18,10,18,12,18,'full','moderate','Sow seeds vertically, pointed end down, barely covered, as they are sensitive to orientation; maintain 70–75°F for germination. Plant so the crown sits slightly above soil level to prevent crown rot, which is the most common cause of plant failure. Water at the base rather than overhead; gerberas prefer a dry-wet-dry cycle rather than constantly moist soil. Deadhead spent flowers by cutting the stem to the base to encourage continuous bloom from spring through fall in mild climates.','["general horticultural reference"]','{"slug": "gerbera-daisy", "common_name": "Gerbera Daisy", "scientific_name": "Gerbera jamesonii", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -12, "max": -10}, "note": "Start seeds indoors 10–12 weeks before last frost and transplant after all frost danger has passed."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 10, "max": 18}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds vertically, pointed end down, barely covered, as they are sensitive to orientation; maintain 70–75°F for germination. Plant so the crown sits slightly above soil level to prevent crown rot, which is the most common cause of plant failure. Water at the base rather than overhead; gerberas prefer a dry-wet-dry cycle rather than constantly moist soil. Deadhead spent flowers by cutting the stem to the base to encourage continuous bloom from spring through fall in mild climates.", "sources": ["general horticultural reference"]}')
