INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('allium-giant','Giant Allium','Allium giganteum','flower','bulb',NULL,NULL,NULL,NULL,180,240,'transplant','bulb','perennial','hardy','fall',-8,-4,'Plant large bulbs in fall at a depth of 3–4 times the bulb diameter (typically 6–8 in) in well-drained soil.',5,8,12,18,36,48,8,12,'full','low','Plant bulbs in fall, pointed side up, at 3–4 times their diameter in depth; good drainage is essential as bulbs rot in waterlogged soil. The bold, softball-sized purple globes atop tall stems create dramatic vertical accents in late spring to early summer borders. Foliage, which smells of onion when crushed, often begins to yellow before flowers are fully open — conceal the base with later-rising perennials. Allow seedheads to remain for architectural interest; deadhead if you wish to prevent excessive self-seeding.','["general horticultural reference"]','{"slug": "allium-giant", "common_name": "Giant Allium", "scientific_name": "Allium giganteum", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 180, "max": 240}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant large bulbs in fall at a depth of 3–4 times the bulb diameter (typically 6–8 in) in well-drained soil."}, "usda_zones": {"min": 5, "max": 8}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 36, "max": 48}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "low", "directions": "Plant bulbs in fall, pointed side up, at 3–4 times their diameter in depth; good drainage is essential as bulbs rot in waterlogged soil. The bold, softball-sized purple globes atop tall stems create dramatic vertical accents in late spring to early summer borders. Foliage, which smells of onion when crushed, often begins to yellow before flowers are fully open — conceal the base with later-rising perennials. Allow seedheads to remain for architectural interest; deadhead if you wish to prevent excessive self-seeding.", "sources": ["general horticultural reference"]}')
