INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('globe-thistle','Globe Thistle','Echinops ritro','flower','perennial',14,21,60,70,365,730,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; plants typically bloom in their second year from seed.',3,9,24,36,36,60,24,36,'full','low','Sow seeds 1/4 in deep; cold stratification is not required but may speed germination. Established globe thistle is extremely drought-tolerant and thrives in poor, sandy, or chalky well-drained soil — fertile, moist soil causes lax growth and flopping. The spiky steel-blue globe flowers are excellent for fresh cutting and dry perfectly for everlasting arrangements if cut just before fully open. Divide clumps in spring every 4–5 years using a sharp spade; they are slow to re-establish so divisions should be generous.','["general horticultural reference"]','{"slug": "globe-thistle", "common_name": "Globe Thistle", "scientific_name": "Echinops ritro", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; plants typically bloom in their second year from seed."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Sow seeds 1/4 in deep; cold stratification is not required but may speed germination. Established globe thistle is extremely drought-tolerant and thrives in poor, sandy, or chalky well-drained soil — fertile, moist soil causes lax growth and flopping. The spiky steel-blue globe flowers are excellent for fresh cutting and dry perfectly for everlasting arrangements if cut just before fully open. Divide clumps in spring every 4–5 years using a sharp spade; they are slow to re-establish so divisions should be generous.", "sources": ["general horticultural reference"]}')
