INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('gloriosa-lily','Gloriosa Lily','Gloriosa superba','flower','bulb',NULL,NULL,NULL,NULL,70,90,'transplant','tuber','warm','tender','last_frost',0,2,'Plant tubers horizontally 4 in deep after last frost; in zones 8+ can be planted in early spring once soil is 65°F.',8,12,8,12,48,72,12,18,'full','moderate','Plant the fragile, finger-shaped tubers horizontally 4 in deep, handling carefully to avoid snapping them; provide a trellis or support as the vine climbs by leaf-tip tendrils. The striking reflexed flowers in flame-red and yellow with wavy-edged petals are produced freely from midsummer into fall. All parts of the plant are highly toxic if ingested — site away from children and pets. In zones below 8, dig tubers after foliage dies, dry them, and store in dry peat moss at 50–60°F over winter.','["general horticultural reference"]','{"slug": "gloriosa-lily", "common_name": "Gloriosa Lily", "scientific_name": "Gloriosa superba", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "tuber", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Plant tubers horizontally 4 in deep after last frost; in zones 8+ can be planted in early spring once soil is 65°F."}, "usda_zones": {"min": 8, "max": 12}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Plant the fragile, finger-shaped tubers horizontally 4 in deep, handling carefully to avoid snapping them; provide a trellis or support as the vine climbs by leaf-tip tendrils. The striking reflexed flowers in flame-red and yellow with wavy-edged petals are produced freely from midsummer into fall. All parts of the plant are highly toxic if ingested — site away from children and pets. In zones below 8, dig tubers after foliage dies, dry them, and store in dry peat moss at 50–60°F over winter.", "sources": ["general horticultural reference"]}')
