  VALUES ('chionodoxa','Glory-of-the-Snow','Chionodoxa luciliae','flower','bulb',NULL,NULL,NULL,NULL,90,120,'transplant','bulb','perennial','hardy','fall',-8,-4,'Plant small bulbs 3 in deep in fall; naturalize in lawns, rock gardens, or under deciduous trees.',3,8,2,3,4,6,2,3,'full','low','Plant bulbs in fall, 3 in deep and 2–3 in apart, in any well-drained soil; glory-of-the-snow blooms very early, often pushing through snow in late winter to early spring. The vivid blue, star-shaped flowers with white centers naturalize freely by both offsets and self-seeding, forming large colonies over time. Plant in large drifts under deciduous trees where they receive full sun while leafless and will not be disturbed during summer dormancy. No special care is needed once established; bulbs rarely need dividing.','["general horticultural reference"]','{"slug": "chionodoxa", "common_name": "Glory-of-the-Snow", "scientific_name": "Chionodoxa luciliae", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant small bulbs 3 in deep in fall; naturalize in lawns, rock gardens, or under deciduous trees."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 2, "max": 3}, "height_in": {"min": 4, "max": 6}, "spread_in": {"min": 2, "max": 3}, "sun": "full", "water": "low", "directions": "Plant bulbs in fall, 3 in deep and 2–3 in apart, in any well-drained soil; glory-of-the-snow blooms very early, often pushing through snow in late winter to early spring. The vivid blue, star-shaped flowers with white centers naturalize freely by both offsets and self-seeding, forming large colonies over time. Plant in large drifts under deciduous trees where they receive full sun while leafless and will not be disturbed during summer dormancy. No special care is needed once established; bulbs rarely need dividing.", "sources": ["general horticultural reference"]}')
