INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('goldenrod','Goldenrod','Solidago canadensis','flower','perennial',14,21,60,70,270,365,'seed','direct','perennial','hardy','last_frost',-4,-2,'Direct sow in early spring or fall; clump-forming cultivars are better-behaved than the straight species.',3,9,18,24,24,60,18,30,'full','low','Plant in full sun in average to poor, well-drained soil; goldenrod thrives in lean conditions and becomes overly lax and floppy in rich, moist soil. The arching plumes of golden-yellow flowers from late summer through fall are essential late-season food for monarch butterflies and dozens of native bee species. Contrary to popular belief, goldenrod does not cause hay fever — its pollen is heavy and insect-carried, not windborne. Choose named compact cultivars like ''Fireworks'' or ''Little Lemon'' for well-behaved garden varieties; divide every 2–3 years to control spread.','["general horticultural reference"]','{"slug": "goldenrod", "common_name": "Goldenrod", "scientific_name": "Solidago canadensis", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring or fall; clump-forming cultivars are better-behaved than the straight species."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "low", "directions": "Plant in full sun in average to poor, well-drained soil; goldenrod thrives in lean conditions and becomes overly lax and floppy in rich, moist soil. The arching plumes of golden-yellow flowers from late summer through fall are essential late-season food for monarch butterflies and dozens of native bee species. Contrary to popular belief, goldenrod does not cause hay fever — its pollen is heavy and insect-carried, not windborne. Choose named compact cultivars like ''Fireworks'' or ''Little Lemon'' for well-behaved garden varieties; divide every 2–3 years to control spread.", "sources": ["general horticultural reference"]}')
