INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('grape-hyacinth','Grape Hyacinth','Muscari armeniacum','flower','bulb',NULL,NULL,NULL,NULL,150,180,'transplant','bulb','perennial','hardy','fall',-8,-4,'Plant bulbs in fall, 3–4 in deep; foliage emerges in fall and overwinters, so plant early enough for roots to establish.',3,9,2,3,6,9,2,3,'full','low','Plant small bulbs 3–4 in deep in any well-drained soil; foliage emerges in fall and overwinters as a low ground cover, with tight clusters of cobalt-blue, urn-shaped flowers appearing in early to mid-spring. Muscari naturalizes aggressively by offsets and self-seeding and can spread widely — site where this is desirable or divide clumps every few years in fall to control spread. Excellent planted beneath tulips and daffodils to create complementary color combinations. Deer and rodents generally leave them alone.','["general horticultural reference"]','{"slug": "grape-hyacinth", "common_name": "Grape Hyacinth", "scientific_name": "Muscari armeniacum", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 150, "max": 180}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant bulbs in fall, 3–4 in deep; foliage emerges in fall and overwinters, so plant early enough for roots to establish."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 2, "max": 3}, "height_in": {"min": 6, "max": 9}, "spread_in": {"min": 2, "max": 3}, "sun": "full", "water": "low", "directions": "Plant small bulbs 3–4 in deep in any well-drained soil; foliage emerges in fall and overwinters as a low ground cover, with tight clusters of cobalt-blue, urn-shaped flowers appearing in early to mid-spring. Muscari naturalizes aggressively by offsets and self-seeding and can spread widely — site where this is desirable or divide clumps every few years in fall to control spread. Excellent planted beneath tulips and daffodils to create complementary color combinations. Deer and rodents generally leave them alone.", "sources": ["general horticultural reference"]}')
