  VALUES ('hardy-hibiscus','Hardy Hibiscus','Hibiscus moscheutos','flower','perennial',14,21,70,85,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-10,-8,'Start seeds indoors 8–10 weeks before last frost after nicking the seed coat and soaking 24 hours; transplant after all frost danger has passed.',4,9,24,36,36,72,24,48,'full','high','Nick or file seed coats and soak in warm water for 24 hours before sowing to improve germination rates significantly. Plant in full sun in moist, fertile soil — hardy hibiscus is native to wetlands and performs best with consistent moisture but tolerates average garden beds with regular irrigation. This is a late riser in spring; the shoots emerge much later than other perennials, so mark plants to avoid accidental disturbance. The dinner-plate-sized flowers in white, pink, and crimson open each morning and close by evening, with new blooms produced daily from midsummer through frost.','["general horticultural reference"]','{"slug": "hardy-hibiscus", "common_name": "Hardy Hibiscus", "scientific_name": "Hibiscus moscheutos", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start seeds indoors 8–10 weeks before last frost after nicking the seed coat and soaking 24 hours; transplant after all frost danger has passed."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 24, "max": 48}, "sun": "full", "water": "high", "directions": "Nick or file seed coats and soak in warm water for 24 hours before sowing to improve germination rates significantly. Plant in full sun in moist, fertile soil — hardy hibiscus is native to wetlands and performs best with consistent moisture but tolerates average garden beds with regular irrigation. This is a late riser in spring; the shoots emerge much later than other perennials, so mark plants to avoid accidental disturbance. The dinner-plate-sized flowers in white, pink, and crimson open each morning and close by evening, with new blooms produced daily from midsummer through frost.", "sources": ["general horticultural reference"]}')
