INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('heliotrope','Heliotrope','Heliotropium arborescens','flower','annual',14,28,70,80,80,100,'transplant','indoor-start','warm','tender','last_frost',-12,-10,'Start seeds indoors 10–12 weeks before last frost; transplant only after all frost risk has passed.',2,11,12,18,12,24,12,18,'full','moderate','Sow seeds 1/8 in deep; germination is slow (14–28 days) and benefits from bottom heat at 70–80°F consistently. Transplant into rich, moist, well-drained soil in full sun; heat brings out the intensely vanilla-scented, deep purple flower clusters. Pinch tips once or twice before transplanting to produce bushier plants with more flowering heads. In zones 10–11 heliotrope is a shrubby perennial; elsewhere take cuttings in late summer to overwinter prized fragrant selections indoors.','["general horticultural reference"]','{"slug": "heliotrope", "common_name": "Heliotrope", "scientific_name": "Heliotropium arborescens", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 70, "max": 80}, "days_to_maturity": {"min": 80, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -12, "max": -10}, "note": "Start seeds indoors 10–12 weeks before last frost; transplant only after all frost risk has passed."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/8 in deep; germination is slow (14–28 days) and benefits from bottom heat at 70–80°F consistently. Transplant into rich, moist, well-drained soil in full sun; heat brings out the intensely vanilla-scented, deep purple flower clusters. Pinch tips once or twice before transplanting to produce bushier plants with more flowering heads. In zones 10–11 heliotrope is a shrubby perennial; elsewhere take cuttings in late summer to overwinter prized fragrant selections indoors.", "sources": ["general horticultural reference"]}')
