INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('honesty-lunaria','Honesty / Money Plant','Lunaria annua','flower','annual',10,14,55,65,120,150,'seed','direct','cool','hardy','last_frost',-4,0,'Direct sow in early spring or in summer for flowers the following spring; behaves as a biennial in most climates.',2,11,12,18,24,36,12,18,'partial','moderate','Sow seeds in spring or early summer; plants develop as a rosette the first year and flower the following spring — a true biennial. Purple or white cross-shaped flowers appear in mid-spring, followed by the flat, papery-silver seed pods that give the plant its common names ''honesty'' and ''money plant.'' To harvest pods for dried arrangements, cut when the outer husks have dried and carefully peel away both sides to reveal the lustrous translucent membrane. Plants self-sow freely and once established will perpetuate themselves year after year.','["general horticultural reference"]','{"slug": "honesty-lunaria", "common_name": "Honesty / Money Plant", "scientific_name": "Lunaria annua", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 120, "max": 150}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Direct sow in early spring or in summer for flowers the following spring; behaves as a biennial in most climates."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Sow seeds in spring or early summer; plants develop as a rosette the first year and flower the following spring — a true biennial. Purple or white cross-shaped flowers appear in mid-spring, followed by the flat, papery-silver seed pods that give the plant its common names ''honesty'' and ''money plant.'' To harvest pods for dried arrangements, cut when the outer husks have dried and carefully peel away both sides to reveal the lustrous translucent membrane. Plants self-sow freely and once established will perpetuate themselves year after year.", "sources": ["general horticultural reference"]}')
