INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cerinthe-honeywort','Honeywort / Cerinthe','Cerinthe major ''Purpurascens''','flower','annual',7,14,55,65,60,90,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow in early spring 2–4 weeks before last frost, or sow in fall in zones 7+ for overwintering.',2,11,9,12,18,24,9,12,'full','moderate','Sow seeds 1/4 in deep in cool soil; germination is rapid in the 55–65°F range and slows dramatically in warm conditions. The blue-green waxy foliage and pendant, tubular flowers in deep violet-purple with showy blue-purple bracts are a magnet for bumblebees. Cerinthe prefers cool weather and will bolt and die in summer heat; in mild climates it self-sows prolifically and may return year after year. Harvest stems when bracts are fully colored for a distinctive and long-lasting cut flower.','["general horticultural reference"]','{"slug": "cerinthe-honeywort", "common_name": "Honeywort / Cerinthe", "scientific_name": "Cerinthe major ''Purpurascens''", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring 2–4 weeks before last frost, or sow in fall in zones 7+ for overwintering."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep in cool soil; germination is rapid in the 55–65°F range and slows dramatically in warm conditions. The blue-green waxy foliage and pendant, tubular flowers in deep violet-purple with showy blue-purple bracts are a magnet for bumblebees. Cerinthe prefers cool weather and will bolt and die in summer heat; in mild climates it self-sows prolifically and may return year after year. Harvest stems when bracts are fully colored for a distinctive and long-lasting cut flower.", "sources": ["general horticultural reference"]}')
