  VALUES ('hosta','Hosta','Hosta spp.','flower','perennial',NULL,NULL,NULL,NULL,60,90,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions in spring as new growth emerges or in fall at least 6 weeks before frost.',3,9,12,36,6,48,12,60,'shade','moderate','Set crowns at soil level in humus-rich, consistently moist soil; avoid planting too deep or crowns may rot. Hostas tolerate deep shade but produce their best foliage color with 2–4 hours of dappled morning light. Divide large clumps every 4–5 years in early spring by slicing through the crown with a sharp spade. Slugs are the primary pest; use iron phosphate bait around vulnerable new growth.','["general horticultural reference"]','{"slug": "hosta", "common_name": "Hosta", "scientific_name": "Hosta spp.", "category": "flower", "subcategory": "perennial", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in spring as new growth emerges or in fall at least 6 weeks before frost."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 36}, "height_in": {"min": 6, "max": 48}, "spread_in": {"min": 12, "max": 60}, "sun": "shade", "water": "moderate", "directions": "Set crowns at soil level in humus-rich, consistently moist soil; avoid planting too deep or crowns may rot. Hostas tolerate deep shade but produce their best foliage color with 2–4 hours of dappled morning light. Divide large clumps every 4–5 years in early spring by slicing through the crown with a sharp spade. Slugs are the primary pest; use iron phosphate bait around vulnerable new growth.", "sources": ["general horticultural reference"]}')
