  VALUES ('hyacinth','Hyacinth','Hyacinthus orientalis','flower','bulb',NULL,NULL,NULL,NULL,150,210,'transplant','bulb','perennial','hardy','fall',-8,-4,'Plant bulbs in fall, 4–8 weeks before hard frost, for intensely fragrant spring bloom.',4,8,6,8,10,14,6,8,'full','moderate','Plant bulbs at a depth of 6–8 in (about 3 times the bulb height) in well-drained soil with the pointed end up; wear gloves as the bulb sap can irritate sensitive skin. Hyacinths produce their most spectacular, dense spikes in year 1; subsequent years yield looser, more relaxed flower clusters that many gardeners find charming. Allow foliage to yellow completely before removing it so the bulb can replenish its energy. In warm climates (zones 8+), lift and chill bulbs for 6 weeks before replanting.','["general horticultural reference"]','{"slug": "hyacinth", "common_name": "Hyacinth", "scientific_name": "Hyacinthus orientalis", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 150, "max": 210}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant bulbs in fall, 4–8 weeks before hard frost, for intensely fragrant spring bloom."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 10, "max": 14}, "spread_in": {"min": 6, "max": 8}, "sun": "full", "water": "moderate", "directions": "Plant bulbs at a depth of 6–8 in (about 3 times the bulb height) in well-drained soil with the pointed end up; wear gloves as the bulb sap can irritate sensitive skin. Hyacinths produce their most spectacular, dense spikes in year 1; subsequent years yield looser, more relaxed flower clusters that many gardeners find charming. Allow foliage to yellow completely before removing it so the bulb can replenish its energy. In warm climates (zones 8+), lift and chill bulbs for 6 weeks before replanting.", "sources": ["general horticultural reference"]}')
