INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ice-plant','Ice Plant','Delosperma cooperi','flower','perennial',14,21,65,75,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after all frost risk has passed into sharply drained soil.',5,9,12,18,3,6,12,24,'full','low','Surface-sow tiny seeds on moist, gritty mix without covering, as they need light to germinate; avoid overwatering at all stages. Plant in the hottest, driest, sunniest spot in the garden — sandy, rocky, or gravelly soil is ideal, and root rot is the main cause of failure in clay or poorly drained sites. The magenta to purple daisy-like flowers cover the succulent mats nearly all summer and reopen only in bright sunlight. Hardy ice plant spreads steadily to make a weed-suppressing groundcover on slopes and rock gardens.','["general horticultural reference"]','{"slug": "ice-plant", "common_name": "Ice Plant", "scientific_name": "Delosperma cooperi", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after all frost risk has passed into sharply drained soil."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 3, "max": 6}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "low", "directions": "Surface-sow tiny seeds on moist, gritty mix without covering, as they need light to germinate; avoid overwatering at all stages. Plant in the hottest, driest, sunniest spot in the garden — sandy, rocky, or gravelly soil is ideal, and root rot is the main cause of failure in clay or poorly drained sites. The magenta to purple daisy-like flowers cover the succulent mats nearly all summer and reopen only in bright sunlight. Hardy ice plant spreads steadily to make a weed-suppressing groundcover on slopes and rock gardens.", "sources": ["general horticultural reference"]}')
