INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('iceland-poppy','Iceland Poppy','Papaver nudicaule','flower','annual',10,14,50,60,90,120,'seed','direct','cool','hardy','first_frost',-6,-4,'In zones 7–10 sow in fall 4–6 weeks before first frost for winter and spring bloom; in colder zones direct sow in very early spring as soon as soil can be worked.',2,10,9,12,12,24,6,9,'full','moderate','Surface-sow or barely cover seeds on well-prepared, fine-textured soil; seeds need light and cool temperatures (50–60°F) to germinate — warm soil prevents germination. Plants grow as basal rosettes through winter in mild climates before sending up slender stems topped with large, tissue-paper flowers in spring. Iceland poppies are cool-season plants that stop flowering when summer heat arrives; in cold climates treat them as an early-spring annual with fall-sown or indoor-started transplants set out very early. Harvest cut flowers when buds are just beginning to crack open color and sear stem ends in boiling water to maximize vase life.','["general horticultural reference"]','{"slug": "iceland-poppy", "common_name": "Iceland Poppy", "scientific_name": "Papaver nudicaule", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 50, "max": 60}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "In zones 7–10 sow in fall 4–6 weeks before first frost for winter and spring bloom; in colder zones direct sow in very early spring as soon as soil can be worked."}, "usda_zones": {"min": 2, "max": 10}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 6, "max": 9}, "sun": "full", "water": "moderate", "directions": "Surface-sow or barely cover seeds on well-prepared, fine-textured soil; seeds need light and cool temperatures (50–60°F) to germinate — warm soil prevents germination. Plants grow as basal rosettes through winter in mild climates before sending up slender stems topped with large, tissue-paper flowers in spring. Iceland poppies are cool-season plants that stop flowering when summer heat arrives; in cold climates treat them as an early-spring annual with fall-sown or indoor-started transplants set out very early. Harvest cut flowers when buds are just beginning to crack open color and sear stem ends in boiling water to maximize vase life.", "sources": ["general horticultural reference"]}')
