INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('japanese-anemone','Japanese Anemone','Anemone x hybrida','flower','perennial',NULL,NULL,NULL,NULL,365,730,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions or container-grown plants in spring; slow to establish but eventually spreads vigorously.',4,8,18,24,24,48,18,36,'partial','moderate','Plant in humus-rich, moisture-retentive, well-drained soil in partial shade; Japanese anemone is slow to establish in its first 1–2 years but spreads freely by underground runners once settled. Single or semi-double flowers in white, pink, or deep rose appear on tall, branched stems from late summer through fall when few other perennials are in bloom. Can become invasive in rich, moist conditions — site carefully or contain with buried barriers. Divide in early spring every 3–4 years to control spread or increase the planting.','["general horticultural reference"]','{"slug": "japanese-anemone", "common_name": "Japanese Anemone", "scientific_name": "Anemone x hybrida", "category": "flower", "subcategory": "perennial", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions or container-grown plants in spring; slow to establish but eventually spreads vigorously."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Plant in humus-rich, moisture-retentive, well-drained soil in partial shade; Japanese anemone is slow to establish in its first 1–2 years but spreads freely by underground runners once settled. Single or semi-double flowers in white, pink, or deep rose appear on tall, branched stems from late summer through fall when few other perennials are in bloom. Can become invasive in rich, moist conditions — site carefully or contain with buried barriers. Divide in early spring every 3–4 years to control spread or increase the planting.", "sources": ["general horticultural reference"]}')
