  VALUES ('japanese-iris','Japanese Iris','Iris ensata','flower','perennial',NULL,NULL,NULL,NULL,270,365,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions in spring after frost or immediately after late-summer bloom; keep roots consistently moist after planting.',4,9,18,24,30,48,18,24,'full','high','Plant rhizomes 2 in deep in rich, acidic (pH 5.5–6.5), moisture-retentive to wet soil; Japanese iris excel at pond margins and rain gardens. The enormous flat flowers up to 10 in across appear in early to midsummer in shades of purple, blue, white, and lavender, often with intricate veining. Avoid lime or wood ash near these plants — alkaline soil causes yellowing and poor growth. Divide every 3–4 years in late summer or early spring, replanting healthy outer fans and discarding the woody centers.','["general horticultural reference"]','{"slug": "japanese-iris", "common_name": "Japanese Iris", "scientific_name": "Iris ensata", "category": "flower", "subcategory": "perennial", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in spring after frost or immediately after late-summer bloom; keep roots consistently moist after planting."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 30, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "high", "directions": "Plant rhizomes 2 in deep in rich, acidic (pH 5.5–6.5), moisture-retentive to wet soil; Japanese iris excel at pond margins and rain gardens. The enormous flat flowers up to 10 in across appear in early to midsummer in shades of purple, blue, white, and lavender, often with intricate veining. Avoid lime or wood ash near these plants — alkaline soil causes yellowing and poor growth. Divide every 3–4 years in late summer or early spring, replanting healthy outer fans and discarding the woody centers.", "sources": ["general horticultural reference"]}')
