  VALUES ('joe-pye-weed','Joe Pye Weed','Eutrochium purpureum','flower','perennial',14,21,60,70,365,730,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost after cold-stratifying for 4–6 weeks; transplant in spring.',3,8,24,36,48,84,24,36,'partial','moderate','Cold-stratify seeds for 4–6 weeks in a moist medium in the refrigerator before sowing indoors; germination is improved but still irregular. Plant in moist, humus-rich soil in full sun to partial shade; this native prairie plant tolerates occasional wet feet and dry spells once established. Cutting stems back by half in June (Chelsea chop) reduces ultimate height and prevents the need for staking without sacrificing the domed, mauve-pink flower clusters beloved by butterflies. Seedheads are ornamentally interesting into winter and provide food for goldfinches.','["general horticultural reference"]','{"slug": "joe-pye-weed", "common_name": "Joe Pye Weed", "scientific_name": "Eutrochium purpureum", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost after cold-stratifying for 4–6 weeks; transplant in spring."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 48, "max": 84}, "spread_in": {"min": 24, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Cold-stratify seeds for 4–6 weeks in a moist medium in the refrigerator before sowing indoors; germination is improved but still irregular. Plant in moist, humus-rich soil in full sun to partial shade; this native prairie plant tolerates occasional wet feet and dry spells once established. Cutting stems back by half in June (Chelsea chop) reduces ultimate height and prevents the need for staking without sacrificing the domed, mauve-pink flower clusters beloved by butterflies. Seedheads are ornamentally interesting into winter and provide food for goldfinches.", "sources": ["general horticultural reference"]}')
