  VALUES ('lantana','Lantana','Lantana camara','flower','annual',14,42,70,80,70,90,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start seeds indoors 8–10 weeks before last frost; most gardeners use purchased transplants due to slow, uneven germination.',2,11,18,36,12,48,18,48,'full','low','Sow seeds after lightly scarifying or nicking the seed coat; soak overnight to improve germination, which is slow and can take 4–6 weeks at 70–80°F. Transplant in full sun after all frost risk has passed; lantana thrives in heat, drought, and poor soil and blooms most freely under mild stress. The multicolored flower clusters change color as they age, giving plants a jewel-like effect; deadhead clusters as they fade to keep new flowers coming. Perennial in zones 9–11 where it can become invasive; grow as an annual elsewhere.','["general horticultural reference"]','{"slug": "lantana", "common_name": "Lantana", "scientific_name": "Lantana camara", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 42}, "germination_soil_temp_f": {"min": 70, "max": 80}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start seeds indoors 8–10 weeks before last frost; most gardeners use purchased transplants due to slow, uneven germination."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 18, "max": 36}, "height_in": {"min": 12, "max": 48}, "spread_in": {"min": 18, "max": 48}, "sun": "full", "water": "low", "directions": "Sow seeds after lightly scarifying or nicking the seed coat; soak overnight to improve germination, which is slow and can take 4–6 weeks at 70–80°F. Transplant in full sun after all frost risk has passed; lantana thrives in heat, drought, and poor soil and blooms most freely under mild stress. The multicolored flower clusters change color as they age, giving plants a jewel-like effect; deadhead clusters as they fade to keep new flowers coming. Perennial in zones 9–11 where it can become invasive; grow as an annual elsewhere.", "sources": ["general horticultural reference"]}')
