  VALUES ('larkspur','Larkspur','Consolida ajacis','flower','annual',14,21,50,65,65,100,'seed','direct','cool','hardy','last_frost',-8,-4,'Direct sow in early spring 4–8 weeks before last frost, or sow in fall in mild climates for early spring bloom. Seeds need cold stratification and prefer cool soil to germinate.',3,9,6,12,18,48,6,10,'full','moderate','Sow seed 1/8 in deep directly in the garden as early as the ground can be worked — larkspur germinates best in cool soil below 65°F and may fail to sprout if the weather turns warm. Do not start indoors, as plants have taproots that do not transplant well. Thin to 9–12 in to promote sturdy stems. Allow some seed to fall for reliable self-sowing in subsequent years.','["general horticultural reference"]','{"slug": "larkspur", "common_name": "Larkspur", "scientific_name": "Consolida ajacis", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 65, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Direct sow in early spring 4–8 weeks before last frost, or sow in fall in mild climates for early spring bloom. Seeds need cold stratification and prefer cool soil to germinate."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 18, "max": 48}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/8 in deep directly in the garden as early as the ground can be worked — larkspur germinates best in cool soil below 65°F and may fail to sprout if the weather turns warm. Do not start indoors, as plants have taproots that do not transplant well. Thin to 9–12 in to promote sturdy stems. Allow some seed to fall for reliable self-sowing in subsequent years.", "sources": ["general horticultural reference"]}')
