INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('liatris','Liatris','Liatris spicata','flower','perennial',21,28,55,65,365,730,'transplant','bulb','perennial','hardy','spring',0,4,'Plant corms 3–4 in deep in spring as soon as the soil can be worked; they establish quickly and bloom the first season.',3,9,12,15,24,48,12,18,'full','low','Plant corms 3–4 in deep with the flat side down in well-drained, average to poor soil in full sun; rich or wet soil leads to floppy growth. Liatris is unique in opening its flowers from the top of the spike downward, prolonging the bloom period for 3–4 weeks in midsummer. The purple to rose-pink spikes are outstanding cut flowers and highly attractive to butterflies and bees; stems last 10–14 days in a vase. Clumps multiply steadily; divide every 3–4 years in spring to prevent overcrowding and maintain strong bloom.','["general horticultural reference"]','{"slug": "liatris", "common_name": "Liatris", "scientific_name": "Liatris spicata", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 28}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant corms 3–4 in deep in spring as soon as the soil can be worked; they establish quickly and bloom the first season."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 15}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Plant corms 3–4 in deep with the flat side down in well-drained, average to poor soil in full sun; rich or wet soil leads to floppy growth. Liatris is unique in opening its flowers from the top of the spike downward, prolonging the bloom period for 3–4 weeks in midsummer. The purple to rose-pink spikes are outstanding cut flowers and highly attractive to butterflies and bees; stems last 10–14 days in a vase. Clumps multiply steadily; divide every 3–4 years in spring to prevent overcrowding and maintain strong bloom.", "sources": ["general horticultural reference"]}')
