INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lisianthus','Lisianthus','Eustoma grandiflorum','flower','annual',14,21,70,75,150,180,'transplant','indoor-start','warm','tender','last_frost',-16,-14,'Start seeds indoors 14–16 weeks before last frost date; lisianthus requires a very long lead time and is challenging from seed.',2,11,12,18,18,36,12,18,'full','moderate','Surface-sow tiny, pelleted seeds on sterile, fine-textured mix; do not cover as seeds need light and maintain steady 70–75°F. Seedlings grow extremely slowly for the first 8–10 weeks, so patience is essential — do not overwater at this stage as damping off is common. Transplant carefully after last frost into rich, well-drained, alkaline-leaning soil in full sun. The ruffled, rose-like blooms in white, purple, pink, and bicolor make lisianthus one of the finest cut flowers; harvest stems when 2–3 buds per stem have opened.','["general horticultural reference"]','{"slug": "lisianthus", "common_name": "Lisianthus", "scientific_name": "Eustoma grandiflorum", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 150, "max": 180}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -16, "max": -14}, "note": "Start seeds indoors 14–16 weeks before last frost date; lisianthus requires a very long lead time and is challenging from seed."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Surface-sow tiny, pelleted seeds on sterile, fine-textured mix; do not cover as seeds need light and maintain steady 70–75°F. Seedlings grow extremely slowly for the first 8–10 weeks, so patience is essential — do not overwater at this stage as damping off is common. Transplant carefully after last frost into rich, well-drained, alkaline-leaning soil in full sun. The ruffled, rose-like blooms in white, purple, pink, and bicolor make lisianthus one of the finest cut flowers; harvest stems when 2–3 buds per stem have opened.", "sources": ["general horticultural reference"]}')
