INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('little-bluestem','Little Bluestem','Schizachyrium scoparium','flower','ornamental-grass',14,21,65,75,180,270,'seed','direct','perennial','hardy','last_frost',0,4,'Direct sow after last frost in spring, or plant divisions in spring in full sun and lean, well-drained soil.',3,9,18,24,24,48,18,24,'full','low','Direct sow in full sun in lean, well-drained to dry soil; little bluestem is a native prairie grass of exceptional ornamental value that thrives in poor, sandy, or rocky soil where it develops the best fall color. Blue-green summer foliage turns brilliant coppery-orange and burgundy-red in fall, and the silver-white fluffy seedheads persist through winter, capturing hoarfrost beautifully. In rich, moist soil plants become floppy and lose their characteristic upright form. Cut back to 4–6 in in late winter before new growth emerges; divide every 3–4 years if needed.','["general horticultural reference"]','{"slug": "little-bluestem", "common_name": "Little Bluestem", "scientific_name": "Schizachyrium scoparium", "category": "flower", "subcategory": "ornamental-grass", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 180, "max": 270}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Direct sow after last frost in spring, or plant divisions in spring in full sun and lean, well-drained soil."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Direct sow in full sun in lean, well-drained to dry soil; little bluestem is a native prairie grass of exceptional ornamental value that thrives in poor, sandy, or rocky soil where it develops the best fall color. Blue-green summer foliage turns brilliant coppery-orange and burgundy-red in fall, and the silver-white fluffy seedheads persist through winter, capturing hoarfrost beautifully. In rich, moist soil plants become floppy and lose their characteristic upright form. Cut back to 4–6 in in late winter before new growth emerges; divide every 3–4 years if needed.", "sources": ["general horticultural reference"]}')
