INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('love-lies-bleeding','Love-Lies-Bleeding (Amaranth)','Amaranthus caudatus','flower','annual',7,14,65,75,60,90,'seed','direct','warm','tender','last_frost',0,2,'Direct sow after last frost when soil is warm; do not start too early indoors as plants grow quickly and become rootbound.',2,11,18,24,36,60,18,24,'full','low','Sow seed on the soil surface and press lightly — seed needs light to germinate. Direct sowing is preferred as plants grow fast and resent transplanting. Thin seedlings to 18–24 in to allow the dramatic, rope-like crimson tassels to develop fully. The hanging panicles can be cut and hung upside down to dry when they reach full length.','["general horticultural reference"]','{"slug": "love-lies-bleeding", "common_name": "Love-Lies-Bleeding (Amaranth)", "scientific_name": "Amaranthus caudatus", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow after last frost when soil is warm; do not start too early indoors as plants grow quickly and become rootbound."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Sow seed on the soil surface and press lightly — seed needs light to germinate. Direct sowing is preferred as plants grow fast and resent transplanting. Thin seedlings to 18–24 in to allow the dramatic, rope-like crimson tassels to develop fully. The hanging panicles can be cut and hung upside down to dry when they reach full length.", "sources": ["general horticultural reference"]}')
