  VALUES ('love-in-a-mist','Love-in-a-Mist','Nigella damascena','flower','annual',10,14,55,65,60,80,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost in early spring; also sow in fall in zones 7–10 for spring bloom.',2,11,9,12,12,18,9,12,'full','low','Scatter seeds directly on prepared soil and rake in 1/8 in deep; nigella resents transplanting and germinates best in cool soil. Thin seedlings to 9–12 in to prevent overcrowding — plants are quick to grow and will self-sow freely if allowed to set the inflated seed pods. The blue or white flowers are surrounded by thread-like bracts that give the plant its misty appearance; after bloom the ornamental balloon-like pods are equally attractive and excellent for dried arrangements. Make succession sowings every 3–4 weeks until early summer for continuous bloom.','["general horticultural reference"]','{"slug": "love-in-a-mist", "common_name": "Love-in-a-Mist", "scientific_name": "Nigella damascena", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost in early spring; also sow in fall in zones 7–10 for spring bloom."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "low", "directions": "Scatter seeds directly on prepared soil and rake in 1/8 in deep; nigella resents transplanting and germinates best in cool soil. Thin seedlings to 9–12 in to prevent overcrowding — plants are quick to grow and will self-sow freely if allowed to set the inflated seed pods. The blue or white flowers are surrounded by thread-like bracts that give the plant its misty appearance; after bloom the ornamental balloon-like pods are equally attractive and excellent for dried arrangements. Make succession sowings every 3–4 weeks until early summer for continuous bloom.", "sources": ["general horticultural reference"]}')
