INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lungwort','Lungwort','Pulmonaria saccharata','flower','perennial',21,42,55,65,270,365,'seed','division','perennial','hardy','spring',0,4,'Plant divisions in spring or fall in a shaded, moist site; division is the most reliable propagation method.',3,8,12,18,9,15,18,24,'shade','moderate','Plant in deep shade to partial shade in humus-rich, consistently moist soil; lungwort is one of the best shade perennials, offering both attractive silver-spotted foliage and early spring flowers. Pink buds open to blue or violet tubular flowers in early spring, often when little else is in bloom, providing nectar for early pollinators. In hot, dry summers the leaves may develop powdery mildew — shear back affected foliage after flowering and new, fresh leaves will emerge. Divide clumps every 3–4 years immediately after flowering to maintain vigor.','["general horticultural reference"]','{"slug": "lungwort", "common_name": "Lungwort", "scientific_name": "Pulmonaria saccharata", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "seed", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in spring or fall in a shaded, moist site; division is the most reliable propagation method."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 9, "max": 15}, "spread_in": {"min": 18, "max": 24}, "sun": "shade", "water": "moderate", "directions": "Plant in deep shade to partial shade in humus-rich, consistently moist soil; lungwort is one of the best shade perennials, offering both attractive silver-spotted foliage and early spring flowers. Pink buds open to blue or violet tubular flowers in early spring, often when little else is in bloom, providing nectar for early pollinators. In hot, dry summers the leaves may develop powdery mildew — shear back affected foliage after flowering and new, fresh leaves will emerge. Divide clumps every 3–4 years immediately after flowering to maintain vigor.", "sources": ["general horticultural reference"]}')
