  VALUES ('maiden-grass','Maiden Grass','Miscanthus sinensis','flower','ornamental-grass',14,21,65,75,180,270,'transplant','division','perennial','hardy','spring',0,6,'Plant divisions in spring when soil has warmed; miscanthus establishes best in warm soil and can be slow in cold springs.',5,9,36,60,48,84,36,60,'full','moderate','Plant divisions in full sun in any well-drained to moderately moist soil; maiden grass forms large, dramatic clumps with arching, green or variegated foliage and showy, feathery silver plumes in late summer and fall. Cut back hard in late winter or early spring before new growth emerges — use pruners or a chainsaw on large clumps; tie the clump with twine before cutting to simplify cleanup. Divide every 3–5 years in spring when the center of the clump dies out. Some cultivars are sterile; check before planting, as seeding types can naturalize aggressively in some regions.','["general horticultural reference"]','{"slug": "maiden-grass", "common_name": "Maiden Grass", "scientific_name": "Miscanthus sinensis", "category": "flower", "subcategory": "ornamental-grass", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 180, "max": 270}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 6}, "note": "Plant divisions in spring when soil has warmed; miscanthus establishes best in warm soil and can be slow in cold springs."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 48, "max": 84}, "spread_in": {"min": 36, "max": 60}, "sun": "full", "water": "moderate", "directions": "Plant divisions in full sun in any well-drained to moderately moist soil; maiden grass forms large, dramatic clumps with arching, green or variegated foliage and showy, feathery silver plumes in late summer and fall. Cut back hard in late winter or early spring before new growth emerges — use pruners or a chainsaw on large clumps; tie the clump with twine before cutting to simplify cleanup. Divide every 3–5 years in spring when the center of the clump dies out. Some cultivars are sterile; check before planting, as seeding types can naturalize aggressively in some regions.", "sources": ["general horticultural reference"]}')
