  VALUES ('martagon-lily','Martagon Lily','Lilium martagon','flower','bulb',NULL,NULL,NULL,NULL,90,120,'transplant','bulb','perennial','hardy','fall',-8,-4,'Plant bulbs in fall at least 6 weeks before the ground freezes; disturb as little as possible once established.',3,8,12,18,36,72,12,18,'partial','moderate','Plant bulbs 6 in deep in humus-rich, well-drained soil; martagon lilies are unusual in tolerating partial shade and actually prefer dappled woodland conditions. Whorled leaves and pendant, turks-cap-shaped flowers in pink, purple, or white with recurved petals appear in early summer. Martagon lilies are slow to establish and may not bloom for 2 years after planting — once settled they are very long-lived and resent being disturbed. Self-seeding is common; seedlings take 4–7 years to bloom.','["general horticultural reference"]','{"slug": "martagon-lily", "common_name": "Martagon Lily", "scientific_name": "Lilium martagon", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant bulbs in fall at least 6 weeks before the ground freezes; disturb as little as possible once established."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Plant bulbs 6 in deep in humus-rich, well-drained soil; martagon lilies are unusual in tolerating partial shade and actually prefer dappled woodland conditions. Whorled leaves and pendant, turks-cap-shaped flowers in pink, purple, or white with recurved petals appear in early summer. Martagon lilies are slow to establish and may not bloom for 2 years after planting — once settled they are very long-lived and resent being disturbed. Self-seeding is common; seedlings take 4–7 years to bloom.", "sources": ["general horticultural reference"]}')
