  VALUES ('meadow-rue','Meadow Rue','Thalictrum rochebruneanum','flower','perennial',21,42,55,65,365,548,'seed','indoor-start','perennial','hardy','last_frost',-10,-8,'Start seeds indoors 8–10 weeks before last frost with cold stratification; or plant divisions in early spring.',4,8,18,24,48,72,18,24,'partial','moderate','Plant in humus-rich, consistently moist soil in partial shade; tall meadow rue creates an airy, vertical accent with blue-green, columbine-like foliage and billowing clouds of lavender-purple flowers in midsummer. The delicate flowers are held on strong, self-supporting stems and sway gracefully in a breeze. Seldom needs staking if grown in adequate light; divide every 4–5 years in early spring to keep plants vigorous. Excellent in a woodland border or at the back of a shaded perennial bed.','["general horticultural reference"]','{"slug": "meadow-rue", "common_name": "Meadow Rue", "scientific_name": "Thalictrum rochebruneanum", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start seeds indoors 8–10 weeks before last frost with cold stratification; or plant divisions in early spring."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 18, "max": 24}, "sun": "partial", "water": "moderate", "directions": "Plant in humus-rich, consistently moist soil in partial shade; tall meadow rue creates an airy, vertical accent with blue-green, columbine-like foliage and billowing clouds of lavender-purple flowers in midsummer. The delicate flowers are held on strong, self-supporting stems and sway gracefully in a breeze. Seldom needs staking if grown in adequate light; divide every 4–5 years in early spring to keep plants vigorous. Excellent in a woodland border or at the back of a shaded perennial bed.", "sources": ["general horticultural reference"]}')
