  VALUES ('mexican-bush-sage','Mexican Bush Sage','Salvia leucantha','flower','perennial',14,21,70,80,90,150,'transplant','transplant','perennial','half-hardy','last_frost',0,4,'Plant container stock after last frost; Mexican bush sage blooms in fall and is the showiest late-season salvia for zone 8–11 landscapes.',8,11,36,48,48,72,36,48,'full','low','Plant in well-drained, moderately fertile soil in full sun; Mexican bush sage is drought tolerant once established and demands good drainage over fertility. It is a short-day plant that blooms from September through frost, producing velvety purple flower spikes loved by hummingbirds and bumblebees; the later into fall it blooms, the more spectacular the display. Cut the entire plant back to 6–8 in after the last hard freeze in late winter to stimulate dense new basal growth. Propagate easily by dividing the clump in spring or rooting stem cuttings in moist perlite.','["Texas A&M AgriLife Extension Service", "general horticultural reference"]','{"slug": "mexican-bush-sage", "common_name": "Mexican Bush Sage", "scientific_name": "Salvia leucantha", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 80}, "days_to_maturity": {"min": 90, "max": 150}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant container stock after last frost; Mexican bush sage blooms in fall and is the showiest late-season salvia for zone 8–11 landscapes."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 36, "max": 48}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 36, "max": 48}, "sun": "full", "water": "low", "directions": "Plant in well-drained, moderately fertile soil in full sun; Mexican bush sage is drought tolerant once established and demands good drainage over fertility. It is a short-day plant that blooms from September through frost, producing velvety purple flower spikes loved by hummingbirds and bumblebees; the later into fall it blooms, the more spectacular the display. Cut the entire plant back to 6–8 in after the last hard freeze in late winter to stimulate dense new basal growth. Propagate easily by dividing the clump in spring or rooting stem cuttings in moist perlite.", "sources": ["Texas A&M AgriLife Extension Service", "general horticultural reference"]}')
