INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('mexican-feather-grass','Mexican Feather Grass','Nassella tenuissima','flower','ornamental-grass',14,21,60,70,90,120,'seed','direct','perennial','hardy','last_frost',-2,2,'Direct sow around last frost date in a sunny, dry site; self-seeds profusely — site away from natural areas.',6,10,12,18,18,24,12,18,'full','low','Sow seeds directly in full sun in lean, very well-drained soil — rich or moist conditions produce weak, floppy plants. The hair-fine, bright green leaves form airy, billowing mounds that catch every breeze, creating a constant motion in the landscape; the foliage turns blonde and golden in summer heat. This grass self-seeds very aggressively and is considered invasive in California and some southwestern states — deadhead before seeds ripen if growing in areas with native grasslands. Cut back hard in late winter before new growth begins.','["general horticultural reference"]','{"slug": "mexican-feather-grass", "common_name": "Mexican Feather Grass", "scientific_name": "Nassella tenuissima", "category": "flower", "subcategory": "ornamental-grass", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Direct sow around last frost date in a sunny, dry site; self-seeds profusely — site away from natural areas."}, "usda_zones": {"min": 6, "max": 10}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seeds directly in full sun in lean, very well-drained soil — rich or moist conditions produce weak, floppy plants. The hair-fine, bright green leaves form airy, billowing mounds that catch every breeze, creating a constant motion in the landscape; the foliage turns blonde and golden in summer heat. This grass self-seeds very aggressively and is considered invasive in California and some southwestern states — deadhead before seeds ripen if growing in areas with native grasslands. Cut back hard in late winter before new growth begins.", "sources": ["general horticultural reference"]}')
