INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('mexican-sunflower','Mexican Sunflower','Tithonia rotundifolia','flower','annual',5,10,65,85,70,90,'seed','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant after frost danger passes — one of the best heat-loving annuals for attracting butterflies and hummingbirds.',3,11,24,36,48,72,24,36,'full','low','Sow seeds 1/4 in deep in warm starting mix; transplant carefully as Tithonia dislikes root disturbance — use biodegradable pots if starting indoors. Mexican sunflower thrives in heat, poor soil, and dry conditions, making it ideal for back-of-border plantings in Gulf Coast summers when other annuals falter. The vivid orange, 3-inch daisy-like flowers are irresistible to monarch butterflies, swallowtails, and hummingbirds from midsummer through frost. Deadhead regularly by cutting stems (not just the flower head) back to a side shoot to maintain tidy plants and prolong heavy bloom.','["general horticultural reference"]','{"slug": "mexican-sunflower", "common_name": "Mexican Sunflower", "scientific_name": "Tithonia rotundifolia", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant after frost danger passes — one of the best heat-loving annuals for attracting butterflies and hummingbirds."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Sow seeds 1/4 in deep in warm starting mix; transplant carefully as Tithonia dislikes root disturbance — use biodegradable pots if starting indoors. Mexican sunflower thrives in heat, poor soil, and dry conditions, making it ideal for back-of-border plantings in Gulf Coast summers when other annuals falter. The vivid orange, 3-inch daisy-like flowers are irresistible to monarch butterflies, swallowtails, and hummingbirds from midsummer through frost. Deadhead regularly by cutting stems (not just the flower head) back to a side shoot to maintain tidy plants and prolong heavy bloom.", "sources": ["general horticultural reference"]}')
