  VALUES ('monkshood','Monkshood','Aconitum napellus','flower','perennial',25,42,55,65,365,548,'seed','division','perennial','hardy','fall',-8,-4,'Plant tuber-like roots in fall or early spring in a cool, moist, partially shaded site; wear gloves — all parts are highly toxic.',3,7,18,24,36,60,18,24,'partial','moderate','Plant with the tuber-like roots 3–4 in deep in rich, cool, moist, well-drained soil; monkshood is a stately perennial with bold, deeply lobed foliage and tall spikes of deep blue-violet helmet-shaped flowers in late summer to early fall. All parts of the plant are extremely toxic if ingested or if the sap contacts broken skin — always wear gloves when handling and wash hands thoroughly after. It is one of the best late-season blues in the perennial garden and thrives where summers are cool. Divide every 4–5 years in early spring; keep plants where they will not be disturbed by children or pets.','["general horticultural reference"]','{"slug": "monkshood", "common_name": "Monkshood", "scientific_name": "Aconitum napellus", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 25, "max": 42}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "seed", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant tuber-like roots in fall or early spring in a cool, moist, partially shaded site; wear gloves — all parts are highly toxic."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "partial", "water": "moderate", "directions": "Plant with the tuber-like roots 3–4 in deep in rich, cool, moist, well-drained soil; monkshood is a stately perennial with bold, deeply lobed foliage and tall spikes of deep blue-violet helmet-shaped flowers in late summer to early fall. All parts of the plant are extremely toxic if ingested or if the sap contacts broken skin — always wear gloves when handling and wash hands thoroughly after. It is one of the best late-season blues in the perennial garden and thrives where summers are cool. Divide every 4–5 years in early spring; keep plants where they will not be disturbed by children or pets.", "sources": ["general horticultural reference"]}')
