INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('moonflower','Moonflower','Ipomoea alba','flower','annual',5,14,65,80,70,100,'seed','indoor-start','warm','tender','last_frost',-4,-2,'Start indoors 2–4 weeks before last frost after nicking or soaking seed; transplant after all frost risk has passed.',3,11,12,18,72,180,12,24,'full','moderate','Nick or soak seeds in warm water for 12 hours before sowing 1/2 in deep. Moonflower is a vigorous, fast-growing vine that needs a strong trellis or fence. Unlike morning glories, its large, fragrant white blossoms open in the evening and remain open through the night and into the following morning. Avoid high-nitrogen fertilizers to encourage blooming.','["general horticultural reference"]','{"slug": "moonflower", "common_name": "Moonflower", "scientific_name": "Ipomoea alba", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 5, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 80}, "days_to_maturity": {"min": 70, "max": 100}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Start indoors 2–4 weeks before last frost after nicking or soaking seed; transplant after all frost risk has passed."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 72, "max": 180}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "moderate", "directions": "Nick or soak seeds in warm water for 12 hours before sowing 1/2 in deep. Moonflower is a vigorous, fast-growing vine that needs a strong trellis or fence. Unlike morning glories, its large, fragrant white blossoms open in the evening and remain open through the night and into the following morning. Avoid high-nitrogen fertilizers to encourage blooming.", "sources": ["general horticultural reference"]}')
