INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('nemesia','Nemesia','Nemesia strumosa','flower','annual',7,14,60,65,50,70,'transplant','indoor-start','cool','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant 2–3 weeks before last frost as plants tolerate light frost.',2,11,6,9,8,14,6,9,'full','moderate','Sow seeds 1/8 in deep in fine-textured germination mix at 60–65°F; avoid higher temperatures as heat inhibits germination. Plant outdoors in cool weather in a spot with morning sun and afternoon shade where summers are hot. Nemesia blooms prolifically in cool conditions with cheerful two-toned flowers in a huge range of colors; it typically falters in summer heat so shear back and move containers to a cooler spot. Plants may revive and rebloom in fall when temperatures drop again.','["general horticultural reference"]','{"slug": "nemesia", "common_name": "Nemesia", "scientific_name": "Nemesia strumosa", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 65}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant 2–3 weeks before last frost as plants tolerate light frost."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 8, "max": 14}, "spread_in": {"min": 6, "max": 9}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/8 in deep in fine-textured germination mix at 60–65°F; avoid higher temperatures as heat inhibits germination. Plant outdoors in cool weather in a spot with morning sun and afternoon shade where summers are hot. Nemesia blooms prolifically in cool conditions with cheerful two-toned flowers in a huge range of colors; it typically falters in summer heat so shear back and move containers to a cooler spot. Plants may revive and rebloom in fall when temperatures drop again.", "sources": ["general horticultural reference"]}')
