  VALUES ('obedient-plant','Obedient Plant','Physostegia virginiana','flower','perennial',14,21,65,70,365,730,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; plants bloom in year two from seed but transplants purchased in spring bloom the first year.',2,9,18,24,24,48,18,36,'full','moderate','Sow seeds 1/8 in deep; cold stratification for 4–6 weeks improves germination. Plant in moist to average soil in full sun; established plants spread aggressively by underground rhizomes and may require annual division to prevent them from overtaking the border. The name refers to the curious behavior of individual florets staying in place when moved along the square stem. The pink to lilac spikes bloom in late summer and fall when pollinators are seeking food before winter.','["general horticultural reference"]','{"slug": "obedient-plant", "common_name": "Obedient Plant", "scientific_name": "Physostegia virginiana", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; plants bloom in year two from seed but transplants purchased in spring bloom the first year."}, "usda_zones": {"min": 2, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 36}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/8 in deep; cold stratification for 4–6 weeks improves germination. Plant in moist to average soil in full sun; established plants spread aggressively by underground rhizomes and may require annual division to prevent them from overtaking the border. The name refers to the curious behavior of individual florets staying in place when moved along the square stem. The pink to lilac spikes bloom in late summer and fall when pollinators are seeking food before winter.", "sources": ["general horticultural reference"]}')
