INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('oriental-lily','Oriental Lily','Lilium orientalis hybrids','flower','bulb',NULL,NULL,NULL,NULL,90,120,'transplant','bulb','perennial','hardy','fall',-8,-4,'Plant bulbs in fall or early spring as soon as the ground can be worked; fall planting is preferred in zones 4–7.',4,9,12,18,24,60,12,18,'full','moderate','Plant bulbs 6–8 in deep (3 times the bulb diameter) in well-drained, organically rich, slightly acidic soil; apply mulch to keep roots cool. Oriental lilies prefer to have their heads in the sun and their feet in the shade — interplant with low perennials to shade the root zone. The large, intensely fragrant blooms appear in mid- to late summer; deadhead after flowering but allow foliage to remain until it yellows naturally. Avoid overhead watering to reduce the risk of botrytis; stake tall cultivars against wind damage.','["general horticultural reference"]','{"slug": "oriental-lily", "common_name": "Oriental Lily", "scientific_name": "Lilium orientalis hybrids", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant bulbs in fall or early spring as soon as the ground can be worked; fall planting is preferred in zones 4–7."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Plant bulbs 6–8 in deep (3 times the bulb diameter) in well-drained, organically rich, slightly acidic soil; apply mulch to keep roots cool. Oriental lilies prefer to have their heads in the sun and their feet in the shade — interplant with low perennials to shade the root zone. The large, intensely fragrant blooms appear in mid- to late summer; deadhead after flowering but allow foliage to remain until it yellows naturally. Avoid overhead watering to reduce the risk of botrytis; stake tall cultivars against wind damage.", "sources": ["general horticultural reference"]}')
