  VALUES ('oriental-poppy','Oriental Poppy','Papaver orientale','flower','perennial',10,21,55,65,365,730,'seed','direct','perennial','hardy','last_frost',-4,0,'Direct sow in early spring or fall; seeds need cool soil and germinate best when sown directly outdoors.',3,7,18,24,24,36,18,24,'full','low','Surface-sow seeds in early spring on well-prepared, well-drained soil; seeds need cool temperatures and light, so press firmly without covering. Oriental poppies bloom for a brief but spectacular 2–3 weeks in late spring to early summer with crepe-paper petals in orange, red, pink, or white up to 6 in across. Plants go dormant after bloom leaving a bare spot — interplant with late-emerging annuals like baby''s breath or dahlias to fill the gap. Divide clumps in late summer while dormant; established plants dislike being moved during the growing season.','["general horticultural reference"]','{"slug": "oriental-poppy", "common_name": "Oriental Poppy", "scientific_name": "Papaver orientale", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Direct sow in early spring or fall; seeds need cool soil and germinate best when sown directly outdoors."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Surface-sow seeds in early spring on well-prepared, well-drained soil; seeds need cool temperatures and light, so press firmly without covering. Oriental poppies bloom for a brief but spectacular 2–3 weeks in late spring to early summer with crepe-paper petals in orange, red, pink, or white up to 6 in across. Plants go dormant after bloom leaving a bare spot — interplant with late-emerging annuals like baby''s breath or dahlias to fill the gap. Divide clumps in late summer while dormant; established plants dislike being moved during the growing season.", "sources": ["general horticultural reference"]}')
