  VALUES ('orlaya-white-lace','Orlaya / White Lace Flower','Orlaya grandiflora','flower','annual',14,21,55,65,60,75,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow in early spring 2–4 weeks before last frost, or sow in fall where winters are mild.',2,11,9,12,18,24,9,12,'full','low','Sow seeds on the soil surface in early spring as they need light and cool temperatures to germinate; do not cover seeds. Orlaya produces flat-topped umbel flowers with large, irregular outer florets that create a delicate lace effect in pure white, ideal as a cut flower filler. It prefers lean, well-drained soil — overly rich conditions produce lush foliage at the expense of flowers. Plants self-sow readily where happy, returning reliably if the ground is not disturbed; collect seed or allow them to fall for the following year.','["general horticultural reference"]','{"slug": "orlaya-white-lace", "common_name": "Orlaya / White Lace Flower", "scientific_name": "Orlaya grandiflora", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 60, "max": 75}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring 2–4 weeks before last frost, or sow in fall where winters are mild."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "low", "directions": "Sow seeds on the soil surface in early spring as they need light and cool temperatures to germinate; do not cover seeds. Orlaya produces flat-topped umbel flowers with large, irregular outer florets that create a delicate lace effect in pure white, ideal as a cut flower filler. It prefers lean, well-drained soil — overly rich conditions produce lush foliage at the expense of flowers. Plants self-sow readily where happy, returning reliably if the ground is not disturbed; collect seed or allow them to fall for the following year.", "sources": ["general horticultural reference"]}')
