INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ornamental-allium','Ornamental Allium','Allium spp.','flower','bulb',NULL,NULL,NULL,NULL,180,240,'transplant','bulb','perennial','hardy','fall',-8,-4,'Plant bulbs in fall, 4–8 weeks before the ground freezes, for late-spring to early-summer bloom.',4,9,6,12,12,60,6,12,'full','low','Plant bulbs in fall at a depth of 3 times their diameter in sharply drained soil; the large-flowered types like ''Globemaster'' can be planted 12 in deep for stability. Foliage often begins to yellow while the flowers are still in bloom — interplanting with perennials helps mask the dying leaves. Deer and rodents avoid alliums, making them a good choice for wildlife-prone gardens. Spherical seedheads are ornamentally interesting and can be dried for arrangements.','["general horticultural reference"]','{"slug": "ornamental-allium", "common_name": "Ornamental Allium", "scientific_name": "Allium spp.", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 180, "max": 240}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant bulbs in fall, 4–8 weeks before the ground freezes, for late-spring to early-summer bloom."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 12, "max": 60}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "low", "directions": "Plant bulbs in fall at a depth of 3 times their diameter in sharply drained soil; the large-flowered types like ''Globemaster'' can be planted 12 in deep for stability. Foliage often begins to yellow while the flowers are still in bloom — interplanting with perennials helps mask the dying leaves. Deer and rodents avoid alliums, making them a good choice for wildlife-prone gardens. Spherical seedheads are ornamentally interesting and can be dried for arrangements.", "sources": ["general horticultural reference"]}')
