INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ornamental-millet','Ornamental Millet','Pennisetum glaucum ''Purple Majesty''','flower','ornamental-grass',5,10,65,75,60,90,'seed','indoor-start','warm','tender','last_frost',-6,-4,'Start seeds indoors 4–6 weeks before last frost; transplant after soil has warmed thoroughly.',2,11,18,24,36,60,18,24,'full','moderate','Start seeds indoors 4–6 weeks before last frost at 70–75°F; transplant after frost danger passes into full sun and fertile, well-drained soil — warm soil is essential for strong establishment. Grown as an annual for its striking deep burgundy-purple foliage and the large, cylindrical flower/grain heads that arch gracefully under their own weight in late summer. An excellent anchor plant in tropical-style or mixed annual borders, and the dried seed heads are useful in arrangements. Highly attractive to birds in fall — leave some plants intact for wildlife value.','["general horticultural reference"]','{"slug": "ornamental-millet", "common_name": "Ornamental Millet", "scientific_name": "Pennisetum glaucum ''Purple Majesty''", "category": "flower", "subcategory": "ornamental-grass", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start seeds indoors 4–6 weeks before last frost; transplant after soil has warmed thoroughly."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Start seeds indoors 4–6 weeks before last frost at 70–75°F; transplant after frost danger passes into full sun and fertile, well-drained soil — warm soil is essential for strong establishment. Grown as an annual for its striking deep burgundy-purple foliage and the large, cylindrical flower/grain heads that arch gracefully under their own weight in late summer. An excellent anchor plant in tropical-style or mixed annual borders, and the dried seed heads are useful in arrangements. Highly attractive to birds in fall — leave some plants intact for wildlife value.", "sources": ["general horticultural reference"]}')
