INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('salpiglossis','Painted Tongue','Salpiglossis sinuata','flower','annual',14,21,60,70,60,80,'transplant','indoor-start','cool','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost and transplant 2–3 weeks before last frost as plants tolerate light frost.',2,11,9,12,18,24,9,12,'full','moderate','Sow seeds in the dark (cover lightly and keep the tray in darkness) at 60–70°F; darkness improves germination for salpiglossis. Plant in fertile, well-drained soil in full sun; the petunia-like flowers with intricate veining in yellow, red, purple, maroon, and bicolor thrive in cool weather. Provide light support with twiggy stakes since plants can flop in wind; pinch tips once for bushier plants. Plants decline in summer heat — treat them as a spring and fall flower in warm climates or plant where afternoon shade moderates temperatures.','["general horticultural reference"]','{"slug": "salpiglossis", "common_name": "Painted Tongue", "scientific_name": "Salpiglossis sinuata", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost and transplant 2–3 weeks before last frost as plants tolerate light frost."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds in the dark (cover lightly and keep the tray in darkness) at 60–70°F; darkness improves germination for salpiglossis. Plant in fertile, well-drained soil in full sun; the petunia-like flowers with intricate veining in yellow, red, purple, maroon, and bicolor thrive in cool weather. Provide light support with twiggy stakes since plants can flop in wind; pinch tips once for bushier plants. Plants decline in summer heat — treat them as a spring and fall flower in warm climates or plant where afternoon shade moderates temperatures.", "sources": ["general horticultural reference"]}')
