INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('pansy','Pansy','Viola × wittrockiana','flower','annual',10,14,65,70,60,80,'transplant','indoor-start','cool','half-hardy','last_frost',-14,-12,'Start indoors 12–14 weeks before last frost for spring planting, or start in late summer for fall transplanting. Plants tolerate hard frost once established.',3,10,6,10,6,12,6,10,'full','moderate','Sow seed 1/8 in deep in a moist starting mix; cover the tray with dark plastic as darkness aids germination. Transplant outdoors several weeks before the last frost, as cool weather brings out the richest colors and most abundant bloom. Deadhead spent flowers regularly to prevent seed set, which stops flowering. Plants decline as summer heat arrives; remove and replace with heat-tolerant annuals.','["general horticultural reference"]','{"slug": "pansy", "common_name": "Pansy", "scientific_name": "Viola × wittrockiana", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 70}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -14, "max": -12}, "note": "Start indoors 12–14 weeks before last frost for spring planting, or start in late summer for fall transplanting. Plants tolerate hard frost once established."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 6, "max": 10}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/8 in deep in a moist starting mix; cover the tray with dark plastic as darkness aids germination. Transplant outdoors several weeks before the last frost, as cool weather brings out the richest colors and most abundant bloom. Deadhead spent flowers regularly to prevent seed set, which stops flowering. Plants decline as summer heat arrives; remove and replace with heat-tolerant annuals.", "sources": ["general horticultural reference"]}')
