  VALUES ('pasque-flower','Pasque Flower','Pulsatilla vulgaris','flower','perennial',21,42,55,65,270,365,'seed','direct','perennial','hardy','fall',-8,-4,'Sow fresh seed in fall; sap and foliage can irritate skin — handle with gloves and avoid contact with eyes.',4,8,12,18,8,12,12,18,'full','low','Sow fresh seed in fall directly in a sunny, gravelly, or rocky, very well-drained site; pasque flower germinates best from fresh seed with natural cold stratification and is slow to establish but extremely long-lived once settled. Silky, nodding purple, lavender, or white flowers emerge in early spring from the fuzzy, hairy foliage and are followed by fluffy, ornamental seedheads similar to clematis. Perfectly drained, lean, alkaline or neutral soil is essential — clay or continuously wet conditions are fatal. Resents transplanting; sow in situ or plant container-grown specimens when small.','["general horticultural reference"]','{"slug": "pasque-flower", "common_name": "Pasque Flower", "scientific_name": "Pulsatilla vulgaris", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow fresh seed in fall; sap and foliage can irritate skin — handle with gloves and avoid contact with eyes."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 8, "max": 12}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow fresh seed in fall directly in a sunny, gravelly, or rocky, very well-drained site; pasque flower germinates best from fresh seed with natural cold stratification and is slow to establish but extremely long-lived once settled. Silky, nodding purple, lavender, or white flowers emerge in early spring from the fuzzy, hairy foliage and are followed by fluffy, ornamental seedheads similar to clematis. Perfectly drained, lean, alkaline or neutral soil is essential — clay or continuously wet conditions are fatal. Resents transplanting; sow in situ or plant container-grown specimens when small.", "sources": ["general horticultural reference"]}')
