INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('pentas','Pentas','Pentas lanceolata','flower','annual',7,14,70,80,60,80,'transplant','indoor-start','warm','tender','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; transplant after all frost danger has passed and soil has warmed.',2,11,12,18,12,24,12,18,'full','moderate','Surface-sow tiny seeds on moist fine-textured mix and provide light at 70–80°F; germination occurs within 7–14 days. Pentas is one of the best butterfly and hummingbird plants for hot, humid gardens, blooming continuously from transplant to frost without deadheading. Plant in full sun in well-drained, fertile soil and fertilize monthly to sustain the heavy flower production. Shear plants back by one-third in midsummer if they become leggy; they recover quickly in heat and resume flowering within 2–3 weeks.','["general horticultural reference"]','{"slug": "pentas", "common_name": "Pentas", "scientific_name": "Pentas lanceolata", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 80}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; transplant after all frost danger has passed and soil has warmed."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Surface-sow tiny seeds on moist fine-textured mix and provide light at 70–80°F; germination occurs within 7–14 days. Pentas is one of the best butterfly and hummingbird plants for hot, humid gardens, blooming continuously from transplant to frost without deadheading. Plant in full sun in well-drained, fertile soil and fertilize monthly to sustain the heavy flower production. Shear plants back by one-third in midsummer if they become leggy; they recover quickly in heat and resume flowering within 2–3 weeks.", "sources": ["general horticultural reference"]}')
