  VALUES ('peony','Peony','Paeonia lactiflora','flower','perennial',NULL,NULL,NULL,NULL,730,1095,'transplant','division','perennial','hardy','fall',-6,-4,'Plant bare-root divisions in fall 4–6 weeks before the ground freezes; eyes no deeper than 1–2 in below soil surface.',3,8,36,48,24,36,36,48,'full','moderate','Plant roots with the pink eyes no more than 1–2 in below the soil surface — planting too deeply is the most common reason peonies fail to bloom. Peonies require 6 weeks of temperatures below 40°F to set flower buds, so they need cold winters and are not suited to zones 9+. Expect minimal bloom the first 1–2 years as the plant establishes; mature plants can live 50+ years with little care. Cut foliage to the ground in fall to remove potential disease inoculum.','["general horticultural reference"]','{"slug": "peony", "common_name": "Peony", "scientific_name": "Paeonia lactiflora", "category": "flower", "subcategory": "perennial", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Plant bare-root divisions in fall 4–6 weeks before the ground freezes; eyes no deeper than 1–2 in below soil surface."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 36, "max": 48}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 36, "max": 48}, "sun": "full", "water": "moderate", "directions": "Plant roots with the pink eyes no more than 1–2 in below the soil surface — planting too deeply is the most common reason peonies fail to bloom. Peonies require 6 weeks of temperatures below 40°F to set flower buds, so they need cold winters and are not suited to zones 9+. Expect minimal bloom the first 1–2 years as the plant establishes; mature plants can live 50+ years with little care. Cut foliage to the ground in fall to remove potential disease inoculum.", "sources": ["general horticultural reference"]}')
