  VALUES ('perennial-salvia','Perennial Salvia','Salvia nemorosa','flower','perennial',14,21,60,70,90,120,'transplant','division','perennial','hardy','spring',0,4,'Plant in spring after frost danger passes in well-drained soil; established plants are drought-tolerant.',4,9,18,24,18,36,18,24,'full','low','Plant in well-drained soil — perennial salvia is exceptionally heat- and drought-tolerant once established and will rot in soggy conditions. Shear plants back by one-third to one-half after the first flush of deep violet-blue spikes fades to trigger a strong second (and sometimes third) bloom. The aromatic foliage deters deer and rabbits, making it a reliable choice for wildlife-challenged gardens. Divide clumps every 3–4 years in early spring to keep them vigorous.','["general horticultural reference"]','{"slug": "perennial-salvia", "common_name": "Perennial Salvia", "scientific_name": "Salvia nemorosa", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring after frost danger passes in well-drained soil; established plants are drought-tolerant."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Plant in well-drained soil — perennial salvia is exceptionally heat- and drought-tolerant once established and will rot in soggy conditions. Shear plants back by one-third to one-half after the first flush of deep violet-blue spikes fades to trigger a strong second (and sometimes third) bloom. The aromatic foliage deters deer and rabbits, making it a reliable choice for wildlife-challenged gardens. Divide clumps every 3–4 years in early spring to keep them vigorous.", "sources": ["general horticultural reference"]}')
