INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('pincushion-flower','Pincushion Flower','Scabiosa atropurpurea','flower','annual',10,14,60,70,70,90,'transplant','indoor-start','cool','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant 2 weeks before last frost as plants tolerate light frost.',2,11,9,12,18,30,9,12,'full','moderate','Sow seeds 1/8 in deep in a well-drained mix; germination is reliable at 60–70°F and seedlings grow quickly. Plant in full sun in well-drained, slightly alkaline soil — scabiosa performs best in cool to moderate temperatures and fades in intense summer heat. Cut flowers frequently to encourage continuous bloom from early summer until fall; flowers are excellent for cutting with long, wiry stems and last 7–10 days in a vase. In zones 7–10 try sowing in fall for earlier spring bloom before heat sets in.','["general horticultural reference"]','{"slug": "pincushion-flower", "common_name": "Pincushion Flower", "scientific_name": "Scabiosa atropurpurea", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant 2 weeks before last frost as plants tolerate light frost."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/8 in deep in a well-drained mix; germination is reliable at 60–70°F and seedlings grow quickly. Plant in full sun in well-drained, slightly alkaline soil — scabiosa performs best in cool to moderate temperatures and fades in intense summer heat. Cut flowers frequently to encourage continuous bloom from early summer until fall; flowers are excellent for cutting with long, wiry stems and last 7–10 days in a vase. In zones 7–10 try sowing in fall for earlier spring bloom before heat sets in.", "sources": ["general horticultural reference"]}')
