INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('scabiosa-annual','Pincushion Flower (Annual)','Scabiosa atropurpurea','flower','annual',10,15,60,70,80,100,'seed','indoor-start','cool','half-hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; transplant after frost danger has passed into a sunny, alkaline-friendly site.',2,11,9,12,24,36,9,12,'full','low','Start seeds indoors 6–8 weeks before last frost, sowing 1/4 in deep in a light germination mix; transplant outdoors after frost into well-drained, slightly alkaline or neutral soil. The domed, pincushion flowers in rich maroon, lavender, white, pink, and burgundy are magnets for butterflies and superb for cutting. Deadhead consistently to prevent self-seeding and extend the long bloom period from early summer through frost. Avoid rich, wet soils — scabiosa thrives in moderately lean conditions and is drought-tolerant once established.','["general horticultural reference"]','{"slug": "scabiosa-annual", "common_name": "Pincushion Flower (Annual)", "scientific_name": "Scabiosa atropurpurea", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 15}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 80, "max": 100}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; transplant after frost danger has passed into a sunny, alkaline-friendly site."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "low", "directions": "Start seeds indoors 6–8 weeks before last frost, sowing 1/4 in deep in a light germination mix; transplant outdoors after frost into well-drained, slightly alkaline or neutral soil. The domed, pincushion flowers in rich maroon, lavender, white, pink, and burgundy are magnets for butterflies and superb for cutting. Deadhead consistently to prevent self-seeding and extend the long bloom period from early summer through frost. Avoid rich, wet soils — scabiosa thrives in moderately lean conditions and is drought-tolerant once established.", "sources": ["general horticultural reference"]}')
