INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('muhly-grass','Pink Muhly Grass','Muhlenbergia capillaris','flower','ornamental-grass',14,21,65,75,180,270,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions or container plants in spring; avoid fall planting in zones 6–7 as plants need a full season to establish before winter.',5,10,24,36,30,48,24,36,'full','low','Plant in full sun and well-drained, lean to average soil; muhly grass is tolerant of sandy soil, heat, humidity, and drought once established and is an outstanding choice for hot, dry southern landscapes. The main attraction is the spectacular cloud of airy, rose-pink flower plumes in September–October that transform the planting into something otherworldly when backlit by low autumn sun. Cut back to 4–6 in in late winter before new growth begins; avoid heavy organic mulching which can cause crown rot in humid climates. Divide every 4–5 years in spring to rejuvenate large clumps.','["general horticultural reference"]','{"slug": "muhly-grass", "common_name": "Pink Muhly Grass", "scientific_name": "Muhlenbergia capillaris", "category": "flower", "subcategory": "ornamental-grass", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 180, "max": 270}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions or container plants in spring; avoid fall planting in zones 6–7 as plants need a full season to establish before winter."}, "usda_zones": {"min": 5, "max": 10}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 30, "max": 48}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Plant in full sun and well-drained, lean to average soil; muhly grass is tolerant of sandy soil, heat, humidity, and drought once established and is an outstanding choice for hot, dry southern landscapes. The main attraction is the spectacular cloud of airy, rose-pink flower plumes in September–October that transform the planting into something otherworldly when backlit by low autumn sun. Cut back to 4–6 in in late winter before new growth begins; avoid heavy organic mulching which can cause crown rot in humid climates. Divide every 4–5 years in spring to rejuvenate large clumps.", "sources": ["general horticultural reference"]}')
