INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('primrose-polyanthus','Polyanthus Primrose','Primula x polyantha','flower','perennial',14,28,55,65,180,270,'transplant','indoor-start','perennial','hardy','last_frost',-16,-14,'Start seeds indoors 14–16 weeks before last frost after surface-sowing and cold-stratifying at 35–40°F for 3–4 weeks.',3,8,9,12,6,10,9,12,'partial','moderate','Surface-sow tiny seeds on moist, sterile mix and cold-stratify at 35–40°F for 3–4 weeks to break dormancy, then move to 65°F for germination. Grow on at cool temperatures (55–60°F) since heat causes etiolation; transplant into partial shade in humus-rich, moist, well-drained soil in early spring. Primroses bloom best in cool, moist conditions — they are outstanding spring plants but typically go dormant in summer heat. Divide crowded clumps after bloom in spring and replant divisions in refreshed, compost-amended soil.','["general horticultural reference"]','{"slug": "primrose-polyanthus", "common_name": "Polyanthus Primrose", "scientific_name": "Primula x polyantha", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 180, "max": 270}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -16, "max": -14}, "note": "Start seeds indoors 14–16 weeks before last frost after surface-sowing and cold-stratifying at 35–40°F for 3–4 weeks."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 6, "max": 10}, "spread_in": {"min": 9, "max": 12}, "sun": "partial", "water": "moderate", "directions": "Surface-sow tiny seeds on moist, sterile mix and cold-stratify at 35–40°F for 3–4 weeks to break dormancy, then move to 65°F for germination. Grow on at cool temperatures (55–60°F) since heat causes etiolation; transplant into partial shade in humus-rich, moist, well-drained soil in early spring. Primroses bloom best in cool, moist conditions — they are outstanding spring plants but typically go dormant in summer heat. Divide crowded clumps after bloom in spring and replant divisions in refreshed, compost-amended soil.", "sources": ["general horticultural reference"]}')
