  VALUES ('prairie-dropseed','Prairie Dropseed','Sporobolus heterolepis','flower','ornamental-grass',21,42,65,75,270,365,'seed','direct','perennial','hardy','last_frost',0,4,'Direct sow after last frost; very slow to establish from seed — divisions or plugs reach ornamental size much faster.',3,9,18,24,18,24,18,30,'full','low','Sow seeds in full sun in lean, well-drained, sandy or rocky soil after last frost; prairie dropseed is a slow-growing native that takes 2–3 years from seed to develop into an ornamental clump. The extremely fine-textured, emerald-green foliage forms a perfect arching fountain shape, and open, airy flower panicles in late summer emit a distinctive fragrance of warm popcorn or cilantro. Fall color is a beautiful tawny orange-gold and the foliage persists attractively through winter. Once established it is extremely drought- and heat-tolerant and virtually maintenance-free.','["general horticultural reference"]','{"slug": "prairie-dropseed", "common_name": "Prairie Dropseed", "scientific_name": "Sporobolus heterolepis", "category": "flower", "subcategory": "ornamental-grass", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Direct sow after last frost; very slow to establish from seed — divisions or plugs reach ornamental size much faster."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "low", "directions": "Sow seeds in full sun in lean, well-drained, sandy or rocky soil after last frost; prairie dropseed is a slow-growing native that takes 2–3 years from seed to develop into an ornamental clump. The extremely fine-textured, emerald-green foliage forms a perfect arching fountain shape, and open, airy flower panicles in late summer emit a distinctive fragrance of warm popcorn or cilantro. Fall color is a beautiful tawny orange-gold and the foliage persists attractively through winter. Once established it is extremely drought- and heat-tolerant and virtually maintenance-free.", "sources": ["general horticultural reference"]}')
