  VALUES ('prairie-smoke','Prairie Smoke','Geum triflorum','flower','perennial',21,42,55,65,270,365,'seed','direct','perennial','hardy','fall',-8,-4,'Direct sow in fall for natural cold stratification; or start indoors in late winter with 8–10 weeks of cold moist stratification.',3,7,12,18,6,16,12,18,'full','low','Sow seeds in fall and allow winter cold to naturally stratify them, or cold-stratify indoors for 8–10 weeks before spring sowing; plant in lean, well-drained to dry soil in full sun. The nodding, burgundy-pink flowers in mid-spring are followed by the spectacular feathery, smoke-like seed plumes that give the plant its name and provide ornamental interest for weeks. Prairie smoke is a rugged, drought-tolerant native wildflower that thrives in rocky or sandy soils where more demanding plants struggle. It spreads slowly into a weed-suppressing groundcover in open, sunny areas.','["general horticultural reference"]','{"slug": "prairie-smoke", "common_name": "Prairie Smoke", "scientific_name": "Geum triflorum", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Direct sow in fall for natural cold stratification; or start indoors in late winter with 8–10 weeks of cold moist stratification."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 6, "max": 16}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seeds in fall and allow winter cold to naturally stratify them, or cold-stratify indoors for 8–10 weeks before spring sowing; plant in lean, well-drained to dry soil in full sun. The nodding, burgundy-pink flowers in mid-spring are followed by the spectacular feathery, smoke-like seed plumes that give the plant its name and provide ornamental interest for weeks. Prairie smoke is a rugged, drought-tolerant native wildflower that thrives in rocky or sandy soils where more demanding plants struggle. It spreads slowly into a weed-suppressing groundcover in open, sunny areas.", "sources": ["general horticultural reference"]}')
