INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('purple-coneflower','Purple Coneflower','Echinacea purpurea','flower','perennial',10,21,65,75,365,730,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost or direct sow in fall for natural cold stratification.',3,9,18,24,24,48,18,24,'full','low','Sow seeds 1/8 in deep; cold stratification for 4–8 weeks improves germination rates significantly. Transplant after last frost into well-drained soil — established plants tolerate drought well. Flowers typically appear in year 2 from seed; deadhead spent blooms to extend the season or leave seedheads for birds. Divide clumps every 3–4 years in spring to maintain vigor.','["general horticultural reference"]','{"slug": "purple-coneflower", "common_name": "Purple Coneflower", "scientific_name": "Echinacea purpurea", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost or direct sow in fall for natural cold stratification."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Sow seeds 1/8 in deep; cold stratification for 4–8 weeks improves germination rates significantly. Transplant after last frost into well-drained soil — established plants tolerate drought well. Flowers typically appear in year 2 from seed; deadhead spent blooms to extend the season or leave seedheads for birds. Divide clumps every 3–4 years in spring to maintain vigor.", "sources": ["general horticultural reference"]}')
