INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('purple-fountain-grass','Purple Fountain Grass','Pennisetum setaceum ''Rubrum''','flower','ornamental-grass',NULL,NULL,NULL,NULL,90,120,'transplant','transplant','warm','tender','last_frost',0,2,'Plant container-grown transplants after last frost; this cultivar does not come true from seed and is propagated by division.',9,11,24,36,36,48,24,36,'full','low','Plant after last frost in full sun and very well-drained soil; purple fountain grass is grown as an annual north of zone 9 for its arching burgundy-red foliage and showy, rose-tinged plumes from midsummer through frost. It thrives in heat and drought once established but requires consistent moisture the first few weeks after transplanting. In frost-free climates it is a perennial that can become invasive — avoid planting near natural areas and remove flower heads before seeds ripen. Bring container-grown specimens indoors before frost to overwinter as a houseplant in colder zones.','["general horticultural reference"]','{"slug": "purple-fountain-grass", "common_name": "Purple Fountain Grass", "scientific_name": "Pennisetum setaceum ''Rubrum''", "category": "flower", "subcategory": "ornamental-grass", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "transplant", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Plant container-grown transplants after last frost; this cultivar does not come true from seed and is propagated by division."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 48}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Plant after last frost in full sun and very well-drained soil; purple fountain grass is grown as an annual north of zone 9 for its arching burgundy-red foliage and showy, rose-tinged plumes from midsummer through frost. It thrives in heat and drought once established but requires consistent moisture the first few weeks after transplanting. In frost-free climates it is a perennial that can become invasive — avoid planting near natural areas and remove flower heads before seeds ripen. Bring container-grown specimens indoors before frost to overwinter as a houseplant in colder zones.", "sources": ["general horticultural reference"]}')
