INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ranunculus','Ranunculus','Ranunculus asiaticus','flower','bulb',NULL,NULL,NULL,NULL,90,120,'transplant','bulb','cool','half-hardy','fall',-6,-4,'In mild-winter climates (zones 8–10) plant corms in fall for late-winter/spring bloom; in cold climates start indoors and transplant after last frost.',8,11,6,9,12,24,6,9,'full','moderate','Soak corms in cool water for 4 hours before planting, then set them claw-side down about 2 in deep in well-drained, fertile soil. Ranunculus thrives in cool temperatures (45–65°F) and will decline when heat arrives, so timing is critical. In zones 9–10 plant October through January for blooms from February through May; provide afternoon shade in the warmest areas. After foliage yellows, allow corms to dry in situ or lift, cure, and store in a cool dry location for replanting.','["general horticultural reference"]','{"slug": "ranunculus", "common_name": "Ranunculus", "scientific_name": "Ranunculus asiaticus", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "bulb", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "In mild-winter climates (zones 8–10) plant corms in fall for late-winter/spring bloom; in cold climates start indoors and transplant after last frost."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 6, "max": 9}, "sun": "full", "water": "moderate", "directions": "Soak corms in cool water for 4 hours before planting, then set them claw-side down about 2 in deep in well-drained, fertile soil. Ranunculus thrives in cool temperatures (45–65°F) and will decline when heat arrives, so timing is critical. In zones 9–10 plant October through January for blooms from February through May; provide afternoon shade in the warmest areas. After foliage yellows, allow corms to dry in situ or lift, cure, and store in a cool dry location for replanting.", "sources": ["general horticultural reference"]}')
