  VALUES ('rattlesnake-master','Rattlesnake Master','Eryngium yuccifolium','flower','perennial',21,42,55,65,365,730,'seed','direct','perennial','hardy','fall',-8,-4,'Direct sow fresh seed in fall for natural cold stratification; transplants poorly due to deep taproot.',3,9,24,36,36,60,24,36,'full','low','Sow fresh seed in fall directly in a sunny prairie or meadow garden in lean, well-drained soil; rattlesnake master develops a deep taproot and resents being moved after establishment. The dramatic, yucca-like basal rosette of spiny blue-green leaves is topped by tall branched stems bearing small, spiny, globe-shaped white flower heads in midsummer that are highly attractive to native bees. It is extremely drought-tolerant and actually performs better in poor, sandy or rocky soil than in rich garden beds. The sculptural seedheads provide winter interest and are prized for dried arrangements.','["general horticultural reference"]','{"slug": "rattlesnake-master", "common_name": "Rattlesnake Master", "scientific_name": "Eryngium yuccifolium", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Direct sow fresh seed in fall for natural cold stratification; transplants poorly due to deep taproot."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Sow fresh seed in fall directly in a sunny prairie or meadow garden in lean, well-drained soil; rattlesnake master develops a deep taproot and resents being moved after establishment. The dramatic, yucca-like basal rosette of spiny blue-green leaves is topped by tall branched stems bearing small, spiny, globe-shaped white flower heads in midsummer that are highly attractive to native bees. It is extremely drought-tolerant and actually performs better in poor, sandy or rocky soil than in rich garden beds. The sculptural seedheads provide winter interest and are prized for dried arrangements.", "sources": ["general horticultural reference"]}')
