INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('kniphofia','Red Hot Poker','Kniphofia uvaria','flower','perennial',14,21,65,75,365,730,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; transplant after all frost danger has passed in spring.',5,9,18,24,24,48,18,24,'full','moderate','Sow seeds 1/8 in deep and maintain even moisture at 65–75°F until germination. Plant in full sun in well-drained soil — good drainage is critical, especially in winter, as plants rot in waterlogged conditions. The torch-like flower spikes transition from red or orange in bud to yellow as the florets open, creating a two-toned effect that attracts hummingbirds throughout summer and fall. In zones 5–6 tie the leaves together and mulch deeply around the crown before the first hard freeze to protect the growing point.','["general horticultural reference"]','{"slug": "kniphofia", "common_name": "Red Hot Poker", "scientific_name": "Kniphofia uvaria", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; transplant after all frost danger has passed in spring."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/8 in deep and maintain even moisture at 65–75°F until germination. Plant in full sun in well-drained soil — good drainage is critical, especially in winter, as plants rot in waterlogged conditions. The torch-like flower spikes transition from red or orange in bud to yellow as the florets open, creating a two-toned effect that attracts hummingbirds throughout summer and fall. In zones 5–6 tie the leaves together and mulch deeply around the crown before the first hard freeze to protect the growing point.", "sources": ["general horticultural reference"]}')
