  VALUES ('rose-campion','Rose Campion','Silene coronaria','flower','perennial',7,14,60,70,90,365,'seed','direct','perennial','hardy','last_frost',-2,2,'Direct sow in early spring around last frost date; plants may bloom the first fall from an early sowing or establish and bloom their second year.',4,8,12,18,18,30,12,18,'full','low','Sow seeds 1/8 in deep in well-drained soil; germination is fast and reliable. Plant in full sun in poor to average, very well-drained soil — rose campion thrives under dry, sunny conditions that would stress many perennials. The intensely magenta-crimson flowers glow against the woolly, silver-white felted stems and leaves, which are ornamental throughout the growing season. Individual plants are short-lived (2–3 years) but self-sow abundantly so colonies persist indefinitely; thin or transplant self-sown seedlings to prevent overcrowding.','["general horticultural reference"]','{"slug": "rose-campion", "common_name": "Rose Campion", "scientific_name": "Silene coronaria", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 365}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Direct sow in early spring around last frost date; plants may bloom the first fall from an early sowing or establish and bloom their second year."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seeds 1/8 in deep in well-drained soil; germination is fast and reliable. Plant in full sun in poor to average, very well-drained soil — rose campion thrives under dry, sunny conditions that would stress many perennials. The intensely magenta-crimson flowers glow against the woolly, silver-white felted stems and leaves, which are ornamental throughout the growing season. Individual plants are short-lived (2–3 years) but self-sow abundantly so colonies persist indefinitely; thin or transplant self-sown seedlings to prevent overcrowding.", "sources": ["general horticultural reference"]}')
