INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sea-holly','Sea Holly','Eryngium planum','flower','perennial',14,30,55,65,365,548,'seed','direct','perennial','hardy','last_frost',-4,-2,'Direct sow in early spring or fall; tap-rooted and resents transplanting — sow where plants will remain.',4,9,18,24,24,36,18,24,'full','low','Sow seeds directly in well-drained, even poor, sandy or gravelly soil; sea holly develops a deep taproot and strongly dislikes being transplanted after establishment. The metallic steel-blue stems, bracts, and thimble-shaped flower heads appear in midsummer and hold their color and structure well into fall. Drought-tolerant once established, sea holly declines in rich, moist soil — lean, infertile conditions produce the best blue coloration. Cut stems for fresh or dried arrangements before flowers fully open to preserve the vivid blue color.','["general horticultural reference"]','{"slug": "sea-holly", "common_name": "Sea Holly", "scientific_name": "Eryngium planum", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring or fall; tap-rooted and resents transplanting — sow where plants will remain."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Sow seeds directly in well-drained, even poor, sandy or gravelly soil; sea holly develops a deep taproot and strongly dislikes being transplanted after establishment. The metallic steel-blue stems, bracts, and thimble-shaped flower heads appear in midsummer and hold their color and structure well into fall. Drought-tolerant once established, sea holly declines in rich, moist soil — lean, infertile conditions produce the best blue coloration. Cut stems for fresh or dried arrangements before flowers fully open to preserve the vivid blue color.", "sources": ["general horticultural reference"]}')
