INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('shasta-daisy','Shasta Daisy','Leucanthemum x superbum','flower','perennial',10,21,60,70,120,365,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start seeds indoors 6–8 weeks before last frost; transplant after frost danger passes.',5,9,18,24,18,36,18,24,'full','moderate','Sow seeds on the surface of moist potting mix and keep at 60–70°F for germination; transplant after the last frost into well-drained soil. Shasta daisies often bloom lightly the first year from seed and fully the second year — named cultivars from division or plugs bloom more reliably in year 1. Deadhead spent flowers to encourage repeat blooming from midsummer into fall. Divide clumps every 2–3 years in spring, discarding the woody center and replanting vigorous outer sections.','["general horticultural reference"]','{"slug": "shasta-daisy", "common_name": "Shasta Daisy", "scientific_name": "Leucanthemum x superbum", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 120, "max": 365}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start seeds indoors 6–8 weeks before last frost; transplant after frost danger passes."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds on the surface of moist potting mix and keep at 60–70°F for germination; transplant after the last frost into well-drained soil. Shasta daisies often bloom lightly the first year from seed and fully the second year — named cultivars from division or plugs bloom more reliably in year 1. Deadhead spent flowers to encourage repeat blooming from midsummer into fall. Divide clumps every 2–3 years in spring, discarding the woody center and replanting vigorous outer sections.", "sources": ["general horticultural reference"]}')
