INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('brunnera','Siberian Bugloss','Brunnera macrophylla','flower','perennial',21,42,55,65,270,365,'seed','division','perennial','hardy','spring',0,4,'Plant divisions in spring as soon as plants can be purchased; also self-seeds moderately in moist, shaded sites.',3,8,18,24,12,18,18,24,'shade','moderate','Plant in partial to full shade in cool, humus-rich, moist but well-drained soil; brunnera is one of the best foliage plants for shade, particularly the silver-variegated cultivars like ''Jack Frost.'' Delicate sprays of forget-me-not blue flowers appear in early to mid-spring above the large, heart-shaped leaves. In hot or dry conditions the leaves may scorch — consistent moisture and afternoon shade are essential in warmer climates. Divide clumps every 4–5 years in early spring; variegated cultivars must be divided rather than grown from seed to maintain their markings.','["general horticultural reference"]','{"slug": "brunnera", "common_name": "Siberian Bugloss", "scientific_name": "Brunnera macrophylla", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "seed", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in spring as soon as plants can be purchased; also self-seeds moderately in moist, shaded sites."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 18, "max": 24}, "sun": "shade", "water": "moderate", "directions": "Plant in partial to full shade in cool, humus-rich, moist but well-drained soil; brunnera is one of the best foliage plants for shade, particularly the silver-variegated cultivars like ''Jack Frost.'' Delicate sprays of forget-me-not blue flowers appear in early to mid-spring above the large, heart-shaped leaves. In hot or dry conditions the leaves may scorch — consistent moisture and afternoon shade are essential in warmer climates. Divide clumps every 4–5 years in early spring; variegated cultivars must be divided rather than grown from seed to maintain their markings.", "sources": ["general horticultural reference"]}')
