  VALUES ('siberian-iris','Siberian Iris','Iris sibirica','flower','perennial',NULL,NULL,NULL,NULL,270,365,'transplant','division','perennial','hardy','spring',0,4,'Plant divisions in early spring as growth begins, or in late summer after flowering; set rhizomes just below soil surface.',3,9,18,24,24,48,18,30,'full','moderate','Plant rhizomes just 1–2 in below the soil surface in moisture-retentive, slightly acidic soil; unlike bearded iris, Siberian iris prefers consistently moist conditions and tolerates wet spots. Graceful, narrow foliage forms attractive clumps all season, topped by elegant blue, purple, or white flowers in early summer. Siberian iris are very long-lived and rarely need dividing — only do so when the center of the clump dies out or blooming diminishes, typically every 5–8 years. Division is best done immediately after flowering or in early fall; replant promptly and water well.','["general horticultural reference"]','{"slug": "siberian-iris", "common_name": "Siberian Iris", "scientific_name": "Iris sibirica", "category": "flower", "subcategory": "perennial", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in early spring as growth begins, or in late summer after flowering; set rhizomes just below soil surface."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "moderate", "directions": "Plant rhizomes just 1–2 in below the soil surface in moisture-retentive, slightly acidic soil; unlike bearded iris, Siberian iris prefers consistently moist conditions and tolerates wet spots. Graceful, narrow foliage forms attractive clumps all season, topped by elegant blue, purple, or white flowers in early summer. Siberian iris are very long-lived and rarely need dividing — only do so when the center of the clump dies out or blooming diminishes, typically every 5–8 years. Division is best done immediately after flowering or in early fall; replant promptly and water well.", "sources": ["general horticultural reference"]}')
