INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('snake-head-fritillary','Snake''s Head Fritillary','Fritillaria meleagris','flower','bulb',NULL,NULL,NULL,NULL,150,180,'transplant','bulb','perennial','hardy','fall',-8,-4,'Plant bulbs in early fall, 4 in deep, in moist but well-drained soil; ideal for naturalizing in damp meadows.',3,8,3,4,10,15,3,4,'full','moderate','Plant bulbs in early fall, 4 in deep and 3–4 in apart, in organically rich, moisture-retentive but not waterlogged soil; perfect for damp meadow or pond-edge plantings. The nodding, checkerboard-patterned bells in deep purple, white, or pink appear in mid-spring and are among the most intricately patterned flowers in the spring garden. Naturalizes freely in damp grassland — avoid mowing until foliage has died back completely in early summer. Once established the bulbs multiply steadily; divide congested clumps in early fall.','["general horticultural reference"]','{"slug": "snake-head-fritillary", "common_name": "Snake''s Head Fritillary", "scientific_name": "Fritillaria meleagris", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 150, "max": 180}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant bulbs in early fall, 4 in deep, in moist but well-drained soil; ideal for naturalizing in damp meadows."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 3, "max": 4}, "height_in": {"min": 10, "max": 15}, "spread_in": {"min": 3, "max": 4}, "sun": "full", "water": "moderate", "directions": "Plant bulbs in early fall, 4 in deep and 3–4 in apart, in organically rich, moisture-retentive but not waterlogged soil; perfect for damp meadow or pond-edge plantings. The nodding, checkerboard-patterned bells in deep purple, white, or pink appear in mid-spring and are among the most intricately patterned flowers in the spring garden. Naturalizes freely in damp grassland — avoid mowing until foliage has died back completely in early summer. Once established the bulbs multiply steadily; divide congested clumps in early fall.", "sources": ["general horticultural reference"]}')
