  VALUES ('snapdragon','Snapdragon','Antirrhinum majus','flower','annual',10,14,65,70,75,100,'transplant','indoor-start','cool','half-hardy','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant 2–4 weeks before last frost as plants tolerate light frost.',3,10,6,12,8,36,6,12,'full','moderate','Press seed onto the surface of moist starting mix and do not cover — seed needs light to germinate. Pinch seedlings once to promote multiple spikes. Transplant to the garden a few weeks before the last frost, as snapdragons thrive in cool conditions and can tolerate a light freeze. After the primary spike blooms, cut it off to encourage a second flush from side branches.','["general horticultural reference"]','{"slug": "snapdragon", "common_name": "Snapdragon", "scientific_name": "Antirrhinum majus", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 70}, "days_to_maturity": {"min": 75, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant 2–4 weeks before last frost as plants tolerate light frost."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 8, "max": 36}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Press seed onto the surface of moist starting mix and do not cover — seed needs light to germinate. Pinch seedlings once to promote multiple spikes. Transplant to the garden a few weeks before the last frost, as snapdragons thrive in cool conditions and can tolerate a light freeze. After the primary spike blooms, cut it off to encourage a second flush from side branches.", "sources": ["general horticultural reference"]}')
