INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('snowdrop','Snowdrop','Galanthus nivalis','flower','bulb',NULL,NULL,NULL,NULL,90,120,'transplant','bulb','perennial','hardy','fall',-10,-6,'Plant small bulbs in fall, 3 in deep; alternatively plant ''in the green'' (just after bloom) for better establishment.',3,7,2,3,3,6,2,3,'partial','moderate','Plant bulbs 3 in deep in moisture-retentive, humus-rich soil under deciduous trees or in a shaded border; snowdrops are one of the first bulbs to bloom, often in January or February. They establish most successfully when transplanted ''in the green'' — lifted and divided just after blooming while foliage is still active. Clumps multiply steadily and benefit from division every 3–4 years right after flowering to prevent overcrowding. Allow foliage to die back naturally; avoid mowing naturalised areas until leaves have fully yellowed.','["general horticultural reference"]','{"slug": "snowdrop", "common_name": "Snowdrop", "scientific_name": "Galanthus nivalis", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -10, "max": -6}, "note": "Plant small bulbs in fall, 3 in deep; alternatively plant ''in the green'' (just after bloom) for better establishment."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 2, "max": 3}, "height_in": {"min": 3, "max": 6}, "spread_in": {"min": 2, "max": 3}, "sun": "partial", "water": "moderate", "directions": "Plant bulbs 3 in deep in moisture-retentive, humus-rich soil under deciduous trees or in a shaded border; snowdrops are one of the first bulbs to bloom, often in January or February. They establish most successfully when transplanted ''in the green'' — lifted and divided just after blooming while foliage is still active. Clumps multiply steadily and benefit from division every 3–4 years right after flowering to prevent overcrowding. Allow foliage to die back naturally; avoid mowing naturalised areas until leaves have fully yellowed.", "sources": ["general horticultural reference"]}')
