  VALUES ('spiderwort','Spiderwort','Tradescantia virginiana','flower','perennial',14,21,60,70,365,730,'seed','direct','perennial','hardy','last_frost',-2,2,'Direct sow in early spring around last frost date; cold stratification for 4 weeks improves germination of seed.',4,9,18,24,18,36,18,24,'partial','moderate','Cold-stratify seeds for 4 weeks before sowing; established divisions establish more reliably than seed-grown plants and can be done in spring or fall. Plant in partial shade to full sun in moist, average to rich soil; plants tolerate wet conditions and make excellent rain garden plants. The three-petaled flowers in purple, blue, pink, or white open only for a single morning but are produced in rapid succession over many weeks. Shear the entire plant to 8 in after the main bloom flush to stimulate fresh foliage and a second round of flowers in fall.','["general horticultural reference"]','{"slug": "spiderwort", "common_name": "Spiderwort", "scientific_name": "Tradescantia virginiana", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Direct sow in early spring around last frost date; cold stratification for 4 weeks improves germination of seed."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "partial", "water": "moderate", "directions": "Cold-stratify seeds for 4 weeks before sowing; established divisions establish more reliably than seed-grown plants and can be done in spring or fall. Plant in partial shade to full sun in moist, average to rich soil; plants tolerate wet conditions and make excellent rain garden plants. The three-petaled flowers in purple, blue, pink, or white open only for a single morning but are produced in rapid succession over many weeks. Shear the entire plant to 8 in after the main bloom flush to stimulate fresh foliage and a second round of flowers in fall.", "sources": ["general horticultural reference"]}')
