  VALUES ('statice','Statice','Limonium sinuatum','flower','annual',10,21,65,72,90,120,'transplant','indoor-start','cool','half-hardy','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant 2–3 weeks before last frost as plants tolerate mild frost.',3,10,12,15,18,30,10,14,'full','low','Sow seed 1/8 in deep in moist starting mix; seeds come in a papery casing and germination is slow. Statice prefers cool conditions early in the season. Harvest flower stems for drying when 75% of the florets on each branch have opened. The papery calyces — which hold their color dried — are the ornamental part; the true petals are tiny and brief.','["general horticultural reference"]','{"slug": "statice", "common_name": "Statice", "scientific_name": "Limonium sinuatum", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 72}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant 2–3 weeks before last frost as plants tolerate mild frost."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 12, "max": 15}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 10, "max": 14}, "sun": "full", "water": "low", "directions": "Sow seed 1/8 in deep in moist starting mix; seeds come in a papery casing and germination is slow. Statice prefers cool conditions early in the season. Harvest flower stems for drying when 75% of the florets on each branch have opened. The papery calyces — which hold their color dried — are the ornamental part; the true petals are tiny and brief.", "sources": ["general horticultural reference"]}')
