INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('stock','Stock','Matthiola incana','flower','annual',7,14,60,65,60,90,'transplant','indoor-start','cool','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant 2–4 weeks before last frost as young plants tolerate light frost.',3,9,8,12,12,30,8,12,'full','moderate','Sow seed on the surface of moist starting mix — light aids germination, so cover with only the thinnest layer of vermiculite if at all. Stock thrives in cool weather (55–65°F nights) and the fragrance is intensified by cool temperatures. Transplant to the garden in early spring; plants begin to decline when daytime temperatures consistently exceed 80°F. Cut flowers when one-third of the buds on the spike are open for the longest vase life.','["general horticultural reference"]','{"slug": "stock", "common_name": "Stock", "scientific_name": "Matthiola incana", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 65}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant 2–4 weeks before last frost as young plants tolerate light frost."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 12, "max": 30}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seed on the surface of moist starting mix — light aids germination, so cover with only the thinnest layer of vermiculite if at all. Stock thrives in cool weather (55–65°F nights) and the fragrance is intensified by cool temperatures. Transplant to the garden in early spring; plants begin to decline when daytime temperatures consistently exceed 80°F. Cut flowers when one-third of the buds on the spike are open for the longest vase life.", "sources": ["general horticultural reference"]}')
