  VALUES ('stokes-aster','Stokes'' Aster','Stokesia laevis','flower','perennial',14,28,60,70,365,730,'seed','indoor-start','perennial','hardy','last_frost',-10,-8,'Start seeds indoors 8–10 weeks before last frost after cold-stratifying for 4–6 weeks; transplant after last frost.',5,9,12,18,12,24,12,18,'full','moderate','Cold-stratify seeds in moist medium at 35–40°F for 4–6 weeks before sowing indoors; germination is slow but improved by stratification. Plant in full sun in well-drained, sandy or loamy soil; Stokes'' aster is native to the American Southeast and tolerates heat and humidity well but dislikes wet winter conditions. The large, cornflower-like blooms in blue, lavender, or white appear from early summer to fall and are excellent for cutting. Divide clumps every 3–4 years in spring to maintain vigor; plants spread slowly and are well-behaved in the border.','["general horticultural reference"]','{"slug": "stokes-aster", "common_name": "Stokes'' Aster", "scientific_name": "Stokesia laevis", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start seeds indoors 8–10 weeks before last frost after cold-stratifying for 4–6 weeks; transplant after last frost."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Cold-stratify seeds in moist medium at 35–40°F for 4–6 weeks before sowing indoors; germination is slow but improved by stratification. Plant in full sun in well-drained, sandy or loamy soil; Stokes'' aster is native to the American Southeast and tolerates heat and humidity well but dislikes wet winter conditions. The large, cornflower-like blooms in blue, lavender, or white appear from early summer to fall and are excellent for cutting. Divide clumps every 3–4 years in spring to maintain vigor; plants spread slowly and are well-behaved in the border.", "sources": ["general horticultural reference"]}')
