  VALUES ('strawflower','Strawflower','Xerochrysum bracteatum','flower','annual',5,10,70,75,65,90,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant after all frost risk has passed.',3,11,9,12,18,36,8,12,'full','low','Sow seed on the surface of moist starting mix and press lightly — light aids germination, so barely cover seed. Strawflowers tolerate drought and poor soils remarkably well. For drying, harvest stems when the central button of each head is still closed, before the outer bracts fully open; they will continue to open as they dry. Deadhead garden plants regularly to maintain continuous bloom.','["general horticultural reference"]','{"slug": "strawflower", "common_name": "Strawflower", "scientific_name": "Xerochrysum bracteatum", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 65, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant after all frost risk has passed."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "low", "directions": "Sow seed on the surface of moist starting mix and press lightly — light aids germination, so barely cover seed. Strawflowers tolerate drought and poor soils remarkably well. For drying, harvest stems when the central button of each head is still closed, before the outer bracts fully open; they will continue to open as they dry. Deadhead garden plants regularly to maintain continuous bloom.", "sources": ["general horticultural reference"]}')
