  VALUES ('sweet-alyssum','Sweet Alyssum','Lobularia maritima','flower','annual',5,10,60,70,40,60,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; alyssum tolerates light frost and prefers cool weather.',3,11,6,10,3,8,8,12,'full','moderate','Scatter seed on the soil surface and press gently — light aids germination; just barely cover if needed to prevent the seed from blowing away. Sweet alyssum may slow or stop blooming in peak summer heat; shear plants back by half and they will rebound strongly when temperatures cool in early fall. The honey-scented flowers attract beneficial insects throughout the season.','["general horticultural reference"]','{"slug": "sweet-alyssum", "common_name": "Sweet Alyssum", "scientific_name": "Lobularia maritima", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 40, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; alyssum tolerates light frost and prefers cool weather."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 10}, "height_in": {"min": 3, "max": 8}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "moderate", "directions": "Scatter seed on the soil surface and press gently — light aids germination; just barely cover if needed to prevent the seed from blowing away. Sweet alyssum may slow or stop blooming in peak summer heat; shear plants back by half and they will rebound strongly when temperatures cool in early fall. The honey-scented flowers attract beneficial insects throughout the season.", "sources": ["general horticultural reference"]}')
