INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sweet-sultan','Sweet Sultan','Centaurea moschata','flower','annual',7,14,55,65,65,80,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow in early spring 2–4 weeks before last frost; does not transplant well due to taproot.',2,11,9,12,18,30,9,12,'full','low','Sow seeds directly in a sunny, well-drained location in early spring; thin to 9–12 in apart as seedlings emerge. The fragrant, fringed, powder-puff flowers in shades of pink, purple, yellow, and white are excellent for cutting, with a pleasant, musky sweet scent. Plants prefer cool weather and will begin to decline as summer heat intensifies — make a second sowing in late summer for fall bloom in warm climates. Successive sowings every 3–4 weeks in spring extend the flowering season through early summer.','["general horticultural reference"]','{"slug": "sweet-sultan", "common_name": "Sweet Sultan", "scientific_name": "Centaurea moschata", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 65, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring 2–4 weeks before last frost; does not transplant well due to taproot."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "low", "directions": "Sow seeds directly in a sunny, well-drained location in early spring; thin to 9–12 in apart as seedlings emerge. The fragrant, fringed, powder-puff flowers in shades of pink, purple, yellow, and white are excellent for cutting, with a pleasant, musky sweet scent. Plants prefer cool weather and will begin to decline as summer heat intensifies — make a second sowing in late summer for fall bloom in warm climates. Successive sowings every 3–4 weeks in spring extend the flowering season through early summer.", "sources": ["general horticultural reference"]}')
