  VALUES ('sweet-william','Sweet William','Dianthus barbatus','flower','annual',7,14,65,70,60,80,'transplant','indoor-start','cool','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant can go out 2–4 weeks before last frost as plants are frost-tolerant.',3,9,9,12,12,24,9,12,'full','moderate','Sow seeds 1/8 in deep in well-drained germination mix; germination is fast and reliable at 65–70°F. Plant in full sun in well-drained, neutral to slightly alkaline soil; sweet William is technically a biennial that flowers in its second year, but modern annual varieties bloom the first year from an early indoor start. The domed, fragrant flower clusters in vivid shades of red, pink, white, and bicolor appear in late spring and early summer. Deadhead spent clusters promptly to extend the blooming period; plants self-sow readily to maintain a colony from year to year.','["general horticultural reference"]','{"slug": "sweet-william", "common_name": "Sweet William", "scientific_name": "Dianthus barbatus", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 70}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant can go out 2–4 weeks before last frost as plants are frost-tolerant."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/8 in deep in well-drained germination mix; germination is fast and reliable at 65–70°F. Plant in full sun in well-drained, neutral to slightly alkaline soil; sweet William is technically a biennial that flowers in its second year, but modern annual varieties bloom the first year from an early indoor start. The domed, fragrant flower clusters in vivid shades of red, pink, white, and bicolor appear in late spring and early summer. Deadhead spent clusters promptly to extend the blooming period; plants self-sow readily to maintain a colony from year to year.", "sources": ["general horticultural reference"]}')
