INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('switchgrass','Switchgrass','Panicum virgatum','flower','ornamental-grass',14,21,65,75,180,270,'seed','direct','perennial','hardy','last_frost',0,4,'Direct sow after last frost in spring; warm soil (above 60°F) promotes best germination.',3,9,24,36,36,72,24,36,'full','low','Sow seeds in full sun after last frost in average to poor, well-drained soil; switchgrass is extremely adaptable and tolerates clay, sand, wet or dry conditions, and even brief flooding — a true workhorse native grass. The airy, branching panicles of tiny seeds in late summer create a misty, luminous effect, and many cultivars develop spectacular red, burgundy, or orange fall color. Cut back to 4–6 in in late winter; divide every 3–4 years in spring when the clump center dies out. Named cultivars like ''Shenandoah'' and ''Prairie Fire'' offer predictably strong red fall color.','["general horticultural reference"]','{"slug": "switchgrass", "common_name": "Switchgrass", "scientific_name": "Panicum virgatum", "category": "flower", "subcategory": "ornamental-grass", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 180, "max": 270}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Direct sow after last frost in spring; warm soil (above 60°F) promotes best germination."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Sow seeds in full sun after last frost in average to poor, well-drained soil; switchgrass is extremely adaptable and tolerates clay, sand, wet or dry conditions, and even brief flooding — a true workhorse native grass. The airy, branching panicles of tiny seeds in late summer create a misty, luminous effect, and many cultivars develop spectacular red, burgundy, or orange fall color. Cut back to 4–6 in in late winter; divide every 3–4 years in spring when the clump center dies out. Named cultivars like ''Shenandoah'' and ''Prairie Fire'' offer predictably strong red fall color.", "sources": ["general horticultural reference"]}')
