INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('verbena-bonariensis','Tall Verbena','Verbena bonariensis','flower','perennial',14,28,65,75,90,120,'seed','indoor-start','perennial','half-hardy','last_frost',-10,-8,'Start seeds indoors 8–10 weeks before last frost after cold-stratifying for 1–2 weeks; often blooms from seed the first year.',7,11,18,24,36,60,18,24,'full','low','Cold-stratify seeds in moist towels for 1–2 weeks at 35–40°F, then sow indoors at 65–75°F; germination remains erratic over 14–28 days. Plant in full sun in poor to average, well-drained soil; this South American native is drought-tolerant and naturalizes readily once established. The wiry, branching stems carry clusters of small purple flowers from midsummer through frost at an unusual height that allows it to weave transparently through other plants. Grown as an annual north of zone 7, it self-sows prolifically even in cold climates and seedlings replace killed parent plants.','["general horticultural reference"]','{"slug": "verbena-bonariensis", "common_name": "Tall Verbena", "scientific_name": "Verbena bonariensis", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start seeds indoors 8–10 weeks before last frost after cold-stratifying for 1–2 weeks; often blooms from seed the first year."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Cold-stratify seeds in moist towels for 1–2 weeks at 35–40°F, then sow indoors at 65–75°F; germination remains erratic over 14–28 days. Plant in full sun in poor to average, well-drained soil; this South American native is drought-tolerant and naturalizes readily once established. The wiry, branching stems carry clusters of small purple flowers from midsummer through frost at an unusual height that allows it to weave transparently through other plants. Grown as an annual north of zone 7, it self-sows prolifically even in cold climates and seedlings replace killed parent plants.", "sources": ["general horticultural reference"]}')
