INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('tigridia','Tiger Flower','Tigridia pavonia','flower','bulb',NULL,NULL,NULL,NULL,60,90,'transplant','bulb','warm','tender','last_frost',0,2,'Plant bulbs after all frost danger passes in spring, once soil has warmed above 60°F.',8,11,4,6,18,30,6,8,'full','moderate','Plant bulbs 3–4 in deep in well-drained, moderately fertile soil; each exotic three-petaled flower lasts only one day but new buds open in succession over weeks. The vivid blooms come in yellow, orange, red, pink, and white, typically with a heavily spotted or blotched center cup. Plant in groups of a dozen or more for a showy display from midsummer into fall. In zones colder than 8, dig bulbs after first frost, dry thoroughly, and store in paper bags in a cool, frost-free location.','["general horticultural reference"]','{"slug": "tigridia", "common_name": "Tiger Flower", "scientific_name": "Tigridia pavonia", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "bulb", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Plant bulbs after all frost danger passes in spring, once soil has warmed above 60°F."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 6, "max": 8}, "sun": "full", "water": "moderate", "directions": "Plant bulbs 3–4 in deep in well-drained, moderately fertile soil; each exotic three-petaled flower lasts only one day but new buds open in succession over weeks. The vivid blooms come in yellow, orange, red, pink, and white, typically with a heavily spotted or blotched center cup. Plant in groups of a dozen or more for a showy display from midsummer into fall. In zones colder than 8, dig bulbs after first frost, dry thoroughly, and store in paper bags in a cool, frost-free location.", "sources": ["general horticultural reference"]}')
