  VALUES ('toad-lily','Toad Lily','Tricyrtis hirta','flower','perennial',28,42,55,65,180,270,'seed','division','perennial','hardy','spring',0,4,'Plant divisions in early spring as growth begins; they establish quickly and bloom in their first season from divisions.',4,9,18,24,24,36,18,24,'shade','moderate','Plant in humus-rich, consistently moist, well-drained shade; toad lily is an elegant late-season bloomer that produces exotic-looking, orchid-like flowers in white, purple, or lilac with dark spots from late summer through fall. The arching stems with clasping leaves create a graceful, architectural presence throughout the season. Consistent moisture is essential — plants decline in dry soil; mulch heavily to maintain soil moisture and temperature. Divide every 3–4 years in early spring to manage the slowly spreading clumps.','["general horticultural reference"]','{"slug": "toad-lily", "common_name": "Toad Lily", "scientific_name": "Tricyrtis hirta", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 28, "max": 42}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 180, "max": 270}, "maturity_from": "seed", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions in early spring as growth begins; they establish quickly and bloom in their first season from divisions."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "shade", "water": "moderate", "directions": "Plant in humus-rich, consistently moist, well-drained shade; toad lily is an elegant late-season bloomer that produces exotic-looking, orchid-like flowers in white, purple, or lilac with dark spots from late summer through fall. The arching stems with clasping leaves create a graceful, architectural presence throughout the season. Consistent moisture is essential — plants decline in dry soil; mulch heavily to maintain soil moisture and temperature. Divide every 3–4 years in early spring to manage the slowly spreading clumps.", "sources": ["general horticultural reference"]}')
