INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('tropical-milkweed','Tropical Milkweed','Asclepias curassavica','flower','perennial',10,14,65,80,90,120,'seed','indoor-start','perennial','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; in zone 8–11 it acts as a short-lived perennial and blooms from spring through hard frost.',8,11,18,24,36,48,24,36,'full','moderate','Sow seeds 1/8 in deep in warm starting mix and transplant after frost danger has passed; tropical milkweed establishes quickly and blooms in its first season unlike most native milkweeds. It is an important monarch host plant and nectar source throughout the Gulf Coast growing season, but in zone 9–11 where it does not freeze back, cut plants to 6 in in fall and winter to disrupt the overwinter buildup of Ophryocystis elektroscirrha (OE), a protozoan parasite that accumulates on non-dormant milkweed. Deadhead spent flower clusters to encourage continuous blooming, or allow seedpods to dry and open for easy self-sowing. The red-and-yellow bicolor flowers distinguish it from native milkweeds at a glance.','["Xerces Society for Invertebrate Conservation", "general horticultural reference"]','{"slug": "tropical-milkweed", "common_name": "Tropical Milkweed", "scientific_name": "Asclepias curassavica", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 80}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; in zone 8–11 it acts as a short-lived perennial and blooms from spring through hard frost."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 48}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/8 in deep in warm starting mix and transplant after frost danger has passed; tropical milkweed establishes quickly and blooms in its first season unlike most native milkweeds. It is an important monarch host plant and nectar source throughout the Gulf Coast growing season, but in zone 9–11 where it does not freeze back, cut plants to 6 in in fall and winter to disrupt the overwinter buildup of Ophryocystis elektroscirrha (OE), a protozoan parasite that accumulates on non-dormant milkweed. Deadhead spent flower clusters to encourage continuous blooming, or allow seedpods to dry and open for easy self-sowing. The red-and-yellow bicolor flowers distinguish it from native milkweeds at a glance.", "sources": ["Xerces Society for Invertebrate Conservation", "general horticultural reference"]}')
