INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('tulip','Tulip','Tulipa spp.','flower','bulb',NULL,NULL,NULL,NULL,150,210,'transplant','bulb','perennial','hardy','fall',-8,-4,'Plant bulbs in fall when soil temperatures drop below 55°F, about 4–8 weeks before hard frost.',3,8,4,6,10,26,4,6,'full','moderate','Plant bulbs pointed end up at a depth of 3 times their height, typically 6–8 in deep, in well-drained soil — standing water will cause rot. In warmer zones (7–8), pre-chill bulbs for 6–8 weeks in the refrigerator before planting to simulate the cold period they need. Most hybrid tulips perform best in year 1; replanting fresh bulbs annually is common practice in mild climates. Allow leaves to die back naturally after bloom to recharge the bulb.','["general horticultural reference"]','{"slug": "tulip", "common_name": "Tulip", "scientific_name": "Tulipa spp.", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 150, "max": 210}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Plant bulbs in fall when soil temperatures drop below 55°F, about 4–8 weeks before hard frost."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 10, "max": 26}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Plant bulbs pointed end up at a depth of 3 times their height, typically 6–8 in deep, in well-drained soil — standing water will cause rot. In warmer zones (7–8), pre-chill bulbs for 6–8 weeks in the refrigerator before planting to simulate the cold period they need. Most hybrid tulips perform best in year 1; replanting fresh bulbs annually is common practice in mild climates. Allow leaves to die back naturally after bloom to recharge the bulb.", "sources": ["general horticultural reference"]}')
