INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('turks-cap','Turk''s Cap','Malvaviscus arboreus var. drummondii','flower','perennial',21,30,70,85,180,365,'transplant','transplant','perennial','half-hardy','last_frost',0,4,'Plant container stock after last frost; an extremely tough Texas native that thrives in heat, part shade, and dry soils where few flowering shrubs will grow.',7,11,36,72,36,84,36,72,'partial','low','Plant in well-drained to average soil in partial to full sun; Turk''s cap is one of the most shade-tolerant flowering natives for the Gulf South and performs well under the canopy of live oaks. The distinctive red flowers never fully open, forming a twisted turban shape, and are a top hummingbird nectar source from summer through fall. Small red fruits that follow are edible and mildly sweet — birds devour them quickly, and new plants sprout readily from seeds they drop. Prune back to 12–18 in in late winter; in zone 7–8 the top dies back but the roots are reliably hardy to about 10°F.','["Texas A&M AgriLife Extension Service", "Lady Bird Johnson Wildflower Center"]','{"slug": "turks-cap", "common_name": "Turk''s Cap", "scientific_name": "Malvaviscus arboreus var. drummondii", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 21, "max": 30}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 180, "max": 365}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant container stock after last frost; an extremely tough Texas native that thrives in heat, part shade, and dry soils where few flowering shrubs will grow."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 36, "max": 72}, "height_in": {"min": 36, "max": 84}, "spread_in": {"min": 36, "max": 72}, "sun": "partial", "water": "low", "directions": "Plant in well-drained to average soil in partial to full sun; Turk''s cap is one of the most shade-tolerant flowering natives for the Gulf South and performs well under the canopy of live oaks. The distinctive red flowers never fully open, forming a twisted turban shape, and are a top hummingbird nectar source from summer through fall. Small red fruits that follow are edible and mildly sweet — birds devour them quickly, and new plants sprout readily from seeds they drop. Prune back to 12–18 in in late winter; in zone 7–8 the top dies back but the roots are reliably hardy to about 10°F.", "sources": ["Texas A&M AgriLife Extension Service", "Lady Bird Johnson Wildflower Center"]}')
