  VALUES ('viola','Viola (Johnny Jump-Up)','Viola tricolor','flower','annual',10,14,65,70,50,70,'transplant','indoor-start','cool','half-hardy','last_frost',-12,-10,'Start indoors 10–12 weeks before last frost; transplant several weeks before last frost as plants tolerate mild freezes.',3,10,4,8,4,8,6,10,'full','moderate','Sow seed 1/8 in deep in a cool, moist starting mix; darkness during germination is beneficial. Violas are more petite and heat-tolerant than pansies, often self-sowing prolifically in the garden. Deadhead to extend flowering, or allow seed to set for naturalized self-seeding the following year. They shine in early spring containers and border edges.','["general horticultural reference"]','{"slug": "viola", "common_name": "Viola (Johnny Jump-Up)", "scientific_name": "Viola tricolor", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 70}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -12, "max": -10}, "note": "Start indoors 10–12 weeks before last frost; transplant several weeks before last frost as plants tolerate mild freezes."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 4, "max": 8}, "height_in": {"min": 4, "max": 8}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/8 in deep in a cool, moist starting mix; darkness during germination is beneficial. Violas are more petite and heat-tolerant than pansies, often self-sowing prolifically in the garden. Deadhead to extend flowering, or allow seed to set for naturalized self-seeding the following year. They shine in early spring containers and border edges.", "sources": ["general horticultural reference"]}')
