  VALUES ('virginia-bluebells','Virginia Bluebells','Mertensia virginica','flower','perennial',14,30,55,65,365,730,'seed','direct','perennial','hardy','fall',-8,-4,'Sow fresh seed in fall directly in a shaded, moist site; or plant divisions/transplants in early spring.',3,9,12,18,12,24,12,18,'partial','moderate','Plant in humus-rich, consistently moist, shaded to partly shaded woodland soil; Virginia bluebells are a spring ephemeral that goes dormant by early summer, disappearing completely underground. The clusters of pink buds open to sky-blue, nodding tubular flowers in early to mid-spring and are among the most beautiful of native wildflowers. Mark the location of clumps so they are not accidentally disturbed; interplant with hostas, ferns, or other perennials that will fill the gap when bluebells go dormant. Divide crowded clumps or transplant in early fall when dormant.','["general horticultural reference"]','{"slug": "virginia-bluebells", "common_name": "Virginia Bluebells", "scientific_name": "Mertensia virginica", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Sow fresh seed in fall directly in a shaded, moist site; or plant divisions/transplants in early spring."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Plant in humus-rich, consistently moist, shaded to partly shaded woodland soil; Virginia bluebells are a spring ephemeral that goes dormant by early summer, disappearing completely underground. The clusters of pink buds open to sky-blue, nodding tubular flowers in early to mid-spring and are among the most beautiful of native wildflowers. Mark the location of clumps so they are not accidentally disturbed; interplant with hostas, ferns, or other perennials that will fill the gap when bluebells go dormant. Divide crowded clumps or transplant in early fall when dormant.", "sources": ["general horticultural reference"]}')
