  VALUES ('watsonia','Watsonia','Watsonia spp.','flower','bulb',NULL,NULL,NULL,NULL,90,120,'transplant','bulb','perennial','tender','last_frost',0,2,'Plant corms after last frost in spring for summer bloom; in mild-winter climates (zones 9–10) plant in fall.',8,11,6,8,24,48,6,12,'full','moderate','Plant corms 3–4 in deep in fertile, well-drained soil; watsonia closely resembles gladiolus and thrives in similar conditions. The tall, sword-like foliage produces elegant spikes of tubular flowers in shades of pink, red, coral, white, and bicolor throughout summer. In frost-free climates corms multiply into large colonies and can become invasive — divide every few years to manage spread. In colder zones lift corms after frost kills the foliage, cure, and store in a cool, dry, frost-free location.','["general horticultural reference"]','{"slug": "watsonia", "common_name": "Watsonia", "scientific_name": "Watsonia spp.", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Plant corms after last frost in spring for summer bloom; in mild-winter climates (zones 9–10) plant in fall."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Plant corms 3–4 in deep in fertile, well-drained soil; watsonia closely resembles gladiolus and thrives in similar conditions. The tall, sword-like foliage produces elegant spikes of tubular flowers in shades of pink, red, coral, white, and bicolor throughout summer. In frost-free climates corms multiply into large colonies and can become invasive — divide every few years to manage spread. In colder zones lift corms after frost kills the foliage, cure, and store in a cool, dry, frost-free location.", "sources": ["general horticultural reference"]}')
