  VALUES ('wild-quinine','Wild Quinine','Parthenium integrifolium','flower','perennial',14,28,60,70,365,548,'seed','direct','perennial','hardy','fall',-8,-4,'Direct sow in fall for natural cold stratification; alternatively cold-stratify indoors and spring-sow after last frost.',4,8,18,24,30,48,18,24,'full','low','Sow in lean to average, well-drained soil in full sun; wild quinine is a sturdy native prairie plant that tolerates heat, drought, and clay once established. The flat-topped clusters of small white button flowers appear in midsummer and persist for many weeks, drawing in a wide diversity of native bees, wasps, and beetles. The button-like, persistent seed heads provide architectural interest into fall and winter. A reliable, long-lived plant that requires virtually no maintenance once established in a sunny meadow or native plant garden.','["general horticultural reference"]','{"slug": "wild-quinine", "common_name": "Wild Quinine", "scientific_name": "Parthenium integrifolium", "category": "flower", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -8, "max": -4}, "note": "Direct sow in fall for natural cold stratification; alternatively cold-stratify indoors and spring-sow after last frost."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 30, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Sow in lean to average, well-drained soil in full sun; wild quinine is a sturdy native prairie plant that tolerates heat, drought, and clay once established. The flat-topped clusters of small white button flowers appear in midsummer and persist for many weeks, drawing in a wide diversity of native bees, wasps, and beetles. The button-like, persistent seed heads provide architectural interest into fall and winter. A reliable, long-lived plant that requires virtually no maintenance once established in a sunny meadow or native plant garden.", "sources": ["general horticultural reference"]}')
