  VALUES ('winter-aconite','Winter Aconite','Eranthis hyemalis','flower','bulb',NULL,NULL,NULL,NULL,90,120,'transplant','bulb','perennial','hardy','fall',-10,-6,'Plant tubers in fall as soon as available — they dry out quickly; soak in water for 24 hours before planting.',3,7,2,3,3,4,2,3,'partial','moderate','Soak the small, hard tubers in water for 24 hours before planting to rehydrate them; plant 2 in deep under deciduous trees or shrubs as soon as received in late summer or early fall. Bright yellow cup-shaped flowers surrounded by a green ruff appear in late winter, often alongside snowdrops, before any leaves emerge on overhead trees. Winter aconite self-seeds freely and slowly forms large, cheerful carpets if left undisturbed. Best planted where they can stay permanently; they strongly dislike being moved.','["general horticultural reference"]','{"slug": "winter-aconite", "common_name": "Winter Aconite", "scientific_name": "Eranthis hyemalis", "category": "flower", "subcategory": "bulb", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -10, "max": -6}, "note": "Plant tubers in fall as soon as available — they dry out quickly; soak in water for 24 hours before planting."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 2, "max": 3}, "height_in": {"min": 3, "max": 4}, "spread_in": {"min": 2, "max": 3}, "sun": "partial", "water": "moderate", "directions": "Soak the small, hard tubers in water for 24 hours before planting to rehydrate them; plant 2 in deep under deciduous trees or shrubs as soon as received in late summer or early fall. Bright yellow cup-shaped flowers surrounded by a green ruff appear in late winter, often alongside snowdrops, before any leaves emerge on overhead trees. Winter aconite self-seeds freely and slowly forms large, cheerful carpets if left undisturbed. Best planted where they can stay permanently; they strongly dislike being moved.", "sources": ["general horticultural reference"]}')
