INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('torenia','Wishbone Flower','Torenia fournieri','flower','annual',7,14,70,75,60,80,'transplant','indoor-start','warm','tender','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after all frost risk has passed.',2,11,8,10,8,14,8,12,'partial','moderate','Surface-sow tiny seeds on moist mix without covering; they need light to germinate at 70–75°F. Torenia is one of the best flowering annuals for shaded and part-shaded spots in hot, humid climates where impatiens are lost to downy mildew. The bicolored, snapdragon-like flowers in purple, pink, white, or yellow bloom profusely without deadheading throughout summer. Keep soil consistently moist, as plants wilt quickly when dry but recover readily; fertilize monthly with a balanced liquid feed.','["general horticultural reference"]','{"slug": "torenia", "common_name": "Wishbone Flower", "scientific_name": "Torenia fournieri", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 75}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after all frost risk has passed."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 8, "max": 10}, "height_in": {"min": 8, "max": 14}, "spread_in": {"min": 8, "max": 12}, "sun": "partial", "water": "moderate", "directions": "Surface-sow tiny seeds on moist mix without covering; they need light to germinate at 70–75°F. Torenia is one of the best flowering annuals for shaded and part-shaded spots in hot, humid climates where impatiens are lost to downy mildew. The bicolored, snapdragon-like flowers in purple, pink, white, or yellow bloom profusely without deadheading throughout summer. Keep soil consistently moist, as plants wilt quickly when dry but recover readily; fertilize monthly with a balanced liquid feed.", "sources": ["general horticultural reference"]}')
