INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('xeranthemum','Xeranthemum','Xeranthemum annuum','flower','annual',10,15,60,70,60,75,'seed','direct','warm','tender','last_frost',0,2,'Direct sow after last frost; prefers to be direct sown as transplants disturb its taproot.',2,11,6,9,18,30,6,9,'full','low','Direct sow after last frost in full sun with lean, well-drained soil; xeranthemum is one of the easiest everlastings to grow and tolerates poor, dry conditions well. The papery, daisy-like flowers in shades of lavender, pink, purple, and white are naturally self-preserving and air-dry on the stem. Harvest stems for drying when flowers are about two-thirds open; hang upside down in a warm, airy location for 2–3 weeks. Successive sowings 2–3 weeks apart can extend the harvest season into early fall.','["general horticultural reference"]','{"slug": "xeranthemum", "common_name": "Xeranthemum", "scientific_name": "Xeranthemum annuum", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 10, "max": 15}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 60, "max": 75}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow after last frost; prefers to be direct sown as transplants disturb its taproot."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 6, "max": 9}, "sun": "full", "water": "low", "directions": "Direct sow after last frost in full sun with lean, well-drained soil; xeranthemum is one of the easiest everlastings to grow and tolerates poor, dry conditions well. The papery, daisy-like flowers in shades of lavender, pink, purple, and white are naturally self-preserving and air-dry on the stem. Harvest stems for drying when flowers are about two-thirds open; hang upside down in a warm, airy location for 2–3 weeks. Successive sowings 2–3 weeks apart can extend the harvest season into early fall.", "sources": ["general horticultural reference"]}')
