  VALUES ('zinnia','Zinnia','Zinnia elegans','flower','annual',5,7,70,80,60,70,'seed','direct','warm','tender','last_frost',0,1,'Direct sow after last frost when soil temperature is above 65°F; also easy to start indoors 4–6 weeks early.',3,11,6,18,12,48,8,18,'full','moderate','Sow seed 1/4 in deep directly in the garden once frost risk is past and soil is warm. Pinch seedlings at 6 in tall to promote branching and a fuller plant with more stems for cutting. Cut flowers frequently to the next set of leaves to stimulate continuous bloom through summer. Avoid overhead watering to reduce powdery mildew; water at the base.','["general horticultural reference"]','{"slug": "zinnia", "common_name": "Zinnia", "scientific_name": "Zinnia elegans", "category": "flower", "subcategory": "annual", "days_to_germination": {"min": 5, "max": 7}, "germination_soil_temp_f": {"min": 70, "max": 80}, "days_to_maturity": {"min": 60, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 1}, "note": "Direct sow after last frost when soil temperature is above 65°F; also easy to start indoors 4–6 weeks early."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 18}, "height_in": {"min": 12, "max": 48}, "spread_in": {"min": 8, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep directly in the garden once frost risk is past and soil is warm. Pinch seedlings at 6 in tall to promote branching and a fuller plant with more stems for cutting. Cut flowers frequently to the next set of leaves to stimulate continuous bloom through summer. Avoid overhead watering to reduce powdery mildew; water at the base.", "sources": ["general horticultural reference"]}')
