  VALUES ('abiu','Abiu','Pouteria caimito','fruit','tropical',NULL,NULL,NULL,NULL,1095,1825,'transplant','transplant','perennial','tender','spring',0,8,'Plant grafted trees in spring; abiu is cold-sensitive and requires a frost-free year-round climate.',10,11,180,300,180,420,144,300,'full','moderate','Plant in deep, fertile, well-drained, slightly acidic soil in full sun; abiu is closely related to sapodilla and canistel and shares their preference for warm, humid conditions with regular moisture. Trees are self-fertile and heavy bearers once established; grafted selections begin fruiting in 2–4 years versus 7+ for seedlings. The smooth golden-yellow skin of ripe fruit conceals a translucent, gelatinous, caramel-flavored flesh — eat by cutting in half and scooping; avoid getting the sticky latex near the lips if the fruit is slightly underripe. Harvest when the skin has turned fully golden-yellow and the fruit yields gently to thumb pressure, typically in late summer through fall.','["general horticultural reference"]','{"slug": "abiu", "common_name": "Abiu", "scientific_name": "Pouteria caimito", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted trees in spring; abiu is cold-sensitive and requires a frost-free year-round climate."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 180, "max": 300}, "height_in": {"min": 180, "max": 420}, "spread_in": {"min": 144, "max": 300}, "sun": "full", "water": "moderate", "directions": "Plant in deep, fertile, well-drained, slightly acidic soil in full sun; abiu is closely related to sapodilla and canistel and shares their preference for warm, humid conditions with regular moisture. Trees are self-fertile and heavy bearers once established; grafted selections begin fruiting in 2–4 years versus 7+ for seedlings. The smooth golden-yellow skin of ripe fruit conceals a translucent, gelatinous, caramel-flavored flesh — eat by cutting in half and scooping; avoid getting the sticky latex near the lips if the fruit is slightly underripe. Harvest when the skin has turned fully golden-yellow and the fruit yields gently to thumb pressure, typically in late summer through fall.", "sources": ["general horticultural reference"]}')
