INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('acerola','Acerola (Barbados Cherry)','Malpighia emarginata','fruit','tropical fruit',21,42,75,85,730,1460,'transplant','transplant','perennial','tender','last_frost',0,8,'Plant container-grown or grafted stock in spring after all frost danger; in zone 9 site against a south-facing wall for extra warmth.',9,11,96,180,60,180,72,180,'full','moderate','Acerola produces cherry-like fruits with one of the highest natural concentrations of vitamin C of any food plant — up to 65 times that of an orange. The shrubby tree is self-fertile and can bear multiple times per year in truly frost-free climates; it is very sensitive to cold below 30°F and root systems are damaged below 28°F. Plant in well-drained, slightly acid to neutral soil and fertilize lightly with a balanced fertilizer three times per year. Fruit ripens very quickly from green to red and is extremely perishable — harvest when fully red and process (freeze, juice) within 24–48 hours for maximum vitamin C retention.','["University of Florida IFAS Extension", "general horticultural reference"]','{"slug": "acerola", "common_name": "Acerola (Barbados Cherry)", "scientific_name": "Malpighia emarginata", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 730, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant container-grown or grafted stock in spring after all frost danger; in zone 9 site against a south-facing wall for extra warmth."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 96, "max": 180}, "height_in": {"min": 60, "max": 180}, "spread_in": {"min": 72, "max": 180}, "sun": "full", "water": "moderate", "directions": "Acerola produces cherry-like fruits with one of the highest natural concentrations of vitamin C of any food plant — up to 65 times that of an orange. The shrubby tree is self-fertile and can bear multiple times per year in truly frost-free climates; it is very sensitive to cold below 30°F and root systems are damaged below 28°F. Plant in well-drained, slightly acid to neutral soil and fertilize lightly with a balanced fertilizer three times per year. Fruit ripens very quickly from green to red and is extremely perishable — harvest when fully red and process (freeze, juice) within 24–48 hours for maximum vitamin C retention.", "sources": ["University of Florida IFAS Extension", "general horticultural reference"]}')
