  VALUES ('beechnut','American Beech (Beechnut)','Fagus grandifolia','fruit','nut',NULL,NULL,NULL,NULL,3650,7300,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root or container-grown trees in early spring in rich, moist, well-drained, acidic soil.',3,9,480,960,480,960,360,720,'full','moderate','American beech is monoecious and wind-pollinated, but nut production is highly variable and irregular — large mast crops occur every 2–5 years, driven by weather patterns; at least two trees (ideally a grove) dramatically improves mast yield in any given year. The triangular beechnuts are sweet and nutritious, high in fat and protein, and valued by both wildlife and people; they are best eaten raw or lightly roasted and are traditionally used for oil extraction. Beech is extremely sensitive to soil compaction and grade changes around the root zone — construction damage is the primary killer of mature trees in urban settings. Plant in deep, moist, well-drained, acidic soil away from construction zones and plan for very long-term production: significant nut crops typically begin 10+ years after planting.','["general horticultural reference"]','{"slug": "beechnut", "common_name": "American Beech (Beechnut)", "scientific_name": "Fagus grandifolia", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 3650, "max": 7300}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root or container-grown trees in early spring in rich, moist, well-drained, acidic soil."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 480, "max": 960}, "height_in": {"min": 480, "max": 960}, "spread_in": {"min": 360, "max": 720}, "sun": "full", "water": "moderate", "directions": "American beech is monoecious and wind-pollinated, but nut production is highly variable and irregular — large mast crops occur every 2–5 years, driven by weather patterns; at least two trees (ideally a grove) dramatically improves mast yield in any given year. The triangular beechnuts are sweet and nutritious, high in fat and protein, and valued by both wildlife and people; they are best eaten raw or lightly roasted and are traditionally used for oil extraction. Beech is extremely sensitive to soil compaction and grade changes around the root zone — construction damage is the primary killer of mature trees in urban settings. Plant in deep, moist, well-drained, acidic soil away from construction zones and plan for very long-term production: significant nut crops typically begin 10+ years after planting.", "sources": ["general horticultural reference"]}')
