INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('apricot','Apricot','Prunus armeniaca','fruit','stone fruit',NULL,NULL,NULL,NULL,1095,1825,'transplant','transplant','perennial','hardy','spring',-6,-2,'Plant bare-root trees in late winter, as early as the soil can be worked, to allow root establishment before bloom.',5,9,144,240,120,216,120,216,'full','low','Most apricot varieties are self-fertile, which simplifies home-orchard planting, but two trees will increase yields. The key limiting factor in temperate climates is the tree''s early bloom time — a hard frost after bud break will eliminate the crop, so choose a sheltered north-facing or slightly elevated site to delay bloom, or select late-blooming cultivars. Prune in early summer rather than winter to reduce risk of cytospora canker infection. Harvest when the fruit is fully orange, fragrant, and gives slightly to the touch.','["general horticultural reference"]','{"slug": "apricot", "common_name": "Apricot", "scientific_name": "Prunus armeniaca", "category": "fruit", "subcategory": "stone fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -6, "max": -2}, "note": "Plant bare-root trees in late winter, as early as the soil can be worked, to allow root establishment before bloom."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 144, "max": 240}, "height_in": {"min": 120, "max": 216}, "spread_in": {"min": 120, "max": 216}, "sun": "full", "water": "low", "directions": "Most apricot varieties are self-fertile, which simplifies home-orchard planting, but two trees will increase yields. The key limiting factor in temperate climates is the tree''s early bloom time — a hard frost after bud break will eliminate the crop, so choose a sheltered north-facing or slightly elevated site to delay bloom, or select late-blooming cultivars. Prune in early summer rather than winter to reduce risk of cytospora canker infection. Harvest when the fruit is fully orange, fragrant, and gives slightly to the touch.", "sources": ["general horticultural reference"]}')
