  VALUES ('asian-persimmon','Asian Persimmon','Diospyros kaki','fruit','berry-like drupe',NULL,NULL,NULL,NULL,1460,2920,'transplant','transplant','perennial','half-hardy','spring',0,4,'Plant in spring after frost danger has passed; fall planting is fine in zones 8–10.',7,10,144,240,144,240,120,216,'full','low','Asian persimmons come in astringent types (such as Hachiya, best eaten when jelly-soft) and non-astringent types (such as Fuyu, eaten firm like an apple). Most cultivars are self-fertile and produce well as single trees. Trees need very little pruning — maintain a central leader and remove inward-growing branches to open the canopy. In cooler parts of zone 7, choose hardier varieties and site against a south-facing wall; in zones 9–10, low-chill cultivars perform best.','["general horticultural reference"]','{"slug": "asian-persimmon", "common_name": "Asian Persimmon", "scientific_name": "Diospyros kaki", "category": "fruit", "subcategory": "berry-like drupe", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2920}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring after frost danger has passed; fall planting is fine in zones 8–10."}, "usda_zones": {"min": 7, "max": 10}, "spacing_in": {"min": 144, "max": 240}, "height_in": {"min": 144, "max": 240}, "spread_in": {"min": 120, "max": 216}, "sun": "full", "water": "low", "directions": "Asian persimmons come in astringent types (such as Hachiya, best eaten when jelly-soft) and non-astringent types (such as Fuyu, eaten firm like an apple). Most cultivars are self-fertile and produce well as single trees. Trees need very little pruning — maintain a central leader and remove inward-growing branches to open the canopy. In cooler parts of zone 7, choose hardier varieties and site against a south-facing wall; in zones 9–10, low-chill cultivars perform best.", "sources": ["general horticultural reference"]}')
