INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('avocado','Avocado','Persea americana','fruit','drupe',NULL,NULL,NULL,NULL,1095,2555,'transplant','transplant','perennial','tender','last_frost',2,8,'Plant in spring when all frost risk is past and soil is warm; avoid planting in summer heat.',9,11,240,360,144,360,144,300,'full','moderate','Avocados bear Type A flowers (open as female in the morning) and Type B flowers (open as female in the afternoon); planting one of each type near each other ensures pollen is available throughout the day and greatly increases fruit set. Grafted trees begin fruiting in 3–5 years; seedlings may take 8–10 years. Avocados are sensitive to root rot in heavy or poorly drained soils — plant on a mound or raised bed and irrigate deeply but infrequently. Fruit does not ripen on the tree; pick when full-sized and let ripen at room temperature for 3–8 days.','["general horticultural reference"]','{"slug": "avocado", "common_name": "Avocado", "scientific_name": "Persea americana", "category": "fruit", "subcategory": "drupe", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2555}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant in spring when all frost risk is past and soil is warm; avoid planting in summer heat."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 240, "max": 360}, "height_in": {"min": 144, "max": 360}, "spread_in": {"min": 144, "max": 300}, "sun": "full", "water": "moderate", "directions": "Avocados bear Type A flowers (open as female in the morning) and Type B flowers (open as female in the afternoon); planting one of each type near each other ensures pollen is available throughout the day and greatly increases fruit set. Grafted trees begin fruiting in 3–5 years; seedlings may take 8–10 years. Avocados are sensitive to root rot in heavy or poorly drained soils — plant on a mound or raised bed and irrigate deeply but infrequently. Fruit does not ripen on the tree; pick when full-sized and let ripen at room temperature for 3–8 days.", "sources": ["general horticultural reference"]}')
