INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('bael-fruit','Bael (Bengal Quince)','Aegle marmelos','fruit','tropical',NULL,NULL,NULL,NULL,1825,3650,'transplant','transplant','perennial','half-hardy','spring',0,6,'Plant in spring after cold weather passes; bael tolerates light frost once established but does best in warm subtropical to tropical climates.',9,11,180,360,180,480,144,360,'full','low','Bael is a spiny citrus relative (family Rutaceae) highly revered in South Asian horticulture and medicine that tolerates drought, alkaline soils, and brief frosts to about 25°F once the trunk is mature — among the hardiest of the true tropical fruit trees. Trees are self-fertile and pollinated by insects; a single specimen fruits reliably. The hard-shelled, woody fruit takes 9–12 months to ripen on the tree; harvest when the skin turns from green to yellowish-green and the fruit sounds hollow when tapped. The sticky, aromatic flesh is scooped out and eaten fresh with sugar, blended into a popular cooling drink (bael sherbet), or dried; dried slices brew into a medicinal tisane with mild anti-diarrheal properties.','["general horticultural reference"]','{"slug": "bael-fruit", "common_name": "Bael (Bengal Quince)", "scientific_name": "Aegle marmelos", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1825, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 6}, "note": "Plant in spring after cold weather passes; bael tolerates light frost once established but does best in warm subtropical to tropical climates."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 180, "max": 360}, "height_in": {"min": 180, "max": 480}, "spread_in": {"min": 144, "max": 360}, "sun": "full", "water": "low", "directions": "Bael is a spiny citrus relative (family Rutaceae) highly revered in South Asian horticulture and medicine that tolerates drought, alkaline soils, and brief frosts to about 25°F once the trunk is mature — among the hardiest of the true tropical fruit trees. Trees are self-fertile and pollinated by insects; a single specimen fruits reliably. The hard-shelled, woody fruit takes 9–12 months to ripen on the tree; harvest when the skin turns from green to yellowish-green and the fruit sounds hollow when tapped. The sticky, aromatic flesh is scooped out and eaten fresh with sugar, blended into a popular cooling drink (bael sherbet), or dried; dried slices brew into a medicinal tisane with mild anti-diarrheal properties.", "sources": ["general horticultural reference"]}')
