  VALUES ('bilimbi','Bilimbi (Cucumber Tree)','Averrhoa bilimbi','fruit','tropical',NULL,NULL,NULL,NULL,1095,1825,'transplant','transplant','perennial','tender','spring',0,8,'Plant in spring in a frost-free site; bilimbi is more cold-sensitive than its relative starfruit.',10,11,120,216,96,216,96,180,'full','moderate','Bilimbi is a cauliflorous tree — clusters of small red flowers and the resulting green, cucumber-shaped fruits emerge directly from the trunk and main branches — creating a striking ornamental effect. It is self-fertile and prolific, producing nearly year-round in warm climates with adequate moisture. The fruit is extremely acidic and rarely eaten raw; it is prized as a souring agent in Southeast Asian and Caribbean cuisines, used as a marinade tenderizer, and made into preserves, chutneys, and cooling drinks. Harvest the pale green to yellow-green fruits while still firm for culinary use; fully ripe fruits become soft and ferment quickly on the tree.','["general horticultural reference"]','{"slug": "bilimbi", "common_name": "Bilimbi (Cucumber Tree)", "scientific_name": "Averrhoa bilimbi", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant in spring in a frost-free site; bilimbi is more cold-sensitive than its relative starfruit."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 120, "max": 216}, "height_in": {"min": 96, "max": 216}, "spread_in": {"min": 96, "max": 180}, "sun": "full", "water": "moderate", "directions": "Bilimbi is a cauliflorous tree — clusters of small red flowers and the resulting green, cucumber-shaped fruits emerge directly from the trunk and main branches — creating a striking ornamental effect. It is self-fertile and prolific, producing nearly year-round in warm climates with adequate moisture. The fruit is extremely acidic and rarely eaten raw; it is prized as a souring agent in Southeast Asian and Caribbean cuisines, used as a marinade tenderizer, and made into preserves, chutneys, and cooling drinks. Harvest the pale green to yellow-green fruits while still firm for culinary use; fully ripe fruits become soft and ferment quickly on the tree.", "sources": ["general horticultural reference"]}')
