  VALUES ('black-sapote','Black Sapote','Diospyros nigra','fruit','tropical fruit',14,30,75,85,1460,2920,'transplant','transplant','perennial','tender','last_frost',0,8,'Plant in spring after all frost risk has passed; young trees are cold-sensitive and need protection until the trunk is at least 2 inches in diameter.',10,11,180,300,180,360,144,300,'full','moderate','Black sapote is a relative of the Asian persimmon; when ripe its flesh turns chocolate-brown and has a rich, pudding-like flavor often described as chocolate mousse. Trees are dioecious or polygamous — plant at least two seedlings or a grafted female with a male nearby for reliable fruiting. They prefer well-drained, fertile soils with a pH near 6.5 and are sensitive to frost, waterlogging, and salt winds. Harvest when the skin turns from bright olive-green to olive-yellow-green and the fruit gives to very gentle pressure; leave at room temperature 5–7 days until the inside is completely dark and custardy.','["University of Florida IFAS Extension", "general horticultural reference"]','{"slug": "black-sapote", "common_name": "Black Sapote", "scientific_name": "Diospyros nigra", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 1460, "max": 2920}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant in spring after all frost risk has passed; young trees are cold-sensitive and need protection until the trunk is at least 2 inches in diameter."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 180, "max": 300}, "height_in": {"min": 180, "max": 360}, "spread_in": {"min": 144, "max": 300}, "sun": "full", "water": "moderate", "directions": "Black sapote is a relative of the Asian persimmon; when ripe its flesh turns chocolate-brown and has a rich, pudding-like flavor often described as chocolate mousse. Trees are dioecious or polygamous — plant at least two seedlings or a grafted female with a male nearby for reliable fruiting. They prefer well-drained, fertile soils with a pH near 6.5 and are sensitive to frost, waterlogging, and salt winds. Harvest when the skin turns from bright olive-green to olive-yellow-green and the fruit gives to very gentle pressure; leave at room temperature 5–7 days until the inside is completely dark and custardy.", "sources": ["University of Florida IFAS Extension", "general horticultural reference"]}')
