  VALUES ('black-walnut','Black Walnut','Juglans nigra','fruit','nut',NULL,NULL,NULL,NULL,2555,4380,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root or container stock in early spring; site carefully as the tree grows very large and produces juglone.',4,9,480,720,480,960,360,720,'full','moderate','Black walnut is a native North American species grown primarily for its richly flavored nuts and valuable timber. It produces high concentrations of juglone in its roots, leaves, and hulls, which is toxic to many garden plants including tomatoes, peppers, apples, and blueberries; maintain a 50–80 foot buffer from sensitive plants. Trees are monoecious and partially self-fertile but cross well with a second tree. Hulls stain skin and clothing an indelible dark brown; wear gloves when husking. Nuts are ready when hulls are yellow-green to black and dent when pressed; cure for 2–3 weeks after husking.','["general horticultural reference"]','{"slug": "black-walnut", "common_name": "Black Walnut", "scientific_name": "Juglans nigra", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 2555, "max": 4380}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root or container stock in early spring; site carefully as the tree grows very large and produces juglone."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 480, "max": 720}, "height_in": {"min": 480, "max": 960}, "spread_in": {"min": 360, "max": 720}, "sun": "full", "water": "moderate", "directions": "Black walnut is a native North American species grown primarily for its richly flavored nuts and valuable timber. It produces high concentrations of juglone in its roots, leaves, and hulls, which is toxic to many garden plants including tomatoes, peppers, apples, and blueberries; maintain a 50–80 foot buffer from sensitive plants. Trees are monoecious and partially self-fertile but cross well with a second tree. Hulls stain skin and clothing an indelible dark brown; wear gloves when husking. Nuts are ready when hulls are yellow-green to black and dent when pressed; cure for 2–3 weeks after husking.", "sources": ["general horticultural reference"]}')
