  VALUES ('blood-orange','Blood Orange','Citrus sinensis','fruit','citrus',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','tender','last_frost',2,8,'Plant in spring after frost risk has passed; blood oranges require cool winters for anthocyanin color development — they color best in climates with cold nights during ripening.',9,11,144,240,120,240,120,216,'full','moderate','Blood orange cultivars (Moro, Tarocco, Sanguinello) develop their signature ruby-red flesh and juice through the accumulation of anthocyanins, a pigment triggered by cool nights during fruit development — temperatures between 40 and 50°F for several weeks from late autumn through midwinter produce the deepest coloring. In frost-free tropical climates the flesh remains orange with little anthocyanin. Trees are self-fertile, medium-sized, and managed identically to other sweet oranges: plant in well-drained soil, fertilize with a citrus blend three times per year, and irrigate deeply but infrequently. Harvest from late winter through early spring when the flesh has developed full color and the fruit is sweet.','["University of California Cooperative Extension", "general horticultural reference"]','{"slug": "blood-orange", "common_name": "Blood Orange", "scientific_name": "Citrus sinensis", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant in spring after frost risk has passed; blood oranges require cool winters for anthocyanin color development — they color best in climates with cold nights during ripening."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 144, "max": 240}, "height_in": {"min": 120, "max": 240}, "spread_in": {"min": 120, "max": 216}, "sun": "full", "water": "moderate", "directions": "Blood orange cultivars (Moro, Tarocco, Sanguinello) develop their signature ruby-red flesh and juice through the accumulation of anthocyanins, a pigment triggered by cool nights during fruit development — temperatures between 40 and 50°F for several weeks from late autumn through midwinter produce the deepest coloring. In frost-free tropical climates the flesh remains orange with little anthocyanin. Trees are self-fertile, medium-sized, and managed identically to other sweet oranges: plant in well-drained soil, fertilize with a citrus blend three times per year, and irrigate deeply but infrequently. Harvest from late winter through early spring when the flesh has developed full color and the fruit is sweet.", "sources": ["University of California Cooperative Extension", "general horticultural reference"]}')
