  VALUES ('breadfruit','Breadfruit','Artocarpus altilis','fruit','tropical',NULL,NULL,NULL,NULL,1095,1825,'transplant','transplant','perennial','tender','spring',0,8,'Plant root-shoot suckers or grafted trees in spring; breadfruit requires a fully frost-free year-round climate.',10,11,240,480,240,600,240,480,'full','moderate','Propagate from root shoots or cuttings rather than seed, as most cultivated varieties are seedless and parthenocarpic — no pollination is required for fruit set. Trees prefer deep, fertile, well-drained soil and consistent moisture; they tolerate brief drought once mature but perform best with regular irrigation. A single mature tree can produce 200–800 fruits per year; thin clusters to 2–3 fruit per stem to improve size. Harvest when the skin transitions from bright green to yellowish-green with slight latex seeping from surface cracks, indicating starch has developed but the flesh has not yet become overripe and sticky.','["general horticultural reference"]','{"slug": "breadfruit", "common_name": "Breadfruit", "scientific_name": "Artocarpus altilis", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant root-shoot suckers or grafted trees in spring; breadfruit requires a fully frost-free year-round climate."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 240, "max": 480}, "height_in": {"min": 240, "max": 600}, "spread_in": {"min": 240, "max": 480}, "sun": "full", "water": "moderate", "directions": "Propagate from root shoots or cuttings rather than seed, as most cultivated varieties are seedless and parthenocarpic — no pollination is required for fruit set. Trees prefer deep, fertile, well-drained soil and consistent moisture; they tolerate brief drought once mature but perform best with regular irrigation. A single mature tree can produce 200–800 fruits per year; thin clusters to 2–3 fruit per stem to improve size. Harvest when the skin transitions from bright green to yellowish-green with slight latex seeping from surface cracks, indicating starch has developed but the flesh has not yet become overripe and sticky.", "sources": ["general horticultural reference"]}')
