  VALUES ('buddhas-hand','Buddha''s Hand Citron','Citrus medica var. sarcodactylis','fruit','citrus',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','tender','last_frost',2,8,'Plant in spring after frost risk passes; Buddha''s hand is very cold-sensitive and ideal for container culture.',9,11,72,144,48,120,48,96,'full','moderate','Buddha''s hand is a citron variety bearing distinctive finger-like lobes that contain only aromatic peel with no juice or pulp; it is valued entirely for its intensely fragrant zest used in baking, cocktails, and as a natural air freshener. Trees are self-fertile and small enough to grow in 15–20 gallon containers, making them suitable for patios and sunrooms in colder climates; bring indoors before temperatures fall below 32°F. Fertilize with a citrus-specific fertilizer three times per year and maintain consistent moisture to prevent fruit drop. Harvest when the fingers have turned fully yellow and the fragrance is intense; fruit can be stored at room temperature for 1–2 weeks.','["general horticultural reference"]','{"slug": "buddhas-hand", "common_name": "Buddha''s Hand Citron", "scientific_name": "Citrus medica var. sarcodactylis", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant in spring after frost risk passes; Buddha''s hand is very cold-sensitive and ideal for container culture."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 72, "max": 144}, "height_in": {"min": 48, "max": 120}, "spread_in": {"min": 48, "max": 96}, "sun": "full", "water": "moderate", "directions": "Buddha''s hand is a citron variety bearing distinctive finger-like lobes that contain only aromatic peel with no juice or pulp; it is valued entirely for its intensely fragrant zest used in baking, cocktails, and as a natural air freshener. Trees are self-fertile and small enough to grow in 15–20 gallon containers, making them suitable for patios and sunrooms in colder climates; bring indoors before temperatures fall below 32°F. Fertilize with a citrus-specific fertilizer three times per year and maintain consistent moisture to prevent fruit drop. Harvest when the fingers have turned fully yellow and the fragrance is intense; fruit can be stored at room temperature for 1–2 weeks.", "sources": ["general horticultural reference"]}')
