  VALUES ('butternut','Butternut','Juglans cinerea','fruit','nut',NULL,NULL,NULL,NULL,1825,3650,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root or container stock in early spring; choose disease-resistant hybrid selections due to butternut canker pressure on the native species.',3,7,360,600,360,720,300,600,'full','moderate','Butternut, or white walnut, produces rich, oily nuts with a milder, sweeter flavor than black walnut and is native to eastern North America. The species is severely threatened by Sirococcus clavigignenti-juglandacearum (butternut canker), so seek out canker-resistant cultivars or hybrids (butternut x heartnut crosses, or selections from university breeding programs) rather than straight-species seedlings. Like other walnuts, butternut is monoecious and partially self-fertile but benefits from a second tree nearby; it also produces juglone that can inhibit nearby sensitive plants. Harvest when the sticky, hairy green hulls begin to soften and turn yellow-brown in early to mid-fall; hull promptly and dry nuts for 2–3 weeks before cracking or storing.','["general horticultural reference", "USDA Forest Service"]','{"slug": "butternut", "common_name": "Butternut", "scientific_name": "Juglans cinerea", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1825, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root or container stock in early spring; choose disease-resistant hybrid selections due to butternut canker pressure on the native species."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 360, "max": 600}, "height_in": {"min": 360, "max": 720}, "spread_in": {"min": 300, "max": 600}, "sun": "full", "water": "moderate", "directions": "Butternut, or white walnut, produces rich, oily nuts with a milder, sweeter flavor than black walnut and is native to eastern North America. The species is severely threatened by Sirococcus clavigignenti-juglandacearum (butternut canker), so seek out canker-resistant cultivars or hybrids (butternut x heartnut crosses, or selections from university breeding programs) rather than straight-species seedlings. Like other walnuts, butternut is monoecious and partially self-fertile but benefits from a second tree nearby; it also produces juglone that can inhibit nearby sensitive plants. Harvest when the sticky, hairy green hulls begin to soften and turn yellow-brown in early to mid-fall; hull promptly and dry nuts for 2–3 weeks before cracking or storing.", "sources": ["general horticultural reference", "USDA Forest Service"]}')
