  VALUES ('calamondin','Calamondin','Citrus x microcarpa','fruit','citrus',NULL,NULL,NULL,NULL,730,1460,'transplant','transplant','perennial','half-hardy','last_frost',2,8,'Plant in spring after frost risk passes; calamondin is excellent for container culture in zones 7–8, where it can be brought indoors in winter.',8,11,60,120,60,144,48,96,'full','moderate','Calamondin is a hybrid between a kumquat and a mandarin orange, producing prolific small, sour-sweet fruits that are eaten whole like kumquats or used as a lime substitute in Southeast Asian cooking. The tree is self-fertile, nearly thornless, highly ornamental with fragrant white flowers, and among the easiest citrus to grow in containers — it tolerates indoor conditions better than most citrus. It tolerates brief dips to about 20°F when established. Fruit ripens from late autumn through spring; harvest when fully orange for best flavor, though the rind remains sweet while the flesh is tart even at the green-orange stage.','["general horticultural reference", "University of Florida IFAS Extension"]','{"slug": "calamondin", "common_name": "Calamondin", "scientific_name": "Citrus x microcarpa", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant in spring after frost risk passes; calamondin is excellent for container culture in zones 7–8, where it can be brought indoors in winter."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 60, "max": 120}, "height_in": {"min": 60, "max": 144}, "spread_in": {"min": 48, "max": 96}, "sun": "full", "water": "moderate", "directions": "Calamondin is a hybrid between a kumquat and a mandarin orange, producing prolific small, sour-sweet fruits that are eaten whole like kumquats or used as a lime substitute in Southeast Asian cooking. The tree is self-fertile, nearly thornless, highly ornamental with fragrant white flowers, and among the easiest citrus to grow in containers — it tolerates indoor conditions better than most citrus. It tolerates brief dips to about 20°F when established. Fruit ripens from late autumn through spring; harvest when fully orange for best flavor, though the rind remains sweet while the flesh is tart even at the green-orange stage.", "sources": ["general horticultural reference", "University of Florida IFAS Extension"]}')
