  VALUES ('canistel','Canistel (Egg Fruit)','Pouteria campechiana','fruit','tropical fruit',14,30,75,85,1825,3650,'transplant','transplant','perennial','tender','last_frost',0,8,'Plant grafted trees in spring after all frost danger has passed; canistel is limited to truly frost-free zones in the continental U.S.',10,11,180,300,180,420,144,240,'full','low','Canistel is an evergreen tropical tree that produces smooth, orange-yellow fruit with dense, dry, egg-yolk-colored flesh — hence the common name egg fruit. Grafted trees are strongly preferred over seedlings; seedlings may take 5–7 years to fruit and show variable quality, while grafted plants can begin bearing in 2–3 years. The tree is drought-tolerant once established and tolerates a range of well-drained soils but is damaged by temperatures below 32°F even briefly. Harvest when the skin turns fully golden-yellow and yields firmly to pressure; ripen indoors at room temperature for 3–5 days until completely soft and sweet.','["California Rare Fruit Growers", "University of Florida IFAS Extension"]','{"slug": "canistel", "common_name": "Canistel (Egg Fruit)", "scientific_name": "Pouteria campechiana", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 1825, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted trees in spring after all frost danger has passed; canistel is limited to truly frost-free zones in the continental U.S."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 180, "max": 300}, "height_in": {"min": 180, "max": 420}, "spread_in": {"min": 144, "max": 240}, "sun": "full", "water": "low", "directions": "Canistel is an evergreen tropical tree that produces smooth, orange-yellow fruit with dense, dry, egg-yolk-colored flesh — hence the common name egg fruit. Grafted trees are strongly preferred over seedlings; seedlings may take 5–7 years to fruit and show variable quality, while grafted plants can begin bearing in 2–3 years. The tree is drought-tolerant once established and tolerates a range of well-drained soils but is damaged by temperatures below 32°F even briefly. Harvest when the skin turns fully golden-yellow and yields firmly to pressure; ripen indoors at room temperature for 3–5 days until completely soft and sweet.", "sources": ["California Rare Fruit Growers", "University of Florida IFAS Extension"]}')
