  VALUES ('carambola','Carambola (Starfruit)','Averrhoa carambola','fruit','tropical fruit',NULL,NULL,NULL,NULL,730,1460,'transplant','transplant','perennial','tender','spring',0,8,'Plant grafted trees in spring; young trees need protection from cold and wind for the first two seasons.',10,11,180,240,120,180,120,180,'full','moderate','Plant in well-drained, fertile soil in full sun; carambola is sensitive to flooding and cold below 27°F even briefly, limiting outdoor cultivation to frost-free zones. The tree blooms multiple times per year and produces fruits along the trunk and main branches — a trait called cauliflory — so hang fruit-protection bags in commercial settings to prevent blemishes. Harvest when the ribs have turned fully yellow and the fruit has slight give; overripe fruit browns quickly at the tips. Fertilize with a balanced citrus-type fertilizer 3–4 times per year to sustain heavy bearing.','["University of Florida IFAS Extension", "general horticultural reference"]','{"slug": "carambola", "common_name": "Carambola (Starfruit)", "scientific_name": "Averrhoa carambola", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted trees in spring; young trees need protection from cold and wind for the first two seasons."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 180, "max": 240}, "height_in": {"min": 120, "max": 180}, "spread_in": {"min": 120, "max": 180}, "sun": "full", "water": "moderate", "directions": "Plant in well-drained, fertile soil in full sun; carambola is sensitive to flooding and cold below 27°F even briefly, limiting outdoor cultivation to frost-free zones. The tree blooms multiple times per year and produces fruits along the trunk and main branches — a trait called cauliflory — so hang fruit-protection bags in commercial settings to prevent blemishes. Harvest when the ribs have turned fully yellow and the fruit has slight give; overripe fruit browns quickly at the tips. Fertilize with a balanced citrus-type fertilizer 3–4 times per year to sustain heavy bearing.", "sources": ["University of Florida IFAS Extension", "general horticultural reference"]}')
