  VALUES ('carob','Carob','Ceratonia siliqua','fruit','tree-fruit',14,30,65,85,2555,4380,'transplant','transplant','perennial','half-hardy','last_frost',0,6,'Plant container-grown stock in spring after frost; carob is well-suited to dry Mediterranean-climate zones 9–11 and tolerates alkaline, rocky soils.',9,11,180,360,144,360,144,360,'full','low','Carob is a slow-growing evergreen legume tree that fixes atmospheric nitrogen and thrives in dry, rocky, alkaline soils where few other fruits survive; it is exceptionally drought-tolerant once established. Trees are dioecious — plant one male for every 8–10 female trees, or choose hermaphroditic cultivars such as Santa Fe and Clifford that produce fruit without a separate male. The long, dark-brown seed pods ripen in late summer and fall and are left on the tree to dry and sweeten; they are harvested when fully brown, dry, and the seeds rattle inside. Carob pods are sweet and chocolatey and used ground as a cocoa substitute or in stock feed.','["California Rare Fruit Growers", "general horticultural reference"]','{"slug": "carob", "common_name": "Carob", "scientific_name": "Ceratonia siliqua", "category": "fruit", "subcategory": "tree-fruit", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 2555, "max": 4380}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 6}, "note": "Plant container-grown stock in spring after frost; carob is well-suited to dry Mediterranean-climate zones 9–11 and tolerates alkaline, rocky soils."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 180, "max": 360}, "height_in": {"min": 144, "max": 360}, "spread_in": {"min": 144, "max": 360}, "sun": "full", "water": "low", "directions": "Carob is a slow-growing evergreen legume tree that fixes atmospheric nitrogen and thrives in dry, rocky, alkaline soils where few other fruits survive; it is exceptionally drought-tolerant once established. Trees are dioecious — plant one male for every 8–10 female trees, or choose hermaphroditic cultivars such as Santa Fe and Clifford that produce fruit without a separate male. The long, dark-brown seed pods ripen in late summer and fall and are left on the tree to dry and sweeten; they are harvested when fully brown, dry, and the seeds rattle inside. Carob pods are sweet and chocolatey and used ground as a cocoa substitute or in stock feed.", "sources": ["California Rare Fruit Growers", "general horticultural reference"]}')
