INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cherimoya','Cherimoya','Annona cherimola','fruit','tropical fruit',14,28,65,80,1460,2555,'transplant','transplant','perennial','half-hardy','last_frost',0,8,'Plant grafted trees in spring after frost danger; in coastal California (zone 10a) fall planting before the rainy season is ideal.',9,11,180,300,144,360,144,300,'full','moderate','Cherimoya thrives in California''s coastal valleys where marine influence moderates temperature; it is less suited to the interior heat of zones 9–10a than to the mild, humid coast. Its flowers are protogynous — the stigma is receptive before the pollen is shed — so hand-pollinate by collecting pollen from partially open flowers in the afternoon and transferring it to newly opened receptive flowers in the morning for reliable fruit set. Trees are partially deciduous and shed leaves during dry or cool periods; withhold irrigation slightly during this dormancy to mimic the seasonally dry upland habitat. Harvest when the green skin begins to turn pale or slightly yellowish and the fruit gives under light thumb pressure; ripen at room temperature 3–5 days until soft and fragrant.','["California Rare Fruit Growers", "general horticultural reference"]','{"slug": "cherimoya", "common_name": "Cherimoya", "scientific_name": "Annona cherimola", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 65, "max": 80}, "days_to_maturity": {"min": 1460, "max": 2555}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted trees in spring after frost danger; in coastal California (zone 10a) fall planting before the rainy season is ideal."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 180, "max": 300}, "height_in": {"min": 144, "max": 360}, "spread_in": {"min": 144, "max": 300}, "sun": "full", "water": "moderate", "directions": "Cherimoya thrives in California''s coastal valleys where marine influence moderates temperature; it is less suited to the interior heat of zones 9–10a than to the mild, humid coast. Its flowers are protogynous — the stigma is receptive before the pollen is shed — so hand-pollinate by collecting pollen from partially open flowers in the afternoon and transferring it to newly opened receptive flowers in the morning for reliable fruit set. Trees are partially deciduous and shed leaves during dry or cool periods; withhold irrigation slightly during this dormancy to mimic the seasonally dry upland habitat. Harvest when the green skin begins to turn pale or slightly yellowish and the fruit gives under light thumb pressure; ripen at room temperature 3–5 days until soft and fragrant.", "sources": ["California Rare Fruit Growers", "general horticultural reference"]}')
