  VALUES ('chestnut','Chestnut','Castanea sativa','fruit','nut',NULL,NULL,NULL,NULL,1825,3650,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root trees in early spring; chestnuts strongly prefer acidic, well-drained soil.',5,9,240,480,360,720,300,600,'full','moderate','Chestnuts require cross-pollination between at least two different cultivars or seedlings — plant them within 50 feet of each other for reliable nut set. American chestnut was devastated by blight, so choose blight-resistant Chinese, European, or hybrid selections (such as Dunstan Chestnuts). Trees strongly prefer acidic soils (pH 4.5–6.5) and perform poorly in alkaline or wet conditions. Harvest in fall when burs open and nuts fall; collect daily as nuts on the ground deteriorate quickly. Fresh chestnuts are perishable — refrigerate promptly and use or freeze within a month.','["general horticultural reference"]','{"slug": "chestnut", "common_name": "Chestnut", "scientific_name": "Castanea sativa", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1825, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in early spring; chestnuts strongly prefer acidic, well-drained soil."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 240, "max": 480}, "height_in": {"min": 360, "max": 720}, "spread_in": {"min": 300, "max": 600}, "sun": "full", "water": "moderate", "directions": "Chestnuts require cross-pollination between at least two different cultivars or seedlings — plant them within 50 feet of each other for reliable nut set. American chestnut was devastated by blight, so choose blight-resistant Chinese, European, or hybrid selections (such as Dunstan Chestnuts). Trees strongly prefer acidic soils (pH 4.5–6.5) and perform poorly in alkaline or wet conditions. Harvest in fall when burs open and nuts fall; collect daily as nuts on the ground deteriorate quickly. Fresh chestnuts are perishable — refrigerate promptly and use or freeze within a month.", "sources": ["general horticultural reference"]}')
