  VALUES ('chinkapin','Chinkapin (Golden Chinquapin)','Castanopsis chrysophylla','fruit','nut',NULL,NULL,NULL,NULL,2190,4380,'transplant','transplant','perennial','hardy','spring',-4,2,'Plant container-grown trees in early spring in moist, well-drained, acidic soil; prefers Pacific Northwest conditions.',6,9,240,480,360,960,240,480,'full','moderate','Chinkapin (Castanopsis chrysophylla, also called golden chinquapin) is a large Pacific Coast evergreen related to chestnuts and oaks, bearing small, intensely sweet nuts in spiny burs — often considered the finest-flavored nut native to the Pacific Northwest. Unlike American chestnut it is not susceptible to chestnut blight, making it a valuable blight-free nut tree for western gardeners. Trees are monoecious but require cross-pollination between at least two seedlings or distinct cultivars for reliable nut production; wind and insects both carry pollen. Burs take two years to mature and split open in autumn — collect nuts promptly before squirrels and jays claim the entire crop, and consume or freeze within a month as the small nuts dry out quickly.','["general horticultural reference"]','{"slug": "chinkapin", "common_name": "Chinkapin (Golden Chinquapin)", "scientific_name": "Castanopsis chrysophylla", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 2190, "max": 4380}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 2}, "note": "Plant container-grown trees in early spring in moist, well-drained, acidic soil; prefers Pacific Northwest conditions."}, "usda_zones": {"min": 6, "max": 9}, "spacing_in": {"min": 240, "max": 480}, "height_in": {"min": 360, "max": 960}, "spread_in": {"min": 240, "max": 480}, "sun": "full", "water": "moderate", "directions": "Chinkapin (Castanopsis chrysophylla, also called golden chinquapin) is a large Pacific Coast evergreen related to chestnuts and oaks, bearing small, intensely sweet nuts in spiny burs — often considered the finest-flavored nut native to the Pacific Northwest. Unlike American chestnut it is not susceptible to chestnut blight, making it a valuable blight-free nut tree for western gardeners. Trees are monoecious but require cross-pollination between at least two seedlings or distinct cultivars for reliable nut production; wind and insects both carry pollen. Burs take two years to mature and split open in autumn — collect nuts promptly before squirrels and jays claim the entire crop, and consume or freeze within a month as the small nuts dry out quickly.", "sources": ["general horticultural reference"]}')
