  VALUES ('cocoplum','Cocoplum','Chrysobalanus icaco','fruit','tropical',NULL,NULL,NULL,NULL,1095,1825,'transplant','transplant','perennial','tender','spring',0,8,'Plant in spring in a frost-free site; tolerates salt, flooding, alkaline soils, and sandy coastal conditions.',10,11,60,180,36,180,60,180,'full','moderate','Cocoplum is an extremely adaptable native Florida and Caribbean shrub-tree that tolerates salt spray, periodic flooding, alkaline soils, and full sun — one of the toughest edible landscape plants for coastal south Florida. Plants are self-fertile and fruit reliably as hedges or specimens; the white, pink, or purple oval drupes ripen sporadically through the warm months. The sweet, mildly flavored flesh is eaten fresh or made into jams and jellies; the large oily seed is edible and has a coconut-like flavor when roasted. Harvest when fruit has reached its full color (cream, pink, or deep purple depending on ecotype) and is soft to the touch.','["general horticultural reference"]','{"slug": "cocoplum", "common_name": "Cocoplum", "scientific_name": "Chrysobalanus icaco", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant in spring in a frost-free site; tolerates salt, flooding, alkaline soils, and sandy coastal conditions."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 60, "max": 180}, "height_in": {"min": 36, "max": 180}, "spread_in": {"min": 60, "max": 180}, "sun": "full", "water": "moderate", "directions": "Cocoplum is an extremely adaptable native Florida and Caribbean shrub-tree that tolerates salt spray, periodic flooding, alkaline soils, and full sun — one of the toughest edible landscape plants for coastal south Florida. Plants are self-fertile and fruit reliably as hedges or specimens; the white, pink, or purple oval drupes ripen sporadically through the warm months. The sweet, mildly flavored flesh is eaten fresh or made into jams and jellies; the large oily seed is edible and has a coconut-like flavor when roasted. Harvest when fruit has reached its full color (cream, pink, or deep purple depending on ecotype) and is soft to the touch.", "sources": ["general horticultural reference"]}')
