INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('common-guava','Common Guava','Psidium guajava','fruit','tropical fruit',14,28,70,85,730,1460,'transplant','transplant','perennial','tender','last_frost',0,8,'Plant grafted or container-grown trees in spring after all frost risk has passed; in frost-free zones fall planting avoids summer heat stress.',9,11,144,216,96,240,96,216,'full','moderate','Guava is self-fertile and productive as a single tree; grafted selections of known cultivars (Ruby Supreme, Thai White) are superior to seedlings for flavor and bearing consistency. Trees tolerate a wide range of soils but are sensitive to standing water and prolonged frost — temperatures below 28°F damage foliage and below 24°F kill established trunks. Prune annually to 10–12 ft to simplify harvest and improve light penetration; guava bears on new growth so heading-back encourages productivity. Harvest when the skin softens, the color shifts from green to yellow or pink, and the fruit is intensely fragrant.','["general horticultural reference", "University of Florida IFAS Extension"]','{"slug": "common-guava", "common_name": "Common Guava", "scientific_name": "Psidium guajava", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 730, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted or container-grown trees in spring after all frost risk has passed; in frost-free zones fall planting avoids summer heat stress."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 144, "max": 216}, "height_in": {"min": 96, "max": 240}, "spread_in": {"min": 96, "max": 216}, "sun": "full", "water": "moderate", "directions": "Guava is self-fertile and productive as a single tree; grafted selections of known cultivars (Ruby Supreme, Thai White) are superior to seedlings for flavor and bearing consistency. Trees tolerate a wide range of soils but are sensitive to standing water and prolonged frost — temperatures below 28°F damage foliage and below 24°F kill established trunks. Prune annually to 10–12 ft to simplify harvest and improve light penetration; guava bears on new growth so heading-back encourages productivity. Harvest when the skin softens, the color shifts from green to yellow or pink, and the fruit is intensely fragrant.", "sources": ["general horticultural reference", "University of Florida IFAS Extension"]}')
