  VALUES ('cornelian-cherry','Cornelian Cherry','Cornus mas','fruit','drupe',NULL,NULL,NULL,NULL,1460,2190,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root or container stock in late winter to early spring before bud break; fall planting also works in zones 5–7.',4,8,120,240,120,240,120,240,'full','low','Cornelian cherry is one of the earliest-blooming woody plants — small yellow flowers appear in late winter before the leaves — and the small, olive-shaped drupes ripen in late summer to a rich ruby red. Plant at least two seedlings or cultivars for best fruit set, as it is partially self-fertile but cross-pollination greatly improves yields. The tree is extremely cold-hardy and tolerates drought, alkaline soils, and urban pollution once established. Harvest when fruit is fully dark red and slightly soft; it is too tart to eat out of hand but makes outstanding preserves, syrups, and fruit leather.','["general horticultural reference"]','{"slug": "cornelian-cherry", "common_name": "Cornelian Cherry", "scientific_name": "Cornus mas", "category": "fruit", "subcategory": "drupe", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root or container stock in late winter to early spring before bud break; fall planting also works in zones 5–7."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 120, "max": 240}, "height_in": {"min": 120, "max": 240}, "spread_in": {"min": 120, "max": 240}, "sun": "full", "water": "low", "directions": "Cornelian cherry is one of the earliest-blooming woody plants — small yellow flowers appear in late winter before the leaves — and the small, olive-shaped drupes ripen in late summer to a rich ruby red. Plant at least two seedlings or cultivars for best fruit set, as it is partially self-fertile but cross-pollination greatly improves yields. The tree is extremely cold-hardy and tolerates drought, alkaline soils, and urban pollution once established. Harvest when fruit is fully dark red and slightly soft; it is too tart to eat out of hand but makes outstanding preserves, syrups, and fruit leather.", "sources": ["general horticultural reference"]}')
