INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('date-palm','Date Palm','Phoenix dactylifera','fruit','tropical fruit',21,60,75,95,2190,3650,'transplant','transplant','perennial','half-hardy','last_frost',0,8,'Plant offshoots or container stock in spring when the soil is warm; dates require the specific combination of desert heat and dry air to ripen properly.',8,11,180,360,480,1080,120,240,'full','low','Dates are dioecious — you need a male tree to pollinate female trees, with one male sufficient for up to 50 females; commercial growers hand-pollinate by shaking male flower strands over female inflorescences in spring. Ripe dates require extremely hot, dry summers (110°F daytime heat preferred) with very low humidity during the ripening period — this limits quality fruit production in the continental U.S. almost entirely to the Coachella Valley and low desert Arizona. Offshoots from the base of female palms are the preferred planting material as they preserve the sex and fruit type of the parent; seed-grown palms yield 50% males and highly variable fruit. Harvest in fall when fruit reaches the desired stage: khalal (crisp, astringent), rutab (partly soft, sweet), or tamr (fully dried).','["UC Cooperative Extension Riverside County", "general horticultural reference"]','{"slug": "date-palm", "common_name": "Date Palm", "scientific_name": "Phoenix dactylifera", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 21, "max": 60}, "germination_soil_temp_f": {"min": 75, "max": 95}, "days_to_maturity": {"min": 2190, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant offshoots or container stock in spring when the soil is warm; dates require the specific combination of desert heat and dry air to ripen properly."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 180, "max": 360}, "height_in": {"min": 480, "max": 1080}, "spread_in": {"min": 120, "max": 240}, "sun": "full", "water": "low", "directions": "Dates are dioecious — you need a male tree to pollinate female trees, with one male sufficient for up to 50 females; commercial growers hand-pollinate by shaking male flower strands over female inflorescences in spring. Ripe dates require extremely hot, dry summers (110°F daytime heat preferred) with very low humidity during the ripening period — this limits quality fruit production in the continental U.S. almost entirely to the Coachella Valley and low desert Arizona. Offshoots from the base of female palms are the preferred planting material as they preserve the sex and fruit type of the parent; seed-grown palms yield 50% males and highly variable fruit. Harvest in fall when fruit reaches the desired stage: khalal (crisp, astringent), rutab (partly soft, sweet), or tamr (fully dried).", "sources": ["UC Cooperative Extension Riverside County", "general horticultural reference"]}')
