INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('durian','Durian','Durio zibethinus','fruit','tropical',NULL,NULL,NULL,NULL,1825,3650,'transplant','transplant','perennial','tender','spring',0,8,'Plant grafted trees in spring in a humid, frost-free tropical climate; durian requires consistent warmth above 50°F.',11,11,360,600,360,960,240,480,'full','high','Durian demands deep, fertile, well-drained soil, high humidity, and temperatures between 75°F and 95°F year-round; it is the most climate-specific of the major tropical fruits and can only be grown outdoors in the most tropical parts of the continental United States (extreme south Florida). Flowers open at night and are primarily bat-pollinated, so maintain nearby native habitat and avoid pesticide applications at dusk; hand-pollination improves set in enclosed settings. Fruit develops over 3–5 months and the spiny husk is potentially dangerous — trees should be netted and fruit harvested from the ground after it falls naturally. The ripe flesh has a rich custard flavor with a pungent sulfurous aroma that intensifies rapidly after harvest; consume or freeze within 24–48 hours.','["general horticultural reference"]','{"slug": "durian", "common_name": "Durian", "scientific_name": "Durio zibethinus", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1825, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted trees in spring in a humid, frost-free tropical climate; durian requires consistent warmth above 50°F."}, "usda_zones": {"min": 11, "max": 11}, "spacing_in": {"min": 360, "max": 600}, "height_in": {"min": 360, "max": 960}, "spread_in": {"min": 240, "max": 480}, "sun": "full", "water": "high", "directions": "Durian demands deep, fertile, well-drained soil, high humidity, and temperatures between 75°F and 95°F year-round; it is the most climate-specific of the major tropical fruits and can only be grown outdoors in the most tropical parts of the continental United States (extreme south Florida). Flowers open at night and are primarily bat-pollinated, so maintain nearby native habitat and avoid pesticide applications at dusk; hand-pollination improves set in enclosed settings. Fruit develops over 3–5 months and the spiny husk is potentially dangerous — trees should be netted and fruit harvested from the ground after it falls naturally. The ripe flesh has a rich custard flavor with a pungent sulfurous aroma that intensifies rapidly after harvest; consume or freeze within 24–48 hours.", "sources": ["general horticultural reference"]}')
