  VALUES ('fig','Fig','Ficus carica','fruit','syconium fruit',NULL,NULL,NULL,NULL,730,1460,'transplant','transplant','perennial','tender','last_frost',0,4,'Plant container or bare-root figs after the last frost date when soil has warmed; in mild climates, fall planting works well.',7,11,120,240,72,240,96,240,'full','low','Common figs (the type grown in most gardens) are parthenocarpic and self-fertile — no pollinator or fig wasp is needed. In zones 6–7 protect the trunk and lower branches over winter by wrapping with burlap or mounding mulch; established roots often resprout even after top-kill. Figs bear two crops on some cultivars: a small breba crop on old wood in early summer and a main crop on new growth in late summer. Harvest when the neck droops, the skin splits slightly, and the fruit is soft and fragrant; a drop of syrup at the eye signals perfect ripeness.','["general horticultural reference"]','{"slug": "fig", "common_name": "Fig", "scientific_name": "Ficus carica", "category": "fruit", "subcategory": "syconium fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant container or bare-root figs after the last frost date when soil has warmed; in mild climates, fall planting works well."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 120, "max": 240}, "height_in": {"min": 72, "max": 240}, "spread_in": {"min": 96, "max": 240}, "sun": "full", "water": "low", "directions": "Common figs (the type grown in most gardens) are parthenocarpic and self-fertile — no pollinator or fig wasp is needed. In zones 6–7 protect the trunk and lower branches over winter by wrapping with burlap or mounding mulch; established roots often resprout even after top-kill. Figs bear two crops on some cultivars: a small breba crop on old wood in early summer and a main crop on new growth in late summer. Harvest when the neck droops, the skin splits slightly, and the fruit is soft and fragrant; a drop of syrup at the eye signals perfect ripeness.", "sources": ["general horticultural reference"]}')
