  VALUES ('finger-lime','Finger Lime (Caviar Lime)','Microcitrus australasica','fruit','citrus',NULL,NULL,NULL,NULL,1460,2920,'transplant','transplant','perennial','half-hardy','last_frost',0,6,'Plant grafted trees in spring; finger lime tolerates brief frosts to about 22–25°F once established.',8,11,60,120,60,144,60,120,'full','moderate','Finger lime is an Australian rainforest citrus producing cylindrical finger-length fruits filled with spherical pulp vesicles that burst on the palate like caviar — highly prized in fine dining as a garnish. Grafted trees are strongly preferred over seedlings, which are slow to fruit and thorny; grafted plants begin fruiting in 2–3 years and are more manageable in size. The tree is self-fertile and does not require a pollinator; it performs well in containers and espalier forms. Fruit ripens in late autumn through winter; harvest when the skin (green, yellow, red, or black depending on variety) is fully colored and the fruit releases easily with gentle pressure — avoid overripening, as the vesicles lose their pop.','["general horticultural reference"]','{"slug": "finger-lime", "common_name": "Finger Lime (Caviar Lime)", "scientific_name": "Microcitrus australasica", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2920}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 6}, "note": "Plant grafted trees in spring; finger lime tolerates brief frosts to about 22–25°F once established."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 60, "max": 120}, "height_in": {"min": 60, "max": 144}, "spread_in": {"min": 60, "max": 120}, "sun": "full", "water": "moderate", "directions": "Finger lime is an Australian rainforest citrus producing cylindrical finger-length fruits filled with spherical pulp vesicles that burst on the palate like caviar — highly prized in fine dining as a garnish. Grafted trees are strongly preferred over seedlings, which are slow to fruit and thorny; grafted plants begin fruiting in 2–3 years and are more manageable in size. The tree is self-fertile and does not require a pollinator; it performs well in containers and espalier forms. Fruit ripens in late autumn through winter; harvest when the skin (green, yellow, red, or black depending on variety) is fully colored and the fruit releases easily with gentle pressure — avoid overripening, as the vesicles lose their pop.", "sources": ["general horticultural reference"]}')
