  VALUES ('gac-fruit','Gac Fruit','Momordica cochinchinensis','fruit','tropical',14,28,75,90,120,180,'transplant','transplant','perennial','tender','last_frost',0,4,'Plant tuber divisions or started plants after last frost; provide a strong trellis — vines reach 30 feet.',9,11,72,120,120,360,96,180,'full','moderate','Gac is a vigorous, tuberous-rooted perennial vine in the cucumber family that regrows each year from a starchy tuber in zones 9–11 and can be grown as an annual elsewhere; it requires a sturdy trellis or fence. Plants are dioecious, so grow at least one male and several female plants together; bees transfer pollen between the separate male and female flowers. The football-sized, brilliant orange-red fruit is among the richest known sources of lycopene and beta-carotene; the red aril surrounding the seeds is the edible portion, traditionally mixed into Vietnamese sticky rice (xôi gấc). Harvest when the skin is fully orange-red and the surface texture softens from spiny to smooth; fruit is mature approximately 4–5 months after planting.','["general horticultural reference"]','{"slug": "gac-fruit", "common_name": "Gac Fruit", "scientific_name": "Momordica cochinchinensis", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 75, "max": 90}, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant tuber divisions or started plants after last frost; provide a strong trellis — vines reach 30 feet."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 72, "max": 120}, "height_in": {"min": 120, "max": 360}, "spread_in": {"min": 96, "max": 180}, "sun": "full", "water": "moderate", "directions": "Gac is a vigorous, tuberous-rooted perennial vine in the cucumber family that regrows each year from a starchy tuber in zones 9–11 and can be grown as an annual elsewhere; it requires a sturdy trellis or fence. Plants are dioecious, so grow at least one male and several female plants together; bees transfer pollen between the separate male and female flowers. The football-sized, brilliant orange-red fruit is among the richest known sources of lycopene and beta-carotene; the red aril surrounding the seeds is the edible portion, traditionally mixed into Vietnamese sticky rice (xôi gấc). Harvest when the skin is fully orange-red and the surface texture softens from spiny to smooth; fruit is mature approximately 4–5 months after planting.", "sources": ["general horticultural reference"]}')
