INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ginkgo','Ginkgo (Maidenhair Tree)','Ginkgo biloba','fruit','nut',NULL,NULL,NULL,NULL,2920,5475,'transplant','transplant','perennial','hardy','spring',-4,2,'Plant bare-root or container-grown trees in early spring; site male trees downwind of living areas to avoid the malodorous female fruit.',3,9,240,480,360,960,240,480,'full','moderate','Ginkgo is dioecious — only female trees produce the edible nut, but a male is needed nearby for pollination; purchase named female cultivars (Tit, Megi, Oishi) or graft known female wood to avoid planting only males, which cannot be sexed until first flower at 20+ years. The outer fleshy seed coat (sarcotesta) smells powerfully of rancid butter when ripe and contains urushiol-related compounds — wear gloves when handling and process outdoors; the inner cream-colored nut inside the hard shell is the edible portion. Harvest when the fleshy coating has turned yellow-orange and fallen from the tree in autumn; clean immediately, dry the shells, and roast or steam before eating. Do not eat ginkgo nuts raw or in excessive quantities — they contain 4-O-methylpyridoxine, which is toxic in large amounts.','["general horticultural reference"]','{"slug": "ginkgo", "common_name": "Ginkgo (Maidenhair Tree)", "scientific_name": "Ginkgo biloba", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 2920, "max": 5475}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 2}, "note": "Plant bare-root or container-grown trees in early spring; site male trees downwind of living areas to avoid the malodorous female fruit."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 240, "max": 480}, "height_in": {"min": 360, "max": 960}, "spread_in": {"min": 240, "max": 480}, "sun": "full", "water": "moderate", "directions": "Ginkgo is dioecious — only female trees produce the edible nut, but a male is needed nearby for pollination; purchase named female cultivars (Tit, Megi, Oishi) or graft known female wood to avoid planting only males, which cannot be sexed until first flower at 20+ years. The outer fleshy seed coat (sarcotesta) smells powerfully of rancid butter when ripe and contains urushiol-related compounds — wear gloves when handling and process outdoors; the inner cream-colored nut inside the hard shell is the edible portion. Harvest when the fleshy coating has turned yellow-orange and fallen from the tree in autumn; clean immediately, dry the shells, and roast or steam before eating. Do not eat ginkgo nuts raw or in excessive quantities — they contain 4-O-methylpyridoxine, which is toxic in large amounts.", "sources": ["general horticultural reference"]}')
