  VALUES ('heartnut','Heartnut','Juglans ailantifolia var. cordiformis','fruit','nut',NULL,NULL,NULL,NULL,1460,2920,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root or container stock in early spring; heartnut adapts to a wide range of soils and is one of the most productive walnuts for northern growers.',5,8,240,480,240,600,240,480,'full','moderate','Heartnut is a variety of Japanese walnut bearing distinctively heart-shaped nuts that crack open cleanly along a suture to release a whole kernel — unlike black walnut, which requires significant effort to extract meat. Trees are monoecious and partially self-fertile but yield better with a second tree; they begin bearing in 4–7 years from grafted stock. Heartnut is notably less allelopathic than black walnut, making it more garden-friendly as a specimen tree. Nuts fall in clusters in late summer to early fall; hull and dry for 2–3 weeks before cracking and storing.','["general horticultural reference", "Northern Nut Growers Association"]','{"slug": "heartnut", "common_name": "Heartnut", "scientific_name": "Juglans ailantifolia var. cordiformis", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2920}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root or container stock in early spring; heartnut adapts to a wide range of soils and is one of the most productive walnuts for northern growers."}, "usda_zones": {"min": 5, "max": 8}, "spacing_in": {"min": 240, "max": 480}, "height_in": {"min": 240, "max": 600}, "spread_in": {"min": 240, "max": 480}, "sun": "full", "water": "moderate", "directions": "Heartnut is a variety of Japanese walnut bearing distinctively heart-shaped nuts that crack open cleanly along a suture to release a whole kernel — unlike black walnut, which requires significant effort to extract meat. Trees are monoecious and partially self-fertile but yield better with a second tree; they begin bearing in 4–7 years from grafted stock. Heartnut is notably less allelopathic than black walnut, making it more garden-friendly as a specimen tree. Nuts fall in clusters in late summer to early fall; hull and dry for 2–3 weeks before cracking and storing.", "sources": ["general horticultural reference", "Northern Nut Growers Association"]}')
