  VALUES ('ilama','Ilama','Annona diversifolia','fruit','tropical',NULL,NULL,NULL,NULL,1825,2920,'transplant','transplant','perennial','tender','spring',0,8,'Plant grafted trees in spring in a frost-free setting with a distinct dry season to stimulate bloom.',10,11,180,300,120,360,120,240,'full','moderate','Ilama is a semi-deciduous Annona from Mexico and Central America that tolerates drier conditions than most of its relatives, preferring a pronounced dry season to trigger leaf drop and subsequent flowering. Like other Annonaceae, flowers are protogynous and benefit strongly from hand-pollination — collect pollen in the afternoon from half-closed male-stage flowers and dab onto receptive stigmas of newly opened female-stage flowers in the morning. Fruit comes in pink-fleshed and white-fleshed strains; the pink-fleshed type has a slightly acidic flavor while the white is sweeter and more custard-like. Harvest when the skin has slightly separated at the segment lines and the fruit gives to gentle pressure; shelf life at room temperature is only 1–2 days.','["general horticultural reference"]','{"slug": "ilama", "common_name": "Ilama", "scientific_name": "Annona diversifolia", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1825, "max": 2920}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted trees in spring in a frost-free setting with a distinct dry season to stimulate bloom."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 180, "max": 300}, "height_in": {"min": 120, "max": 360}, "spread_in": {"min": 120, "max": 240}, "sun": "full", "water": "moderate", "directions": "Ilama is a semi-deciduous Annona from Mexico and Central America that tolerates drier conditions than most of its relatives, preferring a pronounced dry season to trigger leaf drop and subsequent flowering. Like other Annonaceae, flowers are protogynous and benefit strongly from hand-pollination — collect pollen in the afternoon from half-closed male-stage flowers and dab onto receptive stigmas of newly opened female-stage flowers in the morning. Fruit comes in pink-fleshed and white-fleshed strains; the pink-fleshed type has a slightly acidic flavor while the white is sweeter and more custard-like. Harvest when the skin has slightly separated at the segment lines and the fruit gives to gentle pressure; shelf life at room temperature is only 1–2 days.", "sources": ["general horticultural reference"]}')
