  VALUES ('jaboticaba','Jaboticaba','Plinia cauliflora','fruit','tropical fruit',20,40,75,85,2920,5475,'transplant','transplant','perennial','tender','last_frost',0,8,'Plant container-grown stock in spring after all frost risk passes; jaboticaba is extremely slow-growing and may take 8–15 years from seed to first fruit.',9,11,120,240,96,360,96,240,'full','moderate','Jaboticaba produces grape-like berries directly on its trunk and main branches (cauliflory) in dramatic clusters; the fruit ripens just 20–25 days after flowering and can bear several times per year in frost-free climates. It is self-fertile and requires well-drained, slightly acidic soil (pH 5.0–6.5); chlorosis is common in alkaline soils and can be corrected with chelated iron and sulfur. Trees are slow-growing, making them well-suited to container culture where they can be overwintered in zone 8 or moved under frost protection. Harvest berries when they are entirely deep purple-black, soft, and sweet-tart — they ferment within 3–4 days at room temperature, so refrigerate or process promptly.','["general horticultural reference", "University of Florida IFAS Extension"]','{"slug": "jaboticaba", "common_name": "Jaboticaba", "scientific_name": "Plinia cauliflora", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 20, "max": 40}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 2920, "max": 5475}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant container-grown stock in spring after all frost risk passes; jaboticaba is extremely slow-growing and may take 8–15 years from seed to first fruit."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 120, "max": 240}, "height_in": {"min": 96, "max": 360}, "spread_in": {"min": 96, "max": 240}, "sun": "full", "water": "moderate", "directions": "Jaboticaba produces grape-like berries directly on its trunk and main branches (cauliflory) in dramatic clusters; the fruit ripens just 20–25 days after flowering and can bear several times per year in frost-free climates. It is self-fertile and requires well-drained, slightly acidic soil (pH 5.0–6.5); chlorosis is common in alkaline soils and can be corrected with chelated iron and sulfur. Trees are slow-growing, making them well-suited to container culture where they can be overwintered in zone 8 or moved under frost protection. Harvest berries when they are entirely deep purple-black, soft, and sweet-tart — they ferment within 3–4 days at room temperature, so refrigerate or process promptly.", "sources": ["general horticultural reference", "University of Florida IFAS Extension"]}')
