  VALUES ('jackfruit','Jackfruit','Artocarpus heterophyllus','fruit','tropical',NULL,NULL,NULL,NULL,1095,1825,'transplant','transplant','perennial','tender','spring',0,8,'Plant grafted or container-grown trees in spring in frost-free zones; jackfruit is damaged below 35°F.',10,11,240,480,240,600,240,480,'full','moderate','Plant in well-drained, deep soil — jackfruit is intolerant of waterlogged roots — in full sun with adequate space, as trees can reach 40–50 feet and produce fruit directly on the trunk and main branches (cauliflory). Trees are monoecious, with separate male and female flowers on the same tree, so a single tree can fruit, though planting two improves yields. Fruit can weigh up to 100 lbs; support developing fruit with a rope sling tied to a branch when they are the size of a cantaloupe. Harvest when the skin changes from green to yellowish-brown and the fruit emits a strong sweet aroma; immature fruit is used as a vegetable and ripe fruit eaten fresh or processed.','["general horticultural reference"]','{"slug": "jackfruit", "common_name": "Jackfruit", "scientific_name": "Artocarpus heterophyllus", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted or container-grown trees in spring in frost-free zones; jackfruit is damaged below 35°F."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 240, "max": 480}, "height_in": {"min": 240, "max": 600}, "spread_in": {"min": 240, "max": 480}, "sun": "full", "water": "moderate", "directions": "Plant in well-drained, deep soil — jackfruit is intolerant of waterlogged roots — in full sun with adequate space, as trees can reach 40–50 feet and produce fruit directly on the trunk and main branches (cauliflory). Trees are monoecious, with separate male and female flowers on the same tree, so a single tree can fruit, though planting two improves yields. Fruit can weigh up to 100 lbs; support developing fruit with a rope sling tied to a branch when they are the size of a cantaloupe. Harvest when the skin changes from green to yellowish-brown and the fruit emits a strong sweet aroma; immature fruit is used as a vegetable and ripe fruit eaten fresh or processed.", "sources": ["general horticultural reference"]}')
