  VALUES ('jelly-palm','Jelly Palm (Pindo Palm)','Butia capitata','fruit','palm',NULL,NULL,NULL,NULL,1825,3650,'transplant','transplant','perennial','half-hardy','spring',0,8,'Plant container-grown palms in spring after frost; avoid disturbing the root ball during transplanting.',8,11,144,240,120,240,120,180,'full','low','Jelly palm is one of the hardiest fruiting palms, surviving temperatures down to 12–15°F, and is well-suited to zones 8–11 in well-drained soils ranging from sandy to clay. The tree is monoecious, with male and female flowers on the same large branched inflorescence, so a single specimen fruits reliably without a pollinator. It produces abundant clusters of small orange-yellow drupes in summer; the sweet-tart pulp is rich in pectin and classically used for jelly, wine, and preserves. Allow fruit to fall naturally or gently shake clusters when most fruit has colored; process quickly as the thin-skinned fruit ferments rapidly after harvest.','["general horticultural reference"]','{"slug": "jelly-palm", "common_name": "Jelly Palm (Pindo Palm)", "scientific_name": "Butia capitata", "category": "fruit", "subcategory": "palm", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1825, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant container-grown palms in spring after frost; avoid disturbing the root ball during transplanting."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 144, "max": 240}, "height_in": {"min": 120, "max": 240}, "spread_in": {"min": 120, "max": 180}, "sun": "full", "water": "low", "directions": "Jelly palm is one of the hardiest fruiting palms, surviving temperatures down to 12–15°F, and is well-suited to zones 8–11 in well-drained soils ranging from sandy to clay. The tree is monoecious, with male and female flowers on the same large branched inflorescence, so a single specimen fruits reliably without a pollinator. It produces abundant clusters of small orange-yellow drupes in summer; the sweet-tart pulp is rich in pectin and classically used for jelly, wine, and preserves. Allow fruit to fall naturally or gently shake clusters when most fruit has colored; process quickly as the thin-skinned fruit ferments rapidly after harvest.", "sources": ["general horticultural reference"]}')
