  VALUES ('jujube','Jujube','Ziziphus jujuba','fruit','drupe',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','hardy','last_frost',0,4,'Plant in spring after the last frost date; jujubes establish quickly in warm soil.',6,11,120,240,120,360,96,240,'full','low','Jujube is exceptionally drought-tolerant and thrives in hot, dry climates where other fruits struggle; it prefers well-drained, even sandy soils and performs poorly with excessive moisture. Most cultivars are self-fertile, though a second variety increases yields. Li and Lang are the most widely planted in North America; Li produces large, round, date-like fruit while Lang is more elongated. Fruit is eaten fresh when crisp and apple-flavored or dried to a sweet, wrinkled date; harvest when skin turns from yellow-green to mahogany-red.','["general horticultural reference"]','{"slug": "jujube", "common_name": "Jujube", "scientific_name": "Ziziphus jujuba", "category": "fruit", "subcategory": "drupe", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring after the last frost date; jujubes establish quickly in warm soil."}, "usda_zones": {"min": 6, "max": 11}, "spacing_in": {"min": 120, "max": 240}, "height_in": {"min": 120, "max": 360}, "spread_in": {"min": 96, "max": 240}, "sun": "full", "water": "low", "directions": "Jujube is exceptionally drought-tolerant and thrives in hot, dry climates where other fruits struggle; it prefers well-drained, even sandy soils and performs poorly with excessive moisture. Most cultivars are self-fertile, though a second variety increases yields. Li and Lang are the most widely planted in North America; Li produces large, round, date-like fruit while Lang is more elongated. Fruit is eaten fresh when crisp and apple-flavored or dried to a sweet, wrinkled date; harvest when skin turns from yellow-green to mahogany-red.", "sources": ["general horticultural reference"]}')
