INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('key-lime','Key Lime','Citrus aurantiifolia','fruit','citrus',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','tender','last_frost',2,8,'Plant in spring after all frost risk has passed; key lime is the most cold-sensitive common citrus and is suitable only for zones 10–11 in the ground.',10,11,72,144,72,180,72,144,'full','moderate','Key lime is a small, thorny tree distinct from the larger Persian lime (Citrus latifolia) — its fruit is smaller, more aromatic, more acidic, and nearly seedless at full yellow ripeness. It is self-fertile and bears prolifically in truly tropical conditions; the tree is damaged by any frost and requires zone 10–11 for outdoor culture, though it adapts well to large containers for zone 9 growers who can move it inside. Harvest fruit while still light green to yellow-green, before it turns fully yellow; yellow fruit is riper and less acid but also more perishable. Apply citrus fertilizer three times per year and ensure excellent drainage to prevent root rot.','["University of Florida IFAS Extension", "general horticultural reference"]','{"slug": "key-lime", "common_name": "Key Lime", "scientific_name": "Citrus aurantiifolia", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant in spring after all frost risk has passed; key lime is the most cold-sensitive common citrus and is suitable only for zones 10–11 in the ground."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 72, "max": 144}, "height_in": {"min": 72, "max": 180}, "spread_in": {"min": 72, "max": 144}, "sun": "full", "water": "moderate", "directions": "Key lime is a small, thorny tree distinct from the larger Persian lime (Citrus latifolia) — its fruit is smaller, more aromatic, more acidic, and nearly seedless at full yellow ripeness. It is self-fertile and bears prolifically in truly tropical conditions; the tree is damaged by any frost and requires zone 10–11 for outdoor culture, though it adapts well to large containers for zone 9 growers who can move it inside. Harvest fruit while still light green to yellow-green, before it turns fully yellow; yellow fruit is riper and less acid but also more perishable. Apply citrus fertilizer three times per year and ensure excellent drainage to prevent root rot.", "sources": ["University of Florida IFAS Extension", "general horticultural reference"]}')
