  VALUES ('korean-pine','Korean Pine (Pine Nut)','Pinus koraiensis','fruit','nut',30,90,40,65,3650,7300,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant in early spring before bud break; Korean pine is a cold-hardy alternative to Stone pine for producing large, commercially sized pine nuts in the northern U.S.',3,7,240,480,360,900,240,480,'full','moderate','Korean pine is a large, ornamental five-needle pine that produces the large, wingless pine nuts commonly sold in Asian markets — seeds are bigger than those of Italian stone pine and have a rich, buttery flavor. Trees are monoecious and bear cones that ripen over two growing seasons; significant cone production typically begins at 15–25 years from seed. Cones are harvested in early autumn when the scales begin to separate; spread cones on tarps to dry and then beat or tumble to dislodge seeds. The outer seed coat must be cracked to access the edible kernel, which is high in oil and should be refrigerated or frozen to prevent rancidity.','["general horticultural reference", "Northern Nut Growers Association"]','{"slug": "korean-pine", "common_name": "Korean Pine (Pine Nut)", "scientific_name": "Pinus koraiensis", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": 30, "max": 90}, "germination_soil_temp_f": {"min": 40, "max": 65}, "days_to_maturity": {"min": 3650, "max": 7300}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant in early spring before bud break; Korean pine is a cold-hardy alternative to Stone pine for producing large, commercially sized pine nuts in the northern U.S."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 240, "max": 480}, "height_in": {"min": 360, "max": 900}, "spread_in": {"min": 240, "max": 480}, "sun": "full", "water": "moderate", "directions": "Korean pine is a large, ornamental five-needle pine that produces the large, wingless pine nuts commonly sold in Asian markets — seeds are bigger than those of Italian stone pine and have a rich, buttery flavor. Trees are monoecious and bear cones that ripen over two growing seasons; significant cone production typically begins at 15–25 years from seed. Cones are harvested in early autumn when the scales begin to separate; spread cones on tarps to dry and then beat or tumble to dislodge seeds. The outer seed coat must be cracked to access the edible kernel, which is high in oil and should be refrigerated or frozen to prevent rancidity.", "sources": ["general horticultural reference", "Northern Nut Growers Association"]}')
