  VALUES ('lemon','Lemon','Citrus limon','fruit','citrus',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','tender','last_frost',2,8,'Plant in spring after frost risk has passed; in frost-free zones plant any time but avoid midsummer planting.',9,11,120,216,96,216,96,192,'full','moderate','Lemons are self-fertile and can bloom and fruit year-round in frost-free climates; Eureka and Lisbon are the commercial standards, while Meyer lemon is hardier (damaged below 22°F) and better suited to containers in cooler climates. Plant in well-drained, slightly acidic soil and fertilize with citrus-specific fertilizer three times per year. In zones 8–9, grow in large containers and bring indoors when temperatures drop below 28°F. Fruit is ready when fully yellow, slightly soft, and the rind is thin — do not wait for it to fall off the tree.','["general horticultural reference"]','{"slug": "lemon", "common_name": "Lemon", "scientific_name": "Citrus limon", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant in spring after frost risk has passed; in frost-free zones plant any time but avoid midsummer planting."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 120, "max": 216}, "height_in": {"min": 96, "max": 216}, "spread_in": {"min": 96, "max": 192}, "sun": "full", "water": "moderate", "directions": "Lemons are self-fertile and can bloom and fruit year-round in frost-free climates; Eureka and Lisbon are the commercial standards, while Meyer lemon is hardier (damaged below 22°F) and better suited to containers in cooler climates. Plant in well-drained, slightly acidic soil and fertilize with citrus-specific fertilizer three times per year. In zones 8–9, grow in large containers and bring indoors when temperatures drop below 28°F. Fruit is ready when fully yellow, slightly soft, and the rind is thin — do not wait for it to fall off the tree.", "sources": ["general horticultural reference"]}')
