  VALUES ('limequat','Limequat','Citrus x floridana','fruit','citrus',NULL,NULL,NULL,NULL,1095,1825,'transplant','transplant','perennial','half-hardy','last_frost',2,8,'Plant grafted trees in spring; limequat''s kumquat parentage gives it excellent cold tolerance for a lime-flavored citrus.',8,11,48,96,48,96,48,96,'full','moderate','Limequat is a Key lime × kumquat hybrid combining the intense lime flavor of Citrus aurantiifolia with the cold hardiness of Fortunella, tolerating temperatures down to about 20°F — the hardiest of the lime-flavored citrus. Like kumquat, the entire fruit — sweet edible peel and sour juice pulp together — can be eaten whole or sliced into drinks and salads. Trees are self-fertile, compact, and well-suited to container culture in zones 7–8, where they can be moved indoors during hard freezes. The small oval to round fruits ripen from green to yellow in autumn through winter; harvest when fully yellow for the sweetest peel, or use while still green for the most intense lime flavor.','["general horticultural reference"]','{"slug": "limequat", "common_name": "Limequat", "scientific_name": "Citrus x floridana", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant grafted trees in spring; limequat''s kumquat parentage gives it excellent cold tolerance for a lime-flavored citrus."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 48, "max": 96}, "height_in": {"min": 48, "max": 96}, "spread_in": {"min": 48, "max": 96}, "sun": "full", "water": "moderate", "directions": "Limequat is a Key lime × kumquat hybrid combining the intense lime flavor of Citrus aurantiifolia with the cold hardiness of Fortunella, tolerating temperatures down to about 20°F — the hardiest of the lime-flavored citrus. Like kumquat, the entire fruit — sweet edible peel and sour juice pulp together — can be eaten whole or sliced into drinks and salads. Trees are self-fertile, compact, and well-suited to container culture in zones 7–8, where they can be moved indoors during hard freezes. The small oval to round fruits ripen from green to yellow in autumn through winter; harvest when fully yellow for the sweetest peel, or use while still green for the most intense lime flavor.", "sources": ["general horticultural reference"]}')
