  VALUES ('longan','Longan','Dimocarpus longan','fruit','tropical fruit',NULL,NULL,NULL,NULL,1095,1825,'transplant','transplant','perennial','tender','spring',0,8,'Plant grafted trees after all cold weather has passed; young trees are cold-sensitive and need protection until the trunk is well established.',10,11,240,360,240,360,180,300,'full','moderate','Plant grafted trees in deep, well-drained, slightly acidic soil (pH 5.5–6.5) in full sun; longan will not tolerate standing water or saturated roots. A brief winter cool-dry period — temperatures in the mid-40s°F for several weeks — is essential to trigger reliable flowering, making coastal south Florida and extreme south Texas the two viable zones in the continental United States. Fruit clusters ripen in summer and should be harvested by cutting whole panicles with scissors when the skin turns tan to light brown and the flesh is translucent and sweet. Prune annually after harvest to keep the canopy to a manageable height and promote new fruiting wood.','["University of Florida IFAS Tropical Research and Education Center", "general horticultural reference"]','{"slug": "longan", "common_name": "Longan", "scientific_name": "Dimocarpus longan", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted trees after all cold weather has passed; young trees are cold-sensitive and need protection until the trunk is well established."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 240, "max": 360}, "height_in": {"min": 240, "max": 360}, "spread_in": {"min": 180, "max": 300}, "sun": "full", "water": "moderate", "directions": "Plant grafted trees in deep, well-drained, slightly acidic soil (pH 5.5–6.5) in full sun; longan will not tolerate standing water or saturated roots. A brief winter cool-dry period — temperatures in the mid-40s°F for several weeks — is essential to trigger reliable flowering, making coastal south Florida and extreme south Texas the two viable zones in the continental United States. Fruit clusters ripen in summer and should be harvested by cutting whole panicles with scissors when the skin turns tan to light brown and the flesh is translucent and sweet. Prune annually after harvest to keep the canopy to a manageable height and promote new fruiting wood.", "sources": ["University of Florida IFAS Tropical Research and Education Center", "general horticultural reference"]}')
