INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('loquat','Loquat','Eriobotrya japonica','fruit','pome fruit',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','half-hardy','last_frost',0,4,'Plant in spring after frost risk has passed; in zones 9–11 fall planting is preferred.',8,11,120,216,96,240,96,216,'full','low','Loquat is an evergreen tree that flowers in fall and winter and ripens its fruit in late winter to early spring — one of the earliest fruiting trees of the season. Most varieties are self-fertile, though two trees increase crop size. Fruit clusters can be thinned at golf-ball size to produce fewer but larger fruit. Harvest when fruit is fully golden-yellow to orange, slightly soft, and sweet-tart; the thin skin is edible but seeds are large and should be discarded. Trees are cold-hardy to about 12°F but flowers and developing fruit are damaged below 28°F.','["general horticultural reference"]','{"slug": "loquat", "common_name": "Loquat", "scientific_name": "Eriobotrya japonica", "category": "fruit", "subcategory": "pome fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring after frost risk has passed; in zones 9–11 fall planting is preferred."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 120, "max": 216}, "height_in": {"min": 96, "max": 240}, "spread_in": {"min": 96, "max": 216}, "sun": "full", "water": "low", "directions": "Loquat is an evergreen tree that flowers in fall and winter and ripens its fruit in late winter to early spring — one of the earliest fruiting trees of the season. Most varieties are self-fertile, though two trees increase crop size. Fruit clusters can be thinned at golf-ball size to produce fewer but larger fruit. Harvest when fruit is fully golden-yellow to orange, slightly soft, and sweet-tart; the thin skin is edible but seeds are large and should be discarded. Trees are cold-hardy to about 12°F but flowers and developing fruit are damaged below 28°F.", "sources": ["general horticultural reference"]}')
