  VALUES ('macadamia','Macadamia','Macadamia integrifolia','fruit','nut',28,60,68,80,2190,3650,'transplant','transplant','perennial','tender','last_frost',0,8,'Plant grafted trees in spring after frost; macadamias grow best in frost-free zones with well-distributed rainfall.',9,11,180,360,180,420,180,360,'full','moderate','Macadamias are self-fertile but cross-pollination between two or more varieties meaningfully increases yields; grafted trees start bearing at 3–5 years, while seedlings can take 10–15 years. The tree prefers well-drained, slightly acid soil (pH 5.5–6.5) and is sensitive to root disturbance — plant without disturbing the root ball. Trees produce racemes of cream-white flowers that fall and create a slippery surface; harvesting is done by collecting nuts that have dropped naturally as the green husk splits and the nut falls. Shell and dry nuts for 3–4 weeks before cracking; the shells require a commercial or heavy-duty nut cracker as they are among the hardest of any food nut.','["University of Hawaii Cooperative Extension", "general horticultural reference"]','{"slug": "macadamia", "common_name": "Macadamia", "scientific_name": "Macadamia integrifolia", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": 28, "max": 60}, "germination_soil_temp_f": {"min": 68, "max": 80}, "days_to_maturity": {"min": 2190, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted trees in spring after frost; macadamias grow best in frost-free zones with well-distributed rainfall."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 180, "max": 360}, "height_in": {"min": 180, "max": 420}, "spread_in": {"min": 180, "max": 360}, "sun": "full", "water": "moderate", "directions": "Macadamias are self-fertile but cross-pollination between two or more varieties meaningfully increases yields; grafted trees start bearing at 3–5 years, while seedlings can take 10–15 years. The tree prefers well-drained, slightly acid soil (pH 5.5–6.5) and is sensitive to root disturbance — plant without disturbing the root ball. Trees produce racemes of cream-white flowers that fall and create a slippery surface; harvesting is done by collecting nuts that have dropped naturally as the green husk splits and the nut falls. Shell and dry nuts for 3–4 weeks before cracking; the shells require a commercial or heavy-duty nut cracker as they are among the hardest of any food nut.", "sources": ["University of Hawaii Cooperative Extension", "general horticultural reference"]}')
