  VALUES ('mango','Mango','Mangifera indica','fruit','tropical fruit',7,21,75,85,1095,2190,'transplant','transplant','perennial','tender','last_frost',0,8,'Plant grafted trees in spring after all frost risk has passed; in zones 10b–11 the rainy-season break in early spring is the optimal planting window.',10,11,240,480,180,600,180,480,'full','moderate','Plant grafted trees of named cultivars (Kent, Tommy Atkins, Haden, Keitt) rather than seedlings; grafted trees fruit in 3–5 years and produce fruit true to type. Mangoes require a cool-dry period of 4–6 weeks during winter — nights below 60°F without frost — to trigger uniform flowering; excess rainfall during bloom causes anthracnose and poor fruit set. Prune after harvest each year by removing one-quarter to one-third of the outer canopy to keep the tree at a manageable height and promote fresh fruiting wood. Fruit is ripe when the shoulders near the stem fill out, color develops according to the cultivar, and the flesh yields slightly to pressure; the stem end is often the last to color.','["University of Florida IFAS Extension", "general horticultural reference"]','{"slug": "mango", "common_name": "Mango", "scientific_name": "Mangifera indica", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted trees in spring after all frost risk has passed; in zones 10b–11 the rainy-season break in early spring is the optimal planting window."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 240, "max": 480}, "height_in": {"min": 180, "max": 600}, "spread_in": {"min": 180, "max": 480}, "sun": "full", "water": "moderate", "directions": "Plant grafted trees of named cultivars (Kent, Tommy Atkins, Haden, Keitt) rather than seedlings; grafted trees fruit in 3–5 years and produce fruit true to type. Mangoes require a cool-dry period of 4–6 weeks during winter — nights below 60°F without frost — to trigger uniform flowering; excess rainfall during bloom causes anthracnose and poor fruit set. Prune after harvest each year by removing one-quarter to one-third of the outer canopy to keep the tree at a manageable height and promote fresh fruiting wood. Fruit is ripe when the shoulders near the stem fill out, color develops according to the cultivar, and the flesh yields slightly to pressure; the stem end is often the last to color.", "sources": ["University of Florida IFAS Extension", "general horticultural reference"]}')
