  VALUES ('mangosteen','Mangosteen','Garcinia mangostana','fruit','tropical',NULL,NULL,NULL,NULL,2555,4380,'transplant','transplant','perennial','tender','spring',0,8,'Plant in spring in a site with reliably warm temperatures year-round; mangosteen is extremely sensitive to cold and drought stress.',10,11,240,360,144,360,120,240,'partial','high','Mangosteen is one of the slowest-growing and most demanding tropical fruit trees, requiring deep, rich, well-drained, acidic soil (pH 5.0–6.5), humidity above 80%, and temperatures that never fall below 40°F or rise above 100°F. It is apomictic — seed-grown trees are genetically identical to the mother, eliminating the need for pollinators, though fruit set is parthenocarpic in cultivation. Young trees require shade for the first several years; gradually transition to full sun as the canopy develops. Harvest when the thick purple rind has deepened to a dark maroon-purple and yields slightly to thumb pressure, typically 5–6 months after fruit set.','["general horticultural reference"]','{"slug": "mangosteen", "common_name": "Mangosteen", "scientific_name": "Garcinia mangostana", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 2555, "max": 4380}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant in spring in a site with reliably warm temperatures year-round; mangosteen is extremely sensitive to cold and drought stress."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 240, "max": 360}, "height_in": {"min": 144, "max": 360}, "spread_in": {"min": 120, "max": 240}, "sun": "partial", "water": "high", "directions": "Mangosteen is one of the slowest-growing and most demanding tropical fruit trees, requiring deep, rich, well-drained, acidic soil (pH 5.0–6.5), humidity above 80%, and temperatures that never fall below 40°F or rise above 100°F. It is apomictic — seed-grown trees are genetically identical to the mother, eliminating the need for pollinators, though fruit set is parthenocarpic in cultivation. Young trees require shade for the first several years; gradually transition to full sun as the canopy develops. Harvest when the thick purple rind has deepened to a dark maroon-purple and yields slightly to thumb pressure, typically 5–6 months after fruit set.", "sources": ["general horticultural reference"]}')
