  VALUES ('medlar','Medlar','Mespilus germanica','fruit','pome',NULL,NULL,NULL,NULL,1460,2555,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root trees in late winter to early spring while dormant; fall planting suits zones 6–8.',5,9,120,180,96,240,120,240,'full','moderate','Medlar is a small, gnarled tree that tolerates a wide range of soils and needs minimal pruning beyond removing crossing branches; it is largely self-fertile and rarely needs a pollinator. Fruit is harvested in late autumn after the first light frost when the skin has turned brown and slightly wrinkled, then ''bleted'' (stored at room temperature for 2–4 weeks) until the flesh softens to a custard-like consistency and loses its harsh astringency. The bletted fruit tastes of apple butter with wine overtones and is traditionally made into jelly or cheese. Few pests bother medlar, making it one of the easiest heritage fruits for a low-spray garden.','["general horticultural reference"]','{"slug": "medlar", "common_name": "Medlar", "scientific_name": "Mespilus germanica", "category": "fruit", "subcategory": "pome", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2555}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter to early spring while dormant; fall planting suits zones 6–8."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 120, "max": 180}, "height_in": {"min": 96, "max": 240}, "spread_in": {"min": 120, "max": 240}, "sun": "full", "water": "moderate", "directions": "Medlar is a small, gnarled tree that tolerates a wide range of soils and needs minimal pruning beyond removing crossing branches; it is largely self-fertile and rarely needs a pollinator. Fruit is harvested in late autumn after the first light frost when the skin has turned brown and slightly wrinkled, then ''bleted'' (stored at room temperature for 2–4 weeks) until the flesh softens to a custard-like consistency and loses its harsh astringency. The bletted fruit tastes of apple butter with wine overtones and is traditionally made into jelly or cheese. Few pests bother medlar, making it one of the easiest heritage fruits for a low-spray garden.", "sources": ["general horticultural reference"]}')
