  VALUES ('meyer-lemon','Meyer Lemon','Citrus x meyeri','fruit','citrus',NULL,NULL,NULL,NULL,730,1460,'transplant','transplant','perennial','half-hardy','last_frost',2,8,'Plant in spring after frost risk passes; Meyer lemon is the hardiest true-fruiting lemon and can be grown in containers in zones 7–8 with winter protection.',8,11,72,144,60,144,60,144,'full','moderate','Meyer lemon is a natural hybrid between a lemon and either a mandarin or sweet orange, resulting in a thinner-skinned, less acidic, and more cold-tolerant fruit than standard lemon varieties; it tolerates brief dips to about 22°F once established. It is self-fertile, blooms nearly year-round in frost-free climates, and is exceptionally well-suited to container culture — a 20-gallon pot allows the plant to be moved indoors in zones 7–8. Plant in fast-draining citrus mix or well-amended garden soil and fertilize with citrus-specific fertilizer in late winter, late spring, and midsummer. Fruit is ripe when the skin turns deep golden-yellow and yields to gentle pressure; the rind is thin and zests well for culinary use.','["University of California Cooperative Extension", "general horticultural reference"]','{"slug": "meyer-lemon", "common_name": "Meyer Lemon", "scientific_name": "Citrus x meyeri", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant in spring after frost risk passes; Meyer lemon is the hardiest true-fruiting lemon and can be grown in containers in zones 7–8 with winter protection."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 72, "max": 144}, "height_in": {"min": 60, "max": 144}, "spread_in": {"min": 60, "max": 144}, "sun": "full", "water": "moderate", "directions": "Meyer lemon is a natural hybrid between a lemon and either a mandarin or sweet orange, resulting in a thinner-skinned, less acidic, and more cold-tolerant fruit than standard lemon varieties; it tolerates brief dips to about 22°F once established. It is self-fertile, blooms nearly year-round in frost-free climates, and is exceptionally well-suited to container culture — a 20-gallon pot allows the plant to be moved indoors in zones 7–8. Plant in fast-draining citrus mix or well-amended garden soil and fertilize with citrus-specific fertilizer in late winter, late spring, and midsummer. Fruit is ripe when the skin turns deep golden-yellow and yields to gentle pressure; the rind is thin and zests well for culinary use.", "sources": ["University of California Cooperative Extension", "general horticultural reference"]}')
