  VALUES ('miracle-fruit','Miracle Fruit','Synsepalum dulcificum','fruit','tropical',NULL,NULL,NULL,NULL,1460,2920,'transplant','transplant','perennial','tender','spring',0,8,'Plant in spring; grows well in large containers that can be overwintered indoors in zones 9 and below.',10,11,48,96,48,120,48,96,'partial','moderate','Plant in highly acidic soil (pH 4.5–5.5), which is critical — miracle fruit performs poorly above pH 6.0 and the leaves turn chlorotic in alkaline conditions. It requires consistently warm temperatures and suffers at any temperature below 40°F; container culture in large pots using acidic potting mix is the most practical approach outside zones 10–11. The small red berries contain miraculin, a glycoprotein that binds to taste receptors and makes sour foods taste sweet for 30–60 minutes after eating one fruit; harvest when berries are fully red and soft. Although individual plants are self-fertile, cross-pollination by insects improves berry set, so grow multiple plants together.','["general horticultural reference"]','{"slug": "miracle-fruit", "common_name": "Miracle Fruit", "scientific_name": "Synsepalum dulcificum", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2920}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant in spring; grows well in large containers that can be overwintered indoors in zones 9 and below."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 48, "max": 96}, "height_in": {"min": 48, "max": 120}, "spread_in": {"min": 48, "max": 96}, "sun": "partial", "water": "moderate", "directions": "Plant in highly acidic soil (pH 4.5–5.5), which is critical — miracle fruit performs poorly above pH 6.0 and the leaves turn chlorotic in alkaline conditions. It requires consistently warm temperatures and suffers at any temperature below 40°F; container culture in large pots using acidic potting mix is the most practical approach outside zones 10–11. The small red berries contain miraculin, a glycoprotein that binds to taste receptors and makes sour foods taste sweet for 30–60 minutes after eating one fruit; harvest when berries are fully red and soft. Although individual plants are self-fertile, cross-pollination by insects improves berry set, so grow multiple plants together.", "sources": ["general horticultural reference"]}')
