INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('moringa','Moringa (Drumstick Tree)','Moringa oleifera','fruit','tropical tree',7,14,70,95,90,180,'transplant','direct','perennial','tender','last_frost',1,4,'Sow seed or plant cuttings after last frost; moringa grows explosively in heat and can be coppiced to manage size in zone 9.',9,11,60,120,120,360,60,120,'full','low','Sow seeds 1 in deep directly into warm, well-drained soil — moringa dislikes transplanting due to its long taproot. It grows extraordinarily fast in hot, dry conditions and tolerates poor, sandy soils; avoid over-watering or heavy clay, which causes stem and root rot. In zone 9 the tree may freeze to the ground in hard winters but regrows vigorously from the root crown each spring. Harvest young leaves, flowers, and immature seed pods (drumsticks) regularly; coppicing the main stem at 3–4 ft encourages dense, bushy regrowth with more leaf area at reachable height.','["ECHO (Educational Concerns for Hunger Organization) technical note", "University of Florida IFAS Extension"]','{"slug": "moringa", "common_name": "Moringa (Drumstick Tree)", "scientific_name": "Moringa oleifera", "category": "fruit", "subcategory": "tropical tree", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 95}, "days_to_maturity": {"min": 90, "max": 180}, "maturity_from": "transplant", "sow_method": "direct", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 4}, "note": "Sow seed or plant cuttings after last frost; moringa grows explosively in heat and can be coppiced to manage size in zone 9."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 60, "max": 120}, "height_in": {"min": 120, "max": 360}, "spread_in": {"min": 60, "max": 120}, "sun": "full", "water": "low", "directions": "Sow seeds 1 in deep directly into warm, well-drained soil — moringa dislikes transplanting due to its long taproot. It grows extraordinarily fast in hot, dry conditions and tolerates poor, sandy soils; avoid over-watering or heavy clay, which causes stem and root rot. In zone 9 the tree may freeze to the ground in hard winters but regrows vigorously from the root crown each spring. Harvest young leaves, flowers, and immature seed pods (drumsticks) regularly; coppicing the main stem at 3–4 ft encourages dense, bushy regrowth with more leaf area at reachable height.", "sources": ["ECHO (Educational Concerns for Hunger Organization) technical note", "University of Florida IFAS Extension"]}')
