  VALUES ('mulberry','Mulberry','Morus rubra','fruit','aggregate fruit',NULL,NULL,NULL,NULL,1825,3650,'transplant','transplant','perennial','hardy','spring',-2,2,'Plant in early spring; mulberries establish readily from container stock.',4,8,240,480,240,600,240,480,'full','low','Red mulberry (native to eastern North America) and white mulberry (Morus alba, from Asia) are both grown for fruit; white mulberry is more tolerant of heat and alkaline soils. Most mulberries are self-fertile or near-enough so that a single tree crops well. Trees require very little care once established — no regular spraying or thinning is needed. Fruit ripens over several weeks and drops when ripe; lay a tarp beneath the canopy for easy collection, as the juice stains pavement and clothing permanently.','["general horticultural reference"]','{"slug": "mulberry", "common_name": "Mulberry", "scientific_name": "Morus rubra", "category": "fruit", "subcategory": "aggregate fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1825, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Plant in early spring; mulberries establish readily from container stock."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 240, "max": 480}, "height_in": {"min": 240, "max": 600}, "spread_in": {"min": 240, "max": 480}, "sun": "full", "water": "low", "directions": "Red mulberry (native to eastern North America) and white mulberry (Morus alba, from Asia) are both grown for fruit; white mulberry is more tolerant of heat and alkaline soils. Most mulberries are self-fertile or near-enough so that a single tree crops well. Trees require very little care once established — no regular spraying or thinning is needed. Fruit ripens over several weeks and drops when ripe; lay a tarp beneath the canopy for easy collection, as the juice stains pavement and clothing permanently.", "sources": ["general horticultural reference"]}')
