INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('nance','Nance','Byrsonima crassifolia','fruit','tropical',NULL,NULL,NULL,NULL,1460,2555,'transplant','transplant','perennial','tender','spring',0,8,'Plant in spring in a frost-free site; nance tolerates poor, well-drained soils exceptionally well.',10,11,120,216,120,300,96,216,'full','low','Nance is a tough, drought-tolerant shrub-tree native to tropical America that thrives on poor, acidic, sandy or rocky soils where other fruit trees struggle, and is among the most fire-tolerant tropical fruit plants. It is partially self-fertile, but fruit set improves significantly when multiple plants are grown together; bees are the primary pollinators. The small yellow drupes ripen over an extended season and have a distinctive pungent, waxy, cheese-like aroma that intensifies when processed; they are consumed fresh, frozen in syrup, fermented into a popular Central American drink called chicha, or cooked into preserves. Harvest when the fruit has fully yellowed and drops freely from the clusters, then refrigerate or process immediately.','["general horticultural reference"]','{"slug": "nance", "common_name": "Nance", "scientific_name": "Byrsonima crassifolia", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2555}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant in spring in a frost-free site; nance tolerates poor, well-drained soils exceptionally well."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 120, "max": 216}, "height_in": {"min": 120, "max": 300}, "spread_in": {"min": 96, "max": 216}, "sun": "full", "water": "low", "directions": "Nance is a tough, drought-tolerant shrub-tree native to tropical America that thrives on poor, acidic, sandy or rocky soils where other fruit trees struggle, and is among the most fire-tolerant tropical fruit plants. It is partially self-fertile, but fruit set improves significantly when multiple plants are grown together; bees are the primary pollinators. The small yellow drupes ripen over an extended season and have a distinctive pungent, waxy, cheese-like aroma that intensifies when processed; they are consumed fresh, frozen in syrup, fermented into a popular Central American drink called chicha, or cooked into preserves. Harvest when the fruit has fully yellowed and drops freely from the clusters, then refrigerate or process immediately.", "sources": ["general horticultural reference"]}')
