  VALUES ('natal-plum','Natal Plum (Carissa)','Carissa macrocarpa','fruit','tropical',NULL,NULL,NULL,NULL,365,730,'transplant','transplant','perennial','tender','spring',0,6,'Plant in spring in a frost-free coastal or tropical setting; natal plum is exceptionally tolerant of salt spray and wind.',9,11,36,96,36,120,36,120,'full','low','Natal plum is a spiny, salt-tolerant, evergreen shrub from coastal South Africa widely used as a fruiting hedge or ornamental in zones 9–11; only the ripe fruit is edible — all other plant parts, including the milky latex, are toxic. Plants are self-fertile and bear fragrant white flowers year-round in frost-free climates, producing a steady supply of oval crimson fruits about the size of a large olive. The sweet, cranberry-like fruit is excellent eaten fresh, as jam, or in desserts; harvest when it has turned fully deep red and yields to light pressure. In zone 9 site against a south-facing wall or near structures for frost protection.','["general horticultural reference"]','{"slug": "natal-plum", "common_name": "Natal Plum (Carissa)", "scientific_name": "Carissa macrocarpa", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 6}, "note": "Plant in spring in a frost-free coastal or tropical setting; natal plum is exceptionally tolerant of salt spray and wind."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 36, "max": 96}, "height_in": {"min": 36, "max": 120}, "spread_in": {"min": 36, "max": 120}, "sun": "full", "water": "low", "directions": "Natal plum is a spiny, salt-tolerant, evergreen shrub from coastal South Africa widely used as a fruiting hedge or ornamental in zones 9–11; only the ripe fruit is edible — all other plant parts, including the milky latex, are toxic. Plants are self-fertile and bear fragrant white flowers year-round in frost-free climates, producing a steady supply of oval crimson fruits about the size of a large olive. The sweet, cranberry-like fruit is excellent eaten fresh, as jam, or in desserts; harvest when it has turned fully deep red and yields to light pressure. In zone 9 site against a south-facing wall or near structures for frost protection.", "sources": ["general horticultural reference"]}')
