  VALUES ('olive','Olive','Olea europaea','fruit','drupe',NULL,NULL,NULL,NULL,1460,2920,'transplant','transplant','perennial','half-hardy','last_frost',0,4,'Plant in spring after the last frost; in Mediterranean-climate zones fall planting is also suitable.',8,11,144,240,120,360,120,300,'full','low','Olives thrive in the classic Mediterranean climate — hot, dry summers and mild, wet winters — and are extremely drought-tolerant once established, but they require 200–400 chill hours to set fruit reliably. Most cultivars are self-fertile, but cross-pollination with a second variety improves yields significantly. Trees are long-lived and slow-growing; minimal pruning is needed beyond thinning for light penetration. For table olives, harvest when fruit is still green-to-straw colored; for oil, pick when about half the fruit has turned black.','["general horticultural reference"]','{"slug": "olive", "common_name": "Olive", "scientific_name": "Olea europaea", "category": "fruit", "subcategory": "drupe", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2920}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring after the last frost; in Mediterranean-climate zones fall planting is also suitable."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 144, "max": 240}, "height_in": {"min": 120, "max": 360}, "spread_in": {"min": 120, "max": 300}, "sun": "full", "water": "low", "directions": "Olives thrive in the classic Mediterranean climate — hot, dry summers and mild, wet winters — and are extremely drought-tolerant once established, but they require 200–400 chill hours to set fruit reliably. Most cultivars are self-fertile, but cross-pollination with a second variety improves yields significantly. Trees are long-lived and slow-growing; minimal pruning is needed beyond thinning for light penetration. For table olives, harvest when fruit is still green-to-straw colored; for oil, pick when about half the fruit has turned black.", "sources": ["general horticultural reference"]}')
