INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('orange','Orange','Citrus sinensis','fruit','citrus',NULL,NULL,NULL,NULL,1460,2555,'transplant','transplant','perennial','tender','last_frost',2,8,'Plant in spring after frost risk passes; in frost-free zones, spring or early fall planting is ideal.',9,11,144,240,120,240,120,216,'full','moderate','Sweet oranges (Citrus sinensis) are self-fertile; navel oranges and many blood oranges are seedless because they are parthenocarpic. Most oranges need warm nights to develop sweetness and cannot be grown outdoors north of zone 9; the Hamlin and Navel types are slightly more cold-tolerant. Fruit can stay on the tree for weeks to months after ripening, extending harvest, but may re-green in warm weather without losing quality. Apply a balanced citrus fertilizer in late winter, late spring, and midsummer for best production.','["general horticultural reference"]','{"slug": "orange", "common_name": "Orange", "scientific_name": "Citrus sinensis", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2555}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant in spring after frost risk passes; in frost-free zones, spring or early fall planting is ideal."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 144, "max": 240}, "height_in": {"min": 120, "max": 240}, "spread_in": {"min": 120, "max": 216}, "sun": "full", "water": "moderate", "directions": "Sweet oranges (Citrus sinensis) are self-fertile; navel oranges and many blood oranges are seedless because they are parthenocarpic. Most oranges need warm nights to develop sweetness and cannot be grown outdoors north of zone 9; the Hamlin and Navel types are slightly more cold-tolerant. Fruit can stay on the tree for weeks to months after ripening, extending harvest, but may re-green in warm weather without losing quality. Apply a balanced citrus fertilizer in late winter, late spring, and midsummer for best production.", "sources": ["general horticultural reference"]}')
