INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('papaya','Papaya','Carica papaya','fruit','tropical fruit',10,21,70,85,180,365,'transplant','transplant','perennial','tender','last_frost',0,4,'Start seeds indoors 8 weeks before last frost and transplant after all cold risk has passed; even a light frost kills papaya plants.',10,11,72,144,120,360,72,120,'full','high','Papaya is one of the fastest-bearing fruit plants — grafted or transplanted seedlings can fruit within 6–12 months of planting. It is highly sensitive to frost, waterlogged soil, and root disturbance; plant in well-raised, excellently drained beds and never let roots sit in water even briefly. Most commercial papaya is hermaphroditic (self-fertile), allowing a single tree to produce fruit; dioecious types require a male plant within 20 feet. Cut the growing tip back at 3–4 ft to encourage a compact, easily harvested form. Harvest when at least one-quarter of the skin has turned yellow; ripen fully at room temperature and refrigerate only after fully ripe.','["University of Florida IFAS Extension", "general horticultural reference"]','{"slug": "papaya", "common_name": "Papaya", "scientific_name": "Carica papaya", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 180, "max": 365}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Start seeds indoors 8 weeks before last frost and transplant after all cold risk has passed; even a light frost kills papaya plants."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 72, "max": 144}, "height_in": {"min": 120, "max": 360}, "spread_in": {"min": 72, "max": 120}, "sun": "full", "water": "high", "directions": "Papaya is one of the fastest-bearing fruit plants — grafted or transplanted seedlings can fruit within 6–12 months of planting. It is highly sensitive to frost, waterlogged soil, and root disturbance; plant in well-raised, excellently drained beds and never let roots sit in water even briefly. Most commercial papaya is hermaphroditic (self-fertile), allowing a single tree to produce fruit; dioecious types require a male plant within 20 feet. Cut the growing tip back at 3–4 ft to encourage a compact, easily harvested form. Harvest when at least one-quarter of the skin has turned yellow; ripen fully at room temperature and refrigerate only after fully ripe.", "sources": ["University of Florida IFAS Extension", "general horticultural reference"]}')
