  VALUES ('pawpaw','Pawpaw','Asimina triloba','fruit','berry-like fruit',NULL,NULL,NULL,NULL,2190,3650,'transplant','transplant','perennial','hardy','last_frost',2,6,'Plant container-grown pawpaws in late spring after frost; avoid bare-root stock as the taproot is easily damaged.',5,9,120,240,120,360,96,240,'partial','moderate','Pawpaws require two genetically distinct seedlings or named cultivars for cross-pollination; hand-pollinating flowers with a small brush greatly improves fruit set. Young trees need shade for the first one to two seasons — plant under a light canopy or use a shade cloth — but mature trees prefer full sun to fruit well. The taproot makes transplanting difficult, so use container-grown stock and disturb roots as little as possible. Fruit ripens in late summer to fall and goes from firm to custardy-soft within days; refrigerate immediately after picking as shelf life is very short.','["general horticultural reference"]','{"slug": "pawpaw", "common_name": "Pawpaw", "scientific_name": "Asimina triloba", "category": "fruit", "subcategory": "berry-like fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 2190, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 6}, "note": "Plant container-grown pawpaws in late spring after frost; avoid bare-root stock as the taproot is easily damaged."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 120, "max": 240}, "height_in": {"min": 120, "max": 360}, "spread_in": {"min": 96, "max": 240}, "sun": "partial", "water": "moderate", "directions": "Pawpaws require two genetically distinct seedlings or named cultivars for cross-pollination; hand-pollinating flowers with a small brush greatly improves fruit set. Young trees need shade for the first one to two seasons — plant under a light canopy or use a shade cloth — but mature trees prefer full sun to fruit well. The taproot makes transplanting difficult, so use container-grown stock and disturb roots as little as possible. Fruit ripens in late summer to fall and goes from firm to custardy-soft within days; refrigerate immediately after picking as shelf life is very short.", "sources": ["general horticultural reference"]}')
