  VALUES ('peach-palm','Peach Palm (Pejibaye)','Bactris gasipaes','fruit','palm',NULL,NULL,NULL,NULL,1460,2190,'transplant','transplant','perennial','tender','spring',0,8,'Plant in frost-free conditions in spring; peach palm requires consistently warm, humid conditions.',10,11,120,216,240,600,60,120,'full','high','Peach palm is clump-forming, producing multiple spiny stems from the base; plant suckers or container-grown plants in rich, moist, well-drained soil in full sun with consistent irrigation. It is dioecious in the wild but many cultivated selections are monoecious and self-productive; planting in clusters of 3–5 stems improves pollination and yield. The starchy, oily orange-red drupes are rich in beta-carotene and must be boiled or roasted before eating as raw fruit contains irritating calcium oxalate crystals. Harvest bunches when fruit has turned fully orange to red and softens slightly; boil or cook within a few days as the starchy fruit does not store well raw.','["general horticultural reference"]','{"slug": "peach-palm", "common_name": "Peach Palm (Pejibaye)", "scientific_name": "Bactris gasipaes", "category": "fruit", "subcategory": "palm", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant in frost-free conditions in spring; peach palm requires consistently warm, humid conditions."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 120, "max": 216}, "height_in": {"min": 240, "max": 600}, "spread_in": {"min": 60, "max": 120}, "sun": "full", "water": "high", "directions": "Peach palm is clump-forming, producing multiple spiny stems from the base; plant suckers or container-grown plants in rich, moist, well-drained soil in full sun with consistent irrigation. It is dioecious in the wild but many cultivated selections are monoecious and self-productive; planting in clusters of 3–5 stems improves pollination and yield. The starchy, oily orange-red drupes are rich in beta-carotene and must be boiled or roasted before eating as raw fruit contains irritating calcium oxalate crystals. Harvest bunches when fruit has turned fully orange to red and softens slightly; boil or cook within a few days as the starchy fruit does not store well raw.", "sources": ["general horticultural reference"]}')
