INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('pecan','Pecan','Carya illinoinensis','fruit','nut',NULL,NULL,NULL,NULL,2190,3650,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root trees in late winter to early spring; pecans have a deep taproot — handle carefully and plant immediately.',5,9,360,720,480,960,360,720,'full','moderate','Pecans are protandrous or protogynous depending on variety — pollen shed and receptive female flowers rarely overlap on the same tree — so always plant at least two cultivars of opposite types (Type I with Type II) to ensure cross-pollination. Northern varieties (Hark, Kanza, Lakota) are bred for shorter growing seasons and suit zones 5–7; southern varieties need 250+ frost-free days. Pecans are heavy zinc feeders; apply zinc foliar spray in spring if leaves show rosette symptoms. Harvest when shucks split open in autumn and nuts fall freely.','["general horticultural reference"]','{"slug": "pecan", "common_name": "Pecan", "scientific_name": "Carya illinoinensis", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 2190, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter to early spring; pecans have a deep taproot — handle carefully and plant immediately."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 360, "max": 720}, "height_in": {"min": 480, "max": 960}, "spread_in": {"min": 360, "max": 720}, "sun": "full", "water": "moderate", "directions": "Pecans are protandrous or protogynous depending on variety — pollen shed and receptive female flowers rarely overlap on the same tree — so always plant at least two cultivars of opposite types (Type I with Type II) to ensure cross-pollination. Northern varieties (Hark, Kanza, Lakota) are bred for shorter growing seasons and suit zones 5–7; southern varieties need 250+ frost-free days. Pecans are heavy zinc feeders; apply zinc foliar spray in spring if leaves show rosette symptoms. Harvest when shucks split open in autumn and nuts fall freely.", "sources": ["general horticultural reference"]}')
