  VALUES ('phalsa','Phalsa (Indian Sherbet Berry)','Grewia asiatica','fruit','tropical',NULL,NULL,NULL,NULL,365,730,'transplant','transplant','perennial','half-hardy','spring',0,6,'Plant in spring; phalsa is coppiced annually in India but can be trained as a small tree in warmer zones.',9,11,60,120,60,180,60,120,'full','low','Phalsa is a fast-growing shrubby tree from South Asia that tolerates drought, heat, and a range of soils, fruiting reliably within 1–2 years of planting — one of the quickest-bearing subtropical fruits. In traditional cultivation it is heavily pruned (nearly to the ground) each year after fruiting, which promotes vigorous new fruiting wood; in zone 9 this also serves as winter frost management. The small, dark purple-red drupes ripen over several weeks in summer and have a refreshing sweet-sour flavor prized in Indian cooling drinks (phalsa sherbet) and jams. The fruit is extremely perishable — harvest when fully dark purple and soft and use within 24 hours; it does not store or ship well.','["general horticultural reference"]','{"slug": "phalsa", "common_name": "Phalsa (Indian Sherbet Berry)", "scientific_name": "Grewia asiatica", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 6}, "note": "Plant in spring; phalsa is coppiced annually in India but can be trained as a small tree in warmer zones."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 60, "max": 120}, "height_in": {"min": 60, "max": 180}, "spread_in": {"min": 60, "max": 120}, "sun": "full", "water": "low", "directions": "Phalsa is a fast-growing shrubby tree from South Asia that tolerates drought, heat, and a range of soils, fruiting reliably within 1–2 years of planting — one of the quickest-bearing subtropical fruits. In traditional cultivation it is heavily pruned (nearly to the ground) each year after fruiting, which promotes vigorous new fruiting wood; in zone 9 this also serves as winter frost management. The small, dark purple-red drupes ripen over several weeks in summer and have a refreshing sweet-sour flavor prized in Indian cooling drinks (phalsa sherbet) and jams. The fruit is extremely perishable — harvest when fully dark purple and soft and use within 24 hours; it does not store or ship well.", "sources": ["general horticultural reference"]}')
