  VALUES ('pineapple-guava','Pineapple Guava (Feijoa)','Acca sellowiana','fruit','subtropical fruit',NULL,NULL,NULL,NULL,730,1095,'transplant','transplant','perennial','half-hardy','spring',0,4,'Plant container-grown stock in spring after frost danger; established plants tolerate brief dips to 15°F once mature.',8,11,96,180,72,144,72,144,'full','low','Plant in well-drained soil in full sun; pineapple guava tolerates drought, coastal salt spray, and moderate alkalinity better than most subtropical fruits. Most selections set better crops with a second nearby cultivar for cross-pollination, though some are self-fruitful. The showy red-stamened flowers are edible and mild-flavored — harvest petals before they fall for salads. Fruits drop naturally when ripe in autumn; check the ground daily and collect before birds and insects take them, then ripen indoors for 3–5 days until they yield to gentle pressure.','["general horticultural reference", "University of California Cooperative Extension"]','{"slug": "pineapple-guava", "common_name": "Pineapple Guava (Feijoa)", "scientific_name": "Acca sellowiana", "category": "fruit", "subcategory": "subtropical fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant container-grown stock in spring after frost danger; established plants tolerate brief dips to 15°F once mature."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 96, "max": 180}, "height_in": {"min": 72, "max": 144}, "spread_in": {"min": 72, "max": 144}, "sun": "full", "water": "low", "directions": "Plant in well-drained soil in full sun; pineapple guava tolerates drought, coastal salt spray, and moderate alkalinity better than most subtropical fruits. Most selections set better crops with a second nearby cultivar for cross-pollination, though some are self-fruitful. The showy red-stamened flowers are edible and mild-flavored — harvest petals before they fall for salads. Fruits drop naturally when ripe in autumn; check the ground daily and collect before birds and insects take them, then ripen indoors for 3–5 days until they yield to gentle pressure.", "sources": ["general horticultural reference", "University of California Cooperative Extension"]}')
