  VALUES ('pistachio','Pistachio','Pistacia vera','fruit','nut / drupe',NULL,NULL,NULL,NULL,2555,4380,'transplant','transplant','perennial','half-hardy','last_frost',0,4,'Plant in spring after frost; pistachios need hot, dry summers and cold winters — a very specific climate.',7,11,240,360,144,360,144,300,'full','low','Pistachio is dioecious — you must plant at least one male tree (typically Peters variety) for every 8–10 female trees; pollen is wind-carried. The tree requires 700–1000 chill hours in winter and blisteringly hot, dry summers (100°F+ is ideal) to ripen nuts properly, making it poorly suited to humid or mild-summer climates. Trees are extremely drought-tolerant and actually prefer alkaline, well-drained soils. Nuts are ready when hulls turn from green to red-pink and slip off easily; harvest by shaking limbs and collect nuts off tarps laid below.','["general horticultural reference"]','{"slug": "pistachio", "common_name": "Pistachio", "scientific_name": "Pistacia vera", "category": "fruit", "subcategory": "nut / drupe", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 2555, "max": 4380}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant in spring after frost; pistachios need hot, dry summers and cold winters — a very specific climate."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 240, "max": 360}, "height_in": {"min": 144, "max": 360}, "spread_in": {"min": 144, "max": 300}, "sun": "full", "water": "low", "directions": "Pistachio is dioecious — you must plant at least one male tree (typically Peters variety) for every 8–10 female trees; pollen is wind-carried. The tree requires 700–1000 chill hours in winter and blisteringly hot, dry summers (100°F+ is ideal) to ripen nuts properly, making it poorly suited to humid or mild-summer climates. Trees are extremely drought-tolerant and actually prefer alkaline, well-drained soils. Nuts are ready when hulls turn from green to red-pink and slip off easily; harvest by shaking limbs and collect nuts off tarps laid below.", "sources": ["general horticultural reference"]}')
