  VALUES ('plum','Plum','Prunus domestica','fruit','stone fruit',NULL,NULL,NULL,NULL,1095,1825,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root trees in late winter to early spring; fall planting suits zones 7 and warmer.',4,9,120,216,120,216,120,180,'full','moderate','European plums (Prunus domestica) are often self-fertile, but Japanese plums (P. salicina) generally need a compatible pollinator planted nearby within 50 feet. Prune European types to a central leader and Japanese types to an open center; remove crossing branches each dormant season. Thin fruit clusters to 3–4 inches apart after natural fruit drop to encourage larger size. Pick when fruit achieves full color and yields gently to pressure — overripe plums are soft and ferment quickly.','["general horticultural reference"]','{"slug": "plum", "common_name": "Plum", "scientific_name": "Prunus domestica", "category": "fruit", "subcategory": "stone fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter to early spring; fall planting suits zones 7 and warmer."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 120, "max": 216}, "height_in": {"min": 120, "max": 216}, "spread_in": {"min": 120, "max": 180}, "sun": "full", "water": "moderate", "directions": "European plums (Prunus domestica) are often self-fertile, but Japanese plums (P. salicina) generally need a compatible pollinator planted nearby within 50 feet. Prune European types to a central leader and Japanese types to an open center; remove crossing branches each dormant season. Thin fruit clusters to 3–4 inches apart after natural fruit drop to encourage larger size. Pick when fruit achieves full color and yields gently to pressure — overripe plums are soft and ferment quickly.", "sources": ["general horticultural reference"]}')
