  VALUES ('pomelo','Pomelo','Citrus maxima','fruit','citrus',NULL,NULL,NULL,NULL,1460,2555,'transplant','transplant','perennial','tender','last_frost',2,8,'Plant grafted trees in spring after frost risk has passed; pomelo requires a long, hot growing season and performs best in zones 9b–11.',9,11,180,300,144,300,144,240,'full','moderate','Pomelo is the largest citrus fruit — often the size of a large cantaloupe — and the ancestor of the grapefruit. It is less bitter than grapefruit, with a sweeter, milder flavor, and a very thick pith that insulates the segments. Trees are self-fertile but cross-pollination with another variety increases fruit set. Pomelos require heat to develop sweetness and need a longer season than most citrus — fruit set in spring is ready from October through February of the following year. Apply citrus fertilizer three times annually and maintain consistent moisture during fruit development; drought stress during sizing causes dry, pithy fruit.','["University of California Cooperative Extension", "general horticultural reference"]','{"slug": "pomelo", "common_name": "Pomelo", "scientific_name": "Citrus maxima", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2555}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant grafted trees in spring after frost risk has passed; pomelo requires a long, hot growing season and performs best in zones 9b–11."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 180, "max": 300}, "height_in": {"min": 144, "max": 300}, "spread_in": {"min": 144, "max": 240}, "sun": "full", "water": "moderate", "directions": "Pomelo is the largest citrus fruit — often the size of a large cantaloupe — and the ancestor of the grapefruit. It is less bitter than grapefruit, with a sweeter, milder flavor, and a very thick pith that insulates the segments. Trees are self-fertile but cross-pollination with another variety increases fruit set. Pomelos require heat to develop sweetness and need a longer season than most citrus — fruit set in spring is ready from October through February of the following year. Apply citrus fertilizer three times annually and maintain consistent moisture during fruit development; drought stress during sizing causes dry, pithy fruit.", "sources": ["University of California Cooperative Extension", "general horticultural reference"]}')
