  VALUES ('quince','Quince','Cydonia oblonga','fruit','pome fruit',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root trees in late winter to early spring before bud break.',5,9,120,180,120,180,120,180,'full','moderate','Quince is self-fertile and one of the easier tree fruits to grow, tolerating heavier and wetter soils than apples or pears. It needs 300–500 chill hours, which suits zones 5–9 broadly. The fruit is astringent and almost always cooked rather than eaten raw; it turns pink when heated with sugar and is prized for marmalade, paste (membrillo), and jelly. Harvest in late autumn when the fruit turns fully golden-yellow and fragrant, before the first hard freeze.','["general horticultural reference"]','{"slug": "quince", "common_name": "Quince", "scientific_name": "Cydonia oblonga", "category": "fruit", "subcategory": "pome fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter to early spring before bud break."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 120, "max": 180}, "height_in": {"min": 120, "max": 180}, "spread_in": {"min": 120, "max": 180}, "sun": "full", "water": "moderate", "directions": "Quince is self-fertile and one of the easier tree fruits to grow, tolerating heavier and wetter soils than apples or pears. It needs 300–500 chill hours, which suits zones 5–9 broadly. The fruit is astringent and almost always cooked rather than eaten raw; it turns pink when heated with sugar and is prized for marmalade, paste (membrillo), and jelly. Harvest in late autumn when the fruit turns fully golden-yellow and fragrant, before the first hard freeze.", "sources": ["general horticultural reference"]}')
