INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('rambutan','Rambutan','Nephelium lappaceum','fruit','tropical',NULL,NULL,NULL,NULL,1460,2190,'transplant','transplant','perennial','tender','spring',0,8,'Plant grafted trees in spring after all cold risk has passed; young trees are extremely frost-sensitive.',10,11,240,360,240,480,180,360,'full','high','Plant in deep, well-drained, fertile, slightly acidic soil (pH 5.5–6.5) in a frost-free location; rambutan is damaged at any temperature below 40°F and is one of the most cold-sensitive common fruit trees. Most cultivars bear both male and hermaphrodite flowers on separate trees, so plant at least one male tree alongside female or hermaphrodite fruiting trees to ensure pollination. Trees require consistent rainfall or irrigation — roughly 60–150 inches of annual precipitation equivalent — especially during fruit development, with a short dry period to stimulate flowering. Harvest clusters when the leathery spines (soft spinterns) have turned fully red or yellow depending on variety and the flesh is translucent, sweet, and separates cleanly from the seed.','["general horticultural reference"]','{"slug": "rambutan", "common_name": "Rambutan", "scientific_name": "Nephelium lappaceum", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1460, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted trees in spring after all cold risk has passed; young trees are extremely frost-sensitive."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 240, "max": 360}, "height_in": {"min": 240, "max": 480}, "spread_in": {"min": 180, "max": 360}, "sun": "full", "water": "high", "directions": "Plant in deep, well-drained, fertile, slightly acidic soil (pH 5.5–6.5) in a frost-free location; rambutan is damaged at any temperature below 40°F and is one of the most cold-sensitive common fruit trees. Most cultivars bear both male and hermaphrodite flowers on separate trees, so plant at least one male tree alongside female or hermaphrodite fruiting trees to ensure pollination. Trees require consistent rainfall or irrigation — roughly 60–150 inches of annual precipitation equivalent — especially during fruit development, with a short dry period to stimulate flowering. Harvest clusters when the leathery spines (soft spinterns) have turned fully red or yellow depending on variety and the flesh is translucent, sweet, and separates cleanly from the seed.", "sources": ["general horticultural reference"]}')
