  VALUES ('rangpur-lime','Rangpur Lime','Citrus limonia','fruit','citrus',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','half-hardy','last_frost',2,8,'Plant grafted trees in spring; Rangpur lime is hardier than true limes and withstands brief frosts to about 25°F.',8,11,96,180,72,180,72,144,'full','moderate','Rangpur lime is actually a mandarin-lime hybrid (not a true lime) prized for its mandarin orange appearance, intensely sour juice, and significantly greater cold-hardiness than Key or Persian limes, making it a practical choice for zone 8 citrus gardens and container culture. It is self-fertile, productive as a single tree, and bears fruit nearly year-round in warm climates; fruit ripens to a deep orange-red color similar to a tangerine. Use the juice as a direct substitute for regular lime juice in cocktails, marinades, and curries — it is slightly more complex and aromatic. Harvest when the fruit has turned fully orange-red and yields to gentle pressure; fruit can be held on the tree for several weeks after ripening without significant quality loss.','["general horticultural reference"]','{"slug": "rangpur-lime", "common_name": "Rangpur Lime", "scientific_name": "Citrus limonia", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant grafted trees in spring; Rangpur lime is hardier than true limes and withstands brief frosts to about 25°F."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 96, "max": 180}, "height_in": {"min": 72, "max": 180}, "spread_in": {"min": 72, "max": 144}, "sun": "full", "water": "moderate", "directions": "Rangpur lime is actually a mandarin-lime hybrid (not a true lime) prized for its mandarin orange appearance, intensely sour juice, and significantly greater cold-hardiness than Key or Persian limes, making it a practical choice for zone 8 citrus gardens and container culture. It is self-fertile, productive as a single tree, and bears fruit nearly year-round in warm climates; fruit ripens to a deep orange-red color similar to a tangerine. Use the juice as a direct substitute for regular lime juice in cocktails, marinades, and curries — it is slightly more complex and aromatic. Harvest when the fruit has turned fully orange-red and yields to gentle pressure; fruit can be held on the tree for several weeks after ripening without significant quality loss.", "sources": ["general horticultural reference"]}')
