INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('rollinia','Rollinia (Biriba)','Annona mucosa','fruit','tropical',NULL,NULL,NULL,NULL,730,1460,'transplant','transplant','perennial','tender','spring',0,8,'Plant grafted or seedling trees in spring in a frost-free tropical site; biriba is among the faster-fruiting Annona relatives.',10,11,180,300,144,360,144,300,'full','high','Rollinia / biriba is an Annona relative from Amazonia that prefers deep, fertile, consistently moist soil and produces fruit faster than cherimoya or soursop under hot, humid conditions. Like other Annonaceae, the flowers exhibit protogynous dichogamy — the female stage opens first, closes, then reopens in the male stage — so hand-pollination at the correct time greatly increases fruit set: collect pollen from half-open flowers in the afternoon and apply to fully open receptive stigmas the following morning. The soft, custard-flavored fruit is covered in soft yellow spines and must be handled very gently — it bruises and ferments within hours of reaching peak ripeness. Harvest when the spines have softened and yellowed and the fruit gives noticeably to pressure; consume immediately or refrigerate for no more than 24 hours.','["general horticultural reference"]','{"slug": "rollinia", "common_name": "Rollinia (Biriba)", "scientific_name": "Annona mucosa", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted or seedling trees in spring in a frost-free tropical site; biriba is among the faster-fruiting Annona relatives."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 180, "max": 300}, "height_in": {"min": 144, "max": 360}, "spread_in": {"min": 144, "max": 300}, "sun": "full", "water": "high", "directions": "Rollinia / biriba is an Annona relative from Amazonia that prefers deep, fertile, consistently moist soil and produces fruit faster than cherimoya or soursop under hot, humid conditions. Like other Annonaceae, the flowers exhibit protogynous dichogamy — the female stage opens first, closes, then reopens in the male stage — so hand-pollination at the correct time greatly increases fruit set: collect pollen from half-open flowers in the afternoon and apply to fully open receptive stigmas the following morning. The soft, custard-flavored fruit is covered in soft yellow spines and must be handled very gently — it bruises and ferments within hours of reaching peak ripeness. Harvest when the spines have softened and yellowed and the fruit gives noticeably to pressure; consume immediately or refrigerate for no more than 24 hours.", "sources": ["general horticultural reference"]}')
