  VALUES ('sapodilla','Sapodilla','Manilkara zapota','fruit','tropical fruit',21,42,75,85,2190,4380,'transplant','transplant','perennial','tender','last_frost',0,8,'Plant grafted trees in spring; sapodilla tolerates salt spray and wind, making it useful for coastal zones 10–11.',10,11,240,360,240,480,180,360,'full','low','Sapodilla is an exceptionally wind- and salt-tolerant tropical tree; it is one of the few fruiting trees that thrives in coastal south Florida and can tolerate brief periods of flooding. Trees are slow-growing and long-lived with extremely hard, durable wood. Grafted plants fruit in 4–8 years; seedlings may take a decade. The fruit is fully ripe when the skin loses its sandy, rough texture, the green coloring fades to light tan, and the flesh yields to slight pressure — unripe fruit contains astringent latex. Harvest by rubbing the skin; if the scurf (grainy coating) rubs off easily and flesh inside is reddish-brown and translucent, it is ready.','["University of Florida IFAS Extension", "general horticultural reference"]','{"slug": "sapodilla", "common_name": "Sapodilla", "scientific_name": "Manilkara zapota", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 2190, "max": 4380}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted trees in spring; sapodilla tolerates salt spray and wind, making it useful for coastal zones 10–11."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 240, "max": 360}, "height_in": {"min": 240, "max": 480}, "spread_in": {"min": 180, "max": 360}, "sun": "full", "water": "low", "directions": "Sapodilla is an exceptionally wind- and salt-tolerant tropical tree; it is one of the few fruiting trees that thrives in coastal south Florida and can tolerate brief periods of flooding. Trees are slow-growing and long-lived with extremely hard, durable wood. Grafted plants fruit in 4–8 years; seedlings may take a decade. The fruit is fully ripe when the skin loses its sandy, rough texture, the green coloring fades to light tan, and the flesh yields to slight pressure — unripe fruit contains astringent latex. Harvest by rubbing the skin; if the scurf (grainy coating) rubs off easily and flesh inside is reddish-brown and translucent, it is ready.", "sources": ["University of Florida IFAS Extension", "general horticultural reference"]}')
