  VALUES ('sea-grape','Sea Grape','Coccoloba uvifera','fruit','tropical',NULL,NULL,NULL,NULL,1095,2190,'transplant','transplant','perennial','tender','spring',0,8,'Plant in spring in a coastal or frost-free site; sea grape is among the most salt-tolerant fruiting trees available.',10,11,120,360,60,360,96,360,'full','low','Sea grape is dioecious — male and female plants must both be present for fruit production — so purchase nursery plants that have been confirmed female, or graft from a known fruiting specimen and include a male pollinator nearby. It is one of the most wind- and salt-spray-tolerant fruiting trees available and naturally colonizes beach dunes and coastal scrub; it thrives on sandy, alkaline soils where most fruit trees fail. The grape-like clusters of purple-red fruits ripen in late summer to fall and are used to make a tart, mild jelly; individual fruits must be fully purple before picking as unripe fruit is astringent. Sea grape is legally protected in some coastal states — confirm local regulations before heavy pruning.','["general horticultural reference"]','{"slug": "sea-grape", "common_name": "Sea Grape", "scientific_name": "Coccoloba uvifera", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant in spring in a coastal or frost-free site; sea grape is among the most salt-tolerant fruiting trees available."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 120, "max": 360}, "height_in": {"min": 60, "max": 360}, "spread_in": {"min": 96, "max": 360}, "sun": "full", "water": "low", "directions": "Sea grape is dioecious — male and female plants must both be present for fruit production — so purchase nursery plants that have been confirmed female, or graft from a known fruiting specimen and include a male pollinator nearby. It is one of the most wind- and salt-spray-tolerant fruiting trees available and naturally colonizes beach dunes and coastal scrub; it thrives on sandy, alkaline soils where most fruit trees fail. The grape-like clusters of purple-red fruits ripen in late summer to fall and are used to make a tart, mild jelly; individual fruits must be fully purple before picking as unripe fruit is astringent. Sea grape is legally protected in some coastal states — confirm local regulations before heavy pruning.", "sources": ["general horticultural reference"]}')
