  VALUES ('shagbark-hickory','Shagbark Hickory','Carya ovata','fruit','nut',NULL,NULL,NULL,NULL,2920,5475,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root or container seedlings in early spring; shagbark hickory has a deep taproot and strongly resists transplanting once established — site carefully.',4,8,360,600,480,960,240,480,'full','moderate','Shagbark hickory is a stately native North American tree recognized by its exfoliating, shaggy gray bark; it produces small, round nuts with thin shells and exceptionally sweet, richly flavored kernels prized over pecans by many nut connoisseurs. Trees are monoecious and wind-pollinated; two or more trees improve nut set but a single tree can produce modest crops. Seedlings bear unpredictably and may take 10–20 years to fruit; grafted improved selections (Grainger, Wilcox) begin bearing in 5–7 years. Nuts drop in autumn when the four-sectioned husk splits open; collect promptly before squirrels take them and cure for 2–3 weeks before cracking.','["general horticultural reference", "Northern Nut Growers Association"]','{"slug": "shagbark-hickory", "common_name": "Shagbark Hickory", "scientific_name": "Carya ovata", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 2920, "max": 5475}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root or container seedlings in early spring; shagbark hickory has a deep taproot and strongly resists transplanting once established — site carefully."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 360, "max": 600}, "height_in": {"min": 480, "max": 960}, "spread_in": {"min": 240, "max": 480}, "sun": "full", "water": "moderate", "directions": "Shagbark hickory is a stately native North American tree recognized by its exfoliating, shaggy gray bark; it produces small, round nuts with thin shells and exceptionally sweet, richly flavored kernels prized over pecans by many nut connoisseurs. Trees are monoecious and wind-pollinated; two or more trees improve nut set but a single tree can produce modest crops. Seedlings bear unpredictably and may take 10–20 years to fruit; grafted improved selections (Grainger, Wilcox) begin bearing in 5–7 years. Nuts drop in autumn when the four-sectioned husk splits open; collect promptly before squirrels take them and cure for 2–3 weeks before cracking.", "sources": ["general horticultural reference", "Northern Nut Growers Association"]}')
