  VALUES ('sour-cherry','Sour Cherry','Prunus cerasus','fruit','stone fruit',NULL,NULL,NULL,NULL,1095,1825,'transplant','transplant','perennial','hardy','spring',-4,0,'Plant bare-root trees in late winter to early spring before bud break.',4,6,120,180,120,180,120,180,'full','moderate','Sour (tart) cherries such as Montmorency are self-fertile, reliably productive, and significantly hardier than sweet cherries, making them the better choice for zones 4–6. They require 1000–1200 chill hours and tolerate heavier soils than sweet cherries do. Thin lightly to maintain canopy airflow and prune in early summer to manage brown rot pressure in humid climates. Harvest when fruit is fully red and slightly soft — tart cherries rarely sweeten on the tree and are best for cooking, preserving, or juice.','["general horticultural reference"]','{"slug": "sour-cherry", "common_name": "Sour Cherry", "scientific_name": "Prunus cerasus", "category": "fruit", "subcategory": "stone fruit", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant bare-root trees in late winter to early spring before bud break."}, "usda_zones": {"min": 4, "max": 6}, "spacing_in": {"min": 120, "max": 180}, "height_in": {"min": 120, "max": 180}, "spread_in": {"min": 120, "max": 180}, "sun": "full", "water": "moderate", "directions": "Sour (tart) cherries such as Montmorency are self-fertile, reliably productive, and significantly hardier than sweet cherries, making them the better choice for zones 4–6. They require 1000–1200 chill hours and tolerate heavier soils than sweet cherries do. Thin lightly to maintain canopy airflow and prune in early summer to manage brown rot pressure in humid climates. Harvest when fruit is fully red and slightly soft — tart cherries rarely sweeten on the tree and are best for cooking, preserving, or juice.", "sources": ["general horticultural reference"]}')
