  VALUES ('soursop','Soursop (Guanabana)','Annona muricata','fruit','tropical fruit',14,30,75,85,1095,2190,'transplant','transplant','perennial','tender','last_frost',0,8,'Plant in spring after all frost risk has passed; soursop requires truly tropical conditions and is limited to zone 11 and the most sheltered frost-free pockets of zone 10b.',10,11,120,240,120,360,96,216,'full','moderate','Soursop is a rapid-growing small tree bearing the largest fruit of the Annona genus — sometimes exceeding 10 pounds — with spiny dark-green skin and white, fibrous, intensely aromatic pulp that is used primarily in beverages and desserts. Like its relatives (cherimoya, sugar-apple), soursop flowers have a specialized pollination mechanism that benefits greatly from hand-pollination using a small brush or cotton swab in late afternoon. The tree prefers deep, well-drained loam and is sensitive to standing water, drought stress, and cold below 32°F. Harvest when the skin has darkened from bright green to dull olive-green, the spines soften, and the fruit yields to gentle pressing; ripen at room temperature for 1–2 days.','["University of Florida IFAS Extension", "general horticultural reference"]','{"slug": "soursop", "common_name": "Soursop (Guanabana)", "scientific_name": "Annona muricata", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 1095, "max": 2190}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant in spring after all frost risk has passed; soursop requires truly tropical conditions and is limited to zone 11 and the most sheltered frost-free pockets of zone 10b."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 120, "max": 240}, "height_in": {"min": 120, "max": 360}, "spread_in": {"min": 96, "max": 216}, "sun": "full", "water": "moderate", "directions": "Soursop is a rapid-growing small tree bearing the largest fruit of the Annona genus — sometimes exceeding 10 pounds — with spiny dark-green skin and white, fibrous, intensely aromatic pulp that is used primarily in beverages and desserts. Like its relatives (cherimoya, sugar-apple), soursop flowers have a specialized pollination mechanism that benefits greatly from hand-pollination using a small brush or cotton swab in late afternoon. The tree prefers deep, well-drained loam and is sensitive to standing water, drought stress, and cold below 32°F. Harvest when the skin has darkened from bright green to dull olive-green, the spines soften, and the fruit yields to gentle pressing; ripen at room temperature for 1–2 days.", "sources": ["University of Florida IFAS Extension", "general horticultural reference"]}')
