  VALUES ('stone-pine','Stone Pine (Italian Stone Pine)','Pinus pinea','fruit','nut',NULL,NULL,NULL,NULL,2555,5475,'transplant','transplant','perennial','half-hardy','spring',-2,4,'Plant container-grown trees in spring; stone pine develops a deep taproot early — avoid disturbing roots.',7,11,240,480,240,600,240,480,'full','low','Stone pine is the classic Mediterranean umbrella-form pine grown for the large, richly flavored pine nuts (pignoli) used in pesto, pastries, and Middle Eastern cuisine; it is monoecious, self-fertile, and pollen-heavy — individual trees produce both male and female cones. Cones take three years to mature from pollination to seed release, so a productive tree has three overlapping cone crops at any given time. Harvest brown, closed cones by hand or after they fall naturally in late autumn, then sun-dry or gently heat them until the scales open and release the papery-shelled nuts inside. The tree thrives in sandy, well-drained, alkaline to acidic soil and is extremely drought-tolerant once the taproot is established.','["general horticultural reference"]','{"slug": "stone-pine", "common_name": "Stone Pine (Italian Stone Pine)", "scientific_name": "Pinus pinea", "category": "fruit", "subcategory": "nut", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 2555, "max": 5475}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": -2, "max": 4}, "note": "Plant container-grown trees in spring; stone pine develops a deep taproot early — avoid disturbing roots."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 240, "max": 480}, "height_in": {"min": 240, "max": 600}, "spread_in": {"min": 240, "max": 480}, "sun": "full", "water": "low", "directions": "Stone pine is the classic Mediterranean umbrella-form pine grown for the large, richly flavored pine nuts (pignoli) used in pesto, pastries, and Middle Eastern cuisine; it is monoecious, self-fertile, and pollen-heavy — individual trees produce both male and female cones. Cones take three years to mature from pollination to seed release, so a productive tree has three overlapping cone crops at any given time. Harvest brown, closed cones by hand or after they fall naturally in late autumn, then sun-dry or gently heat them until the scales open and release the papery-shelled nuts inside. The tree thrives in sandy, well-drained, alkaline to acidic soil and is extremely drought-tolerant once the taproot is established.", "sources": ["general horticultural reference"]}')
