INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sugar-apple','Sugar Apple (Sweetsop)','Annona squamosa','fruit','tropical fruit',14,30,75,85,1095,1825,'transplant','transplant','perennial','tender','last_frost',0,8,'Plant after all frost danger has passed; sugar apple requires a long, hot, humid growing season and is limited to frost-free zones.',10,11,120,240,96,240,96,180,'full','moderate','Sugar apple is a semi-deciduous small tree that drops leaves during the dry season — a natural dormancy that can be encouraged in cultivation by reducing water in late autumn to trigger uniform bloom flush in spring. Like other Annona species, the flowers are bisexual but dichogamous; hand-pollinate using a soft brush to transfer pollen from male-stage flowers (petals separating but pollen not yet shed) to female-stage flowers (stigma sticky and receptive). Fruit is composed of loosely packed segments that separate when ripe; harvest when skin segments begin to separate and the fruit yields to light pressure. Trees are fast-growing and benefit from annual pruning after fruit set to maintain canopy density and manageable size.','["University of Florida IFAS Extension", "general horticultural reference"]','{"slug": "sugar-apple", "common_name": "Sugar Apple (Sweetsop)", "scientific_name": "Annona squamosa", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant after all frost danger has passed; sugar apple requires a long, hot, humid growing season and is limited to frost-free zones."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 120, "max": 240}, "height_in": {"min": 96, "max": 240}, "spread_in": {"min": 96, "max": 180}, "sun": "full", "water": "moderate", "directions": "Sugar apple is a semi-deciduous small tree that drops leaves during the dry season — a natural dormancy that can be encouraged in cultivation by reducing water in late autumn to trigger uniform bloom flush in spring. Like other Annona species, the flowers are bisexual but dichogamous; hand-pollinate using a soft brush to transfer pollen from male-stage flowers (petals separating but pollen not yet shed) to female-stage flowers (stigma sticky and receptive). Fruit is composed of loosely packed segments that separate when ripe; harvest when skin segments begin to separate and the fruit yields to light pressure. Trees are fast-growing and benefit from annual pruning after fruit set to maintain canopy density and manageable size.", "sources": ["University of Florida IFAS Extension", "general horticultural reference"]}')
