  VALUES ('surinam-cherry','Surinam Cherry (Pitanga)','Eugenia uniflora','fruit','tropical fruit',14,30,70,85,1095,1825,'transplant','transplant','perennial','tender','last_frost',0,8,'Plant in spring after frost; established plants recover from brief dips to 28°F but young plants need protection.',9,11,72,180,72,240,72,180,'full','low','Surinam cherry is a densely foliaged shrub or small tree commonly used as a formal or informal hedge in frost-free zones; it tolerates shearing well without sacrificing fruiting wood because it blooms on new growth. The fruits change color through green, orange, and red to very dark red (nearly black) — they are most flavorful when fully dark red, as earlier stages carry a pronounced resinous flavor. Self-fertile and prolific, it bears twice a year in suitable climates. It has naturalized invasively in Hawaii and parts of Florida; check local regulations before planting.','["University of Florida IFAS Extension", "general horticultural reference"]','{"slug": "surinam-cherry", "common_name": "Surinam Cherry (Pitanga)", "scientific_name": "Eugenia uniflora", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 1095, "max": 1825}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant in spring after frost; established plants recover from brief dips to 28°F but young plants need protection."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 72, "max": 180}, "height_in": {"min": 72, "max": 240}, "spread_in": {"min": 72, "max": 180}, "sun": "full", "water": "low", "directions": "Surinam cherry is a densely foliaged shrub or small tree commonly used as a formal or informal hedge in frost-free zones; it tolerates shearing well without sacrificing fruiting wood because it blooms on new growth. The fruits change color through green, orange, and red to very dark red (nearly black) — they are most flavorful when fully dark red, as earlier stages carry a pronounced resinous flavor. Self-fertile and prolific, it bears twice a year in suitable climates. It has naturalized invasively in Hawaii and parts of Florida; check local regulations before planting.", "sources": ["University of Florida IFAS Extension", "general horticultural reference"]}')
