INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('tamarind','Tamarind','Tamarindus indica','fruit','tropical fruit',7,14,75,85,2190,4380,'transplant','transplant','perennial','tender','last_frost',0,8,'Plant in spring after all frost danger has passed; tamarind tolerates coastal conditions and is surprisingly drought-tolerant once established.',10,11,240,480,240,600,240,480,'full','low','Tamarind is a massive, long-lived tropical tree that can take 6–8 years from seed or 3–5 years from grafted stock to begin bearing the distinctive hard-shelled brown pods. It is self-fertile and thrives in hot, dry conditions; it is one of the most drought-tolerant tropical fruit trees. The interior pulp surrounding the seeds is intensely sour when young and sweet-sour when fully ripe; pods are harvested when the shell is brittle and the pulp is sticky, fibrous, and deep brown. Trees require no significant pruning and are largely pest-free in the continental U.S.; remove only dead or crossing wood.','["general horticultural reference", "University of Florida IFAS Extension"]','{"slug": "tamarind", "common_name": "Tamarind", "scientific_name": "Tamarindus indica", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 2190, "max": 4380}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant in spring after all frost danger has passed; tamarind tolerates coastal conditions and is surprisingly drought-tolerant once established."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 240, "max": 480}, "height_in": {"min": 240, "max": 600}, "spread_in": {"min": 240, "max": 480}, "sun": "full", "water": "low", "directions": "Tamarind is a massive, long-lived tropical tree that can take 6–8 years from seed or 3–5 years from grafted stock to begin bearing the distinctive hard-shelled brown pods. It is self-fertile and thrives in hot, dry conditions; it is one of the most drought-tolerant tropical fruit trees. The interior pulp surrounding the seeds is intensely sour when young and sweet-sour when fully ripe; pods are harvested when the shell is brittle and the pulp is sticky, fibrous, and deep brown. Trees require no significant pruning and are largely pest-free in the continental U.S.; remove only dead or crossing wood.", "sources": ["general horticultural reference", "University of Florida IFAS Extension"]}')
