  VALUES ('wax-jambu','Wax Jambu (Java Apple)','Syzygium samarangense','fruit','tropical',NULL,NULL,NULL,NULL,730,1460,'transplant','transplant','perennial','tender','spring',0,8,'Plant in spring after frost risk passes; trees are damaged below 28°F but recover from brief cold if the trunk is protected.',10,11,144,240,120,360,120,240,'full','moderate','Plant in well-drained, slightly acidic to neutral soil in full sun; wax jambu tolerates brief flooding better than most tropical fruits and grows well near water features. Trees are self-fertile and fruit heavily along the branches — a single mature tree produces hundreds of bell-shaped, crisp, mildly sweet fruits per season. Fertilize three times per year with a balanced fertilizer; maintain a regular irrigation schedule during flowering and fruiting to prevent premature fruit drop. Harvest when fruits reach their full color (pink, red, or white depending on variety) and the waxy skin is firm and glossy; the spongy flesh has a very short shelf life and is best eaten within a day or two of picking.','["general horticultural reference"]','{"slug": "wax-jambu", "common_name": "Wax Jambu (Java Apple)", "scientific_name": "Syzygium samarangense", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 730, "max": 1460}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant in spring after frost risk passes; trees are damaged below 28°F but recover from brief cold if the trunk is protected."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 144, "max": 240}, "height_in": {"min": 120, "max": 360}, "spread_in": {"min": 120, "max": 240}, "sun": "full", "water": "moderate", "directions": "Plant in well-drained, slightly acidic to neutral soil in full sun; wax jambu tolerates brief flooding better than most tropical fruits and grows well near water features. Trees are self-fertile and fruit heavily along the branches — a single mature tree produces hundreds of bell-shaped, crisp, mildly sweet fruits per season. Fertilize three times per year with a balanced fertilizer; maintain a regular irrigation schedule during flowering and fruiting to prevent premature fruit drop. Harvest when fruits reach their full color (pink, red, or white depending on variety) and the waxy skin is firm and glossy; the spongy flesh has a very short shelf life and is best eaten within a day or two of picking.", "sources": ["general horticultural reference"]}')
