  VALUES ('white-sapote','White Sapote','Casimiroa edulis','fruit','tropical fruit',14,28,70,80,1825,3650,'transplant','transplant','perennial','half-hardy','last_frost',0,8,'Plant grafted trees in spring after frost danger; established trees tolerate brief dips to 22°F and suit zone 9 in sheltered microclimates.',9,11,240,360,180,480,180,360,'full','low','White sapote is a fast-growing, drought-tolerant evergreen tree that bears creamy, custard-flavored fruit often compared to a blend of peach and vanilla. Grafted cultivars (Vernon, Suebelle, Cuccio) fruit in 3–5 years and produce more reliably than seedlings, which can take a decade or more and show highly variable fruit quality. Trees are self-fertile, though two cultivars nearby increase set. Harvest when fruit is light green to yellowish, yields slightly to palm pressure, and separates easily from the stem; it ripens to soft within 3–5 days at room temperature and has very short shelf life.','["California Rare Fruit Growers", "general horticultural reference"]','{"slug": "white-sapote", "common_name": "White Sapote", "scientific_name": "Casimiroa edulis", "category": "fruit", "subcategory": "tropical fruit", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 70, "max": 80}, "days_to_maturity": {"min": 1825, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 8}, "note": "Plant grafted trees in spring after frost danger; established trees tolerate brief dips to 22°F and suit zone 9 in sheltered microclimates."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 240, "max": 360}, "height_in": {"min": 180, "max": 480}, "spread_in": {"min": 180, "max": 360}, "sun": "full", "water": "low", "directions": "White sapote is a fast-growing, drought-tolerant evergreen tree that bears creamy, custard-flavored fruit often compared to a blend of peach and vanilla. Grafted cultivars (Vernon, Suebelle, Cuccio) fruit in 3–5 years and produce more reliably than seedlings, which can take a decade or more and show highly variable fruit quality. Trees are self-fertile, though two cultivars nearby increase set. Harvest when fruit is light green to yellowish, yields slightly to palm pressure, and separates easily from the stem; it ripens to soft within 3–5 days at room temperature and has very short shelf life.", "sources": ["California Rare Fruit Growers", "general horticultural reference"]}')
