  VALUES ('wood-apple','Wood Apple (Elephant Apple)','Limonia acidissima','fruit','tropical',NULL,NULL,NULL,NULL,2190,3650,'transplant','transplant','perennial','half-hardy','spring',0,6,'Plant in spring in well-drained, even poor soils; wood apple is extremely drought-tolerant once established.',9,11,180,360,180,480,144,360,'full','low','Wood apple is a deciduous tree from South and Southeast Asia related to bael; it tolerates poor, rocky, alkaline soils and drought conditions that defeat most fruit trees, making it valuable for arid-zone agroforestry. The spherical, gray-shelled fruits have a hard woody shell that must be cracked open with a hammer; the dark, pungent, sticky flesh inside is strongly acidic and astringent and is usually mixed with sugar, coconut, and spices or blended into drinks rather than eaten plain. It is self-fertile and pollinated by insects; a single tree crops reliably after the first 5–7 years. Harvest when fallen fruit has fully ripened on the ground, or remove from the tree when the gray shell turns slightly yellowish and sounds hollow when struck.','["general horticultural reference"]','{"slug": "wood-apple", "common_name": "Wood Apple (Elephant Apple)", "scientific_name": "Limonia acidissima", "category": "fruit", "subcategory": "tropical", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 2190, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 6}, "note": "Plant in spring in well-drained, even poor soils; wood apple is extremely drought-tolerant once established."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 180, "max": 360}, "height_in": {"min": 180, "max": 480}, "spread_in": {"min": 144, "max": 360}, "sun": "full", "water": "low", "directions": "Wood apple is a deciduous tree from South and Southeast Asia related to bael; it tolerates poor, rocky, alkaline soils and drought conditions that defeat most fruit trees, making it valuable for arid-zone agroforestry. The spherical, gray-shelled fruits have a hard woody shell that must be cracked open with a hammer; the dark, pungent, sticky flesh inside is strongly acidic and astringent and is usually mixed with sugar, coconut, and spices or blended into drinks rather than eaten plain. It is self-fertile and pollinated by insects; a single tree crops reliably after the first 5–7 years. Harvest when fallen fruit has fully ripened on the ground, or remove from the tree when the gray shell turns slightly yellowish and sounds hollow when struck.", "sources": ["general horticultural reference"]}')
