  VALUES ('yuzu','Yuzu','Citrus junos','fruit','citrus',NULL,NULL,NULL,NULL,1825,3650,'transplant','transplant','perennial','half-hardy','last_frost',2,8,'Plant grafted trees in spring; yuzu is among the hardiest citrus and can tolerate temperatures to 14–18°F when established, making it viable in zone 8 and possibly sheltered zone 7b.',8,11,96,180,72,180,72,144,'full','moderate','Yuzu is prized almost entirely for its intensely aromatic rind and highly acidic juice rather than its thin, seedy flesh; the fruit is rarely eaten out of hand but is indispensable in Japanese cuisine as a seasoning, in yuzu kosho paste, and in bath products. It is self-fertile and grafted trees begin to fruit in 3–4 years, though seedlings are notoriously slow — often taking 10 or more years. The tree has sharp thorns and is more cold-hardy than any lemon or standard lime. Harvest from late autumn through early winter when the fruit turns from green to yellow; green fruit has the most intense aroma for zesting.','["general horticultural reference", "University of California Cooperative Extension"]','{"slug": "yuzu", "common_name": "Yuzu", "scientific_name": "Citrus junos", "category": "fruit", "subcategory": "citrus", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 1825, "max": 3650}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Plant grafted trees in spring; yuzu is among the hardiest citrus and can tolerate temperatures to 14–18°F when established, making it viable in zone 8 and possibly sheltered zone 7b."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 96, "max": 180}, "height_in": {"min": 72, "max": 180}, "spread_in": {"min": 72, "max": 144}, "sun": "full", "water": "moderate", "directions": "Yuzu is prized almost entirely for its intensely aromatic rind and highly acidic juice rather than its thin, seedy flesh; the fruit is rarely eaten out of hand but is indispensable in Japanese cuisine as a seasoning, in yuzu kosho paste, and in bath products. It is self-fertile and grafted trees begin to fruit in 3–4 years, though seedlings are notoriously slow — often taking 10 or more years. The tree has sharp thorns and is more cold-hardy than any lemon or standard lime. Harvest from late autumn through early winter when the fruit turns from green to yellow; green fruit has the most intense aroma for zesting.", "sources": ["general horticultural reference", "University of California Cooperative Extension"]}')
