  VALUES ('african-blue-basil','African Blue Basil','Ocimum kilimandscharicum × basilicum ''Dark Opal''','herb','culinary',NULL,NULL,NULL,NULL,60,90,'transplant','cutting','perennial','tender','last_frost',0,4,'Root stem cuttings after last frost; this sterile hybrid does not set viable seed and must be propagated vegetatively.',10,11,18,24,24,48,18,30,'full','moderate','Take 4–6 in stem cuttings, remove lower leaves, and root in moist perlite or water; transplant once a vigorous root system develops. Plant in fertile, well-drained soil in full sun after all frost danger has passed; in zones below 10, treat as a long-season annual or overwinter rooted cuttings indoors under grow lights. Because this sterile hybrid never sets seed, it flowers continuously throughout the season — a great benefit for pollinators — without the bolting problem common to culinary basil. Harvest stem tips freely; the camphor-scented, dark-veined foliage is used in cooked dishes and infused oils.','["general horticultural reference"]','{"slug": "african-blue-basil", "common_name": "African Blue Basil", "scientific_name": "Ocimum kilimandscharicum × basilicum ''Dark Opal''", "category": "herb", "subcategory": "culinary", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Root stem cuttings after last frost; this sterile hybrid does not set viable seed and must be propagated vegetatively."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "moderate", "directions": "Take 4–6 in stem cuttings, remove lower leaves, and root in moist perlite or water; transplant once a vigorous root system develops. Plant in fertile, well-drained soil in full sun after all frost danger has passed; in zones below 10, treat as a long-season annual or overwinter rooted cuttings indoors under grow lights. Because this sterile hybrid never sets seed, it flowers continuously throughout the season — a great benefit for pollinators — without the bolting problem common to culinary basil. Harvest stem tips freely; the camphor-scented, dark-veined foliage is used in cooked dishes and infused oils.", "sources": ["general horticultural reference"]}')
