  VALUES ('agrimony','Agrimony','Agrimonia eupatoria','herb','medicinal',28,60,55,65,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-10,-8,'Cold-stratify seed for 4–6 weeks, then start indoors 8–10 weeks before last frost; transplant after frost danger passes.',3,9,12,18,18,36,12,18,'full','low','Cold-stratify seed in moist peat in the refrigerator for 4–6 weeks before surface-sowing onto warm starting mix; germination is slow and erratic without this treatment. Plant in well-drained, neutral to alkaline soil in full sun; agrimony is native to dry meadows and roadsides and tolerates drought and lean soils well. Harvest the entire above-ground plant just as the lower flowers on the spike begin to open in early summer, cutting stems to leave at least 2 in of growth for regrowth. Dry gathered material in bundles for use in traditional astringent teas for sore throats, mild digestive complaints, and as a wound-cleansing wash.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "agrimony", "common_name": "Agrimony", "scientific_name": "Agrimonia eupatoria", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 28, "max": 60}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Cold-stratify seed for 4–6 weeks, then start indoors 8–10 weeks before last frost; transplant after frost danger passes."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Cold-stratify seed in moist peat in the refrigerator for 4–6 weeks before surface-sowing onto warm starting mix; germination is slow and erratic without this treatment. Plant in well-drained, neutral to alkaline soil in full sun; agrimony is native to dry meadows and roadsides and tolerates drought and lean soils well. Harvest the entire above-ground plant just as the lower flowers on the spike begin to open in early summer, cutting stems to leave at least 2 in of growth for regrowth. Dry gathered material in bundles for use in traditional astringent teas for sore throats, mild digestive complaints, and as a wound-cleansing wash.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
