INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ajwain','Ajwain (Carom)','Trachyspermum ammi','herb','culinary',7,14,65,80,100,130,'seed','direct','warm','tender','last_frost',0,2,'Direct sow at or just after last frost once soil has warmed; ajwain needs a long, warm season to set seed.',9,11,9,12,24,36,9,12,'full','moderate','Sow seeds 1/4 in deep directly in the garden in well-drained, fertile soil once soil temperature reaches 65°F; thin to 9–12 in. Ajwain closely resembles caraway and parsley in appearance but the tiny fruits (commonly called seeds) carry an intensely sharp thymol flavor — far stronger than thyme — used in Indian flatbreads, lentil dishes, and digestive preparations. Young leaves are also edible and make a flavorful addition to salads and chutneys. Harvest seed umbels when they turn tan and dry, cutting into bags to catch the seeds, and cure in a warm, airy location before storing in airtight jars.','["general horticultural reference"]','{"slug": "ajwain", "common_name": "Ajwain (Carom)", "scientific_name": "Trachyspermum ammi", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 80}, "days_to_maturity": {"min": 100, "max": 130}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow at or just after last frost once soil has warmed; ajwain needs a long, warm season to set seed."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep directly in the garden in well-drained, fertile soil once soil temperature reaches 65°F; thin to 9–12 in. Ajwain closely resembles caraway and parsley in appearance but the tiny fruits (commonly called seeds) carry an intensely sharp thymol flavor — far stronger than thyme — used in Indian flatbreads, lentil dishes, and digestive preparations. Young leaves are also edible and make a flavorful addition to salads and chutneys. Harvest seed umbels when they turn tan and dry, cutting into bags to catch the seeds, and cure in a warm, airy location before storing in airtight jars.", "sources": ["general horticultural reference"]}')
