INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('american-ginseng','American Ginseng','Panax quinquefolius','herb','medicinal perennial',180,540,50,60,1825,2920,'seed','direct','perennial','hardy','fall',-4,0,'Sow stratified seed in autumn in a woodland bed; seeds require 18–24 months of warm-then-cold stratification before germinating.',3,7,12,18,12,24,12,18,'shade','moderate','Purchase properly stratified seed and sow 1–2 in deep in a shaded, forested bed with well-drained, humus-rich, slightly acidic soil; do not expect germination until the following spring at the earliest. Ginseng requires 60–75% canopy shade and the deep, crumbly forest soil of its native Appalachian habitat — it will not thrive in open garden conditions. Plants must grow for a minimum of 5–7 years before roots reach marketable size, making patience the primary gardening virtue here. Harvest roots in autumn by carefully digging to preserve the branched root shape; roots are dried slowly at low heat and used in adaptogenic teas, tinctures, and traditional Chinese medicine preparations.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "american-ginseng", "common_name": "American Ginseng", "scientific_name": "Panax quinquefolius", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 180, "max": 540}, "germination_soil_temp_f": {"min": 50, "max": 60}, "days_to_maturity": {"min": 1825, "max": 2920}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Sow stratified seed in autumn in a woodland bed; seeds require 18–24 months of warm-then-cold stratification before germinating."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "shade", "water": "moderate", "directions": "Purchase properly stratified seed and sow 1–2 in deep in a shaded, forested bed with well-drained, humus-rich, slightly acidic soil; do not expect germination until the following spring at the earliest. Ginseng requires 60–75% canopy shade and the deep, crumbly forest soil of its native Appalachian habitat — it will not thrive in open garden conditions. Plants must grow for a minimum of 5–7 years before roots reach marketable size, making patience the primary gardening virtue here. Harvest roots in autumn by carefully digging to preserve the branched root shape; roots are dried slowly at low heat and used in adaptogenic teas, tinctures, and traditional Chinese medicine preparations.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
