INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('angelica','Angelica','Angelica archangelica','herb','culinary',21,42,50,65,365,730,'seed','direct','perennial','hardy','first_frost',-2,0,'Sow fresh seed in autumn just before first frost; seed loses viability quickly and requires cold stratification through winter to germinate reliably in spring.',4,9,24,36,48,84,24,36,'partial','moderate','Sow fresh seed immediately after harvest or purchase in autumn, pressing 1/4 in deep into moist soil; stored or old seed germinates poorly. Angelica is a short-lived perennial or biennial that requires deep, rich, moisture-retentive soil and partial shade — its ideal habitat is moist woodland edge. Removing the flower head in the second year prolongs the plant''s life, while allowing it to set seed means the plant dies after seeding but self-sown seedlings will follow. Harvest young leaf stems and petioles in spring for candying; collect seeds when ripe for use in gin and liqueur flavoring.','["general horticultural reference", "RHS Plant Guides"]','{"slug": "angelica", "common_name": "Angelica", "scientific_name": "Angelica archangelica", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -2, "max": 0}, "note": "Sow fresh seed in autumn just before first frost; seed loses viability quickly and requires cold stratification through winter to germinate reliably in spring."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 48, "max": 84}, "spread_in": {"min": 24, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Sow fresh seed immediately after harvest or purchase in autumn, pressing 1/4 in deep into moist soil; stored or old seed germinates poorly. Angelica is a short-lived perennial or biennial that requires deep, rich, moisture-retentive soil and partial shade — its ideal habitat is moist woodland edge. Removing the flower head in the second year prolongs the plant''s life, while allowing it to set seed means the plant dies after seeding but self-sown seedlings will follow. Harvest young leaf stems and petioles in spring for candying; collect seeds when ripe for use in gin and liqueur flavoring.", "sources": ["general horticultural reference", "RHS Plant Guides"]}')
