  VALUES ('apple-mint','Apple Mint','Mentha suaveolens','herb','culinary',10,16,65,75,60,90,'transplant','division','perennial','hardy','last_frost',-2,2,'Plant divisions or rooted cuttings around the last frost date in spring; apple mint spreads vigorously by underground runners.',5,9,18,24,18,36,24,48,'partial','moderate','Plant divisions in moist, moderately fertile soil and install a root barrier or grow in a sunken container to contain the vigorous spreading rhizomes. Apple mint is more heat- and drought-tolerant than peppermint and copes better with partial shade; the large, soft, woolly leaves have a mild, fruity mint fragrance with an apple note. Cut plants back by half after the first flush of growth to encourage dense, leafy regrowth and delay flowering. Use fresh leaves in fruit salads, jellies, and summer drinks; the soft texture makes it excellent for mint sauce and a gentler choice for culinary use than the more pungent peppermint.','["general horticultural reference"]','{"slug": "apple-mint", "common_name": "Apple Mint", "scientific_name": "Mentha suaveolens", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 10, "max": 16}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Plant divisions or rooted cuttings around the last frost date in spring; apple mint spreads vigorously by underground runners."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 24, "max": 48}, "sun": "partial", "water": "moderate", "directions": "Plant divisions in moist, moderately fertile soil and install a root barrier or grow in a sunken container to contain the vigorous spreading rhizomes. Apple mint is more heat- and drought-tolerant than peppermint and copes better with partial shade; the large, soft, woolly leaves have a mild, fruity mint fragrance with an apple note. Cut plants back by half after the first flush of growth to encourage dense, leafy regrowth and delay flowering. Use fresh leaves in fruit salads, jellies, and summer drinks; the soft texture makes it excellent for mint sauce and a gentler choice for culinary use than the more pungent peppermint.", "sources": ["general horticultural reference"]}')
