  VALUES ('ashwagandha','Ashwagandha / Indian Winter Cherry','Withania somnifera','herb','medicinal tender perennial',14,21,70,80,150,180,'transplant','indoor-start','warm','tender','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after all frost danger passes into a sunny, warm location.',8,12,24,36,36,60,24,36,'full','low','Sow seeds 1/4 in deep in warm starting mix and keep consistently warm at 70–80°F until germination; transplant after last frost into sandy or loamy, well-drained soil. Ashwagandha thrives in hot, dry conditions similar to its native Indian range — avoid overwatering and boggy soil. The fleshy taproot is the primary medicinal part and is harvested after the plant''s first autumn, when the small lantern-like berries begin to turn red. Wash, slice, and dry the roots for use in adaptogenic powders and decoctions; yields improve substantially if plants are grown through a full growing season.','["general horticultural reference"]','{"slug": "ashwagandha", "common_name": "Ashwagandha / Indian Winter Cherry", "scientific_name": "Withania somnifera", "category": "herb", "subcategory": "medicinal tender perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 80}, "days_to_maturity": {"min": 150, "max": 180}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after all frost danger passes into a sunny, warm location."}, "usda_zones": {"min": 8, "max": 12}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Sow seeds 1/4 in deep in warm starting mix and keep consistently warm at 70–80°F until germination; transplant after last frost into sandy or loamy, well-drained soil. Ashwagandha thrives in hot, dry conditions similar to its native Indian range — avoid overwatering and boggy soil. The fleshy taproot is the primary medicinal part and is harvested after the plant''s first autumn, when the small lantern-like berries begin to turn red. Wash, slice, and dry the roots for use in adaptogenic powders and decoctions; yields improve substantially if plants are grown through a full growing season.", "sources": ["general horticultural reference"]}')
