  VALUES ('berggarten-sage','Berggarten Sage','Salvia officinalis ''Berggarten''','herb','culinary',NULL,NULL,NULL,NULL,75,100,'transplant','cutting','perennial','hardy','last_frost',0,4,'Plant rooted cuttings or nursery transplants after last frost; this non-blooming cultivar is propagated vegetatively.',5,8,18,24,12,18,18,24,'full','low','Root 3–4 in semi-ripe cuttings in moist perlite in late summer; Berggarten sage rarely flowers and is almost exclusively vegetatively propagated. Plant in well-drained, lean soil in full sun; the exceptionally large, rounded, gray-green leaves make it one of the most productive and ornamental culinary sages. Because it does not bolt to flower, the plant concentrates energy into leaf production and remains more compact and tidy than the species. Harvest large leaves throughout the season, cutting back the plant by one-third in spring to remove any winter-killed wood and encourage fresh basal growth.','["general horticultural reference"]','{"slug": "berggarten-sage", "common_name": "Berggarten Sage", "scientific_name": "Salvia officinalis ''Berggarten''", "category": "herb", "subcategory": "culinary", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 75, "max": 100}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted cuttings or nursery transplants after last frost; this non-blooming cultivar is propagated vegetatively."}, "usda_zones": {"min": 5, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Root 3–4 in semi-ripe cuttings in moist perlite in late summer; Berggarten sage rarely flowers and is almost exclusively vegetatively propagated. Plant in well-drained, lean soil in full sun; the exceptionally large, rounded, gray-green leaves make it one of the most productive and ornamental culinary sages. Because it does not bolt to flower, the plant concentrates energy into leaf production and remains more compact and tidy than the species. Harvest large leaves throughout the season, cutting back the plant by one-third in spring to remove any winter-killed wood and encourage fresh basal growth.", "sources": ["general horticultural reference"]}')
