INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('betony','Betony (Wood Betony)','Stachys betonica','herb','medicinal',14,28,55,65,90,120,'seed','direct','perennial','hardy','soil_workable',0,4,'Direct sow in early spring as soon as soil can be worked; cold stratification for 4 weeks improves germination.',4,8,12,18,18,30,12,18,'partial','moderate','Cold-stratify seeds for 4 weeks in the refrigerator before sowing 1/4 in deep in humus-rich, well-drained soil in partial shade. Betony (Betonica officinalis, synonym Stachys betonica) has a long history in European herbal medicine as a nervine tonic and digestive herb; the leaves are dried for tea. Grow in partial shade with moisture-retentive soil; plants are long-lived once established and require little attention beyond dividing crowded clumps every 3–4 years. Harvest leaves and flowering tops in early summer when the rosy-pink flower spikes are just opening, then dry thoroughly in a well-ventilated space.','["general horticultural reference"]','{"slug": "betony", "common_name": "Betony (Wood Betony)", "scientific_name": "Stachys betonica", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Direct sow in early spring as soon as soil can be worked; cold stratification for 4 weeks improves germination."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Cold-stratify seeds for 4 weeks in the refrigerator before sowing 1/4 in deep in humus-rich, well-drained soil in partial shade. Betony (Betonica officinalis, synonym Stachys betonica) has a long history in European herbal medicine as a nervine tonic and digestive herb; the leaves are dried for tea. Grow in partial shade with moisture-retentive soil; plants are long-lived once established and require little attention beyond dividing crowded clumps every 3–4 years. Harvest leaves and flowering tops in early summer when the rosy-pink flower spikes are just opening, then dry thoroughly in a well-ventilated space.", "sources": ["general horticultural reference"]}')
