INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('blessed-thistle','Blessed Thistle','Cnicus benedictus','herb','medicinal',7,14,55,70,60,90,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; as a cool-season annual, it can also be sown in late summer for an autumn harvest.',3,11,12,18,18,30,12,18,'full','low','Sow seeds 1/4 in deep directly in well-drained, poor to moderately fertile soil in full sun; blessed thistle thrives in lean conditions and declines in rich, moist soil. As a cool-season annual it bolts in summer heat, so early spring or late summer sowing provides the best leaf harvest. Harvest the young leaves and leafy stems before the spiny flower heads fully open, wearing gloves to protect against the prickles. Dried aerial parts are used in traditional bitter digestive tinctures, teas for stimulating appetite, and historical preparations reputed to support lactation.','["general horticultural reference"]','{"slug": "blessed-thistle", "common_name": "Blessed Thistle", "scientific_name": "Cnicus benedictus", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 70}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; as a cool-season annual, it can also be sown in late summer for an autumn harvest."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seeds 1/4 in deep directly in well-drained, poor to moderately fertile soil in full sun; blessed thistle thrives in lean conditions and declines in rich, moist soil. As a cool-season annual it bolts in summer heat, so early spring or late summer sowing provides the best leaf harvest. Harvest the young leaves and leafy stems before the spiny flower heads fully open, wearing gloves to protect against the prickles. Dried aerial parts are used in traditional bitter digestive tinctures, teas for stimulating appetite, and historical preparations reputed to support lactation.", "sources": ["general horticultural reference"]}')
