INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('vervain-blue','Blue Vervain','Verbena hastata','herb','medicinal',14,28,55,65,90,120,'seed','direct','perennial','hardy','soil_workable',0,2,'Direct sow in early spring; seeds benefit from cold stratification and light exposure, so surface-sow and leave outdoors over winter for spring germination.',3,8,18,24,36,60,18,24,'full','moderate','Surface-sow seeds and cold-stratify by sowing in fall or placing moistened seeds in the refrigerator for 30 days before spring sowing; do not cover, as seeds need light. Blue vervain is a North American native wetland herb used in traditional and folk herbalism as a nervine and bitter tonic; the aerial parts are harvested when flowering begins. Plant in moist, fertile soil in full sun to light shade; it thrives along stream edges and in rain gardens. Harvest aerial portions — leaves, stems, and flower spikes — in midsummer when the lower flowers on the spike have just opened, and dry for tincture or tea.','["general horticultural reference"]','{"slug": "vervain-blue", "common_name": "Blue Vervain", "scientific_name": "Verbena hastata", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow in early spring; seeds benefit from cold stratification and light exposure, so surface-sow and leave outdoors over winter for spring germination."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Surface-sow seeds and cold-stratify by sowing in fall or placing moistened seeds in the refrigerator for 30 days before spring sowing; do not cover, as seeds need light. Blue vervain is a North American native wetland herb used in traditional and folk herbalism as a nervine and bitter tonic; the aerial parts are harvested when flowering begins. Plant in moist, fertile soil in full sun to light shade; it thrives along stream edges and in rain gardens. Harvest aerial portions — leaves, stems, and flower spikes — in midsummer when the lower flowers on the spike have just opened, and dry for tincture or tea.", "sources": ["general horticultural reference"]}')
