INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('borage','Borage','Borago officinalis','herb','annual',7,14,65,75,50,70,'seed','direct','cool','half-hardy','last_frost',-2,2,'Direct sow around the last frost date; borage dislikes root disturbance and self-seeds freely.',3,11,12,18,18,36,12,18,'full','low','Sow seeds 1/2 in deep directly in their permanent position; borage has a taproot that is easily damaged and transplants poorly. Grow in full sun in any well-drained soil—even poor, dry soil suits it. Once established it self-seeds readily, so remove unwanted seedlings while they are small. The star-shaped blue flowers are edible with a cool cucumber flavor; harvest them when newly opened for garnishing salads and drinks.','["general horticultural reference"]','{"slug": "borage", "common_name": "Borage", "scientific_name": "Borago officinalis", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Direct sow around the last frost date; borage dislikes root disturbance and self-seeds freely."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seeds 1/2 in deep directly in their permanent position; borage has a taproot that is easily damaged and transplants poorly. Grow in full sun in any well-drained soil—even poor, dry soil suits it. Once established it self-seeds readily, so remove unwanted seedlings while they are small. The star-shaped blue flowers are edible with a cool cucumber flavor; harvest them when newly opened for garnishing salads and drinks.", "sources": ["general horticultural reference"]}')
