  VALUES ('bronze-fennel','Bronze Fennel','Foeniculum vulgare ''Purpureum''','herb','perennial',7,14,60,75,60,90,'seed','direct','perennial','hardy','last_frost',-2,2,'Direct sow around the last frost date; fennel dislikes transplanting.',4,9,18,24,48,72,18,24,'full','low','Sow seeds 1/4 in deep directly in their final position; bronze fennel resents root disturbance and transplants poorly. Grow in full sun with well-drained, fertile soil and deadhead spent flower heads to limit self-seeding, which can become excessive. Plant away from dill, coriander, and most vegetables as fennel is allelopathic to many garden neighbors. Harvest the feathery bronze fronds as needed; flavor is best before flowering.','["general horticultural reference"]','{"slug": "bronze-fennel", "common_name": "Bronze Fennel", "scientific_name": "Foeniculum vulgare ''Purpureum''", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Direct sow around the last frost date; fennel dislikes transplanting."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Sow seeds 1/4 in deep directly in their final position; bronze fennel resents root disturbance and transplants poorly. Grow in full sun with well-drained, fertile soil and deadhead spent flower heads to limit self-seeding, which can become excessive. Plant away from dill, coriander, and most vegetables as fennel is allelopathic to many garden neighbors. Harvest the feathery bronze fronds as needed; flavor is best before flowering.", "sources": ["general horticultural reference"]}')
