INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('buckler-leaf-sorrel','Buckler-Leaf Sorrel','Rumex scutatus','herb','culinary',7,14,55,70,50,60,'seed','direct','perennial','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; buckler-leaf sorrel is one of the first perennial herbs to produce harvestable leaves in spring.',3,9,12,18,9,18,12,18,'partial','moderate','Sow seeds 1/4 in deep in well-drained soil with moderate fertility; thin to 12 in apart once seedlings reach 2 in. Buckler-leaf sorrel has small, shield-shaped silvery-green leaves with a clean, bright lemon-acid flavor that is preferred over common sorrel in French cuisine for sorrel soup and sauces. Remove flowering stalks as they appear to redirect energy into leaf production; divide clumps every 2–3 years to maintain vigor. Harvest the small leaves regularly while they are fresh and tender, as flavor intensifies in older foliage to the point of bitterness.','["general horticultural reference"]','{"slug": "buckler-leaf-sorrel", "common_name": "Buckler-Leaf Sorrel", "scientific_name": "Rumex scutatus", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 70}, "days_to_maturity": {"min": 50, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; buckler-leaf sorrel is one of the first perennial herbs to produce harvestable leaves in spring."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 9, "max": 18}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Sow seeds 1/4 in deep in well-drained soil with moderate fertility; thin to 12 in apart once seedlings reach 2 in. Buckler-leaf sorrel has small, shield-shaped silvery-green leaves with a clean, bright lemon-acid flavor that is preferred over common sorrel in French cuisine for sorrel soup and sauces. Remove flowering stalks as they appear to redirect energy into leaf production; divide clumps every 2–3 years to maintain vigor. Harvest the small leaves regularly while they are fresh and tender, as flavor intensifies in older foliage to the point of bitterness.", "sources": ["general horticultural reference"]}')
