INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('calamint','Calamint','Clinopodium nepeta','herb','culinary',10,21,60,70,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost or divide established plants in spring; transplant after frost danger has passed.',5,9,12,18,12,24,12,18,'full','low','Surface-sow seeds on well-drained seed-starting mix and lightly press in; germination is steady within two to three weeks in warm conditions. Plant in lean, well-drained soil in full sun; calamint thrives in rocky or gravelly sites and is highly drought-tolerant once established. The small, aromatic leaves have a flavor that blends pennyroyal-mint with oregano, making it a traditional Italian seasoning for mushrooms and bean dishes. Cut back by half after the first flush of lavender flowers in midsummer to encourage a second bloom and fresh, tender growth for harvesting.','["general horticultural reference"]','{"slug": "calamint", "common_name": "Calamint", "scientific_name": "Clinopodium nepeta", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost or divide established plants in spring; transplant after frost danger has passed."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Surface-sow seeds on well-drained seed-starting mix and lightly press in; germination is steady within two to three weeks in warm conditions. Plant in lean, well-drained soil in full sun; calamint thrives in rocky or gravelly sites and is highly drought-tolerant once established. The small, aromatic leaves have a flavor that blends pennyroyal-mint with oregano, making it a traditional Italian seasoning for mushrooms and bean dishes. Cut back by half after the first flush of lavender flowers in midsummer to encourage a second bloom and fresh, tender growth for harvesting.", "sources": ["general horticultural reference"]}')
