INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('catnip','Catnip','Nepeta cataria','herb','aromatic perennial',7,14,60,70,70,90,'transplant','direct','perennial','hardy','last_frost',-2,2,'Direct sow around last frost date; crushing or nicking seed coat before sowing improves germination rates.',3,9,18,24,18,36,18,30,'full','low','Direct sow by pressing seeds lightly into moist soil; crushing the seed coat slightly before sowing can speed germination. Plants grown from seed attract cats less strongly than those that have been bruised, so direct-sown plants may establish more easily in gardens with resident cats. Cut back plants by half after the first flowering to encourage a second flush and prevent excessive seeding. Harvest aerial parts just before flowering for drying into cat toys and sachets; the nepetalactone content is highest at this stage, and the herb has mild calming properties for human tea use as well.','["general horticultural reference"]','{"slug": "catnip", "common_name": "Catnip", "scientific_name": "Nepeta cataria", "category": "herb", "subcategory": "aromatic perennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Direct sow around last frost date; crushing or nicking seed coat before sowing improves germination rates."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "low", "directions": "Direct sow by pressing seeds lightly into moist soil; crushing the seed coat slightly before sowing can speed germination. Plants grown from seed attract cats less strongly than those that have been bruised, so direct-sown plants may establish more easily in gardens with resident cats. Cut back plants by half after the first flowering to encourage a second flush and prevent excessive seeding. Harvest aerial parts just before flowering for drying into cat toys and sachets; the nepetalactone content is highest at this stage, and the herb has mild calming properties for human tea use as well.", "sources": ["general horticultural reference"]}')
