  VALUES ('chamomile-german','Chamomile (German)','Matricaria chamomilla','herb','annual',7,14,55,65,60,80,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow in early spring 2–4 weeks before last frost; light frost will not harm established seedlings.',3,9,6,9,18,24,6,9,'full','low','Surface-sow the tiny seeds by pressing them onto moist soil without covering; they require light to germinate. Thin seedlings to 6–9 in apart in well-drained, moderately poor soil—rich soil encourages lush stems that flop easily. German chamomile self-seeds reliably and will naturalize in a sunny spot with minimal care. Harvest flower heads just as the white petals begin to reflex downward, which indicates peak essential oil content for tea.','["general horticultural reference"]','{"slug": "chamomile-german", "common_name": "Chamomile (German)", "scientific_name": "Matricaria chamomilla", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring 2–4 weeks before last frost; light frost will not harm established seedlings."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 6, "max": 9}, "sun": "full", "water": "low", "directions": "Surface-sow the tiny seeds by pressing them onto moist soil without covering; they require light to germinate. Thin seedlings to 6–9 in apart in well-drained, moderately poor soil—rich soil encourages lush stems that flop easily. German chamomile self-seeds reliably and will naturalize in a sunny spot with minimal care. Harvest flower heads just as the white petals begin to reflex downward, which indicates peak essential oil content for tea.", "sources": ["general horticultural reference"]}')
