INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('chervil','Chervil','Anthriscus cerefolium','herb','annual',7,14,50,65,50,70,'seed','direct','cool','half-hardy','last_frost',-6,-4,'Direct sow 4–6 weeks before last frost in a shaded spot; again in late summer for a fall harvest.',3,11,6,9,12,24,6,9,'partial','moderate','Scatter seeds on the soil surface and press them in lightly, or cover with 1/8 in of fine soil; chervil prefers cool, partly shaded conditions and bolts quickly in heat. Direct sow rather than transplanting, as the taproot is sensitive to disturbance. Keep the soil consistently moist during germination and throughout the cool season. Harvest delicate, fern-like leaves when plants are 6–8 in tall, before any flower stalks emerge, to capture the mild anise flavor.','["general horticultural reference"]','{"slug": "chervil", "common_name": "Chervil", "scientific_name": "Anthriscus cerefolium", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Direct sow 4–6 weeks before last frost in a shaded spot; again in late summer for a fall harvest."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 6, "max": 9}, "sun": "partial", "water": "moderate", "directions": "Scatter seeds on the soil surface and press them in lightly, or cover with 1/8 in of fine soil; chervil prefers cool, partly shaded conditions and bolts quickly in heat. Direct sow rather than transplanting, as the taproot is sensitive to disturbance. Keep the soil consistently moist during germination and throughout the cool season. Harvest delicate, fern-like leaves when plants are 6–8 in tall, before any flower stalks emerge, to capture the mild anise flavor.", "sources": ["general horticultural reference"]}')
