INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('chicory','Chicory','Cichorium intybus','herb','culinary',7,14,55,75,60,85,'seed','direct','perennial','hardy','last_frost',-4,-2,'Direct sow in early spring 2–4 weeks before last frost; for root harvest, sow by early summer so roots mature by autumn.',3,9,12,18,24,60,12,18,'full','low','Sow seeds 1/4 in deep in deep, well-drained soil; chicory develops a long taproot that makes it drought-tolerant once established but resists transplanting. Young leaves provide a pleasantly bitter addition to salads and are most palatable before the plant flowers; blanching the developing crown under an upturned pot for 2–3 weeks produces creamy, milder forced leaves in late winter. The thick taproot is roasted and ground as a coffee substitute or additive, harvested in the plant''s second autumn. Bright blue flowers open and close with the sun daily, attracting bees through summer.','["general horticultural reference"]','{"slug": "chicory", "common_name": "Chicory", "scientific_name": "Cichorium intybus", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 75}, "days_to_maturity": {"min": 60, "max": 85}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring 2–4 weeks before last frost; for root harvest, sow by early summer so roots mature by autumn."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seeds 1/4 in deep in deep, well-drained soil; chicory develops a long taproot that makes it drought-tolerant once established but resists transplanting. Young leaves provide a pleasantly bitter addition to salads and are most palatable before the plant flowers; blanching the developing crown under an upturned pot for 2–3 weeks produces creamy, milder forced leaves in late winter. The thick taproot is roasted and ground as a coffee substitute or additive, harvested in the plant''s second autumn. Bright blue flowers open and close with the sun daily, attracting bees through summer.", "sources": ["general horticultural reference"]}')
