INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('chives','Chives','Allium schoenoprasum','herb','perennial',10,14,60,70,60,90,'seed','direct','perennial','hardy','last_frost',-6,-4,'Direct sow or start indoors 4–6 weeks before last frost; chives tolerate light frost.',3,9,6,9,12,18,6,12,'full','moderate','Sow seeds 1/4 in deep in groups of 4–6 and thin clumps to 6–9 in apart once established; thinnings are edible. Water regularly and divide crowded clumps every 2–3 years in spring or fall to maintain vigor. Remove spent flower heads to prevent excessive self-seeding, or leave a few for their edible, mildly onion-flavored blooms. Harvest by snipping leaves to about 1 in above the soil; plants regrow quickly.','["general horticultural reference"]','{"slug": "chives", "common_name": "Chives", "scientific_name": "Allium schoenoprasum", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Direct sow or start indoors 4–6 weeks before last frost; chives tolerate light frost."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep in groups of 4–6 and thin clumps to 6–9 in apart once established; thinnings are edible. Water regularly and divide crowded clumps every 2–3 years in spring or fall to maintain vigor. Remove spent flower heads to prevent excessive self-seeding, or leave a few for their edible, mildly onion-flavored blooms. Harvest by snipping leaves to about 1 in above the soil; plants regrow quickly.", "sources": ["general horticultural reference"]}')
