INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('chocolate-mint','Chocolate Mint','Mentha x piperita ''Chocolate''','herb','culinary',NULL,NULL,NULL,NULL,60,90,'transplant','division','perennial','hardy','last_frost',-2,2,'Plant divisions or rooted cuttings around the last frost date; this cultivar is a sterile peppermint hybrid and must be propagated vegetatively to maintain its chocolate-mint character.',5,9,18,24,12,24,18,36,'partial','moderate','Plant divisions in rich, consistently moist soil and confine the roots with a buried barrier or container, as this mint spreads aggressively like all peppermint cultivars. Provide consistent moisture and partial shade in hot climates to prevent the dark-stemmed foliage from scorching. Harvest stems just before flowers open for the most pronounced menthol-and-chocolate aroma; the leaves are prized for their distinctive scent in desserts, hot chocolate, and after-dinner teas. Cut plants back to 2–3 in above ground after each main harvest to stimulate a flush of fragrant new growth.','["general horticultural reference"]','{"slug": "chocolate-mint", "common_name": "Chocolate Mint", "scientific_name": "Mentha x piperita ''Chocolate''", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Plant divisions or rooted cuttings around the last frost date; this cultivar is a sterile peppermint hybrid and must be propagated vegetatively to maintain its chocolate-mint character."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 18, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Plant divisions in rich, consistently moist soil and confine the roots with a buried barrier or container, as this mint spreads aggressively like all peppermint cultivars. Provide consistent moisture and partial shade in hot climates to prevent the dark-stemmed foliage from scorching. Harvest stems just before flowers open for the most pronounced menthol-and-chocolate aroma; the leaves are prized for their distinctive scent in desserts, hot chocolate, and after-dinner teas. Cut plants back to 2–3 in above ground after each main harvest to stimulate a flush of fragrant new growth.", "sources": ["general horticultural reference"]}')
