  VALUES ('cilantro','Cilantro / Coriander','Coriandrum sativum','herb','annual',7,14,55,75,45,70,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; succession-sow every 3 weeks through spring and again in early fall.',3,11,6,8,12,24,6,9,'full','moderate','Lightly crush the husks before sowing, then press seeds 1/4 in into the soil and keep evenly moist until germination. Thin seedlings to 6 in apart so plants don''t compete for moisture, which slows bolting. Avoid transplanting; cilantro''s taproot resents disturbance. Begin harvesting outer leaves once plants reach 4–6 in, and harvest seed heads (coriander) when they turn tan and dry on the stem.','["general horticultural reference"]','{"slug": "cilantro", "common_name": "Cilantro / Coriander", "scientific_name": "Coriandrum sativum", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 75}, "days_to_maturity": {"min": 45, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; succession-sow every 3 weeks through spring and again in early fall."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 6, "max": 9}, "sun": "full", "water": "moderate", "directions": "Lightly crush the husks before sowing, then press seeds 1/4 in into the soil and keep evenly moist until germination. Thin seedlings to 6 in apart so plants don''t compete for moisture, which slows bolting. Avoid transplanting; cilantro''s taproot resents disturbance. Begin harvesting outer leaves once plants reach 4–6 in, and harvest seed heads (coriander) when they turn tan and dry on the stem.", "sources": ["general horticultural reference"]}')
