INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cinnamon-basil','Cinnamon Basil','Ocimum basilicum ''Cinnamon''','herb','culinary',5,10,65,85,60,80,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant only after all frost danger has passed.',2,11,12,18,18,30,12,18,'full','moderate','Sow seeds 1/4 in deep in fertile, moist seed-starting mix held above 65°F, and transplant outdoors once night temperatures stay above 50°F. Cinnamon basil has reddish stems and pink-purple flowers; it contains methyl cinnamate, which gives the foliage a distinct warm spice note alongside the usual basil flavor. Pinch out flower stalks as they appear to maintain leaf production, and harvest by cutting stems back to a set of lower leaves. Use fresh or dried in fruit dishes, desserts, teas, and anywhere a subtle cinnamon note complements the basil flavor.','["general horticultural reference"]','{"slug": "cinnamon-basil", "common_name": "Cinnamon Basil", "scientific_name": "Ocimum basilicum ''Cinnamon''", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant only after all frost danger has passed."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep in fertile, moist seed-starting mix held above 65°F, and transplant outdoors once night temperatures stay above 50°F. Cinnamon basil has reddish stems and pink-purple flowers; it contains methyl cinnamate, which gives the foliage a distinct warm spice note alongside the usual basil flavor. Pinch out flower stalks as they appear to maintain leaf production, and harvest by cutting stems back to a set of lower leaves. Use fresh or dried in fruit dishes, desserts, teas, and anywhere a subtle cinnamon note complements the basil flavor.", "sources": ["general horticultural reference"]}')
