INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('clary-sage','Clary Sage','Salvia sclarea','herb','aromatic',7,14,60,70,365,548,'seed','direct','perennial','hardy','last_frost',-4,-2,'Direct sow in early spring 2–4 weeks before last frost; as a biennial, plants flower and produce oil-rich bracts in their second summer.',4,9,18,24,48,60,18,24,'full','low','Sow seeds 1/4 in deep in well-drained, alkaline or neutral soil in full sun; germination is quick and reliable. In the first year the plant forms a large rosette of bold, wrinkled leaves; in the second year it sends up a dramatic 4–5 ft flower spike laden with showy pink-purple and white bracts. Harvest the flowering tops just as the flowers begin to open — the essential oil sclareol is concentrated in the sticky glands of the bracts and calyces. Dry the cut stems in bundles or steam-distill for essential oil used in perfumery, aromatherapy, and as a fixative in soaps and cosmetics.','["general horticultural reference"]','{"slug": "clary-sage", "common_name": "Clary Sage", "scientific_name": "Salvia sclarea", "category": "herb", "subcategory": "aromatic", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring 2–4 weeks before last frost; as a biennial, plants flower and produce oil-rich bracts in their second summer."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 48, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Sow seeds 1/4 in deep in well-drained, alkaline or neutral soil in full sun; germination is quick and reliable. In the first year the plant forms a large rosette of bold, wrinkled leaves; in the second year it sends up a dramatic 4–5 ft flower spike laden with showy pink-purple and white bracts. Harvest the flowering tops just as the flowers begin to open — the essential oil sclareol is concentrated in the sticky glands of the bracts and calyces. Dry the cut stems in bundles or steam-distill for essential oil used in perfumery, aromatherapy, and as a fixative in soaps and cosmetics.", "sources": ["general horticultural reference"]}')
