  VALUES ('sage-common','Common Sage','Salvia officinalis','herb','aromatic perennial',10,21,60,70,75,100,'transplant','indoor-start','perennial','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after all frost danger has passed as young plants are more cold-sensitive than mature ones.',4,8,18,24,18,30,18,30,'full','low','Sow seeds 1/4 in deep in warm starting mix; germination is reliable at 65–70°F. Plant in well-drained, moderately fertile soil and prune plants hard in spring to remove winter-killed tips and promote bushy growth from the base. Harvest leafy stems before flowering for culinary and medicinal use; the volatile oils are most concentrated on sunny mornings before flowering. Dried sage leaves and bundles are used in cooking, traditional salubrious teas, and as smudge sticks in ceremonial contexts.','["general horticultural reference"]','{"slug": "sage-common", "common_name": "Common Sage", "scientific_name": "Salvia officinalis", "category": "herb", "subcategory": "aromatic perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 75, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after all frost danger has passed as young plants are more cold-sensitive than mature ones."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "low", "directions": "Sow seeds 1/4 in deep in warm starting mix; germination is reliable at 65–70°F. Plant in well-drained, moderately fertile soil and prune plants hard in spring to remove winter-killed tips and promote bushy growth from the base. Harvest leafy stems before flowering for culinary and medicinal use; the volatile oils are most concentrated on sunny mornings before flowering. Dried sage leaves and bundles are used in cooking, traditional salubrious teas, and as smudge sticks in ceremonial contexts.", "sources": ["general horticultural reference"]}')
