INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('thyme-common','Common Thyme','Thymus vulgaris','herb','aromatic perennial',8,20,60,70,75,90,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; surface-sow or barely cover seed as light aids germination.',5,9,12,18,6,12,12,18,'full','low','Surface-sow seeds or cover to 1/8 in in warm, well-drained starting mix; seedlings are small and slow to establish so start early indoors. Plant in sharply drained, lean soil in full sun — like other Mediterranean herbs, thyme deteriorates in fertile, moist conditions. Trim plants lightly after each harvest to prevent woodiness; replace plants every 3–4 years when the center becomes unproductive. Harvest leafy stem tips before or during flowering for the highest thymol content, using fresh or dried in culinary preparations and traditional antiseptic and cough-relief remedies.','["general horticultural reference"]','{"slug": "thyme-common", "common_name": "Common Thyme", "scientific_name": "Thymus vulgaris", "category": "herb", "subcategory": "aromatic perennial", "days_to_germination": {"min": 8, "max": 20}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 75, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; surface-sow or barely cover seed as light aids germination."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Surface-sow seeds or cover to 1/8 in in warm, well-drained starting mix; seedlings are small and slow to establish so start early indoors. Plant in sharply drained, lean soil in full sun — like other Mediterranean herbs, thyme deteriorates in fertile, moist conditions. Trim plants lightly after each harvest to prevent woodiness; replace plants every 3–4 years when the center becomes unproductive. Harvest leafy stem tips before or during flowering for the highest thymol content, using fresh or dried in culinary preparations and traditional antiseptic and cough-relief remedies.", "sources": ["general horticultural reference"]}')
