  VALUES ('corsican-mint','Corsican Mint','Mentha requienii','herb','aromatic',10,21,60,70,60,90,'transplant','division','perennial','half-hardy','last_frost',-2,2,'Divide or transplant rooted mats around the last frost date; Corsican mint is the smallest mint and prefers cool, moist conditions.',6,9,6,9,1,3,12,24,'partial','moderate','Plant small divisions in consistently moist, humus-rich soil in a partially shaded spot; Corsican mint forms a moss-like carpet of tiny peppermint-scented leaves just 1–3 in tall and is ideal between stepping stones or at the edge of a cool, moist path. Unlike most mints, it dislikes hot, dry conditions and should never be allowed to dry out completely. The plant releases a powerful peppermint fragrance when lightly stepped on, making it a sensory ground cover. In zones 6–7 it may die back in hard winters but typically returns from the root; mulch lightly in late autumn to protect the shallow root system.','["general horticultural reference"]','{"slug": "corsican-mint", "common_name": "Corsican Mint", "scientific_name": "Mentha requienii", "category": "herb", "subcategory": "aromatic", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Divide or transplant rooted mats around the last frost date; Corsican mint is the smallest mint and prefers cool, moist conditions."}, "usda_zones": {"min": 6, "max": 9}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 1, "max": 3}, "spread_in": {"min": 12, "max": 24}, "sun": "partial", "water": "moderate", "directions": "Plant small divisions in consistently moist, humus-rich soil in a partially shaded spot; Corsican mint forms a moss-like carpet of tiny peppermint-scented leaves just 1–3 in tall and is ideal between stepping stones or at the edge of a cool, moist path. Unlike most mints, it dislikes hot, dry conditions and should never be allowed to dry out completely. The plant releases a powerful peppermint fragrance when lightly stepped on, making it a sensory ground cover. In zones 6–7 it may die back in hard winters but typically returns from the root; mulch lightly in late autumn to protect the shallow root system.", "sources": ["general horticultural reference"]}')
