  VALUES ('costmary','Costmary (Bible Leaf)','Tanacetum balsamita','herb','aromatic',10,21,60,70,90,120,'transplant','division','perennial','hardy','last_frost',-2,2,'Divide established root clumps in early spring around the last frost date; seed germination is slow and unreliable so division is the standard propagation method.',4,9,24,36,24,48,24,36,'full','low','Divide the clumping rhizome in early spring, replanting sections 2–3 in deep in well-drained, fertile soil in full sun; costmary tolerates partial shade but becomes straggly and produces fewer of the large, minty-balsamic leaves. The broad, silver-green leaves were historically placed in Bibles and hymnals as bookmarks because the pleasant fragrance helped keep the reader awake during long services — hence the common name. Harvest large, mature leaves at any point during the growing season for use as a herb in ales and meat dishes, for sachets in linen, or as a flavoring in salads and teas. Cut plants back hard after flowering to rejuvenate the foliage and prevent excessive spread.','["general horticultural reference"]','{"slug": "costmary", "common_name": "Costmary (Bible Leaf)", "scientific_name": "Tanacetum balsamita", "category": "herb", "subcategory": "aromatic", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Divide established root clumps in early spring around the last frost date; seed germination is slow and unreliable so division is the standard propagation method."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Divide the clumping rhizome in early spring, replanting sections 2–3 in deep in well-drained, fertile soil in full sun; costmary tolerates partial shade but becomes straggly and produces fewer of the large, minty-balsamic leaves. The broad, silver-green leaves were historically placed in Bibles and hymnals as bookmarks because the pleasant fragrance helped keep the reader awake during long services — hence the common name. Harvest large, mature leaves at any point during the growing season for use as a herb in ales and meat dishes, for sachets in linen, or as a flavoring in salads and teas. Cut plants back hard after flowering to rejuvenate the foliage and prevent excessive spread.", "sources": ["general horticultural reference"]}')
