INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('creeping-thyme','Creeping Thyme','Thymus praecox','herb','culinary',14,28,60,70,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost or divide established plants in spring; transplant after frost danger has passed.',4,9,9,12,2,4,12,24,'full','low','Surface-sow tiny seeds on well-drained seed-starting mix and press in without covering; germination is slow and irregular over 2–4 weeks. Plant in dry, gritty soil in full sun; creeping thyme thrives in rock gardens, between stepping stones, and on sunny slopes where it forms a fragrant, flowering mat. Avoid heavy clay and excessive moisture, which rot the shallow roots quickly. Harvest sprigs as needed for cooking — the flavor is milder than upright thyme but usable; the primary garden value is as a low, aromatic, bee-friendly ground cover.','["general horticultural reference"]','{"slug": "creeping-thyme", "common_name": "Creeping Thyme", "scientific_name": "Thymus praecox", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost or divide established plants in spring; transplant after frost danger has passed."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 2, "max": 4}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "low", "directions": "Surface-sow tiny seeds on well-drained seed-starting mix and press in without covering; germination is slow and irregular over 2–4 weeks. Plant in dry, gritty soil in full sun; creeping thyme thrives in rock gardens, between stepping stones, and on sunny slopes where it forms a fragrant, flowering mat. Avoid heavy clay and excessive moisture, which rot the shallow roots quickly. Harvest sprigs as needed for cooking — the flavor is milder than upright thyme but usable; the primary garden value is as a low, aromatic, bee-friendly ground cover.", "sources": ["general horticultural reference"]}')
