INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cuban-oregano','Cuban Oregano (Broad-Leaf Thyme)','Plectranthus amboinicus','herb','perennial',NULL,NULL,NULL,NULL,60,90,'transplant','transplant','perennial','tender','last_frost',0,4,'Root cuttings in water or moist mix and transplant after frost; in zone 9–11 plants overwinter but may die back to roots in zone 9 hard freezes.',9,11,18,30,12,24,24,48,'full','low','Propagate from stem cuttings 4–6 in long; cuttings root in 1–2 weeks in moist perlite or a glass of water and are far more reliable than seed. Plant in any well-drained soil in full sun to bright partial shade; Cuban oregano tolerates heat, humidity, and dry spells far better than Mediterranean oregano. The thick, succulent leaves have a pungent, oregano-like aroma intensified by thyme — use fresh in Caribbean, Indian, and Southeast Asian cooking. Remove flower spikes to keep the plant in vigorous vegetative growth; take a few cuttings before the first frost if growing as an annual.','["University of Florida IFAS Extension", "general horticultural reference"]','{"slug": "cuban-oregano", "common_name": "Cuban Oregano (Broad-Leaf Thyme)", "scientific_name": "Plectranthus amboinicus", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Root cuttings in water or moist mix and transplant after frost; in zone 9–11 plants overwinter but may die back to roots in zone 9 hard freezes."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 18, "max": 30}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 24, "max": 48}, "sun": "full", "water": "low", "directions": "Propagate from stem cuttings 4–6 in long; cuttings root in 1–2 weeks in moist perlite or a glass of water and are far more reliable than seed. Plant in any well-drained soil in full sun to bright partial shade; Cuban oregano tolerates heat, humidity, and dry spells far better than Mediterranean oregano. The thick, succulent leaves have a pungent, oregano-like aroma intensified by thyme — use fresh in Caribbean, Indian, and Southeast Asian cooking. Remove flower spikes to keep the plant in vigorous vegetative growth; take a few cuttings before the first frost if growing as an annual.", "sources": ["University of Florida IFAS Extension", "general horticultural reference"]}')
