INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('culantro','Culantro (Recao)','Eryngium foetidum','herb','culinary',14,21,70,85,70,90,'seed','direct','warm','tender','last_frost',0,2,'Direct sow after last frost in a warm, partially shaded site; culantro prefers high heat and humidity.',9,11,9,12,8,18,9,12,'partial','moderate','Sow seeds on the soil surface and press in lightly; germination can be slow and erratic, so sow generously and keep soil consistently moist and warm. Culantro thrives in partial shade and high humidity, performing well in spots too hot and bright for cilantro; its strap-like, serrated leaves have a much more intense cilantro flavor and hold up better in cooking. Thin seedlings to 9–12 in apart and keep soil moderately moist; the plant bolts to flower in dry or cool conditions. Harvest individual outer leaves at any time; one or two leaves substitute for a much larger amount of cilantro in sofrito, chutneys, and Caribbean stews.','["general horticultural reference"]','{"slug": "culantro", "common_name": "Culantro (Recao)", "scientific_name": "Eryngium foetidum", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow after last frost in a warm, partially shaded site; culantro prefers high heat and humidity."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 8, "max": 18}, "spread_in": {"min": 9, "max": 12}, "sun": "partial", "water": "moderate", "directions": "Sow seeds on the soil surface and press in lightly; germination can be slow and erratic, so sow generously and keep soil consistently moist and warm. Culantro thrives in partial shade and high humidity, performing well in spots too hot and bright for cilantro; its strap-like, serrated leaves have a much more intense cilantro flavor and hold up better in cooking. Thin seedlings to 9–12 in apart and keep soil moderately moist; the plant bolts to flower in dry or cool conditions. Harvest individual outer leaves at any time; one or two leaves substitute for a much larger amount of cilantro in sofrito, chutneys, and Caribbean stews.", "sources": ["general horticultural reference"]}')
