INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('curry-leaf','Curry Leaf','Murraya koenigii','herb','perennial',14,28,70,85,180,365,'transplant','transplant','perennial','tender','last_frost',0,4,'Plant container-grown stock after last frost; in zone 9 protect with frost cloth during freezes — the woody stems can survive brief dips to 28°F once established.',9,11,36,60,48,96,36,60,'full','moderate','Plant in well-drained, moderately fertile soil in full sun; curry leaf shrubs grow slowly at first but accelerate once established in a warm zone 9–11 site. Fresh leaves are essential to South Indian cooking and release their aroma only when heated in oil — dried leaves are a poor substitute, so growing your own is worthwhile. Harvest by snipping young branch tips regularly, which encourages dense new growth; remove flower clusters as they appear if you prefer to maximize leaf production. Mulch heavily through zone 9 winters and wrap the trunk if temperatures below 28°F are expected for more than a night or two.','["general horticultural reference", "University of Florida IFAS Extension"]','{"slug": "curry-leaf", "common_name": "Curry Leaf", "scientific_name": "Murraya koenigii", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 180, "max": 365}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant container-grown stock after last frost; in zone 9 protect with frost cloth during freezes — the woody stems can survive brief dips to 28°F once established."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 48, "max": 96}, "spread_in": {"min": 36, "max": 60}, "sun": "full", "water": "moderate", "directions": "Plant in well-drained, moderately fertile soil in full sun; curry leaf shrubs grow slowly at first but accelerate once established in a warm zone 9–11 site. Fresh leaves are essential to South Indian cooking and release their aroma only when heated in oil — dried leaves are a poor substitute, so growing your own is worthwhile. Harvest by snipping young branch tips regularly, which encourages dense new growth; remove flower clusters as they appear if you prefer to maximize leaf production. Mulch heavily through zone 9 winters and wrap the trunk if temperatures below 28°F are expected for more than a night or two.", "sources": ["general horticultural reference", "University of Florida IFAS Extension"]}')
