INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('curry-plant','Curry Plant','Helichrysum italicum','herb','aromatic',14,21,65,75,180,365,'transplant','cutting','perennial','half-hardy','last_frost',0,4,'Plant rooted cuttings after last frost; easier to propagate from cuttings than from slow and variable seed.',7,11,18,24,12,24,18,24,'full','low','Take 3–4 in softwood cuttings in late spring, strip lower leaves, and insert into sharp-draining propagating mix; roots develop in 3–4 weeks. The silver-needle foliage has a striking curry-like aroma but this herb is primarily used for its fragrance rather than as a true culinary spice — a leaf or two can be added to braises or soups but should be removed before serving. Plant in sharply drained, lean soil in full sun; it is native to Mediterranean coastal cliffs and thrives under hot, dry conditions. Trim lightly after the yellow button flowers fade to keep the plant tidy; in zone 7 mulch over winter or take cuttings as insurance against hard freezes.','["general horticultural reference"]','{"slug": "curry-plant", "common_name": "Curry Plant", "scientific_name": "Helichrysum italicum", "category": "herb", "subcategory": "aromatic", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 180, "max": 365}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted cuttings after last frost; easier to propagate from cuttings than from slow and variable seed."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Take 3–4 in softwood cuttings in late spring, strip lower leaves, and insert into sharp-draining propagating mix; roots develop in 3–4 weeks. The silver-needle foliage has a striking curry-like aroma but this herb is primarily used for its fragrance rather than as a true culinary spice — a leaf or two can be added to braises or soups but should be removed before serving. Plant in sharply drained, lean soil in full sun; it is native to Mediterranean coastal cliffs and thrives under hot, dry conditions. Trim lightly after the yellow button flowers fade to keep the plant tidy; in zone 7 mulch over winter or take cuttings as insurance against hard freezes.", "sources": ["general horticultural reference"]}')
