  VALUES ('damiana','Damiana','Turnera diffusa','herb','medicinal',14,28,70,85,150,240,'transplant','cutting','perennial','tender','last_frost',0,4,'Root cuttings in late spring and transplant after all frost danger has passed; damiana is a subtropical shrub that needs consistent warmth to establish.',9,12,24,36,24,72,24,48,'full','low','Take 3–4 in stem cuttings in spring or summer and root in gritty, barely moist medium; damiana is easier and faster from cuttings than from the slow-germinating seed. Plant in sharply drained, sandy or rocky, poor soil in full sun — damiana is native to the dry shrublands of Mexico and the Caribbean and rots in moist, fertile conditions. In zones below 9, grow in containers and overwinter in a frost-free, bright location, watering sparingly. Harvest leafy stems and the small yellow flowers throughout the growing season, drying them for use in traditional Mexican tonic teas and liqueur preparations.','["general horticultural reference"]','{"slug": "damiana", "common_name": "Damiana", "scientific_name": "Turnera diffusa", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 150, "max": 240}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Root cuttings in late spring and transplant after all frost danger has passed; damiana is a subtropical shrub that needs consistent warmth to establish."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 24, "max": 72}, "spread_in": {"min": 24, "max": 48}, "sun": "full", "water": "low", "directions": "Take 3–4 in stem cuttings in spring or summer and root in gritty, barely moist medium; damiana is easier and faster from cuttings than from the slow-germinating seed. Plant in sharply drained, sandy or rocky, poor soil in full sun — damiana is native to the dry shrublands of Mexico and the Caribbean and rots in moist, fertile conditions. In zones below 9, grow in containers and overwinter in a frost-free, bright location, watering sparingly. Harvest leafy stems and the small yellow flowers throughout the growing season, drying them for use in traditional Mexican tonic teas and liqueur preparations.", "sources": ["general horticultural reference"]}')
