  VALUES ('dandelion','Dandelion','Taraxacum officinale','herb','medicinal',7,14,50,70,60,95,'seed','direct','perennial','hardy','last_frost',-6,-2,'Direct sow in early spring as soon as soil is workable; also sow in late summer for autumn and early spring harvest.',3,10,9,12,6,18,9,15,'full','low','Sow seeds 1/8 in deep in deep, loose, well-drained soil; cultivated broad-leafed varieties produce larger, more tender leaves than typical lawn weeds. Blanch developing rosettes under a cover for 1–2 weeks in spring to produce milder, less bitter leaves for salads. All plant parts are useful: young leaves are eaten raw or cooked, flowers are made into wine or fritters, and the taproot is roasted as a coffee substitute or used fresh in bitter-tonic preparations. Harvest roots in autumn of the second year when they are largest and most concentrated in the liver-supportive compound taraxacin.','["general horticultural reference"]','{"slug": "dandelion", "common_name": "Dandelion", "scientific_name": "Taraxacum officinale", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 50, "max": 70}, "days_to_maturity": {"min": 60, "max": 95}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -2}, "note": "Direct sow in early spring as soon as soil is workable; also sow in late summer for autumn and early spring harvest."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 6, "max": 18}, "spread_in": {"min": 9, "max": 15}, "sun": "full", "water": "low", "directions": "Sow seeds 1/8 in deep in deep, loose, well-drained soil; cultivated broad-leafed varieties produce larger, more tender leaves than typical lawn weeds. Blanch developing rosettes under a cover for 1–2 weeks in spring to produce milder, less bitter leaves for salads. All plant parts are useful: young leaves are eaten raw or cooked, flowers are made into wine or fritters, and the taproot is roasted as a coffee substitute or used fresh in bitter-tonic preparations. Harvest roots in autumn of the second year when they are largest and most concentrated in the liver-supportive compound taraxacin.", "sources": ["general horticultural reference"]}')
