  VALUES ('echinacea','Echinacea / Purple Coneflower','Echinacea purpurea','herb','medicinal perennial',10,21,65,75,120,150,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost or direct sow in fall for natural cold stratification; transplant after frost danger passes.',3,9,18,24,24,48,18,24,'full','low','Sow seed on the surface or just 1/8 in deep; cold stratification for 4–8 weeks significantly improves germination rates, especially for fresh seed. Plant in well-drained soil and avoid overwatering once established, as echinacea tolerates drought well. Roots are the primary medicinal part and are harvested in fall of the third or fourth year; flowers and leaves can be harvested earlier for teas and tinctures. Allow some seed heads to remain for self-seeding and to feed overwintering birds.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "echinacea", "common_name": "Echinacea / Purple Coneflower", "scientific_name": "Echinacea purpurea", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 120, "max": 150}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost or direct sow in fall for natural cold stratification; transplant after frost danger passes."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Sow seed on the surface or just 1/8 in deep; cold stratification for 4–8 weeks significantly improves germination rates, especially for fresh seed. Plant in well-drained soil and avoid overwatering once established, as echinacea tolerates drought well. Roots are the primary medicinal part and are harvested in fall of the third or fourth year; flowers and leaves can be harvested earlier for teas and tinctures. Allow some seed heads to remain for self-seeding and to feed overwintering birds.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
