INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('epazote','Epazote','Dysphania ambrosioides','herb','annual',7,14,65,80,50,70,'seed','direct','warm','tender','last_frost',0,2,'Direct sow at or just after last frost once soil has warmed; epazote self-seeds prolifically once established.',8,11,12,18,18,48,12,18,'full','low','Surface-sow the tiny seeds by pressing them gently into soil without covering, as they require light for germination; thin to 12–18 in. Epazote is remarkably drought-tolerant once established and thrives in lean, well-drained soil; rich, moist conditions encourage excessive growth. Deadhead regularly to control self-seeding, which can be invasive in warm climates. Harvest young stem tips throughout the season; the pungent, resinous flavor mellows somewhat with cooking.','["general horticultural reference"]','{"slug": "epazote", "common_name": "Epazote", "scientific_name": "Dysphania ambrosioides", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 80}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow at or just after last frost once soil has warmed; epazote self-seeds prolifically once established."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 48}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Surface-sow the tiny seeds by pressing them gently into soil without covering, as they require light for germination; thin to 12–18 in. Epazote is remarkably drought-tolerant once established and thrives in lean, well-drained soil; rich, moist conditions encourage excessive growth. Deadhead regularly to control self-seeding, which can be invasive in warm climates. Harvest young stem tips throughout the season; the pungent, resinous flavor mellows somewhat with cooking.", "sources": ["general horticultural reference"]}')
