INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('fenugreek','Fenugreek','Trigonella foenum-graecum','herb','annual',3,7,60,75,20,30,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; can also sow in late summer for a fall crop.',3,11,6,9,12,24,4,6,'full','moderate','Soak seeds overnight to speed germination, then sow 1/2 in deep in rows and thin to 6 in apart; fenugreek prefers cool conditions and will bolt quickly in summer heat. Grow in well-drained, fertile soil in full sun. Days to maturity listed is for young leaf harvest; allow 3–5 months for seed pods to develop and dry if growing for seed spice. Harvest leaves at any time for use as a slightly bitter herb, and collect seed pods once they turn tan and feel firm.','["general horticultural reference"]','{"slug": "fenugreek", "common_name": "Fenugreek", "scientific_name": "Trigonella foenum-graecum", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 3, "max": 7}, "germination_soil_temp_f": {"min": 60, "max": 75}, "days_to_maturity": {"min": 20, "max": 30}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; can also sow in late summer for a fall crop."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Soak seeds overnight to speed germination, then sow 1/2 in deep in rows and thin to 6 in apart; fenugreek prefers cool conditions and will bolt quickly in summer heat. Grow in well-drained, fertile soil in full sun. Days to maturity listed is for young leaf harvest; allow 3–5 months for seed pods to develop and dry if growing for seed spice. Harvest leaves at any time for use as a slightly bitter herb, and collect seed pods once they turn tan and feel firm.", "sources": ["general horticultural reference"]}')
