INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('french-sorrel','French Sorrel','Rumex scutatus','herb','perennial',7,14,55,70,50,60,'seed','direct','perennial','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; sorrel is one of the first herbs to emerge in spring.',4,9,12,18,12,18,12,18,'partial','moderate','Sow seeds 1/4 in deep in well-drained, moderately fertile soil; thin to 12 in apart once seedlings are 2 in tall. Remove flower stalks as soon as they appear to prevent the plant from diverting energy away from leaf production. Divide established clumps every 2–3 years to maintain vigor and refresh the planting. Harvest the shield-shaped leaves regularly while they are young and tender; the bright, lemony oxalic flavor becomes more pronounced in larger, older leaves.','["general horticultural reference"]','{"slug": "french-sorrel", "common_name": "French Sorrel", "scientific_name": "Rumex scutatus", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 70}, "days_to_maturity": {"min": 50, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; sorrel is one of the first herbs to emerge in spring."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Sow seeds 1/4 in deep in well-drained, moderately fertile soil; thin to 12 in apart once seedlings are 2 in tall. Remove flower stalks as soon as they appear to prevent the plant from diverting energy away from leaf production. Divide established clumps every 2–3 years to maintain vigor and refresh the planting. Harvest the shield-shaped leaves regularly while they are young and tender; the bright, lemony oxalic flavor becomes more pronounced in larger, older leaves.", "sources": ["general horticultural reference"]}')
