INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('french-tarragon','French Tarragon','Artemisia dracunculus var. sativa','herb','perennial',NULL,NULL,NULL,NULL,60,90,'transplant','division','perennial','hardy','last_frost',-2,2,'Plant divisions or rooted cuttings around last frost date; French tarragon does not come true from seed.',4,8,18,24,18,36,12,18,'full','low','Always source French tarragon as a division or cutting—seeds sold as tarragon are typically the flavorless Russian type. Plant in lean, well-drained soil; overly rich soil encourages lush but bland foliage. Divide plants every 2–3 years in spring to maintain flavor and vigor, discarding old woody centers. Begin harvesting once shoots reach 6 in; the anise-like fragrance intensifies just before the plant''s inconspicuous flowers open.','["general horticultural reference"]','{"slug": "french-tarragon", "common_name": "French Tarragon", "scientific_name": "Artemisia dracunculus var. sativa", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Plant divisions or rooted cuttings around last frost date; French tarragon does not come true from seed."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Always source French tarragon as a division or cutting—seeds sold as tarragon are typically the flavorless Russian type. Plant in lean, well-drained soil; overly rich soil encourages lush but bland foliage. Divide plants every 2–3 years in spring to maintain flavor and vigor, discarding old woody centers. Begin harvesting once shoots reach 6 in; the anise-like fragrance intensifies just before the plant''s inconspicuous flowers open.", "sources": ["general horticultural reference"]}')
