INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('galangal','Galangal (Greater Galangal)','Alpinia galanga','herb','culinary',NULL,NULL,NULL,NULL,270,365,'transplant','division','perennial','tender','last_frost',2,6,'Plant rhizome divisions after last frost once soil has thoroughly warmed to at least 70°F; galangal needs extended warm conditions.',9,12,24,36,48,84,24,36,'partial','high','Plant rhizome sections with at least one growing bud 2–4 in deep in rich, moisture-retentive, humus-rich soil in partial shade; galangal needs consistent moisture and high humidity to thrive. Unlike ginger, galangal has a distinctly peppery, piney, medicinal flavor with less sweetness, and is a foundational ingredient in Thai, Indonesian, and Malay cuisines. In zones below 9, grow in large containers that can be moved indoors before frost; the rhizomes are frost-sensitive but the plant can be stored dormant above 50°F in winter. Harvest rhizomes after 10–12 months when the foliage begins to yellow in fall, digging with care to take only what is needed while leaving part of the clump to regrow.','["general horticultural reference"]','{"slug": "galangal", "common_name": "Galangal (Greater Galangal)", "scientific_name": "Alpinia galanga", "category": "herb", "subcategory": "culinary", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 270, "max": 365}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 6}, "note": "Plant rhizome divisions after last frost once soil has thoroughly warmed to at least 70°F; galangal needs extended warm conditions."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 48, "max": 84}, "spread_in": {"min": 24, "max": 36}, "sun": "partial", "water": "high", "directions": "Plant rhizome sections with at least one growing bud 2–4 in deep in rich, moisture-retentive, humus-rich soil in partial shade; galangal needs consistent moisture and high humidity to thrive. Unlike ginger, galangal has a distinctly peppery, piney, medicinal flavor with less sweetness, and is a foundational ingredient in Thai, Indonesian, and Malay cuisines. In zones below 9, grow in large containers that can be moved indoors before frost; the rhizomes are frost-sensitive but the plant can be stored dormant above 50°F in winter. Harvest rhizomes after 10–12 months when the foliage begins to yellow in fall, digging with care to take only what is needed while leaving part of the clump to regrow.", "sources": ["general horticultural reference"]}')
