  VALUES ('good-king-henry','Good King Henry','Blitum bonus-henricus','herb','culinary',14,21,50,65,60,90,'seed','direct','perennial','hardy','soil_workable',0,2,'Direct sow as soon as soil can be worked in early spring; seeds may need cold stratification for best germination.',3,7,12,18,12,24,12,18,'partial','moderate','Cold-stratify seeds in the refrigerator for 2–4 weeks before sowing to improve germination rates; sow 1/4 in deep in moisture-retentive, fertile soil. This old European cottage garden vegetable-herb was once widely grown for its young shoots (used like asparagus), leaves (used like spinach), and flower buds (used like broccoli). Grow in moist, humus-rich soil in partial shade; plants are long-lived perennials once established and require little care. Harvest young shoots in spring, leaves throughout the season, and flower buds before they open; do not harvest heavily in the first year to allow the plant to establish.','["general horticultural reference"]','{"slug": "good-king-henry", "common_name": "Good King Henry", "scientific_name": "Blitum bonus-henricus", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow as soon as soil can be worked in early spring; seeds may need cold stratification for best germination."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Cold-stratify seeds in the refrigerator for 2–4 weeks before sowing to improve germination rates; sow 1/4 in deep in moisture-retentive, fertile soil. This old European cottage garden vegetable-herb was once widely grown for its young shoots (used like asparagus), leaves (used like spinach), and flower buds (used like broccoli). Grow in moist, humus-rich soil in partial shade; plants are long-lived perennials once established and require little care. Harvest young shoots in spring, leaves throughout the season, and flower buds before they open; do not harvest heavily in the first year to allow the plant to establish.", "sources": ["general horticultural reference"]}')
