INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('gotu-kola','Gotu Kola','Centella asiatica','herb','medicinal',14,28,70,85,90,120,'transplant','transplant','perennial','tender','last_frost',0,2,'Transplant rooted runners after all frost danger has passed into a warm, moist location; propagation from stolons is far more reliable than seed.',9,12,12,18,2,6,12,24,'partial','high','Propagate from stolons (creeping stems with nodes), which root readily in moist potting mix or at the edges of ponds; plant in rich, consistently moist to wet soil in partial shade, as gotu kola thrives in the margins of water bodies in its native tropical Asian habitat. In zones below 9, grow in containers that can be overwintered on a warm, bright windowsill with consistently moist soil. Harvest the small, fan-shaped leaves regularly once the plant is established; the fresh leaves are eaten in salads in Sri Lankan cuisine and used in Ayurvedic and traditional Chinese medicine as a cognitive tonic and wound-healing herb. Harvest leaf material by snipping stems without uprooting the plant to allow continued production.','["general horticultural reference"]','{"slug": "gotu-kola", "common_name": "Gotu Kola", "scientific_name": "Centella asiatica", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Transplant rooted runners after all frost danger has passed into a warm, moist location; propagation from stolons is far more reliable than seed."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 2, "max": 6}, "spread_in": {"min": 12, "max": 24}, "sun": "partial", "water": "high", "directions": "Propagate from stolons (creeping stems with nodes), which root readily in moist potting mix or at the edges of ponds; plant in rich, consistently moist to wet soil in partial shade, as gotu kola thrives in the margins of water bodies in its native tropical Asian habitat. In zones below 9, grow in containers that can be overwintered on a warm, bright windowsill with consistently moist soil. Harvest the small, fan-shaped leaves regularly once the plant is established; the fresh leaves are eaten in salads in Sri Lankan cuisine and used in Ayurvedic and traditional Chinese medicine as a cognitive tonic and wound-healing herb. Harvest leaf material by snipping stems without uprooting the plant to allow continued production.", "sources": ["general horticultural reference"]}')
