INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('greek-basil','Greek Basil','Ocimum basilicum var. minimum','herb','culinary',5,10,65,85,60,80,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant after nights are reliably above 50°F.',2,11,8,12,8,12,8,12,'full','moderate','Sow seeds 1/4 in deep in warm, moist seed-starting mix and thin seedlings to avoid crowding once they have two true leaves. Greek basil forms a naturally compact, globe-shaped mound with tiny, intensely aromatic leaves — no pinching required to maintain shape, though removing flower buds prolongs leaf harvest. Plant in fertile, well-drained soil in full sun; the petite habit makes it an excellent edging plant or container herb. Harvest by snipping small stem tips; the high surface-area-to-volume ratio of the small leaves delivers concentrated flavor.','["general horticultural reference"]','{"slug": "greek-basil", "common_name": "Greek Basil", "scientific_name": "Ocimum basilicum var. minimum", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant after nights are reliably above 50°F."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 8, "max": 12}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep in warm, moist seed-starting mix and thin seedlings to avoid crowding once they have two true leaves. Greek basil forms a naturally compact, globe-shaped mound with tiny, intensely aromatic leaves — no pinching required to maintain shape, though removing flower buds prolongs leaf harvest. Plant in fertile, well-drained soil in full sun; the petite habit makes it an excellent edging plant or container herb. Harvest by snipping small stem tips; the high surface-area-to-volume ratio of the small leaves delivers concentrated flavor.", "sources": ["general horticultural reference"]}')
