INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('greek-mountain-tea','Greek Mountain Tea (Sideritis)','Sideritis syriaca','herb','tea',14,28,65,75,180,365,'transplant','indoor-start','perennial','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after frost danger passes into very well-drained, rocky or sandy soil.',7,11,18,24,12,24,12,18,'full','low','Sow seeds 1/8 in deep in well-drained, alkaline starting mix and keep warm at 68–72°F until germination; use gritty, mineral-rich mix to mimic its rocky Mediterranean mountain habitat. Plant out in the poorest, most well-drained spot in the garden — excess moisture and rich soil are the primary causes of failure. The silver-felted stems and leaves are harvested in full bloom in summer when the yellow flowers are visible; cut entire stems and hang in bundles to dry in a warm, airy space. Brew the whole dried stems as an herbal tea by simmering 5–10 minutes; the resulting infusion has a mild, honey-and-herb flavor and is traditionally consumed throughout Greece for immune support and as an everyday tonic.','["general horticultural reference"]','{"slug": "greek-mountain-tea", "common_name": "Greek Mountain Tea (Sideritis)", "scientific_name": "Sideritis syriaca", "category": "herb", "subcategory": "tea", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 180, "max": 365}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after frost danger passes into very well-drained, rocky or sandy soil."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seeds 1/8 in deep in well-drained, alkaline starting mix and keep warm at 68–72°F until germination; use gritty, mineral-rich mix to mimic its rocky Mediterranean mountain habitat. Plant out in the poorest, most well-drained spot in the garden — excess moisture and rich soil are the primary causes of failure. The silver-felted stems and leaves are harvested in full bloom in summer when the yellow flowers are visible; cut entire stems and hang in bundles to dry in a warm, airy space. Brew the whole dried stems as an herbal tea by simmering 5–10 minutes; the resulting infusion has a mild, honey-and-herb flavor and is traditionally consumed throughout Greece for immune support and as an everyday tonic.", "sources": ["general horticultural reference"]}')
