INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('greek-oregano','Greek Oregano','Origanum vulgare subsp. hirtum','herb','culinary',7,14,65,75,80,100,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost and transplant after all frost danger has passed.',5,10,12,18,12,20,12,18,'full','low','Surface-sow seeds by pressing them into barely moist, well-drained seed-starting mix without covering, as they need light to germinate. Greek oregano (also called Italian or true oregano) is the pungent, white-flowered subspecies prized in Mediterranean cooking; it has far stronger flavor than common Origanum vulgare. Plant in lean, gritty, alkaline-leaning soil in full sun — excessive fertility dilutes the essential oils that give it its distinctive bite. Cut plants back by one-third after flowering each year to keep them compact; harvest just as buds begin to open for peak aroma.','["general horticultural reference"]','{"slug": "greek-oregano", "common_name": "Greek Oregano", "scientific_name": "Origanum vulgare subsp. hirtum", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 80, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost and transplant after all frost danger has passed."}, "usda_zones": {"min": 5, "max": 10}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 20}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Surface-sow seeds by pressing them into barely moist, well-drained seed-starting mix without covering, as they need light to germinate. Greek oregano (also called Italian or true oregano) is the pungent, white-flowered subspecies prized in Mediterranean cooking; it has far stronger flavor than common Origanum vulgare. Plant in lean, gritty, alkaline-leaning soil in full sun — excessive fertility dilutes the essential oils that give it its distinctive bite. Cut plants back by one-third after flowering each year to keep them compact; harvest just as buds begin to open for peak aroma.", "sources": ["general horticultural reference"]}')
