  VALUES ('hoja-santa','Hoja Santa (Root Beer Plant)','Piper auritum','herb','culinary',NULL,NULL,NULL,NULL,60,90,'transplant','division','perennial','half-hardy','last_frost',0,4,'Plant divisions or rooted suckers after last frost; in zones below 8 grow in large containers and overwinter indoors.',8,11,36,60,48,120,36,72,'partial','moderate','Divide established clumps in spring by separating rooted suckers from the base of the mother plant and replanting in rich, moist soil. Hoja santa grows rapidly in warm, humid conditions and prefers partial shade with consistent moisture; the enormous heart-shaped leaves can reach 12 in wide and emit a distinctive anise–root beer aroma from their essential oils. In Mexican cuisine the leaves are used to wrap tamales, season mole verde, and envelop fish for grilling. In zones 8–9, plants die to the ground after frost but reliably regrow from the roots; mulch heavily to protect the root zone through winter.','["general horticultural reference"]','{"slug": "hoja-santa", "common_name": "Hoja Santa (Root Beer Plant)", "scientific_name": "Piper auritum", "category": "herb", "subcategory": "culinary", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant divisions or rooted suckers after last frost; in zones below 8 grow in large containers and overwinter indoors."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 48, "max": 120}, "spread_in": {"min": 36, "max": 72}, "sun": "partial", "water": "moderate", "directions": "Divide established clumps in spring by separating rooted suckers from the base of the mother plant and replanting in rich, moist soil. Hoja santa grows rapidly in warm, humid conditions and prefers partial shade with consistent moisture; the enormous heart-shaped leaves can reach 12 in wide and emit a distinctive anise–root beer aroma from their essential oils. In Mexican cuisine the leaves are used to wrap tamales, season mole verde, and envelop fish for grilling. In zones 8–9, plants die to the ground after frost but reliably regrow from the roots; mulch heavily to protect the root zone through winter.", "sources": ["general horticultural reference"]}')
