INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('holy-basil-tulsi','Holy Basil / Tulsi','Ocimum tenuiflorum','herb','medicinal annual',7,14,70,85,60,90,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; do not transplant until nights are reliably above 55°F as cold soil stunts growth.',10,12,12,18,18,36,12,18,'full','moderate','Sow seeds 1/4 in deep in warm starting mix at 75–85°F; germination is swift when soil is adequately warm. Transplant after night temperatures stay above 55°F and pinch growing tips immediately to promote bushy growth. Regular pinching and removal of flower spikes prolongs the leaf harvest and delays bitterness; harvest leaves in the morning after dew has dried for the most aromatic result. Fresh or dried leaves are used in adaptogenic teas, Ayurvedic preparations, and as a sacred plant in Hindu tradition.','["general horticultural reference"]','{"slug": "holy-basil-tulsi", "common_name": "Holy Basil / Tulsi", "scientific_name": "Ocimum tenuiflorum", "category": "herb", "subcategory": "medicinal annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; do not transplant until nights are reliably above 55°F as cold soil stunts growth."}, "usda_zones": {"min": 10, "max": 12}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep in warm starting mix at 75–85°F; germination is swift when soil is adequately warm. Transplant after night temperatures stay above 55°F and pinch growing tips immediately to promote bushy growth. Regular pinching and removal of flower spikes prolongs the leaf harvest and delays bitterness; harvest leaves in the morning after dew has dried for the most aromatic result. Fresh or dried leaves are used in adaptogenic teas, Ayurvedic preparations, and as a sacred plant in Hindu tradition.", "sources": ["general horticultural reference"]}')
