INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('huacatay','Huacatay (Black Mint)','Tagetes minuta','herb','culinary',7,14,65,80,70,90,'seed','direct','warm','tender','last_frost',0,2,'Direct sow after last frost once soil is warm; can also be started indoors 4 weeks early for a longer season.',9,11,18,24,48,96,12,18,'full','low','Sow seeds 1/4 in deep in well-drained soil after last frost; thin to 18–24 in apart as huacatay grows into a tall, upright plant. This Andean herb — essential in Peruvian cuisine for dishes like ocopa sauce and anticuchos marinades — has a complex flavor combining mint, tarragon, and citrus. Plants are day-length sensitive and flower in late summer to fall; harvest leaves and stem tips throughout the vegetative season before flowering commences. Grow in full sun with moderate fertility; the plant is drought-tolerant once established and spreads by self-seeding in warm climates.','["general horticultural reference"]','{"slug": "huacatay", "common_name": "Huacatay (Black Mint)", "scientific_name": "Tagetes minuta", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 80}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow after last frost once soil is warm; can also be started indoors 4 weeks early for a longer season."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 48, "max": 96}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seeds 1/4 in deep in well-drained soil after last frost; thin to 18–24 in apart as huacatay grows into a tall, upright plant. This Andean herb — essential in Peruvian cuisine for dishes like ocopa sauce and anticuchos marinades — has a complex flavor combining mint, tarragon, and citrus. Plants are day-length sensitive and flower in late summer to fall; harvest leaves and stem tips throughout the vegetative season before flowering commences. Grow in full sun with moderate fertility; the plant is drought-tolerant once established and spreads by self-seeding in warm climates.", "sources": ["general horticultural reference"]}')
