INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('hyssop','Hyssop','Hyssopus officinalis','herb','aromatic perennial',7,14,60,70,75,100,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; surface-sow or cover lightly with 1/8 in of fine mix.',3,9,12,18,18,24,12,18,'full','low','Sow seeds 1/8 in deep indoors in warm starting mix; germination is fast and reliable at 65–70°F. Plant in lean, well-drained, slightly alkaline soil — hyssop is drought-tolerant once established and thrives in conditions similar to lavender. Prune plants back by about one-third after flowering to keep them from becoming woody and to promote a compact, bushy habit. Harvest leafy stems and flowers in the morning just as the blossoms begin to open, drying them for use in expectorant teas, culinary herb blends, and potpourri.','["general horticultural reference"]','{"slug": "hyssop", "common_name": "Hyssop", "scientific_name": "Hyssopus officinalis", "category": "herb", "subcategory": "aromatic perennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 75, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; surface-sow or cover lightly with 1/8 in of fine mix."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seeds 1/8 in deep indoors in warm starting mix; germination is fast and reliable at 65–70°F. Plant in lean, well-drained, slightly alkaline soil — hyssop is drought-tolerant once established and thrives in conditions similar to lavender. Prune plants back by about one-third after flowering to keep them from becoming woody and to promote a compact, bushy habit. Harvest leafy stems and flowers in the morning just as the blossoms begin to open, drying them for use in expectorant teas, culinary herb blends, and potpourri.", "sources": ["general horticultural reference"]}')
