INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('jiaogulan','Jiaogulan','Gynostemma pentaphyllum','herb','tea',14,28,68,80,60,90,'transplant','indoor-start','perennial','half-hardy','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant after all frost danger has passed as young plants are cold-sensitive.',7,11,18,24,12,24,24,60,'partial','moderate','Sow seeds 1/4 in deep in warm, moist starting mix and provide a trellis or support on which the vigorous twining vine can climb; jiaogulan grows 10–20 ft if given the right conditions. Plant in moderately fertile, well-drained soil with some afternoon shade in hot climates; consistent moisture promotes the most lush and harvestable leaf growth. In zones 7–8 the plant dies to the ground in winter but regrows from the root; in zone 9 and above it may be evergreen. Harvest the five-lobed leaflets throughout the growing season for fresh or dried tea; known as southern ginseng, the leaves contain saponins similar to those in Panax ginseng and are used in adaptogenic preparations.','["general horticultural reference"]','{"slug": "jiaogulan", "common_name": "Jiaogulan", "scientific_name": "Gynostemma pentaphyllum", "category": "herb", "subcategory": "tea", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 68, "max": 80}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant after all frost danger has passed as young plants are cold-sensitive."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 24, "max": 60}, "sun": "partial", "water": "moderate", "directions": "Sow seeds 1/4 in deep in warm, moist starting mix and provide a trellis or support on which the vigorous twining vine can climb; jiaogulan grows 10–20 ft if given the right conditions. Plant in moderately fertile, well-drained soil with some afternoon shade in hot climates; consistent moisture promotes the most lush and harvestable leaf growth. In zones 7–8 the plant dies to the ground in winter but regrows from the root; in zone 9 and above it may be evergreen. Harvest the five-lobed leaflets throughout the growing season for fresh or dried tea; known as southern ginseng, the leaves contain saponins similar to those in Panax ginseng and are used in adaptogenic preparations.", "sources": ["general horticultural reference"]}')
