INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('kalonji','Kalonji (Nigella, Black Seed)','Nigella sativa','herb','culinary',10,14,55,65,90,120,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; kalonji prefers cool spring conditions and dislikes heat.',3,11,6,9,12,18,6,9,'full','moderate','Sow seeds 1/4 in deep directly where they are to grow; kalonji has fine, thread-like foliage similar to its ornamental cousin love-in-a-mist and dislikes transplanting. Grow in well-drained, moderately fertile soil in full sun; the plant bolts quickly in summer heat, so time sowing for a cool-season harvest. Harvest the swollen seed pods when they begin to turn tan and paper-like, cutting whole stems into bags before the pods split and release the seeds. The intensely aromatic black seeds are used in South Asian cooking on naan breads and in spice blends, and have a long history of medicinal use; they are not to be confused with black cumin (Bunium persicum).','["general horticultural reference"]','{"slug": "kalonji", "common_name": "Kalonji (Nigella, Black Seed)", "scientific_name": "Nigella sativa", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; kalonji prefers cool spring conditions and dislikes heat."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 6, "max": 9}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep directly where they are to grow; kalonji has fine, thread-like foliage similar to its ornamental cousin love-in-a-mist and dislikes transplanting. Grow in well-drained, moderately fertile soil in full sun; the plant bolts quickly in summer heat, so time sowing for a cool-season harvest. Harvest the swollen seed pods when they begin to turn tan and paper-like, cutting whole stems into bags before the pods split and release the seeds. The intensely aromatic black seeds are used in South Asian cooking on naan breads and in spice blends, and have a long history of medicinal use; they are not to be confused with black cumin (Bunium persicum).", "sources": ["general horticultural reference"]}')
