  VALUES ('lady-s-mantle','Lady''s Mantle','Alchemilla mollis','herb','medicinal',21,42,55,65,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost after cold stratification; or sow fresh seed outdoors in autumn for natural stratification and spring germination.',3,8,12,18,9,18,18,24,'partial','moderate','Cold-stratify seed in the refrigerator for 3–4 weeks before surface-sowing; the tiny seeds need cool temperatures and moderate moisture to germinate. Plant in humus-rich, well-drained but moisture-retentive soil; lady''s mantle tolerates full sun in cooler climates but benefits from afternoon shade in hot regions. The pleated, velvety leaves catch dewdrops and rainwater, creating sparkling spheres of water — a notable ornamental feature. Harvest leaves and the chartreuse flower sprays in early summer for use in traditional women''s tonics; the foliage and flowers also add texture to fresh-cut and dried flower arrangements.','["general horticultural reference"]','{"slug": "lady-s-mantle", "common_name": "Lady''s Mantle", "scientific_name": "Alchemilla mollis", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost after cold stratification; or sow fresh seed outdoors in autumn for natural stratification and spring germination."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 9, "max": 18}, "spread_in": {"min": 18, "max": 24}, "sun": "partial", "water": "moderate", "directions": "Cold-stratify seed in the refrigerator for 3–4 weeks before surface-sowing; the tiny seeds need cool temperatures and moderate moisture to germinate. Plant in humus-rich, well-drained but moisture-retentive soil; lady''s mantle tolerates full sun in cooler climates but benefits from afternoon shade in hot regions. The pleated, velvety leaves catch dewdrops and rainwater, creating sparkling spheres of water — a notable ornamental feature. Harvest leaves and the chartreuse flower sprays in early summer for use in traditional women''s tonics; the foliage and flowers also add texture to fresh-cut and dried flower arrangements.", "sources": ["general horticultural reference"]}')
