INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lemon-basil','Lemon Basil','Ocimum × citriodorum','herb','culinary',5,10,65,85,60,80,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant only after nights are reliably above 50°F.',2,11,12,18,12,20,10,16,'full','moderate','Sow seeds 1/4 in deep in warm seed-starting mix at 70°F or above; germination is rapid once soil temperature is adequate. Transplant into rich, well-drained garden soil in full sun and pinch the growing tip early to encourage a bushy, multi-stemmed plant. Lemon basil is compact compared to sweet basil and has a distinct citrus fragrance from the presence of citral; it pairs well with fish, poultry, and Southeast Asian cuisines. Harvest by snipping stems just above a leaf pair once plants are well established, and pinch flower buds promptly to extend the harvest season.','["general horticultural reference"]','{"slug": "lemon-basil", "common_name": "Lemon Basil", "scientific_name": "Ocimum × citriodorum", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant only after nights are reliably above 50°F."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 20}, "spread_in": {"min": 10, "max": 16}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep in warm seed-starting mix at 70°F or above; germination is rapid once soil temperature is adequate. Transplant into rich, well-drained garden soil in full sun and pinch the growing tip early to encourage a bushy, multi-stemmed plant. Lemon basil is compact compared to sweet basil and has a distinct citrus fragrance from the presence of citral; it pairs well with fish, poultry, and Southeast Asian cuisines. Harvest by snipping stems just above a leaf pair once plants are well established, and pinch flower buds promptly to extend the harvest season.", "sources": ["general horticultural reference"]}')
