INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lemon-catnip','Lemon Catnip','Nepeta cataria var. citriodora','herb','tea',7,14,60,70,80,100,'seed','direct','perennial','hardy','last_frost',-4,-2,'Direct sow or start indoors 4 weeks before last frost; lemon catnip self-seeds freely once established.',3,9,18,24,18,36,18,30,'full','low','Sow seeds on the surface of well-drained starting mix and press in lightly; fresh seeds germinate readily in 1–2 weeks. Lemon catnip has all the nepetalactone chemistry of common catnip (making it equally irresistible to cats) but its foliage carries a pleasant lemon-mint scent suitable for tea and aromatherapy. Grow in full sun in any well-drained soil; cut plants back by half after the first flush of flowers to encourage a second bloom and fresh aromatic foliage. Harvest stems before flowers fully open for the best flavor in herbal teas; dry quickly in a warm, airy spot and store in airtight containers.','["general horticultural reference"]','{"slug": "lemon-catnip", "common_name": "Lemon Catnip", "scientific_name": "Nepeta cataria var. citriodora", "category": "herb", "subcategory": "tea", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 80, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow or start indoors 4 weeks before last frost; lemon catnip self-seeds freely once established."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "low", "directions": "Sow seeds on the surface of well-drained starting mix and press in lightly; fresh seeds germinate readily in 1–2 weeks. Lemon catnip has all the nepetalactone chemistry of common catnip (making it equally irresistible to cats) but its foliage carries a pleasant lemon-mint scent suitable for tea and aromatherapy. Grow in full sun in any well-drained soil; cut plants back by half after the first flush of flowers to encourage a second bloom and fresh aromatic foliage. Harvest stems before flowers fully open for the best flavor in herbal teas; dry quickly in a warm, airy spot and store in airtight containers.", "sources": ["general horticultural reference"]}')
