INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lemon-thyme','Lemon Thyme','Thymus x citriodorus','herb','culinary',14,28,65,75,75,90,'transplant','cutting','perennial','hardy','last_frost',-4,0,'Root stem cuttings in late spring; named cultivars do not come true from seed, so vegetative propagation is necessary to preserve the lemon character.',5,9,9,12,6,12,12,18,'full','low','Take 3–4 in tip cuttings in late spring or early summer, remove lower leaves, and insert into gritty, free-draining mix; roots develop in 2–3 weeks. Plant in full sun in sharply drained, lean, slightly alkaline soil, as lemon thyme rots in wet or rich conditions just like common thyme. Shear lightly after flowering each season to prevent woodiness and maintain a tidy mound of fragrant foliage. Harvest leafy sprigs at any time; the lemon-thyme combination flavor is prized in fish dishes, salad dressings, and desserts, and is excellent fresh or dried.','["general horticultural reference"]','{"slug": "lemon-thyme", "common_name": "Lemon Thyme", "scientific_name": "Thymus x citriodorus", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 75, "max": 90}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Root stem cuttings in late spring; named cultivars do not come true from seed, so vegetative propagation is necessary to preserve the lemon character."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Take 3–4 in tip cuttings in late spring or early summer, remove lower leaves, and insert into gritty, free-draining mix; roots develop in 2–3 weeks. Plant in full sun in sharply drained, lean, slightly alkaline soil, as lemon thyme rots in wet or rich conditions just like common thyme. Shear lightly after flowering each season to prevent woodiness and maintain a tidy mound of fragrant foliage. Harvest leafy sprigs at any time; the lemon-thyme combination flavor is prized in fish dishes, salad dressings, and desserts, and is excellent fresh or dried.", "sources": ["general horticultural reference"]}')
