  VALUES ('lemon-verbena','Lemon Verbena','Aloysia citrodora','herb','aromatic tender perennial',14,30,68,80,90,120,'transplant','cutting','perennial','tender','last_frost',0,2,'Transplant rooted cuttings outdoors after all frost danger has passed; bring containers indoors before the first autumn frost.',8,11,24,36,36,84,24,48,'full','moderate','Propagate from softwood cuttings taken in summer rather than from seed, which has poor viability; root cuttings in moist perlite under plastic until rooted. Plant in full sun and well-drained soil; in zones below 8 grow in containers that can be overwintered indoors in a cool, bright spot. Prune hard in spring when new growth emerges from what may look like dead wood — lemon verbena is often a slow riser after dormancy. Harvest leaves any time for intensely lemon-scented tea, dessert flavoring, and potpourri; fragrance peaks just before the plant begins to flower.','["general horticultural reference"]','{"slug": "lemon-verbena", "common_name": "Lemon Verbena", "scientific_name": "Aloysia citrodora", "category": "herb", "subcategory": "aromatic tender perennial", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 68, "max": 80}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Transplant rooted cuttings outdoors after all frost danger has passed; bring containers indoors before the first autumn frost."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 84}, "spread_in": {"min": 24, "max": 48}, "sun": "full", "water": "moderate", "directions": "Propagate from softwood cuttings taken in summer rather than from seed, which has poor viability; root cuttings in moist perlite under plastic until rooted. Plant in full sun and well-drained soil; in zones below 8 grow in containers that can be overwintered indoors in a cool, bright spot. Prune hard in spring when new growth emerges from what may look like dead wood — lemon verbena is often a slow riser after dormancy. Harvest leaves any time for intensely lemon-scented tea, dessert flavoring, and potpourri; fragrance peaks just before the plant begins to flower.", "sources": ["general horticultural reference"]}')
