  VALUES ('lemongrass','Lemongrass','Cymbopogon citratus','herb','annual',14,21,70,85,75,100,'transplant','transplant','warm','tender','last_frost',0,2,'Transplant divisions or rooted stalks after last frost when soil is reliably warm.',10,11,24,36,36,60,24,36,'full','moderate','Propagate by placing fresh grocery-store stalks (with roots intact) in water until roots develop, then transplant into rich, well-drained soil in full sun. Lemongrass needs heat and consistent moisture; water deeply and regularly during the growing season. In zones below 10, grow in large containers and bring indoors before first frost, cutting back to 6 in tall. Harvest outer stalks by cutting or twisting at the base when they reach pencil thickness; use the pale, tender base for cooking.','["general horticultural reference"]','{"slug": "lemongrass", "common_name": "Lemongrass", "scientific_name": "Cymbopogon citratus", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 75, "max": 100}, "maturity_from": "transplant", "sow_method": "transplant", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Transplant divisions or rooted stalks after last frost when soil is reliably warm."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Propagate by placing fresh grocery-store stalks (with roots intact) in water until roots develop, then transplant into rich, well-drained soil in full sun. Lemongrass needs heat and consistent moisture; water deeply and regularly during the growing season. In zones below 10, grow in large containers and bring indoors before first frost, cutting back to 6 in tall. Harvest outer stalks by cutting or twisting at the base when they reach pencil thickness; use the pale, tender base for cooking.", "sources": ["general horticultural reference"]}')
