INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('licorice','Licorice','Glycyrrhiza glabra','herb','medicinal',14,21,65,75,1095,1460,'seed','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost after scarifying or soaking seed overnight; transplant carefully after frost danger passes to avoid disturbing roots.',6,11,18,24,36,60,18,30,'full','moderate','Scarify seed coat lightly with sandpaper or soak overnight before sowing 1/4 in deep in warm starting mix; germination improves significantly with this treatment. Plant in deep, fertile, well-drained soil in full sun — licorice develops an extensive, deep root system and resents being moved. Roots are ready to harvest in the third or fourth autumn when they are at least pencil-thick, digging carefully to extract as much of the lateral root run as possible. The dried root is used medicinally as a demulcent and anti-inflammatory for digestive and respiratory conditions; note that excessive consumption raises blood pressure.','["general horticultural reference"]','{"slug": "licorice", "common_name": "Licorice", "scientific_name": "Glycyrrhiza glabra", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 1095, "max": 1460}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost after scarifying or soaking seed overnight; transplant carefully after frost danger passes to avoid disturbing roots."}, "usda_zones": {"min": 6, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "moderate", "directions": "Scarify seed coat lightly with sandpaper or soak overnight before sowing 1/4 in deep in warm starting mix; germination improves significantly with this treatment. Plant in deep, fertile, well-drained soil in full sun — licorice develops an extensive, deep root system and resents being moved. Roots are ready to harvest in the third or fourth autumn when they are at least pencil-thick, digging carefully to extract as much of the lateral root run as possible. The dried root is used medicinally as a demulcent and anti-inflammatory for digestive and respiratory conditions; note that excessive consumption raises blood pressure.", "sources": ["general horticultural reference"]}')
