INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lovage','Lovage','Levisticum officinale','herb','perennial',10,21,50,65,85,100,'seed','direct','perennial','hardy','last_frost',-4,-2,'Direct sow in early spring, 2–4 weeks before last frost; fresh seed germinates best.',4,8,24,36,36,84,24,36,'partial','moderate','Sow fresh seed 1/4 in deep in moist, fertile soil in early spring; stored seed loses viability quickly. Give lovage a permanent spot as it develops a large taproot that dislikes disturbance, and provide deep, moisture-retentive, fertile soil. Remove flower stalks as they appear to keep the plant producing leafy growth for longer. Harvest young outer leaves and stems throughout the season; the intense celery-like flavor means a little goes a long way.','["general horticultural reference"]','{"slug": "lovage", "common_name": "Lovage", "scientific_name": "Levisticum officinale", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 85, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring, 2–4 weeks before last frost; fresh seed germinates best."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 84}, "spread_in": {"min": 24, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Sow fresh seed 1/4 in deep in moist, fertile soil in early spring; stored seed loses viability quickly. Give lovage a permanent spot as it develops a large taproot that dislikes disturbance, and provide deep, moisture-retentive, fertile soil. Remove flower stalks as they appear to keep the plant producing leafy growth for longer. Harvest young outer leaves and stems throughout the season; the intense celery-like flavor means a little goes a long way.", "sources": ["general horticultural reference"]}')
