INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('marjoram','Marjoram','Origanum majorana','herb','annual',7,14,65,75,60,80,'transplant','indoor-start','warm','tender','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after all frost danger has passed.',9,11,9,12,12,18,9,12,'full','low','Surface-sow the tiny seeds without covering, pressing them gently into moist, well-drained seed mix and placing in a warm, bright spot. Transplant into well-drained, slightly alkaline garden soil after nights are reliably above 50°F. Pinch out growing tips regularly to keep plants bushy and delay flowering. Harvest stems just as the knotted flower buds form for the sweetest, most aromatic leaves.','["general horticultural reference"]','{"slug": "marjoram", "common_name": "Marjoram", "scientific_name": "Origanum majorana", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after all frost danger has passed."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "low", "directions": "Surface-sow the tiny seeds without covering, pressing them gently into moist, well-drained seed mix and placing in a warm, bright spot. Transplant into well-drained, slightly alkaline garden soil after nights are reliably above 50°F. Pinch out growing tips regularly to keep plants bushy and delay flowering. Harvest stems just as the knotted flower buds form for the sweetest, most aromatic leaves.", "sources": ["general horticultural reference"]}')
