INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('marshmallow','Marshmallow','Althaea officinalis','herb','medicinal perennial',14,21,65,75,120,180,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; scarifying the seed coat lightly with sandpaper or soaking overnight in warm water speeds germination.',3,9,24,36,48,84,24,36,'full','moderate','Scarify or soak seed overnight before sowing 1/4 in deep; marshmallow appreciates consistent moisture, particularly during its establishment period. Plant in deep, moderately moist soil as the tap root grows substantial in mature plants. Harvest leaves and flowers in summer for use in soothing teas and poultices; the fleshy root is the most mucilaginous part and is best dug in the plant''s second or third autumn. The dried root can be sliced, powdered, or made into a cold-water infusion to extract its slippery mucilage for throat-coat and digestive preparations.','["general horticultural reference"]','{"slug": "marshmallow", "common_name": "Marshmallow", "scientific_name": "Althaea officinalis", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; scarifying the seed coat lightly with sandpaper or soaking overnight in warm water speeds germination."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 48, "max": 84}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Scarify or soak seed overnight before sowing 1/4 in deep; marshmallow appreciates consistent moisture, particularly during its establishment period. Plant in deep, moderately moist soil as the tap root grows substantial in mature plants. Harvest leaves and flowers in summer for use in soothing teas and poultices; the fleshy root is the most mucilaginous part and is best dug in the plant''s second or third autumn. The dried root can be sliced, powdered, or made into a cold-water infusion to extract its slippery mucilage for throat-coat and digestive preparations.", "sources": ["general horticultural reference"]}')
