INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('meadowsweet','Meadowsweet','Filipendula ulmaria','herb','medicinal',14,28,50,65,120,180,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost after 4–6 weeks of cold stratification; transplant to a moist site after frost danger passes.',3,9,18,24,36,60,18,30,'partial','high','Cold-stratify seed in moist medium in the refrigerator for 4–6 weeks before surface-sowing; plant out in consistently moist to wet, humus-rich soil in partial shade or full sun where soil never dries out, mimicking its native pond-margin habitat. Meadowsweet bears frothy, sweetly almond-scented flower plumes in midsummer that were historically used to flavor mead and wines. Harvest flowers and upper leaves just as the buds begin to open, drying quickly at low heat to preserve the salicylate compounds that give the herb its traditional analgesic and anti-inflammatory reputation. The plant is the original source from which salicylic acid — the basis of aspirin — was first isolated.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "meadowsweet", "common_name": "Meadowsweet", "scientific_name": "Filipendula ulmaria", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost after 4–6 weeks of cold stratification; transplant to a moist site after frost danger passes."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 30}, "sun": "partial", "water": "high", "directions": "Cold-stratify seed in moist medium in the refrigerator for 4–6 weeks before surface-sowing; plant out in consistently moist to wet, humus-rich soil in partial shade or full sun where soil never dries out, mimicking its native pond-margin habitat. Meadowsweet bears frothy, sweetly almond-scented flower plumes in midsummer that were historically used to flavor mead and wines. Harvest flowers and upper leaves just as the buds begin to open, drying quickly at low heat to preserve the salicylate compounds that give the herb its traditional analgesic and anti-inflammatory reputation. The plant is the original source from which salicylic acid — the basis of aspirin — was first isolated.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
