INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('mexican-oregano','Mexican Oregano','Lippia graveolens','herb','culinary',7,14,68,80,90,150,'transplant','cutting','perennial','half-hardy','last_frost',0,4,'Plant rooted cuttings or nursery transplants after last frost; in zones below 8 overwinter indoors or take cuttings each fall.',8,11,24,36,24,72,24,48,'full','low','Root 4–6 in softwood cuttings in moist perlite; this shrubby herb from the Mexican highlands is unrelated to Mediterranean oregano but delivers a stronger, more citrusy-oregano flavor essential in chili, mole, and refried beans. Plant in sharply drained, lean soil in full sun; Mexican oregano is extremely drought-tolerant once established and actually develops more aromatic foliage under moderate stress. Prune plants lightly after each harvest to encourage fresh, leafy growth and prevent excessive woodiness. Harvest leaves and small branch tips at any time, drying them at low heat for the most authentic dried herb for Tex-Mex and Mexican cooking.','["general horticultural reference"]','{"slug": "mexican-oregano", "common_name": "Mexican Oregano", "scientific_name": "Lippia graveolens", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 68, "max": 80}, "days_to_maturity": {"min": 90, "max": 150}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted cuttings or nursery transplants after last frost; in zones below 8 overwinter indoors or take cuttings each fall."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 24, "max": 72}, "spread_in": {"min": 24, "max": 48}, "sun": "full", "water": "low", "directions": "Root 4–6 in softwood cuttings in moist perlite; this shrubby herb from the Mexican highlands is unrelated to Mediterranean oregano but delivers a stronger, more citrusy-oregano flavor essential in chili, mole, and refried beans. Plant in sharply drained, lean soil in full sun; Mexican oregano is extremely drought-tolerant once established and actually develops more aromatic foliage under moderate stress. Prune plants lightly after each harvest to encourage fresh, leafy growth and prevent excessive woodiness. Harvest leaves and small branch tips at any time, drying them at low heat for the most authentic dried herb for Tex-Mex and Mexican cooking.", "sources": ["general horticultural reference"]}')
