INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('mexican-tarragon','Mexican Tarragon (Mexican Mint Marigold)','Tagetes lucida','herb','perennial',7,14,70,85,90,120,'transplant','indoor-start','perennial','half-hardy','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; in zone 8–11 it overwinters and becomes a dependable perennial where French tarragon languishes in summer heat.',8,11,18,24,24,36,18,24,'full','low','Sow seeds 1/8 in deep in warm starting mix or propagate by stem cuttings, which root readily in moist perlite. Mexican tarragon thrives in the same hot, humid summers that kill French tarragon and delivers a very similar anise-like flavor; harvest foliage throughout the season by pinching stem tips. It blooms in fall with small golden-yellow flowers that attract butterflies — you can allow blooming or deadhead to maintain leaf production. In zone 9–11 the plant is perennial; cut back hard in early spring to stimulate fresh growth.','["Texas A&M AgriLife Extension Service", "general horticultural reference"]','{"slug": "mexican-tarragon", "common_name": "Mexican Tarragon (Mexican Mint Marigold)", "scientific_name": "Tagetes lucida", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; in zone 8–11 it overwinters and becomes a dependable perennial where French tarragon languishes in summer heat."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Sow seeds 1/8 in deep in warm starting mix or propagate by stem cuttings, which root readily in moist perlite. Mexican tarragon thrives in the same hot, humid summers that kill French tarragon and delivers a very similar anise-like flavor; harvest foliage throughout the season by pinching stem tips. It blooms in fall with small golden-yellow flowers that attract butterflies — you can allow blooming or deadhead to maintain leaf production. In zone 9–11 the plant is perennial; cut back hard in early spring to stimulate fresh growth.", "sources": ["Texas A&M AgriLife Extension Service", "general horticultural reference"]}')
