  VALUES ('motherwort','Motherwort','Leonurus cardiaca','herb','medicinal perennial',7,21,60,70,90,120,'transplant','direct','perennial','hardy','last_frost',-4,0,'Direct sow in early spring as the seed benefits from natural cold stratification or a brief refrigerator stratification period of 2–4 weeks.',3,8,18,24,36,60,18,24,'partial','moderate','Direct sow in early spring or late autumn and allow natural freeze-thaw cycles to stratify the seed over winter for strong spring germination. Motherwort thrives in partial shade and moderately fertile, well-drained soil, often naturalizing along hedgerows and woodland margins. Harvest the upper third of flowering stems just as the lower flowers begin to open, using aerial parts fresh or tinctured in alcohol. Wear gloves when harvesting as the prickly calyces are sharp; avoid use during pregnancy due to its uterine-stimulating properties.','["general horticultural reference"]','{"slug": "motherwort", "common_name": "Motherwort", "scientific_name": "Leonurus cardiaca", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Direct sow in early spring as the seed benefits from natural cold stratification or a brief refrigerator stratification period of 2–4 weeks."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 24}, "sun": "partial", "water": "moderate", "directions": "Direct sow in early spring or late autumn and allow natural freeze-thaw cycles to stratify the seed over winter for strong spring germination. Motherwort thrives in partial shade and moderately fertile, well-drained soil, often naturalizing along hedgerows and woodland margins. Harvest the upper third of flowering stems just as the lower flowers begin to open, using aerial parts fresh or tinctured in alcohol. Wear gloves when harvesting as the prickly calyces are sharp; avoid use during pregnancy due to its uterine-stimulating properties.", "sources": ["general horticultural reference"]}')
