INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('mountain-mint','Mountain Mint','Pycnanthemum virginianum','herb','tea',21,42,60,70,90,120,'transplant','division','perennial','hardy','last_frost',-2,2,'Divide established clumps in early spring or plant nursery divisions around the last frost date; cold-stratified seed can also be sown indoors 8–10 weeks before last frost.',3,8,18,24,24,36,18,30,'full','moderate','Divide clumps by prying them apart with two forks and replant in moderately moist, average soil in full sun to light shade; mountain mint naturalizes readily and spreads by rhizomes, though less aggressively than true mints. The leaves and silvery-white flower clusters are intensely menthol-scented — far more potent than peppermint — and are excellent as a native tea herb. Harvest leafy stems and the clusters of tiny white flowers in midsummer just as blooming begins for the most aromatic result. The prolific flowers are exceptional for native bees and other pollinators, making this a valuable dual-purpose plant.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "mountain-mint", "common_name": "Mountain Mint", "scientific_name": "Pycnanthemum virginianum", "category": "herb", "subcategory": "tea", "days_to_germination": {"min": 21, "max": 42}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Divide established clumps in early spring or plant nursery divisions around the last frost date; cold-stratified seed can also be sown indoors 8–10 weeks before last frost."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "moderate", "directions": "Divide clumps by prying them apart with two forks and replant in moderately moist, average soil in full sun to light shade; mountain mint naturalizes readily and spreads by rhizomes, though less aggressively than true mints. The leaves and silvery-white flower clusters are intensely menthol-scented — far more potent than peppermint — and are excellent as a native tea herb. Harvest leafy stems and the clusters of tiny white flowers in midsummer just as blooming begins for the most aromatic result. The prolific flowers are exceptional for native bees and other pollinators, making this a valuable dual-purpose plant.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
