INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('mugwort','Mugwort','Artemisia vulgaris','herb','medicinal',7,21,60,70,90,120,'transplant','division','perennial','hardy','last_frost',-2,2,'Divide established clumps in early spring or plant root divisions around the last frost date; mugwort also self-seeds freely if flower stalks are allowed to mature.',3,9,18,24,36,72,18,36,'full','low','Plant root divisions in any well-drained soil; mugwort is extremely vigorous and can become invasive via rhizomes, so consider installing a root barrier or growing in a contained bed. The deeply lobed, silver-backed leaves are strongly aromatic with a bitter, sage-like scent used in traditional European and East Asian medicine. Harvest leafy stems just before flowering in midsummer for use in moxibustion, digestive bitters, dream pillows, and traditional holiday flavoring of fatty meats. Cut plants back hard in late summer to control spread and prevent self-seeding.','["general horticultural reference"]','{"slug": "mugwort", "common_name": "Mugwort", "scientific_name": "Artemisia vulgaris", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Divide established clumps in early spring or plant root divisions around the last frost date; mugwort also self-seeds freely if flower stalks are allowed to mature."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 18, "max": 36}, "sun": "full", "water": "low", "directions": "Plant root divisions in any well-drained soil; mugwort is extremely vigorous and can become invasive via rhizomes, so consider installing a root barrier or growing in a contained bed. The deeply lobed, silver-backed leaves are strongly aromatic with a bitter, sage-like scent used in traditional European and East Asian medicine. Harvest leafy stems just before flowering in midsummer for use in moxibustion, digestive bitters, dream pillows, and traditional holiday flavoring of fatty meats. Cut plants back hard in late summer to control spread and prevent self-seeding.", "sources": ["general horticultural reference"]}')
