INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('pandan','Pandan (Screwpine)','Pandanus amaryllifolius','herb','culinary',NULL,NULL,NULL,NULL,180,365,'transplant','cutting','perennial','tender','last_frost',2,6,'Plant rooted suckers or stem cuttings after last frost in a warm, sheltered position; requires consistently warm temperatures above 60°F.',10,12,24,36,24,72,24,48,'partial','high','Propagate by removing rooted basal suckers from an established plant and potting into rich, moist, well-drained potting mix; cuttings without roots should be allowed to callous before planting. Pandan is a tropical Southeast Asian herb that rarely sets seed in cultivation and must be grown vegetatively; the long, strap-like leaves impart a distinctive vanilla-like, grassy fragrance used throughout Southeast Asian sweets, rice dishes, and drinks. Grow in bright indirect light or dappled shade with consistent moisture and high humidity; in temperate climates it makes an excellent houseplant or conservatory specimen. Harvest mature outer leaves by cutting at the base; knot or tie leaves before use in cooking to release their fragrance, or blend with water to make an extract.','["general horticultural reference"]','{"slug": "pandan", "common_name": "Pandan (Screwpine)", "scientific_name": "Pandanus amaryllifolius", "category": "herb", "subcategory": "culinary", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 180, "max": 365}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 6}, "note": "Plant rooted suckers or stem cuttings after last frost in a warm, sheltered position; requires consistently warm temperatures above 60°F."}, "usda_zones": {"min": 10, "max": 12}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 24, "max": 72}, "spread_in": {"min": 24, "max": 48}, "sun": "partial", "water": "high", "directions": "Propagate by removing rooted basal suckers from an established plant and potting into rich, moist, well-drained potting mix; cuttings without roots should be allowed to callous before planting. Pandan is a tropical Southeast Asian herb that rarely sets seed in cultivation and must be grown vegetatively; the long, strap-like leaves impart a distinctive vanilla-like, grassy fragrance used throughout Southeast Asian sweets, rice dishes, and drinks. Grow in bright indirect light or dappled shade with consistent moisture and high humidity; in temperate climates it makes an excellent houseplant or conservatory specimen. Harvest mature outer leaves by cutting at the base; knot or tie leaves before use in cooking to release their fragrance, or blend with water to make an extract.", "sources": ["general horticultural reference"]}')
