INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('papalo','Papalo','Porophyllum ruderale','herb','culinary',7,14,65,80,60,90,'seed','direct','warm','tender','last_frost',0,2,'Direct sow at or just after last frost once soil has warmed to 65°F; papalo thrives in hot summers when cilantro fails.',9,11,18,24,24,60,18,30,'full','low','Sow seeds 1/4 in deep directly in the garden once soil is warm and all frost danger has passed; papalo does not transplant well due to its taproot. This Mexican culinary herb is used raw, added at the table rather than during cooking — heat destroys its unique flavor, which blends notes of cilantro, rue, and citrus. Grow in full sun in well-drained soil; it tolerates heat and moderate drought admirably, making it valuable as a summer substitute for cilantro. Harvest young leaves and stem tips regularly while the plant is in vegetative growth; use very sparingly as the flavor is more intense than cilantro.','["general horticultural reference"]','{"slug": "papalo", "common_name": "Papalo", "scientific_name": "Porophyllum ruderale", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 80}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow at or just after last frost once soil has warmed to 65°F; papalo thrives in hot summers when cilantro fails."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "low", "directions": "Sow seeds 1/4 in deep directly in the garden once soil is warm and all frost danger has passed; papalo does not transplant well due to its taproot. This Mexican culinary herb is used raw, added at the table rather than during cooking — heat destroys its unique flavor, which blends notes of cilantro, rue, and citrus. Grow in full sun in well-drained soil; it tolerates heat and moderate drought admirably, making it valuable as a summer substitute for cilantro. Harvest young leaves and stem tips regularly while the plant is in vegetative growth; use very sparingly as the flavor is more intense than cilantro.", "sources": ["general horticultural reference"]}')
