  VALUES ('pennyroyal','Pennyroyal','Mentha pulegium','herb','aromatic perennial',10,16,60,70,70,90,'transplant','indoor-start','perennial','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; surface-sow as seeds need light and keep soil consistently moist.',5,9,12,18,6,12,12,24,'partial','moderate','Surface-sow seeds onto moist starting mix as they need light to germinate, keeping the medium evenly moist throughout germination. Pennyroyal spreads by creeping stems and works well as a fragrant ground cover in moist, partially shaded spots; it spreads less aggressively than other mints. The intensely peppermint-scented leaves are used fresh or dried as a traditional flea-repelling herb for pet bedding and as a strewing herb. Caution: pennyroyal oil is highly toxic and internal use carries serious risk — use the dried herb only in small quantities for tea and keep away from pregnant women and pets.','["general horticultural reference"]','{"slug": "pennyroyal", "common_name": "Pennyroyal", "scientific_name": "Mentha pulegium", "category": "herb", "subcategory": "aromatic perennial", "days_to_germination": {"min": 10, "max": 16}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; surface-sow as seeds need light and keep soil consistently moist."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 12, "max": 24}, "sun": "partial", "water": "moderate", "directions": "Surface-sow seeds onto moist starting mix as they need light to germinate, keeping the medium evenly moist throughout germination. Pennyroyal spreads by creeping stems and works well as a fragrant ground cover in moist, partially shaded spots; it spreads less aggressively than other mints. The intensely peppermint-scented leaves are used fresh or dried as a traditional flea-repelling herb for pet bedding and as a strewing herb. Caution: pennyroyal oil is highly toxic and internal use carries serious risk — use the dried herb only in small quantities for tea and keep away from pregnant women and pets.", "sources": ["general horticultural reference"]}')
