  VALUES ('peppermint','Peppermint','Mentha x piperita','herb','perennial',NULL,NULL,NULL,NULL,60,90,'transplant','division','perennial','hardy','last_frost',-2,2,'Divide or transplant rooted runners in spring around the last frost date.',3,8,18,24,12,36,18,36,'partial','moderate','Plant divisions or purchased starts in moist, rich soil and install a root barrier or grow in sunken containers, as peppermint spreads aggressively via underground stolons. Keep soil consistently moist and mulch to retain moisture during dry spells. Cut plants back to a few inches after the first flush of growth to encourage denser, more flavorful regrowth. Harvest stems before flower buds open, when menthol content is at its peak.','["general horticultural reference"]','{"slug": "peppermint", "common_name": "Peppermint", "scientific_name": "Mentha x piperita", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Divide or transplant rooted runners in spring around the last frost date."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 36}, "spread_in": {"min": 18, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Plant divisions or purchased starts in moist, rich soil and install a root barrier or grow in sunken containers, as peppermint spreads aggressively via underground stolons. Keep soil consistently moist and mulch to retain moisture during dry spells. Cut plants back to a few inches after the first flush of growth to encourage denser, more flavorful regrowth. Harvest stems before flower buds open, when menthol content is at its peak.", "sources": ["general horticultural reference"]}')
