INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('pineapple-sage','Pineapple Sage','Salvia elegans','herb','aromatic',14,21,65,75,90,120,'transplant','cutting','perennial','tender','last_frost',0,2,'Transplant rooted cuttings outdoors after all frost danger has passed; in zones 8–11 it overwinters as a perennial shrub.',8,11,24,36,36,60,24,36,'full','moderate','Propagate from 4–6 in softwood cuttings in late spring or early summer, which root readily in moist perlite within 2–3 weeks; plants started from cuttings establish more quickly and reliably than seed. Plant in well-drained, moderately fertile soil in full sun and water consistently during summer; pineapple sage is less drought-tolerant than culinary sage. In zones below 8, take cuttings before the first autumn frost and overwinter plants on a bright, frost-free windowsill. Harvest the pineapple-scented leaves throughout summer for fruit salads, drinks, and tea; the brilliant red flowers bloom in autumn and attract hummingbirds.','["general horticultural reference"]','{"slug": "pineapple-sage", "common_name": "Pineapple Sage", "scientific_name": "Salvia elegans", "category": "herb", "subcategory": "aromatic", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Transplant rooted cuttings outdoors after all frost danger has passed; in zones 8–11 it overwinters as a perennial shrub."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Propagate from 4–6 in softwood cuttings in late spring or early summer, which root readily in moist perlite within 2–3 weeks; plants started from cuttings establish more quickly and reliably than seed. Plant in well-drained, moderately fertile soil in full sun and water consistently during summer; pineapple sage is less drought-tolerant than culinary sage. In zones below 8, take cuttings before the first autumn frost and overwinter plants on a bright, frost-free windowsill. Harvest the pineapple-scented leaves throughout summer for fruit salads, drinks, and tea; the brilliant red flowers bloom in autumn and attract hummingbirds.", "sources": ["general horticultural reference"]}')
