INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('red-veined-sorrel','Red-Veined Sorrel','Rumex sanguineus var. sanguineus','herb','culinary',7,14,55,70,50,70,'seed','direct','perennial','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; red-veined sorrel tolerates light spring frosts and can also be sown in early fall.',4,9,9,12,12,18,9,12,'partial','moderate','Sow seeds 1/4 in deep in moist, well-drained soil and thin to 9–12 in apart; red-veined sorrel germinates readily in cool soil. The lance-shaped leaves with vivid crimson veins are ornamentally striking and have a mild lemony-tart flavor suitable for salads, garnishes, and light sautés. Remove flower stalks promptly to prevent self-seeding and to keep the plant producing tender new foliage throughout the season. Harvest outer leaves when they are young and vibrant; flavor and texture deteriorate in the largest, oldest leaves.','["general horticultural reference"]','{"slug": "red-veined-sorrel", "common_name": "Red-Veined Sorrel", "scientific_name": "Rumex sanguineus var. sanguineus", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 70}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; red-veined sorrel tolerates light spring frosts and can also be sown in early fall."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 9, "max": 12}, "sun": "partial", "water": "moderate", "directions": "Sow seeds 1/4 in deep in moist, well-drained soil and thin to 9–12 in apart; red-veined sorrel germinates readily in cool soil. The lance-shaped leaves with vivid crimson veins are ornamentally striking and have a mild lemony-tart flavor suitable for salads, garnishes, and light sautés. Remove flower stalks promptly to prevent self-seeding and to keep the plant producing tender new foliage throughout the season. Harvest outer leaves when they are young and vibrant; flavor and texture deteriorate in the largest, oldest leaves.", "sources": ["general horticultural reference"]}')
