INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('chamomile-roman','Roman Chamomile','Chamaemelum nobile','herb','tea',7,14,55,65,60,90,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; surface-sow as seeds need light to germinate, then transplant after frost danger passes.',4,9,12,18,3,12,12,18,'full','low','Surface-sow the tiny seeds onto moist, well-drained starting mix without covering; they require light and a temperature of 55–65°F for reliable germination. Plant in sandy or gritty, well-drained soil and avoid heavy clay or constantly moist conditions, which promote crown rot. Roman chamomile spreads by creeping stems and can be walked on lightly, making it a fragrant lawn substitute in cooler climates. Harvest flower heads when the petals are fully reflexed downward and the yellow disc is well developed, drying them quickly on screens for apple-scented tea.','["general horticultural reference"]','{"slug": "chamomile-roman", "common_name": "Roman Chamomile", "scientific_name": "Chamaemelum nobile", "category": "herb", "subcategory": "tea", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; surface-sow as seeds need light to germinate, then transplant after frost danger passes."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 3, "max": 12}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Surface-sow the tiny seeds onto moist, well-drained starting mix without covering; they require light and a temperature of 55–65°F for reliable germination. Plant in sandy or gritty, well-drained soil and avoid heavy clay or constantly moist conditions, which promote crown rot. Roman chamomile spreads by creeping stems and can be walked on lightly, making it a fragrant lawn substitute in cooler climates. Harvest flower heads when the petals are fully reflexed downward and the yellow disc is well developed, drying them quickly on screens for apple-scented tea.", "sources": ["general horticultural reference"]}')
