INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('rosemary','Rosemary','Salvia rosmarinus','herb','perennial',15,25,65,75,180,365,'transplant','cutting','perennial','half-hardy','last_frost',-2,2,'Root softwood cuttings in late spring or early summer; transplant rooted cuttings after last frost.',7,11,24,36,24,60,24,48,'full','low','Propagate from 4–6 in softwood cuttings stripped of lower leaves and set into gritty, free-draining medium; mist lightly and expect roots in 3–4 weeks. Plant in sharply drained, neutral to slightly alkaline soil and never let roots sit in standing water. In zones below 7, grow in containers and overwinter indoors in a bright, cool spot. Harvest stem tips freely; regular light trimming keeps the shrub compact and promotes fresh, aromatic growth.','["general horticultural reference"]','{"slug": "rosemary", "common_name": "Rosemary", "scientific_name": "Salvia rosmarinus", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 15, "max": 25}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 180, "max": 365}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Root softwood cuttings in late spring or early summer; transplant rooted cuttings after last frost."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 24, "max": 48}, "sun": "full", "water": "low", "directions": "Propagate from 4–6 in softwood cuttings stripped of lower leaves and set into gritty, free-draining medium; mist lightly and expect roots in 3–4 weeks. Plant in sharply drained, neutral to slightly alkaline soil and never let roots sit in standing water. In zones below 7, grow in containers and overwinter indoors in a bright, cool spot. Harvest stem tips freely; regular light trimming keeps the shrub compact and promotes fresh, aromatic growth.", "sources": ["general horticultural reference"]}')
