  VALUES ('rue','Rue','Ruta graveolens','herb','aromatic perennial',10,14,60,70,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after soil has warmed.',4,9,12,18,18,36,18,24,'full','low','Sow seed 1/8 in deep indoors in a warm spot; rue germinates best at around 68°F. Plant in poor, well-drained, alkaline soil and avoid overhead watering to prevent fungal issues in the bluish-green foliage. Always wear gloves and long sleeves when handling rue, as the sap can cause severe phototoxic skin burns when exposed to sunlight. Harvest small sprigs of foliage before flowering for traditional uses as a strewing herb or insect deterrent; internal use requires professional guidance due to toxicity at high doses.','["general horticultural reference"]','{"slug": "rue", "common_name": "Rue", "scientific_name": "Ruta graveolens", "category": "herb", "subcategory": "aromatic perennial", "days_to_germination": {"min": 10, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after soil has warmed."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "low", "directions": "Sow seed 1/8 in deep indoors in a warm spot; rue germinates best at around 68°F. Plant in poor, well-drained, alkaline soil and avoid overhead watering to prevent fungal issues in the bluish-green foliage. Always wear gloves and long sleeves when handling rue, as the sap can cause severe phototoxic skin burns when exposed to sunlight. Harvest small sprigs of foliage before flowering for traditional uses as a strewing herb or insect deterrent; internal use requires professional guidance due to toxicity at high doses.", "sources": ["general horticultural reference"]}')
