INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('saffron-crocus','Saffron Crocus','Crocus sativus','herb','culinary',NULL,NULL,NULL,NULL,365,548,'transplant','bulb','perennial','hardy','first_frost',-8,-6,'Plant corms 6–8 weeks before the first autumn frost so they establish before winter; flowers appear in the first autumn after planting.',6,10,4,6,3,6,3,4,'full','low','Plant corms (not seeds) 3–4 in deep in sharply drained, alkaline to neutral soil in full sun during late summer to early autumn; good drainage is critical as corms rot quickly in waterlogged soil. Each corm produces lilac-purple flowers in autumn of the first year; within each flower are three vivid red stigmas — these are saffron. Harvest the flowers as soon as they open in the morning and carefully pluck the three red stigmas from each blossom, drying immediately on a warm screen or in a low oven. Corms multiply each year; lift and divide every 3–4 years to prevent overcrowding and maintain flowering vigor.','["general horticultural reference"]','{"slug": "saffron-crocus", "common_name": "Saffron Crocus", "scientific_name": "Crocus sativus", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Plant corms 6–8 weeks before the first autumn frost so they establish before winter; flowers appear in the first autumn after planting."}, "usda_zones": {"min": 6, "max": 10}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 3, "max": 6}, "spread_in": {"min": 3, "max": 4}, "sun": "full", "water": "low", "directions": "Plant corms (not seeds) 3–4 in deep in sharply drained, alkaline to neutral soil in full sun during late summer to early autumn; good drainage is critical as corms rot quickly in waterlogged soil. Each corm produces lilac-purple flowers in autumn of the first year; within each flower are three vivid red stigmas — these are saffron. Harvest the flowers as soon as they open in the morning and carefully pluck the three red stigmas from each blossom, drying immediately on a warm screen or in a low oven. Corms multiply each year; lift and divide every 3–4 years to prevent overcrowding and maintain flowering vigor.", "sources": ["general horticultural reference"]}')
