INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('salad-burnet','Salad Burnet','Sanguisorba minor','herb','culinary',7,21,50,65,50,70,'seed','direct','perennial','hardy','last_frost',-4,-2,'Direct sow in early spring 2–4 weeks before last frost; can also be sown in autumn for spring germination.',4,8,12,18,12,18,12,18,'full','low','Sow seed 1/4 in deep in well-drained, alkaline or neutral soil; salad burnet tolerates poor, thin soils and performs well on chalky or limestone ground. As an evergreen perennial, it provides fresh cucumber-flavored leaves through mild winters when little else is harvestable. Remove flower stems as they appear to keep the plant producing the most tender, flavorful leaves rather than diverting energy into seed production. Harvest the youngest leaves at the tips of each stem for the freshest cucumber taste in salads, cool drinks, and herb butters.','["general horticultural reference"]','{"slug": "salad-burnet", "common_name": "Salad Burnet", "scientific_name": "Sanguisorba minor", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow in early spring 2–4 weeks before last frost; can also be sown in autumn for spring germination."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seed 1/4 in deep in well-drained, alkaline or neutral soil; salad burnet tolerates poor, thin soils and performs well on chalky or limestone ground. As an evergreen perennial, it provides fresh cucumber-flavored leaves through mild winters when little else is harvestable. Remove flower stems as they appear to keep the plant producing the most tender, flavorful leaves rather than diverting energy into seed production. Harvest the youngest leaves at the tips of each stem for the freshest cucumber taste in salads, cool drinks, and herb butters.", "sources": ["general horticultural reference"]}')
