INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('self-heal','Self-Heal','Prunella vulgaris','herb','medicinal perennial',14,21,60,70,60,90,'transplant','direct','perennial','hardy','last_frost',-4,0,'Direct sow in early spring; cold stratification for 2–3 weeks improves germination rates for this low-growing native plant.',4,9,12,18,6,12,12,18,'partial','moderate','Surface-sow seeds onto moist soil in early spring; a 2–3 week cold stratification in the fridge before sowing can improve germination rates. Self-heal spreads by stolons and will naturalize into a dense mat in moist, partly shaded spots; it tolerates light foot traffic and can work as a lawn substitute. Harvest aerial parts — leaves, stems, and flowers — when plants are in full bloom throughout summer, using them in poultices, teas, and infused preparations traditionally associated with wound healing. The purple flower spikes are also attractive and pollinator-friendly, making self-heal a useful dual-purpose ground cover.','["general horticultural reference"]','{"slug": "self-heal", "common_name": "Self-Heal", "scientific_name": "Prunella vulgaris", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Direct sow in early spring; cold stratification for 2–3 weeks improves germination rates for this low-growing native plant."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Surface-sow seeds onto moist soil in early spring; a 2–3 week cold stratification in the fridge before sowing can improve germination rates. Self-heal spreads by stolons and will naturalize into a dense mat in moist, partly shaded spots; it tolerates light foot traffic and can work as a lawn substitute. Harvest aerial parts — leaves, stems, and flowers — when plants are in full bloom throughout summer, using them in poultices, teas, and infused preparations traditionally associated with wound healing. The purple flower spikes are also attractive and pollinator-friendly, making self-heal a useful dual-purpose ground cover.", "sources": ["general horticultural reference"]}')
