  VALUES ('shiso','Shiso / Perilla','Perilla frutescens','herb','annual',7,14,65,75,60,80,'seed','direct','warm','tender','last_frost',0,2,'Direct sow at or just after last frost; shiso needs warm soil and will self-seed freely.',3,11,12,18,24,36,12,18,'full','moderate','Refrigerate seeds for a few days before sowing to break dormancy, then surface-sow or cover with 1/8 in of soil after the last frost. Grow in rich, moist, well-drained soil in full sun; shiso tolerates partial shade but growth is less vigorous. Pinch flower spikes promptly to extend leaf production, or allow a few to go to seed for next year''s volunteer plants. Harvest the large, ruffled leaves at any stage; young leaves are most tender and aromatic for fresh use.','["general horticultural reference"]','{"slug": "shiso", "common_name": "Shiso / Perilla", "scientific_name": "Perilla frutescens", "category": "herb", "subcategory": "annual", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow at or just after last frost; shiso needs warm soil and will self-seed freely."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Refrigerate seeds for a few days before sowing to break dormancy, then surface-sow or cover with 1/8 in of soil after the last frost. Grow in rich, moist, well-drained soil in full sun; shiso tolerates partial shade but growth is less vigorous. Pinch flower spikes promptly to extend leaf production, or allow a few to go to seed for next year''s volunteer plants. Harvest the large, ruffled leaves at any stage; young leaves are most tender and aromatic for fresh use.", "sources": ["general horticultural reference"]}')
