  VALUES ('skullcap','Skullcap','Scutellaria lateriflora','herb','medicinal perennial',14,30,65,75,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; cold-moist stratification for 4 weeks before sowing greatly improves germination of this native wildflower.',4,8,12,18,12,24,12,18,'partial','moderate','Cold-stratify seed in moist peat in the refrigerator for 4 weeks before surface-sowing onto a warm starting mix; germination is slow and erratic. Plant in partial shade with consistently moist, humus-rich soil that mimics its woodland-edge native habitat. Harvest aerial parts — stems, leaves, and small flowers — in full bloom during summer, using them fresh or dried for tinctures and teas valued for their calming properties. Divide established clumps every few years in early spring to maintain vigor.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "skullcap", "common_name": "Skullcap", "scientific_name": "Scutellaria lateriflora", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; cold-moist stratification for 4 weeks before sowing greatly improves germination of this native wildflower."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Cold-stratify seed in moist peat in the refrigerator for 4 weeks before surface-sowing onto a warm starting mix; germination is slow and erratic. Plant in partial shade with consistently moist, humus-rich soil that mimics its woodland-edge native habitat. Harvest aerial parts — stems, leaves, and small flowers — in full bloom during summer, using them fresh or dried for tinctures and teas valued for their calming properties. Divide established clumps every few years in early spring to maintain vigor.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
