INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('soapwort','Soapwort','Saponaria officinalis','herb','medicinal',10,21,55,65,90,120,'transplant','direct','perennial','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; soapwort can also be started indoors or divided from established clumps in spring or autumn.',3,9,18,24,18,36,18,30,'full','low','Sow seeds 1/4 in deep in well-drained, neutral to alkaline soil; soapwort is extremely adaptable and tolerates poor, dry soils once established, spreading by both seed and rhizome. The entire plant — especially the roots — contains saponins that create a soapy lather when bruised and agitated in water, making it historically valuable for washing delicate textiles and woolens. Harvest roots in autumn and foliage before flowering for use in gentle natural soap preparations; the lather cleans without the harshness of detergents. Deadhead spent flowers to limit self-seeding, or allow a few to naturalize for a low-maintenance informal planting of clove-scented pink blooms.','["general horticultural reference"]','{"slug": "soapwort", "common_name": "Soapwort", "scientific_name": "Saponaria officinalis", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; soapwort can also be started indoors or divided from established clumps in spring or autumn."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "low", "directions": "Sow seeds 1/4 in deep in well-drained, neutral to alkaline soil; soapwort is extremely adaptable and tolerates poor, dry soils once established, spreading by both seed and rhizome. The entire plant — especially the roots — contains saponins that create a soapy lather when bruised and agitated in water, making it historically valuable for washing delicate textiles and woolens. Harvest roots in autumn and foliage before flowering for use in gentle natural soap preparations; the lather cleans without the harshness of detergents. Deadhead spent flowers to limit self-seeding, or allow a few to naturalize for a low-maintenance informal planting of clove-scented pink blooms.", "sources": ["general horticultural reference"]}')
