INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('southernwood','Southernwood (Lad''s Love)','Artemisia abrotanum','herb','aromatic',NULL,NULL,NULL,NULL,90,180,'transplant','cutting','perennial','hardy','last_frost',0,4,'Plant rooted cuttings or nursery transplants after last frost; southernwood rarely sets viable seed and is almost always propagated vegetatively.',4,9,24,36,24,48,24,36,'full','low','Root 4–6 in semi-ripe cuttings in late summer in gritty, moist propagating mix; cuttings root readily without hormone treatment. Southernwood is a woody, feathery-leaved Artemisia with a sharp lemon-camphor fragrance historically used as a moth repellent and insect deterrent in drawers and linen presses. Plant in well-drained, lean soil in full sun; like most artemisias it suffers in wet or rich conditions and prefers slightly alkaline soil. Cut back hard to within 6 in of the ground in early spring to prevent excessive woodiness and stimulate a fresh flush of aromatic silver-green growth.','["general horticultural reference"]','{"slug": "southernwood", "common_name": "Southernwood (Lad''s Love)", "scientific_name": "Artemisia abrotanum", "category": "herb", "subcategory": "aromatic", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 180}, "maturity_from": "transplant", "sow_method": "cutting", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rooted cuttings or nursery transplants after last frost; southernwood rarely sets viable seed and is almost always propagated vegetatively."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Root 4–6 in semi-ripe cuttings in late summer in gritty, moist propagating mix; cuttings root readily without hormone treatment. Southernwood is a woody, feathery-leaved Artemisia with a sharp lemon-camphor fragrance historically used as a moth repellent and insect deterrent in drawers and linen presses. Plant in well-drained, lean soil in full sun; like most artemisias it suffers in wet or rich conditions and prefers slightly alkaline soil. Cut back hard to within 6 in of the ground in early spring to prevent excessive woodiness and stimulate a fresh flush of aromatic silver-green growth.", "sources": ["general horticultural reference"]}')
