INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('spilanthes','Spilanthes (Toothache Plant)','Acmella oleracea','herb','medicinal',7,14,68,80,60,80,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant after all frost danger has passed when soil is warm.',9,11,12,18,12,18,12,18,'full','moderate','Sow seeds 1/8 in deep in warm, moist seed-starting mix at 75°F; transplant after last frost into rich, well-drained soil with consistent moisture. Spilanthes is notable for spilanthol, a compound in the flowers and leaves that causes an intense, numbing tingle on the tongue — hence the common name toothache plant; it has uses in local anesthetic preparations and salivation-stimulating tinctures. The distinctive red and yellow, cone-shaped flower heads are harvested fresh or dried for tinctures and topical preparations; even a small piece of flower head produces a pronounced oral sensation. Grow in full sun with moderate moisture; deadhead regularly to encourage continuous flowering throughout the warm season.','["general horticultural reference"]','{"slug": "spilanthes", "common_name": "Spilanthes (Toothache Plant)", "scientific_name": "Acmella oleracea", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 68, "max": 80}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant after all frost danger has passed when soil is warm."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/8 in deep in warm, moist seed-starting mix at 75°F; transplant after last frost into rich, well-drained soil with consistent moisture. Spilanthes is notable for spilanthol, a compound in the flowers and leaves that causes an intense, numbing tingle on the tongue — hence the common name toothache plant; it has uses in local anesthetic preparations and salivation-stimulating tinctures. The distinctive red and yellow, cone-shaped flower heads are harvested fresh or dried for tinctures and topical preparations; even a small piece of flower head produces a pronounced oral sensation. Grow in full sun with moderate moisture; deadhead regularly to encourage continuous flowering throughout the warm season.", "sources": ["general horticultural reference"]}')
