INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('wormwood-sweet-annie','Sweet Annie (Annual Wormwood)','Artemisia annua','herb','medicinal',7,14,60,70,120,150,'seed','direct','warm','tender','last_frost',-2,0,'Direct sow just before or at last frost; seeds are tiny and need light for germination — do not cover.',3,11,24,36,36,96,24,36,'full','low','Broadcast the dust-like seeds onto a weed-free seedbed and press in without covering; they require light to germinate and will not sprout if buried. Sweet Annie grows rapidly into a large, feathery-leaved annual with an intensely sweet, camphor-like fragrance widely used in wreath-making and dried floral arrangements. The plant is the natural source of artemisinin, a compound researched extensively for anti-malarial properties; harvest aerial parts when the plant begins to flower for the highest artemisinin content. Self-seeds prolifically in warm climates, so deadhead spent plants before seeds fully ripen if reseeding in the garden is not desired.','["general horticultural reference"]','{"slug": "wormwood-sweet-annie", "common_name": "Sweet Annie (Annual Wormwood)", "scientific_name": "Artemisia annua", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 120, "max": 150}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 0}, "note": "Direct sow just before or at last frost; seeds are tiny and need light for germination — do not cover."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 96}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Broadcast the dust-like seeds onto a weed-free seedbed and press in without covering; they require light to germinate and will not sprout if buried. Sweet Annie grows rapidly into a large, feathery-leaved annual with an intensely sweet, camphor-like fragrance widely used in wreath-making and dried floral arrangements. The plant is the natural source of artemisinin, a compound researched extensively for anti-malarial properties; harvest aerial parts when the plant begins to flower for the highest artemisinin content. Self-seeds prolifically in warm climates, so deadhead spent plants before seeds fully ripen if reseeding in the garden is not desired.", "sources": ["general horticultural reference"]}')
