INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sweet-cicely','Sweet Cicely','Myrrhis odorata','herb','culinary',30,60,40,55,365,548,'seed','direct','perennial','hardy','first_frost',-4,-2,'Sow fresh seed in autumn 2–4 weeks before first frost; the seed requires cold stratification through winter and will not germinate without it.',3,7,24,36,36,60,24,36,'partial','moderate','Sow fresh seed immediately — it loses viability rapidly and requires a sustained cold period to germinate; autumn sowing directly in the garden is the most reliable approach. Plant in deep, fertile, moist soil in partial to full shade, where it will naturalize into a handsome long-lived clump. All parts of the plant are edible and anise-scented: young leaves sweeten acidic fruits in cooking and reduce the need for sugar, green seeds are eaten as a snack, and roots are grated raw in salads. Cut flower stems before they set seed if you want to limit self-sowing; once established, plants are highly drought-tolerant and largely self-sufficient.','["general horticultural reference", "RHS Plant Guides"]','{"slug": "sweet-cicely", "common_name": "Sweet Cicely", "scientific_name": "Myrrhis odorata", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 30, "max": 60}, "germination_soil_temp_f": {"min": 40, "max": 55}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Sow fresh seed in autumn 2–4 weeks before first frost; the seed requires cold stratification through winter and will not germinate without it."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 24, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Sow fresh seed immediately — it loses viability rapidly and requires a sustained cold period to germinate; autumn sowing directly in the garden is the most reliable approach. Plant in deep, fertile, moist soil in partial to full shade, where it will naturalize into a handsome long-lived clump. All parts of the plant are edible and anise-scented: young leaves sweeten acidic fruits in cooking and reduce the need for sugar, green seeds are eaten as a snack, and roots are grated raw in salads. Cut flower stems before they set seed if you want to limit self-sowing; once established, plants are highly drought-tolerant and largely self-sufficient.", "sources": ["general horticultural reference", "RHS Plant Guides"]}')
