  VALUES ('sweet-woodruff','Sweet Woodruff','Galium odoratum','herb','aromatic',30,90,40,55,365,548,'transplant','division','perennial','hardy','last_frost',-4,0,'Divide established clumps in early spring or plant nursery divisions around the last frost date; germination from seed is very slow and division is far more reliable.',4,8,12,18,6,12,18,36,'shade','moderate','Plant divisions in cool, humus-rich, moist, slightly acidic soil in full to partial shade; sweet woodruff thrives under deciduous trees where little else will grow, spreading into an attractive ground-covering mat. Water regularly until established, then the plant largely maintains itself in moist woodland conditions. Harvest stems and leaves as the plant begins to flower in late spring, when coumarin content peaks and the characteristic fresh-mown hay scent intensifies on drying. Dried sprigs are used to flavor the traditional German May wine (Maibowle) and for fragrant sachets in linen.','["general horticultural reference", "RHS Plant Guides"]','{"slug": "sweet-woodruff", "common_name": "Sweet Woodruff", "scientific_name": "Galium odoratum", "category": "herb", "subcategory": "aromatic", "days_to_germination": {"min": 30, "max": 90}, "germination_soil_temp_f": {"min": 40, "max": 55}, "days_to_maturity": {"min": 365, "max": 548}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Divide established clumps in early spring or plant nursery divisions around the last frost date; germination from seed is very slow and division is far more reliable."}, "usda_zones": {"min": 4, "max": 8}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 18, "max": 36}, "sun": "shade", "water": "moderate", "directions": "Plant divisions in cool, humus-rich, moist, slightly acidic soil in full to partial shade; sweet woodruff thrives under deciduous trees where little else will grow, spreading into an attractive ground-covering mat. Water regularly until established, then the plant largely maintains itself in moist woodland conditions. Harvest stems and leaves as the plant begins to flower in late spring, when coumarin content peaks and the characteristic fresh-mown hay scent intensifies on drying. Dried sprigs are used to flavor the traditional German May wine (Maibowle) and for fragrant sachets in linen.", "sources": ["general horticultural reference", "RHS Plant Guides"]}')
