INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('syrian-oregano-zaatar','Syrian Oregano (Za''atar)','Origanum syriacum','herb','culinary',7,14,65,75,90,120,'transplant','indoor-start','perennial','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; in zones below 8 grow as an annual or overwinter rooted cuttings indoors.',8,11,12,18,12,24,12,18,'full','low','Surface-sow seeds on moist, gritty seed-starting mix and keep at 68–72°F; tiny seeds need light so do not cover. Syrian oregano is the primary botanical ingredient in the Middle Eastern spice blend called za''atar; its flavor is strongly oregano-thyme with a hint of marjoram. Grow in very well-drained, poor to moderate soil in full sun — it is native to rocky limestone slopes and rewards lean conditions with the most aromatic foliage. Harvest young stems and leaves throughout the growing season, drying them for use in the za''atar spice blend or using fresh in flatbreads, salads, and dips.','["general horticultural reference"]','{"slug": "syrian-oregano-zaatar", "common_name": "Syrian Oregano (Za''atar)", "scientific_name": "Origanum syriacum", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; in zones below 8 grow as an annual or overwinter rooted cuttings indoors."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Surface-sow seeds on moist, gritty seed-starting mix and keep at 68–72°F; tiny seeds need light so do not cover. Syrian oregano is the primary botanical ingredient in the Middle Eastern spice blend called za''atar; its flavor is strongly oregano-thyme with a hint of marjoram. Grow in very well-drained, poor to moderate soil in full sun — it is native to rocky limestone slopes and rewards lean conditions with the most aromatic foliage. Harvest young stems and leaves throughout the growing season, drying them for use in the za''atar spice blend or using fresh in flatbreads, salads, and dips.", "sources": ["general horticultural reference"]}')
