INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('tansy','Tansy','Tanacetum vulgare','herb','aromatic',7,14,60,70,90,120,'transplant','division','perennial','hardy','last_frost',-2,2,'Divide established clumps in early spring or plant nursery divisions around the last frost date; tansy self-seeds freely and can also be direct-sown.',3,9,18,24,36,60,18,36,'full','low','Plant divisions in any well-drained soil in full sun; tansy is a vigorous, drought-tolerant perennial that spreads by rhizome and can become invasive — site it where its spread can be managed or grow it in a contained bed. The finely cut, strongly aromatic foliage contains thujone, which is toxic in large doses, so tansy should not be consumed internally and should be handled with care. Harvest leafy stems and flat-topped clusters of button-like yellow flowers throughout summer for use as a traditional insect-repelling strewing herb, moth-deterring sachets, and companion-planting aromatic barriers. Deadhead promptly to reduce the copious self-seeding that can make tansy weedy in favorable conditions.','["general horticultural reference"]','{"slug": "tansy", "common_name": "Tansy", "scientific_name": "Tanacetum vulgare", "category": "herb", "subcategory": "aromatic", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Divide established clumps in early spring or plant nursery divisions around the last frost date; tansy self-seeds freely and can also be direct-sown."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 18, "max": 36}, "sun": "full", "water": "low", "directions": "Plant divisions in any well-drained soil in full sun; tansy is a vigorous, drought-tolerant perennial that spreads by rhizome and can become invasive — site it where its spread can be managed or grow it in a contained bed. The finely cut, strongly aromatic foliage contains thujone, which is toxic in large doses, so tansy should not be consumed internally and should be handled with care. Harvest leafy stems and flat-topped clusters of button-like yellow flowers throughout summer for use as a traditional insect-repelling strewing herb, moth-deterring sachets, and companion-planting aromatic barriers. Deadhead promptly to reduce the copious self-seeding that can make tansy weedy in favorable conditions.", "sources": ["general horticultural reference"]}')
