  VALUES ('thai-basil','Thai Basil','Ocimum basilicum var. thyrsiflora','herb','culinary',5,10,65,85,60,75,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant after soil and night temperatures are reliably warm.',2,11,12,18,12,24,12,18,'full','moderate','Sow seeds 1/4 in deep in warm starting mix and transplant after the last frost when soil has warmed; Thai basil withstands heat slightly better than sweet basil. The glossy, dark-green leaves with purple stems carry a spicy anise-clove flavor that holds up better during cooking than sweet basil, making it ideal for stir-fries, curries, and pho. Pinch out purple flower spikes as they emerge to maintain vigorous leaf production, though the flowers are edible and attractive to pollinators. Harvest stems above a leaf node; plants branch densely and remain productive throughout the warm season.','["general horticultural reference"]','{"slug": "thai-basil", "common_name": "Thai Basil", "scientific_name": "Ocimum basilicum var. thyrsiflora", "category": "herb", "subcategory": "culinary", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 60, "max": 75}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant after soil and night temperatures are reliably warm."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 in deep in warm starting mix and transplant after the last frost when soil has warmed; Thai basil withstands heat slightly better than sweet basil. The glossy, dark-green leaves with purple stems carry a spicy anise-clove flavor that holds up better during cooking than sweet basil, making it ideal for stir-fries, curries, and pho. Pinch out purple flower spikes as they emerge to maintain vigorous leaf production, though the flowers are edible and attractive to pollinators. Harvest stems above a leaf node; plants branch densely and remain productive throughout the warm season.", "sources": ["general horticultural reference"]}')
