INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('tulsi-vana','Vana Tulsi (Wild Holy Basil)','Ocimum tenuiflorum var. vana','herb','medicinal',7,14,68,80,60,90,'transplant','indoor-start','warm','tender','last_frost',-6,-4,'Start indoors 4–6 weeks before last frost; transplant after all danger of frost has passed and soil is warm.',10,11,12,18,18,36,12,18,'full','moderate','Surface-sow or press seeds 1/8 in into warm seed-starting mix; maintain 70–80°F for best germination. Vana tulsi (forest holy basil) is the most clove-like and pungent of the tulsi varieties, with green leaves and a more open, branching habit than Rama tulsi; it is revered in Ayurvedic practice and used widely in adaptogenic herbal teas. Pinch growing tips early to encourage branching, and remove flower spikes as they emerge to extend vegetative leaf production throughout the season. Harvest by cutting stem tips; dry leaves at low temperature to preserve the volatile eugenol-rich essential oils.','["general horticultural reference"]','{"slug": "tulsi-vana", "common_name": "Vana Tulsi (Wild Holy Basil)", "scientific_name": "Ocimum tenuiflorum var. vana", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 68, "max": 80}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Start indoors 4–6 weeks before last frost; transplant after all danger of frost has passed and soil is warm."}, "usda_zones": {"min": 10, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Surface-sow or press seeds 1/8 in into warm seed-starting mix; maintain 70–80°F for best germination. Vana tulsi (forest holy basil) is the most clove-like and pungent of the tulsi varieties, with green leaves and a more open, branching habit than Rama tulsi; it is revered in Ayurvedic practice and used widely in adaptogenic herbal teas. Pinch growing tips early to encourage branching, and remove flower spikes as they emerge to extend vegetative leaf production throughout the season. Harvest by cutting stem tips; dry leaves at low temperature to preserve the volatile eugenol-rich essential oils.", "sources": ["general horticultural reference"]}')
