INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('vietnamese-coriander','Vietnamese Coriander (Rau Ram)','Persicaria odorata','herb','perennial',NULL,NULL,NULL,NULL,30,60,'transplant','transplant','perennial','tender','last_frost',0,4,'Transplant rooted cuttings after frost in full sun to part shade; thrives in hot, humid conditions that make cilantro bolt.',9,11,12,18,12,24,18,30,'partial','moderate','Propagate from stem cuttings, which root readily in water or moist potting mix within a week; seed is rarely available. Vietnamese coriander prefers consistently moist, rich soil and tolerates partial shade — qualities that let it thrive in spots too hot or dry for cilantro. The pointed, dark-green leaves with chevron markings taste of cilantro with a peppery bite and are used raw in Vietnamese pho, salads, and noodle dishes. In zone 9 it may freeze back but generally rebounds from the root crown; mulch heavily in winter to protect roots.','["general horticultural reference", "university extension guides"]','{"slug": "vietnamese-coriander", "common_name": "Vietnamese Coriander (Rau Ram)", "scientific_name": "Persicaria odorata", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": null, "max": null}, "days_to_maturity": {"min": 30, "max": 60}, "maturity_from": "transplant", "sow_method": "transplant", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Transplant rooted cuttings after frost in full sun to part shade; thrives in hot, humid conditions that make cilantro bolt."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 18, "max": 30}, "sun": "partial", "water": "moderate", "directions": "Propagate from stem cuttings, which root readily in water or moist potting mix within a week; seed is rarely available. Vietnamese coriander prefers consistently moist, rich soil and tolerates partial shade — qualities that let it thrive in spots too hot or dry for cilantro. The pointed, dark-green leaves with chevron markings taste of cilantro with a peppery bite and are used raw in Vietnamese pho, salads, and noodle dishes. In zone 9 it may freeze back but generally rebounds from the root crown; mulch heavily in winter to protect roots.", "sources": ["general horticultural reference", "university extension guides"]}')
