INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('germander','Wall Germander','Teucrium chamaedrys','herb','medicinal',14,28,60,70,120,180,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost or propagate from cuttings; transplant after frost danger has passed.',5,9,12,18,10,18,12,24,'full','low','Surface-sow seeds or take 3 in softwood cuttings in late spring; cuttings are generally more reliable as germination can be slow. Wall germander is an ancient medicinal herb used historically as a bitter digestive tonic; it has glossy, dark-green, oak-like leaves and rosy-pink summer flowers that attract bees. Plant in lean, well-drained, alkaline to neutral soil in full sun; it is extremely drought-tolerant once established and makes an excellent low edging or clipped knot-garden hedge. Trim after flowering to maintain a tidy, compact form; harvest small quantities of fresh foliage for occasional medicinal use.','["general horticultural reference"]','{"slug": "germander", "common_name": "Wall Germander", "scientific_name": "Teucrium chamaedrys", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost or propagate from cuttings; transplant after frost danger has passed."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 10, "max": 18}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "low", "directions": "Surface-sow seeds or take 3 in softwood cuttings in late spring; cuttings are generally more reliable as germination can be slow. Wall germander is an ancient medicinal herb used historically as a bitter digestive tonic; it has glossy, dark-green, oak-like leaves and rosy-pink summer flowers that attract bees. Plant in lean, well-drained, alkaline to neutral soil in full sun; it is extremely drought-tolerant once established and makes an excellent low edging or clipped knot-garden hedge. Trim after flowering to maintain a tidy, compact form; harvest small quantities of fresh foliage for occasional medicinal use.", "sources": ["general horticultural reference"]}')
