INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('watermint','Water Mint','Mentha aquatica','herb','tea',10,16,60,70,60,90,'transplant','division','perennial','hardy','last_frost',-2,2,'Plant divisions in early spring around the last frost date in consistently moist to wet soil at a pond margin or bog garden.',3,10,18,24,12,24,18,36,'full','high','Plant divisions in the shallow margins of a pond, bog garden, or in any spot with consistently wet to water-logged soil; water mint is the only mint species that tolerates standing water and thrives in conditions where other mints would rot. The strongly aromatic leaves carry a robust spearmint-with-floral character and are the natural parent of peppermint alongside spearmint. Harvest leafy stems throughout the growing season before flowering for the most intense aroma; use fresh or dried in teas and as a flavoring. Water mint spreads rapidly by underwater runners and may need periodic thinning in contained water features.','["general horticultural reference"]','{"slug": "watermint", "common_name": "Water Mint", "scientific_name": "Mentha aquatica", "category": "herb", "subcategory": "tea", "days_to_germination": {"min": 10, "max": 16}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Plant divisions in early spring around the last frost date in consistently moist to wet soil at a pond margin or bog garden."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 18, "max": 36}, "sun": "full", "water": "high", "directions": "Plant divisions in the shallow margins of a pond, bog garden, or in any spot with consistently wet to water-logged soil; water mint is the only mint species that tolerates standing water and thrives in conditions where other mints would rot. The strongly aromatic leaves carry a robust spearmint-with-floral character and are the natural parent of peppermint alongside spearmint. Harvest leafy stems throughout the growing season before flowering for the most intense aroma; use fresh or dried in teas and as a flavoring. Water mint spreads rapidly by underwater runners and may need periodic thinning in contained water features.", "sources": ["general horticultural reference"]}')
