INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('white-sage','White Sage','Salvia apiana','herb','aromatic',14,21,60,70,365,730,'transplant','indoor-start','perennial','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; mature plants tolerate brief light frost but establish best in warm, dry conditions.',8,11,24,36,24,60,24,48,'full','low','Sow seeds 1/8 in deep in lean, fast-draining mix; refrigerate seeds for 2 weeks before sowing to improve germination rates. Plant in extremely well-drained, sandy or rocky soil in full sun — white sage is a California chaparral native that is highly drought-tolerant once established but will rot quickly in wet, heavy soil. Avoid supplemental irrigation once plants are established in their second season; overwatering is the most common cause of death. Harvest mature leaves and small branches by cutting, and dry in bundles in a warm, well-ventilated space for aromatic and ceremonial use.','["general horticultural reference"]','{"slug": "white-sage", "common_name": "White Sage", "scientific_name": "Salvia apiana", "category": "herb", "subcategory": "aromatic", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; mature plants tolerate brief light frost but establish best in warm, dry conditions."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 24, "max": 48}, "sun": "full", "water": "low", "directions": "Sow seeds 1/8 in deep in lean, fast-draining mix; refrigerate seeds for 2 weeks before sowing to improve germination rates. Plant in extremely well-drained, sandy or rocky soil in full sun — white sage is a California chaparral native that is highly drought-tolerant once established but will rot quickly in wet, heavy soil. Avoid supplemental irrigation once plants are established in their second season; overwatering is the most common cause of death. Harvest mature leaves and small branches by cutting, and dry in bundles in a warm, well-ventilated space for aromatic and ceremonial use.", "sources": ["general horticultural reference"]}')
