INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('wild-bergamot','Wild Bergamot','Monarda fistulosa var. fistulosa','herb','aromatic perennial',10,21,60,70,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; surface-sow as seeds are tiny and need light for good germination.',3,9,18,24,24,48,18,30,'full','low','Surface-sow seeds onto moist starting mix and keep at 65–70°F; wild bergamot germinates in 10–21 days and is more drought-tolerant than the cultivated red bee balm. Plant in well-drained, average to lean soil in full sun for the most aromatic foliage and best disease resistance. Harvest leaves and flowers throughout summer for oregano-scented teas with a mild thymol character, used traditionally by many Indigenous nations for cold and fever support. Divide established clumps every 2–3 years as the center tends to die out.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "wild-bergamot", "common_name": "Wild Bergamot", "scientific_name": "Monarda fistulosa var. fistulosa", "category": "herb", "subcategory": "aromatic perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; surface-sow as seeds are tiny and need light for good germination."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "low", "directions": "Surface-sow seeds onto moist starting mix and keep at 65–70°F; wild bergamot germinates in 10–21 days and is more drought-tolerant than the cultivated red bee balm. Plant in well-drained, average to lean soil in full sun for the most aromatic foliage and best disease resistance. Harvest leaves and flowers throughout summer for oregano-scented teas with a mild thymol character, used traditionally by many Indigenous nations for cold and fever support. Divide established clumps every 2–3 years as the center tends to die out.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
