INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('winter-savory','Winter Savory','Satureja montana','herb','perennial',10,21,60,70,70,90,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after danger of frost has passed.',5,9,9,12,12,15,12,15,'full','low','Surface-sow seeds on barely moist seed-starting mix, pressing them in without covering; light aids germination. Plant out in sharply drained soil in full sun, spacing 12 in apart; winter savory is more drought-tolerant and woodier than its summer cousin. Trim lightly after flowering each year to prevent excessive woody growth. Harvest young shoot tips for the most intense, slightly resinous flavor; older stems are good for long-simmered dishes.','["general horticultural reference"]','{"slug": "winter-savory", "common_name": "Winter Savory", "scientific_name": "Satureja montana", "category": "herb", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after danger of frost has passed."}, "usda_zones": {"min": 5, "max": 9}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 12, "max": 15}, "spread_in": {"min": 12, "max": 15}, "sun": "full", "water": "low", "directions": "Surface-sow seeds on barely moist seed-starting mix, pressing them in without covering; light aids germination. Plant out in sharply drained soil in full sun, spacing 12 in apart; winter savory is more drought-tolerant and woodier than its summer cousin. Trim lightly after flowering each year to prevent excessive woody growth. Harvest young shoot tips for the most intense, slightly resinous flavor; older stems are good for long-simmered dishes.", "sources": ["general horticultural reference"]}')
