  VALUES ('wintergreen','Wintergreen','Gaultheria procumbens','herb','tea',30,90,40,55,365,730,'transplant','division','perennial','hardy','last_frost',-2,2,'Plant nursery divisions or transplants in early spring around the last frost date; wintergreen establishes slowly and is best sourced as a division rather than grown from seed.',3,7,12,18,3,6,12,24,'shade','moderate','Plant in acidic, humus-rich, moist but well-drained soil under deciduous or evergreen shade; wintergreen is a native North American woodland plant that thrives in conditions hostile to most herbs, particularly under conifers or in acidic woodland gardens. Established plants slowly spread into a glossy evergreen mat bearing small white flowers in summer and bright red berries through winter. Harvest the thick, aromatic leaves at any season for wintergreen tea; crush a leaf to confirm the characteristic methyl salicylate fragrance before using. Both berries and leaves are edible and safe in culinary quantities; the essential oil is very concentrated and should not be used internally.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "wintergreen", "common_name": "Wintergreen", "scientific_name": "Gaultheria procumbens", "category": "herb", "subcategory": "tea", "days_to_germination": {"min": 30, "max": 90}, "germination_soil_temp_f": {"min": 40, "max": 55}, "days_to_maturity": {"min": 365, "max": 730}, "maturity_from": "transplant", "sow_method": "division", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Plant nursery divisions or transplants in early spring around the last frost date; wintergreen establishes slowly and is best sourced as a division rather than grown from seed."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 3, "max": 6}, "spread_in": {"min": 12, "max": 24}, "sun": "shade", "water": "moderate", "directions": "Plant in acidic, humus-rich, moist but well-drained soil under deciduous or evergreen shade; wintergreen is a native North American woodland plant that thrives in conditions hostile to most herbs, particularly under conifers or in acidic woodland gardens. Established plants slowly spread into a glossy evergreen mat bearing small white flowers in summer and bright red berries through winter. Harvest the thick, aromatic leaves at any season for wintergreen tea; crush a leaf to confirm the characteristic methyl salicylate fragrance before using. Both berries and leaves are edible and safe in culinary quantities; the essential oil is very concentrated and should not be used internally.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
