  VALUES ('wood-betony','Wood Betony','Betonica officinalis','herb','medicinal',14,30,55,65,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost after a brief cold stratification; transplant to a partially shaded site after frost danger passes.',4,9,12,18,18,24,12,18,'partial','moderate','Cold-stratify seed for 2–4 weeks in the refrigerator, then surface-sow onto moist, peat-based starting mix in a warm location; germination can be slow and erratic. Plant in humus-rich, well-drained soil in partial shade or dappled light, where wood betony colonizes the herbaceous layer of meadow and woodland edge. The square stems bear whorls of rosy-purple flowers in early to midsummer and are ornamental as well as useful. Harvest aerial parts — stems, leaves, and flowers — in full bloom, drying for use in traditional headache and digestive bitters teas, where the herb is valued for its mild nervine and astringent properties.','["general horticultural reference"]','{"slug": "wood-betony", "common_name": "Wood Betony", "scientific_name": "Betonica officinalis", "category": "herb", "subcategory": "medicinal", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 55, "max": 65}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost after a brief cold stratification; transplant to a partially shaded site after frost danger passes."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Cold-stratify seed for 2–4 weeks in the refrigerator, then surface-sow onto moist, peat-based starting mix in a warm location; germination can be slow and erratic. Plant in humus-rich, well-drained soil in partial shade or dappled light, where wood betony colonizes the herbaceous layer of meadow and woodland edge. The square stems bear whorls of rosy-purple flowers in early to midsummer and are ornamental as well as useful. Harvest aerial parts — stems, leaves, and flowers — in full bloom, drying for use in traditional headache and digestive bitters teas, where the herb is valued for its mild nervine and astringent properties.", "sources": ["general horticultural reference"]}')
