INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('yarrow','Yarrow','Achillea millefolium','herb','medicinal perennial',7,14,60,72,90,120,'transplant','indoor-start','perennial','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; surface-sow as seeds need light to germinate well.',3,9,18,24,18,36,18,30,'full','low','Surface-sow seeds onto moist starting mix and press gently; do not cover as light is needed for germination. Plant in well-drained, even poor soil — overly fertile ground produces floppy growth with reduced potency. Divide clumps every 2–3 years in spring to maintain vigor and prevent the center from dying out. Harvest flat-topped flower clusters when three-quarters of the flowers are open, using them fresh or dried for wound-healing poultices, teas, and dried flower arrangements.','["general horticultural reference", "USDA PLANTS Database"]','{"slug": "yarrow", "common_name": "Yarrow", "scientific_name": "Achillea millefolium", "category": "herb", "subcategory": "medicinal perennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 72}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; surface-sow as seeds need light to germinate well."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "low", "directions": "Surface-sow seeds onto moist starting mix and press gently; do not cover as light is needed for germination. Plant in well-drained, even poor soil — overly fertile ground produces floppy growth with reduced potency. Divide clumps every 2–3 years in spring to maintain vigor and prevent the center from dying out. Harvest flat-topped flower clusters when three-quarters of the flowers are open, using them fresh or dried for wound-healing poultices, teas, and dried flower arrangements.", "sources": ["general horticultural reference", "USDA PLANTS Database"]}')
