  VALUES ('acorn-squash','Acorn Squash','Cucurbita pepo','vegetable','cucurbit',4,10,60,95,75,100,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost once soil is thoroughly warm.',3,10,24,48,12,18,48,96,'full','moderate','Sow seeds 1 inch deep in compost-enriched hills after soil reaches 65°F, planting 3–4 seeds per hill and thinning to 2. Allow vines to spread freely or train onto a sturdy trellis. Leave fruits on the vine until the rind is hard and resists a thumbnail; the stem will also begin to dry and cork over. Cure harvested squash at room temperature for 1–2 weeks to harden the skin before storage.','["general horticultural reference"]','{"slug": "acorn-squash", "common_name": "Acorn Squash", "scientific_name": "Cucurbita pepo", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 60, "max": 95}, "days_to_maturity": {"min": 75, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost once soil is thoroughly warm."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 24, "max": 48}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 48, "max": 96}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 inch deep in compost-enriched hills after soil reaches 65°F, planting 3–4 seeds per hill and thinning to 2. Allow vines to spread freely or train onto a sturdy trellis. Leave fruits on the vine until the rind is hard and resists a thumbnail; the stem will also begin to dry and cork over. Cure harvested squash at room temperature for 1–2 weeks to harden the skin before storage.", "sources": ["general horticultural reference"]}')
