INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('adzuki-bean','Adzuki Bean','Vigna angularis','vegetable','legume',5,12,60,85,90,120,'seed','direct','warm','tender','last_frost',1,3,'Direct sow 1–3 weeks after last frost when soil is warm; adzuki beans need a full warm season to produce dried beans.',5,10,4,6,18,24,8,12,'full','low','Sow seeds 1 inch deep in well-drained soil; adzuki beans are relatively drought-tolerant once established and prefer soil that is not overly rich in nitrogen. Plants produce clusters of small, dark red beans in slender pods; harvest fresh pods at 60–70 days for green shelling beans, or leave pods until they dry and turn tan for the classic small red dried bean. Watch pods closely at maturity as they shatter easily — harvest when most pods are tan but before they split open. The small, sweet beans are famous in East Asian cuisine, particularly for red bean paste in confections.','["general horticultural reference"]','{"slug": "adzuki-bean", "common_name": "Adzuki Bean", "scientific_name": "Vigna angularis", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 12}, "germination_soil_temp_f": {"min": 60, "max": 85}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 3}, "note": "Direct sow 1–3 weeks after last frost when soil is warm; adzuki beans need a full warm season to produce dried beans."}, "usda_zones": {"min": 5, "max": 10}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "low", "directions": "Sow seeds 1 inch deep in well-drained soil; adzuki beans are relatively drought-tolerant once established and prefer soil that is not overly rich in nitrogen. Plants produce clusters of small, dark red beans in slender pods; harvest fresh pods at 60–70 days for green shelling beans, or leave pods until they dry and turn tan for the classic small red dried bean. Watch pods closely at maturity as they shatter easily — harvest when most pods are tan but before they split open. The small, sweet beans are famous in East Asian cuisine, particularly for red bean paste in confections.", "sources": ["general horticultural reference"]}')
