INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('african-eggplant','African Eggplant (Garden Egg)','Solanum aethiopicum','vegetable','fruiting',7,14,75,90,70,90,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant once soil reaches 70°F and nights are reliably above 55°F.',9,12,18,24,24,48,18,24,'full','moderate','Sow seeds 1/4 inch deep in warm starting mix at 80°F and provide consistent warmth until transplanting. This West African species produces small, rounded fruits in white, green, yellow, or red and is more heat and drought tolerant than common eggplant; it is widely grown as a staple vegetable across sub-Saharan Africa. Harvest fruits while skin is still glossy and firm — they are best eaten cooked in stews, soups, and sauces where their slightly bitter flavor mellows and complements. Plants are perennial in frost-free climates and can be cut back hard after the main season to produce a second flush of fruiting growth.','["general horticultural reference"]','{"slug": "african-eggplant", "common_name": "African Eggplant (Garden Egg)", "scientific_name": "Solanum aethiopicum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 75, "max": 90}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant once soil reaches 70°F and nights are reliably above 55°F."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm starting mix at 80°F and provide consistent warmth until transplanting. This West African species produces small, rounded fruits in white, green, yellow, or red and is more heat and drought tolerant than common eggplant; it is widely grown as a staple vegetable across sub-Saharan Africa. Harvest fruits while skin is still glossy and firm — they are best eaten cooked in stews, soups, and sauces where their slightly bitter flavor mellows and complements. Plants are perennial in frost-free climates and can be cut back hard after the main season to produce a second flush of fruiting growth.", "sources": ["general horticultural reference"]}')
