INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('agretti','Agretti (Monk''s Beard)','Salsola soda','vegetable','greens',7,21,50,65,45,60,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; fresh seed is critical as viability drops sharply after 6 months — sow generously.',3,9,6,9,12,18,9,12,'full','low','Sow very fresh seed 1/4 inch deep thickly in cool, well-drained soil, as germination rates drop dramatically when seed is more than a few months old — plan to sow thickly and use thinnings. Agretti is an Italian coastal plant related to glasswort, and it thrives in sandy, saline, or alkaline soils where most vegetables struggle; it is very intolerant of waterlogged conditions. Harvest young shoot tips and the grass-like, succulent leaves when 6–8 inches tall by snipping with scissors 1–2 inches above the soil, allowing the plant to regrow once or twice before it goes to seed. The slender, fleshy, bright-green leaves have a mildly salty, slightly mineral flavor outstanding blanched with lemon or served alongside fish and seafood in the Italian spring tradition.','["general horticultural reference"]','{"slug": "agretti", "common_name": "Agretti (Monk''s Beard)", "scientific_name": "Salsola soda", "category": "vegetable", "subcategory": "greens", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 45, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; fresh seed is critical as viability drops sharply after 6 months — sow generously."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "low", "directions": "Sow very fresh seed 1/4 inch deep thickly in cool, well-drained soil, as germination rates drop dramatically when seed is more than a few months old — plan to sow thickly and use thinnings. Agretti is an Italian coastal plant related to glasswort, and it thrives in sandy, saline, or alkaline soils where most vegetables struggle; it is very intolerant of waterlogged conditions. Harvest young shoot tips and the grass-like, succulent leaves when 6–8 inches tall by snipping with scissors 1–2 inches above the soil, allowing the plant to regrow once or twice before it goes to seed. The slender, fleshy, bright-green leaves have a mildly salty, slightly mineral flavor outstanding blanched with lemon or served alongside fish and seafood in the Italian spring tradition.", "sources": ["general horticultural reference"]}')
