INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('aji-amarillo','Aji Amarillo','Capsicum baccatum','vegetable','fruiting',10,21,75,85,80,100,'transplant','indoor-start','warm','tender','last_frost',-12,-10,'Start indoors 10–12 weeks before last frost; transplant after soil reaches 65°F and all frost danger has passed.',9,12,18,24,24,48,18,24,'full','moderate','Sow seeds 1/4 inch deep in warm starting mix at 80°F; Capsicum baccatum germinates more reliably when bottom heat is maintained consistently throughout the seedling stage. Transplant to the warmest, most sheltered garden bed once nights stay above 55°F, spacing plants 18–24 inches apart in well-drained, fertile soil. Fruits ripen from green through yellow-orange to a vibrant golden yellow and should be harvested when fully colored for the characteristic fruity, berry-like heat. In frost-free climates the plants are perennial; pot and overwinter indoors elsewhere to carry productive plants to a second year.','["general horticultural reference"]','{"slug": "aji-amarillo", "common_name": "Aji Amarillo", "scientific_name": "Capsicum baccatum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 80, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -12, "max": -10}, "note": "Start indoors 10–12 weeks before last frost; transplant after soil reaches 65°F and all frost danger has passed."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm starting mix at 80°F; Capsicum baccatum germinates more reliably when bottom heat is maintained consistently throughout the seedling stage. Transplant to the warmest, most sheltered garden bed once nights stay above 55°F, spacing plants 18–24 inches apart in well-drained, fertile soil. Fruits ripen from green through yellow-orange to a vibrant golden yellow and should be harvested when fully colored for the characteristic fruity, berry-like heat. In frost-free climates the plants are perennial; pot and overwinter indoors elsewhere to carry productive plants to a second year.", "sources": ["general horticultural reference"]}')
