  VALUES ('amaranth-callaloo','Amaranth (Callaloo)','Amaranthus tricolor','vegetable','leafy-green',5,10,65,85,30,45,'seed','direct','warm','tender','last_frost',1,3,'Direct sow 1–3 weeks after last frost once soil has warmed to at least 65°F; seeds are tiny and benefit from surface sowing.',3,11,6,12,18,48,12,18,'full','moderate','Scatter tiny seeds on the soil surface or press in no deeper than 1/8 inch, and keep moist until germination; thin to 6–12 inches once seedlings are established. Vegetable amaranth thrives in heat and is exceptionally drought-tolerant once established, making it a reliable summer green when spinach has bolted. Harvest young leaves and shoot tips continuously from 30 days onward; regular harvesting delays flowering and extends the harvest window. Leaves are best cooked briefly — sautéed, steamed, or simmered in soups — and are rich in iron and calcium.','["general horticultural reference"]','{"slug": "amaranth-callaloo", "common_name": "Amaranth (Callaloo)", "scientific_name": "Amaranthus tricolor", "category": "vegetable", "subcategory": "leafy-green", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 30, "max": 45}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 3}, "note": "Direct sow 1–3 weeks after last frost once soil has warmed to at least 65°F; seeds are tiny and benefit from surface sowing."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 18, "max": 48}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Scatter tiny seeds on the soil surface or press in no deeper than 1/8 inch, and keep moist until germination; thin to 6–12 inches once seedlings are established. Vegetable amaranth thrives in heat and is exceptionally drought-tolerant once established, making it a reliable summer green when spinach has bolted. Harvest young leaves and shoot tips continuously from 30 days onward; regular harvesting delays flowering and extends the harvest window. Leaves are best cooked briefly — sautéed, steamed, or simmered in soups — and are rich in iron and calcium.", "sources": ["general horticultural reference"]}')
