INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('anaheim-pepper','Anaheim Pepper','Capsicum annuum','vegetable','fruiting',7,21,70,85,75,85,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant 1–2 weeks after frost danger passes when soil is warm.',5,11,18,24,24,36,18,24,'full','moderate','Sow seeds 1/4 inch deep in warm mix at 80°F and provide bright light once germinated to prevent leggy growth; transplant after frost danger has completely passed. Anaheim peppers are mildly hot (500–2,500 Scoville units), long and tapered, and the classic pepper for green chile and chiles rellenos. Harvest green at 75 days for mild flavor, or allow pods to ripen to red for a sweeter, slightly hotter pepper that can be dried and ground into pure chile powder. Consistent watering and a light fertilizer application when flowers begin to set helps prevent blossom drop in heat.','["general horticultural reference"]','{"slug": "anaheim-pepper", "common_name": "Anaheim Pepper", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 75, "max": 85}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant 1–2 weeks after frost danger passes when soil is warm."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm mix at 80°F and provide bright light once germinated to prevent leggy growth; transplant after frost danger has completely passed. Anaheim peppers are mildly hot (500–2,500 Scoville units), long and tapered, and the classic pepper for green chile and chiles rellenos. Harvest green at 75 days for mild flavor, or allow pods to ripen to red for a sweeter, slightly hotter pepper that can be dried and ground into pure chile powder. Consistent watering and a light fertilizer application when flowers begin to set helps prevent blossom drop in heat.", "sources": ["general horticultural reference"]}')
