INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('arugula','Arugula','Eruca vesicaria subsp. sativa','vegetable','leafy green',3,7,40,75,21,40,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; succession sow every 2–3 weeks through spring and again in fall.',2,11,4,6,6,12,4,8,'partial','moderate','Broadcast or sow in rows at 1/4 in depth in cool soil; arugula is one of the fastest salad greens to harvest. Thin to 4–6 in for full-sized leaves, or leave thicker for baby leaf harvests. Cut-and-come-again harvests are possible but quality drops quickly in warm weather as leaves become very pungent and plants bolt. Baby leaves at 2–3 in are mild; let them grow to 4–6 in for classic peppery flavor.','["general horticultural reference"]','{"slug": "arugula", "common_name": "Arugula", "scientific_name": "Eruca vesicaria subsp. sativa", "category": "vegetable", "subcategory": "leafy green", "days_to_germination": {"min": 3, "max": 7}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 21, "max": 40}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; succession sow every 2–3 weeks through spring and again in fall."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 4, "max": 8}, "sun": "partial", "water": "moderate", "directions": "Broadcast or sow in rows at 1/4 in depth in cool soil; arugula is one of the fastest salad greens to harvest. Thin to 4–6 in for full-sized leaves, or leave thicker for baby leaf harvests. Cut-and-come-again harvests are possible but quality drops quickly in warm weather as leaves become very pungent and plants bolt. Baby leaves at 2–3 in are mild; let them grow to 4–6 in for classic peppery flavor.", "sources": ["general horticultural reference"]}')
