INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('banana-pepper','Banana Pepper','Capsicum annuum','vegetable','fruiting',8,14,70,85,60,75,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed.',4,11,14,18,18,30,14,18,'full','moderate','Sow seeds 1/4 inch deep in warm starting mix and keep at 75–80°F until sprouts appear. Transplant to the garden after last frost and water evenly to maintain steady growth and prevent fruit splitting. Banana peppers are mild and productive; pick fruits at 4–6 inches long when pale yellow for the mildest flavor. Leaving fruits to mature to orange or red increases both sweetness and slight heat.','["general horticultural reference"]','{"slug": "banana-pepper", "common_name": "Banana Pepper", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 8, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 60, "max": 75}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 14, "max": 18}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 14, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm starting mix and keep at 75–80°F until sprouts appear. Transplant to the garden after last frost and water evenly to maintain steady growth and prevent fruit splitting. Banana peppers are mild and productive; pick fruits at 4–6 inches long when pale yellow for the mildest flavor. Leaving fruits to mature to orange or red increases both sweetness and slight heat.", "sources": ["general horticultural reference"]}')
