  VALUES ('beet','Beet','Beta vulgaris','vegetable','root',5,14,50,85,50,70,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before the last frost; make a second sowing in late summer for a fall crop.',2,11,3,4,8,14,3,5,'full','moderate','Sow beet clusters (each is a multi-seeded fruit) 1/2 in deep in rows 12 in apart. Because each corky seed can produce 2–3 seedlings, thin early to 3–4 in to avoid crowding, and use the thinnings as salad greens. Maintain even soil moisture to prevent woody, cracked roots. Harvest globe roots at 1.5–3 in diameter; larger roots become pithy and lose sweetness.','["general horticultural reference"]','{"slug": "beet", "common_name": "Beet", "scientific_name": "Beta vulgaris", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 5, "max": 14}, "germination_soil_temp_f": {"min": 50, "max": 85}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before the last frost; make a second sowing in late summer for a fall crop."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 3, "max": 4}, "height_in": {"min": 8, "max": 14}, "spread_in": {"min": 3, "max": 5}, "sun": "full", "water": "moderate", "directions": "Sow beet clusters (each is a multi-seeded fruit) 1/2 in deep in rows 12 in apart. Because each corky seed can produce 2–3 seedlings, thin early to 3–4 in to avoid crowding, and use the thinnings as salad greens. Maintain even soil moisture to prevent woody, cracked roots. Harvest globe roots at 1.5–3 in diameter; larger roots become pithy and lose sweetness.", "sources": ["general horticultural reference"]}')
