INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('bitter-melon','Bitter Melon (Bitter Gourd)','Momordica charantia','vegetable','fruiting',7,14,75,95,55,75,'transplant','indoor-start','warm','tender','last_frost',-4,-2,'Start indoors 2–4 weeks before last frost; transplant after soil warms to 75°F — the hotter the summer, the better it performs.',9,12,12,24,60,120,12,24,'full','moderate','Nick the seed coat or soak seeds 24 hours before sowing to improve germination; sow 1/2 in deep in warm starting mix at 80–85°F. Provide a trellis at least 6 feet tall — the vines climb by tendrils and produce more fruit when grown vertically. Hand-pollinate by transferring pollen from male to female flowers (female has a tiny immature fruit at the base) using a soft brush to improve fruit set in low-insect conditions. Harvest when fruits are still firm, bright green, and about 4–6 in long; fully ripe fruits turn orange-yellow and split open, revealing red-coated seeds that birds relish but the bitter flesh is no longer palatable.','["general horticultural reference", "University of Florida IFAS Extension"]','{"slug": "bitter-melon", "common_name": "Bitter Melon (Bitter Gourd)", "scientific_name": "Momordica charantia", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 75, "max": 95}, "days_to_maturity": {"min": 55, "max": 75}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Start indoors 2–4 weeks before last frost; transplant after soil warms to 75°F — the hotter the summer, the better it performs."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 12, "max": 24}, "height_in": {"min": 60, "max": 120}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "moderate", "directions": "Nick the seed coat or soak seeds 24 hours before sowing to improve germination; sow 1/2 in deep in warm starting mix at 80–85°F. Provide a trellis at least 6 feet tall — the vines climb by tendrils and produce more fruit when grown vertically. Hand-pollinate by transferring pollen from male to female flowers (female has a tiny immature fruit at the base) using a soft brush to improve fruit set in low-insect conditions. Harvest when fruits are still firm, bright green, and about 4–6 in long; fully ripe fruits turn orange-yellow and split open, revealing red-coated seeds that birds relish but the bitter flesh is no longer palatable.", "sources": ["general horticultural reference", "University of Florida IFAS Extension"]}')
