  VALUES ('black-radish','Black Radish','Raphanus sativus var. niger','vegetable','root',4,7,45,70,55,70,'seed','direct','cool','hardy','first_frost',-10,-8,'Sow 8–10 weeks before first fall frost; black radish stores well into winter and is best harvested after light frosts improve flavor.',2,11,6,8,9,18,6,8,'full','moderate','Sow seeds 1/2 inch deep in loose, deeply prepared, fertile soil in late summer for fall harvest; thin seedlings to 6–8 inches to allow the large roots to develop fully. Black radish is an ancient European winter storage root with rough, jet-black skin and crisp, pungent white flesh — significantly hotter than spring radishes and reminiscent of strong horseradish. Harvest after light frost, which mellows the intense pungency; roots can reach 3–4 inches in diameter and 4–6 inches long. The robust flavor is best appreciated when the flesh is grated raw into salads with sour cream, pickled in brine, or cooked in soups where the heat moderates pleasantly.','["general horticultural reference"]','{"slug": "black-radish", "common_name": "Black Radish", "scientific_name": "Raphanus sativus var. niger", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 45, "max": 70}, "days_to_maturity": {"min": 55, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Sow 8–10 weeks before first fall frost; black radish stores well into winter and is best harvested after light frosts improve flavor."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 9, "max": 18}, "spread_in": {"min": 6, "max": 8}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/2 inch deep in loose, deeply prepared, fertile soil in late summer for fall harvest; thin seedlings to 6–8 inches to allow the large roots to develop fully. Black radish is an ancient European winter storage root with rough, jet-black skin and crisp, pungent white flesh — significantly hotter than spring radishes and reminiscent of strong horseradish. Harvest after light frost, which mellows the intense pungency; roots can reach 3–4 inches in diameter and 4–6 inches long. The robust flavor is best appreciated when the flesh is grated raw into salads with sour cream, pickled in brine, or cooked in soups where the heat moderates pleasantly.", "sources": ["general horticultural reference"]}')
