INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('bottle-gourd','Bottle Gourd (Calabash)','Lagenaria siceraria','vegetable','cucurbit',7,14,65,90,60,90,'seed','indoor-start','warm','tender','last_frost',-4,-3,'Start indoors 3–4 weeks before last frost and transplant after frost danger passes; direct sowing is also possible once soil is warm.',4,11,36,60,12,24,120,240,'full','moderate','Sow seeds 1/2 inch deep in warm mix or directly in warm soil; nick the seed coat or soak overnight to speed germination. Bottle gourd is a vigorous, tropical vine that requires a sturdy trellis or fence and very warm conditions to thrive. Harvest immature fruits when they are 6–8 inches long (or the desired shape depending on variety) for vegetable use — they are delicate and best cooked; allow fruits to mature fully and dry on the vine if growing for use as a gourd vessel. Pollination requires both male and female flowers to be open simultaneously; hand-pollinate in the morning if fruit set is poor.','["general horticultural reference"]','{"slug": "bottle-gourd", "common_name": "Bottle Gourd (Calabash)", "scientific_name": "Lagenaria siceraria", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 90}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -3}, "note": "Start indoors 3–4 weeks before last frost and transplant after frost danger passes; direct sowing is also possible once soil is warm."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 120, "max": 240}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/2 inch deep in warm mix or directly in warm soil; nick the seed coat or soak overnight to speed germination. Bottle gourd is a vigorous, tropical vine that requires a sturdy trellis or fence and very warm conditions to thrive. Harvest immature fruits when they are 6–8 inches long (or the desired shape depending on variety) for vegetable use — they are delicate and best cooked; allow fruits to mature fully and dry on the vine if growing for use as a gourd vessel. Pollination requires both male and female flowers to be open simultaneously; hand-pollinate in the morning if fruit set is poor.", "sources": ["general horticultural reference"]}')
