INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('broccoli-raab','Broccoli Raab (Rapini)','Brassica rapa subsp. ruvo','vegetable','brassica',4,7,40,75,40,60,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost for spring crop; sow again in late summer for fall harvest.',3,9,4,6,12,24,6,10,'full','moderate','Direct sow seed 1/4 in deep and thin to 4–6 in; rapini grows quickly and is best as a cool-season crop because heat intensifies bitterness and accelerates bolting. Side-dress with nitrogen once plants are established to encourage the leafy shoot growth that is the primary harvest. Harvest when flower buds are visible but before they open fully, cutting the top 6–8 in of the shoot with leaves included. Repeated cuts extend the harvest, as side shoots continue to develop after the main stem is removed.','["general horticultural reference"]','{"slug": "broccoli-raab", "common_name": "Broccoli Raab (Rapini)", "scientific_name": "Brassica rapa subsp. ruvo", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 40, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost for spring crop; sow again in late summer for fall harvest."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Direct sow seed 1/4 in deep and thin to 4–6 in; rapini grows quickly and is best as a cool-season crop because heat intensifies bitterness and accelerates bolting. Side-dress with nitrogen once plants are established to encourage the leafy shoot growth that is the primary harvest. Harvest when flower buds are visible but before they open fully, cutting the top 6–8 in of the shoot with leaves included. Repeated cuts extend the harvest, as side shoots continue to develop after the main stem is removed.", "sources": ["general horticultural reference"]}')
