INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('bulb-onion','Bulb Onion','Allium cepa','vegetable','bulb',NULL,NULL,50,80,90,120,'transplant','bulb','cool','hardy','last_frost',-4,-2,'Plant sets or transplants 2–4 weeks before last frost; onions from sets mature faster and are simpler for home gardeners.',3,10,4,6,12,18,3,5,'full','moderate','Press sets or transplants 1 in deep with the pointed tip facing up in rich, well-drained, loose soil. Onion bulb size is determined by the number of leaves at the time of bulbing: each leaf corresponds to a ring, so healthy top growth is essential throughout spring. Reduce watering once the necks begin to soften and tops start to fall over naturally. Cure harvested bulbs in a warm, airy spot for 2–3 weeks before moving to dry, cool storage.','["general horticultural reference"]','{"slug": "bulb-onion", "common_name": "Bulb Onion", "scientific_name": "Allium cepa", "category": "vegetable", "subcategory": "bulb", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": 50, "max": 80}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "bulb", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Plant sets or transplants 2–4 weeks before last frost; onions from sets mature faster and are simpler for home gardeners."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 3, "max": 5}, "sun": "full", "water": "moderate", "directions": "Press sets or transplants 1 in deep with the pointed tip facing up in rich, well-drained, loose soil. Onion bulb size is determined by the number of leaves at the time of bulbing: each leaf corresponds to a ring, so healthy top growth is essential throughout spring. Reduce watering once the necks begin to soften and tops start to fall over naturally. Cure harvested bulbs in a warm, airy spot for 2–3 weeks before moving to dry, cool storage.", "sources": ["general horticultural reference"]}')
