INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('burdock','Burdock (Gobo)','Arctium lappa','vegetable','root',7,21,50,80,120,150,'seed','direct','cool','hardy','last_frost',-4,-2,'Sow 2–4 weeks before last frost in deep, raised beds or containers; roots can reach 3 feet and demand well-prepared deep soil.',3,10,4,6,24,48,18,24,'full','moderate','Sow seeds 1/2 inch deep in soil loosened to at least 18 inches; raised beds filled with light, compost-rich mix make harvest far easier than attempting to dig clay or compacted soil. Thin to 4–6 inches once seedlings are established. Gobo roots are harvested at 18–24 inches long and about 3/4 inch in diameter, typically 120 days after sowing; use a spading fork to loosen the soil alongside the root before pulling to prevent breakage. Scrub roots and slice thinly for kinpira and stir-fries; soaking cut pieces in acidulated water prevents browning.','["general horticultural reference"]','{"slug": "burdock", "common_name": "Burdock (Gobo)", "scientific_name": "Arctium lappa", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 50, "max": 80}, "days_to_maturity": {"min": 120, "max": 150}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Sow 2–4 weeks before last frost in deep, raised beds or containers; roots can reach 3 feet and demand well-prepared deep soil."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/2 inch deep in soil loosened to at least 18 inches; raised beds filled with light, compost-rich mix make harvest far easier than attempting to dig clay or compacted soil. Thin to 4–6 inches once seedlings are established. Gobo roots are harvested at 18–24 inches long and about 3/4 inch in diameter, typically 120 days after sowing; use a spading fork to loosen the soil alongside the root before pulling to prevent breakage. Scrub roots and slice thinly for kinpira and stir-fries; soaking cut pieces in acidulated water prevents browning.", "sources": ["general horticultural reference"]}')
