INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('bush-bean','Bush Bean','Phaseolus vulgaris','vegetable','legume',7,14,60,85,50,65,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after the last frost when soil is reliably warm; succession sow every 2–3 weeks for a continuous harvest.',3,11,4,6,18,24,12,18,'full','moderate','Sow seeds 1 in deep in well-drained soil once nighttime temperatures stay above 50°F. Avoid overhead watering once flowers appear to reduce bean rust and fungal issues. Pick pods when they snap cleanly and the seeds inside are still small; regular harvesting extends production. Inoculating seed with rhizobium before planting boosts nitrogen fixation and yield.','["general horticultural reference"]','{"slug": "bush-bean", "common_name": "Bush Bean", "scientific_name": "Phaseolus vulgaris", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 85}, "days_to_maturity": {"min": 50, "max": 65}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after the last frost when soil is reliably warm; succession sow every 2–3 weeks for a continuous harvest."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 in deep in well-drained soil once nighttime temperatures stay above 50°F. Avoid overhead watering once flowers appear to reduce bean rust and fungal issues. Pick pods when they snap cleanly and the seeds inside are still small; regular harvesting extends production. Inoculating seed with rhizobium before planting boosts nitrogen fixation and yield.", "sources": ["general horticultural reference"]}')
