INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cabbage','Cabbage','Brassica oleracea var. capitata','vegetable','brassica',5,10,45,85,60,120,'transplant','indoor-start','cool','hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant 4 weeks before last frost for spring crop, or start midsummer for fall harvest.',1,9,12,24,12,18,12,24,'full','moderate','Sow seed 1/4 in deep indoors and harden seedlings off gradually before setting out into cool soil. Feed transplants with a balanced fertilizer at planting and side-dress with nitrogen when heads begin to size. Keep soil moisture consistent, as uneven watering causes heads to split. Harvest when the head feels firm and solid when squeezed; a light frost sweetens the flavor.','["general horticultural reference"]','{"slug": "cabbage", "common_name": "Cabbage", "scientific_name": "Brassica oleracea var. capitata", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 60, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant 4 weeks before last frost for spring crop, or start midsummer for fall harvest."}, "usda_zones": {"min": 1, "max": 9}, "spacing_in": {"min": 12, "max": 24}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep indoors and harden seedlings off gradually before setting out into cool soil. Feed transplants with a balanced fertilizer at planting and side-dress with nitrogen when heads begin to size. Keep soil moisture consistent, as uneven watering causes heads to split. Harvest when the head feels firm and solid when squeezed; a light frost sweetens the flavor.", "sources": ["general horticultural reference"]}')
