INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('camelina','Camelina (False Flax)','Camelina sativa','vegetable','oilseed',5,10,35,65,85,100,'seed','direct','cool','hardy','soil_workable',0,3,'Sow as early as the ground can be worked in spring; tolerates light frost and thin, dry soils where most oilseeds fail.',3,8,3,6,18,36,4,8,'full','low','Surface-sow tiny seed at 5–8 lb/acre and tamp firmly; camelina requires light for good germination and should not be buried more than 1/4 in deep. It matures in under 100 days and tolerates drought and cold better than any other oilseed crop, making it a fine spring or overwintered autumn oilseed in short-season gardens. Harvest when 80% of the pods are golden and dry — thresh by beating bundled stalks into a bucket, then winnow. The oil is exceptionally high in omega-3 fatty acids and has a pleasant nutty flavor for culinary use.','["general horticultural reference"]','{"slug": "camelina", "common_name": "Camelina (False Flax)", "scientific_name": "Camelina sativa", "category": "vegetable", "subcategory": "oilseed", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 35, "max": 65}, "days_to_maturity": {"min": 85, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 3}, "note": "Sow as early as the ground can be worked in spring; tolerates light frost and thin, dry soils where most oilseeds fail."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 3, "max": 6}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "low", "directions": "Surface-sow tiny seed at 5–8 lb/acre and tamp firmly; camelina requires light for good germination and should not be buried more than 1/4 in deep. It matures in under 100 days and tolerates drought and cold better than any other oilseed crop, making it a fine spring or overwintered autumn oilseed in short-season gardens. Harvest when 80% of the pods are golden and dry — thresh by beating bundled stalks into a bucket, then winnow. The oil is exceptionally high in omega-3 fatty acids and has a pleasant nutty flavor for culinary use.", "sources": ["general horticultural reference"]}')
