INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cantaloupe','Cantaloupe / Muskmelon','Cucumis melo var. reticulatus','vegetable','cucurbit',3,10,65,90,70,90,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost once soil reaches 65°F; can start indoors 2–3 weeks early.',4,11,24,36,12,18,60,96,'full','moderate','Sow seeds 1 inch deep in warm, fertile hills after all frost danger has passed, planting 4–5 seeds per hill and thinning to 2. Reduce watering as fruits near maturity to concentrate sugars in the flesh. Ripe cantaloupes emit a sweet fragrance at the blossom end and slip easily from the vine with gentle pressure; this is called full-slip harvest. Avoid overwatering late in the season, which dilutes flavor and can cause splitting.','["general horticultural reference"]','{"slug": "cantaloupe", "common_name": "Cantaloupe / Muskmelon", "scientific_name": "Cucumis melo var. reticulatus", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 3, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 90}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost once soil reaches 65°F; can start indoors 2–3 weeks early."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 60, "max": 96}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 inch deep in warm, fertile hills after all frost danger has passed, planting 4–5 seeds per hill and thinning to 2. Reduce watering as fruits near maturity to concentrate sugars in the flesh. Ripe cantaloupes emit a sweet fragrance at the blossom end and slip easily from the vine with gentle pressure; this is called full-slip harvest. Avoid overwatering late in the season, which dilutes flavor and can cause splitting.", "sources": ["general horticultural reference"]}')
