INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cardoon','Cardoon','Cynara cardunculus','vegetable','perennial',10,21,65,85,120,150,'seed','indoor-start','perennial','half-hardy','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after frost danger passes, spacing widely as plants become very large.',7,10,36,48,48,84,36,60,'full','moderate','Sow seeds 1/2 inch deep in large cells or pots and grow on at 65–70°F; transplant into deeply prepared, fertile soil with plenty of compost. In late summer, blanch the stalks by gathering them upright, wrapping loosely in cardboard or burlap, and tying for 4–6 weeks to produce pale, tender, mildly bitter stalks. Harvest in late autumn by cutting the whole plant at the base, then trim the central stalks for cooking. In Zones 7–10 cardoon is perennial; cut old growth to the ground in early spring and topdress with compost to stimulate regrowth.','["general horticultural reference"]','{"slug": "cardoon", "common_name": "Cardoon", "scientific_name": "Cynara cardunculus", "category": "vegetable", "subcategory": "perennial", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 120, "max": 150}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "perennial", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after frost danger passes, spacing widely as plants become very large."}, "usda_zones": {"min": 7, "max": 10}, "spacing_in": {"min": 36, "max": 48}, "height_in": {"min": 48, "max": 84}, "spread_in": {"min": 36, "max": 60}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/2 inch deep in large cells or pots and grow on at 65–70°F; transplant into deeply prepared, fertile soil with plenty of compost. In late summer, blanch the stalks by gathering them upright, wrapping loosely in cardboard or burlap, and tying for 4–6 weeks to produce pale, tender, mildly bitter stalks. Harvest in late autumn by cutting the whole plant at the base, then trim the central stalks for cooking. In Zones 7–10 cardoon is perennial; cut old growth to the ground in early spring and topdress with compost to stimulate regrowth.", "sources": ["general horticultural reference"]}')
