INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('carrot','Carrot','Daucus carota subsp. sativus','vegetable','root',10,21,45,85,60,80,'seed','direct','cool','half-hardy','last_frost',-3,2,'Direct sow 3 weeks before to 2 weeks after last frost; succession sow every 3 weeks.',3,11,2,3,8,12,2,3,'full','moderate','Sow seed 1/4 in deep in loose, stone-free soil and keep the surface consistently moist until sprouting, which is slow. Thin seedlings to 2–3 in so roots can size up. Harvest when shoulders reach desired diameter; flavor sweetens after a light frost.','["general horticultural reference"]','{"slug": "carrot", "common_name": "Carrot", "scientific_name": "Daucus carota subsp. sativus", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -3, "max": 2}, "note": "Direct sow 3 weeks before to 2 weeks after last frost; succession sow every 3 weeks."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 2, "max": 3}, "height_in": {"min": 8, "max": 12}, "spread_in": {"min": 2, "max": 3}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep in loose, stone-free soil and keep the surface consistently moist until sprouting, which is slow. Thin seedlings to 2–3 in so roots can size up. Harvest when shoulders reach desired diameter; flavor sweetens after a light frost.", "sources": ["general horticultural reference"]}')
