INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cauliflower','Cauliflower','Brassica oleracea var. botrytis','vegetable','brassica',5,10,45,85,55,80,'transplant','indoor-start','cool','half-hardy','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant about 4 weeks before last frost.',3,10,18,24,18,30,18,24,'full','moderate','Sow 1/4 in deep in well-drained starter mix 6–8 weeks before transplanting; cauliflower is sensitive to temperature swings and nutrient deficiencies. When the developing curd is about the size of a golf ball, gather outer leaves over it and secure with a rubber band to blanch for white varieties. Harvest when the head is firm, tight, and 6–8 in across before the curds begin to separate. Consistent soil moisture and boron-sufficient soil prevent hollow stem and poor curd formation.','["general horticultural reference"]','{"slug": "cauliflower", "common_name": "Cauliflower", "scientific_name": "Brassica oleracea var. botrytis", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 55, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant about 4 weeks before last frost."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow 1/4 in deep in well-drained starter mix 6–8 weeks before transplanting; cauliflower is sensitive to temperature swings and nutrient deficiencies. When the developing curd is about the size of a golf ball, gather outer leaves over it and secure with a rubber band to blanch for white varieties. Harvest when the head is firm, tight, and 6–8 in across before the curds begin to separate. Consistent soil moisture and boron-sufficient soil prevent hollow stem and poor curd formation.", "sources": ["general horticultural reference"]}')
