INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('celeriac','Celeriac','Apium graveolens var. rapaceum','vegetable','root',10,21,60,70,100,120,'transplant','indoor-start','cool','half-hardy','last_frost',-10,-8,'Start indoors 8–10 weeks before the last frost; transplant after frost danger has passed when plants are 3–4 in tall.',3,9,12,14,18,24,12,16,'full','high','Sow seeds on the surface of moist starting mix — they need light to germinate — and barely cover with vermiculite; seedling growth is extremely slow for the first 6 weeks. Transplant into rich, consistently moist soil and remove the lower side shoots throughout summer to encourage bulb development. Celeriac bulbs are at their best after light autumn frosts, which deepen the nutty flavor. Harvest before the ground freezes hard; trim roots and leaves and store in slightly moist sand in a cold root cellar.','["general horticultural reference"]','{"slug": "celeriac", "common_name": "Celeriac", "scientific_name": "Apium graveolens var. rapaceum", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 70}, "days_to_maturity": {"min": 100, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before the last frost; transplant after frost danger has passed when plants are 3–4 in tall."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 12, "max": 14}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 12, "max": 16}, "sun": "full", "water": "high", "directions": "Sow seeds on the surface of moist starting mix — they need light to germinate — and barely cover with vermiculite; seedling growth is extremely slow for the first 6 weeks. Transplant into rich, consistently moist soil and remove the lower side shoots throughout summer to encourage bulb development. Celeriac bulbs are at their best after light autumn frosts, which deepen the nutty flavor. Harvest before the ground freezes hard; trim roots and leaves and store in slightly moist sand in a cold root cellar.", "sources": ["general horticultural reference"]}')
