INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('celery','Celery','Apium graveolens var. dulce','vegetable','stem',10,21,60,75,100,130,'transplant','indoor-start','cool','half-hardy','last_frost',-12,-10,'Start indoors 10–12 weeks before last frost; transplant after all frost danger passes and soil has warmed slightly.',2,10,10,12,18,24,10,12,'full','high','Surface-sow or barely cover tiny seed with 1/8 in of moist mix; celery germinates slowly and needs consistent warmth and bright light from the start. Transplant into deeply prepared, rich soil and provide consistent, abundant moisture throughout the season, as drought quickly causes tough, stringy stalks. Hill soil around the base or use collars to blanch stalks to a paler color and milder flavor if desired. Harvest entire plants by cutting at soil level when stalks are 12–18 in tall and firm.','["general horticultural reference"]','{"slug": "celery", "common_name": "Celery", "scientific_name": "Apium graveolens var. dulce", "category": "vegetable", "subcategory": "stem", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 60, "max": 75}, "days_to_maturity": {"min": 100, "max": 130}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -12, "max": -10}, "note": "Start indoors 10–12 weeks before last frost; transplant after all frost danger passes and soil has warmed slightly."}, "usda_zones": {"min": 2, "max": 10}, "spacing_in": {"min": 10, "max": 12}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 10, "max": 12}, "sun": "full", "water": "high", "directions": "Surface-sow or barely cover tiny seed with 1/8 in of moist mix; celery germinates slowly and needs consistent warmth and bright light from the start. Transplant into deeply prepared, rich soil and provide consistent, abundant moisture throughout the season, as drought quickly causes tough, stringy stalks. Hill soil around the base or use collars to blanch stalks to a paler color and milder flavor if desired. Harvest entire plants by cutting at soil level when stalks are 12–18 in tall and firm.", "sources": ["general horticultural reference"]}')
