INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('celtuce','Celtuce (Stem Lettuce)','Lactuca sativa var. asparagina','vegetable','leafy-green',5,10,45,75,60,90,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost in spring; can also be started indoors 4 weeks early and transplanted out.',3,10,10,14,18,36,10,14,'full','moderate','Sow seeds 1/4 inch deep or start indoors and transplant at 4–5 weeks; celtuce is grown primarily for its swollen, asparagus-like central stalk rather than its leaves, though young leaves are also edible. The stalk is ready when it is 1–1.5 inches in diameter and 12–15 inches tall; peel away the outer layer to reveal the crisp, mild interior. Keep soil consistently moist and rich in nitrogen for the fastest stalk development. Harvest before the plant bolts, as heat causes bitterness and pithy texture in the stalk.','["general horticultural reference"]','{"slug": "celtuce", "common_name": "Celtuce (Stem Lettuce)", "scientific_name": "Lactuca sativa var. asparagina", "category": "vegetable", "subcategory": "leafy-green", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 45, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost in spring; can also be started indoors 4 weeks early and transplanted out."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 10, "max": 14}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 10, "max": 14}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep or start indoors and transplant at 4–5 weeks; celtuce is grown primarily for its swollen, asparagus-like central stalk rather than its leaves, though young leaves are also edible. The stalk is ready when it is 1–1.5 inches in diameter and 12–15 inches tall; peel away the outer layer to reveal the crisp, mild interior. Keep soil consistently moist and rich in nitrogen for the fastest stalk development. Harvest before the plant bolts, as heat causes bitterness and pithy texture in the stalk.", "sources": ["general horticultural reference"]}')
