INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('chayote','Chayote','Sechium edule','vegetable','cucurbit',14,28,65,85,80,120,'transplant','tuber','warm','tender','last_frost',-4,-2,'Start indoors 2–4 weeks before last frost by placing an entire fruit on its side in a pot of moist mix; transplant after all frost danger is past.',7,11,48,120,36,96,120,240,'full','moderate','Plant the whole fruit (it is the seed) on its side with the broad end slightly angled down, barely covered with moist soil; sprouting begins from the narrow end. Provide a very strong trellis as a single mature vine can reach 30 feet and produce dozens to hundreds of fruits per season. Harvest fruits when they are 3–6 inches long and the skin is still smooth and light green; older fruits become pithy and hard. In Zones 9–11, chayote is perennial and will produce an edible tuberous root as well as fruits; in cooler zones, grow as an annual by starting fresh each spring.','["general horticultural reference"]','{"slug": "chayote", "common_name": "Chayote", "scientific_name": "Sechium edule", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 80, "max": 120}, "maturity_from": "transplant", "sow_method": "tuber", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Start indoors 2–4 weeks before last frost by placing an entire fruit on its side in a pot of moist mix; transplant after all frost danger is past."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 48, "max": 120}, "height_in": {"min": 36, "max": 96}, "spread_in": {"min": 120, "max": 240}, "sun": "full", "water": "moderate", "directions": "Plant the whole fruit (it is the seed) on its side with the broad end slightly angled down, barely covered with moist soil; sprouting begins from the narrow end. Provide a very strong trellis as a single mature vine can reach 30 feet and produce dozens to hundreds of fruits per season. Harvest fruits when they are 3–6 inches long and the skin is still smooth and light green; older fruits become pithy and hard. In Zones 9–11, chayote is perennial and will produce an edible tuberous root as well as fruits; in cooler zones, grow as an annual by starting fresh each spring.", "sources": ["general horticultural reference"]}')
