INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('chia','Chia','Salvia hispanica','vegetable','grain',5,14,60,85,120,160,'seed','direct','warm','tender','last_frost',1,4,'Sow after last frost; chia is a short-day plant that flowers in fall, so it is best suited to climates with a long frost-free autumn.',9,12,18,24,36,60,12,18,'full','low','Surface-sow seed on a firm, moist seedbed and barely press in, as chia seed is mucilaginous and will stick to the surface when wet; thin plants to 18–24 in once seedlings emerge. Chia does not respond well to transplanting and should be direct-sown where it will grow. The plant flowers in autumn as day length shortens and produces whorled spikes of small purple flowers followed by seed-filled calyces; harvest stalks when the calyces begin to dry and before birds consume the seed. Place harvested stalks head-first into paper bags to finish drying, then shake out seed and screen away debris; seeds are rich in omega-3 fatty acids, calcium, and fiber.','["general horticultural reference"]','{"slug": "chia", "common_name": "Chia", "scientific_name": "Salvia hispanica", "category": "vegetable", "subcategory": "grain", "days_to_germination": {"min": 5, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 85}, "days_to_maturity": {"min": 120, "max": 160}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 4}, "note": "Sow after last frost; chia is a short-day plant that flowers in fall, so it is best suited to climates with a long frost-free autumn."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Surface-sow seed on a firm, moist seedbed and barely press in, as chia seed is mucilaginous and will stick to the surface when wet; thin plants to 18–24 in once seedlings emerge. Chia does not respond well to transplanting and should be direct-sown where it will grow. The plant flowers in autumn as day length shortens and produces whorled spikes of small purple flowers followed by seed-filled calyces; harvest stalks when the calyces begin to dry and before birds consume the seed. Place harvested stalks head-first into paper bags to finish drying, then shake out seed and screen away debris; seeds are rich in omega-3 fatty acids, calcium, and fiber.", "sources": ["general horticultural reference"]}')
