  VALUES ('chickpea','Chickpea (Garbanzo Bean)','Cicer arietinum','vegetable','legume',6,12,50,75,90,110,'seed','direct','cool','half-hardy','last_frost',-2,0,'Sow around the last frost date; chickpeas prefer a cool start but need warm, dry weather to mature properly.',4,10,6,8,18,24,10,14,'full','low','Sow chickpeas 2 in deep in light, well-drained soil with a neutral to slightly alkaline pH; they perform poorly in heavy, waterlogged ground. The plants produce distinctive sticky, glandular hairs on stems and pods that can cause a mild skin reaction in sensitive individuals, so harvest with gloves. Pick pods when they are green and plump for fresh eating, or leave plants to dry fully in place and harvest entire plants when 90% of pods have turned tan. Shell and sun-dry for a day before long-term storage.','["general horticultural reference"]','{"slug": "chickpea", "common_name": "Chickpea (Garbanzo Bean)", "scientific_name": "Cicer arietinum", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 6, "max": 12}, "germination_soil_temp_f": {"min": 50, "max": 75}, "days_to_maturity": {"min": 90, "max": 110}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 0}, "note": "Sow around the last frost date; chickpeas prefer a cool start but need warm, dry weather to mature properly."}, "usda_zones": {"min": 4, "max": 10}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 10, "max": 14}, "sun": "full", "water": "low", "directions": "Sow chickpeas 2 in deep in light, well-drained soil with a neutral to slightly alkaline pH; they perform poorly in heavy, waterlogged ground. The plants produce distinctive sticky, glandular hairs on stems and pods that can cause a mild skin reaction in sensitive individuals, so harvest with gloves. Pick pods when they are green and plump for fresh eating, or leave plants to dry fully in place and harvest entire plants when 90% of pods have turned tan. Shell and sun-dry for a day before long-term storage.", "sources": ["general horticultural reference"]}')
