INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('chinese-celery','Chinese Celery','Apium graveolens var. secalinum','vegetable','leafy-green',10,21,55,75,60,90,'transplant','indoor-start','cool','half-hardy','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant 3–4 weeks before last frost as plants can handle light frost.',4,10,6,10,12,24,6,10,'partial','high','Sow tiny seeds on the surface of moist starting mix and press lightly without covering; seeds need light to germinate and are very slow — allow 2–3 weeks. Chinese celery produces slender, hollow stems and abundant leaves with intense celery flavor far more pungent than Western stalk celery; it is used primarily as an herb and flavoring rather than eaten in large quantities raw. Transplant into moisture-retentive, fertile soil and keep evenly moist throughout the season, as drought causes bitterness and premature bolting. Harvest outer stalks continuously once plants are established; the leaves are the most intensely flavored part.','["general horticultural reference"]','{"slug": "chinese-celery", "common_name": "Chinese Celery", "scientific_name": "Apium graveolens var. secalinum", "category": "vegetable", "subcategory": "leafy-green", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 55, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant 3–4 weeks before last frost as plants can handle light frost."}, "usda_zones": {"min": 4, "max": 10}, "spacing_in": {"min": 6, "max": 10}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 6, "max": 10}, "sun": "partial", "water": "high", "directions": "Sow tiny seeds on the surface of moist starting mix and press lightly without covering; seeds need light to germinate and are very slow — allow 2–3 weeks. Chinese celery produces slender, hollow stems and abundant leaves with intense celery flavor far more pungent than Western stalk celery; it is used primarily as an herb and flavoring rather than eaten in large quantities raw. Transplant into moisture-retentive, fertile soil and keep evenly moist throughout the season, as drought causes bitterness and premature bolting. Harvest outer stalks continuously once plants are established; the leaves are the most intensely flavored part.", "sources": ["general horticultural reference"]}')
