INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('chinese-yam','Chinese Yam (Cinnamon Vine)','Dioscorea polystachya','vegetable','root',NULL,NULL,60,75,180,240,'transplant','tuber','warm','hardy','last_frost',0,4,'Plant tuber sections or bulbils in spring after last frost once soil reaches 60°F; established crowns are hardy to zone 5.',5,10,12,18,120,180,12,24,'full','moderate','Plant tuber sections or aerial bulbils (small potato-like growths that form in the leaf axils) 2–3 inches deep in deep, loose, stone-free soil; the main tuber can grow 3 feet straight down, so deep, well-prepared beds are essential. Provide a trellis or fence immediately as this vigorous twining vine can reach 15 feet in a season. Harvest main tubers in late fall after the vine dies back, being careful to dig deeply and extract the entire tuber without breaking; the secondary bulbils can also be harvested and eaten or saved for replanting. The raw tuber is one of the few yams that can be eaten uncooked and grated — called nagaimo in Japanese cuisine — where its distinctive gluey texture is prized.','["general horticultural reference"]','{"slug": "chinese-yam", "common_name": "Chinese Yam (Cinnamon Vine)", "scientific_name": "Dioscorea polystachya", "category": "vegetable", "subcategory": "root", "days_to_germination": null, "germination_soil_temp_f": {"min": 60, "max": 75}, "days_to_maturity": {"min": 180, "max": 240}, "maturity_from": "transplant", "sow_method": "tuber", "season": "warm", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant tuber sections or bulbils in spring after last frost once soil reaches 60°F; established crowns are hardy to zone 5."}, "usda_zones": {"min": 5, "max": 10}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 120, "max": 180}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "moderate", "directions": "Plant tuber sections or aerial bulbils (small potato-like growths that form in the leaf axils) 2–3 inches deep in deep, loose, stone-free soil; the main tuber can grow 3 feet straight down, so deep, well-prepared beds are essential. Provide a trellis or fence immediately as this vigorous twining vine can reach 15 feet in a season. Harvest main tubers in late fall after the vine dies back, being careful to dig deeply and extract the entire tuber without breaking; the secondary bulbils can also be harvested and eaten or saved for replanting. The raw tuber is one of the few yams that can be eaten uncooked and grated — called nagaimo in Japanese cuisine — where its distinctive gluey texture is prized.", "sources": ["general horticultural reference"]}')
