INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('choy-sum','Choy Sum','Brassica rapa var. parachinensis','vegetable','brassica',4,8,50,80,35,55,'seed','direct','cool','half-hardy','last_frost',-2,0,'Sow around the last frost date in spring, or 6–8 weeks before first fall frost; best in cool weather but tolerates mild warmth better than other brassicas.',3,11,6,10,10,18,6,10,'full','moderate','Sow seeds 1/4 inch deep in rows, thinning to 6–10 inches; plants can be sown more densely and thinned progressively, using the thinnings as greens. Harvest the central flower stalk when buds are just beginning to show yellow but before flowers open, cutting 6 inches down to leave side shoots. The stems, leaves, and flower buds are all edible; successive harvesting keeps production going for several weeks. Even soil moisture and cool temperatures produce the sweetest, most tender stalks.','["general horticultural reference"]','{"slug": "choy-sum", "common_name": "Choy Sum", "scientific_name": "Brassica rapa var. parachinensis", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 4, "max": 8}, "germination_soil_temp_f": {"min": 50, "max": 80}, "days_to_maturity": {"min": 35, "max": 55}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 0}, "note": "Sow around the last frost date in spring, or 6–8 weeks before first fall frost; best in cool weather but tolerates mild warmth better than other brassicas."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 10}, "height_in": {"min": 10, "max": 18}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in rows, thinning to 6–10 inches; plants can be sown more densely and thinned progressively, using the thinnings as greens. Harvest the central flower stalk when buds are just beginning to show yellow but before flowers open, cutting 6 inches down to leave side shoots. The stems, leaves, and flower buds are all edible; successive harvesting keeps production going for several weeks. Even soil moisture and cool temperatures produce the sweetest, most tender stalks.", "sources": ["general horticultural reference"]}')
