  VALUES ('collard-greens','Collard Greens','Brassica oleracea var. viridis','vegetable','brassica',5,10,45,85,55,75,'seed','direct','cool','hardy','last_frost',-4,0,'Direct sow or transplant around last frost date in spring; for fall, direct sow 8–10 weeks before first frost.',6,11,18,24,24,36,18,24,'full','moderate','Sow seed 1/2 in deep in fertile soil and thin to 18–24 in; collards are heat-tolerant among brassicas and can produce well into summer in the South. Fertilize with nitrogen every 4–6 weeks to maintain vigorous leaf production on these tall, long-season plants. Begin harvesting lower, fully expanded leaves once plants are 10–12 in tall, always leaving the top growing cluster intact. Frost sweetens the leaves substantially; plants may overwinter in zones 7–9.','["general horticultural reference"]','{"slug": "collard-greens", "common_name": "Collard Greens", "scientific_name": "Brassica oleracea var. viridis", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 55, "max": 75}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Direct sow or transplant around last frost date in spring; for fall, direct sow 8–10 weeks before first frost."}, "usda_zones": {"min": 6, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/2 in deep in fertile soil and thin to 18–24 in; collards are heat-tolerant among brassicas and can produce well into summer in the South. Fertilize with nitrogen every 4–6 weeks to maintain vigorous leaf production on these tall, long-season plants. Begin harvesting lower, fully expanded leaves once plants are 10–12 in tall, always leaving the top growing cluster intact. Frost sweetens the leaves substantially; plants may overwinter in zones 7–9.", "sources": ["general horticultural reference"]}')
