INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cranberry-bean','Cranberry Bean (Borlotti Bean)','Phaseolus vulgaris','vegetable','legume',7,14,60,85,60,85,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost when soil is reliably above 60°F; avoid planting in wet, cold soil which causes seed rot.',3,10,4,6,18,24,12,18,'full','moderate','Sow seeds 1–1.5 inches deep in fertile, well-drained soil; cranberry beans can be grown as a bush or pole type depending on variety. Harvest at the fresh shell stage when pods are colorfully streaked with red and cream and beans inside are plump but not yet dry — this is the classic fresh borlotti stage prized in Italian cooking. For dried beans, leave pods on the plant until they are papery and rattle when shaken, then pull entire plants and cure under cover before threshing. Regular watering during pod fill prevents shriveled beans.','["general horticultural reference"]','{"slug": "cranberry-bean", "common_name": "Cranberry Bean (Borlotti Bean)", "scientific_name": "Phaseolus vulgaris", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 85}, "days_to_maturity": {"min": 60, "max": 85}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost when soil is reliably above 60°F; avoid planting in wet, cold soil which causes seed rot."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1–1.5 inches deep in fertile, well-drained soil; cranberry beans can be grown as a bush or pole type depending on variety. Harvest at the fresh shell stage when pods are colorfully streaked with red and cream and beans inside are plump but not yet dry — this is the classic fresh borlotti stage prized in Italian cooking. For dried beans, leave pods on the plant until they are papery and rattle when shaken, then pull entire plants and cure under cover before threshing. Regular watering during pod fill prevents shriveled beans.", "sources": ["general horticultural reference"]}')
