INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cubanelle-pepper','Cubanelle Pepper (Italian Frying Pepper)','Capsicum annuum','vegetable','fruiting',7,21,70,85,65,80,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after soil warms to at least 60°F.',5,11,18,24,24,30,18,24,'full','moderate','Sow seeds 1/4 inch deep in warm starting mix and maintain soil at 80°F for best germination; grow seedlings in bright light to prevent stretching. The cubanelle produces thin-walled, tapered fruits 4–6 inches long that ripen from pale yellowish-green to red; they are nearly sweet with very mild heat and excellent for frying, stuffing, and fresh eating. Harvest green fruits at 65 days or leave on the plant to ripen red for sweeter flavor. Plants are prolific producers; side-dress with a balanced fertilizer midseason to maintain yield.','["general horticultural reference"]','{"slug": "cubanelle-pepper", "common_name": "Cubanelle Pepper (Italian Frying Pepper)", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 65, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after soil warms to at least 60°F."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 30}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm starting mix and maintain soil at 80°F for best germination; grow seedlings in bright light to prevent stretching. The cubanelle produces thin-walled, tapered fruits 4–6 inches long that ripen from pale yellowish-green to red; they are nearly sweet with very mild heat and excellent for frying, stuffing, and fresh eating. Harvest green fruits at 65 days or leave on the plant to ripen red for sweeter flavor. Plants are prolific producers; side-dress with a balanced fertilizer midseason to maintain yield.", "sources": ["general horticultural reference"]}')
