INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('cucamelon','Cucamelon (Mouse Melon)','Melothria scabra','vegetable','cucurbit',7,14,65,85,60,75,'seed','indoor-start','warm','tender','last_frost',-4,-3,'Start indoors 3–4 weeks before last frost and transplant after frost danger passes; cucamelon dislikes root disturbance so use biodegradable pots.',5,11,12,18,60,120,12,18,'full','moderate','Sow 1/4 inch deep in warm mix indoors and pot on without disturbing the root ball when transplanting; cucamelon develops a large tuberous root that can overwinter in frost-free climates. Train the delicate vines up a trellis or netting and keep soil consistently moist for best fruit set. Harvest the grape-sized fruits when they look like tiny watermelons and feel firm — they become seedy and bitter if left too long. The flavor is a pleasant combination of cucumber and lime; pick frequently to maintain heavy production.','["general horticultural reference"]','{"slug": "cucamelon", "common_name": "Cucamelon (Mouse Melon)", "scientific_name": "Melothria scabra", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 60, "max": 75}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -3}, "note": "Start indoors 3–4 weeks before last frost and transplant after frost danger passes; cucamelon dislikes root disturbance so use biodegradable pots."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 60, "max": 120}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow 1/4 inch deep in warm mix indoors and pot on without disturbing the root ball when transplanting; cucamelon develops a large tuberous root that can overwinter in frost-free climates. Train the delicate vines up a trellis or netting and keep soil consistently moist for best fruit set. Harvest the grape-sized fruits when they look like tiny watermelons and feel firm — they become seedy and bitter if left too long. The flavor is a pleasant combination of cucumber and lime; pick frequently to maintain heavy production.", "sources": ["general horticultural reference"]}')
