  VALUES ('edamame','Edamame (Soybean)','Glycine max','vegetable','legume',6,14,60,85,75,100,'seed','direct','warm','tender','last_frost',1,3,'Sow 1–3 weeks after last frost when soil has reached at least 60°F; cold, wet soil causes seed rot.',4,11,4,6,18,30,8,12,'full','moderate','Sow seeds 1 to 1.5 in deep in rows 18–24 in apart; inoculate with soybean-specific rhizobium for best nitrogen fixation. Edamame is self-supporting but benefits from well-drained, fertile soil with only modest added nitrogen. Harvest when pods are bright green, plump, and the seeds fill the pod but the shell has not yet begun to yellow. To harvest, pull the entire plant and strip pods at once; blanch immediately for best flavor and color.','["general horticultural reference"]','{"slug": "edamame", "common_name": "Edamame (Soybean)", "scientific_name": "Glycine max", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 6, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 85}, "days_to_maturity": {"min": 75, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 3}, "note": "Sow 1–3 weeks after last frost when soil has reached at least 60°F; cold, wet soil causes seed rot."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 to 1.5 in deep in rows 18–24 in apart; inoculate with soybean-specific rhizobium for best nitrogen fixation. Edamame is self-supporting but benefits from well-drained, fertile soil with only modest added nitrogen. Harvest when pods are bright green, plump, and the seeds fill the pod but the shell has not yet begun to yellow. To harvest, pull the entire plant and strip pods at once; blanch immediately for best flavor and color.", "sources": ["general horticultural reference"]}')
