  VALUES ('eggplant','Eggplant','Solanum melongena','vegetable','fruiting',7,14,75,90,65,80,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant 2–3 weeks after frost danger has passed when soil is warm.',4,12,18,24,24,48,18,30,'full','moderate','Sow seeds 1/4 inch deep in warm starting mix and maintain soil temperature above 80°F for the best germination rates. Eggplant demands the warmest possible spot in the garden; cold soil stunts growth significantly, so do not rush transplanting. Mulch heavily to hold soil warmth and moisture, and fertilize with a phosphorus-rich blend to promote flowering. Harvest fruits while the skin is still glossy, as dull skin signals over-maturity and bitterness.','["general horticultural reference"]','{"slug": "eggplant", "common_name": "Eggplant", "scientific_name": "Solanum melongena", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 75, "max": 90}, "days_to_maturity": {"min": 65, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant 2–3 weeks after frost danger has passed when soil is warm."}, "usda_zones": {"min": 4, "max": 12}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm starting mix and maintain soil temperature above 80°F for the best germination rates. Eggplant demands the warmest possible spot in the garden; cold soil stunts growth significantly, so do not rush transplanting. Mulch heavily to hold soil warmth and moisture, and fertilize with a phosphorus-rich blend to promote flowering. Harvest fruits while the skin is still glossy, as dull skin signals over-maturity and bitterness.", "sources": ["general horticultural reference"]}')
