  VALUES ('egyptian-walking-onion','Egyptian Walking Onion (Tree Onion)','Allium × proliferum','vegetable','allium',NULL,NULL,NULL,NULL,90,120,'transplant','bulb','perennial','hardy','fall',-4,0,'Plant topset bulbils in early fall so they establish before winter; spring planting is also possible but fall-planted bulbils produce larger plants more quickly.',3,9,6,10,18,30,6,10,'full','moderate','Plant the small topset bulbils 1–2 inches deep in fall or early spring, pressing firmly into well-drained soil; established clumps need dividing every 2–3 years to maintain vigor. Egyptian walking onions produce clusters of small bulbils at the top of the flower stalk; as these become heavy the stalk bends and the bulbils root where they land, effectively ''walking'' across the garden. Harvest underground bulbs in early summer after the foliage begins to die back, or harvest green tops continuously throughout the growing season like scallions. The topset bulbils can be harvested for pickling or used as transplants.','["general horticultural reference"]','{"slug": "egyptian-walking-onion", "common_name": "Egyptian Walking Onion (Tree Onion)", "scientific_name": "Allium × proliferum", "category": "vegetable", "subcategory": "allium", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "bulb", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Plant topset bulbils in early fall so they establish before winter; spring planting is also possible but fall-planted bulbils produce larger plants more quickly."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 6, "max": 10}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Plant the small topset bulbils 1–2 inches deep in fall or early spring, pressing firmly into well-drained soil; established clumps need dividing every 2–3 years to maintain vigor. Egyptian walking onions produce clusters of small bulbils at the top of the flower stalk; as these become heavy the stalk bends and the bulbils root where they land, effectively ''walking'' across the garden. Harvest underground bulbs in early summer after the foliage begins to die back, or harvest green tops continuously throughout the growing season like scallions. The topset bulbils can be harvested for pickling or used as transplants.", "sources": ["general horticultural reference"]}')
