  VALUES ('einkorn-wheat','Einkorn Wheat','Triticum monococcum','vegetable','grain',5,10,40,75,240,270,'seed','direct','cool','hardy','first_frost',-6,-2,'Sow 2–6 weeks before the first fall frost to allow establishment before winter; einkorn overwinters as a low rosette and resumes growth in early spring.',4,9,1,2,24,36,3,6,'full','low','Sow seed 1 in deep in fall at 80–100 lb per acre (about 2–3 oz per 100 sq ft); einkorn is an ancient hulled wheat that outperforms modern wheats on poor, low-fertility soils and has exceptional drought tolerance. It overwinters, then bolts in spring to reach harvest in early summer, about 2 weeks earlier than modern winter wheat. Harvest when the grain is in the hard dough stage — the straw turns yellow but the heads have not yet shattered — by cutting and binding into sheaves left to dry for a week before threshing. Einkorn retains a tough hull after threshing that requires dehulling before milling; the flour is notably nutty and golden from higher carotenoid content.','["general horticultural reference"]','{"slug": "einkorn-wheat", "common_name": "Einkorn Wheat", "scientific_name": "Triticum monococcum", "category": "vegetable", "subcategory": "grain", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 240, "max": 270}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -6, "max": -2}, "note": "Sow 2–6 weeks before the first fall frost to allow establishment before winter; einkorn overwinters as a low rosette and resumes growth in early spring."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 3, "max": 6}, "sun": "full", "water": "low", "directions": "Sow seed 1 in deep in fall at 80–100 lb per acre (about 2–3 oz per 100 sq ft); einkorn is an ancient hulled wheat that outperforms modern wheats on poor, low-fertility soils and has exceptional drought tolerance. It overwinters, then bolts in spring to reach harvest in early summer, about 2 weeks earlier than modern winter wheat. Harvest when the grain is in the hard dough stage — the straw turns yellow but the heads have not yet shattered — by cutting and binding into sheaves left to dry for a week before threshing. Einkorn retains a tough hull after threshing that requires dehulling before milling; the flour is notably nutty and golden from higher carotenoid content.", "sources": ["general horticultural reference"]}')
