  VALUES ('elephant-garlic','Elephant Garlic','Allium ampeloprasum','vegetable','allium',NULL,NULL,50,65,240,300,'transplant','bulb','cool','hardy','fall',-4,-2,'Plant cloves in fall 2–4 weeks before hard ground freeze to allow root establishment before winter dormancy.',3,9,8,12,24,48,8,12,'full','moderate','Plant individual cloves 2–4 inches deep pointed end up in well-drained, fertile soil in fall, with the flat base downward. Elephant garlic is technically a leek relative (Allium ampeloprasum) rather than a true garlic; its flavor is much milder and sweeter than hardneck garlic, lacking the pungent bite, and the huge cloves are easy to peel. Remove flower scapes (curling stems) in early summer to redirect energy into bulb development, just as with true garlic. Harvest when the lower third of the leaves has browned, dig carefully, and cure in a warm, ventilated location for 3–4 weeks before storing or braiding.','["general horticultural reference"]','{"slug": "elephant-garlic", "common_name": "Elephant Garlic", "scientific_name": "Allium ampeloprasum", "category": "vegetable", "subcategory": "allium", "days_to_germination": null, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 240, "max": 300}, "maturity_from": "transplant", "sow_method": "bulb", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Plant cloves in fall 2–4 weeks before hard ground freeze to allow root establishment before winter dormancy."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "moderate", "directions": "Plant individual cloves 2–4 inches deep pointed end up in well-drained, fertile soil in fall, with the flat base downward. Elephant garlic is technically a leek relative (Allium ampeloprasum) rather than a true garlic; its flavor is much milder and sweeter than hardneck garlic, lacking the pungent bite, and the huge cloves are easy to peel. Remove flower scapes (curling stems) in early summer to redirect energy into bulb development, just as with true garlic. Harvest when the lower third of the leaves has browned, dig carefully, and cure in a warm, ventilated location for 3–4 weeks before storing or braiding.", "sources": ["general horticultural reference"]}')
