INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('endive','Endive','Cichorium endivia','vegetable','leafy green',5,9,50,75,85,100,'seed','direct','cool','half-hardy','first_frost',-14,-12,'For best quality, sow in midsummer so heads mature in cool fall weather 12–14 weeks before first frost.',4,9,10,14,10,16,10,14,'full','moderate','Sow seed 1/4 in deep in fertile soil and thin to 10–14 in; endive has a long growing season and benefits from cool temperatures during head development. Blanch curly endive (frisée) by tying outer leaves over the heart for 10 days before harvest to reduce bitterness. Harvest by cutting the whole head at soil level once it feels firm and the inner leaves are pale and well-formed. Light frost improves flavor by reducing bitterness slightly.','["general horticultural reference"]','{"slug": "endive", "common_name": "Endive", "scientific_name": "Cichorium endivia", "category": "vegetable", "subcategory": "leafy green", "days_to_germination": {"min": 5, "max": 9}, "germination_soil_temp_f": {"min": 50, "max": 75}, "days_to_maturity": {"min": 85, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -14, "max": -12}, "note": "For best quality, sow in midsummer so heads mature in cool fall weather 12–14 weeks before first frost."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 10, "max": 14}, "height_in": {"min": 10, "max": 16}, "spread_in": {"min": 10, "max": 14}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep in fertile soil and thin to 10–14 in; endive has a long growing season and benefits from cool temperatures during head development. Blanch curly endive (frisée) by tying outer leaves over the heart for 10 days before harvest to reduce bitterness. Harvest by cutting the whole head at soil level once it feels firm and the inner leaves are pale and well-formed. Light frost improves flavor by reducing bitterness slightly.", "sources": ["general horticultural reference"]}')
