INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('escarole','Escarole','Cichorium endivia var. latifolium','vegetable','leafy green',5,9,50,75,85,100,'seed','direct','cool','half-hardy','first_frost',-14,-12,'Sow in midsummer so the broad-leaved head matures in cool fall weather, 12–14 weeks before first frost.',4,9,12,16,10,14,12,16,'full','moderate','Sow seed 1/4 in deep in well-amended soil; escarole forms broad, flat rosettes with broad wavy leaves that are less bitter than curly endive. Blanch by gathering outer leaves and tying them over the center for 10–14 days before harvest to produce a creamy, tender heart. Harvest the full rosette by cutting at the soil line when heads are 12–14 in across. Escarole holds well in the garden through light frosts, which improve its mellow, slightly bitter flavor.','["general horticultural reference"]','{"slug": "escarole", "common_name": "Escarole", "scientific_name": "Cichorium endivia var. latifolium", "category": "vegetable", "subcategory": "leafy green", "days_to_germination": {"min": 5, "max": 9}, "germination_soil_temp_f": {"min": 50, "max": 75}, "days_to_maturity": {"min": 85, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -14, "max": -12}, "note": "Sow in midsummer so the broad-leaved head matures in cool fall weather, 12–14 weeks before first frost."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 12, "max": 16}, "height_in": {"min": 10, "max": 14}, "spread_in": {"min": 12, "max": 16}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep in well-amended soil; escarole forms broad, flat rosettes with broad wavy leaves that are less bitter than curly endive. Blanch by gathering outer leaves and tying them over the center for 10–14 days before harvest to produce a creamy, tender heart. Harvest the full rosette by cutting at the soil line when heads are 12–14 in across. Escarole holds well in the garden through light frosts, which improve its mellow, slightly bitter flavor.", "sources": ["general horticultural reference"]}')
