INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('fava-bean','Fava Bean','Vicia faba','vegetable','legume',7,14,40,75,75,100,'seed','direct','cool','hardy','last_frost',-6,-4,'Direct sow 4–6 weeks before the last spring frost; in mild-winter areas, sow in autumn for a spring harvest.',3,10,6,9,24,60,12,18,'full','moderate','Sow seeds 2 in deep in cool, moist soil; they germinate well even near freezing and are damaged by summer heat. Pinch out the top few inches of growth once the first pods begin to set to discourage black bean aphids, which congregate on tender new shoots. Harvest young pods when about 3 in long for eating whole, or let them fill out for shelling; seeds toughen quickly once they lighten in color. Support tall varieties with stakes and twine as plants approach flowering.','["general horticultural reference"]','{"slug": "fava-bean", "common_name": "Fava Bean", "scientific_name": "Vicia faba", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 75, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Direct sow 4–6 weeks before the last spring frost; in mild-winter areas, sow in autumn for a spring harvest."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 2 in deep in cool, moist soil; they germinate well even near freezing and are damaged by summer heat. Pinch out the top few inches of growth once the first pods begin to set to discourage black bean aphids, which congregate on tender new shoots. Harvest young pods when about 3 in long for eating whole, or let them fill out for shelling; seeds toughen quickly once they lighten in color. Support tall varieties with stakes and twine as plants approach flowering.", "sources": ["general horticultural reference"]}')
