  VALUES ('finger-millet','Finger Millet (Ragi)','Eleusine coracana','vegetable','grain',5,10,65,90,90,130,'seed','direct','warm','tender','last_frost',1,4,'Sow after last frost when soil is warm; finger millet thrives in hot, humid conditions and tolerates mildly acidic or infertile soils.',7,11,6,9,24,48,6,10,'full','moderate','Sow seed 1/4 in deep in prepared rows or broadcast on a firm seedbed, thinning to 6–9 in when plants are 4 in tall; finger millet produces distinctive finger-like seed head rays that are diagnostic and easy to recognize at harvest. The seed turns dark reddish-brown when ripe and the heads curve inward; harvest before birds strip them by cutting the heads at early dough stage and finishing the dry-down on a tarp in the sun. Rub heads between palms to release the very small seeds, which need no hulling; grind into flour (ragi flour) or soak and ferment for traditional beverages. The crop is notably high in calcium and iron compared to other small grains.','["general horticultural reference"]','{"slug": "finger-millet", "common_name": "Finger Millet (Ragi)", "scientific_name": "Eleusine coracana", "category": "vegetable", "subcategory": "grain", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 90}, "days_to_maturity": {"min": 90, "max": 130}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 4}, "note": "Sow after last frost when soil is warm; finger millet thrives in hot, humid conditions and tolerates mildly acidic or infertile soils."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep in prepared rows or broadcast on a firm seedbed, thinning to 6–9 in when plants are 4 in tall; finger millet produces distinctive finger-like seed head rays that are diagnostic and easy to recognize at harvest. The seed turns dark reddish-brown when ripe and the heads curve inward; harvest before birds strip them by cutting the heads at early dough stage and finishing the dry-down on a tarp in the sun. Rub heads between palms to release the very small seeds, which need no hulling; grind into flour (ragi flour) or soak and ferment for traditional beverages. The crop is notably high in calcium and iron compared to other small grains.", "sources": ["general horticultural reference"]}')
