INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('flax-fiber','Flax (Fiber/Linen Type)','Linum usitatissimum','vegetable','fiber',5,10,45,70,90,110,'seed','direct','cool','half-hardy','soil_workable',0,3,'Sow as early as possible in spring; fiber flax must be grown densely to produce long, unbranched stems suitable for linen production.',3,8,1,2,24,40,2,4,'full','moderate','Broadcast fiber flax seed thickly at 80–120 lb/acre (roughly 1 seed per sq in in garden beds) and press 1/4 in into a firm, smooth seedbed; the dense stand forces plants to grow tall and unbranched, producing the long stem fibers needed for linen. Harvest when the lower third of the stem turns yellow — pull plants by the root rather than cutting to preserve fiber length. Ret the pulled bundles in water or on damp grass for 1–2 weeks to break down the pectin binding fibers to the stem, then dry before breaking and scutching. Fiber flax seed can also be eaten as a food flax, though oil and food varieties are typically shorter with more branching.','["general horticultural reference"]','{"slug": "flax-fiber", "common_name": "Flax (Fiber/Linen Type)", "scientific_name": "Linum usitatissimum", "category": "vegetable", "subcategory": "fiber", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 45, "max": 70}, "days_to_maturity": {"min": 90, "max": 110}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 3}, "note": "Sow as early as possible in spring; fiber flax must be grown densely to produce long, unbranched stems suitable for linen production."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 24, "max": 40}, "spread_in": {"min": 2, "max": 4}, "sun": "full", "water": "moderate", "directions": "Broadcast fiber flax seed thickly at 80–120 lb/acre (roughly 1 seed per sq in in garden beds) and press 1/4 in into a firm, smooth seedbed; the dense stand forces plants to grow tall and unbranched, producing the long stem fibers needed for linen. Harvest when the lower third of the stem turns yellow — pull plants by the root rather than cutting to preserve fiber length. Ret the pulled bundles in water or on damp grass for 1–2 weeks to break down the pectin binding fibers to the stem, then dry before breaking and scutching. Fiber flax seed can also be eaten as a food flax, though oil and food varieties are typically shorter with more branching.", "sources": ["general horticultural reference"]}')
