INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('flax-seed','Flax (Oilseed / Linseed)','Linum usitatissimum','vegetable','grain',5,10,40,70,75,100,'seed','direct','cool','half-hardy','last_frost',-4,0,'Sow in early spring up to the last frost date; flax needs cool conditions to germinate and does not tolerate summer heat.',3,9,1,2,18,36,3,6,'full','moderate','Broadcast seed at 25–30 lb per acre (about 1 oz per 40 sq ft) and rake to 1/4 in depth on a firm, weed-free seedbed; flax produces delicate sky-blue flowers that last only a morning and then forms round seed capsules (bolls) that rattle when dry. Harvest entire plants when half the bolls have turned brown and the stems are yellowing, cutting at the base and bundling into sheaves; finish drying upside-down for 10–14 days over a tarp. Thresh by beating sheaves inside a barrel, then winnow and screen; the small, oval, brown or golden seeds store for 1–2 years and are rich in omega-3 fatty acids. Grind seeds just before use for maximum nutrition, as whole seeds pass largely undigested.','["general horticultural reference"]','{"slug": "flax-seed", "common_name": "Flax (Oilseed / Linseed)", "scientific_name": "Linum usitatissimum", "category": "vegetable", "subcategory": "grain", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 40, "max": 70}, "days_to_maturity": {"min": 75, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Sow in early spring up to the last frost date; flax needs cool conditions to germinate and does not tolerate summer heat."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 3, "max": 6}, "sun": "full", "water": "moderate", "directions": "Broadcast seed at 25–30 lb per acre (about 1 oz per 40 sq ft) and rake to 1/4 in depth on a firm, weed-free seedbed; flax produces delicate sky-blue flowers that last only a morning and then forms round seed capsules (bolls) that rattle when dry. Harvest entire plants when half the bolls have turned brown and the stems are yellowing, cutting at the base and bundling into sheaves; finish drying upside-down for 10–14 days over a tarp. Thresh by beating sheaves inside a barrel, then winnow and screen; the small, oval, brown or golden seeds store for 1–2 years and are rich in omega-3 fatty acids. Grind seeds just before use for maximum nutrition, as whole seeds pass largely undigested.", "sources": ["general horticultural reference"]}')
