INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('fresno-pepper','Fresno Pepper','Capsicum annuum','vegetable','fruiting',7,21,70,85,70,85,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after all frost danger passes and soil is above 60°F.',5,11,18,24,24,36,18,24,'full','moderate','Sow 1/4 inch deep in warm mix at 80°F and pot up once seedlings have two true leaves; transplant to the garden after last frost. Fresno peppers resemble jalapeños but are slightly thinner-walled, fruitier in flavor, and ripen from green to bright red, with heat increasing as they mature (2,500–10,000 Scoville units). Harvest green fruits at 70 days for a jalapeño substitute, or ripen fully to red for a sweeter, hotter pepper that is excellent in hot sauces and salsas. Consistent deep watering (rather than frequent shallow watering) produces the best quality fruit and reduces stress-induced heat spikes.','["general horticultural reference"]','{"slug": "fresno-pepper", "common_name": "Fresno Pepper", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 70, "max": 85}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after all frost danger passes and soil is above 60°F."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow 1/4 inch deep in warm mix at 80°F and pot up once seedlings have two true leaves; transplant to the garden after last frost. Fresno peppers resemble jalapeños but are slightly thinner-walled, fruitier in flavor, and ripen from green to bright red, with heat increasing as they mature (2,500–10,000 Scoville units). Harvest green fruits at 70 days for a jalapeño substitute, or ripen fully to red for a sweeter, hotter pepper that is excellent in hot sauces and salsas. Consistent deep watering (rather than frequent shallow watering) produces the best quality fruit and reduces stress-induced heat spikes.", "sources": ["general horticultural reference"]}')
