INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('gai-lan','Gai Lan (Chinese Broccoli)','Brassica oleracea var. alboglabra','vegetable','brassica',5,10,50,80,45,70,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost in spring; start a fall crop by direct sowing 8–10 weeks before first frost.',3,10,8,12,12,24,8,12,'full','moderate','Sow seeds 1/4 inch deep in fertile, well-drained soil amended with compost, and thin to 8–12 inches. Harvest the central flowering shoot when buds are tight and stems are still tender, cutting 6–8 inches down the stalk before any flowers open; leaving a few leaves on the stem encourages multiple side shoots. Keep soil evenly moist and feed with a balanced fertilizer at planting and again at mid-season. Hot weather causes rapid bolting and tough stems, so timing the crop for cool weather is essential.','["general horticultural reference"]','{"slug": "gai-lan", "common_name": "Gai Lan (Chinese Broccoli)", "scientific_name": "Brassica oleracea var. alboglabra", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 50, "max": 80}, "days_to_maturity": {"min": 45, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost in spring; start a fall crop by direct sowing 8–10 weeks before first frost."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in fertile, well-drained soil amended with compost, and thin to 8–12 inches. Harvest the central flowering shoot when buds are tight and stems are still tender, cutting 6–8 inches down the stalk before any flowers open; leaving a few leaves on the stem encourages multiple side shoots. Keep soil evenly moist and feed with a balanced fertilizer at planting and again at mid-season. Hot weather causes rapid bolting and tough stems, so timing the crop for cool weather is essential.", "sources": ["general horticultural reference"]}')
