  VALUES ('sorrel','Garden Sorrel','Rumex acetosa','vegetable','perennial',7,14,50,75,60,90,'seed','direct','perennial','hardy','last_frost',-2,2,'Direct sow around last frost date; established plants return each spring and produce for many years.',3,7,12,18,12,24,12,18,'partial','moderate','Sow seed 1/4 in deep in well-drained soil and thin to 12–18 in; sorrel is a perennial that emerges early in spring and can be one of the first greens harvested each year. Remove flower stalks as they appear to keep the plant in vegetative production and prevent self-seeding. Harvest young, tender leaves 3–4 in long for the mildest lemony flavor; large, older leaves become coarser. Divide clumps every 3–4 years to rejuvenate the plant and control its spread.','["general horticultural reference"]','{"slug": "sorrel", "common_name": "Garden Sorrel", "scientific_name": "Rumex acetosa", "category": "vegetable", "subcategory": "perennial", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 50, "max": 75}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Direct sow around last frost date; established plants return each spring and produce for many years."}, "usda_zones": {"min": 3, "max": 7}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "moderate", "directions": "Sow seed 1/4 in deep in well-drained soil and thin to 12–18 in; sorrel is a perennial that emerges early in spring and can be one of the first greens harvested each year. Remove flower stalks as they appear to keep the plant in vegetative production and prevent self-seeding. Harvest young, tender leaves 3–4 in long for the mildest lemony flavor; large, older leaves become coarser. Divide clumps every 3–4 years to rejuvenate the plant and control its spread.", "sources": ["general horticultural reference"]}')
