INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('garlic','Garlic','Allium sativum','vegetable','bulb',NULL,NULL,50,70,240,270,'transplant','bulb','cool','hardy','first_frost',-6,-4,'Plant cloves 4–6 weeks before the ground freezes in autumn so roots establish before winter; spring planting produces smaller bulbs.',3,9,6,8,18,24,4,6,'full','moderate','Break bulbs into individual cloves and plant each 2 in deep, pointed tip up, in well-amended soil enriched with compost; hardneck varieties are better for cold climates while softneck types store longer. Mulch the bed with 4–6 in of straw after the ground freezes to insulate and prevent heaving. Snap off hardneck scapes in early summer to redirect energy to the bulb. Harvest when the lower 4–5 leaves have dried to brown but 5–6 green leaves remain, then cure in a shaded, breezy spot for 3–4 weeks.','["general horticultural reference"]','{"slug": "garlic", "common_name": "Garlic", "scientific_name": "Allium sativum", "category": "vegetable", "subcategory": "bulb", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": 50, "max": 70}, "days_to_maturity": {"min": 240, "max": 270}, "maturity_from": "transplant", "sow_method": "bulb", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Plant cloves 4–6 weeks before the ground freezes in autumn so roots establish before winter; spring planting produces smaller bulbs."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Break bulbs into individual cloves and plant each 2 in deep, pointed tip up, in well-amended soil enriched with compost; hardneck varieties are better for cold climates while softneck types store longer. Mulch the bed with 4–6 in of straw after the ground freezes to insulate and prevent heaving. Snap off hardneck scapes in early summer to redirect energy to the bulb. Harvest when the lower 4–5 leaves have dried to brown but 5–6 green leaves remain, then cure in a shaded, breezy spot for 3–4 weeks.", "sources": ["general horticultural reference"]}')
