INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ghost-pepper','Ghost Pepper (Bhut Jolokia)','Capsicum chinense x Capsicum frutescens','vegetable','fruiting',14,30,80,90,120,150,'transplant','indoor-start','warm','tender','last_frost',-14,-12,'Start indoors 12–14 weeks before last frost to allow enough growing time; transplant only after nights are reliably above 60°F.',9,12,24,36,24,48,18,30,'full','moderate','Sow seeds 1/4 inch deep and maintain a constant soil temperature of 85–90°F; germination is slow and irregular, so start more seeds than needed and be patient. Transplant to a sheltered, heat-retaining bed after all frost danger has passed, and protect young plants from cool nights with row cover. Fruits turn from green to red (or yellow in some strains) at full maturity; wear gloves and avoid touching the face when harvesting, as the heat exceeds one million Scoville units. The extremely long growing season makes this pepper best suited to zones 9–12 or greenhouse culture in cooler regions.','["general horticultural reference"]','{"slug": "ghost-pepper", "common_name": "Ghost Pepper (Bhut Jolokia)", "scientific_name": "Capsicum chinense x Capsicum frutescens", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 80, "max": 90}, "days_to_maturity": {"min": 120, "max": 150}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -14, "max": -12}, "note": "Start indoors 12–14 weeks before last frost to allow enough growing time; transplant only after nights are reliably above 60°F."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep and maintain a constant soil temperature of 85–90°F; germination is slow and irregular, so start more seeds than needed and be patient. Transplant to a sheltered, heat-retaining bed after all frost danger has passed, and protect young plants from cool nights with row cover. Fruits turn from green to red (or yellow in some strains) at full maturity; wear gloves and avoid touching the face when harvesting, as the heat exceeds one million Scoville units. The extremely long growing season makes this pepper best suited to zones 9–12 or greenhouse culture in cooler regions.", "sources": ["general horticultural reference"]}')
