INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ginger','Ginger','Zingiber officinale','vegetable','root',NULL,NULL,70,85,150,240,'transplant','tuber','warm','tender','last_frost',-4,-2,'Start rhizome pieces indoors 4–6 weeks before last frost; move outside only after all danger of frost has passed and temperatures are consistently warm.',8,12,8,12,24,48,12,18,'partial','high','Break fresh ginger rhizomes into 1–2 in pieces each with a visible growth bud and pre-sprout them in a warm, moist environment for 2–3 weeks before planting 2 in deep in rich, moisture-retentive soil. Ginger thrives in dappled shade and resents direct afternoon sun in hot climates. Keep soil consistently moist and avoid letting it dry out. Harvest young ginger in as little as 4–5 months for milder flavor, or leave in the ground until foliage yellows for full-size, more pungent roots.','["general horticultural reference"]','{"slug": "ginger", "common_name": "Ginger", "scientific_name": "Zingiber officinale", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": null, "max": null}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 150, "max": 240}, "maturity_from": "transplant", "sow_method": "tuber", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Start rhizome pieces indoors 4–6 weeks before last frost; move outside only after all danger of frost has passed and temperatures are consistently warm."}, "usda_zones": {"min": 8, "max": 12}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 12, "max": 18}, "sun": "partial", "water": "high", "directions": "Break fresh ginger rhizomes into 1–2 in pieces each with a visible growth bud and pre-sprout them in a warm, moist environment for 2–3 weeks before planting 2 in deep in rich, moisture-retentive soil. Ginger thrives in dappled shade and resents direct afternoon sun in hot climates. Keep soil consistently moist and avoid letting it dry out. Harvest young ginger in as little as 4–5 months for milder flavor, or leave in the ground until foliage yellows for full-size, more pungent roots.", "sources": ["general horticultural reference"]}')
