INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('grain-amaranth','Grain Amaranth','Amaranthus hypochondriacus','vegetable','pseudograin',5,10,65,85,90,120,'seed','direct','warm','tender','last_frost',1,4,'Sow after last frost when soil is warm; grain amaranth thrives in hot weather and tolerates drought and poor soil better than most grains.',4,11,12,18,48,84,12,18,'full','low','Surface-sow or barely cover seed 1/8 in deep, then thin to 12–18 in when seedlings are 2 in tall; amaranth seed is tiny and germinates readily in warm soil but competing weeds must be controlled in the first 3 weeks before the plant takes over. The tall, dramatic seed heads ripen from the bottom up — harvest when the top of the panicle begins to dry and seed crumbles easily when pinched. Cut heads into a bag or over a tarp, dry for 1–2 weeks, then thresh and winnow; a single plant can yield 1/4–1/2 lb of seed. Grain amaranth seed is gluten-free and high in lysine, making it nutritionally complementary to corn or wheat.','["general horticultural reference"]','{"slug": "grain-amaranth", "common_name": "Grain Amaranth", "scientific_name": "Amaranthus hypochondriacus", "category": "vegetable", "subcategory": "pseudograin", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 4}, "note": "Sow after last frost when soil is warm; grain amaranth thrives in hot weather and tolerates drought and poor soil better than most grains."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 48, "max": 84}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Surface-sow or barely cover seed 1/8 in deep, then thin to 12–18 in when seedlings are 2 in tall; amaranth seed is tiny and germinates readily in warm soil but competing weeds must be controlled in the first 3 weeks before the plant takes over. The tall, dramatic seed heads ripen from the bottom up — harvest when the top of the panicle begins to dry and seed crumbles easily when pinched. Cut heads into a bag or over a tarp, dry for 1–2 weeks, then thresh and winnow; a single plant can yield 1/4–1/2 lb of seed. Grain amaranth seed is gluten-free and high in lysine, making it nutritionally complementary to corn or wheat.", "sources": ["general horticultural reference"]}')
