INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sorghum-grain','Grain Sorghum (Milo)','Sorghum bicolor','vegetable','grain',5,10,60,95,90,130,'seed','direct','warm','tender','last_frost',1,4,'Sow after last frost when soil is reliably above 60°F; grain sorghum needs a long, warm season but withstands drought far better than corn.',5,10,6,12,36,72,8,12,'full','low','Drill seed 1/2 in deep in rows 24–30 in apart, thinning to 6–8 in within the row once plants are established; grain sorghum stalls visibly during drought but resumes growth when moisture returns, unlike corn which suffers permanent yield loss. The compact seed heads (panicles) are ready to harvest when seeds dent and the plant begins to dry down naturally, roughly 30 days after bloom. Cut heads by hand into bags or combine at low cylinder speed to avoid shattering; dry grain to 13% moisture or less before storage. Whole sorghum grain is gluten-free and can be popped like popcorn or ground into flour.','["general horticultural reference"]','{"slug": "sorghum-grain", "common_name": "Grain Sorghum (Milo)", "scientific_name": "Sorghum bicolor", "category": "vegetable", "subcategory": "grain", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 60, "max": 95}, "days_to_maturity": {"min": 90, "max": 130}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 4}, "note": "Sow after last frost when soil is reliably above 60°F; grain sorghum needs a long, warm season but withstands drought far better than corn."}, "usda_zones": {"min": 5, "max": 10}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "low", "directions": "Drill seed 1/2 in deep in rows 24–30 in apart, thinning to 6–8 in within the row once plants are established; grain sorghum stalls visibly during drought but resumes growth when moisture returns, unlike corn which suffers permanent yield loss. The compact seed heads (panicles) are ready to harvest when seeds dent and the plant begins to dry down naturally, roughly 30 days after bloom. Cut heads by hand into bags or combine at low cylinder speed to avoid shattering; dry grain to 13% moisture or less before storage. Whole sorghum grain is gluten-free and can be popped like popcorn or ground into flour.", "sources": ["general horticultural reference"]}')
