INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ground-cherry','Ground Cherry','Physalis pruinosa','vegetable','fruiting',7,14,70,80,70,90,'transplant','indoor-start','warm','tender','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; transplant after all frost danger has passed.',4,10,18,24,18,36,18,30,'full','moderate','Sow seeds shallowly, just 1/8 inch deep, in warm starting mix 6–8 weeks before the last frost. Transplant to the garden once nighttime temperatures stay above 50°F and provide moderate, consistent moisture. Fruits drop to the ground when ripe, so check beneath the plants frequently once husks begin to dry and turn tan. The papery husk protects fallen fruit and allows it to keep for several weeks at room temperature.','["general horticultural reference"]','{"slug": "ground-cherry", "common_name": "Ground Cherry", "scientific_name": "Physalis pruinosa", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 80}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; transplant after all frost danger has passed."}, "usda_zones": {"min": 4, "max": 10}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "moderate", "directions": "Sow seeds shallowly, just 1/8 inch deep, in warm starting mix 6–8 weeks before the last frost. Transplant to the garden once nighttime temperatures stay above 50°F and provide moderate, consistent moisture. Fruits drop to the ground when ripe, so check beneath the plants frequently once husks begin to dry and turn tan. The papery husk protects fallen fruit and allows it to keep for several weeks at room temperature.", "sources": ["general horticultural reference"]}')
