INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('guajillo-pepper','Guajillo Pepper','Capsicum annuum','vegetable','fruiting',8,14,75,85,85,100,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed into warm, well-drained soil.',5,11,18,24,24,48,18,24,'full','moderate','Sow seeds 1/4 inch deep in warm starting mix at 80°F and maintain consistent warmth until transplanting time. Plants grow tall and may benefit from staking; set into fertile, well-drained soil after last frost and side-dress with a balanced fertilizer when flowering begins. Long, narrow pods ripen from green to dark glossy red and must be fully dried for authentic guajillo chile flavor — harvest red ripe pods and dry in a food dehydrator or warm oven. The dried pods develop a distinctive tangy, berry-like flavor essential in Mexican mole and enchilada sauces.','["general horticultural reference"]','{"slug": "guajillo-pepper", "common_name": "Guajillo Pepper", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 8, "max": 14}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 85, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed into warm, well-drained soil."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm starting mix at 80°F and maintain consistent warmth until transplanting time. Plants grow tall and may benefit from staking; set into fertile, well-drained soil after last frost and side-dress with a balanced fertilizer when flowering begins. Long, narrow pods ripen from green to dark glossy red and must be fully dried for authentic guajillo chile flavor — harvest red ripe pods and dry in a food dehydrator or warm oven. The dried pods develop a distinctive tangy, berry-like flavor essential in Mexican mole and enchilada sauces.", "sources": ["general horticultural reference"]}')
