  VALUES ('habanero','Habanero Pepper','Capsicum chinense','vegetable','fruiting',10,21,80,90,90,120,'transplant','indoor-start','warm','tender','last_frost',-12,-10,'Start indoors 10–12 weeks before last frost due to the long growing season; transplant 2 weeks after all frost danger has passed.',5,12,18,24,18,36,18,24,'full','moderate','Sow seeds 1/4 inch deep and maintain soil temperature at 85–90°F to achieve reliable germination, as Capsicum chinense species are notably slow to sprout. Transplant into the warmest, most sheltered spot in the garden once conditions are fully settled. Consistent feeding with a potassium-rich fertilizer during fruiting will maximize yields. Harvest when fruits reach their characteristic orange or red color and feel firm; handle with gloves due to extreme capsaicin levels.','["general horticultural reference"]','{"slug": "habanero", "common_name": "Habanero Pepper", "scientific_name": "Capsicum chinense", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 80, "max": 90}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -12, "max": -10}, "note": "Start indoors 10–12 weeks before last frost due to the long growing season; transplant 2 weeks after all frost danger has passed."}, "usda_zones": {"min": 5, "max": 12}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep and maintain soil temperature at 85–90°F to achieve reliable germination, as Capsicum chinense species are notably slow to sprout. Transplant into the warmest, most sheltered spot in the garden once conditions are fully settled. Consistent feeding with a potassium-rich fertilizer during fruiting will maximize yields. Harvest when fruits reach their characteristic orange or red color and feel firm; handle with gloves due to extreme capsaicin levels.", "sources": ["general horticultural reference"]}')
