INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('hamburg-parsley','Hamburg Parsley (Root Parsley)','Petroselinum crispum var. tuberosum','vegetable','root',14,28,50,70,90,120,'seed','direct','cool','hardy','soil_workable',0,4,'Direct sow as soon as soil can be worked in spring; the long growing season requires an early start and the slow germination period means pre-soaking seeds is beneficial.',3,9,6,8,12,24,9,12,'full','moderate','Soak seeds in warm water for 24 hours before sowing to improve germination; sow 1/4 inch deep in deeply loosened, stone-free soil in rows, as seeds germinate slowly and unevenly over 2–4 weeks. Thin seedlings to 6–8 inches apart once established; the flat-leaf parsley-like foliage is edible throughout the season as an herb. The ivory-white, parsnip-like root develops slowly all season and tastes like a concentrated, slightly sweet parsley-parsnip hybrid — exceptional in Central European soups and stews. Harvest in fall after light frost improves sweetness; roots left in the ground over winter in milder climates will re-sprout in spring but roots lose quality as the plant prepares to bolt.','["general horticultural reference"]','{"slug": "hamburg-parsley", "common_name": "Hamburg Parsley (Root Parsley)", "scientific_name": "Petroselinum crispum var. tuberosum", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 50, "max": 70}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Direct sow as soon as soil can be worked in spring; the long growing season requires an early start and the slow germination period means pre-soaking seeds is beneficial."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "moderate", "directions": "Soak seeds in warm water for 24 hours before sowing to improve germination; sow 1/4 inch deep in deeply loosened, stone-free soil in rows, as seeds germinate slowly and unevenly over 2–4 weeks. Thin seedlings to 6–8 inches apart once established; the flat-leaf parsley-like foliage is edible throughout the season as an herb. The ivory-white, parsnip-like root develops slowly all season and tastes like a concentrated, slightly sweet parsley-parsnip hybrid — exceptional in Central European soups and stews. Harvest in fall after light frost improves sweetness; roots left in the ground over winter in milder climates will re-sprout in spring but roots lose quality as the plant prepares to bolt.", "sources": ["general horticultural reference"]}')
