INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('hemp-seed','Hemp (Grain/Seed)','Cannabis sativa','vegetable','oilseed',3,7,46,77,70,110,'seed','direct','warm','half-hardy','last_frost',0,2,'Sow at or just after last frost; hemp grows very quickly and tolerates light frost at seedling stage but is damaged by hard freezes.',4,9,4,8,36,96,6,14,'full','moderate','Drill seed 3/4–1 in deep at 20–30 lb/acre for grain production (denser stands reduce branching and improve yield); hemp requires a federal or state license to grow legally in the United States. Plants are dioecious — female plants produce the seed-bearing flowers; for grain production allow plants to go naturally to seed and harvest when seeds are firm and no longer milky. Thresh and dry seed to below 10% moisture for storage; hulled hemp seed (hearts) is nutritionally rich in protein and balanced omega-3/6 fatty acids. Do not confuse grain hemp with high-THC varieties; certified grain cultivars contain less than 0.3% THC.','["general horticultural reference"]','{"slug": "hemp-seed", "common_name": "Hemp (Grain/Seed)", "scientific_name": "Cannabis sativa", "category": "vegetable", "subcategory": "oilseed", "days_to_germination": {"min": 3, "max": 7}, "germination_soil_temp_f": {"min": 46, "max": 77}, "days_to_maturity": {"min": 70, "max": 110}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Sow at or just after last frost; hemp grows very quickly and tolerates light frost at seedling stage but is damaged by hard freezes."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 4, "max": 8}, "height_in": {"min": 36, "max": 96}, "spread_in": {"min": 6, "max": 14}, "sun": "full", "water": "moderate", "directions": "Drill seed 3/4–1 in deep at 20–30 lb/acre for grain production (denser stands reduce branching and improve yield); hemp requires a federal or state license to grow legally in the United States. Plants are dioecious — female plants produce the seed-bearing flowers; for grain production allow plants to go naturally to seed and harvest when seeds are firm and no longer milky. Thresh and dry seed to below 10% moisture for storage; hulled hemp seed (hearts) is nutritionally rich in protein and balanced omega-3/6 fatty acids. Do not confuse grain hemp with high-THC varieties; certified grain cultivars contain less than 0.3% THC.", "sources": ["general horticultural reference"]}')
