INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('hubbard-squash','Hubbard Squash','Cucurbita maxima','vegetable','cucurbit',4,10,65,95,90,110,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost once soil has warmed to 65°F; Hubbard requires a long, warm season so time carefully against fall frost dates.',3,10,48,72,12,18,96,144,'full','moderate','Plant 3–4 seeds 1 inch deep per hill in deeply worked, fertile soil, thinning to two vines after establishment. Hubbard squash produces very large, warty fruits with a hard blue-gray or orange shell and very sweet, dry, fine-grained flesh ideal for pie and soup. Allow vines to spread freely over 8–12 feet of ground, or train onto a very strong trellis and support individual fruits in slings. Fruits are ripe when the rind resists a fingernail, the skin has turned its characteristic color, and the stem is fully dry; cure for two weeks before storing.','["general horticultural reference"]','{"slug": "hubbard-squash", "common_name": "Hubbard Squash", "scientific_name": "Cucurbita maxima", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 95}, "days_to_maturity": {"min": 90, "max": 110}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost once soil has warmed to 65°F; Hubbard requires a long, warm season so time carefully against fall frost dates."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 48, "max": 72}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 96, "max": 144}, "sun": "full", "water": "moderate", "directions": "Plant 3–4 seeds 1 inch deep per hill in deeply worked, fertile soil, thinning to two vines after establishment. Hubbard squash produces very large, warty fruits with a hard blue-gray or orange shell and very sweet, dry, fine-grained flesh ideal for pie and soup. Allow vines to spread freely over 8–12 feet of ground, or train onto a very strong trellis and support individual fruits in slings. Fruits are ripe when the rind resists a fingernail, the skin has turned its characteristic color, and the stem is fully dry; cure for two weeks before storing.", "sources": ["general horticultural reference"]}')
