INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('hungarian-wax-pepper','Hungarian Wax Pepper','Capsicum annuum','vegetable','fruiting',7,21,70,85,65,80,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant 1–2 weeks after frost danger passes once nights are consistently above 50°F.',5,11,18,24,24,36,18,24,'full','moderate','Sow seeds 1/4 inch deep in warm mix maintained at 78–82°F; germination is fastest and most even with bottom heat from a heat mat. Hungarian wax peppers produce thick-walled, banana-shaped fruits that ripen from pale yellow through orange to red; they range from mildly hot (1,000 Scoville) when yellow to moderately hot when fully red. Harvest yellow fruits at 65 days for pickling (the classic use), or allow to ripen through the color stages for fresh eating and sauces. Plants are heavy producers and benefit from a midseason application of balanced fertilizer to sustain yield.','["general horticultural reference"]','{"slug": "hungarian-wax-pepper", "common_name": "Hungarian Wax Pepper", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 65, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant 1–2 weeks after frost danger passes once nights are consistently above 50°F."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm mix maintained at 78–82°F; germination is fastest and most even with bottom heat from a heat mat. Hungarian wax peppers produce thick-walled, banana-shaped fruits that ripen from pale yellow through orange to red; they range from mildly hot (1,000 Scoville) when yellow to moderately hot when fully red. Harvest yellow fruits at 65 days for pickling (the classic use), or allow to ripen through the color stages for fresh eating and sauces. Plants are heavy producers and benefit from a midseason application of balanced fertilizer to sustain yield.", "sources": ["general horticultural reference"]}')
