  VALUES ('jicama','Jicama','Pachyrhizus erosus','vegetable','root',14,21,75,85,150,210,'seed','direct','warm','tender','last_frost',2,4,'Sow 2–4 weeks after last frost into warm soil; jicama needs a long frost-free season of at least 5 months and thrives in zone 9–11 Gulf Coast conditions.',9,11,12,18,60,120,12,24,'full','moderate','Sow scarified seeds 1 in deep in loose, deep, well-drained soil 2–4 weeks after the last frost once soil is thoroughly warm. Jicama is a vigorous vine requiring a sturdy trellis; pinch flower buds as they appear throughout the season — leaving flowers reduces tuber size dramatically since the plant diverts energy to seed set. Begin harvesting small tubers at about 5 months; larger tubers become more fibrous if left past 9 months. Only the roots are edible — all above-ground parts, including seeds and pods, contain rotenone and are toxic.','["Texas A&M AgriLife Extension Service", "general horticultural reference"]','{"slug": "jicama", "common_name": "Jicama", "scientific_name": "Pachyrhizus erosus", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 150, "max": 210}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 4}, "note": "Sow 2–4 weeks after last frost into warm soil; jicama needs a long frost-free season of at least 5 months and thrives in zone 9–11 Gulf Coast conditions."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 60, "max": 120}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow scarified seeds 1 in deep in loose, deep, well-drained soil 2–4 weeks after the last frost once soil is thoroughly warm. Jicama is a vigorous vine requiring a sturdy trellis; pinch flower buds as they appear throughout the season — leaving flowers reduces tuber size dramatically since the plant diverts energy to seed set. Begin harvesting small tubers at about 5 months; larger tubers become more fibrous if left past 9 months. Only the roots are edible — all above-ground parts, including seeds and pods, contain rotenone and are toxic.", "sources": ["Texas A&M AgriLife Extension Service", "general horticultural reference"]}')
