INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('yam-bean','Jicama (Yam Bean)','Pachyrhizus erosus','vegetable','root',7,14,70,85,150,180,'seed','direct','warm','tender','last_frost',2,4,'Sow after last frost when soil is warm; jicama requires a long, frost-free season of at least 5 months to form substantial roots.',9,12,12,18,24,60,24,48,'full','moderate','Sow seeds 1 in deep in warm, well-drained soil after soaking them overnight to speed germination. Remove all flower buds as they appear throughout the season; allowing flowering diverts energy from root development and shortens the season significantly. Vines can climb and should be trellised or allowed to sprawl; note that all aerial parts of the plant (seeds, pods, leaves) are toxic — only the root is edible. Harvest roots after the first cool weather of autumn when skins turn tan and cork-like.','["general horticultural reference"]','{"slug": "yam-bean", "common_name": "Jicama (Yam Bean)", "scientific_name": "Pachyrhizus erosus", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 150, "max": 180}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 4}, "note": "Sow after last frost when soil is warm; jicama requires a long, frost-free season of at least 5 months to form substantial roots."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 24, "max": 48}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 in deep in warm, well-drained soil after soaking them overnight to speed germination. Remove all flower buds as they appear throughout the season; allowing flowering diverts energy from root development and shortens the season significantly. Vines can climb and should be trellised or allowed to sprawl; note that all aerial parts of the plant (seeds, pods, leaves) are toxic — only the root is edible. Harvest roots after the first cool weather of autumn when skins turn tan and cork-like.", "sources": ["general horticultural reference"]}')
