INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('jimmy-nardello','Jimmy Nardello''s Sweet Frying Pepper','Capsicum annuum','vegetable','fruiting',8,14,70,85,80,90,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant 2 weeks after frost danger has passed once soil is warm.',4,11,18,24,24,36,18,24,'full','moderate','Sow seeds 1/4 inch deep in warm starting mix at 75–80°F and transplant after last frost into fertile, well-drained soil. This Italian heirloom from Basilicata bears long, thin-walled, crinkled fruits that dangle in clusters and turn from green to brilliant red at maturity. The fruits are nearly heat-free and intensely sweet, making them outstanding for frying in olive oil, roasting, or drying. Harvest when fully red for peak sweetness, or dry on a string in a warm, airy location — the thin walls dehydrate rapidly and concentrate flavor.','["Slow Food Ark of Taste", "general horticultural reference"]','{"slug": "jimmy-nardello", "common_name": "Jimmy Nardello''s Sweet Frying Pepper", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 8, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 80, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant 2 weeks after frost danger has passed once soil is warm."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm starting mix at 75–80°F and transplant after last frost into fertile, well-drained soil. This Italian heirloom from Basilicata bears long, thin-walled, crinkled fruits that dangle in clusters and turn from green to brilliant red at maturity. The fruits are nearly heat-free and intensely sweet, making them outstanding for frying in olive oil, roasting, or drying. Harvest when fully red for peak sweetness, or dry on a string in a warm, airy location — the thin walls dehydrate rapidly and concentrate flavor.", "sources": ["Slow Food Ark of Taste", "general horticultural reference"]}')
