INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('kabocha-squash','Kabocha Squash','Cucurbita maxima','vegetable','cucurbit',4,10,65,95,85,100,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost once soil temperature reaches 65°F; count back from first fall frost to confirm enough growing days.',3,10,36,60,12,18,72,120,'full','moderate','Sow 2–3 seeds 1 inch deep per hill in deeply amended, compost-rich soil and thin to the strongest vine after the first true leaves appear. Kabocha is a Japanese winter squash of the Cucurbita maxima species; its flattened, dark-green fruits have dense, dry, sweet orange flesh superior to many other squash types. Harvest when the skin is very hard, the stem corky and dry, and a small section of rind scratched with a fingernail shows no damage. Cure at room temperature for 10–14 days before storing; properly cured kabocha keeps four to six months in a cool, dry room.','["general horticultural reference"]','{"slug": "kabocha-squash", "common_name": "Kabocha Squash", "scientific_name": "Cucurbita maxima", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 95}, "days_to_maturity": {"min": 85, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost once soil temperature reaches 65°F; count back from first fall frost to confirm enough growing days."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 72, "max": 120}, "sun": "full", "water": "moderate", "directions": "Sow 2–3 seeds 1 inch deep per hill in deeply amended, compost-rich soil and thin to the strongest vine after the first true leaves appear. Kabocha is a Japanese winter squash of the Cucurbita maxima species; its flattened, dark-green fruits have dense, dry, sweet orange flesh superior to many other squash types. Harvest when the skin is very hard, the stem corky and dry, and a small section of rind scratched with a fingernail shows no damage. Cure at room temperature for 10–14 days before storing; properly cured kabocha keeps four to six months in a cool, dry room.", "sources": ["general horticultural reference"]}')
