INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('kale','Kale','Brassica oleracea var. sabellica','vegetable','brassica',5,10,45,85,50,70,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow or transplant 2–4 weeks before last frost in spring; sow again in late summer for a fall and overwintering crop.',3,11,12,18,12,36,12,24,'full','moderate','Sow seed 1/4 in deep and thin to 12–18 in; kale tolerates crowding better than most brassicas but produces larger leaves with proper spacing. Side-dress with compost or a nitrogen fertilizer midseason to support continued leaf production. Harvest outer leaves first, leaving the growing center intact to keep the plant producing. Flavor becomes noticeably sweeter after the first hard frost, and plants often survive winter in zones 7 and warmer.','["general horticultural reference"]','{"slug": "kale", "common_name": "Kale", "scientific_name": "Brassica oleracea var. sabellica", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow or transplant 2–4 weeks before last frost in spring; sow again in late summer for a fall and overwintering crop."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 12, "max": 36}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep and thin to 12–18 in; kale tolerates crowding better than most brassicas but produces larger leaves with proper spacing. Side-dress with compost or a nitrogen fertilizer midseason to support continued leaf production. Harvest outer leaves first, leaving the growing center intact to keep the plant producing. Flavor becomes noticeably sweeter after the first hard frost, and plants often survive winter in zones 7 and warmer.", "sources": ["general horticultural reference"]}')
