INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('kenaf','Kenaf','Hibiscus cannabinus','vegetable','fiber',7,14,60,95,90,140,'seed','direct','warm','tender','last_frost',1,4,'Sow after last frost in warm soil; kenaf grows tall rapidly and is grown for bast fiber, animal fodder, and paper pulp.',8,11,4,8,72,180,8,18,'full','moderate','Direct-sow seed 1/2–1 in deep at 25–30 lb/acre for fiber production (narrower spacing promotes taller, less branched stems); kenaf is a warm-season annual related to okra that can reach 14 feet in a single season. For fiber, harvest at early flowering before stems become too woody — cut at ground level and ret the stalks in water for 10–20 days to separate the long bast fibers from the woody core. The core material (hurds) is useful as animal bedding or biomass fuel, while the bast fibers make durable rope, sacking, and paper. Young leaves and shoots are edible and nutritious — commonly cooked as a green in West African cuisine.','["general horticultural reference"]','{"slug": "kenaf", "common_name": "Kenaf", "scientific_name": "Hibiscus cannabinus", "category": "vegetable", "subcategory": "fiber", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 95}, "days_to_maturity": {"min": 90, "max": 140}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 4}, "note": "Sow after last frost in warm soil; kenaf grows tall rapidly and is grown for bast fiber, animal fodder, and paper pulp."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 4, "max": 8}, "height_in": {"min": 72, "max": 180}, "spread_in": {"min": 8, "max": 18}, "sun": "full", "water": "moderate", "directions": "Direct-sow seed 1/2–1 in deep at 25–30 lb/acre for fiber production (narrower spacing promotes taller, less branched stems); kenaf is a warm-season annual related to okra that can reach 14 feet in a single season. For fiber, harvest at early flowering before stems become too woody — cut at ground level and ret the stalks in water for 10–20 days to separate the long bast fibers from the woody core. The core material (hurds) is useful as animal bedding or biomass fuel, while the bast fibers make durable rope, sacking, and paper. Young leaves and shoots are edible and nutritious — commonly cooked as a green in West African cuisine.", "sources": ["general horticultural reference"]}')
