  VALUES ('kohlrabi','Kohlrabi','Brassica oleracea var. gongylodes','vegetable','brassica',5,10,45,85,45,60,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last spring frost, or sow in late summer for a fall crop.',3,10,5,8,12,18,6,10,'full','moderate','Direct sow seed 1/4 in deep in cool, fertile soil and thin plants to 5–8 in to give the swollen stem room to develop. Keep soil consistently moist, as drought stress causes the bulb to become woody and strongly flavored. Harvest when the swollen stem is 2–3 in across for best tenderness; larger bulbs become fibrous. Pull the whole plant and trim the leaves before storing in the refrigerator.','["general horticultural reference"]','{"slug": "kohlrabi", "common_name": "Kohlrabi", "scientific_name": "Brassica oleracea var. gongylodes", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 45, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last spring frost, or sow in late summer for a fall crop."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 5, "max": 8}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Direct sow seed 1/4 in deep in cool, fertile soil and thin plants to 5–8 in to give the swollen stem room to develop. Keep soil consistently moist, as drought stress causes the bulb to become woody and strongly flavored. Harvest when the swollen stem is 2–3 in across for best tenderness; larger bulbs become fibrous. Pull the whole plant and trim the leaves before storing in the refrigerator.", "sources": ["general horticultural reference"]}')
