  VALUES ('komatsuna','Komatsuna (Japanese Mustard Spinach)','Brassica rapa var. perviridis','vegetable','brassica',4,7,45,80,30,45,'seed','direct','cool','hardy','last_frost',-4,-2,'Sow 2–4 weeks before last frost in spring, or 6–8 weeks before first fall frost; succession sow every 2–3 weeks.',3,11,4,8,8,14,4,8,'full','moderate','Sow seeds 1/4 inch deep, thinning to 4 inches for baby greens or 8 inches for full-sized plants. Komatsuna is one of the most versatile Asian brassicas — milder than mustard, more heat-tolerant than spinach, and remarkably cold-hardy. Begin harvesting at 30 days for tender salad leaves, or allow plants to reach full size at 8–14 inches for stir-frying and braising. Water consistently to keep leaves mild and succulent.','["general horticultural reference"]','{"slug": "komatsuna", "common_name": "Komatsuna (Japanese Mustard Spinach)", "scientific_name": "Brassica rapa var. perviridis", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 45, "max": 80}, "days_to_maturity": {"min": 30, "max": 45}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Sow 2–4 weeks before last frost in spring, or 6–8 weeks before first fall frost; succession sow every 2–3 weeks."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 4, "max": 8}, "height_in": {"min": 8, "max": 14}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep, thinning to 4 inches for baby greens or 8 inches for full-sized plants. Komatsuna is one of the most versatile Asian brassicas — milder than mustard, more heat-tolerant than spinach, and remarkably cold-hardy. Begin harvesting at 30 days for tender salad leaves, or allow plants to reach full size at 8–14 inches for stir-frying and braising. Water consistently to keep leaves mild and succulent.", "sources": ["general horticultural reference"]}')
