INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lentil','Lentil','Lens culinaris','vegetable','legume',7,14,45,70,80,110,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; lentils prefer cool growing conditions and deteriorate in summer heat.',3,9,2,4,18,24,6,10,'full','low','Sow seeds 1 in deep in rows 18 in apart in well-drained, moderately fertile soil; avoid high-nitrogen fertilizers that delay podding. The slender, branching plants benefit from brushy twigs as supports to keep pods off the ground and improve air circulation. Harvest the entire plant when the majority of lower pods have turned tan but before they shatter. Thresh by beating dried plants on a tarp and winnow lightly to clean seed before storage.','["general horticultural reference"]','{"slug": "lentil", "common_name": "Lentil", "scientific_name": "Lens culinaris", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 45, "max": 70}, "days_to_maturity": {"min": 80, "max": 110}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; lentils prefer cool growing conditions and deteriorate in summer heat."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 2, "max": 4}, "height_in": {"min": 18, "max": 24}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "low", "directions": "Sow seeds 1 in deep in rows 18 in apart in well-drained, moderately fertile soil; avoid high-nitrogen fertilizers that delay podding. The slender, branching plants benefit from brushy twigs as supports to keep pods off the ground and improve air circulation. Harvest the entire plant when the majority of lower pods have turned tan but before they shatter. Thresh by beating dried plants on a tarp and winnow lightly to clean seed before storage.", "sources": ["general horticultural reference"]}')
