INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lima-bean','Lima Bean','Phaseolus lunatus','vegetable','legume',7,18,65,85,65,90,'seed','direct','warm','tender','last_frost',2,3,'Sow 2–3 weeks after last frost; lima beans demand warm soil and will rot in cold, wet ground.',3,11,6,8,18,30,12,18,'full','moderate','Sow seeds 1 to 1.5 in deep in loose, warm soil with the eye of the bean facing downward. Lima beans are sensitive to drought during flowering; irregular moisture can cause blossom drop and reduced pod set. For fresh shell use, harvest pods when they are bright green and plump but before they begin to fade or yellow. Allow pods to dry completely on the vine for dry bean storage.','["general horticultural reference"]','{"slug": "lima-bean", "common_name": "Lima Bean", "scientific_name": "Phaseolus lunatus", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 18}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 65, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 3}, "note": "Sow 2–3 weeks after last frost; lima beans demand warm soil and will rot in cold, wet ground."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 to 1.5 in deep in loose, warm soil with the eye of the bean facing downward. Lima beans are sensitive to drought during flowering; irregular moisture can cause blossom drop and reduced pod set. For fresh shell use, harvest pods when they are bright green and plump but before they begin to fade or yellow. Allow pods to dry completely on the vine for dry bean storage.", "sources": ["general horticultural reference"]}')
