INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('lotus-root','Lotus Root','Nelumbo nucifera','vegetable','root',NULL,NULL,65,85,150,210,'transplant','tuber','warm','hardy','last_frost',0,4,'Plant rhizome sections in still or slow-moving water 1–2 feet deep after last frost when water temperature stays above 65°F.',5,11,36,60,36,60,36,72,'full','high','Plant intact rhizome sections (with at least one growing tip) horizontally in the mud bottom of a pond, tub, or container submerged under 12–18 inches of still water; never allow the growing tip to dry out. Full sun is essential — lotus will produce only foliage and few flowers in shade. Harvest rhizomes in fall once foliage dies back by reaching into the mud and carefully pulling out the chain of large, starchy sections; the distinctive lacy, hole-patterned cross-section is a signature feature. Rhizomes must be cooked before eating; they are eaten stir-fried, pickled, or braised throughout East and Southeast Asia and have a crunchy texture even after cooking.','["general horticultural reference"]','{"slug": "lotus-root", "common_name": "Lotus Root", "scientific_name": "Nelumbo nucifera", "category": "vegetable", "subcategory": "root", "days_to_germination": null, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 150, "max": 210}, "maturity_from": "transplant", "sow_method": "tuber", "season": "warm", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant rhizome sections in still or slow-moving water 1–2 feet deep after last frost when water temperature stays above 65°F."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 36, "max": 72}, "sun": "full", "water": "high", "directions": "Plant intact rhizome sections (with at least one growing tip) horizontally in the mud bottom of a pond, tub, or container submerged under 12–18 inches of still water; never allow the growing tip to dry out. Full sun is essential — lotus will produce only foliage and few flowers in shade. Harvest rhizomes in fall once foliage dies back by reaching into the mud and carefully pulling out the chain of large, starchy sections; the distinctive lacy, hole-patterned cross-section is a signature feature. Rhizomes must be cooked before eating; they are eaten stir-fried, pickled, or braised throughout East and Southeast Asia and have a crunchy texture even after cooking.", "sources": ["general horticultural reference"]}')
