INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('luffa','Luffa / Sponge Gourd','Luffa aegyptiaca','vegetable','cucurbit',7,14,70,85,90,120,'seed','indoor-start','warm','tender','last_frost',-4,-3,'Start indoors 3–4 weeks before last frost; transplant after all frost danger has passed. Luffa requires a long, hot season.',6,12,12,18,72,144,36,72,'full','moderate','Nick or soak seeds for 24 hours before sowing 1/2 inch deep indoors 3–4 weeks before last frost to give this long-season crop a head start. Provide a very sturdy trellis, as vines can reach 15 feet and carry heavy fruit. For eating, harvest young fruits at 4–6 inches before the fibrous skeleton hardens. For sponges, allow fruits to fully mature and dry on the vine until the skin browns, then soak in water, peel, and rinse out the seeds.','["general horticultural reference"]','{"slug": "luffa", "common_name": "Luffa / Sponge Gourd", "scientific_name": "Luffa aegyptiaca", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -3}, "note": "Start indoors 3–4 weeks before last frost; transplant after all frost danger has passed. Luffa requires a long, hot season."}, "usda_zones": {"min": 6, "max": 12}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 72, "max": 144}, "spread_in": {"min": 36, "max": 72}, "sun": "full", "water": "moderate", "directions": "Nick or soak seeds for 24 hours before sowing 1/2 inch deep indoors 3–4 weeks before last frost to give this long-season crop a head start. Provide a very sturdy trellis, as vines can reach 15 feet and carry heavy fruit. For eating, harvest young fruits at 4–6 inches before the fibrous skeleton hardens. For sponges, allow fruits to fully mature and dry on the vine until the skin browns, then soak in water, peel, and rinse out the seeds.", "sources": ["general horticultural reference"]}')
