  VALUES ('mache','Mache (Corn Salad)','Valerianella locusta','vegetable','leafy green',7,14,40,60,45,60,'seed','direct','cool','hardy','first_frost',-6,-4,'Sow 4–6 weeks before first frost for fall and winter harvest; also sow in very early spring as soon as soil can be worked.',3,9,4,6,4,8,4,6,'partial','moderate','Broadcast or row-sow seed at 1/4 in depth in cool soil and keep moist; mache is extraordinarily cold-tolerant and grows slowly through winter in mild climates. Thin to 4–6 in for well-formed rosettes, though closer spacing produces acceptable baby greens. Harvest entire rosettes by cutting at the soil line, or pinch individual rosettes for salad use. Mache does not tolerate heat and will quickly bolt and disappear as spring temperatures rise; enjoy it as a winter green.','["general horticultural reference"]','{"slug": "mache", "common_name": "Mache (Corn Salad)", "scientific_name": "Valerianella locusta", "category": "vegetable", "subcategory": "leafy green", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 40, "max": 60}, "days_to_maturity": {"min": 45, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Sow 4–6 weeks before first frost for fall and winter harvest; also sow in very early spring as soon as soil can be worked."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 4, "max": 8}, "spread_in": {"min": 4, "max": 6}, "sun": "partial", "water": "moderate", "directions": "Broadcast or row-sow seed at 1/4 in depth in cool soil and keep moist; mache is extraordinarily cold-tolerant and grows slowly through winter in mild climates. Thin to 4–6 in for well-formed rosettes, though closer spacing produces acceptable baby greens. Harvest entire rosettes by cutting at the soil line, or pinch individual rosettes for salad use. Mache does not tolerate heat and will quickly bolt and disappear as spring temperatures rise; enjoy it as a winter green.", "sources": ["general horticultural reference"]}')
