INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('malabar-spinach','Malabar Spinach','Basella alba','vegetable','greens',10,21,65,85,50,70,'transplant','indoor-start','warm','tender','last_frost',-4,0,'Start indoors 4 weeks before last frost; transplant once nights stay above 55°F — the heat-season answer to spinach for zone 8–11 gardens.',9,11,12,18,48,120,12,24,'full','moderate','Soak seeds overnight before sowing to soften the hard seed coat; germination is slow but improves significantly with scarification and warm soil above 70°F. Provide a trellis or fence — the twining vines reach 6–10 feet and produce heavily when they climb. Harvest young leaves and stem tips frequently; the leaves are mucilaginous (similar to okra) and excellent in stir-fries, soups, and anywhere cooked greens are used. The red-stemmed variety (Basella rubra) is slightly more ornamental and equally productive — both tolerate heat and humidity that quickly kills regular spinach.','["general horticultural reference", "University of Florida IFAS Extension"]','{"slug": "malabar-spinach", "common_name": "Malabar Spinach", "scientific_name": "Basella alba", "category": "vegetable", "subcategory": "greens", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": 0}, "note": "Start indoors 4 weeks before last frost; transplant once nights stay above 55°F — the heat-season answer to spinach for zone 8–11 gardens."}, "usda_zones": {"min": 9, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 48, "max": 120}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "moderate", "directions": "Soak seeds overnight before sowing to soften the hard seed coat; germination is slow but improves significantly with scarification and warm soil above 70°F. Provide a trellis or fence — the twining vines reach 6–10 feet and produce heavily when they climb. Harvest young leaves and stem tips frequently; the leaves are mucilaginous (similar to okra) and excellent in stir-fries, soups, and anywhere cooked greens are used. The red-stemmed variety (Basella rubra) is slightly more ornamental and equally productive — both tolerate heat and humidity that quickly kills regular spinach.", "sources": ["general horticultural reference", "University of Florida IFAS Extension"]}')
