INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('miners-lettuce','Miner''s Lettuce','Claytonia perfoliata','vegetable','leafy-green',7,14,40,65,40,50,'seed','direct','cool','hardy','last_frost',-6,-4,'Sow 4–6 weeks before last frost; it prefers cool, moist conditions and will self-sow prolifically if allowed to set seed.',3,10,4,6,4,8,4,6,'partial','moderate','Broadcast seeds over moist soil and press lightly into contact; no covering is needed as seeds germinate best with light. Miner''s lettuce is best sown in partial shade in mild climates, where it will often naturalize and self-sow. The distinctive round, perfoliate leaves (stem appearing to grow through the leaf) are mild and succulent — excellent raw in salads. Harvest whole plants or outer leaves before warm weather triggers bolting, which happens quickly once temperatures exceed 65°F.','["general horticultural reference"]','{"slug": "miners-lettuce", "common_name": "Miner''s Lettuce", "scientific_name": "Claytonia perfoliata", "category": "vegetable", "subcategory": "leafy-green", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 40, "max": 65}, "days_to_maturity": {"min": 40, "max": 50}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Sow 4–6 weeks before last frost; it prefers cool, moist conditions and will self-sow prolifically if allowed to set seed."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 4, "max": 8}, "spread_in": {"min": 4, "max": 6}, "sun": "partial", "water": "moderate", "directions": "Broadcast seeds over moist soil and press lightly into contact; no covering is needed as seeds germinate best with light. Miner''s lettuce is best sown in partial shade in mild climates, where it will often naturalize and self-sow. The distinctive round, perfoliate leaves (stem appearing to grow through the leaf) are mild and succulent — excellent raw in salads. Harvest whole plants or outer leaves before warm weather triggers bolting, which happens quickly once temperatures exceed 65°F.", "sources": ["general horticultural reference"]}')
