INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('mizuna','Mizuna','Brassica rapa var. nipposinica','vegetable','brassica',4,7,45,75,21,40,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost in spring; make a second sowing 6–8 weeks before first fall frost for autumn harvest.',3,11,6,9,8,14,6,10,'full','moderate','Sow seeds 1/4 inch deep in rows or broadcast thinly, thinning to 6–9 inches for full heads or leaving dense for cut-and-come-again baby leaves. Mizuna is extremely fast-growing and bolt-tolerant compared to most brassicas, making it one of the most reliable salad greens for both spring and fall. Begin harvesting outer leaves at 21 days or cut the whole plant an inch above the soil line and allow it to regrow. Consistent moisture promotes tender, mild-flavored leaves; drought causes bitterness.','["general horticultural reference"]','{"slug": "mizuna", "common_name": "Mizuna", "scientific_name": "Brassica rapa var. nipposinica", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 45, "max": 75}, "days_to_maturity": {"min": 21, "max": 40}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost in spring; make a second sowing 6–8 weeks before first fall frost for autumn harvest."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 8, "max": 14}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in rows or broadcast thinly, thinning to 6–9 inches for full heads or leaving dense for cut-and-come-again baby leaves. Mizuna is extremely fast-growing and bolt-tolerant compared to most brassicas, making it one of the most reliable salad greens for both spring and fall. Begin harvesting outer leaves at 21 days or cut the whole plant an inch above the soil line and allow it to regrow. Consistent moisture promotes tender, mild-flavored leaves; drought causes bitterness.", "sources": ["general horticultural reference"]}')
