INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('mung-bean','Mung Bean','Vigna radiata','vegetable','legume',4,10,65,85,60,90,'seed','direct','warm','tender','last_frost',1,3,'Direct sow 1–3 weeks after last frost when soil has warmed to at least 65°F; mung bean needs a long, warm, relatively dry summer to set seed.',7,11,3,6,18,30,6,12,'full','low','Sow seeds 1 inch deep in rows, thinning to 3–6 inches; inoculate with cowpea rhizobium inoculant before planting to ensure nitrogen fixation. Pods can be harvested young (50–60 days) for fresh shelling or snap use, or left on the plant to dry for dried beans or sprouting seeds. Pick pods when they turn black and rattle to collect dry beans; harvest in the morning before pods shatter. Mung beans are also a popular choice for home sprouting — the dry seeds germinate in a jar within 2–4 days.','["general horticultural reference"]','{"slug": "mung-bean", "common_name": "Mung Bean", "scientific_name": "Vigna radiata", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 3}, "note": "Direct sow 1–3 weeks after last frost when soil has warmed to at least 65°F; mung bean needs a long, warm, relatively dry summer to set seed."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 3, "max": 6}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 6, "max": 12}, "sun": "full", "water": "low", "directions": "Sow seeds 1 inch deep in rows, thinning to 3–6 inches; inoculate with cowpea rhizobium inoculant before planting to ensure nitrogen fixation. Pods can be harvested young (50–60 days) for fresh shelling or snap use, or left on the plant to dry for dried beans or sprouting seeds. Pick pods when they turn black and rattle to collect dry beans; harvest in the morning before pods shatter. Mung beans are also a popular choice for home sprouting — the dry seeds germinate in a jar within 2–4 days.", "sources": ["general horticultural reference"]}')
