INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('mustard-greens','Mustard Greens','Brassica juncea','vegetable','brassica',4,7,40,75,30,50,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost in spring; succession sow every 2–3 weeks and again in early fall.',3,11,6,12,12,18,8,12,'full','moderate','Broadcast or row-sow seed at 1/4 in depth and thin to 6–12 in; mustard germinates rapidly even in cool soil. Begin harvesting outer leaves when plants are 6–8 in tall for mild flavor, or allow larger leaves to develop for a stronger pungency. Hot weather causes rapid bolting and sharply increases bitterness, so time sowings to mature in cool conditions. Baby leaves can be cut at 3–4 weeks as a spicy salad green.','["general horticultural reference"]','{"slug": "mustard-greens", "common_name": "Mustard Greens", "scientific_name": "Brassica juncea", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 30, "max": 50}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost in spring; succession sow every 2–3 weeks and again in early fall."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "moderate", "directions": "Broadcast or row-sow seed at 1/4 in depth and thin to 6–12 in; mustard germinates rapidly even in cool soil. Begin harvesting outer leaves when plants are 6–8 in tall for mild flavor, or allow larger leaves to develop for a stronger pungency. Hot weather causes rapid bolting and sharply increases bitterness, so time sowings to mature in cool conditions. Baby leaves can be cut at 3–4 weeks as a spicy salad green.", "sources": ["general horticultural reference"]}')
