INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('oca','Oca (New Zealand Yam)','Oxalis tuberosa','vegetable','root',NULL,NULL,50,65,180,240,'transplant','tuber','cool','half-hardy','last_frost',-2,0,'Plant tubers just before to just after last frost — oca needs a long, cool season and tuber formation is triggered by shortening day length in autumn.',7,10,12,15,12,18,12,18,'full','moderate','Plant small tubers 3 inches deep in loose, well-drained soil in early spring; oca is an Andean crop from the clover family and grows best in cool, moist conditions similar to potato, but requires a very long growing season. The plants produce clover-like foliage and only initiate tuber formation in response to the short days of autumn, so harvesting cannot occur until after the first frosts kill the foliage — typically November. Harvest tubers by digging carefully after frost kills the tops; tubers range from white to yellow, orange, red, and purple depending on the variety. Fresh-dug tubers are acidic and starchy but sweeten after a week of sun exposure that converts starch to sugars; eat roasted, boiled, or raw once sweetened.','["general horticultural reference"]','{"slug": "oca", "common_name": "Oca (New Zealand Yam)", "scientific_name": "Oxalis tuberosa", "category": "vegetable", "subcategory": "root", "days_to_germination": null, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 180, "max": 240}, "maturity_from": "transplant", "sow_method": "tuber", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 0}, "note": "Plant tubers just before to just after last frost — oca needs a long, cool season and tuber formation is triggered by shortening day length in autumn."}, "usda_zones": {"min": 7, "max": 10}, "spacing_in": {"min": 12, "max": 15}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Plant small tubers 3 inches deep in loose, well-drained soil in early spring; oca is an Andean crop from the clover family and grows best in cool, moist conditions similar to potato, but requires a very long growing season. The plants produce clover-like foliage and only initiate tuber formation in response to the short days of autumn, so harvesting cannot occur until after the first frosts kill the foliage — typically November. Harvest tubers by digging carefully after frost kills the tops; tubers range from white to yellow, orange, red, and purple depending on the variety. Fresh-dug tubers are acidic and starchy but sweeten after a week of sun exposure that converts starch to sugars; eat roasted, boiled, or raw once sweetened.", "sources": ["general horticultural reference"]}')
