INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('orach','Orach (Mountain Spinach)','Atriplex hortensis','vegetable','leafy-green',7,14,45,75,40,60,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; seeds need cold stratification or cool soil to germinate well and the crop runs to seed in summer heat.',3,9,9,12,24,60,12,18,'full','low','Press seeds firmly into soil no deeper than 1/4 inch; germination is improved by pre-soaking seeds for a few hours before sowing. Orach grows quickly into an upright plant with red, gold, or green leaves that can substitute for spinach in any cooked preparation. Pinch the central growing tip when the plant is 12 inches tall to encourage bushy side growth and delay bolting. Harvest young leaves frequently; once flower stalks emerge, leaves become less palatable.','["general horticultural reference"]','{"slug": "orach", "common_name": "Orach (Mountain Spinach)", "scientific_name": "Atriplex hortensis", "category": "vegetable", "subcategory": "leafy-green", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 45, "max": 75}, "days_to_maturity": {"min": 40, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; seeds need cold stratification or cool soil to germinate well and the crop runs to seed in summer heat."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 24, "max": 60}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Press seeds firmly into soil no deeper than 1/4 inch; germination is improved by pre-soaking seeds for a few hours before sowing. Orach grows quickly into an upright plant with red, gold, or green leaves that can substitute for spinach in any cooked preparation. Pinch the central growing tip when the plant is 12 inches tall to encourage bushy side growth and delay bolting. Harvest young leaves frequently; once flower stalks emerge, leaves become less palatable.", "sources": ["general horticultural reference"]}')
