INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('padron-pepper','Padrón Pepper','Capsicum annuum','vegetable','fruiting',7,21,70,85,60,80,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant 1–2 weeks after frost danger passes.',5,11,18,24,24,36,18,24,'full','moderate','Start seeds 1/4 inch deep in warm mix at 78–82°F; transplant into fertile, well-drained soil with consistent moisture. Padrón peppers are the Spanish tapas classic — small, thin-walled, and mostly mild, but a percentage of fruits become significantly hot (especially those left to grow larger or harvested later in the season). Pick pods when they are 1.5–2 inches long and still green for the mildest flavor; fried in olive oil and salted, they are traditionally served as pimientos de Padrón. Consistent watering during fruit set prevents irregular heat and blossom drop.','["general horticultural reference"]','{"slug": "padron-pepper", "common_name": "Padrón Pepper", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant 1–2 weeks after frost danger passes."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Start seeds 1/4 inch deep in warm mix at 78–82°F; transplant into fertile, well-drained soil with consistent moisture. Padrón peppers are the Spanish tapas classic — small, thin-walled, and mostly mild, but a percentage of fruits become significantly hot (especially those left to grow larger or harvested later in the season). Pick pods when they are 1.5–2 inches long and still green for the mildest flavor; fried in olive oil and salted, they are traditionally served as pimientos de Padrón. Consistent watering during fruit set prevents irregular heat and blossom drop.", "sources": ["general horticultural reference"]}')
