INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('peanut','Peanut','Arachis hypogaea','vegetable','legume',7,14,65,85,100,150,'seed','direct','warm','tender','last_frost',2,4,'Sow 2–4 weeks after last frost; peanuts need a long, frost-free growing season of at least 120 days.',6,11,6,12,12,18,18,24,'full','moderate','Shell peanuts and plant seeds 2 in deep in loose, sandy, well-drained soil; heavy clay prevents proper peg penetration and pod development. After flowering, keep the area around plants free of weeds and loosen surface soil lightly so fertilization pegs can easily enter the ground. Harvest when foliage begins to yellow and the inner shell veins turn dark, by lifting the entire plant with a fork. Cure plants upside-down in a warm, airy location for 2–3 weeks before removing pods.','["general horticultural reference"]','{"slug": "peanut", "common_name": "Peanut", "scientific_name": "Arachis hypogaea", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 100, "max": 150}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 4}, "note": "Sow 2–4 weeks after last frost; peanuts need a long, frost-free growing season of at least 120 days."}, "usda_zones": {"min": 6, "max": 11}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Shell peanuts and plant seeds 2 in deep in loose, sandy, well-drained soil; heavy clay prevents proper peg penetration and pod development. After flowering, keep the area around plants free of weeds and loosen surface soil lightly so fertilization pegs can easily enter the ground. Harvest when foliage begins to yellow and the inner shell veins turn dark, by lifting the entire plant with a fork. Cure plants upside-down in a warm, airy location for 2–3 weeks before removing pods.", "sources": ["general horticultural reference"]}')
