INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('perilla-vegetable','Perilla (Shiso)','Perilla frutescens','vegetable','leafy-green',7,21,65,80,60,80,'seed','direct','warm','tender','last_frost',0,2,'Direct sow at last frost date or start indoors 4–6 weeks earlier; seeds require light to germinate so press onto the soil surface without covering.',5,11,12,18,18,36,12,18,'full','moderate','Press seeds onto warm, moist soil surface without covering, as light aids germination; cold stratification in the refrigerator for one week before sowing improves germination rates. Perilla is a heat-loving herb-vegetable used extensively in Japanese and Korean cuisines — red types as a colorant and flavoring, green types as a wrap and garnish. Harvest individual large leaves from the base of the plant upward, or cut the whole plant back by half to promote bushy regrowth. Pinch flower spikes as they emerge to extend the leaf harvest and prevent aggressive self-seeding.','["general horticultural reference"]','{"slug": "perilla-vegetable", "common_name": "Perilla (Shiso)", "scientific_name": "Perilla frutescens", "category": "vegetable", "subcategory": "leafy-green", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 65, "max": 80}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow at last frost date or start indoors 4–6 weeks earlier; seeds require light to germinate so press onto the soil surface without covering."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Press seeds onto warm, moist soil surface without covering, as light aids germination; cold stratification in the refrigerator for one week before sowing improves germination rates. Perilla is a heat-loving herb-vegetable used extensively in Japanese and Korean cuisines — red types as a colorant and flavoring, green types as a wrap and garnish. Harvest individual large leaves from the base of the plant upward, or cut the whole plant back by half to promote bushy regrowth. Pinch flower spikes as they emerge to extend the leaf harvest and prevent aggressive self-seeding.", "sources": ["general horticultural reference"]}')
