  VALUES ('pigeon-pea','Pigeon Pea','Cajanus cajan','vegetable','legume',7,14,65,85,120,180,'seed','direct','perennial','tender','last_frost',2,6,'Direct sow 2–6 weeks after last frost; in zone 9–11 pigeon pea grows as a woody short-lived perennial and may produce for 3–5 years before replanting.',9,12,36,60,60,120,36,72,'full','low','Sow seeds 1 in deep in well-drained, low-fertility soil; pigeon pea is a deep-rooted drought tolerant shrub that fixes nitrogen and does not require fertilization. It grows into a woody perennial in frost-free zones and produces pods over an extended season rather than all at once. Harvest green pods when plump for fresh shelling or allow to dry on the plant for dried dal. Prune back to 2–3 ft after the main harvest season to stimulate a second flush of growth and pods.','["ECHO technical notes", "general horticultural reference"]','{"slug": "pigeon-pea", "common_name": "Pigeon Pea", "scientific_name": "Cajanus cajan", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 6}, "note": "Direct sow 2–6 weeks after last frost; in zone 9–11 pigeon pea grows as a woody short-lived perennial and may produce for 3–5 years before replanting."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 60, "max": 120}, "spread_in": {"min": 36, "max": 72}, "sun": "full", "water": "low", "directions": "Sow seeds 1 in deep in well-drained, low-fertility soil; pigeon pea is a deep-rooted drought tolerant shrub that fixes nitrogen and does not require fertilization. It grows into a woody perennial in frost-free zones and produces pods over an extended season rather than all at once. Harvest green pods when plump for fresh shelling or allow to dry on the plant for dried dal. Prune back to 2–3 ft after the main harvest season to stimulate a second flush of growth and pods.", "sources": ["ECHO technical notes", "general horticultural reference"]}')
