  VALUES ('pimento-pepper','Pimento Pepper','Capsicum annuum','vegetable','fruiting',8,14,70,85,75,90,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed.',4,11,18,24,18,30,18,24,'full','moderate','Sow seeds 1/4 inch deep in warm starting mix and transplant to fertile, well-drained garden soil once the risk of frost has fully passed. The heart-shaped, thick-walled fruits ripen from green to deep red and are sweeter and more aromatic than most bell peppers, with a rich, almost spicy fragrance that is distinct to the type. Harvest at full red for fresh use, or roast and peel for preserving in oil — pimento is the classic stuffing for green olives. High yields from compact plants make this a productive choice for containers or small beds.','["general horticultural reference"]','{"slug": "pimento-pepper", "common_name": "Pimento Pepper", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 8, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 75, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm starting mix and transplant to fertile, well-drained garden soil once the risk of frost has fully passed. The heart-shaped, thick-walled fruits ripen from green to deep red and are sweeter and more aromatic than most bell peppers, with a rich, almost spicy fragrance that is distinct to the type. Harvest at full red for fresh use, or roast and peel for preserving in oil — pimento is the classic stuffing for green olives. High yields from compact plants make this a productive choice for containers or small beds.", "sources": ["general horticultural reference"]}')
