  VALUES ('pole-bean','Pole Bean','Phaseolus vulgaris','vegetable','legume',7,14,60,85,60,80,'seed','direct','warm','tender','last_frost',1,2,'Sow after last frost when soil is warm; erect a trellis or pole structure before sowing to avoid disturbing roots later.',3,11,6,8,60,96,12,18,'full','moderate','Plant seeds 1 in deep at the base of a sturdy trellis or teepee of poles set 6–8 ft tall, spacing 3 seeds per pole. Vines twine naturally but may need early guidance toward supports. Harvest pods before seeds bulge prominently for the tenderest texture. Pole beans produce over a longer season than bush types, so keep picking to prevent pod maturation from stopping new flower set.','["general horticultural reference"]','{"slug": "pole-bean", "common_name": "Pole Bean", "scientific_name": "Phaseolus vulgaris", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 60, "max": 85}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Sow after last frost when soil is warm; erect a trellis or pole structure before sowing to avoid disturbing roots later."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 60, "max": 96}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Plant seeds 1 in deep at the base of a sturdy trellis or teepee of poles set 6–8 ft tall, spacing 3 seeds per pole. Vines twine naturally but may need early guidance toward supports. Harvest pods before seeds bulge prominently for the tenderest texture. Pole beans produce over a longer season than bush types, so keep picking to prevent pod maturation from stopping new flower set.", "sources": ["general horticultural reference"]}')
