INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('popcorn','Popcorn','Zea mays var. everta','vegetable','grain',5,10,60,95,90,110,'seed','direct','warm','tender','last_frost',0,2,'Direct sow at or up to 2 weeks after last frost once soil reaches at least 60°F. Isolate from sweet corn by at least 250 feet or time plantings to avoid simultaneous silking.',3,11,9,12,48,72,12,18,'full','moderate','Sow seeds 1–2 inches deep in blocks of at least 4 rows for proper wind pollination, isolating from sweet corn to prevent cross-pollination that ruins eating quality. Side-dress with nitrogen at knee-height and again when tassels appear. Leave ears on the stalk past eating stage until husks are completely brown and papery; pull husks back and hang ears in a dry, ventilated spot for 4–6 weeks until kernels release from the cob easily. Kernels are ready to pop when moisture content drops to around 14%.','["general horticultural reference"]','{"slug": "popcorn", "common_name": "Popcorn", "scientific_name": "Zea mays var. everta", "category": "vegetable", "subcategory": "grain", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 60, "max": 95}, "days_to_maturity": {"min": 90, "max": 110}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow at or up to 2 weeks after last frost once soil reaches at least 60°F. Isolate from sweet corn by at least 250 feet or time plantings to avoid simultaneous silking."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1–2 inches deep in blocks of at least 4 rows for proper wind pollination, isolating from sweet corn to prevent cross-pollination that ruins eating quality. Side-dress with nitrogen at knee-height and again when tassels appear. Leave ears on the stalk past eating stage until husks are completely brown and papery; pull husks back and hang ears in a dry, ventilated spot for 4–6 weeks until kernels release from the cob easily. Kernels are ready to pop when moisture content drops to around 14%.", "sources": ["general horticultural reference"]}')
