INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('potato-onion','Potato Onion','Allium cepa var. aggregatum','vegetable','allium',NULL,NULL,50,75,100,130,'transplant','bulb','cool','hardy','fall',0,6,'Plant bulbs in fall 4–6 weeks before hard freeze in zones 5–9; in zones 3–4, plant as early as possible in spring.',3,9,6,9,12,24,6,9,'full','moderate','Plant individual bulbs 1 inch deep in well-drained, fertile soil — large bulbs planted in fall will multiply into a cluster of 8–12 medium onions, while small bulbs tend to produce fewer but larger bulbs. Potato onions are a multiplier onion type that propagates entirely by bulb division, forming a cluster of bulbs in the same way shallots do; no seed is needed or typically produced. Allow tops to fall over and begin to yellow before harvesting the entire cluster; cure in a warm, airy spot for 2–3 weeks. Save the smallest bulbs from the cluster for replanting, perpetuating the variety indefinitely without seed purchases.','["general horticultural reference"]','{"slug": "potato-onion", "common_name": "Potato Onion", "scientific_name": "Allium cepa var. aggregatum", "category": "vegetable", "subcategory": "allium", "days_to_germination": null, "germination_soil_temp_f": {"min": 50, "max": 75}, "days_to_maturity": {"min": 100, "max": 130}, "maturity_from": "transplant", "sow_method": "bulb", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": 0, "max": 6}, "note": "Plant bulbs in fall 4–6 weeks before hard freeze in zones 5–9; in zones 3–4, plant as early as possible in spring."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 6, "max": 9}, "sun": "full", "water": "moderate", "directions": "Plant individual bulbs 1 inch deep in well-drained, fertile soil — large bulbs planted in fall will multiply into a cluster of 8–12 medium onions, while small bulbs tend to produce fewer but larger bulbs. Potato onions are a multiplier onion type that propagates entirely by bulb division, forming a cluster of bulbs in the same way shallots do; no seed is needed or typically produced. Allow tops to fall over and begin to yellow before harvesting the entire cluster; cure in a warm, airy spot for 2–3 weeks. Save the smallest bulbs from the cluster for replanting, perpetuating the variety indefinitely without seed purchases.", "sources": ["general horticultural reference"]}')
