  VALUES ('proso-millet','Proso Millet (Broomcorn Millet)','Panicum miliaceum','vegetable','grain',5,10,55,90,60,90,'seed','direct','warm','tender','last_frost',1,6,'Sow after last frost; proso millet is the shortest-season grain available to home gardeners, maturing in as little as 60 days.',4,10,4,6,24,48,6,10,'full','low','Drill or broadcast seed 1/2 in deep at roughly 20–25 lb per acre in home-scale rows and thin to 4–6 in; proso millet germinates quickly in warm soil and produces an open panicle of seed in just 60 days, making it practical even in short-season gardens above zone 4. Harvest entire stalks when the lower seeds are hard and the panicle begins to droop; hang bundles upside-down over a tarp for 2 weeks to finish drying. Thresh by beating bundles against the inside of a barrel and winnow outdoors; the hull is loose and comes free with light rubbing in warm water. Proso millet is gluten-free and has the lowest water requirement of any grain crop.','["general horticultural reference"]','{"slug": "proso-millet", "common_name": "Proso Millet (Broomcorn Millet)", "scientific_name": "Panicum miliaceum", "category": "vegetable", "subcategory": "grain", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 55, "max": 90}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 6}, "note": "Sow after last frost; proso millet is the shortest-season grain available to home gardeners, maturing in as little as 60 days."}, "usda_zones": {"min": 4, "max": 10}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "low", "directions": "Drill or broadcast seed 1/2 in deep at roughly 20–25 lb per acre in home-scale rows and thin to 4–6 in; proso millet germinates quickly in warm soil and produces an open panicle of seed in just 60 days, making it practical even in short-season gardens above zone 4. Harvest entire stalks when the lower seeds are hard and the panicle begins to droop; hang bundles upside-down over a tarp for 2 weeks to finish drying. Thresh by beating bundles against the inside of a barrel and winnow outdoors; the hull is loose and comes free with light rubbing in warm water. Proso millet is gluten-free and has the lowest water requirement of any grain crop.", "sources": ["general horticultural reference"]}')
