  VALUES ('pumpkin','Pumpkin','Cucurbita pepo','vegetable','cucurbit',4,10,65,95,75,120,'seed','direct','warm','tender','last_frost',1,3,'Direct sow 1–3 weeks after last frost; time planting to mature before the first fall frost.',3,10,36,60,12,24,60,144,'full','moderate','Sow 3–4 seeds 1 inch deep per hill in deeply worked, compost-rich soil once soil temperature is at least 65°F, then thin to the 2 strongest seedlings. Large-vined types need 6–10 feet of space per plant; choose bush types for smaller gardens. Place a piece of cardboard or straw under developing fruits to prevent rot. Harvest when the shell is fully orange, the rind is hard throughout, and the stem has begun to dry and cork.','["general horticultural reference"]','{"slug": "pumpkin", "common_name": "Pumpkin", "scientific_name": "Cucurbita pepo", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 95}, "days_to_maturity": {"min": 75, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 3}, "note": "Direct sow 1–3 weeks after last frost; time planting to mature before the first fall frost."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 60, "max": 144}, "sun": "full", "water": "moderate", "directions": "Sow 3–4 seeds 1 inch deep per hill in deeply worked, compost-rich soil once soil temperature is at least 65°F, then thin to the 2 strongest seedlings. Large-vined types need 6–10 feet of space per plant; choose bush types for smaller gardens. Place a piece of cardboard or straw under developing fruits to prevent rot. Harvest when the shell is fully orange, the rind is hard throughout, and the stem has begun to dry and cork.", "sources": ["general horticultural reference"]}')
