INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('purple-hull-pea','Purple Hull Pea (Southern Pea)','Vigna unguiculata subsp. unguiculata','vegetable','legume',5,10,65,95,60,75,'seed','direct','warm','tender','last_frost',2,8,'Sow 2 weeks after last frost into warm soil; a quintessential Gulf Coast staple that thrives in heat and humidity that discourage northern legumes.',7,11,3,6,18,36,12,24,'full','low','Sow seeds 1 in deep directly into warm, well-drained soil — purple hull peas rot in cold, wet ground, so wait until soil consistently exceeds 65°F. Inoculate seed with cowpea rhizobium for maximum nitrogen fixation and avoid excess fertilizer, which promotes foliage over pods. Harvest pods when the purple color intensifies and the peas feel plump inside, shelling immediately or refrigerating; over-mature pods turn tan and the peas starch up quickly. Succession-plant every 3 weeks through summer for a continuous harvest; a second planting in late July produces a heavy fall crop in the Gulf South.','["Texas A&M AgriLife Extension Service", "Louisiana State University AgCenter"]','{"slug": "purple-hull-pea", "common_name": "Purple Hull Pea (Southern Pea)", "scientific_name": "Vigna unguiculata subsp. unguiculata", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 95}, "days_to_maturity": {"min": 60, "max": 75}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 8}, "note": "Sow 2 weeks after last frost into warm soil; a quintessential Gulf Coast staple that thrives in heat and humidity that discourage northern legumes."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 3, "max": 6}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "low", "directions": "Sow seeds 1 in deep directly into warm, well-drained soil — purple hull peas rot in cold, wet ground, so wait until soil consistently exceeds 65°F. Inoculate seed with cowpea rhizobium for maximum nitrogen fixation and avoid excess fertilizer, which promotes foliage over pods. Harvest pods when the purple color intensifies and the peas feel plump inside, shelling immediately or refrigerating; over-mature pods turn tan and the peas starch up quickly. Succession-plant every 3 weeks through summer for a continuous harvest; a second planting in late July produces a heavy fall crop in the Gulf South.", "sources": ["Texas A&M AgriLife Extension Service", "Louisiana State University AgCenter"]}')
