INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('purslane','Purslane','Portulaca oleracea','vegetable','leafy-green',7,14,65,85,45,60,'seed','direct','warm','tender','last_frost',1,3,'Sow after last frost when soil is thoroughly warm; germination is erratic in cool soil below 65°F.',4,11,6,12,3,8,8,18,'full','low','Surface-sow tiny seeds or press them 1/8 inch into warm, well-drained soil; do not overwater as seeds rot easily in cool, wet conditions. Golden or green cultivated purslane is much larger and less bitter than its weedy relative, with thick, succulent stems and paddle-shaped leaves. Harvest stem tips 5–6 inches long when plants are lush and before flower buds form; the plant regrows readily after cutting. Purslane is one of the few plant sources of omega-3 fatty acids and is excellent raw in salads or lightly sautéed.','["general horticultural reference"]','{"slug": "purslane", "common_name": "Purslane", "scientific_name": "Portulaca oleracea", "category": "vegetable", "subcategory": "leafy-green", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 45, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 3}, "note": "Sow after last frost when soil is thoroughly warm; germination is erratic in cool soil below 65°F."}, "usda_zones": {"min": 4, "max": 11}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 3, "max": 8}, "spread_in": {"min": 8, "max": 18}, "sun": "full", "water": "low", "directions": "Surface-sow tiny seeds or press them 1/8 inch into warm, well-drained soil; do not overwater as seeds rot easily in cool, wet conditions. Golden or green cultivated purslane is much larger and less bitter than its weedy relative, with thick, succulent stems and paddle-shaped leaves. Harvest stem tips 5–6 inches long when plants are lush and before flower buds form; the plant regrows readily after cutting. Purslane is one of the few plant sources of omega-3 fatty acids and is excellent raw in salads or lightly sautéed.", "sources": ["general horticultural reference"]}')
