INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('quinoa','Quinoa','Chenopodium quinoa','vegetable','pseudograin',3,7,50,75,90,120,'seed','direct','cool','half-hardy','last_frost',-2,2,'Sow around the last frost date in spring; quinoa bolts in midsummer heat, so timing for a cool finish is critical in most climates.',4,10,12,18,48,72,12,18,'full','low','Broadcast or sow seed 1/4 in deep in firm, well-drained soil and thin to 12–18 in when seedlings are 3–4 in tall; quinoa is highly drought-tolerant once established and prefers cool, dry weather through seed fill. The colorful seed heads (red, orange, or cream) are ready to harvest when the seed falls easily from the panicle when rubbed — typically after the first light fall frost has dried the plant. Cut the seed heads into paper bags, dry for 1–2 weeks in a warm airy space, then thresh by rubbing heads between hands and winnow away the chaff outdoors in a breeze. Rinse seed thoroughly before eating to remove bitter saponins from the seed coat.','["general horticultural reference"]','{"slug": "quinoa", "common_name": "Quinoa", "scientific_name": "Chenopodium quinoa", "category": "vegetable", "subcategory": "pseudograin", "days_to_germination": {"min": 3, "max": 7}, "germination_soil_temp_f": {"min": 50, "max": 75}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 2}, "note": "Sow around the last frost date in spring; quinoa bolts in midsummer heat, so timing for a cool finish is critical in most climates."}, "usda_zones": {"min": 4, "max": 10}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 48, "max": 72}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "low", "directions": "Broadcast or sow seed 1/4 in deep in firm, well-drained soil and thin to 12–18 in when seedlings are 3–4 in tall; quinoa is highly drought-tolerant once established and prefers cool, dry weather through seed fill. The colorful seed heads (red, orange, or cream) are ready to harvest when the seed falls easily from the panicle when rubbed — typically after the first light fall frost has dried the plant. Cut the seed heads into paper bags, dry for 1–2 weeks in a warm airy space, then thresh by rubbing heads between hands and winnow away the chaff outdoors in a breeze. Rinse seed thoroughly before eating to remove bitter saponins from the seed coat.", "sources": ["general horticultural reference"]}')
