INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ramps-wild-leek','Ramps (Wild Leek)','Allium tricoccum','vegetable','allium',60,365,35,50,730,1825,'transplant','division','cool','hardy','fall',0,4,'Transplant divisions or plant fresh seed in fall under deciduous hardwood canopy; ramps are woodland ephemerals that emerge in early spring and die back by early summer.',3,8,4,6,6,12,4,6,'shade','moderate','Plant bulb divisions 2–3 inches deep in moist, humus-rich woodland soil under deciduous trees that provide deep summer shade; ramps are native North American woodland plants and require the ephemeral light window of early spring before tree leaf-out. Seed germinates slowly and erratically, often taking 18 months for full emergence after a double dormancy period requiring warm then cold stratification; vegetative division of established clumps is the most reliable propagation method. Harvest sparingly — take no more than one leaf per plant or one bulb in three, leaving the colony to regenerate — as over-harvesting wild populations is a significant ecological concern. The entire plant (broad flat leaves, small white bulb, and stems) carries a strong, complex garlic-onion flavor and is celebrated as a spring delicacy across Appalachia.','["general horticultural reference"]','{"slug": "ramps-wild-leek", "common_name": "Ramps (Wild Leek)", "scientific_name": "Allium tricoccum", "category": "vegetable", "subcategory": "allium", "days_to_germination": {"min": 60, "max": 365}, "germination_soil_temp_f": {"min": 35, "max": 50}, "days_to_maturity": {"min": 730, "max": 1825}, "maturity_from": "transplant", "sow_method": "division", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "fall", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Transplant divisions or plant fresh seed in fall under deciduous hardwood canopy; ramps are woodland ephemerals that emerge in early spring and die back by early summer."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 4, "max": 6}, "sun": "shade", "water": "moderate", "directions": "Plant bulb divisions 2–3 inches deep in moist, humus-rich woodland soil under deciduous trees that provide deep summer shade; ramps are native North American woodland plants and require the ephemeral light window of early spring before tree leaf-out. Seed germinates slowly and erratically, often taking 18 months for full emergence after a double dormancy period requiring warm then cold stratification; vegetative division of established clumps is the most reliable propagation method. Harvest sparingly — take no more than one leaf per plant or one bulb in three, leaving the colony to regenerate — as over-harvesting wild populations is a significant ecological concern. The entire plant (broad flat leaves, small white bulb, and stems) carries a strong, complex garlic-onion flavor and is celebrated as a spring delicacy across Appalachia.", "sources": ["general horticultural reference"]}')
