INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('red-kuri-squash','Red Kuri Squash','Cucurbita maxima','vegetable','cucurbit',4,10,65,95,90,105,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost once soil warms to 65°F; in short-season areas, start indoors 3 weeks before transplanting.',3,10,36,60,12,18,72,120,'full','moderate','Sow 2–3 seeds 1 inch deep per hill in compost-enriched soil and thin to one or two vines per hill once established. Red Kuri is a teardrop-shaped Cucurbita maxima with vivid orange-red skin and nutty, chestnut-flavored, dry flesh that is among the finest of all winter squash. Harvest when skin is deep orange-red and hard; the stems will be beginning to dry and the skin will resist a thumbnail. Cure for 10–14 days at room temperature before storing; fruits keep well for three to four months under cool, dry conditions.','["general horticultural reference"]','{"slug": "red-kuri-squash", "common_name": "Red Kuri Squash", "scientific_name": "Cucurbita maxima", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 95}, "days_to_maturity": {"min": 90, "max": 105}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost once soil warms to 65°F; in short-season areas, start indoors 3 weeks before transplanting."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 72, "max": 120}, "sun": "full", "water": "moderate", "directions": "Sow 2–3 seeds 1 inch deep per hill in compost-enriched soil and thin to one or two vines per hill once established. Red Kuri is a teardrop-shaped Cucurbita maxima with vivid orange-red skin and nutty, chestnut-flavored, dry flesh that is among the finest of all winter squash. Harvest when skin is deep orange-red and hard; the stems will be beginning to dry and the skin will resist a thumbnail. Cure for 10–14 days at room temperature before storing; fruits keep well for three to four months under cool, dry conditions.", "sources": ["general horticultural reference"]}')
