INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('amaranth-red-leaf','Red Leaf Amaranth (Chinese Spinach)','Amaranthus tricolor','vegetable','greens',5,10,65,85,30,50,'seed','direct','warm','tender','last_frost',0,2,'Direct sow at or just after last frost once soil is consistently warm; the heat-season replacement for spinach in tropical and subtropical gardens.',2,11,6,12,18,48,9,18,'full','moderate','Scatter seeds thinly on the soil surface — they need light to germinate — then press gently and keep moist; thin seedlings to 6 inches apart, using thinnings as baby greens. Leaves are brilliantly colored in shades of red, purple, and green and are mildly flavored, used in stir-fries, soups, and as a cooked green throughout South and Southeast Asia. Harvest outer leaves or cut entire young plants at 6–8 inches tall to encourage regrowth; plants that are allowed to flower and set seed will readily self-sow for the following year. This species thrives in the same hot, humid conditions that cause true spinach to bolt immediately.','["general horticultural reference"]','{"slug": "amaranth-red-leaf", "common_name": "Red Leaf Amaranth (Chinese Spinach)", "scientific_name": "Amaranthus tricolor", "category": "vegetable", "subcategory": "greens", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 30, "max": 50}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Direct sow at or just after last frost once soil is consistently warm; the heat-season replacement for spinach in tropical and subtropical gardens."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 18, "max": 48}, "spread_in": {"min": 9, "max": 18}, "sun": "full", "water": "moderate", "directions": "Scatter seeds thinly on the soil surface — they need light to germinate — then press gently and keep moist; thin seedlings to 6 inches apart, using thinnings as baby greens. Leaves are brilliantly colored in shades of red, purple, and green and are mildly flavored, used in stir-fries, soups, and as a cooked green throughout South and Southeast Asia. Harvest outer leaves or cut entire young plants at 6–8 inches tall to encourage regrowth; plants that are allowed to flower and set seed will readily self-sow for the following year. This species thrives in the same hot, humid conditions that cause true spinach to bolt immediately.", "sources": ["general horticultural reference"]}')
