  VALUES ('mizuna-red','Red Mizuna','Brassica rapa var. japonica','vegetable','brassica',4,7,45,75,20,40,'seed','direct','cool','hardy','last_frost',-6,-3,'Direct sow 3–6 weeks before last frost for spring; sow again 6–8 weeks before first fall frost for the best-flavored autumn harvest.',3,11,6,9,9,18,9,15,'full','moderate','Scatter seeds thinly and cover with 1/4 inch of soil in a cool, moist seedbed; germination is rapid in cool conditions. Red mizuna has the same deeply-cut, feathery leaf form as green mizuna but with vivid burgundy-red stems and leaf coloring that intensifies in cool weather, making it as ornamental as it is edible. Harvest outer leaves continuously once plants reach 4 inches, or cut the entire plant 1 inch above the base to allow regrowth; flavor is peppery and nutty, similar to green mizuna but with slightly more bite. Fall sowings consistently outperform spring plantings in flavor and color intensity as frost sweetens the leaves.','["general horticultural reference"]','{"slug": "mizuna-red", "common_name": "Red Mizuna", "scientific_name": "Brassica rapa var. japonica", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 45, "max": 75}, "days_to_maturity": {"min": 20, "max": 40}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -3}, "note": "Direct sow 3–6 weeks before last frost for spring; sow again 6–8 weeks before first fall frost for the best-flavored autumn harvest."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 9, "max": 18}, "spread_in": {"min": 9, "max": 15}, "sun": "full", "water": "moderate", "directions": "Scatter seeds thinly and cover with 1/4 inch of soil in a cool, moist seedbed; germination is rapid in cool conditions. Red mizuna has the same deeply-cut, feathery leaf form as green mizuna but with vivid burgundy-red stems and leaf coloring that intensifies in cool weather, making it as ornamental as it is edible. Harvest outer leaves continuously once plants reach 4 inches, or cut the entire plant 1 inch above the base to allow regrowth; flavor is peppery and nutty, similar to green mizuna but with slightly more bite. Fall sowings consistently outperform spring plantings in flavor and color intensity as frost sweetens the leaves.", "sources": ["general horticultural reference"]}')
