INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ridge-gourd','Ridge Gourd (Angled Luffa)','Luffa acutangula','vegetable','cucurbit',7,14,75,90,60,80,'seed','direct','warm','tender','last_frost',2,4,'Direct sow 2–4 weeks after last frost once soil reaches 75°F; requires sustained heat to produce well.',9,12,18,24,72,120,18,36,'full','moderate','Sow seeds 1/2 inch deep in warm soil after last frost and provide a trellis or fence immediately, as vines climb vigorously by tendrils. Ridge gourd differs from smooth luffa in having ten prominent sharp ridges running the length of the fruit and slightly more tender flesh when young. Harvest fruits at 6–9 inches long while skin is still soft and the ridges are firm and green — the young flesh is mild, slightly sweet, and commonly used in Indian dal, stir-fries, and curries. Like smooth luffa, fruits left to fully mature develop a tough fiber skeleton and can serve as a scrubbing sponge.','["general horticultural reference"]','{"slug": "ridge-gourd", "common_name": "Ridge Gourd (Angled Luffa)", "scientific_name": "Luffa acutangula", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 75, "max": 90}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 4}, "note": "Direct sow 2–4 weeks after last frost once soil reaches 75°F; requires sustained heat to produce well."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 72, "max": 120}, "spread_in": {"min": 18, "max": 36}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/2 inch deep in warm soil after last frost and provide a trellis or fence immediately, as vines climb vigorously by tendrils. Ridge gourd differs from smooth luffa in having ten prominent sharp ridges running the length of the fruit and slightly more tender flesh when young. Harvest fruits at 6–9 inches long while skin is still soft and the ridges are firm and green — the young flesh is mild, slightly sweet, and commonly used in Indian dal, stir-fries, and curries. Like smooth luffa, fruits left to fully mature develop a tough fiber skeleton and can serve as a scrubbing sponge.", "sources": ["general horticultural reference"]}')
