  VALUES ('rocoto-pepper','Rocoto Pepper (Manzano)','Capsicum pubescens','vegetable','fruiting',14,28,65,75,90,150,'transplant','indoor-start','warm','half-hardy','last_frost',-14,-12,'Start indoors 12–14 weeks before last frost; unlike most peppers, rocoto prefers cool nights and actually performs poorly in intense summer heat.',8,11,24,36,36,72,24,36,'partial','moderate','Sow seeds 1/4 inch deep at a cooler 65–70°F — unlike other peppers, Capsicum pubescens actually germinates better in cooler soil and is damaged by excessive heat. This Andean species is unique among cultivated peppers for its purple flowers and distinctive black seeds; it tolerates light frost better than any other pepper species. Transplant to a position with afternoon shade in hot climates, as rocoto stops setting fruit when temperatures exceed 90°F — coastal or mountain gardens suit it best. Fruits resemble small apples (hence ''manzano'') and ripen to yellow, orange, or red with thick, sweet flesh and intense, burning heat.','["general horticultural reference"]','{"slug": "rocoto-pepper", "common_name": "Rocoto Pepper (Manzano)", "scientific_name": "Capsicum pubescens", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 14, "max": 28}, "germination_soil_temp_f": {"min": 65, "max": 75}, "days_to_maturity": {"min": 90, "max": 150}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -14, "max": -12}, "note": "Start indoors 12–14 weeks before last frost; unlike most peppers, rocoto prefers cool nights and actually performs poorly in intense summer heat."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 24, "max": 36}, "sun": "partial", "water": "moderate", "directions": "Sow seeds 1/4 inch deep at a cooler 65–70°F — unlike other peppers, Capsicum pubescens actually germinates better in cooler soil and is damaged by excessive heat. This Andean species is unique among cultivated peppers for its purple flowers and distinctive black seeds; it tolerates light frost better than any other pepper species. Transplant to a position with afternoon shade in hot climates, as rocoto stops setting fruit when temperatures exceed 90°F — coastal or mountain gardens suit it best. Fruits resemble small apples (hence ''manzano'') and ripen to yellow, orange, or red with thick, sweet flesh and intense, burning heat.", "sources": ["general horticultural reference"]}')
