INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('roselle','Roselle (Jamaican Sorrel)','Hibiscus sabdariffa','vegetable','fruiting',7,14,70,90,100,150,'seed','indoor-start','warm','tender','last_frost',-8,-6,'Start indoors 6–8 weeks before last frost; roselle needs a long growing season and should be transplanted out only after all danger of frost is past.',8,11,24,36,36,72,24,36,'full','moderate','Start seeds 1/4 inch deep in warm mix; germination is fastest at 80–85°F. Transplant after last frost into fertile, well-drained soil and water deeply but infrequently once established. The calyces (fleshy sepals surrounding the seedpods) are the harvested vegetable, ready when they are plump, bright red, and still tender — about a week after the flower drops. Harvest calyces promptly every few days as they become fibrous if left on the plant too long; they are used fresh for teas, jams, and sauces.','["general horticultural reference"]','{"slug": "roselle", "common_name": "Roselle (Jamaican Sorrel)", "scientific_name": "Hibiscus sabdariffa", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 90}, "days_to_maturity": {"min": 100, "max": 150}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -8, "max": -6}, "note": "Start indoors 6–8 weeks before last frost; roselle needs a long growing season and should be transplanted out only after all danger of frost is past."}, "usda_zones": {"min": 8, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Start seeds 1/4 inch deep in warm mix; germination is fastest at 80–85°F. Transplant after last frost into fertile, well-drained soil and water deeply but infrequently once established. The calyces (fleshy sepals surrounding the seedpods) are the harvested vegetable, ready when they are plump, bright red, and still tender — about a week after the flower drops. Harvest calyces promptly every few days as they become fibrous if left on the plant too long; they are used fresh for teas, jams, and sauces.", "sources": ["general horticultural reference"]}')
