INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('safflower-oilseed','Safflower (Oilseed)','Carthamus tinctorius','vegetable','oilseed',7,14,40,75,100,130,'seed','direct','cool','half-hardy','soil_workable',0,3,'Sow early in spring; safflower has a deep taproot that scavenges subsoil moisture, making it the most drought-resistant oilseed for dryland gardens.',3,9,6,10,24,48,8,16,'full','low','Plant seed 1 in deep at 6–10 in apart in rows 18–24 in wide; safflower needs a long growing season so early planting in cool soil is critical. The plant grows a large rosette in the vegetative phase, then bolts to form spiny, branching heads with brilliant orange or yellow florets. Harvest when the heads are dry and papery — cut and place in cloth bags to finish drying, then thresh by rubbing to release the seed. Safflower oil is prized for its high linoleic acid content and heat stability; the petals can also be used as a saffron substitute.','["general horticultural reference"]','{"slug": "safflower-oilseed", "common_name": "Safflower (Oilseed)", "scientific_name": "Carthamus tinctorius", "category": "vegetable", "subcategory": "oilseed", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 100, "max": 130}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "soil_workable", "weeks_from_anchor": {"min": 0, "max": 3}, "note": "Sow early in spring; safflower has a deep taproot that scavenges subsoil moisture, making it the most drought-resistant oilseed for dryland gardens."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 6, "max": 10}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 8, "max": 16}, "sun": "full", "water": "low", "directions": "Plant seed 1 in deep at 6–10 in apart in rows 18–24 in wide; safflower needs a long growing season so early planting in cool soil is critical. The plant grows a large rosette in the vegetative phase, then bolts to form spiny, branching heads with brilliant orange or yellow florets. Harvest when the heads are dry and papery — cut and place in cloth bags to finish drying, then thresh by rubbing to release the seed. Safflower oil is prized for its high linoleic acid content and heat stability; the petals can also be used as a saffron substitute.", "sources": ["general horticultural reference"]}')
