  VALUES ('salsify','Salsify (Oyster Plant)','Tragopogon porrifolius','vegetable','root',10,20,50,75,120,150,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow as early as 2–4 weeks before last frost; the long season requires early sowing and deep, loose soil.',3,9,3,4,12,24,3,5,'full','moderate','Sow seeds 1/2 inch deep in deeply dug, stone-free soil; salsify develops long taproots that fork and deform in rocky or compacted ground. Thin to 3–4 inches after germination and keep weed-free, as salsify''s grass-like tops are easily overwhelmed early on. Roots are ready in autumn when they reach pencil thickness and finger length; flavor improves markedly after hard frost. Roots can overwinter in the ground and be harvested as needed through winter in mild climates, or dig all roots in late fall and store in damp sand.','["general horticultural reference"]','{"slug": "salsify", "common_name": "Salsify (Oyster Plant)", "scientific_name": "Tragopogon porrifolius", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 10, "max": 20}, "germination_soil_temp_f": {"min": 50, "max": 75}, "days_to_maturity": {"min": 120, "max": 150}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow as early as 2–4 weeks before last frost; the long season requires early sowing and deep, loose soil."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 3, "max": 4}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 3, "max": 5}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/2 inch deep in deeply dug, stone-free soil; salsify develops long taproots that fork and deform in rocky or compacted ground. Thin to 3–4 inches after germination and keep weed-free, as salsify''s grass-like tops are easily overwhelmed early on. Roots are ready in autumn when they reach pencil thickness and finger length; flavor improves markedly after hard frost. Roots can overwinter in the ground and be harvested as needed through winter in mild climates, or dig all roots in late fall and store in damp sand.", "sources": ["general horticultural reference"]}')
