INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('scorzonera','Scorzonera (Black Salsify)','Scorzonera hispanica','vegetable','root',10,18,50,75,120,180,'seed','direct','cool','hardy','last_frost',-4,-2,'Sow as early as 2–4 weeks before last frost; scorzonera can also be sown in late summer for next-year roots, as it is a biennial in most climates.',3,9,4,6,18,30,4,6,'full','moderate','Sow seeds 1/2 inch deep in deeply loosened, rich soil; like salsify, roots fork in compacted ground. Scorzonera produces a black-skinned root with creamy white interior and a more refined flavor than salsify, often described as mildly nutty and sweet. Roots can be harvested in the first autumn when pencil-thick, but leaving them in the ground through winter and harvesting the following spring produces larger, sweeter roots. When harvesting, dig carefully as the roots are brittle and ooze a milky latex; peel under water to prevent discoloration.','["general horticultural reference"]','{"slug": "scorzonera", "common_name": "Scorzonera (Black Salsify)", "scientific_name": "Scorzonera hispanica", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 10, "max": 18}, "germination_soil_temp_f": {"min": 50, "max": 75}, "days_to_maturity": {"min": 120, "max": 180}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Sow as early as 2–4 weeks before last frost; scorzonera can also be sown in late summer for next-year roots, as it is a biennial in most climates."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/2 inch deep in deeply loosened, rich soil; like salsify, roots fork in compacted ground. Scorzonera produces a black-skinned root with creamy white interior and a more refined flavor than salsify, often described as mildly nutty and sweet. Roots can be harvested in the first autumn when pencil-thick, but leaving them in the ground through winter and harvesting the following spring produces larger, sweeter roots. When harvesting, dig carefully as the roots are brittle and ooze a milky latex; peel under water to prevent discoloration.", "sources": ["general horticultural reference"]}')
