INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('scotch-bonnet','Scotch Bonnet','Capsicum chinense','vegetable','fruiting',10,21,80,90,100,120,'transplant','indoor-start','warm','tender','last_frost',-12,-10,'Start indoors 10–12 weeks before last frost; transplant 2 weeks after frost danger has passed once soil is thoroughly warm.',9,12,18,24,18,36,18,24,'full','moderate','Sow seeds 1/4 inch deep in moist starting mix, maintaining soil at 85°F for best germination results; this Capsicum chinense type is among the slower starters. Transplant into fertile, well-drained soil only after the garden is fully warm, and consider black plastic mulch to boost soil temperatures in cooler climates. The bonnet-shaped fruits ripen from green through yellow, orange, or red depending on the strain and carry a distinctive fruity aroma alongside intense heat. Use gloves when handling ripe fruits; they are essential in Caribbean jerk seasoning and hot sauces.','["general horticultural reference"]','{"slug": "scotch-bonnet", "common_name": "Scotch Bonnet", "scientific_name": "Capsicum chinense", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 80, "max": 90}, "days_to_maturity": {"min": 100, "max": 120}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -12, "max": -10}, "note": "Start indoors 10–12 weeks before last frost; transplant 2 weeks after frost danger has passed once soil is thoroughly warm."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in moist starting mix, maintaining soil at 85°F for best germination results; this Capsicum chinense type is among the slower starters. Transplant into fertile, well-drained soil only after the garden is fully warm, and consider black plastic mulch to boost soil temperatures in cooler climates. The bonnet-shaped fruits ripen from green through yellow, orange, or red depending on the strain and carry a distinctive fruity aroma alongside intense heat. Use gloves when handling ripe fruits; they are essential in Caribbean jerk seasoning and hot sauces.", "sources": ["general horticultural reference"]}')
