INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sea-kale','Sea Kale','Crambe maritima','vegetable','brassica',14,30,50,70,730,1095,'transplant','division','cool','hardy','spring',0,4,'Plant root cuttings (thongs) in early spring; plants establish slowly and should not be harvested until the second or third year.',4,9,24,36,24,36,24,36,'full','low','Plant root cuttings (thongs) 2–3 inches deep in deep, well-drained, sandy or gravelly soil with good lime content mimicking its native coastal habitat; sea kale is extremely drought and salt tolerant once established. The harvest is the blanched young shoots produced in early spring — cover crowns with a large pot or bucket to exclude light in late winter, and cut the pale, tender shoots when 6–8 inches tall. After harvesting the blanched shoots, remove the cover to allow the plant to photosynthesize and rebuild energy for the following year — do not blanch the same crown more than two consecutive years. The blanched shoots taste like a delicate cross between asparagus and cauliflower and have been a British garden delicacy since the 18th century.','["general horticultural reference"]','{"slug": "sea-kale", "common_name": "Sea Kale", "scientific_name": "Crambe maritima", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 14, "max": 30}, "germination_soil_temp_f": {"min": 50, "max": 70}, "days_to_maturity": {"min": 730, "max": 1095}, "maturity_from": "transplant", "sow_method": "division", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "spring", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Plant root cuttings (thongs) in early spring; plants establish slowly and should not be harvested until the second or third year."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "low", "directions": "Plant root cuttings (thongs) 2–3 inches deep in deep, well-drained, sandy or gravelly soil with good lime content mimicking its native coastal habitat; sea kale is extremely drought and salt tolerant once established. The harvest is the blanched young shoots produced in early spring — cover crowns with a large pot or bucket to exclude light in late winter, and cut the pale, tender shoots when 6–8 inches tall. After harvesting the blanched shoots, remove the cover to allow the plant to photosynthesize and rebuild energy for the following year — do not blanch the same crown more than two consecutive years. The blanched shoots taste like a delicate cross between asparagus and cauliflower and have been a British garden delicacy since the 18th century.", "sources": ["general horticultural reference"]}')
