INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sesame','Sesame','Sesamum indicum','vegetable','grain',5,10,70,95,90,120,'seed','direct','warm','tender','last_frost',1,4,'Sow after last frost when soil is thoroughly warm; sesame demands heat for germination and will rot in cool, wet soil.',7,11,6,12,36,60,8,12,'full','low','Sow seed 1/4 in deep in rows 18–24 in apart after soil reaches at least 70°F; sesame seed is very small, so mixing with dry sand aids even distribution and prevents clumping. Thin to 6–12 in once plants are 3 in tall and keep well-weeded until the canopy closes. The upright plants produce attractive tubular flowers along the stem that develop into rectangular seed capsules; the key challenge is timing harvest before ''shattering'' — when ripe capsules split and scatter seed spontaneously. Cut entire stalks when the bottom capsules begin to yellow, invert plants into large paper bags, and allow to dry for a week indoors; the capsules then split easily and seed falls into the bag when shaken.','["general horticultural reference"]','{"slug": "sesame", "common_name": "Sesame", "scientific_name": "Sesamum indicum", "category": "vegetable", "subcategory": "grain", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 70, "max": 95}, "days_to_maturity": {"min": 90, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 4}, "note": "Sow after last frost when soil is thoroughly warm; sesame demands heat for germination and will rot in cool, wet soil."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "low", "directions": "Sow seed 1/4 in deep in rows 18–24 in apart after soil reaches at least 70°F; sesame seed is very small, so mixing with dry sand aids even distribution and prevents clumping. Thin to 6–12 in once plants are 3 in tall and keep well-weeded until the canopy closes. The upright plants produce attractive tubular flowers along the stem that develop into rectangular seed capsules; the key challenge is timing harvest before ''shattering'' — when ripe capsules split and scatter seed spontaneously. Cut entire stalks when the bottom capsules begin to yellow, invert plants into large paper bags, and allow to dry for a week indoors; the capsules then split easily and seed falls into the bag when shaken.", "sources": ["general horticultural reference"]}')
