  VALUES ('shishito-pepper','Shishito Pepper','Capsicum annuum','vegetable','fruiting',7,21,70,85,60,75,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after frost danger passes into warm soil.',5,11,18,24,24,36,18,24,'full','moderate','Sow 1/4 inch deep at 80°F in starting mix; shishito germinates somewhat faster than most peppers and grows into a productive, bushy plant. Harvest the thin-walled, wrinkled green pods at 2–4 inches long; roughly 1 in 10 pods will be surprisingly hot while the rest are mild, which is a characteristic of this variety rather than a flaw. Blistering or pan-roasting whole peppers (popped in a hot dry skillet until charred in spots) is the classic preparation. Production is heavy and consistent through summer; keep picking to prevent fruit from ripening fully to red, which slows new pod development.','["general horticultural reference"]','{"slug": "shishito-pepper", "common_name": "Shishito Pepper", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 60, "max": 75}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after frost danger passes into warm soil."}, "usda_zones": {"min": 5, "max": 11}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow 1/4 inch deep at 80°F in starting mix; shishito germinates somewhat faster than most peppers and grows into a productive, bushy plant. Harvest the thin-walled, wrinkled green pods at 2–4 inches long; roughly 1 in 10 pods will be surprisingly hot while the rest are mild, which is a characteristic of this variety rather than a flaw. Blistering or pan-roasting whole peppers (popped in a hot dry skillet until charred in spots) is the classic preparation. Production is heavy and consistent through summer; keep picking to prevent fruit from ripening fully to red, which slows new pod development.", "sources": ["general horticultural reference"]}')
