INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('garland-chrysanthemum','Shungiku (Garland Chrysanthemum)','Glebionis coronaria','vegetable','leafy-green',7,14,50,70,30,50,'seed','direct','cool','half-hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost in spring; make a fall sowing 6–8 weeks before first frost for the best quality crop.',3,10,4,8,10,20,4,8,'full','moderate','Scatter seeds on prepared soil and cover lightly with 1/8 inch of soil; thin to 4–8 inches once seedlings are an inch tall and use thinnings in salads. Begin harvesting young shoot tips and leaves at 30 days by pinching the growing tip, which encourages the plant to branch and remain productive for several more weeks. The aromatic, slightly resinous leaves are a classic ingredient in Japanese hot pot and Chinese stir-fries, best harvested before the plant flowers. Flowers develop quickly in heat, so time the crop for cool weather or provide afternoon shade.','["general horticultural reference"]','{"slug": "garland-chrysanthemum", "common_name": "Shungiku (Garland Chrysanthemum)", "scientific_name": "Glebionis coronaria", "category": "vegetable", "subcategory": "leafy-green", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 50, "max": 70}, "days_to_maturity": {"min": 30, "max": 50}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost in spring; make a fall sowing 6–8 weeks before first frost for the best quality crop."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 4, "max": 8}, "height_in": {"min": 10, "max": 20}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "moderate", "directions": "Scatter seeds on prepared soil and cover lightly with 1/8 inch of soil; thin to 4–8 inches once seedlings are an inch tall and use thinnings in salads. Begin harvesting young shoot tips and leaves at 30 days by pinching the growing tip, which encourages the plant to branch and remain productive for several more weeks. The aromatic, slightly resinous leaves are a classic ingredient in Japanese hot pot and Chinese stir-fries, best harvested before the plant flowers. Flowers develop quickly in heat, so time the crop for cool weather or provide afternoon shade.", "sources": ["general horticultural reference"]}')
