  VALUES ('skirret','Skirret','Sium sisarum','vegetable','root',14,21,50,68,120,150,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost or start indoors 6 weeks early; established clumps can also be divided in spring.',3,8,9,12,24,36,12,18,'full','moderate','Sow seed 1/4 in deep in well-prepared, deeply cultivated soil; skirret produces a cluster of multiple sweet, carrot-like roots that need loose ground to develop well. Keep well-watered through summer as drought stress causes woody, fibrous roots with an unpleasant core. Harvest in autumn after frost, washing and separating the finger-sized roots; any woody central strings are removed before eating. Divide clumps in early spring to propagate, replanting the outer sections and discarding the old center.','["general horticultural reference"]','{"slug": "skirret", "common_name": "Skirret", "scientific_name": "Sium sisarum", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 14, "max": 21}, "germination_soil_temp_f": {"min": 50, "max": 68}, "days_to_maturity": {"min": 120, "max": 150}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost or start indoors 6 weeks early; established clumps can also be divided in spring."}, "usda_zones": {"min": 3, "max": 8}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 24, "max": 36}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep in well-prepared, deeply cultivated soil; skirret produces a cluster of multiple sweet, carrot-like roots that need loose ground to develop well. Keep well-watered through summer as drought stress causes woody, fibrous roots with an unpleasant core. Harvest in autumn after frost, washing and separating the finger-sized roots; any woody central strings are removed before eating. Divide clumps in early spring to propagate, replanting the outer sections and discarding the old center.", "sources": ["general horticultural reference"]}')
