INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('snake-gourd','Snake Gourd','Trichosanthes cucumerina','vegetable','cucurbit',7,14,75,90,60,90,'seed','direct','warm','tender','last_frost',1,3,'Direct sow 1–3 weeks after last frost once soil reaches 75°F; a truly tropical vine requiring a long, hot summer.',9,12,24,36,72,144,24,48,'full','moderate','Nick the seed coat or soak seeds 24 hours before sowing 1/2 inch deep to improve germination rates in this heat-demanding tropical. Provide a tall, sturdy trellis or overhead structure — vines can exceed 12 feet and produce pendulous fruits that must hang freely to grow straight, reaching 1–3 feet in length. Harvest young fruits at 12–18 inches while skin is still soft and pale green-striped white; the tender young fruit is used like summer squash in South and Southeast Asian cooking. Overripe fruits develop an unpleasant bitter compound and turn orange-red, signaling they should be discarded rather than eaten.','["general horticultural reference"]','{"slug": "snake-gourd", "common_name": "Snake Gourd", "scientific_name": "Trichosanthes cucumerina", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 75, "max": 90}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 3}, "note": "Direct sow 1–3 weeks after last frost once soil reaches 75°F; a truly tropical vine requiring a long, hot summer."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 72, "max": 144}, "spread_in": {"min": 24, "max": 48}, "sun": "full", "water": "moderate", "directions": "Nick the seed coat or soak seeds 24 hours before sowing 1/2 inch deep to improve germination rates in this heat-demanding tropical. Provide a tall, sturdy trellis or overhead structure — vines can exceed 12 feet and produce pendulous fruits that must hang freely to grow straight, reaching 1–3 feet in length. Harvest young fruits at 12–18 inches while skin is still soft and pale green-striped white; the tender young fruit is used like summer squash in South and Southeast Asian cooking. Overripe fruits develop an unpleasant bitter compound and turn orange-red, signaling they should be discarded rather than eaten.", "sources": ["general horticultural reference"]}')
