INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('spaghetti-squash','Spaghetti Squash','Cucurbita pepo','vegetable','cucurbit',4,10,60,95,80,100,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost once soil temperature reaches 65°F.',3,10,36,48,12,18,60,96,'full','moderate','Sow seeds 1 inch deep in warm, compost-enriched hills, placing 3 seeds per hill and thinning to 1–2 plants. Give vines ample room to spread, or train onto a strong trellis and support heavy fruits with a sling. The rind turns from pale green to golden yellow when mature and will feel hard when pressed. Allow picked fruits to cure in a warm spot for 1–2 weeks before using or storing; they keep for several months in a cool, dry room.','["general horticultural reference"]','{"slug": "spaghetti-squash", "common_name": "Spaghetti Squash", "scientific_name": "Cucurbita pepo", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 60, "max": 95}, "days_to_maturity": {"min": 80, "max": 100}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost once soil temperature reaches 65°F."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 36, "max": 48}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 60, "max": 96}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 inch deep in warm, compost-enriched hills, placing 3 seeds per hill and thinning to 1–2 plants. Give vines ample room to spread, or train onto a strong trellis and support heavy fruits with a sling. The rind turns from pale green to golden yellow when mature and will feel hard when pressed. Allow picked fruits to cure in a warm spot for 1–2 weeks before using or storing; they keep for several months in a cool, dry room.", "sources": ["general horticultural reference"]}')
