INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('spelt','Spelt','Triticum spelta','vegetable','grain',5,10,40,75,250,280,'seed','direct','cool','hardy','first_frost',-6,-2,'Sow 2–6 weeks before the first fall frost; spelt establishes before winter dormancy and resumes vigorous growth in early spring.',4,9,1,2,36,60,3,6,'full','low','Drill or broadcast seed at 80–100 lb per acre (approximately 2–3 oz per 100 sq ft) in fall to 1 in depth; spelt is taller than modern wheat and slightly more susceptible to lodging in rich soils, so avoid high-nitrogen amendments. It tolerates clay and compacted soils better than most small grains and has reasonable resistance to rust diseases. Harvest at hard dough stage in early summer by cutting, sheaving, and drying for a week before threshing; spelt retains a tough hull (spikelet) that requires a dedicated pearler or dehuller before milling. The resulting flour has a mild, nutty flavor and is widely used by those who tolerate ancient wheats better than modern varieties, though it does contain gluten.','["general horticultural reference"]','{"slug": "spelt", "common_name": "Spelt", "scientific_name": "Triticum spelta", "category": "vegetable", "subcategory": "grain", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 40, "max": 75}, "days_to_maturity": {"min": 250, "max": 280}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -6, "max": -2}, "note": "Sow 2–6 weeks before the first fall frost; spelt establishes before winter dormancy and resumes vigorous growth in early spring."}, "usda_zones": {"min": 4, "max": 9}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 36, "max": 60}, "spread_in": {"min": 3, "max": 6}, "sun": "full", "water": "low", "directions": "Drill or broadcast seed at 80–100 lb per acre (approximately 2–3 oz per 100 sq ft) in fall to 1 in depth; spelt is taller than modern wheat and slightly more susceptible to lodging in rich soils, so avoid high-nitrogen amendments. It tolerates clay and compacted soils better than most small grains and has reasonable resistance to rust diseases. Harvest at hard dough stage in early summer by cutting, sheaving, and drying for a week before threshing; spelt retains a tough hull (spikelet) that requires a dedicated pearler or dehuller before milling. The resulting flour has a mild, nutty flavor and is widely used by those who tolerate ancient wheats better than modern varieties, though it does contain gluten.", "sources": ["general horticultural reference"]}')
