  VALUES ('straightneck-squash','Straightneck Squash','Cucurbita pepo','vegetable','cucurbit',4,10,60,95,48,65,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost once soil is warm.',3,10,24,36,18,30,24,48,'full','moderate','Plant seeds 1 inch deep in warm, loose, well-drained soil enriched with aged compost. Thin to one plant per hill and keep the bed consistently moist throughout the growing season. Monitor frequently for squash vine borers and squash bugs, which are the most serious pests. Harvest fruits at 6–8 inches long while the skin is still soft and pale yellow for the best flavor and texture.','["general horticultural reference"]','{"slug": "straightneck-squash", "common_name": "Straightneck Squash", "scientific_name": "Cucurbita pepo", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 60, "max": 95}, "days_to_maturity": {"min": 48, "max": 65}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost once soil is warm."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 18, "max": 30}, "spread_in": {"min": 24, "max": 48}, "sun": "full", "water": "moderate", "directions": "Plant seeds 1 inch deep in warm, loose, well-drained soil enriched with aged compost. Thin to one plant per hill and keep the bed consistently moist throughout the growing season. Monitor frequently for squash vine borers and squash bugs, which are the most serious pests. Harvest fruits at 6–8 inches long while the skin is still soft and pale yellow for the best flavor and texture.", "sources": ["general horticultural reference"]}')
