INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('sunflower-oilseed','Sunflower (Oilseed Type)','Helianthus annuus','vegetable','oilseed',5,10,50,85,80,110,'seed','direct','warm','tender','last_frost',0,4,'Direct-sow at or after last frost; oilseed sunflower varieties have smaller, black-hulled seeds with a higher oil percentage than confection types.',3,10,8,12,48,84,12,24,'full','low','Plant seed 1 in deep and 8–12 in apart in rows spaced 24–30 in; oilseed varieties like ''Peredovik'' or ''Rostov'' are grown more densely than confection types to reduce branching and produce a single large head per plant. Harvest when the back of the head turns yellow to brown and the seeds are hard — cut heads and hang upside-down in a covered, airy space to cure. Rub seeds out over a screen, then cold-press for oil or roast and use as a whole food. Birds are the main pest; protect ripening heads with netting or paper bags.','["general horticultural reference"]','{"slug": "sunflower-oilseed", "common_name": "Sunflower (Oilseed Type)", "scientific_name": "Helianthus annuus", "category": "vegetable", "subcategory": "oilseed", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 50, "max": 85}, "days_to_maturity": {"min": 80, "max": 110}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 4}, "note": "Direct-sow at or after last frost; oilseed sunflower varieties have smaller, black-hulled seeds with a higher oil percentage than confection types."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 8, "max": 12}, "height_in": {"min": 48, "max": 84}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "low", "directions": "Plant seed 1 in deep and 8–12 in apart in rows spaced 24–30 in; oilseed varieties like ''Peredovik'' or ''Rostov'' are grown more densely than confection types to reduce branching and produce a single large head per plant. Harvest when the back of the head turns yellow to brown and the seeds are hard — cut heads and hang upside-down in a covered, airy space to cure. Rub seeds out over a screen, then cold-press for oil or roast and use as a whole food. Birds are the main pest; protect ripening heads with netting or paper bags.", "sources": ["general horticultural reference"]}')
