INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('tabasco-pepper','Tabasco Pepper','Capsicum frutescens','vegetable','fruiting',10,21,75,85,80,100,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed and soil has warmed to at least 65°F.',8,12,18,24,24,48,18,24,'full','moderate','Sow seeds 1/4 inch deep in warm starting mix and provide consistent heat of 80°F until seedlings emerge. Transplant to well-drained soil in the sunniest garden position, as Capsicum frutescens types thrive with maximum heat accumulation throughout the season. Distinctive erect fruits ripen from yellow-green through yellow and orange to red; harvest at the red stage for the highest capsaicin concentration. Plants are short-lived perennials in frost-free climates and can be overwintered in pots to produce a second heavy crop.','["general horticultural reference"]','{"slug": "tabasco-pepper", "common_name": "Tabasco Pepper", "scientific_name": "Capsicum frutescens", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 10, "max": 21}, "germination_soil_temp_f": {"min": 75, "max": 85}, "days_to_maturity": {"min": 80, "max": 100}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed and soil has warmed to at least 65°F."}, "usda_zones": {"min": 8, "max": 12}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm starting mix and provide consistent heat of 80°F until seedlings emerge. Transplant to well-drained soil in the sunniest garden position, as Capsicum frutescens types thrive with maximum heat accumulation throughout the season. Distinctive erect fruits ripen from yellow-green through yellow and orange to red; harvest at the red stage for the highest capsaicin concentration. Plants are short-lived perennials in frost-free climates and can be overwintered in pots to produce a second heavy crop.", "sources": ["general horticultural reference"]}')
