INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('taro','Taro','Colocasia esculenta','vegetable','root',NULL,NULL,65,85,180,270,'transplant','tuber','warm','tender','last_frost',0,2,'Plant corms at or just after last frost once soil reaches 65°F; in zones 8–11 taro may stay in the ground year-round.',8,12,18,24,36,72,24,48,'partial','high','Plant small corms or corm sections 2–3 inches deep in moist to wet, organically rich soil; taro grows naturally in waterlogged conditions and tolerates standing water at the margins of ponds and streams. Provide afternoon shade in the hottest climates to prevent leaf scorch, and keep the soil consistently moist throughout the growing season — drought stress greatly reduces corm size. Harvest when the large shield-shaped leaves begin to yellow and die back, typically 6–9 months after planting, carefully digging corms to avoid damage. The corms must be thoroughly cooked before eating to neutralize calcium oxalate crystals that cause intense mouth irritation in raw form; young leaves and stems are also edible when cooked.','["general horticultural reference"]','{"slug": "taro", "common_name": "Taro", "scientific_name": "Colocasia esculenta", "category": "vegetable", "subcategory": "root", "days_to_germination": null, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 180, "max": 270}, "maturity_from": "transplant", "sow_method": "tuber", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Plant corms at or just after last frost once soil reaches 65°F; in zones 8–11 taro may stay in the ground year-round."}, "usda_zones": {"min": 8, "max": 12}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 36, "max": 72}, "spread_in": {"min": 24, "max": 48}, "sun": "partial", "water": "high", "directions": "Plant small corms or corm sections 2–3 inches deep in moist to wet, organically rich soil; taro grows naturally in waterlogged conditions and tolerates standing water at the margins of ponds and streams. Provide afternoon shade in the hottest climates to prevent leaf scorch, and keep the soil consistently moist throughout the growing season — drought stress greatly reduces corm size. Harvest when the large shield-shaped leaves begin to yellow and die back, typically 6–9 months after planting, carefully digging corms to avoid damage. The corms must be thoroughly cooked before eating to neutralize calcium oxalate crystals that cause intense mouth irritation in raw form; young leaves and stems are also edible when cooked.", "sources": ["general horticultural reference"]}')
