INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('tatsoi','Tatsoi','Brassica rapa var. narinosa','vegetable','brassica',4,7,45,75,45,50,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost; excels as a fall crop sown 6–8 weeks before first frost, as light freezes sweeten the leaves.',3,10,6,12,4,8,8,12,'full','moderate','Sow seeds 1/4 inch deep and thin to 6–12 inches for full rosettes; closer spacing produces baby greens for salad mix. Tatsoi forms a flat, ground-hugging rosette of dark spoon-shaped leaves and is remarkably cold-hardy, surviving temperatures into the low 20s°F under row cover. Harvest whole plants when 4–6 inches across or pick outer leaves progressively. Avoid planting in summer as heat causes immediate bolting.','["general horticultural reference"]','{"slug": "tatsoi", "common_name": "Tatsoi", "scientific_name": "Brassica rapa var. narinosa", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 45, "max": 75}, "days_to_maturity": {"min": 45, "max": 50}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost; excels as a fall crop sown 6–8 weeks before first frost, as light freezes sweeten the leaves."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 4, "max": 8}, "spread_in": {"min": 8, "max": 12}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep and thin to 6–12 inches for full rosettes; closer spacing produces baby greens for salad mix. Tatsoi forms a flat, ground-hugging rosette of dark spoon-shaped leaves and is remarkably cold-hardy, surviving temperatures into the low 20s°F under row cover. Harvest whole plants when 4–6 inches across or pick outer leaves progressively. Avoid planting in summer as heat causes immediate bolting.", "sources": ["general horticultural reference"]}')
