  VALUES ('teff-grain','Teff (Grain)','Eragrostis tef','vegetable','grain',3,7,60,85,75,120,'seed','direct','warm','tender','last_frost',1,6,'Sow after last frost when soil is warm; teff tolerates both waterlogged and drought conditions better than most grain crops.',5,10,1,2,24,48,4,8,'full','moderate','Surface-broadcast seed — it is extremely small (poppy-seed sized) and must not be buried; mix seed with sand to achieve even distribution at roughly 2–3 lb per 1,000 sq ft, then press lightly with a roller or board for good soil contact. Teff tillers prolifically and forms a graceful, open canopy with hundreds of fine panicles per plant; harvest the entire plant at the base when the majority of seeds have turned brown but before they shatter in a breeze. Thresh by beating bundles over a smooth tarp and winnow carefully in a gentle airflow — the seed is light and easily blown away. Teff grain is naturally gluten-free and is the basis for Ethiopian injera flatbread.','["general horticultural reference"]','{"slug": "teff-grain", "common_name": "Teff (Grain)", "scientific_name": "Eragrostis tef", "category": "vegetable", "subcategory": "grain", "days_to_germination": {"min": 3, "max": 7}, "germination_soil_temp_f": {"min": 60, "max": 85}, "days_to_maturity": {"min": 75, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 6}, "note": "Sow after last frost when soil is warm; teff tolerates both waterlogged and drought conditions better than most grain crops."}, "usda_zones": {"min": 5, "max": 10}, "spacing_in": {"min": 1, "max": 2}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 4, "max": 8}, "sun": "full", "water": "moderate", "directions": "Surface-broadcast seed — it is extremely small (poppy-seed sized) and must not be buried; mix seed with sand to achieve even distribution at roughly 2–3 lb per 1,000 sq ft, then press lightly with a roller or board for good soil contact. Teff tillers prolifically and forms a graceful, open canopy with hundreds of fine panicles per plant; harvest the entire plant at the base when the majority of seeds have turned brown but before they shatter in a breeze. Thresh by beating bundles over a smooth tarp and winnow carefully in a gentle airflow — the seed is light and easily blown away. Teff grain is naturally gluten-free and is the basis for Ethiopian injera flatbread.", "sources": ["general horticultural reference"]}')
