INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('tepary-bean','Tepary Bean','Phaseolus acutifolius','vegetable','legume',5,10,65,90,60,80,'seed','direct','warm','tender','last_frost',2,6,'Direct sow 2–6 weeks after last frost once soil reaches 65°F; tepary bean is a drought-adapted desert crop that actually produces poorly in wet soils.',7,11,6,9,18,36,9,18,'full','low','Sow seeds 1 inch deep directly into very well-drained, low-fertility, sandy or rocky desert-type soil after the soil is thoroughly warm; avoid overwatering, as excess moisture promotes disease and poor productivity in this drought-adapted species. Tepary bean is an ancient domesticate of the Sonoran Desert and O''odham peoples, capable of completing its life cycle on surprisingly little water. Both vining and bush types exist; most modern varieties are semi-vining and benefit from support. Harvest entire plants when the majority of pods have dried and rattled, thresh the seeds, and dry thoroughly before storage; the small seeds (white, brown, tan, or speckled) are high in protein and have a nutty, earthy flavor excellent in Southwest-style soups and stews.','["general horticultural reference"]','{"slug": "tepary-bean", "common_name": "Tepary Bean", "scientific_name": "Phaseolus acutifolius", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 65, "max": 90}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 6}, "note": "Direct sow 2–6 weeks after last frost once soil reaches 65°F; tepary bean is a drought-adapted desert crop that actually produces poorly in wet soils."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 6, "max": 9}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 9, "max": 18}, "sun": "full", "water": "low", "directions": "Sow seeds 1 inch deep directly into very well-drained, low-fertility, sandy or rocky desert-type soil after the soil is thoroughly warm; avoid overwatering, as excess moisture promotes disease and poor productivity in this drought-adapted species. Tepary bean is an ancient domesticate of the Sonoran Desert and O''odham peoples, capable of completing its life cycle on surprisingly little water. Both vining and bush types exist; most modern varieties are semi-vining and benefit from support. Harvest entire plants when the majority of pods have dried and rattled, thresh the seeds, and dry thoroughly before storage; the small seeds (white, brown, tan, or speckled) are high in protein and have a nutty, earthy flavor excellent in Southwest-style soups and stews.", "sources": ["general horticultural reference"]}')
