INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('thai-chili-pepper','Thai Chili Pepper (Bird''s Eye Chili)','Capsicum annuum','vegetable','fruiting',7,21,75,90,70,90,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed and nights stay above 55°F.',9,12,18,24,24,48,18,24,'full','moderate','Sow 1/4 inch deep in warm starting mix at 82–85°F; Thai chili needs more heat for germination than most C. annuum types. Plants are compact and extremely productive, bearing dozens of small (1–2 inch) upright fruits that ripen from green to bright red and carry intense heat of 50,000–100,000 Scoville units. Harvest red-ripe fruits for maximum heat and full flavor; the plants can be brought indoors as houseplants before frost and often survive multiple seasons. Excellent for drying — the small fruits air-dry on the plant or can be strung and hung in a warm spot.','["general horticultural reference"]','{"slug": "thai-chili-pepper", "common_name": "Thai Chili Pepper (Bird''s Eye Chili)", "scientific_name": "Capsicum annuum", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 21}, "germination_soil_temp_f": {"min": 75, "max": 90}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after all frost danger has passed and nights stay above 55°F."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow 1/4 inch deep in warm starting mix at 82–85°F; Thai chili needs more heat for germination than most C. annuum types. Plants are compact and extremely productive, bearing dozens of small (1–2 inch) upright fruits that ripen from green to bright red and carry intense heat of 50,000–100,000 Scoville units. Harvest red-ripe fruits for maximum heat and full flavor; the plants can be brought indoors as houseplants before frost and often survive multiple seasons. Excellent for drying — the small fruits air-dry on the plant or can be strung and hung in a warm spot.", "sources": ["general horticultural reference"]}')
