INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('thai-eggplant','Thai Eggplant','Solanum melongena','vegetable','fruiting',7,14,75,90,70,90,'transplant','indoor-start','warm','tender','last_frost',-10,-8,'Start indoors 8–10 weeks before last frost; transplant after soil warms to at least 65°F and all frost danger has passed.',5,12,18,24,24,48,18,30,'full','moderate','Sow seeds 1/4 inch deep in warm starting mix at 80–85°F and maintain consistent heat throughout the seedling stage; Thai eggplant germinates and grows faster than larger-fruited types. Transplant to a warm, sheltered bed after last frost and mulch heavily to retain soil warmth. The round, golf ball-sized fruits ripen from white-striped green to fully white or yellow depending on the cultivar, and are harvested while still firm and slightly underripe for use in Thai green curry. Overripe fruits become bitter; check plants every 2–3 days and harvest promptly to keep plants productive.','["general horticultural reference"]','{"slug": "thai-eggplant", "common_name": "Thai Eggplant", "scientific_name": "Solanum melongena", "category": "vegetable", "subcategory": "fruiting", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 75, "max": 90}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "transplant", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Start indoors 8–10 weeks before last frost; transplant after soil warms to at least 65°F and all frost danger has passed."}, "usda_zones": {"min": 5, "max": 12}, "spacing_in": {"min": 18, "max": 24}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 18, "max": 30}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in warm starting mix at 80–85°F and maintain consistent heat throughout the seedling stage; Thai eggplant germinates and grows faster than larger-fruited types. Transplant to a warm, sheltered bed after last frost and mulch heavily to retain soil warmth. The round, golf ball-sized fruits ripen from white-striped green to fully white or yellow depending on the cultivar, and are harvested while still firm and slightly underripe for use in Thai green curry. Overripe fruits become bitter; check plants every 2–3 days and harvest promptly to keep plants productive.", "sources": ["general horticultural reference"]}')
