INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('turnip','Turnip','Brassica rapa subsp. rapa','vegetable','root',4,10,45,85,40,60,'seed','direct','cool','hardy','last_frost',-4,-2,'Sow 2–4 weeks before last frost for spring harvest, or 6–8 weeks before first frost for a fall crop.',2,11,4,6,8,16,4,6,'full','moderate','Broadcast or drill seed 1/4 to 1/2 in deep and thin to 4–6 in when seedlings are 2–3 in tall; use the tops as nutritious braising greens. Cool weather sweetens turnips considerably, and fall-sown roots are typically milder than spring ones. Harvest at 2–3 in diameter for the best tenderness; larger roots become woody and sharp in flavor. Flea beetles can disfigure foliage — row cover offers good protection early in the season.','["general horticultural reference"]','{"slug": "turnip", "common_name": "Turnip", "scientific_name": "Brassica rapa subsp. rapa", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 45, "max": 85}, "days_to_maturity": {"min": 40, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Sow 2–4 weeks before last frost for spring harvest, or 6–8 weeks before first frost for a fall crop."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 8, "max": 16}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Broadcast or drill seed 1/4 to 1/2 in deep and thin to 4–6 in when seedlings are 2–3 in tall; use the tops as nutritious braising greens. Cool weather sweetens turnips considerably, and fall-sown roots are typically milder than spring ones. Harvest at 2–3 in diameter for the best tenderness; larger roots become woody and sharp in flavor. Flea beetles can disfigure foliage — row cover offers good protection early in the season.", "sources": ["general horticultural reference"]}')
