  VALUES ('turnip-greens','Turnip Greens','Brassica rapa subsp. rapa','vegetable','brassica',4,7,40,80,30,60,'seed','direct','cool','hardy','last_frost',-4,-2,'Direct sow 2–4 weeks before last frost for spring; sow again in early fall for a second crop of sweet greens.',2,9,4,6,10,18,6,10,'full','moderate','Sow seed 1/4 in deep in fertile soil; turnips are among the fastest-germinating brassicas and begin producing harvestable greens within a month. Thin to 4–6 in if growing for both greens and roots, or leave closer together for greens-only production. Begin harvesting outer leaves when plants are 6–8 in tall, leaving the crown to continue growing. Fall-harvested greens are noticeably sweeter than spring greens due to the conversion of starches to sugars in cool temperatures.','["general horticultural reference"]','{"slug": "turnip-greens", "common_name": "Turnip Greens", "scientific_name": "Brassica rapa subsp. rapa", "category": "vegetable", "subcategory": "brassica", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 40, "max": 80}, "days_to_maturity": {"min": 30, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Direct sow 2–4 weeks before last frost for spring; sow again in early fall for a second crop of sweet greens."}, "usda_zones": {"min": 2, "max": 9}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 10, "max": 18}, "spread_in": {"min": 6, "max": 10}, "sun": "full", "water": "moderate", "directions": "Sow seed 1/4 in deep in fertile soil; turnips are among the fastest-germinating brassicas and begin producing harvestable greens within a month. Thin to 4–6 in if growing for both greens and roots, or leave closer together for greens-only production. Begin harvesting outer leaves when plants are 6–8 in tall, leaving the crown to continue growing. Fall-harvested greens are noticeably sweeter than spring greens due to the conversion of starches to sugars in cool temperatures.", "sources": ["general horticultural reference"]}')
