INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('ulluco','Ulluco','Ullucus tuberosus','vegetable','root',NULL,NULL,50,65,180,210,'transplant','tuber','cool','half-hardy','last_frost',-2,0,'Plant tubers at or just before last frost in cool, moist soil; ulluco initiates tubers only as day length shortens in fall.',7,10,12,15,12,18,12,18,'full','moderate','Plant small seed tubers 3 inches deep in loose, fertile, well-drained soil as early in spring as soil can be worked; ulluco is an Andean root crop closely related to beets that prefers cool, foggy conditions and struggles in summer heat above 80°F. The attractive heart-shaped leaves are glossy and edible as salad greens throughout the season, adding a mild, slightly mucilaginous element similar to malabar spinach. Tuber formation is triggered by short days in autumn, so harvest cannot begin until after the first frost kills the foliage, typically in October or November. The small, colorful tubers (yellow, orange, red, or purple-streaked) are waxy and hold their shape when cooked; boil, roast, or stir-fry in the same way as fingerling potatoes.','["general horticultural reference"]','{"slug": "ulluco", "common_name": "Ulluco", "scientific_name": "Ullucus tuberosus", "category": "vegetable", "subcategory": "root", "days_to_germination": null, "germination_soil_temp_f": {"min": 50, "max": 65}, "days_to_maturity": {"min": 180, "max": 210}, "maturity_from": "transplant", "sow_method": "tuber", "season": "cool", "frost_tolerance": "half-hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -2, "max": 0}, "note": "Plant tubers at or just before last frost in cool, moist soil; ulluco initiates tubers only as day length shortens in fall."}, "usda_zones": {"min": 7, "max": 10}, "spacing_in": {"min": 12, "max": 15}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 12, "max": 18}, "sun": "full", "water": "moderate", "directions": "Plant small seed tubers 3 inches deep in loose, fertile, well-drained soil as early in spring as soil can be worked; ulluco is an Andean root crop closely related to beets that prefers cool, foggy conditions and struggles in summer heat above 80°F. The attractive heart-shaped leaves are glossy and edible as salad greens throughout the season, adding a mild, slightly mucilaginous element similar to malabar spinach. Tuber formation is triggered by short days in autumn, so harvest cannot begin until after the first frost kills the foliage, typically in October or November. The small, colorful tubers (yellow, orange, red, or purple-streaked) are waxy and hold their shape when cooked; boil, roast, or stir-fry in the same way as fingerling potatoes.", "sources": ["general horticultural reference"]}')
