INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('water-chestnut','Water Chestnut','Eleocharis dulcis','vegetable','root',NULL,NULL,65,85,180,240,'transplant','tuber','warm','tender','last_frost',2,4,'Plant sprouted corms 2–4 weeks after last frost once water temperatures exceed 60°F in a container or shallow pond.',8,12,9,12,24,48,9,12,'full','high','Sprout small corms in a tray of moist soil indoors a few weeks before transplanting; plant sprouted corms 1–2 inches deep in the mud bottom of containers, tubs, or shallow water features kept filled to 2–4 inches above the soil surface. Water chestnuts are tropical grass-like sedges grown for their crunchy, sweet corms that form in the mud at the base of the rush-like stems. Drain the growing container in early fall before frost and allow the foliage to die back completely, then harvest corms by sifting through the mud; the crisp, mild corms can be eaten raw or cooked and retain their crunch even after stir-frying. In frost-prone climates store harvested corms in moist sand in a cool (40°F) location and re-plant the following spring.','["general horticultural reference"]','{"slug": "water-chestnut", "common_name": "Water Chestnut", "scientific_name": "Eleocharis dulcis", "category": "vegetable", "subcategory": "root", "days_to_germination": null, "germination_soil_temp_f": {"min": 65, "max": 85}, "days_to_maturity": {"min": 180, "max": 240}, "maturity_from": "transplant", "sow_method": "tuber", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 4}, "note": "Plant sprouted corms 2–4 weeks after last frost once water temperatures exceed 60°F in a container or shallow pond."}, "usda_zones": {"min": 8, "max": 12}, "spacing_in": {"min": 9, "max": 12}, "height_in": {"min": 24, "max": 48}, "spread_in": {"min": 9, "max": 12}, "sun": "full", "water": "high", "directions": "Sprout small corms in a tray of moist soil indoors a few weeks before transplanting; plant sprouted corms 1–2 inches deep in the mud bottom of containers, tubs, or shallow water features kept filled to 2–4 inches above the soil surface. Water chestnuts are tropical grass-like sedges grown for their crunchy, sweet corms that form in the mud at the base of the rush-like stems. Drain the growing container in early fall before frost and allow the foliage to die back completely, then harvest corms by sifting through the mud; the crisp, mild corms can be eaten raw or cooked and retain their crunch even after stir-frying. In frost-prone climates store harvested corms in moist sand in a cool (40°F) location and re-plant the following spring.", "sources": ["general horticultural reference"]}')
