INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('water-spinach','Water Spinach (Kangkong)','Ipomoea aquatica','vegetable','greens',5,10,70,90,30,50,'seed','direct','warm','tender','last_frost',2,4,'Direct sow or transplant stem cuttings 2–4 weeks after last frost once soil and water temperatures are consistently warm.',9,12,6,12,12,24,12,24,'full','high','Sow seeds 1/2 inch deep or root stem cuttings in moist to waterlogged soil; this semi-aquatic vine thrives in boggy beds, the margins of ponds, or in containers of shallow water. Harvest young shoot tips and tender leaves 4–6 inches long by snipping with scissors; plants regrow quickly and can be cut every 2–3 weeks throughout the warm season. The hollow stems and arrowhead-shaped leaves are a staple of Thai, Filipino, Chinese, and Indonesian cooking, most famously stir-fried with garlic and shrimp paste. Note that cultivation is restricted in some U.S. states due to invasive potential in warm climates; check local regulations before planting outdoors.','["general horticultural reference"]','{"slug": "water-spinach", "common_name": "Water Spinach (Kangkong)", "scientific_name": "Ipomoea aquatica", "category": "vegetable", "subcategory": "greens", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 70, "max": 90}, "days_to_maturity": {"min": 30, "max": 50}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 4}, "note": "Direct sow or transplant stem cuttings 2–4 weeks after last frost once soil and water temperatures are consistently warm."}, "usda_zones": {"min": 9, "max": 12}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "high", "directions": "Sow seeds 1/2 inch deep or root stem cuttings in moist to waterlogged soil; this semi-aquatic vine thrives in boggy beds, the margins of ponds, or in containers of shallow water. Harvest young shoot tips and tender leaves 4–6 inches long by snipping with scissors; plants regrow quickly and can be cut every 2–3 weeks throughout the warm season. The hollow stems and arrowhead-shaped leaves are a staple of Thai, Filipino, Chinese, and Indonesian cooking, most famously stir-fried with garlic and shrimp paste. Note that cultivation is restricted in some U.S. states due to invasive potential in warm climates; check local regulations before planting outdoors.", "sources": ["general horticultural reference"]}')
