INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('watercress','Watercress','Nasturtium officinale','vegetable','leafy green',7,14,50,68,50,70,'seed','direct','cool','hardy','last_frost',-4,-2,'Sow in cool, wet conditions 2–4 weeks before last frost; can also be started from cuttings rooted in water.',3,11,6,8,4,10,8,12,'partial','high','Sow seed on the surface of consistently moist, fertile soil near a stream, pond edge, or other reliably wet site; watercress requires more water than almost any other salad green. In garden beds without standing water, water deeply every day and mulch heavily to retain moisture. Harvest stem tips of 4–6 in regularly to encourage bushy growth; the plant becomes bitter and coarse after flowering. Succession plantings from rooted stem cuttings placed in shallow water provide a continuous supply through the cool season.','["general horticultural reference"]','{"slug": "watercress", "common_name": "Watercress", "scientific_name": "Nasturtium officinale", "category": "vegetable", "subcategory": "leafy green", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 50, "max": 68}, "days_to_maturity": {"min": 50, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -2}, "note": "Sow in cool, wet conditions 2–4 weeks before last frost; can also be started from cuttings rooted in water."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 6, "max": 8}, "height_in": {"min": 4, "max": 10}, "spread_in": {"min": 8, "max": 12}, "sun": "partial", "water": "high", "directions": "Sow seed on the surface of consistently moist, fertile soil near a stream, pond edge, or other reliably wet site; watercress requires more water than almost any other salad green. In garden beds without standing water, water deeply every day and mulch heavily to retain moisture. Harvest stem tips of 4–6 in regularly to encourage bushy growth; the plant becomes bitter and coarse after flowering. Succession plantings from rooted stem cuttings placed in shallow water provide a continuous supply through the cool season.", "sources": ["general horticultural reference"]}')
