INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('watermelon','Watermelon','Citrullus lanatus','vegetable','cucurbit',3,10,70,95,70,90,'seed','direct','warm','tender','last_frost',1,3,'Direct sow 1–3 weeks after last frost once soil temperature reaches at least 70°F; or start indoors 2–3 weeks early.',3,11,36,72,12,18,72,144,'full','moderate','Sow seeds 1 inch deep in warm, sandy loam hills with generous compost worked in; watermelons thrive with long, hot summers. Avoid overhead irrigation once fruits are sizing up, as uneven moisture causes cracking. Ripeness indicators include a dull surface sheen replacing the glossy skin, a cream or yellow ground spot on the underside, and a dry tendril nearest the fruit. Thump the fruit and listen for a deep, hollow resonance to confirm ripeness.','["general horticultural reference"]','{"slug": "watermelon", "common_name": "Watermelon", "scientific_name": "Citrullus lanatus", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 3, "max": 10}, "germination_soil_temp_f": {"min": 70, "max": 95}, "days_to_maturity": {"min": 70, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 3}, "note": "Direct sow 1–3 weeks after last frost once soil temperature reaches at least 70°F; or start indoors 2–3 weeks early."}, "usda_zones": {"min": 3, "max": 11}, "spacing_in": {"min": 36, "max": 72}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 72, "max": 144}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 inch deep in warm, sandy loam hills with generous compost worked in; watermelons thrive with long, hot summers. Avoid overhead irrigation once fruits are sizing up, as uneven moisture causes cracking. Ripeness indicators include a dull surface sheen replacing the glossy skin, a cream or yellow ground spot on the underside, and a dry tendril nearest the fruit. Thump the fruit and listen for a deep, hollow resonance to confirm ripeness.", "sources": ["general horticultural reference"]}')
