  VALUES ('watermelon-radish','Watermelon Radish','Raphanus sativus','vegetable','root',4,7,45,70,55,70,'seed','direct','cool','hardy','first_frost',-10,-8,'Sow 8–10 weeks before first fall frost for the sweetest, most vibrant roots; spring plantings are possible but fall is strongly preferred.',2,11,4,6,6,12,4,6,'full','moderate','Direct sow seeds 1/2 inch deep in loose, deeply prepared, stone-free soil in late summer or early fall; thin seedlings to 4–6 inches for proper root development. Watermelon radish is a Chinese heirloom daikon type with a pale green exterior that conceals a vivid magenta-to-pink interior resembling watermelon flesh. Fall planting is strongly preferred over spring — cool nights concentrate sugars and deepen the interior color while reducing pungency. Harvest when roots reach 2–3 inches in diameter; slice thinly for salads, pickle in rice vinegar, or roast where the color intensifies to brilliant crimson.','["general horticultural reference"]','{"slug": "watermelon-radish", "common_name": "Watermelon Radish", "scientific_name": "Raphanus sativus", "category": "vegetable", "subcategory": "root", "days_to_germination": {"min": 4, "max": 7}, "germination_soil_temp_f": {"min": 45, "max": 70}, "days_to_maturity": {"min": 55, "max": 70}, "maturity_from": "seed", "sow_method": "direct", "season": "cool", "frost_tolerance": "hardy", "planting": {"anchor": "first_frost", "weeks_from_anchor": {"min": -10, "max": -8}, "note": "Sow 8–10 weeks before first fall frost for the sweetest, most vibrant roots; spring plantings are possible but fall is strongly preferred."}, "usda_zones": {"min": 2, "max": 11}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 6, "max": 12}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Direct sow seeds 1/2 inch deep in loose, deeply prepared, stone-free soil in late summer or early fall; thin seedlings to 4–6 inches for proper root development. Watermelon radish is a Chinese heirloom daikon type with a pale green exterior that conceals a vivid magenta-to-pink interior resembling watermelon flesh. Fall planting is strongly preferred over spring — cool nights concentrate sugars and deepen the interior color while reducing pungency. Harvest when roots reach 2–3 inches in diameter; slice thinly for salads, pickle in rice vinegar, or roast where the color intensifies to brilliant crimson.", "sources": ["general horticultural reference"]}')
