INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('welsh-onion','Welsh Onion (Bunching Onion)','Allium fistulosum','vegetable','allium',7,14,50,80,65,120,'seed','direct','perennial','hardy','last_frost',-6,-4,'Sow 4–6 weeks before last frost in spring; fall sowing in mild climates produces overwintered clumps ready for early spring harvest.',3,9,4,6,12,24,4,6,'full','moderate','Sow seeds 1/4 inch deep in rows and thin to 4–6 inches, or start in trays and transplant in clusters of 3–5 seedlings. Welsh onion does not form a bulb but produces clumps of hollow, cylindrical green stalks that are harvested like scallions; the entire green top and white base are edible. Harvest outer stalks from established clumps as needed, leaving the center to continue growing; clumps also divide easily and can be split every 2–3 years. Extremely cold-hardy and virtually maintenance-free once established, it serves as a permanent perennial scallion in most temperate gardens.','["general horticultural reference"]','{"slug": "welsh-onion", "common_name": "Welsh Onion (Bunching Onion)", "scientific_name": "Allium fistulosum", "category": "vegetable", "subcategory": "allium", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 50, "max": 80}, "days_to_maturity": {"min": 65, "max": 120}, "maturity_from": "seed", "sow_method": "direct", "season": "perennial", "frost_tolerance": "hardy", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -6, "max": -4}, "note": "Sow 4–6 weeks before last frost in spring; fall sowing in mild climates produces overwintered clumps ready for early spring harvest."}, "usda_zones": {"min": 3, "max": 9}, "spacing_in": {"min": 4, "max": 6}, "height_in": {"min": 12, "max": 24}, "spread_in": {"min": 4, "max": 6}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1/4 inch deep in rows and thin to 4–6 inches, or start in trays and transplant in clusters of 3–5 seedlings. Welsh onion does not form a bulb but produces clumps of hollow, cylindrical green stalks that are harvested like scallions; the entire green top and white base are edible. Harvest outer stalks from established clumps as needed, leaving the center to continue growing; clumps also divide easily and can be split every 2–3 years. Extremely cold-hardy and virtually maintenance-free once established, it serves as a permanent perennial scallion in most temperate gardens.", "sources": ["general horticultural reference"]}')
