  VALUES ('winged-bean','Winged Bean (Asparagus Pea)','Psophocarpus tetragonolobus','vegetable','legume',7,14,70,85,60,90,'seed','direct','warm','tender','last_frost',2,4,'Direct sow 2–4 weeks after last frost once soil reaches 70°F; a truly tropical legume requiring a long, warm, humid season.',10,12,12,18,72,144,12,24,'full','moderate','Scarify or soak seeds 12–24 hours before sowing 1 inch deep in warm, well-drained, low-fertility soil; inoculate with cowpea rhizobium to promote nitrogen fixation. Provide a sturdy trellis or fence at least 6 feet tall as soon as plants emerge, as vines climb rapidly and are very productive when vertical. Virtually every part of the winged bean is edible — harvest young pods at 3–4 inches with frilly wings still tender, leaves and shoot tips as greens, flowers as a colorful salad garnish, and mature dried seeds as high-protein pulses. In the tropics, tuberous roots also form and can be harvested and eaten like yam.','["general horticultural reference"]','{"slug": "winged-bean", "common_name": "Winged Bean (Asparagus Pea)", "scientific_name": "Psophocarpus tetragonolobus", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 85}, "days_to_maturity": {"min": 60, "max": 90}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 4}, "note": "Direct sow 2–4 weeks after last frost once soil reaches 70°F; a truly tropical legume requiring a long, warm, humid season."}, "usda_zones": {"min": 10, "max": 12}, "spacing_in": {"min": 12, "max": 18}, "height_in": {"min": 72, "max": 144}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "moderate", "directions": "Scarify or soak seeds 12–24 hours before sowing 1 inch deep in warm, well-drained, low-fertility soil; inoculate with cowpea rhizobium to promote nitrogen fixation. Provide a sturdy trellis or fence at least 6 feet tall as soon as plants emerge, as vines climb rapidly and are very productive when vertical. Virtually every part of the winged bean is edible — harvest young pods at 3–4 inches with frilly wings still tender, leaves and shoot tips as greens, flowers as a colorful salad garnish, and mature dried seeds as high-protein pulses. In the tropics, tuberous roots also form and can be harvested and eaten like yam.", "sources": ["general horticultural reference"]}')
