  VALUES ('winter-melon','Winter Melon (Wax Gourd)','Benincasa hispida','vegetable','cucurbit',7,14,70,90,80,120,'seed','indoor-start','warm','tender','last_frost',-4,-3,'Start indoors 3–4 weeks before last frost; transplant after frost danger passes and soil is warm.',7,11,36,60,12,18,120,240,'full','moderate','Sow 1/2 inch deep in rich, warm soil after last frost; winter melon is a large-fruited cucurbit that needs a long warm season and a very sturdy trellis or ample ground space. The developing fruits are covered in fine white hairs that mature into a waxy white coating, which gives the fruit exceptional storage life of up to a year at room temperature. Harvest mature fruits when the waxy coating is fully developed and the fruit sounds hollow when tapped. Young fruits can also be harvested at 6–8 inches for immediate cooking in soups and stir-fries.','["general horticultural reference"]','{"slug": "winter-melon", "common_name": "Winter Melon (Wax Gourd)", "scientific_name": "Benincasa hispida", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 7, "max": 14}, "germination_soil_temp_f": {"min": 70, "max": 90}, "days_to_maturity": {"min": 80, "max": 120}, "maturity_from": "seed", "sow_method": "indoor-start", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": -4, "max": -3}, "note": "Start indoors 3–4 weeks before last frost; transplant after frost danger passes and soil is warm."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 36, "max": 60}, "height_in": {"min": 12, "max": 18}, "spread_in": {"min": 120, "max": 240}, "sun": "full", "water": "moderate", "directions": "Sow 1/2 inch deep in rich, warm soil after last frost; winter melon is a large-fruited cucurbit that needs a long warm season and a very sturdy trellis or ample ground space. The developing fruits are covered in fine white hairs that mature into a waxy white coating, which gives the fruit exceptional storage life of up to a year at room temperature. Harvest mature fruits when the waxy coating is fully developed and the fruit sounds hollow when tapped. Young fruits can also be harvested at 6–8 inches for immediate cooking in soups and stir-fries.", "sources": ["general horticultural reference"]}')
