  VALUES ('yacon','Yacon','Smallanthus sonchifolius','vegetable','root',NULL,NULL,NULL,NULL,150,210,'transplant','tuber','warm','tender','last_frost',0,2,'Plant sprouted crown divisions at or just after last frost once soil is 60°F; start in pots indoors 4–6 weeks earlier in short-season climates.',7,11,24,36,48,84,24,36,'full','moderate','Divide the crown (the reddish propagating buds at the top of the storage root cluster) in early spring, allowing cut surfaces to dry for a day before planting 3–4 inches deep. Yacon grows into a large, sunflower-family plant producing crisp, sweet, apple-flavored storage tubers at the base. Harvest after the first frost kills the tops, digging the entire root cluster carefully; separate the large tan storage roots from the reddish crown pieces, saving the crowns in a frost-free location for replanting. Let harvested storage roots cure in sunlight for a few weeks to convert starch to fructooligosaccharides and intensify sweetness.','["general horticultural reference"]','{"slug": "yacon", "common_name": "Yacon", "scientific_name": "Smallanthus sonchifolius", "category": "vegetable", "subcategory": "root", "days_to_germination": null, "germination_soil_temp_f": null, "days_to_maturity": {"min": 150, "max": 210}, "maturity_from": "transplant", "sow_method": "tuber", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 0, "max": 2}, "note": "Plant sprouted crown divisions at or just after last frost once soil is 60°F; start in pots indoors 4–6 weeks earlier in short-season climates."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 48, "max": 84}, "spread_in": {"min": 24, "max": 36}, "sun": "full", "water": "moderate", "directions": "Divide the crown (the reddish propagating buds at the top of the storage root cluster) in early spring, allowing cut surfaces to dry for a day before planting 3–4 inches deep. Yacon grows into a large, sunflower-family plant producing crisp, sweet, apple-flavored storage tubers at the base. Harvest after the first frost kills the tops, digging the entire root cluster carefully; separate the large tan storage roots from the reddish crown pieces, saving the crowns in a frost-free location for replanting. Let harvested storage roots cure in sunlight for a few weeks to convert starch to fructooligosaccharides and intensify sweetness.", "sources": ["general horticultural reference"]}')
