  VALUES ('yardlong-bean','Yardlong Bean (Asparagus Bean)','Vigna unguiculata subsp. sesquipedalis','vegetable','legume',5,10,70,95,60,80,'seed','direct','warm','tender','last_frost',2,6,'Sow 2–6 weeks after last frost once soil is warm; yardlong beans love Gulf Coast heat and humidity and outperform regular beans all summer.',7,11,6,12,120,180,12,24,'full','moderate','Sow seeds 1 in deep once soil is reliably warm; yardlong beans are vigorous climbers that need a sturdy trellis or fence at least 6 feet tall. Unlike common beans, they thrive in high heat and set pods prolifically during summer weather that causes snap beans to drop their blossoms. Harvest when pods are pencil-thin and roughly 12–18 in long, well before they reach their potential 36 in — longer pods become fibrous and bitter. Check daily once pods begin forming, as they move from prime to over-mature in just 2–3 days.','["general horticultural reference", "University of Florida IFAS Extension"]','{"slug": "yardlong-bean", "common_name": "Yardlong Bean (Asparagus Bean)", "scientific_name": "Vigna unguiculata subsp. sesquipedalis", "category": "vegetable", "subcategory": "legume", "days_to_germination": {"min": 5, "max": 10}, "germination_soil_temp_f": {"min": 70, "max": 95}, "days_to_maturity": {"min": 60, "max": 80}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 2, "max": 6}, "note": "Sow 2–6 weeks after last frost once soil is warm; yardlong beans love Gulf Coast heat and humidity and outperform regular beans all summer."}, "usda_zones": {"min": 7, "max": 11}, "spacing_in": {"min": 6, "max": 12}, "height_in": {"min": 120, "max": 180}, "spread_in": {"min": 12, "max": 24}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 in deep once soil is reliably warm; yardlong beans are vigorous climbers that need a sturdy trellis or fence at least 6 feet tall. Unlike common beans, they thrive in high heat and set pods prolifically during summer weather that causes snap beans to drop their blossoms. Harvest when pods are pencil-thin and roughly 12–18 in long, well before they reach their potential 36 in — longer pods become fibrous and bitter. Check daily once pods begin forming, as they move from prime to over-mature in just 2–3 days.", "sources": ["general horticultural reference", "University of Florida IFAS Extension"]}')
