INSERT INTO plants (slug,common_name,scientific_name,category,subcategory,germ_days_min,germ_days_max,germ_soil_temp_f_min,germ_soil_temp_f_max,maturity_days_min,maturity_days_max,maturity_from,sow_method,season,frost_tolerance,plant_anchor,plant_weeks_min,plant_weeks_max,plant_note,usda_zone_min,usda_zone_max,spacing_in_min,spacing_in_max,height_in_min,height_in_max,spread_in_min,spread_in_max,sun,water,directions,sources,data)
  VALUES ('zucchini','Zucchini','Cucurbita pepo','vegetable','cucurbit',4,10,60,95,45,60,'seed','direct','warm','tender','last_frost',1,2,'Direct sow 1–2 weeks after last frost once soil is warm; can also start indoors 2–3 weeks before transplanting.',3,10,24,36,18,36,24,48,'full','moderate','Sow seeds 1 inch deep in warm, compost-enriched soil arranged in hills of 2–3 seeds, then thin to the strongest plant. Water at the soil level rather than overhead to reduce the risk of powdery mildew, which is the most common problem. Check plants daily once fruiting begins, as zucchini grows very rapidly. Harvest fruits at 6–8 inches for the best texture, leaving a short stem attached.','["general horticultural reference"]','{"slug": "zucchini", "common_name": "Zucchini", "scientific_name": "Cucurbita pepo", "category": "vegetable", "subcategory": "cucurbit", "days_to_germination": {"min": 4, "max": 10}, "germination_soil_temp_f": {"min": 60, "max": 95}, "days_to_maturity": {"min": 45, "max": 60}, "maturity_from": "seed", "sow_method": "direct", "season": "warm", "frost_tolerance": "tender", "planting": {"anchor": "last_frost", "weeks_from_anchor": {"min": 1, "max": 2}, "note": "Direct sow 1–2 weeks after last frost once soil is warm; can also start indoors 2–3 weeks before transplanting."}, "usda_zones": {"min": 3, "max": 10}, "spacing_in": {"min": 24, "max": 36}, "height_in": {"min": 18, "max": 36}, "spread_in": {"min": 24, "max": 48}, "sun": "full", "water": "moderate", "directions": "Sow seeds 1 inch deep in warm, compost-enriched soil arranged in hills of 2–3 seeds, then thin to the strongest plant. Water at the soil level rather than overhead to reduce the risk of powdery mildew, which is the most common problem. Check plants daily once fruiting begins, as zucchini grows very rapidly. Harvest fruits at 6–8 inches for the best texture, leaving a short stem attached.", "sources": ["general horticultural reference"]}')
